# =================================================
# ✅ V1058: pykrx 빈 수급표 / Length mismatch 방어
# - 일부 날짜/시장/종목에서 pykrx 내부가 빈 DataFrame에 8개 컬럼명을 강제 부여하며
#   Length mismatch 로그를 뿌릴 수 있어 안전 wrapper로 우회한다.
# =================================================
def _v1058_patch_pykrx_empty_supply_guard():
    try:
        import contextlib
        import io as _io

        def _wrap_stock_func(func_name: str):
            orig = getattr(stock, func_name, None)
            if orig is None or getattr(orig, '_v1058_wrapped', False):
                return

            def _safe(*args, **kwargs):
                try:
                    # pykrx 내부 print/error 로그도 빈데이터 케이스에서는 지저분하게 노출되므로 흡수
                    buf = _io.StringIO()
                    with contextlib.redirect_stdout(buf), contextlib.redirect_stderr(buf):
                        df = orig(*args, **kwargs)
                    if df is None:
                        return pd.DataFrame()
                    return df
                except Exception as e:
                    msg = str(e)
                    if 'Length mismatch' in msg or 'Expected axis has 0 elements' in msg:
                        return pd.DataFrame()
                    # 다른 에러도 런타임 중단보다는 빈 수급으로 넘긴다.
                    return pd.DataFrame()

            _safe._v1058_wrapped = True
            setattr(stock, func_name, _safe)

        _wrap_stock_func('get_market_net_purchases_of_equities_by_ticker')
        _wrap_stock_func('get_market_net_purchases_of_equities')
    except Exception:
        pass

_v1058_patch_pykrx_empty_supply_guard()

