import sys
import os
import threading

# ================================================================
# ✅ 프로그램 정상 종료 패치
# 아래 함수를 파일 상단 (import 아래)에 추가하고
# main 블록 맨 마지막에 graceful_shutdown() 호출
# ================================================================

# =============================================================
# 📰 _fetch_stock_news — 종목별 뉴스 조회 (견고한 버전)
#
# 문제였던 것:
#   ① get_news_sentiment 내부에서 한글 종목명을 URL에 직접 붙일 때
#      UTF-8 인코딩 안 되면 깨짐 → requests params= 로 넘겨야 함
#   ② 네이버 금융 HTML 구조가 바뀌면 파싱 실패
#   ③ euc-kr 인코딩 누락 시 한글 깨짐
#
# 해결:
#   1순위: 기존 get_news_sentiment 호출
#   2순위: 네이버 금융 코드 기반 직접 파싱 (코드 = 숫자라 인코딩 문제 없음)
#   3순위: 네이버 뉴스 검색 (한글 종목명, params= 로 안전하게 전달)
# =============================================================

def _fetch_stock_news(code: str, name: str) -> str:
    """
    종목 코드 + 이름으로 뉴스 헤드라인 최대 3개 반환.
    실패 시 빈 문자열 반환 (에러 전파 안 함).
    """
    if not code:
        return ''

    # ── 1순위: 기존 get_news_sentiment 모듈
    try:
        result = get_news_sentiment(code, name)
        if result:
            if isinstance(result, dict):
                sentiment   = str(result.get('sentiment', ''))
                titles      = result.get('titles', [])
                if titles:
                    return (f"{sentiment} | " if sentiment else '') +                            ' / '.join(str(t)[:30] for t in titles[:3])
                return sentiment
            elif isinstance(result, str) and result.strip():
                return result.strip()[:150]
    except Exception as e:
        log_debug(f"📰 get_news_sentiment 실패({name}): {e}")

    # ── 2순위: 네이버 금융 종목 뉴스 직접 파싱 (코드 기반 — 인코딩 안전)
    try:
        url  = f"https://finance.naver.com/item/news_news.naver?code={code}&page=1"
        res  = requests.get(url, headers=REAL_HEADERS, timeout=5)
        res.encoding = 'euc-kr'
        soup = BeautifulSoup(res.text, 'html.parser')

        # 여러 선택자 시도 (네이버 구조 변경 대응)
        titles = []
        for sel in ['td.title a', '.articleSubject a', '.news_tit', 'a.tit']:
            items = soup.select(sel)
            if items:
                titles = [t.get_text(strip=True) for t in items if t.get_text(strip=True)][:3]
                break

        if titles:
            log_debug(f"📰 [{name}] 네이버금융 뉴스 {len(titles)}건")
            return ' / '.join(t[:30] for t in titles)
    except Exception as e:
        log_debug(f"📰 네이버금융 파싱 실패({name}): {e}")

    # ── 3순위: 네이버 뉴스 검색 (한글 종목명 — params= 로 안전 전달)
    try:
        search_url = "https://search.naver.com/search.naver"
        params     = {
            'where': 'news',
            'query': name,      # ← 한글을 params= 로 넘기면 requests가 자동 URL인코딩
            'sort':  '1',       # 최신순
            'ds':    '',
            'de':    '',
        }
        res2 = requests.get(search_url, params=params, headers=REAL_HEADERS, timeout=5)
        soup2 = BeautifulSoup(res2.text, 'html.parser')

        titles2 = []
        for sel in ['.news_tit', 'a.news_tit', '.api_txt_lines', '.title_link']:
            items2 = soup2.select(sel)
            if items2:
                titles2 = [t.get_text(strip=True) for t in items2 if t.get_text(strip=True)][:3]
                break

        if titles2:
            log_debug(f"📰 [{name}] 네이버검색 뉴스 {len(titles2)}건")
            return ' / '.join(t[:30] for t in titles2)
    except Exception as e:
        log_debug(f"📰 네이버검색 실패({name}): {e}")

    return ''


def graceful_shutdown(exit_code=0):
    """
    모든 작업 완료 후 프로세스를 강제로 정리하고 종료.
    백그라운드 스레드(requests/fdr/openai)가 남아있어도 강제 종료.
    """
    log_info("🔚 정상 종료 시작...")

    # 1. 살아있는 비데몬 스레드 확인 (디버그용)
    alive = [t for t in threading.enumerate() if t.is_alive() and not t.daemon and t != threading.main_thread()]
    if alive:
        log_error(f"⚠️ 잔여 스레드 {len(alive)}개 감지: {[t.name for t in alive]}")
    else:
        log_debug("✅ 잔여 스레드 없음")

    log_info(f"✅ 종료 완료 (exit code: {exit_code})")

    # 2. os._exit() → GC/atexit 무시하고 즉시 종료
    #    sys.exit()는 백그라운드 스레드가 있으면 블로킹될 수 있어서
    #    os._exit()를 사용
    os._exit(exit_code)


# ================================================================
# ✅ ThreadPoolExecutor 타임아웃 래퍼
# 기존 executor.map() 을 아래로 교체
# 스레드가 무한 대기하는 것을 방지
# ================================================================

from concurrent.futures import ThreadPoolExecutor, as_completed, TimeoutError as FuturesTimeoutError

def run_scan_with_timeout(target_dict, weather_data, global_env, leader_env, sector_master_map, timeout_per_stock=10):  # PERF-5: 15→10초
    """
    기존:
        with ThreadPoolExecutor(max_workers=15) as executor:
            results = list(executor.map(lambda p: analyze_final(...), zip(...)))

    교체: 종목당 최대 timeout_per_stock초 제한
    전체 스캔이 멈추지 않도록 보장
    """
    all_hits = []
    pairs = list(zip(target_dict.keys(), target_dict.values()))
    total = len(pairs)

    with ThreadPoolExecutor(max_workers=20) as executor:  # PERF-5: 15→20
        future_map = {
            executor.submit(
                analyze_final,
                code, name, weather_data, global_env, leader_env, sector_master_map
            ): (code, name)
            for code, name in pairs
        }

        done_count = 0
        for future in as_completed(future_map, timeout=timeout_per_stock * total):
            code, name = future_map[future]
            done_count += 1
            try:
                result = future.result(timeout=timeout_per_stock)
                if result:
                    all_hits.extend(result)
            except FuturesTimeoutError:
                log_error(f"⏰ [{name}] 타임아웃 스킵")
            except Exception as e:
                log_error(f"🚨 [{name}] 오류: {e}")

            log_progress(done_count, total)

    return all_hits

