_safe_macro_cache = {}
_macro_fetch_failures = {}


def _clear_macro_fetch_failures():
    _macro_fetch_failures.clear()


def _flush_macro_fetch_failures(context='시황'):
    if not _macro_fetch_failures:
        return

    items = []
    for sym, meta in sorted(_macro_fetch_failures.items()):
        name = meta.get('name', sym)
        err = str(meta.get('error', ''))[:80]
        items.append(f"{sym}/{name}:{err}")

    preview = " | ".join(items[:15])
    if len(items) > 15:
        preview += f" | ...외 {len(items)-15}건"

    log_error(f"🚨 [{context} 데이터 수집 실패] {preview}")




def _fetch_price_from_fdr(symbol):
    df = fdr.DataReader(symbol, start=(datetime.now() - timedelta(days=20)).strftime('%Y-%m-%d'))
    if df is None or df.empty or len(df) < 2:
        raise ValueError("FDR empty dataframe")

    closes = [float(x) for x in df['Close'].dropna().tolist()]
    if len(closes) < 2:
        raise ValueError("FDR insufficient closes")

    return {
        "curr": closes[-1],
        "prev": closes[-2],
        "source": "FDR"
    }


def _fetch_price_from_yahoo_chart(symbol):
    from urllib.parse import quote

    url = f"https://query1.finance.yahoo.com/v8/finance/chart/{quote(symbol, safe='')}"
    params = {
        "range": "1mo",
        "interval": "1d",
        "includePrePost": "false",
    }
    res = requests.get(url, params=params, headers=YAHOO_HEADERS, timeout=8)
    res.raise_for_status()
    data = res.json()

    result_list = (((data or {}).get("chart") or {}).get("result")) or []
    if not result_list:
        raise ValueError("Yahoo chart result missing")

    result = result_list[0]
    meta = result.get("meta", {}) or {}
    indicators = result.get("indicators", {}) or {}
    quote_list = indicators.get("quote", []) or []

    # 우선 meta 값 사용
    regular = meta.get("regularMarketPrice")
    prev_close = meta.get("previousClose")
    if regular is not None and prev_close not in (None, 0):
        return {
            "curr": float(regular),
            "prev": float(prev_close),
            "source": "YahooChartMeta"
        }

    # 없으면 close 배열 사용
    if not quote_list:
        raise ValueError("Yahoo quote missing")
    closes = quote_list[0].get("close", []) or []
    closes = [float(x) for x in closes if x is not None]
    if len(closes) < 2:
        raise ValueError("Yahoo insufficient closes")

    return {
        "curr": closes[-1],
        "prev": closes[-2],
        "source": "YahooChartSeries"
    }


def get_safe_macro(symbol, name):
    cache_key = f"{datetime.now().strftime('%Y-%m-%d')}::{symbol}::{name}"
    if cache_key in _safe_macro_cache:
        return _safe_macro_cache[cache_key]

    last_err = ""
    candidates = []

    # 1차: FDR
    try:
        candidates.append(_fetch_price_from_fdr(symbol))
    except Exception as e:
        last_err = f"FDR:{e}"

    # 2차: Yahoo chart fallback
    try:
        candidates.append(_fetch_price_from_yahoo_chart(symbol))
    except Exception as e:
        if last_err:
            last_err += f" | Yahoo:{e}"
        else:
            last_err = f"Yahoo:{e}"

    if candidates:
        # 0%로 고정되는 걸 줄이기 위해, 변화가 있는 소스를 우선 채택
        chosen = None
        for item in candidates:
            curr = float(item["curr"])
            prev = float(item["prev"])
            chg = ((curr - prev) / prev) * 100 if prev else 0.0
            if abs(chg) >= 0.01:
                chosen = item
                break
        if chosen is None:
            chosen = candidates[0]

        curr = float(chosen["curr"])
        prev = float(chosen["prev"])
        ma5 = curr  # fallback 소스에서는 ma5 신뢰가 낮으므로 단순 상태 처리
        chg = ((curr - prev) / prev) * 100 if prev else 0.0

        status = "☀️맑음" if chg >= 0 else "🌪️폭풍우"
        if "VIX" in name:
            status = "☀️안정" if chg <= 0 else "🌪️위험"
        elif "금리" in name:
            status = "📉완화" if chg <= 0 else "📈상승압력"

        result = {
            "val": curr,
            "chg": round(chg, 2),
            "status": status,
            "text": f"{name}: {curr:,.2f}({chg:+.2f}%) {status}",
            "ok": True,
            "error": "",
            "source": chosen.get("source", ""),
            "label": name,
        }
        _safe_macro_cache[cache_key] = result
        _macro_fetch_failures.pop(symbol, None)
        return result

    result = {
        "val": None,
        "chg": None,
        "status": "☁️불명",
        "text": f"{name}: 연결실패",
        "ok": False,
        "error": last_err[:200],
        "source": "",
        "label": name,
    }
    _safe_macro_cache[cache_key] = result
    _macro_fetch_failures[symbol] = {"name": name, "error": last_err[:120]}
    return result

def _fetch_symbol_bundle(symbol_items, max_workers=8):
    results = {}
    if not symbol_items:
        return results

    with ThreadPoolExecutor(max_workers=min(max_workers, len(symbol_items))) as executor:
        future_map = {
            executor.submit(get_safe_macro, symbol, label): (symbol, label)
            for symbol, label in symbol_items
        }
        for future in as_completed(future_map):
            symbol, label = future_map[future]
            try:
                item = future.result()
                if isinstance(item, dict):
                    item["label"] = label
                results[symbol] = item
            except Exception:
                results[symbol] = {"val": None, "chg": None, "status": "☁️불명", "text": f"{label}: 연결실패", "ok": False, "label": label}
    return results

def _direction_from_change(chg, flat_threshold=0.15):
    chg = safe_float(chg, 0.0)
    if chg >= flat_threshold:
        return "up"
    if chg <= -flat_threshold:
        return "down"
    return "flat"


def _count_bundle_breadth(bundle):
    vals = [v for v in bundle.values() if isinstance(v, dict)]
    if not vals:
        return {"up": 0, "down": 0, "flat": 0, "avg_chg": 0.0, "valid": 0, "fail": 0}

    up = down = flat = fail = 0
    chgs = []

    for v in vals:
        if not v.get("ok", False) or v.get("val") is None:
            fail += 1
            continue

        chg = safe_float(v.get("chg", 0), 0.0)
        direction = _direction_from_change(chg)
        if direction == "up":
            up += 1
        elif direction == "down":
            down += 1
        else:
            flat += 1
        chgs.append(chg)

    return {
        "up": up,
        "down": down,
        "flat": flat,
        "avg_chg": round(sum(chgs) / len(chgs), 2) if chgs else 0.0,
        "valid": len(chgs),
        "fail": fail,
    }


def _bundle_symbol_details(bundle, limit=5):
    details = []
    for sym, info in bundle.items():
        if not isinstance(info, dict):
            continue

        label = info.get("label", sym)
        if info.get("ok", False) and info.get("val") is not None:
            chg = safe_float(info.get("chg", 0), 0.0)
            details.append({
                "symbol": sym,
                "label": label,
                "ok": True,
                "chg": chg,
                "text": f"{label} {chg:+.1f}%"
            })
        else:
            err = str(info.get("error", "실패"))[:20]
            details.append({
                "symbol": sym,
                "label": label,
                "ok": False,
                "chg": None,
                "text": f"{label} 실패"
            })

    details = sorted(
        details,
        key=lambda x: (0 if x["ok"] else 1, -(abs(x["chg"]) if x["chg"] is not None else -999))
    )
    return details[:limit]


def _bundle_detail_text(bundle, limit=5):
    details = _bundle_symbol_details(bundle, limit=limit)
    if not details:
        return "데이터 없음"
    return ", ".join([d["text"] for d in details])


