# ✅ FIX 5: load_krx_listing_safe NameError 수정
# except 블록에서 df_krx가 미정의 상태로 반환되던 버그
# =================================================
def load_krx_listing_safe():
    """
    KRX 전종목 리스트 로드.
    우선순위: ① fdr.StockListing ② pykrx 당일 OHLCV 기반 ③ 빈 DataFrame

    pykrx 당일 시세를 쓰면 Code/Name/Market/Amount/ChangeRate까지 한번에 확보.
    """
    # ① FDR (가장 풍부한 메타데이터)
    try:
        df = fdr.StockListing('KRX')
        if df is not None and not df.empty and len(df) > 100:
            log_info(f"✅ FDR StockListing 성공: {len(df)}개")
            return df
    except Exception as e:
        log_info(f"⚠️ FDR 실패: {e}")

    # ② pykrx 당일 OHLCV — Code/Name/Market/Amount 모두 포함
    log_info("📡 pykrx 당일 시세로 종목 리스트 구성 중...")
    try:
        today = datetime.now().strftime('%Y%m%d')
        dfs = []

        for market in ['KOSPI', 'KOSDAQ']:
            try:
                df_m = stock.get_market_ohlcv(today, market=market)
                if df_m is None or df_m.empty:
                    continue

                df_m = df_m.reset_index()
                col_map = {}
                for c in df_m.columns:
                    cs = str(c).strip()
                    if   cs in ('티커', 'Ticker', '종목코드'):        col_map[c] = 'Code'
                    elif cs in ('시가', 'Open'):                      col_map[c] = 'Open'
                    elif cs in ('고가', 'High'):                      col_map[c] = 'High'
                    elif cs in ('저가', 'Low'):                       col_map[c] = 'Low'
                    elif cs in ('종가', 'Close', '현재가'):           col_map[c] = 'Close'
                    elif cs in ('거래량', 'Volume'):                  col_map[c] = 'Volume'
                    elif cs in ('거래대금', 'Amount', 'Turnover'):    col_map[c] = 'Amount'
                    elif cs in ('등락률', 'Change', 'ChangeRate'):    col_map[c] = 'ChangeRate'
                df_m = df_m.rename(columns=col_map)

                # 종목명 추가
                tickers = df_m['Code'].tolist() if 'Code' in df_m.columns else []
                name_map = {}
                for t in tickers[:2000]:
                    try:
                        name_map[t] = stock.get_market_ticker_name(t)
                    except Exception:
                        name_map[t] = t
                df_m['Name']   = df_m['Code'].map(name_map).fillna(df_m['Code'])
                df_m['Market'] = market
                dfs.append(df_m)
                log_info(f"  {market}: {len(df_m)}개")
            except Exception as e:
                log_error(f"  {market} 실패: {e}")

        if dfs:
            result = pd.concat(dfs, ignore_index=True)
            log_info(f"✅ pykrx 종목 구성 완료: {len(result)}개")
            return result

    except Exception as e:
        log_error(f"🚨 pykrx 전체 실패: {e}")

    # ③ 완전 실패
    log_error("🚨 종목 리스트 로드 완전 실패 — 빈 DataFrame 반환")
    return pd.DataFrame(columns=['Code', 'Name', 'Market'])


def get_stock_sector(ticker, sector_map):
    raw_sector = sector_map.get(ticker, "일반")
    if any(k in raw_sector for k in ['반도체', 'IT부품', '장비']): 
        return "반도체"
    if any(k in raw_sector for k in ['제약', '바이오', '의료기기', '생물']): 
        return "바이오"
    if any(k in raw_sector for k in ['전기차', '배터리', '에너지', '축전지']): 
        return "2차전지"
    return "일반"

def get_safe_macro_legacy_unused(symbol, name):
    # ✅ 중복 정의 제거용 레거시 보관 함수 (실사용 금지)
    try:
        df = fdr.DataReader(symbol, start=(datetime.now() - timedelta(days=15)).strftime('%Y-%m-%d'))
        curr, prev = df.iloc[-1]['Close'], df.iloc[-2]['Close']
        ma5 = df['Close'].tail(5).mean()
        chg = ((curr - prev) / prev) * 100
        status = "☀️맑음" if curr > ma5 else "🌪️폭풍우"
        if "VIX" in name: status = "☀️안정" if curr < ma5 else "🌪️위험"
        return {"val": curr, "chg": chg, "status": status, "text": f"{name}: {curr:,.2f}({chg:+.2f}%) {status}"}
    except:
        return {"status": "☁️불명", "text": f"{name}: 연결실패"}


def get_index_investor_data(market_name):
    try:
        df = stock.get_market_net_purchases_of_equities(END_DATE_STR, END_DATE_STR, market_name)
        if df is None or df.empty:
            prev_day = (datetime.now() - timedelta(days=1)).strftime('%Y%m%d')
            df = stock.get_market_net_purchases_of_equities(prev_day, prev_day, market_name)
        if df is None or df.empty:
            return "수급 데이터 없음"
        total = df.sum(numeric_only=True)
        p = safe_float(total.get('개인', 0), 0)
        f = safe_float(total.get('외국인', total.get('외국인합계', 0)), 0)
        i = safe_float(total.get('기관합계', total.get('기관', 0)), 0)
        return f"개인 {p:+,.0f} | 외인 {f:+,.0f} | 기관 {i:+,.0f}"
    except Exception:
        return "수급 데이터 없음"

# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
# 🎯 시퀀스 확인 통합함수
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
def judge_trade_with_sequence(df, signals):
    seq_ok = judge_yeok_break_sequence_v2(df)
    signals = signals.copy()
    signals['yeok_break'] = seq_ok
    result = calculate_combination_score(signals)
    if seq_ok:
        result['tags'].append('🧬시퀀스확인')
    result['sequence'] = seq_ok
    return result

