def calculate_combination_score(signals):
    effective = signals.copy()
    if effective.get('silent_perfect'):
        effective['silent_strong'] = True

    style = effective.get('style', 'NONE')
    W     = STYLE_WEIGHTS.get(style, STYLE_WEIGHTS['NONE'])

    matched = []
    for combo in COMBO_TABLE:
        try:
            if not combo['cond'](effective):
                continue
        except Exception:
            continue

        base_score = combo['score_fn'](effective) if 'score_fn' in combo else combo['score']
        extra_tags = combo['tag_fn'](effective)   if 'tag_fn'  in combo else []

        matched.append({
            'score':       base_score,
            'grade':       combo['grade'],
            'combination': combo['combination'],
            'tags':        combo['tags'] + extra_tags,
            'type':        combo['type'],
        })

    if matched:
        best = max(matched, key=lambda x: x['score'])
        best['score'] = _apply_style_bonus(best, style, W)
        return best

    tags, bonus = [], 0
    if effective.get('obv_rising'):   bonus += 30; tags.append('📊OBV')
    if effective.get('mfi_strong'):   bonus += 20; tags.append('💰MFI')
    if effective.get('volume_surge'): bonus += 10; tags.append('⚡거래량')

    return {'score': 100 + bonus, 'grade': 'D', 'combination': '🔍기본', 'tags': tags, 'type': None}

def _apply_style_bonus(best, style, W):
    score = best['score']
    if style == 'SWING':
        if any(k in best['combination'] for k in ['폭발', '바닥', '매집', '수렴']):
            score += 30
    elif style == 'SCALP':
        if any(k in best['combination'] for k in ['수박', '돌파', '거래량', '골파기']):
            score += 30
        if any(k in best['combination'] for k in ['바닥', '매집완성']):
            score -= 20
    return score

def check_force_pullback(curr: pd.Series, past: pd.DataFrame):
    """
    세력 눌림목 (선행 정의용)
    - 최근 강봉/거래량 흔적
    - 현재는 눌림 구간
    - 거래량 감소
    - OBV 훼손 적음
    - 20일/40일 근처 지지
    """
    if past is None or past.empty or len(past) < 10:
        return False, "데이터 부족"
    try:
        strong_candle = (
            ((past['Close'] > past['Open']) &
             (((past['Close'] - past['Open']) / (past['Open'] + 1e-9)) * 100 >= 8)) &
            (past['Volume'] > past['Vol_Avg'] * 1.8)
        ).any()
        volume_cooling = curr['Volume'] < (curr['Vol_Avg'] * 0.8)
        near_ma20 = abs(curr['Close'] - curr['MA20']) / (curr['MA20'] + 1e-9) <= 0.03
        near_bb_mid = abs(curr['Close'] - curr['MA40']) / (curr['MA40'] + 1e-9) <= 0.04
        obv_safe = curr['OBV'] >= past['OBV'].tail(5).min()
        candle_not_broken = curr['Close'] >= curr['MA20'] * 0.97
        passed = strong_candle and volume_cooling and (near_ma20 or near_bb_mid) and obv_safe and candle_not_broken
        return passed, f"강봉흔적:{strong_candle}, 거래량감소:{volume_cooling}, 이평근접:{near_ma20 or near_bb_mid}, OBV방어:{obv_safe}"
    except Exception as e:
        return False, f"계산실패:{e}"


def check_ross(curr: pd.Series, past: pd.DataFrame):
    if past.empty or past['BB_LOW'].isna().all():
        return False, "과거 데이터 부족"
    bb_low = past['BB_LOW']
    outside_mask = past['Low'] < bb_low
    if not outside_mask.any():
        return False, "1차 저점 없음"
    first_idx = outside_mask.values.argmax()
    after_first = past.iloc[first_idx + 1:]
    rebound = (after_first['Close'] > after_first['BB_LOW']).any()
    near_band = curr['Low'] <= curr['BB_LOW'] * ROSS_BAND_TOLERANCE
    close_above = curr['Close'] > curr['BB_LOW']
    passed = rebound and near_band and close_above
    return passed, f"반등:{rebound}, 저가밴드근접:{near_band}, 종가밴드위:{close_above}"

def check_rsi_div(curr: pd.Series, past: pd.DataFrame):
    if past['RSI'].isna().all() or pd.isna(curr['RSI']):
        return False, "RSI 데이터 부족"
    min_price_past = past['Low'].min()
    min_rsi_past = past['RSI'].min()
    price_similar = curr['Low'] <= min_price_past * RSI_LOW_TOLERANCE
    rsi_higher = curr['RSI'] > min_rsi_past
    return price_similar and rsi_higher, f"주가저점:{curr['Low']:.0f}(과거:{min_price_past:.0f}), RSI:{curr['RSI']:.1f}(과거:{min_rsi_past:.1f})"

def check_bb40_ross(curr: pd.Series, past: pd.DataFrame):
    """
    BB40 하단 이탈 후 재안착 판단
    - 과거 구간에서 BB40_Lower 하향 이탈이 있었는지
    - 이후 다시 BB40_Lower 위로 복귀한 적이 있는지
    - 현재봉이 BB40_Lower 근처에서 종가 기준 위에 안착했는지
    """
    if past.empty or 'BB40_Lower' not in past.columns or past['BB40_Lower'].isna().all():
        return False, "BB40 데이터 부족"

    bb40_low = past['BB40_Lower']
    outside_mask = past['Low'] < bb40_low

    if not outside_mask.any():
        return False, "BB40 1차 저점 없음"

    first_idx = outside_mask.values.argmax()
    after_first = past.iloc[first_idx + 1:]

    if after_first.empty:
        return False, "BB40 반등 확인 구간 부족"

    rebound = (after_first['Close'] > after_first['BB40_Lower']).any()
    near_band = curr['Low'] <= curr['BB40_Lower'] * ROSS_BAND_TOLERANCE
    close_above = curr['Close'] > curr['BB40_Lower']

    passed = rebound and near_band and close_above
    return passed, f"BB40반등:{rebound}, 저가밴드근접:{near_band}, 종가밴드위:{close_above}"


def check_bb40_rsi_div(curr: pd.Series, past: pd.DataFrame):
    """
    BB40 관점 RSI 다이버전스
    - 과거 BB40 하단 이탈 봉들만 후보로 봄
    - 현재 저점이 과거 저점 부근이거나 더 낮고
    - RSI는 과거보다 높으면 다이버전스로 판단
    """
    if past.empty or 'BB40_Lower' not in past.columns or past['RSI'].isna().all() or pd.isna(curr['RSI']):
        return False, "RSI 데이터 부족"

    bb40_break_df = past[past['Low'] < past['BB40_Lower']].copy()

    if bb40_break_df.empty:
        return False, "BB40 하단 이탈 이력 없음"

    min_price_idx = bb40_break_df['Low'].idxmin()
    min_price_past = bb40_break_df.loc[min_price_idx, 'Low']
    min_rsi_past = bb40_break_df.loc[min_price_idx, 'RSI']

    if pd.isna(min_rsi_past):
        min_rsi_past = bb40_break_df['RSI'].min()

    price_similar = curr['Low'] <= min_price_past * RSI_LOW_TOLERANCE
    rsi_higher = curr['RSI'] > min_rsi_past

    passed = price_similar and rsi_higher
    return passed, f"BB40저점:{curr['Low']:.0f}(과거:{min_price_past:.0f}), RSI:{curr['RSI']:.1f}(과거:{min_rsi_past:.1f})"


def check_bb40_reclaim_rsi_div(curr: pd.Series, past: pd.DataFrame):
    """
    최종 결합형:
    BB40 하단 이탈 후 재안착 + RSI DIV
    """
    bb40_ross, ross_msg = check_bb40_ross(curr, past)
    bb40_div, div_msg = check_bb40_rsi_div(curr, past)

    passed = bb40_ross and bb40_div
    return passed, f"[BB40_Ross] {ross_msg} | [BB40_RSI_DIV] {div_msg}"

def check_good_ma_convergence(curr: pd.Series, past: pd.DataFrame):
    """
    좋은 MA 수렴:
    1. MA20/40/60 서로 가깝다
    2. MA20/40 기울기가 꺾이지 않음
    3. 종가가 수렴대 너무 아래에 있지 않음
    4. BB40 수축 동반
    """
    try:
        if bool(curr.get('Halt_Like', False)) or int(past.get('NoTrade', pd.Series(dtype=float)).sum()) >= 5:
            return False, {'score': 0, 'msg': '거래정지/장기무거래 이력'}

        ma20 = curr['MA20']
        ma40 = curr['MA40']
        ma60 = curr['MA60']

        if pd.isna(ma20) or pd.isna(ma40) or pd.isna(ma60):
            return False, {"score": 0, "msg": "MA 데이터 부족"}

        gap_20_40 = abs(ma20 - ma40) / (ma40 + 1e-9)
        gap_40_60 = abs(ma40 - ma60) / (ma60 + 1e-9)
        gap_20_60 = abs(ma20 - ma60) / (ma60 + 1e-9)
        cond_gap = (gap_20_40 <= 0.025) and (gap_40_60 <= 0.025) and (gap_20_60 <= 0.035)

        if len(past) >= 5:
            ma20_prev = past['MA20'].iloc[-5]
            ma40_prev = past['MA40'].iloc[-5]
        else:
            ma20_prev, ma40_prev = ma20, ma40

        ma20_slope = (ma20 - ma20_prev) / (ma20_prev + 1e-9)
        ma40_slope = (ma40 - ma40_prev) / (ma40_prev + 1e-9)
        cond_slope = (ma20_slope >= -0.003) and (ma40_slope >= -0.003)

        close = curr['Close']
        convergence_bottom = min(ma20, ma40, ma60)
        convergence_top = max(ma20, ma40, ma60)

        cond_price_zone = close >= convergence_bottom * 0.98
        cond_not_too_far = close <= convergence_top * 1.06

        bb40_width = curr['BB40_Width'] if 'BB40_Width' in curr.index else 999
        cond_bb_squeeze = bb40_width <= 14

        score = 0
        if cond_gap:
            score += 35
        if cond_slope:
            score += 20
        if cond_price_zone:
            score += 15
        if cond_not_too_far:
            score += 10
        if cond_bb_squeeze:
            score += 20
        if bb40_width <= 10:
            score += 10

        passed = cond_gap and cond_slope and cond_price_zone and cond_not_too_far and cond_bb_squeeze

        msg = (
            f"gap20_40:{gap_20_40:.3f} gap40_60:{gap_40_60:.3f} gap20_60:{gap_20_60:.3f} | "
            f"ma20기울기:{ma20_slope:+.4f} ma40기울기:{ma40_slope:+.4f} | "
            f"종가:{close:.0f} 수렴하단:{convergence_bottom:.0f} 수렴상단:{convergence_top:.0f} | "
            f"BB40:{bb40_width:.1f}"
        )

        return passed, {"score": score, "msg": msg}

    except Exception as e:
        return False, {"score": 0, "msg": f"오류:{e}"}

def check_ma_convergence_break_ready(curr: pd.Series, past: pd.DataFrame):
    """
    폭발직전 수렴:
    1. 좋은 수렴이 이미 형성
    2. 종가가 수렴대 상단 근처 또는 그 위
    3. BB40 수축이 유지
    4. 거래량이 너무 죽지 않음
    """
    try:
        if bool(curr.get('Halt_Like', False)) or int(past.get('NoTrade', pd.Series(dtype=float)).sum()) >= 5:
            return False, {'score': 0, 'msg': '거래정지/장기무거래 이력'}

        good_conv, good_info = check_good_ma_convergence(curr, past)

        ma20 = curr['MA20']
        ma40 = curr['MA40']
        ma60 = curr['MA60']
        close = curr['Close']
        volume = curr['Volume']
        vol_avg = curr['Vol_Avg']

        convergence_top = max(ma20, ma40, ma60)

        cond_price_break_ready = close >= convergence_top * 0.995
        cond_not_overheat = close <= convergence_top * 1.05

        bb40_width = curr['BB40_Width'] if 'BB40_Width' in curr.index else 999
        cond_bb_squeeze = bb40_width <= 12

        cond_volume_alive = volume >= vol_avg * 0.8

        score = 0
        if good_conv:
            score += int(good_info.get("score", 0) * 0.5)
        if cond_price_break_ready:
            score += 25
        if cond_not_overheat:
            score += 10
        if cond_bb_squeeze:
            score += 20
        if cond_volume_alive:
            score += 10
        if bb40_width <= 8:
            score += 10

        passed = good_conv and cond_price_break_ready and cond_not_overheat and cond_bb_squeeze

        msg = (
            f"좋은수렴:{good_conv} | "
            f"종가:{close:.0f} 수렴상단:{convergence_top:.0f} | "
            f"돌파준비:{cond_price_break_ready} 과열아님:{cond_not_overheat} | "
            f"BB40:{bb40_width:.1f} 거래량유지:{cond_volume_alive}"
        )

        return passed, {"score": score, "msg": msg}

    except Exception as e:
        return False, {"score": 0, "msg": f"오류:{e}"}


# =========================================================
# 🍉 수박패턴 V2 (준비형 → 발사형)
# 기존 Watermelon_Color / Watermelon_Signal 로직을 점수형으로 업그레이드
# =========================================================
def _wm_safe_series(df: pd.DataFrame, col: str, default=0.0) -> pd.Series:
    if col in df.columns:
        return pd.to_numeric(df[col], errors='coerce')
    return pd.Series(default, index=df.index, dtype='float64')



def integrate_watermelon_v2_columns(df: pd.DataFrame) -> pd.DataFrame:
    """
    ✅ Watermelon V3
    준비형 / 1차 발사형 / 재발사형 분리
    기존 컬럼과의 호환 유지:
      - Watermelon_Prepare
      - Watermelon_Launch
      - Watermelon_Signal / Watermelon_Signal_Refined
      - Supply_Turn_Signal / Supply_Turn_Prepare
      - Watermelon_Color / Watermelon_Score / Watermelon_Fire
      - WATERMELON_GREEN_SCORE / WATERMELON_RED_SCORE / WATERMELON_QUALITY
    """
    out = df.copy()

    close = _wm_safe_series(out, 'Close')
    open_ = _wm_safe_series(out, 'Open')
    high = _wm_safe_series(out, 'High')
    low = _wm_safe_series(out, 'Low')
    volume = _wm_safe_series(out, 'Volume')

    ma5 = _wm_safe_series(out, 'MA5')
    ma20 = _wm_safe_series(out, 'MA20')
    ma40 = _wm_safe_series(out, 'MA40')
    bb40_width = _wm_safe_series(out, 'BB40_Width')
    disparity = _wm_safe_series(out, 'Disparity', 100.0)
    vma20 = _wm_safe_series(out, 'VMA20')
    mfi = _wm_safe_series(out, 'MFI')
    obv = _wm_safe_series(out, 'OBV')

    # OBV 기울기 보강
    if 'OBV_SLOPE_10' not in out.columns:
        vol10 = volume.rolling(10).sum().replace(0, np.nan)
        out['OBV_SLOPE_10'] = ((obv.diff(10) / vol10) * 100).replace([np.inf, -np.inf], np.nan).fillna(0).round(2)
    obv_slope_10 = _wm_safe_series(out, 'OBV_SLOPE_10')

    turnover_eok = (close * volume) / 100_000_000

    # 종가 품질
    body_top = pd.concat([open_, close], axis=1).max(axis=1)
    total_range = (high - low).replace(0, np.nan)
    upper_wick_total = (high - body_top).clip(lower=0)
    upper_wick_total_pct = (upper_wick_total / total_range * 100).replace([np.inf, -np.inf], np.nan).fillna(100)
    out['UPPER_WICK_TOTAL_PCT'] = upper_wick_total_pct.round(1)
    out['Upper_Wick_Total_Pct'] = out['UPPER_WICK_TOTAL_PCT']

    # 최근 고점 / MA5 기울기
    out['RecentHigh3'] = high.rolling(3).max()
    out['RecentHigh5'] = high.rolling(5).max()
    out['MA5_Slope_Pos'] = (ma5 >= ma5.shift(1))

    # 준비형 점수
    wm_green_score = (
        (bb40_width <= 18).astype(int) * 20 +
        (close >= ma20 * 0.98).astype(int) * 15 +
        (close >= ma40 * 0.96).astype(int) * 10 +
        ((disparity >= 97) & (disparity <= 108)).astype(int) * 15 +
        (obv_slope_10 > 0).astype(int) * 20 +
        (mfi >= 45).astype(int) * 10 +
        (turnover_eok >= 30).astype(int) * 10
    ).fillna(0)

    # 발사형 점수
    recent3_break = ((close >= out['RecentHigh3'].shift(1)) | (out['MA5_Slope_Pos'] & (close >= ma20))).fillna(False)
    wm_red_score = (
        (close >= ma20).astype(int) * 15 +
        (close >= ma40).astype(int) * 15 +
        (close >= open_).astype(int) * 10 +
        (volume >= vma20 * 1.0).astype(int) * 15 +
        (out['UPPER_WICK_TOTAL_PCT'] <= 35).astype(int) * 10 +
        ((disparity >= 98) & (disparity <= 110)).astype(int) * 10 +
        recent3_break.astype(int) * 15 +
        (obv_slope_10 > 0).astype(int) * 10
    ).fillna(0)

    out['WATERMELON_GREEN_SCORE'] = wm_green_score.astype(int)
    out['WATERMELON_RED_SCORE'] = wm_red_score.astype(int)
    out['WATERMELON_QUALITY'] = (wm_green_score * 0.45 + wm_red_score * 0.55).round(1)

    # 준비형
    out['Watermelon_Prepare'] = (
        (out['WATERMELON_GREEN_SCORE'] >= 65) &
        (bb40_width <= 18) &
        (obv_slope_10 > 0)
    ).astype(bool)

    # 최근 10봉 내 준비형 존재
    out['Watermelon_Prepare_Recent'] = (
        out['Watermelon_Prepare'].rolling(10, min_periods=1).max().shift(1).fillna(0) >= 1
    ).astype(bool)

    # 1차 발사형
    out['Watermelon_First_Launch'] = (
        out['Watermelon_Prepare_Recent'] &
        (out['WATERMELON_RED_SCORE'] >= 70) &
        (out['UPPER_WICK_TOTAL_PCT'] <= 35) &
        (bb40_width <= 20)
    ).astype(bool)

    # 과거 발사 이력
    out['Watermelon_Old_Signal'] = (
        out['Watermelon_First_Launch'].rolling(15, min_periods=1).max().shift(1).fillna(0) >= 1
    ).astype(bool)

    # 눌림 발생
    pullback_happened = (
        (close < ma20) |
        (volume < vma20) |
        (disparity < 100)
    ).fillna(False)
    out['Watermelon_Pullback_Recent'] = (
        pullback_happened.rolling(10, min_periods=1).max().shift(1).fillna(0) >= 1
    ).astype(bool)

    # 재발사형
    out['Watermelon_Relaunch'] = (
        out['Watermelon_Old_Signal'] &
        out['Watermelon_Pullback_Recent'] &
        (out['WATERMELON_RED_SCORE'] >= 62) &
        (close >= ma20) &
        (close >= open_) &
        (obv_slope_10 > 0)
    ).astype(bool)

    # 최종 발사형
    out['Watermelon_Launch'] = (out['Watermelon_First_Launch'] | out['Watermelon_Relaunch']).astype(bool)

    # 레거시 호환
    out['Watermelon_Signal_Refined'] = out['Watermelon_Launch']
    out['Watermelon_Signal'] = out['Watermelon_Launch']

    # 예전 컬럼 호환
    out['WATERMELON_GREEN'] = out['Watermelon_Prepare'].astype(int)
    out['WATERMELON_RED'] = out['Watermelon_Launch'].astype(int)
    out['WATERMELON_GREEN_NEW'] = (
        out['Watermelon_Prepare'] &
        (~out['Watermelon_Prepare'].shift(1).fillna(False))
    ).astype(int)
    out['WATERMELON_RED_NEW'] = (
        out['Watermelon_Launch'] &
        (~out['Watermelon_Launch'].shift(1).fillna(False))
    ).astype(int)

    green_days = []
    red_days = []
    g_cnt = 0
    r_cnt = 0
    for g, r in zip(out['WATERMELON_GREEN'].tolist(), out['WATERMELON_RED'].tolist()):
        g_cnt = g_cnt + 1 if int(g) == 1 else 0
        r_cnt = r_cnt + 1 if int(r) == 1 else 0
        green_days.append(g_cnt)
        red_days.append(r_cnt)
    out['WATERMELON_GREEN_DAYS'] = green_days
    out['WATERMELON_RED_DAYS'] = red_days

    out['Supply_Turn_Prepare'] = out['Watermelon_Prepare_Recent']
    out['Supply_Turn_Signal'] = out['Watermelon_Launch']

    out['Watermelon_Color'] = np.where(
        out['Watermelon_Launch'], 'red',
        np.where(out['Watermelon_Prepare'], 'green', 'none')
    )

    out['Watermelon_Score'] = np.where(
        out['Watermelon_Launch'], 3,
        np.where(out['Watermelon_Prepare'], 2, 0)
    )

    out['Green_Days_10'] = (out['Watermelon_Color'].shift(1) == 'green').rolling(10).sum().fillna(0).astype(int)

    out['Watermelon_Green'] = out['Watermelon_Prepare']
    out['Watermelon_Red'] = out['Watermelon_Launch']
    out['Watermelon_Red2'] = (close >= open_) & out['Watermelon_Launch']

    out['VWMA40'] = (close * volume).rolling(40).mean() / volume.rolling(40).mean()
    out['Vol_Accel'] = volume / volume.rolling(5).mean()
    out['Watermelon_Fire'] = out['WATERMELON_QUALITY'].round(2)

    return out


def watermelon_signal_snapshot(row: pd.Series) -> dict:
    green = bool(row.get('Watermelon_Prepare', False))
    red = bool(row.get('Watermelon_Launch', False))
    red_new = bool(int(row.get('WATERMELON_RED_NEW', 0)))
    green_new = bool(int(row.get('WATERMELON_GREEN_NEW', 0)))

    green_score = int(row.get('WATERMELON_GREEN_SCORE', 0) or 0)
    red_score = int(row.get('WATERMELON_RED_SCORE', 0) or 0)
    quality = float(row.get('WATERMELON_QUALITY', 0) or 0)
    green_days = int(row.get('WATERMELON_GREEN_DAYS', 0) or 0)
    red_days = int(row.get('WATERMELON_RED_DAYS', 0) or 0)

    first_launch = bool(row.get('Watermelon_First_Launch', False))
    relaunch = bool(row.get('Watermelon_Relaunch', False))
    prepare_recent = bool(row.get('Watermelon_Prepare_Recent', False))

    tags = []
    score_bonus = 0
    phase = '없음'

    if green and not red:
        phase = '준비형'
        tags.append(f'🍈수박준비형(G{green_score})')
        score_bonus += 20 + min(max(green_score - 60, 0), 20)
        if green_new:
            tags.append('🍈초록신규')
            score_bonus += 8
        if green_days >= 3:
            tags.append(f'🍈초록{green_days}일')
            score_bonus += min(green_days * 2, 12)

    if first_launch:
        phase = '1차발사형'
        tags.append(f'🍉1차발사형(R{red_score})')
        score_bonus += 90 + min(max(red_score - 70, 0), 20)
        if red_new:
            tags.append('🍉빨강신규점등')
            score_bonus += 25

    elif relaunch:
        phase = '재발사형'
        tags.append(f'🍉재발사형(R{red_score})')
        score_bonus += 70 + min(max(red_score - 62, 0), 18)

    elif red:
        phase = '발사형'
        tags.append(f'🍉수박발사형(R{red_score})')
        score_bonus += 50 + min(red_score * 3, 18)

    if quality >= 80:
        tags.append(f'🏆수박품질{quality:.1f}')
        score_bonus += 20
    elif quality >= 65:
        tags.append(f'✅수박품질{quality:.1f}')
        score_bonus += 10

    if prepare_recent and first_launch:
        tags.append('📦준비후점화')
        score_bonus += 12

    return {
        'green': green,
        'red': red,
        'red_new': red_new,
        'green_new': green_new,
        'phase': phase,
        'green_score': green_score,
        'red_score': red_score,
        'quality': quality,
        'green_days': green_days,
        'red_days': red_days,
        'first_launch': first_launch,
        'relaunch': relaunch,
        'prepare_recent': prepare_recent,
        'score_bonus': int(score_bonus),
        'tags': tags,
    }


# ---------------------------------------------------------
# 📈 [4] 기술적 분석 지표
# ---------------------------------------------------------

def _conv3_series(a: pd.Series, b: pd.Series, c: pd.Series) -> pd.Series:
    mx = pd.concat([a, b, c], axis=1).max(axis=1)
    mn = pd.concat([a, b, c], axis=1).min(axis=1)
    return ((mx - mn) / mx.replace(0, np.nan) * 100).round(2)

def build_ma_convergence_comment_from_row(row) -> str:
    ultra   = bool(row.get('Is_UltraShort_MA_Conv', False))      # 5/10/20
    short   = bool(row.get('Is_Short_MA_Conv', False))           # 5/20/60
    struct  = bool(row.get('Is_Structure_MA_Conv', False))       # 20/60/112
    bridge  = bool(row.get('Is_Bridge_MA_Conv', False))          # 5/20/112
    link    = bool(row.get('Is_Structure_Link_MA_Conv', False))  # 5/60/112
    super_m = bool(row.get('Is_Super_MA_Conv', False))

    if super_m:
        return "초단기·단기·구조 흐름이 동시에 압축된 초강력 응축 구간"
    if ultra and short:
        return "초단기와 단기 이평이 함께 조여져 단기 발사 가능성이 높은 구간"
    if struct and not short:
        return "20/60/112 구조 수렴으로 중기 바닥 구조가 정리되는 준비형 구간"
    if bridge:
        return "MA5가 MA20/112로 붙는 브릿지 수렴, 구조선 재합류 초입"
    if link:
        return "MA5가 MA60/112 구조선으로 접히는 초기 구조 회복형 수렴"
    if ultra:
        return "5/10/20 초단기 응축으로 독사·종가배팅형 단기 탄력 구간"
    if short:
        return "5/20/60 단기 수렴으로 돌파 직전 정돈된 응축 구간"
    return "뚜렷한 MA 응축은 아님"

def get_indicators(df):
    # PERF-1: df.copy() 제거 — analyze_final에서 이미 복사본 전달
    count = len(df)

    recent_avg_amount = (df['Close'] * df['Volume']).tail(5).mean() / 100_000_000
    ma20_amount       = (df['Close'] * df['Volume']).tail(20).mean() / 100_000_000

    # ✅ FIX-A: 거래대금 필터 이원화 (Ver 27.4)
    # 트랙 A — 안정형: 최근5일 150억+ (또는 350억+)
    track_a = (
        (recent_avg_amount >= RECENT_AVG_AMOUNT_1 and recent_avg_amount >= ma20_amount * 1.5)
        or recent_avg_amount >= RECENT_AVG_AMOUNT_2
    )
    # 트랙 B — 급등 초동형 (나무기술/소형 급등주 포착)
    #   조건: 당일 거래량 3배+ AND 당일 거래대금 10억+
    #   (소형주 1,400원 × 70만주 = 9.8억 → 10억 기준)
    last_vol    = df['Volume'].iloc[-1]
    last_close  = df['Close'].iloc[-1]
    last_amount = (last_vol * last_close) / 100_000_000
    vol_ma20_v  = df['Volume'].tail(20).mean()
    track_b = (
        last_amount >= 10 and
        vol_ma20_v > 0 and
        last_vol >= vol_ma20_v * 3.0
    )
    if not (track_a or track_b):
        return None
    # 트랙 기록 (boolean 컬럼 — iloc로 안전하게 접근)
    df['_is_track_b'] = (not track_a) and track_b

    high  = df['High']
    low   = df['Low']
    close = df['Close']

    for n in [5, 10, 20, 40, 60, 112, 224, 448]:
        df[f'MA{n}']    = close.rolling(window=n, min_periods=n).mean()
        df[f'VMA{n}']   = df['Volume'].rolling(window=n, min_periods=n).mean()
        df[f'Slope{n}'] = (df[f'MA{n}'] - df[f'MA{n}'].shift(3)) / df[f'MA{n}'].shift(3) * 100

    # PERF-4: Slope20/40은 이미 Slope 루프에서 계산됨 → 재활용
    df['MA20_slope'] = df['Slope20']
    df['MA40_slope'] = df['Slope40']

    std20 = close.rolling(20).std()
    std40 = close.rolling(40).std()

    df['BB_Upper']      = df['MA20'] + std20 * 2
    df['BB_Lower']      = df['MA20'] - std20 * 2
    df['BB20_Width']    = std20 * 4 / df['MA20'] * 100
    df['BB40_Upper']    = df['MA40'] + std40 * 2
    df['BB40_Lower']    = df['MA40'] - std40 * 2
    df['BB40_Width']    = std40 * 4 / df['MA40'] * 100
    df['BB40_PercentB'] = (close - df['BB40_Lower']) / (df['BB40_Upper'] - df['BB40_Lower'])
    df['BB_UP']  = df['BB40_Upper']
    df['BB_LOW'] = df['BB_Lower']

    # ✅ SHIFT(BBandsUp(30,1.8), 20) — 단테 수박 골든크로스 타점
    # 30일 MA + 1.8σ 상단을 20봉 뒤로 시프트
    # 의미: "20일 전 과열 저항선" → 현재가가 이 선을 하→상 돌파 시 저항→지지 전환 확정
    std30              = close.rolling(30).std()
    df['BB30_Upper_18']       = close.rolling(30).mean() + std30 * 1.8
    df['BB30_Upper_18_Shift'] = df['BB30_Upper_18'].shift(20)   # SHIFT(..., 20)
    # 골든크로스: 전일 종가≤Shift선, 당일 종가>Shift선
    prev_close = close.shift(1)
    df['BB30_Shift_GC'] = (
        (prev_close <= df['BB30_Upper_18_Shift']) &
        (close      >  df['BB30_Upper_18_Shift'])
    )
    # 근접 여부: Shift선 ±3% 이내 (타점 진입 구간)
    df['BB30_Shift_Near'] = (
        (close >= df['BB30_Upper_18_Shift'] * 0.97) &
        (close <= df['BB30_Upper_18_Shift'] * 1.05)
    )

    df['Disparity']      = (close / df['MA20']) * 100
    df['MA_Convergence'] = abs(df['MA20'] - df['MA60']) / df['MA60'] * 100

    # ── 신규 다층 MA수렴 ────────────────────────────────────────
    df['MAConv_5_10_20']   = _conv3_series(df['MA5'],  df['MA10'], df['MA20'])   # 초단기
    df['MAConv_5_20_60']   = _conv3_series(df['MA5'],  df['MA20'], df['MA60'])   # 단기
    df['MAConv_20_60_112'] = _conv3_series(df['MA20'], df['MA60'], df['MA112'])  # 구조
    df['MAConv_5_20_112']  = _conv3_series(df['MA5'],  df['MA20'], df['MA112'])  # 브릿지
    df['MAConv_5_60_112']  = _conv3_series(df['MA5'],  df['MA60'], df['MA112'])  # 구조접속

    df['Is_UltraShort_MA_Conv']      = df['MAConv_5_10_20']   <= 3.5
    df['Is_Short_MA_Conv']           = df['MAConv_5_20_60']   <= 4.5
    df['Is_Structure_MA_Conv']       = df['MAConv_20_60_112'] <= 8.0
    df['Is_Bridge_MA_Conv']          = df['MAConv_5_20_112']  <= 5.5
    df['Is_Structure_Link_MA_Conv']  = df['MAConv_5_60_112']  <= 6.5
    df['Is_Super_MA_Conv']           = df['Is_Short_MA_Conv'] & df['Is_Structure_MA_Conv']

    # ── 전고점 대비 이격 (종가배팅 타점용)
    df['High20']         = df['High'].rolling(20).max()
    df['High52']         = df['High'].rolling(252).max()
    df['NearHigh20_Pct'] = (close / df['High20'] * 100).round(1)
    df['NearHigh52_Pct'] = (close / df['High52'] * 100).round(1)

    # ✅ DataFrame 단편화 해소 (PerformanceWarning 방지)
    # 93개 컬럼을 개별 삽입하면 메모리 단편화 발생
    # → copy()로 한 번에 재구성
    df = df.copy()
    df['Box_Range']      = high.rolling(10).max() / low.rolling(10).min()

    tr = pd.concat([
        high - low,
        abs(high - close.shift(1)),
        abs(low  - close.shift(1))
    ], axis=1).max(axis=1)

    dm_plus  = (high - high.shift(1)).clip(lower=0)
    dm_minus = (low.shift(1) - low).clip(lower=0)
    tr14     = tr.rolling(14).sum()

    df['pDI'] = dm_plus.rolling(14).sum()  / tr14 * 100
    df['mDI'] = dm_minus.rolling(14).sum() / tr14 * 100
    df['ADX'] = ((abs(df['pDI'] - df['mDI']) / (df['pDI'] + df['mDI'])) * 100).rolling(14).mean()

    df['ATR']            = tr.rolling(14).mean()
    df['ATR_MA20']       = df['ATR'].rolling(20).mean()
    df['ATR_Below_MA']   = (df['ATR'] < df['ATR_MA20']).astype(int)
    df['ATR_Below_Days'] = df['ATR_Below_MA'].rolling(10).sum()

    df['Tenkan_sen'] = (high.rolling(9).max()  + low.rolling(9).min())  / 2
    df['Kijun_sen']  = (high.rolling(26).max() + low.rolling(26).min()) / 2
    df['Span_A']     = ((df['Tenkan_sen'] + df['Kijun_sen']) / 2).shift(26)
    df['Span_B']     = ((high.rolling(52).max() + low.rolling(52).min()) / 2).shift(26)
    df['Cloud_Top']  = df[['Span_A', 'Span_B']].max(axis=1)

    l_min, h_max = low.rolling(12).min(), high.rolling(12).max()
    df['Sto_K']  = (close - l_min) / (h_max - l_min) * 100
    df['Sto_D']  = df['Sto_K'].rolling(5).mean()
    df['Sto_SD'] = df['Sto_D'].rolling(5).mean()

    ema12             = close.ewm(span=12).mean()
    ema26             = close.ewm(span=26).mean()
    df['MACD']        = ema12 - ema26
    df['MACD_Signal'] = df['MACD'].ewm(span=9).mean()
    df['MACD_Hist']   = df['MACD'] - df['MACD_Signal']

    df['OBV']         = (np.sign(close.diff()) * df['Volume']).fillna(0).cumsum()
    df['OBV_MA10']    = df['OBV'].rolling(10).mean()
    df['OBV_Rising']  = df['OBV'] > df['OBV_MA10']
    # ✅ V1058: OBV 5일 전 값이 0이면 inf가 발생하므로 0/NaN으로 안전 정리
    _obv_den = df['OBV'].shift(5).abs().replace(0, np.nan)
    df['OBV_Slope']   = ((df['OBV'] - df['OBV'].shift(5)) / _obv_den * 100).replace([np.inf, -np.inf], 0).fillna(0)
    df['OBV_Bullish'] = df['OBV_MA10'] > df['OBV_MA10'].shift(1)
    df['Base_Line']   = close.rolling(20).min().shift(5)

    delta      = close.diff()
    gain       = delta.where(delta > 0, 0).ewm(com=13, adjust=False).mean()
    loss       = (-delta.where(delta < 0, 0)).ewm(com=13, adjust=False).mean()
    df['RSI']  = 100 - (100 / (1 + gain / loss))

    typical_price     = (high + low + close) / 3
    money_flow        = typical_price * df['Volume']
    pos_flow          = money_flow.where(typical_price > typical_price.shift(1), 0).rolling(14).sum()
    neg_flow          = money_flow.where(typical_price < typical_price.shift(1), 0).rolling(14).sum()
    df['MFI']             = 100 - (100 / (1 + pos_flow / neg_flow))
    df['MFI_Strong']      = df['MFI'] > 50
    df['MFI_Prev5']       = df['MFI'].shift(5)
    df['MFI_Above50']     = df['MFI_Strong'].astype(int)
    df['MFI_Strong_Days'] = df['MFI_Above50'].rolling(10).sum()
    df['MFI_10d_ago']     = df['MFI'].shift(10)

    df['Buy_Power']       = df['Volume'] * (close - df['Open'])
    df['Buy_Power_MA']    = df['Buy_Power'].rolling(10).mean()
    df['Buying_Pressure'] = df['Buy_Power'] > df['Buy_Power_MA']

    df['Vol_Avg'] = df['Volume'].rolling(20).mean()
    vol_avg20     = df['Vol_Avg']

    # ✅ 거래정지/장기 무거래 감지
    _same_price_bar = (
        (df['Open'] == df['High']) &
        (df['High'] == df['Low']) &
        (df['Low'] == df['Close']) &
        (df['Close'] == df['Close'].shift(1))
    )
    df['NoTrade'] = ((df['Volume'] <= 0) | _same_price_bar).astype(int)
    df['NoTrade_20'] = df['NoTrade'].rolling(20).sum().fillna(0)
    df['NoTrade_60'] = df['NoTrade'].rolling(60).sum().fillna(0)
    df['Halt_Like'] = (df['NoTrade_20'] >= 5) | (df['NoTrade_60'] >= 10)

    df['MA60_Slope']      = df['MA60'].diff()
    df['MA112_Slope']     = df['MA112'].diff()
    df['Dist_to_MA112']   = (df['MA112'] - close) / close
    df['Near_MA112']      = abs(close - df['MA112']) / df['MA112'] * 100
    df['Below_MA112']     = (df['Close'] < df['MA112']).astype(int)
    df['Below_MA112_60d'] = df['Below_MA112'].rolling(60).sum()

    df['MA224'] = df['MA224'].ffill().fillna(0)

    is_above_series       = close > df['MA224']
    df['Trend_Group']     = is_above_series.astype(int).diff().fillna(0).ne(0).cumsum()
    df['Below_MA224']     = (~is_above_series).astype(int)
    df['Below_MA224_60d'] = df['Below_MA224'].rolling(60).sum()

    vol_power_series = df['Volume'] / vol_avg20
    is_above_ma224   = close > df['MA224']

    near_band_low = (low - df['MA224']).abs() / df['MA224'] < 0.03
    local_min     = low == low.rolling(5, center=True, min_periods=1).min()
    double_bottom_series = (near_band_low & local_min).rolling(30).sum() >= 2

    df['Dolbanzi']       = (vol_power_series >= 3.0) & is_above_ma224 & double_bottom_series
    df['Dolbanzi_Count'] = df.groupby('Trend_Group')['Dolbanzi'].cumsum()

    # ── 수박패턴 V2 적용: 준비형(초록) → 발사형(빨강) 점수 구조 ─────────────
    df = integrate_watermelon_v2_columns(df)

    # ✅ 매집대 품질 검증 지표 (단테 HTS 수식) — 재설계 Ver 27.11
    # If(V>Avg(V,20)*1.1 And Avg(OBV,5)>Avg(OBV,20) And C>Avg(C,20) And C>=Highest(H,20,1)*0.9, 60, 0)
    #
    # [재설계 이유]
    # 기존: Green_Maejip_Days / Green_Days_10 → 구조적 모순 (green=조용함, maejip=활발함)
    # 수정: HTS 수식을 독립 매집강도 지표로 사용 (green/red 색상과 무관)
    #
    # [3가지 독립 신호]
    # A. 독립 매집강도: 최근 10/20일 중 매집 조건 발생 횟수
    # B. 수박 직전 품질: 수박 red 직전 10일간 매집 발생 횟수 (신뢰도 검증)
    # C. 현재 스냅샷: 오늘 매집 조건 충족 여부

    _obv_ma5     = df['OBV'].rolling(5).mean()
    _obv_ma20    = df['OBV'].rolling(20).mean()
    _high20_prev = df['High'].rolling(20).max().shift(1)  # Highest(H,20,1)

    _maejip_cond = (
        (df['Volume'] > vol_avg20 * 1.1) &   # V > Avg(V,20)*1.1
        (_obv_ma5 > _obv_ma20) &              # Avg(OBV,5) > Avg(OBV,20)
        (close > df['MA20']) &                # C > Avg(C,20)
        (close >= _high20_prev * 0.9)         # C >= Highest(H,20,1)*0.9
    )

    # [A] 독립 매집강도 (color 무관 — 이게 핵심)
    df['Maejip_Score']   = np.where(_maejip_cond, 60, 0)
    df['Maejip_Days_10'] = _maejip_cond.rolling(10).sum().fillna(0).astype(int)
    df['Maejip_Days_20'] = _maejip_cond.rolling(20).sum().fillna(0).astype(int)

    # 품질 등급: 최근 10일 중 매집 발생 횟수 기준 (color 무관)
    #   A(강한매집): 7일+ / B(매집중): 5~6일 / C(간헐): 3~4일 / D(미발생): 0~2일
    _days = df['Maejip_Days_10']
    df['Maejip_Quality'] = pd.cut(
        _days,
        bins=[-1, 2, 4, 6, 10],
        labels=['D(미발생)', 'C(간헐적)', 'B(매집중)', 'A(강한매집)']
    ).astype(str)

    # [B] 수박 직전 품질 — red 전환 직전 10일간 매집 발생 횟수
    # 발사형이 떴을 때 "직전 매집이 얼마나 있었는가" → 신호 신뢰도
    _pre_signal_maejip = _maejip_cond.rolling(10).sum().shift(1).fillna(0)
    df['Pre_Signal_Maejip'] = _pre_signal_maejip.astype(int)

    # [C] 현재 + 직전 3일 매집 연속성
    _recent3 = _maejip_cond.rolling(3).sum().fillna(0)
    df['Maejip_Recent3'] = _recent3.astype(int)  # 최근 3일 중 몇 번

    # 수급전환 green 기간 중 매집 발생 (참고용 — 드물게 발생하지만 발생하면 강신호)
    _green_mask = df['Watermelon_Color'] == 'green'
    df['Green_Maejip_Days'] = (_green_mask & _maejip_cond).rolling(10).sum().fillna(0).astype(int)

    # ════════════════════════════════════════════════════
    # 매집 강도 + 세력 추정 평단가 (Ver 27.12)
    # ════════════════════════════════════════════════════

    # [1] 매집 발생일 거래량 강도
    # 매집일(Maejip_cond True)의 평균 거래량 vs 전체 평균 → 강도 배율
    _maejip_vol       = df['Volume'].where(_maejip_cond, np.nan)
    _maejip_vol_mean  = _maejip_vol.rolling(20, min_periods=1).mean()
    df['Maejip_Vol_Ratio'] = (_maejip_vol_mean / vol_avg20).fillna(0).round(2)
    # 매집일 평균 거래대금 (억)
    _maejip_amount    = (df['Volume'] * close).where(_maejip_cond, np.nan)
    df['Maejip_Avg_Amount'] = (_maejip_amount.rolling(20, min_periods=1).mean() / 1e8).fillna(0).round(1)

    # [2] 매집 강도 등급 (빈도 × 거래량 배율 결합)
    # 빈도 점수: 10일 중 발생횟수 (0~10)
    # 강도 점수: 매집일 거래량이 평균의 몇 배 (1.0~5.0+)
    _freq_score   = df['Maejip_Days_10']                       # 0~10
    _vol_score    = df['Maejip_Vol_Ratio'].clip(1.0, 5.0)      # 1~5
    _combo_score  = (_freq_score * _vol_score).round(1)        # 최대 50점
    df['Maejip_Power'] = _combo_score                          # 종합 매집력

    # 매집력 등급
    df['Maejip_Power_Grade'] = pd.cut(
        _combo_score,
        bins=[-0.1, 5, 15, 30, 50],
        labels=['D(매집없음)', 'C(약한매집)', 'B(보통매집)', 'A(강한매집)']
    ).astype(str)

    # [3] 세력 추정 평단가 — 3가지 방법 동시 계산
    # ─ ③ Maejip 발생일 VWAP (최근 60일, 매집일만)
    _m_vol_60  = df['Volume'].where(_maejip_cond, 0).rolling(60, min_periods=1).sum()
    _m_amt_60  = (close * df['Volume']).where(_maejip_cond, 0).rolling(60, min_periods=1).sum()
    df['Seryeok_VWAP_60'] = (_m_amt_60 / _m_vol_60.replace(0, np.nan)).fillna(0).round(0)

    # ─ ③-B 최근 20일 매집일 VWAP (단기 평단)
    _m_vol_20  = df['Volume'].where(_maejip_cond, 0).rolling(20, min_periods=1).sum()
    _m_amt_20  = (close * df['Volume']).where(_maejip_cond, 0).rolling(20, min_periods=1).sum()
    df['Seryeok_VWAP_20'] = (_m_amt_20 / _m_vol_20.replace(0, np.nan)).fillna(0).round(0)

    # ─ ④ 볼륨 클러스터 — 최근 60일 가격대별 거래량 최대 구간
    # 60일 가격 범위를 20구간으로 나눠 거래량 합산 → 최대 거래량 가격대 중앙값
    def _calc_volume_cluster(df_slice, n_bins=20):
        if len(df_slice) < 5:
            return 0
        price_min = df_slice['Low'].min()
        price_max = df_slice['High'].max()
        if price_max <= price_min:
            return float(df_slice['Close'].mean())
        bins = np.linspace(price_min, price_max, n_bins + 1)
        vol_by_bin = np.zeros(n_bins)
        for _, row_s in df_slice.iterrows():
            # 각 봉의 거래량을 High~Low 범위에 균등 분포
            lo, hi, vol = row_s['Low'], row_s['High'], row_s['Volume']
            for b in range(n_bins):
                overlap = max(0, min(hi, bins[b+1]) - max(lo, bins[b]))
                span    = max(hi - lo, 1e-9)
                vol_by_bin[b] += vol * (overlap / span)
        peak_bin = vol_by_bin.argmax()
        return round((bins[peak_bin] + bins[peak_bin+1]) / 2, 0)

    # 롤링으로 매일 계산하면 너무 느림 → 마지막 행만 계산
    _last60 = df.tail(60)
    _vol_cluster_price = _calc_volume_cluster(_last60)
    df['Vol_Cluster_Price'] = 0.0
    df.at[df.index[-1], 'Vol_Cluster_Price'] = _vol_cluster_price

    # [4] 세력 평단 vs 현재가 이격 (수익 구간 판단)
    _sv60 = df['Seryeok_VWAP_60']
    df['Seryeok_Gap_Pct'] = ((close - _sv60) / _sv60.replace(0, np.nan) * 100).fillna(0).round(1)
    # 양수: 현재가가 평단 위 (세력 수익 구간)
    # 음수: 현재가가 평단 아래 (세력 손실 구간 — 지지 가능성↑)
    df['Good_MA_Convergence_Score'] = 0
    df['MA_Convergence_Break_Ready_Score'] = 0

    for col in [
        'BB_Ross', 'RSI_DIV',
        'BB40_Ross', 'BB40_RSI_DIV', 'BB40_Reclaim_RSI_DIV',
        'Force_Pullback', 'BB40_Second_Wave', 'Watermelon_Relaunch', 'OBV_Acc_Breakout',
        'Was_Panic', 'Is_bb_low_Stable', 'Has_Accumulation', 'Is_Rsi_Divergence',
'Good_MA_Convergence',
'MA_Convergence_Break_Ready'
    ]:
        df[col] = False

    df_signal = df.dropna(subset=['BB_UP', 'BB_LOW', 'BB40_Lower', 'RSI']).copy()
    if len(df_signal) > 51:
        curr_s  = df_signal.iloc[-1]
        past    = df_signal.iloc[-41:-1]   # ✅ FIX-검색식1: 20→40일 (중기 눌림목 포착)
        past_50 = df_signal.iloc[-61:-1]   # ✅ FIX-검색식1: 51→61일

        ross, _ = check_ross(curr_s, past)
        rsi_div, _ = check_rsi_div(curr_s, past)

        bb40_ross, _ = check_bb40_ross(curr_s, past)
        bb40_rsi_div, _ = check_bb40_rsi_div(curr_s, past)
        bb40_combo, _ = check_bb40_reclaim_rsi_div(curr_s, past)
        # ✅ FIX-검색식5: 세력눌림목 강봉탐지는 최근 20일만
        past_20_fp = df_signal.iloc[-21:-1]
        force_pullback, _ = check_force_pullback(curr_s, past_20_fp)
        bb40_second_wave, _ = check_bb40_second_wave(curr_s, past_50)
        watermelon_relaunch, _ = check_watermelon_relaunch(curr_s, past_50)
        obv_acc_breakout, _ = check_obv_acc_breakout(curr_s, past_50)
        good_ma_conv, ma_conv_info = check_good_ma_convergence(curr_s, past_50)
        ma_break_ready, ma_break_info = check_ma_convergence_break_ready(curr_s, past_50)
     
        was_panic         = (past_50['Low'] < past_50['BB_LOW']).any()
        is_bb_low_stable  = curr_s['Low'] > curr_s['BB_LOW']
        is_rsi_divergence = curr_s['RSI'] > past_50['RSI'].min()
        has_accumulation  = (past_50['Volume'] > (past_50['Vol_Avg'] * 3)).any()

        idx = df.index[-1]
        df.at[idx, 'BB_Ross']              = ross
        df.at[idx, 'RSI_DIV']              = rsi_div
        df.at[idx, 'BB40_Ross']            = bb40_ross
        df.at[idx, 'BB40_RSI_DIV']         = bb40_rsi_div
        df.at[idx, 'BB40_Reclaim_RSI_DIV'] = bb40_combo
        df.at[idx, 'Was_Panic']            = was_panic
        df.at[idx, 'Is_bb_low_Stable']     = is_bb_low_stable
        df.at[idx, 'Is_Rsi_Divergence']    = is_rsi_divergence
        df.at[idx, 'Has_Accumulation']     = has_accumulation
        df.at[idx, 'Force_Pullback']      = force_pullback
        df.at[idx, 'BB40_Second_Wave']    = bb40_second_wave
        df.at[idx, 'Watermelon_Relaunch'] = watermelon_relaunch
        df.at[idx, 'OBV_Acc_Breakout']    = obv_acc_breakout      
        df.at[idx, 'Good_MA_Convergence'] = good_ma_conv
        df.at[idx, 'Good_MA_Convergence_Score'] = int(ma_conv_info.get("score", 0))
        df.at[idx, 'MA_Convergence_Break_Ready'] = ma_break_ready
        df.at[idx, 'MA_Convergence_Break_Ready_Score'] = int(ma_break_info.get("score", 0))

    prev = df.iloc[-2]
    curr = df.iloc[-1]

    cond_golden_cross = (prev['MA5'] < prev['MA112']) and (curr['MA5'] >= curr['MA112'])
    cond_approaching  = (prev['MA5'] < prev['MA112']) and (curr['MA112'] * 0.98 <= curr['MA5'] <= curr['MA112'] * 1.03)
    cond_cross        = cond_golden_cross or cond_approaching

    cond_inverse_mid = curr['MA112'] < curr['MA224']
    cond_below_448   = curr['Close'] < curr['MA448']
    cond_ma224_range = False if float(curr.get('MA224', 0) or 0) == 0 else (-3 <= ((curr['Close'] - curr['MA224']) / curr['MA224']) * 100 <= 5)
    cond_bb40_range  = -7 <= ((curr['Close'] - curr['BB40_Upper']) / curr['BB40_Upper']) * 100 <= 3

    vol_ratio      = df['Volume'] / df['Volume'].shift(1).replace(0, np.nan)
    cond_vol_300   = (vol_ratio >= 3.0).iloc[-50:].any()
    cond_break_448 = (df['High'] > df['MA448']).iloc[-50:].any()

    df['Is_Real_Watermelon'] = False
    if cond_cross and cond_inverse_mid and cond_below_448 and cond_ma224_range and cond_bb40_range and cond_break_448 and cond_vol_300:
        df.at[df.index[-1], 'Is_Real_Watermelon'] = True

    resistances = df[['BB_Upper', 'BB40_Upper', 'MA60', 'MA112']]
    touch_count = pd.DataFrame({
        col: (close < df[col]) & (high >= df[col] * 0.995)
        for col in ['BB_Upper', 'BB40_Upper', 'MA60', 'MA112']
        if col in df.columns
    }).sum(axis=1)
    df['Daily_Touch']     = touch_count
    df['Total_hammering'] = df['Daily_Touch'].rolling(20).sum().fillna(0).astype(int)

    current_res_max = max(curr['BB_Upper'], curr['BB40_Upper'], curr['MA60'], curr['MA112'])
    df['Is_resistance_break'] = curr['Close'] > current_res_max

    df['Is_Maejip'] = (
        (df['Volume'] > df['Volume'].shift(1) * 2) &
        (df['Close'] > df['Open']) &
        (df['Close'] > df['Close'].shift(1))
    )
    df['Maejip_Count'] = df['Is_Maejip'].rolling(20).sum().fillna(0).astype(int)

    max_ma      = df[['MA5', 'MA10', 'MA20']].max(axis=1)
    min_ma      = df[['MA5', 'MA10', 'MA20']].min(axis=1)
    is_squeezed = (max_ma - min_ma) / min_ma <= 0.03

    was_below_20 = (close < df['MA20']).astype(int).rolling(10).max() == 1
    is_slope_up  = df['MA5'] > df['MA5'].shift(1)
    is_head_up   = is_slope_up & (df['MA5'] >= df['MA20'] * 0.99)

    df['Viper_Hook'] = is_squeezed & was_below_20 & is_head_up

    is_heading_ceiling     = (close < df['MA112']) & (df['MA112_Slope'] < 0) & (df['Dist_to_MA112'] <= 0.04)
    df['is_not_blocked']   = ~is_heading_ceiling
    df['is_not_waterfall'] = df['MA112'] >= df['MA224'] * 0.9
    df['is_ma60_safe']     = df['MA60_Slope'] >= 0

    df['Dist_from_MA5']  = (close - df['MA5']) / df['MA5']
    df['is_hugging_ma5'] = df['Dist_from_MA5'] < 0.08

    df['recent_high_10d'] = df['High'].rolling(10).max().shift(1)
    is_hitting_wall       = abs(df['recent_high_10d'] - close) / close < 0.02
    is_breaking_high      = close > df['recent_high_10d']
    df['is_not_double_top'] = ~(is_hitting_wall & ~is_breaking_high)

    df['Real_Viper_Hook'] = (
        df['Viper_Hook'] &
        df['is_not_blocked'] &
        df['is_not_waterfall'] &
        df['is_ma60_safe'] &
        df['is_hugging_ma5'] &
        df['is_not_double_top']
    )

    df['was_broken_20']  = (close < df['MA20']).rolling(5).max() == 1
    # ✅ FIX-검색식4: 5일 최저값이 아닌 '5일 내 하루라도 저거래량' 기준
    df['is_fake_drop']   = (df['Volume'] < vol_avg20 * 0.5).rolling(5).max() == 1
    df['obv_divergence'] = (close < close.shift(5)) & (df['OBV'] >= df['OBV'].shift(5))
    df['reclaim_20']     = (close > df['MA20']) & (close > df['Open']) & (df['Volume'] > df['Volume'].shift(1))

    df['Golpagi_Trap'] = (
        df['was_broken_20'] &
        (df['is_fake_drop'] & df['obv_divergence']) &
        df['reclaim_20']
    )

    gap_ratio    = abs(curr['MA20'] - curr['MA40']) / (curr['MA40'] + 1e-9)
    cross_series = (df['MA20'] > df['MA40']) & (df['MA20'].shift(1) <= df['MA40'].shift(1))
    cross_recent = cross_series.iloc[-5:].any()
    cross_near   = (curr['MA20'] > curr['MA40']) and (gap_ratio < 0.03)

    ma20_rising = curr['MA20_slope'] > 0
    ma40_rising = curr['MA40_slope'] > -0.05
    ma20_accel  = curr['MA20_slope'] > df['MA20_slope'].rolling(3).mean().iloc[-2]

    jongbe_value = (
        (cross_recent or cross_near) and
        ma20_rising and
        ma40_rising and
        ma20_accel and
        curr['Close'] > curr['MA20']
    )
    df['Jongbe_Break'] = False
    df.at[df.index[-1], 'Jongbe_Break'] = jongbe_value

    # ✅ V1058: 기술지표 계산 중 생긴 inf/-inf를 마지막에 한 번 더 제거
    try:
        df.replace([np.inf, -np.inf], np.nan, inplace=True)
        for _col in ['OBV_Slope', 'Disparity', 'RSI', 'MFI', 'ADX', 'BB40_Width']:
            if _col in df.columns:
                df[_col] = pd.to_numeric(df[_col], errors='coerce').fillna(0)
    except Exception:
        pass

    return df  # ✅ TUNE-2: 로그 스팸 제거

def check_force_pullback(curr: pd.Series, past: pd.DataFrame):
    """
    세력 눌림목:
    - 최근 15일 내 강한 양봉/거래량 폭증 흔적
    - 현재는 과열이 아니라 눌림 구간
    - 거래량 감소
    - OBV 훼손 적음
    - 5일/20일/BB 중심선 근처 지지
    """
    if past.empty or len(past) < 10:
        return False, "데이터 부족"

    strong_candle = (
        ((past['Close'] > past['Open']) &
         (((past['Close'] - past['Open']) / (past['Open'] + 1e-9)) * 100 >= 8)) &
        (past['Volume'] > past['Vol_Avg'] * 1.8)
    ).any()

    volume_cooling = curr['Volume'] < (curr['Vol_Avg'] * 0.8)  # ✅ FIX-검색식5b: 1.0→0.8 (명확한 거래소멸)

    near_ma20 = abs(curr['Close'] - curr['MA20']) / (curr['MA20'] + 1e-9) <= 0.03
    near_bb_mid = abs(curr['Close'] - curr['MA40']) / (curr['MA40'] + 1e-9) <= 0.04

    obv_safe = curr['OBV'] >= past['OBV'].tail(5).min()

    candle_not_broken = curr['Close'] >= curr['MA20'] * 0.97

    passed = strong_candle and volume_cooling and (near_ma20 or near_bb_mid) and obv_safe and candle_not_broken
    return passed, f"강봉흔적:{strong_candle}, 거래량감소:{volume_cooling}, 이평근접:{near_ma20 or near_bb_mid}, OBV방어:{obv_safe}"

def check_bb40_second_wave(curr: pd.Series, past: pd.DataFrame):
    """
    BB40 재안착 후 2차 파동:
    - 과거 BB40 하단 이탈 후 복귀 이력
    - 현재 BB40 중심선 위 or 상단밴드 방향
    - OBV/RSI가 1차 반등보다 강해짐
    """
    if past.empty or len(past) < 15:
        return False, "데이터 부족"

    bb40_break = (past['Low'] < past['BB40_Lower']).any()
    bb40_reclaim = (past['Close'] > past['BB40_Lower']).any()

    above_mid = curr['Close'] > curr['MA40']
    bb_expand = curr['BB40_Width'] > past['BB40_Width'].tail(5).mean()
    obv_up = curr['OBV'] > past['OBV'].tail(5).max()
    rsi_up = curr['RSI'] > past['RSI'].tail(5).max()

    passed = bb40_break and bb40_reclaim and above_mid and (obv_up or rsi_up) and bb_expand
    return passed, f"BB40이탈:{bb40_break}, 복귀:{bb40_reclaim}, 중심선위:{above_mid}, OBV상승:{obv_up}, RSI상승:{rsi_up}"

def check_watermelon_relaunch(curr: pd.Series, past: pd.DataFrame):
    """
    수박 눌림 재폭발:
    - 최근 수박 시그널 이력 존재
    - 중간 눌림 구간 존재
    - 현재 다시 빨강/거래량/상승 압력 재개
    """
    if past.empty or len(past) < 15:
        return False, "데이터 부족"

    had_watermelon = past['Watermelon_Signal'].tail(15).any()

    pullback_happened = (
        (past['Close'] < past['MA20']).tail(10).any() or
        (past['Volume'] < past['Vol_Avg']).tail(10).any()
    )

    relaunch = (
        (curr['Watermelon_Color'] == 'red') and
        (curr['Volume'] > curr['Vol_Avg'] * 1.2) and
        (curr['Close'] >= curr['Open'])
    )

    obv_hold = curr['OBV_Rising']
    passed = had_watermelon and pullback_happened and relaunch and obv_hold
    return passed, f"기존수박:{had_watermelon}, 눌림:{pullback_happened}, 재시동:{relaunch}, OBV유지:{obv_hold}"

def check_obv_acc_breakout(curr: pd.Series, past: pd.DataFrame):
    """
    OBV 매집 후 돌파:
    - 최근 박스권/수렴
    - OBV는 미리 상승
    - 현재 가격/거래량 돌파
    """
    if past.empty or len(past) < 20:
        return False, "데이터 부족"

    box_range = (past['High'].max() / (past['Low'].min() + 1e-9)) <= 1.18
    obv_acc = curr['OBV'] > past['OBV'].tail(10).max()
    price_break = curr['Close'] > past['High'].tail(10).max()
    vol_break = curr['Volume'] > curr['Vol_Avg'] * 1.5

    passed = box_range and obv_acc and price_break and vol_break
    return passed, f"박스권:{box_range}, OBV매집:{obv_acc}, 가격돌파:{price_break}, 거래량:{vol_break}"

def check_institutional_bottom(row):
    """
    후처리 수급 기반 바닥형:
    - bottom_area 또는 bb40 재안착 계열
    - 수급 문자열에 기관/외인/쌍끌 포함
    """
    supply_text = str(row.get('수급', ''))
    bottom_like = (
        bool(row.get('BB40재안착조합', False)) or
        bool(row.get('BB40로스', False)) or
        "112선바닥권" in str(row.get('구분', ''))
    )

    supply_good = (
        "🤝쌍끌" in supply_text or
        "🔴기관" in supply_text or
        "🔵외인" in supply_text
    )

    return bottom_like and supply_good
 
 
