            zone_upper = lower_rn * 1.04
            zone_lower = lower_rn * 0.96
            is_1st_buy = has_surged_30 and (row['Low'] <= zone_upper <= row['High'])
            is_2nd_buy = has_surged_30 and (row['Low'] <= zone_lower <= row['High'])
        
