def enrich_hits_with_supply_and_financial(all_hits_sorted, top_k_supply=80, top_k_financial=30):
    enriched = []

    for idx, item in enumerate(all_hits_sorted):
        item = item.copy()

        code = item.get('code')
        price = item.get('현재가', 0)

        if '수급' not in item or not item['수급']:
            item['수급'] = "미계산"
        if '재무' not in item or not item['재무']:
            item['재무'] = "미계산"

        if idx < top_k_supply:
            try:
                supply_prof = get_supply_profile(code, price)
                if not supply_prof or str(supply_prof.get('tag', '미계산')) == '미계산':
                    supply_prof = _fallback_supply_profile_from_item(item) or supply_prof

                if supply_prof:
                    supply_prof = _finalize_supply_profile_dict(supply_prof)

                fb_prof = _fallback_supply_profile_from_item(item) or {}

                item['수급'] = supply_prof.get('tag') or fb_prof.get('tag', item.get('수급', '미계산'))
                item['수급요약'] = supply_prof.get('summary') or fb_prof.get('summary', item.get('수급요약', ''))
                item['수급당일'] = supply_prof.get('today_text') or fb_prof.get('today_text', item.get('수급당일', ''))
                item['수급3일누적'] = supply_prof.get('cum3_text') or fb_prof.get('cum3_text', item.get('수급3일누적', ''))
                item['수급5일누적'] = supply_prof.get('cum5_text') or fb_prof.get('cum5_text', item.get('수급5일누적', ''))
                item['수급연속'] = supply_prof.get('streak_text') or fb_prof.get('streak_text', item.get('수급연속', ''))
                item['수급판정'] = supply_prof.get('flow_text') or fb_prof.get('flow_text', item.get('수급판정', ''))
                item['수급경고'] = supply_prof.get('warning_text') or fb_prof.get('warning_text', item.get('수급경고', ''))
                item['수급매수매도1일'] = supply_prof.get('gross_today_text') or fb_prof.get('gross_today_text', item.get('수급매수매도1일', ''))
                item['수급매수매도5일'] = supply_prof.get('gross_5d_text') or fb_prof.get('gross_5d_text', item.get('수급매수매도5일', ''))
                item['외인보유요약'] = supply_prof.get('foreign_hold_text') or fb_prof.get('foreign_hold_text', item.get('외인보유요약', '미확인'))
                item['개인수급판정'] = supply_prof.get('personal_judgement') or fb_prof.get('personal_judgement', item.get('개인수급판정', ''))
                item['수급매수매도1일'] = supply_prof.get('gross_today_text') or fb_prof.get('gross_today_text', item.get('수급매수매도1일', ''))
                item['수급매수매도5일'] = supply_prof.get('gross_5d_text') or fb_prof.get('gross_5d_text', item.get('수급매수매도5일', ''))
                item['수급경고'] = supply_prof.get('warning_text') or fb_prof.get('warning_text', item.get('수급경고', ''))
                item['수급신뢰도'] = supply_prof.get('confidence') or fb_prof.get('confidence', item.get('수급신뢰도', '추정'))
                item['수급기준일'] = supply_prof.get('last_date') or fb_prof.get('last_date', item.get('수급기준일', '미확인'))
                item['수급원시성공'] = bool(supply_prof.get('raw_ok', False))
                item['수급원시사유'] = supply_prof.get('raw_reason', '')

                whale_score = safe_int(supply_prof.get('whale_score', 0), 0)
                twin_b = bool(supply_prof.get('twin_b', False))
                item['안전점수'] = safe_int(item.get('안전점수', 0), 0) + whale_score

                current_n = str(item.get('N구분', ''))
                current_g = str(item.get('구분', ''))

                if twin_b:
                    if '🤝쌍끌' not in current_n:
                        item['N구분'] = (current_n + ' 🤝쌍끌').strip()
                    if '🍉쌍끌수급' not in current_g:
                        item['구분'] = (current_g + ' 🍉쌍끌수급').strip()
                    item['안전점수'] += 12

                item['수급상태'] = classify_supply_state(item)

            except Exception:
                fallback_prof = _fallback_supply_profile_from_item(item)
                if fallback_prof:
                    fallback_prof = _finalize_supply_profile_dict(fallback_prof)
                    item['수급'] = fallback_prof.get('tag', '미계산')
                    item['수급요약'] = fallback_prof.get('summary', '')
                    item['수급당일'] = fallback_prof.get('today_text', '')
                    item['수급3일누적'] = fallback_prof.get('cum3_text', '')
                    item['수급5일누적'] = fallback_prof.get('cum5_text', '')
                    item['수급연속'] = fallback_prof.get('streak_text', '')
                    item['수급판정'] = fallback_prof.get('flow_text', '')
                    item['수급경고'] = fallback_prof.get('warning_text', '')
                    item['수급매수매도1일'] = fallback_prof.get('gross_today_text', '')
                    item['수급매수매도5일'] = fallback_prof.get('gross_5d_text', '')
                    item['외인보유요약'] = fallback_prof.get('foreign_hold_text', '미확인')
                    item['수급신뢰도'] = fallback_prof.get('confidence', '추정')
                    item['수급기준일'] = fallback_prof.get('last_date', '미확인')
                    item['수급원시성공'] = bool(fallback_prof.get('raw_ok', False))
                    item['수급원시사유'] = fallback_prof.get('raw_reason', '')
                else:
                    item['수급'] = "⚠️수급오류"

        if idx < top_k_financial:
            try:
                f_tag, f_score = get_financial_health(code)
                item['재무'] = f_tag
                item['안전점수'] = safe_int(item.get('안전점수', 0), 0) + int(f_score * 5)
            except Exception:
                item['재무'] = "⚠️재무오류"

        item['안전점수'] = _normalize_safe_score(item.get('안전점수', 0))
        item['N점수'] = max(0, min(999, safe_int(item.get('N점수', 0), 0)))
        enriched.append(item)

    enriched = sorted(enriched, key=lambda x: x.get('안전점수', 0), reverse=True)
    return enriched


