def _shv4_get(row, key, default=None):
    try:
        if isinstance(row, dict):
            return row.get(key, default)
        return row.get(key, default)
    except Exception:
        try:
            return row[key]
        except Exception:
            return default


def _shv4_int(v, default=0):
    try:
        if v is None:
            return default
        return int(float(v))
    except Exception:
        return default


def _shv4_str(v, default=''):
    try:
        if v is None:
            return default
        return str(v)
    except Exception:
        return default


def _shv4_sanitize_text(text):
    s = str(text or '')
    s = s.replace('🧩 PASS 해석:', '🧩 구조 해석:')
    s = s.replace('⛔ DROP | 단계 시퀀스 미성립', '👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족')
    s = s.replace('👀 구조관찰 | 단계 시퀀스 미충족', '👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족')
    s = s.replace('단계 시퀀스 자체는 부족하지만, 상태·저항구름·정제 조합에 따라 실전 해석은 별도로 판단합니다.',
                  '핵심 밴드/단계 조건은 완전 통과가 아니지만, 상태·저항구름·정제이력·세력흔적을 함께 보며 관찰합니다.')
    s = s.replace('🧩 구조 해석: ⛔ DROP | 단계 시퀀스 미성립',
                  '🧩 구조 해석: 👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족')
    s = s.replace('🧩 PASS 해석: ⛔ DROP | 단계 시퀀스 미성립',
                  '🧩 구조 해석: 👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족')
    return s


def describe_stage_status(stage_status: str) -> str:
    if stage_status == 'PASS_A':
        return '✅ PASS_A | 매집→응축→돌파준비 3단계 통과'
    if stage_status == 'PASS_B':
        return '🟣 PASS_B | 응축→재파동 2단계 통과'
    if stage_status in ('DROP', 'WATCH', '', None):
        return '👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족'
    return '👀 관찰 | 단계 확인 필요'


def get_pass_stage_bundle(row) -> dict:
    try:
        pass_stage = calc_pass_stage(row)
    except Exception:
        pass_stage = _shv4_str(_shv4_get(row, '단계상태', ''))
    if pass_stage == 'PASS_B':
        return {
            'pass_stage': 'PASS_B',
            'pass_title': '🟣 PASS_B | 강화 확인 구조 통과',
            'pass_desc': '기본 3단계 통과 후 재안착·거래량·저항 위치까지 추가 확인된 실전 우선 구조입니다.',
        }
    if pass_stage == 'PASS_A':
        return {
            'pass_stage': 'PASS_A',
            'pass_title': '✅ PASS_A | 매집→응축→돌파준비 3단계 통과',
            'pass_desc': '매집 + 응축 + 돌파준비 흐름이 순서대로 맞는 기본 구조 통과 상태입니다.',
        }
    # 내부값 DROP은 유지해도 사용자 노출값은 WATCH로 완화
    return {
        'pass_stage': 'WATCH',
        'pass_title': '👀 밴드외 구조관찰 | 핵심 밴드 타점 미충족',
        'pass_desc': '핵심 밴드/단계 조건은 완전 통과가 아니지만, 상태·저항구름·정제이력·세력흔적을 함께 보며 관찰합니다.',
    }


def calc_context_bonus_score(item) -> int:
    """맥락보너스는 매수점수 본체가 아니라 정렬/해석 보조값으로 제한."""
    try:
        acc = _shv4_int(_shv4_get(item, '세력흔적점수', _shv4_get(item, 'force_trace_score', 0)), 0)
        ref = _shv4_int(_shv4_get(item, '정제이력점수', _shv4_get(item, 'recent_refine_score', 0)), 0)
        mat = _shv4_int(_shv4_get(item, '재료잔존점수', _shv4_get(item, 'material_score', 0)), 0)
        wm_state = _shv4_str(_shv4_get(item, '수박최종상태', _shv4_get(item, '수박상태명', _shv4_get(item, '상태', ''))))
        phase = _shv4_str(_shv4_get(item, '추천단계', _shv4_get(item, '유형', '')))
        raw = acc * 0.24 + ref * 0.95 + mat * 0.12
        cap = 32
        if '후행' in wm_state or '후행' in phase:
            cap = 22 if mat >= 40 else 16
        return max(0, int(min(cap, raw)))
    except Exception:
        return 0


def _score_band_preempt(v: int) -> str:
    if v >= 60:
        return '선취 가능 우수'
    if v >= 35:
        return '선취 관찰 우수'
    if v >= 10:
        return '선취 참고'
    return '선취 낮음'


def _score_band_breakout(v: int) -> str:
    if v >= 90:
        return '돌파 확인 우수'
    if v >= 60:
        return '돌파 대응 양호'
    if v >= 40:
        return '돌파 참고'
    return '돌파 낮음'


def _score_band_safe(v: int) -> str:
    if v >= 450:
        return '매우 양호'
    if v >= 300:
        return '양호'
    if v >= 180:
        return '보통'
    return '주의'


def _score_band_n(v: int) -> str:
    if v >= 700:
        return '매우 양호'
    if v >= 500:
        return '양호'
    if v >= 300:
        return '보통'
    return '낮음'


def build_score_summary(row) -> str:
    preempt = _shv4_int(_shv4_get(row, '선취점수', _shv4_get(row, '단테점수', 0)), 0)
    breakout = _shv4_int(_shv4_get(row, '돌파점수', 0), 0)
    safe = _shv4_int(_shv4_get(row, '안전점수', 0), 0)
    n_score = _shv4_int(_shv4_get(row, 'N점수', 0), 0)
    parts = [f'선취:{_score_band_preempt(preempt)}']
    if breakout:
        parts.append(f'돌파:{_score_band_breakout(breakout)}')
    parts.append(f'안전:{_score_band_safe(safe)}')
    parts.append(f'N:{_score_band_n(n_score)}')

    phase = _shv4_str(_shv4_get(row, '추천단계', _shv4_get(row, '유형', '')))
    wm_state = _shv4_str(_shv4_get(row, '수박최종상태', _shv4_get(row, '수박상태명', _shv4_get(row, '상태', ''))))
    try:
        resolved = _resolve_track_display_state(row, track='preempt')
        if resolved:
            wm_state = str(resolved)
    except Exception:
        pass
    if '후행' in phase or '후행' in wm_state:
        parts.append('후행:신규추격주의')

    bonus = calc_context_bonus_score(row if isinstance(row, dict) else {'세력흔적점수': _shv4_get(row, '세력흔적점수', 0), '정제이력점수': _shv4_get(row, '정제이력점수', 0), '재료잔존점수': _shv4_get(row, '재료잔존점수', 0), '추천단계': phase, '수박최종상태': wm_state})
    if bonus:
        parts.append(f'맥락보너스:+{bonus}')
    return ' | '.join(parts)


def _shv4_insert_or_update_context_lines(base: dict) -> dict:
    try:
        block = str(base.get('interpretation_block', '') or '')
        lines = block.splitlines() if block else []

        # 기존 점수 해석 줄을 최종 점수 해석으로 교체
        final_score = build_score_summary(base)
        replaced_score = False
        for i, ln in enumerate(lines):
            if ln.startswith('🧮 점수 해석:'):
                lines[i] = f'🧮 점수 해석: {final_score}'
                replaced_score = True
                break
        if final_score and not replaced_score:
            lines.append(f'🧮 점수 해석: {final_score}')

        # context trace 라인은 최종 판정 직전에 삽입
        try:
            ctx_lines = _build_context_trace_lines(base)
        except Exception:
            ctx_lines = []
        if ctx_lines:
            insert_at = len(lines)
            for i, ln in enumerate(lines):
                if ln.startswith('✅ 최종 판정:'):
                    insert_at = i
                    break
            existing_heads = set()
            for ln in lines:
                for head in ('🧲 세력흔적:', '🧪 정제이력:', '📰 재료잔존:', '🛡️ 후행유형:', '🧮 맥락보너스:'):
                    if ln.startswith(head):
                        existing_heads.add(head)
            to_add = []
            for ln in ctx_lines:
                head = None
                for h in ('🧲 세력흔적:', '🧪 정제이력:', '📰 재료잔존:', '🛡️ 후행유형:', '🧮 맥락보너스:'):
                    if ln.startswith(h):
                        head = h
                        break
                if head and head in existing_heads:
                    # 같은 헤더가 있으면 구버전 큰 보너스 라인 대신 최종 계산 라인을 우선 사용하도록 교체
                    for j, old in enumerate(lines):
                        if old.startswith(head):
                            lines[j] = ln
                            break
                elif ln and ln not in lines:
                    to_add.append(ln)
            for ln in reversed(to_add):
                lines.insert(insert_at, ln)

        base['interpretation_block'] = _shv4_sanitize_text('\n'.join(lines))
        base['score_summary'] = final_score
    except Exception:
        try:
            base['interpretation_block'] = _shv4_sanitize_text(base.get('interpretation_block', ''))
        except Exception:
            pass
    return base


def enrich_row_with_human_commentary(row):
    if _SHV4_ORIG_enrich_row_with_human_commentary:
        try:
            base = _SHV4_ORIG_enrich_row_with_human_commentary(row)
        except Exception:
            base = dict(row) if isinstance(row, dict) else row.to_dict()
    else:
        base = dict(row) if isinstance(row, dict) else row.to_dict()
    try:
        # pass bundle과 최종 점수는 항상 마지막 정의 기준으로 재기입
        pb = get_pass_stage_bundle(base)
        base['pass_stage'] = pb.get('pass_stage', '')
        base['pass_title'] = pb.get('pass_title', '')
        base['pass_desc'] = pb.get('pass_desc', '')
        base['score_summary'] = build_score_summary(base)
        base = _shv4_insert_or_update_context_lines(base)
    except Exception:
        pass
    return base


def append_interpretation_to_block(block: str, row) -> str:
    if not isinstance(block, str):
        block = str(block or '')
    enriched = enrich_row_with_human_commentary(row)
    extra = _shv4_sanitize_text(str(enriched.get('interpretation_block', '') or '').strip())
    if not extra:
        return _shv4_sanitize_text(block.rstrip())
    if not block.strip():
        return extra + '\n'

    key_markers = [
        '🪵 매집봉:', '〰️ 소파동:', '📶 중파동:', '🔵 파란타점 영역:',
        '🪑 자리평가:', '🧮 자리세부:', '🧩 구조 해석:', '🧲 세력흔적:',
        '🧪 정제이력:', '📰 재료잔존:', '🛡️ 후행유형:', '🧮 맥락보너스:',
    ]
    missing_lines = []
    current = _shv4_sanitize_text(block)
    for ln in [x.strip() for x in extra.splitlines() if x.strip()]:
        marker = next((m for m in key_markers if ln.startswith(m)), None)
        if marker:
            if marker not in current:
                missing_lines.append(ln)
        else:
            if ln not in current:
                missing_lines.append(ln)
    out = current.rstrip()
    if missing_lines:
        out += '\n\n' + '\n'.join(missing_lines)
    return _shv4_sanitize_text(out).rstrip() + '\n'


def build_integrated_stock_block(block: str, row) -> str:
    return append_interpretation_to_block(block, row)

