def enrich_row_with_human_commentary(row):
    if _V5_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY:
        try:
            base = _V5_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY(row)
        except Exception:
            try:
                base = row.to_dict() if hasattr(row, 'to_dict') else dict(row or {})
            except Exception:
                base = {}
    else:
        try:
            base = row.to_dict() if hasattr(row, 'to_dict') else dict(row or {})
        except Exception:
            base = {}

    try:
        tb = _v5_trade_block(base)
        if 'build_trade_clarity_view' in globals():
            view = build_trade_clarity_view(base)
            base['구조판정'] = view.get('structure', '')
            base['매매판정'] = view.get('action', '')
            base['매매레벨'] = view.get('level', '')
        base['매매관점블록'] = tb
        old = _v5_trade_replace_ambiguous(base.get('interpretation_block', ''))
        if tb and '✅ 구조판정' not in old:
            base['interpretation_block'] = (old.rstrip() + '\n' + tb).strip() if old else tb
        else:
            base['interpretation_block'] = old
        for key in ['easy_interpretation', 'action_summary', 'caution', 'need_check']:
            if isinstance(base.get(key), str):
                base[key] = _v5_trade_replace_ambiguous(base.get(key))
    except Exception as _v5_e:
        try:
            base['interpretation_block'] = (str(base.get('interpretation_block', '') or '').strip() + f'\n⚠️ 매매관점 V5 보정 실패: {_v5_e}').strip()
        except Exception:
            pass
    return base


