def _v81_is_state_diagnostic_title(title: str) -> bool:
    t = str(title or '')
    # 이 블록들은 실행 후보가 아니라 상태 확인용이라 STRICT_FAKE_FILTER로 전부 숨기지 않는다.
    return any(k in t for k in ('초입수박 TOP', '눌림수박 TOP', '후행수박 TOP', 'Blue-1', 'Blue-2'))


def _v81_is_actionable_title(title: str) -> bool:
    t = str(title or '')
    return any(k in t for k in ('선취 후보', '선취 관찰', '흰구름 돌파 후보', '흰구름 돌파 관찰', '즉시진입', '파란점선 타점', '수박상태 빨강'))


# V8 공개 링크 베이스 확장: 기존 V8 변수 + 과거 HTML 리포트 변수 모두 지원
def _v8_mobile_public_base():
    raw = (
        os.getenv('REPORT_PUBLIC_BASE_URL')
        or os.getenv('MOBILE_REPORT_PUBLIC_URL')
        or os.getenv('REPORT_BASE_URL')
        or os.getenv('GITHUB_PAGES_URL')
        or ''
    ).strip()
    if not raw:
        return ''
    if raw.endswith('.html'):
        return raw
    return raw.rstrip('/') + '/main7_mobile_latest.html'


def _filter_fake_rows_for_actionable_block(df: pd.DataFrame, title: str) -> pd.DataFrame:
    """V8.1: 액션 블록은 엄격 필터 유지, 상태 진단 TOP5는 빈칸으로 만들지 않는다."""
    if df is None or df.empty or not _strict_fake_filter_enabled():
        return df
    title = str(title or '')
    if _v81_is_state_diagnostic_title(title):
        return df
    if not _v81_is_actionable_title(title):
        return df
    try:
        return df[~df.apply(_is_fake_caution_row, axis=1)].copy()
    except Exception:
        return df


try:
    _V81_BASE_BUILD_WATERMELON_STATE_BLOCK = build_watermelon_state_block
except Exception:
    _V81_BASE_BUILD_WATERMELON_STATE_BLOCK = None


def _v81_compact_late_watermelon_block(title: str, df: pd.DataFrame) -> str:
    if df is None or df.empty:
        return f"🍉 [{title}]\n- 해당 종목 없음\n"
    lines = [f"🍉 [{title}]\n"]
    for rank, (_, row) in enumerate(df.head(5).iterrows(), 1):
        try:
            item = enrich_row_with_human_commentary(row)
        except Exception:
            item = row
        name = str(item.get('종목명', item.get('name', '')) or '').strip()
        code = str(item.get('code', item.get('종목코드', '')) or '').strip()
        state = str(item.get('수박최종상태', item.get('수박상태명', '후행수박')) or '').strip()
        grade = str(item.get('수박상태등급', item.get('wm_state_grade', '')) or '').strip()
        action, structure = _v8_trade_action(item)
        disparity = _v8_num(item.get('이격', item.get('Disparity', 0)), 0)
        rsi = _v8_num(item.get('RSI', 0), 0)
        refine = str(item.get('수박정제태그', '') or '').strip()
        warn = []
        if disparity >= 115:
            warn.append(f"이격 {disparity:.0f}")
        if rsi >= 70:
            warn.append(f"RSI {rsi:.0f}")
        if '가짜수박주의' in refine:
            warn.append('가짜수박주의')
        warn_txt = ' / '.join(warn) if warn else '눌림 재확인'
        link = _v8_stock_link_text(code)
        lines.append(
            f"{rank}) {name}" + (f"({code})" if code else '') + f"{link}\n"
            f"- 상태:{state} | 등급:{grade} | 구조:{structure} | 매매:{action}\n"
            f"- 주의:{warn_txt}\n"
            f"- 대응: 신규 추격보다 보유자는 이탈선 관리, 신규는 눌림 후 재양봉 확인\n"
        )
    return "\n".join(lines).rstrip() + "\n"


def build_watermelon_state_block(title: str, df: pd.DataFrame) -> str:
    """V8.1: 후행수박 TOP5는 간단 요약, 초입/눌림은 STRICT 필터로 숨기지 않음."""
    if '후행수박 TOP' in str(title or ''):
        return _v81_compact_late_watermelon_block(title, df)
    if _V81_BASE_BUILD_WATERMELON_STATE_BLOCK is not None:
        return _V81_BASE_BUILD_WATERMELON_STATE_BLOCK(title, df)
    return f"🍉 [{title}]\n- 생성 함수 없음\n"


