def _v84_sort_top(df, sort_cols, n=5):
    try:
        if df is None or getattr(df, 'empty', False):
            return df
        cols = [c for c in sort_cols if c in df.columns]
        if cols:
            return df.sort_values(by=cols, ascending=[False]*len(cols)).head(n).reset_index(drop=True)
        return df.head(n).reset_index(drop=True)
    except Exception:
        try:
            return df.head(n).reset_index(drop=True)
        except Exception:
            return df


def build_watermelon_state_top5(df):
    if _V84_BASE_BUILD_WATERMELON_STATE_TOP5 is None:
        import pandas as _pd
        empty = _pd.DataFrame()
        return (empty, empty, empty, empty, empty, empty, empty, empty, empty, empty, empty, empty, empty)
    result = _V84_BASE_BUILD_WATERMELON_STATE_TOP5(df)
    try:
        import pandas as _pd
        (green_df, red_df, blue_df, intro_df, pullback_df, late_df, blue1_df, blue2_df, dante_pick_df, dante_watch_df, dante_ex_df, breakout_pick_df, breakout_watch_df) = result
        work = df.copy() if df is not None else _pd.DataFrame()
        if work is not None and not work.empty:
            txt_cols = [c for c in ['수박최종상태','수박상태명','수박상태태그','태그','N조합','추천단계','유형'] if c in work.columns]
            blob = work[txt_cols].astype(str).agg(' '.join, axis=1) if txt_cols else _pd.Series(['']*len(work), index=work.index)
            red_mask = blob.str.contains('Blue-1|Blue-2|Blue1|Blue2|파란점선|재점화', case=False, na=False)
            blue_mask = blob.str.contains('Blue-1|Blue-2|Blue1|Blue2|파란점선', case=False, na=False)
            if '수박상태빨강' in work.columns:
                red_mask = red_mask | work['수박상태빨강'].fillna(False).astype(bool)
            if '수박파란점선' in work.columns:
                blue_mask = blue_mask | work['수박파란점선'].fillna(False).astype(bool)
            if '파란점선1단기' in work.columns:
                blue_mask = blue_mask | work['파란점선1단기'].fillna(False).astype(bool)
            if '파란점선2스윙' in work.columns:
                blue_mask = blue_mask | work['파란점선2스윙'].fillna(False).astype(bool)
                red_mask = red_mask | work['파란점선2스윙'].fillna(False).astype(bool)
            sort_cols = ['수박파란점선점수','파란점선2스윙점수','파란점선1단기점수','수박공격점수','수박포켓점수','안전점수','N점수']
            red_fb = _v84_sort_top(work[red_mask].copy(), sort_cols)
            blue_fb = _v84_sort_top(work[blue_mask].copy(), sort_cols)
            if (red_df is None or getattr(red_df, 'empty', True)) and red_fb is not None and not red_fb.empty:
                red_df = red_fb
            if (blue_df is None or getattr(blue_df, 'empty', True)) and blue_fb is not None and not blue_fb.empty:
                blue_df = blue_fb
        return (green_df, red_df, blue_df, intro_df, pullback_df, late_df, blue1_df, blue2_df, dante_pick_df, dante_watch_df, dante_ex_df, breakout_pick_df, breakout_watch_df)
    except Exception as e:
        try:
            log_error(f"⚠️ V8.4 수박TOP5 보정 실패: {e}")
        except Exception:
            pass
        return result

