def _v85_num(v, default=0.0):
    try:
        if v is None:
            return default
        s = str(v).replace(',', '').replace('%', '').strip()
        if not s:
            return default
        import re as _re
        m = _re.search(r'-?\d+(?:\.\d+)?', s)
        return float(m.group(0)) if m else default
    except Exception:
        return default

def _v85_int(v, default=0):
    try:
        return int(round(_v85_num(v, default)))
    except Exception:
        return default

def _v85_price(v):
    n = _v85_int(v, 0)
    return f"{n:,}" if n > 0 else "-"

def _v85_pos_pct_label(pos):
    try:
        p = float(pos)
    except Exception:
        p = 0.0
    if p < 0:
        return '박스하단이탈'
    if p <= 25:
        return '하단권'
    if p <= 45:
        return '하단~중단'
    if p <= 65:
        return '중단권'
    if p <= 80:
        return '중상단'
    if p <= 95:
        return '상단권'
    if p <= 100:
        return '상단돌파직전'
    return '박스돌파후확장'

def _v85_slope_pack(close_s):
    try:
        import numpy as _np
        import math as _math
        s = close_s.dropna().astype(float)
        if len(s) < 3:
            return 0.0, 0.0, '횡보박스'
        y = s.values
        x = _np.arange(len(y), dtype=float)
        slope_abs = _np.polyfit(x, y, 1)[0]
        base = float(_np.nanmean(y)) if float(_np.nanmean(y)) != 0 else float(y[0] or 1.0)
        slope_pct = (slope_abs / base) * 100.0
        angle = _math.degrees(_math.atan(slope_pct))
        if slope_pct >= 0.28:
            label = '강한상향'
        elif slope_pct >= 0.07:
            label = '완만상향'
        elif slope_pct <= -0.28:
            label = '강한하향'
        elif slope_pct <= -0.07:
            label = '완만하향'
        else:
            label = '횡보박스'
        return round(angle, 1), round(slope_pct, 2), label
    except Exception:
        return 0.0, 0.0, '횡보박스'

def _v85_price_cols(df):
    try:
        cols = _acc_price_cols(df) if '_acc_price_cols' in globals() else {}
    except Exception:
        cols = {}
    try:
        def pick(*names):
            for n in names:
                if n in df.columns:
                    return n
            return ''
        return {
            'high': cols.get('high') or pick('High', '고가', 'high'),
            'low': cols.get('low') or pick('Low', '저가', 'low'),
            'close': cols.get('close') or pick('Close', '종가', 'close'),
            'open': cols.get('open') or pick('Open', '시가', 'open'),
        }
    except Exception:
        return {'high': '', 'low': '', 'close': '', 'open': ''}

def _v85_box_from_recent(df, low_col, high_col, close_col, bars):
    try:
        recent = df.iloc[max(0, len(df) - int(bars)):].copy()
        if recent is None or len(recent) < 3:
            return 0.0, 0.0, 0.0, 0.0, '데이터부족'
        low = float(recent[low_col].astype(float).min())
        high = float(recent[high_col].astype(float).max())
        close = float(df.iloc[-1][close_col])
        rng = high - low
        pos = ((close - low) / rng) * 100.0 if rng > 0 else 50.0
        return low, high, close, pos, ''
    except Exception as e:
        return 0.0, 0.0, 0.0, 0.0, f'box_error:{e}'

def build_wave_levels(df, accum_info=None, lookback=60):
    out = {
        'small_low': 0.0, 'small_high': 0.0, 'small_mid': 0.0,
        'mid_low': 0.0, 'mid_high': 0.0, 'mid_mid': 0.0,
        'small_state': '', 'mid_state': '', 'small_desc': '', 'mid_desc': '',
        'small_box_dir': '', 'mid_box_dir': '',
        'small_angle': 0.0, 'mid_angle': 0.0,
        'small_slope_pct': 0.0, 'mid_slope_pct': 0.0,
        'small_pos_pct': 0.0, 'mid_pos_pct': 0.0,
        'small_pos_label': '', 'mid_pos_label': '',
        'blue_zone_low': 0.0, 'blue_zone_high': 0.0,
        'debug_note': '', 'debug_cols': '', 'debug_len': 0,
        'accum_found': False,
    }
    try:
        if df is None or len(df) < 5:
            out['small_state'] = '소파동 산출불가'
            out['mid_state'] = '중파동 산출불가'
            out['debug_note'] = 'df length < 5'
            return out
        cols = _v85_price_cols(df)
        out['debug_cols'] = f"H={cols.get('high','')},L={cols.get('low','')},C={cols.get('close','')}"
        out['debug_len'] = int(len(df))
        hcol, lcol, ccol = cols.get('high'), cols.get('low'), cols.get('close')
        if not hcol or not lcol or not ccol:
            out['small_state'] = '소파동 산출불가'
            out['mid_state'] = '중파동 산출불가'
            out['debug_note'] = 'price columns missing'
            return out

        acc = accum_info or {}
        acc_found = bool(acc.get('found', False))
        out['accum_found'] = acc_found

        sl = _v85_num(acc.get('low'), 0.0) if acc_found else 0.0
        sh = _v85_num(acc.get('high'), 0.0) if acc_found else 0.0
        close_now = float(df.iloc[-1][ccol])
        small_note = ''
        if sl <= 0 or sh <= 0 or sh <= sl:
            sl, sh, close_now, spos, small_note = _v85_box_from_recent(df, lcol, hcol, ccol, 15)
        else:
            rng = sh - sl
            spos = ((close_now - sl) / rng) * 100.0 if rng > 0 else 50.0
        s_angle, s_slope, s_dir = _v85_slope_pack(df.iloc[max(0, len(df)-15):][ccol])
        if sl > 0 and sh > 0 and sh > sl:
            out['small_low'], out['small_high'], out['small_mid'] = round(sl, 2), round(sh, 2), round((sl + sh) / 2.0, 2)
            out['small_pos_pct'] = round(spos, 1)
            out['small_pos_label'] = _v85_pos_pct_label(spos)
            out['small_box_dir'] = s_dir
            out['small_angle'] = s_angle
            out['small_slope_pct'] = s_slope
            out['small_state'] = f"소파동 {out['small_pos_label']}"
            if spos >= 100:
                out['small_desc'] = '박스 상단 돌파 후 확장 구간'
            elif spos >= 80:
                out['small_desc'] = '소파동 상단부, 추격보다 눌림 확인'
            elif spos >= 65:
                out['small_desc'] = '소파동 중상단, 재안착 확인 우선'
            elif spos <= 25:
                out['small_desc'] = '소파동 하단권, 손절 짧은 관찰'
            else:
                out['small_desc'] = '박스 중간권, 방향 확인'
            out['blue_zone_low'] = round(sl + (sh - sl) * 0.55, 2)
            out['blue_zone_high'] = round(sl + (sh - sl) * 0.92, 2)
        else:
            out['small_state'] = '소파동 산출불가'
            out['small_desc'] = small_note or '최근 15봉 박스 산출 실패'

        bars = int(lookback or 60)
        ml, mh, close_now, mpos, mid_note = _v85_box_from_recent(df, lcol, hcol, ccol, bars)
        m_angle, m_slope, m_dir = _v85_slope_pack(df.iloc[max(0, len(df)-bars):][ccol])
        if ml > 0 and mh > 0 and mh > ml:
            out['mid_low'], out['mid_high'], out['mid_mid'] = round(ml, 2), round(mh, 2), round((ml + mh) / 2.0, 2)
            out['mid_pos_pct'] = round(mpos, 1)
            out['mid_pos_label'] = _v85_pos_pct_label(mpos)
            out['mid_box_dir'] = m_dir
            out['mid_angle'] = m_angle
            out['mid_slope_pct'] = m_slope
            out['mid_state'] = f"중파동 {out['mid_pos_label']}"
            if mpos >= 100:
                out['mid_desc'] = '중파동 박스 돌파 후 확장'
            elif mpos >= 80:
                out['mid_desc'] = '중파동 상단권, 저항 확인 필요'
            elif mpos <= 25:
                out['mid_desc'] = '중파동 하단권, 반등 확인 필요'
            else:
                out['mid_desc'] = '중파동 박스 내부'
        else:
            out['mid_state'] = '중파동 산출불가'
            out['mid_desc'] = mid_note or '최근 60봉 박스 산출 실패'

        out['debug_note'] = 'ok' if not small_note and not mid_note else ' / '.join([x for x in [small_note, mid_note] if x])
        return out
    except Exception as e:
        out['small_state'] = '소파동 산출불가'
        out['mid_state'] = '중파동 산출불가'
        out['debug_note'] = f'build_wave_levels error: {e}'
        return out

def _v85_wave_line(prefix, low, high, pct, label, direction, angle, slope):
    if _v85_num(low, 0) <= 0 or _v85_num(high, 0) <= 0:
        return f"{prefix}: 산출불가"
    line = f"{prefix}: 박스 {_v85_price(low)}~{_v85_price(high)}"
    if _v85_num(pct, -999) > -900:
        line += f" | 위치 {_v85_num(pct, 0):.0f}%({label or _v85_pos_pct_label(pct)})"
    if direction:
        line += f" | {direction} {_v85_num(angle, 0):+.1f}°({_v85_num(slope, 0):+.2f}%/봉)"
    return line

def _v85_row_dict(row):
    try:
        if isinstance(row, dict):
            return dict(row)
        if hasattr(row, 'to_dict'):
            return row.to_dict()
        return dict(row or {})
    except Exception:
        return {}

def _v85_wave_lines_from_row(row, include_debug=False):
    d = _v85_row_dict(row)
    lines = ['🌀 파동진단']
    small_low = _v85_num(d.get('소파동저점'), 0)
    small_high = _v85_num(d.get('소파동전고점'), 0)
    mid_low = _v85_num(d.get('중파동저점'), 0)
    mid_high = _v85_num(d.get('중파동전고점'), 0)

    if small_low > 0 and small_high > 0:
        lines.append(_v85_wave_line('〰️ 소파동', small_low, small_high, d.get('소파동위치퍼센트', 0), d.get('소파동위치권', ''), d.get('소파동박스방향', ''), d.get('소파동각도', 0), d.get('소파동기울기', 0)))
    else:
        note = str(d.get('소파동디버그노트', '') or '').strip()
        lines.append('〰️ 소파동: 산출불가' + (f' | {note}' if note else ''))

    if mid_low > 0 and mid_high > 0:
        lines.append(_v85_wave_line('📶 중파동', mid_low, mid_high, d.get('중파동위치퍼센트', 0), d.get('중파동위치권', ''), d.get('중파동박스방향', ''), d.get('중파동각도', 0), d.get('중파동기울기', 0)))
    else:
        note = str(d.get('소파동디버그노트', '') or '').strip()
        lines.append('📶 중파동: 산출불가' + (f' | {note}' if note else ''))

    bz_low = _v85_int(d.get('파란타점영역하단'), 0)
    bz_high = _v85_int(d.get('파란타점영역상단'), 0)
    if bz_low > 0 and bz_high > 0:
        lines.append(f"🔵 파란타점 영역: {bz_low:,} ~ {bz_high:,} | 점이 아니라 박스 안 지지 확인 구간")
    else:
        lines.append("🔵 파란타점 영역: 산출불가 | 소파동 박스 확인 필요")

    s_pct = _v85_num(d.get('소파동위치퍼센트'), -1)
    s_dir = str(d.get('소파동박스방향', '') or '')
    m_dir = str(d.get('중파동박스방향', '') or '')
    if s_dir.startswith('완만하향') or s_dir.startswith('강한하향'):
        interp = '단기 하향각이 있어 반등보다 하락각 둔화와 재안착 확인이 우선'
    elif s_pct >= 80:
        interp = '소파동 상단부, 매수는 눌림 재안착 확인이 유리'
    elif s_pct >= 65:
        interp = '소파동 중상단, 추격보다 눌림 재안착 확인이 유리'
    elif s_pct <= 25 and s_pct >= 0:
        interp = '소파동 하단권, 손절선 짧은 관찰 구간'
    elif '상향' in s_dir and '상향' in m_dir:
        interp = '소파동·중파동 모두 상향, 눌림 지지 후 재상승 관찰'
    else:
        interp = '박스 내부 위치 확인 후 지지·재양봉을 우선 확인'
    lines.append(f"🧭 파동해석: {interp}")

    if include_debug:
        lines.append(
            "🧪 파동디버그: "
            f"small={_v85_price(small_low)}~{_v85_price(small_high)} | "
            f"mid={_v85_price(mid_low)}~{_v85_price(mid_high)} | "
            f"cols={str(d.get('소파동디버그컬럼', '') or '-')} | "
            f"len={_v85_int(d.get('소파동디버그길이'), 0)} | "
            f"note={str(d.get('소파동디버그노트', '') or '-')}"
        )
    return lines

def _build_accumulation_overlay_lines(pkg):
    try:
        accum = (pkg or {}).get('accum', {}) or {}
        waves = (pkg or {}).get('waves', {}) or {}
        pos = (pkg or {}).get('position', {}) or {}
        d = {
            '소파동저점': waves.get('small_low', 0),
            '소파동전고점': waves.get('small_high', 0),
            '소파동위치퍼센트': waves.get('small_pos_pct', 0),
            '소파동위치권': waves.get('small_pos_label', ''),
            '소파동박스방향': waves.get('small_box_dir', ''),
            '소파동각도': waves.get('small_angle', 0),
            '소파동기울기': waves.get('small_slope_pct', 0),
            '중파동저점': waves.get('mid_low', 0),
            '중파동전고점': waves.get('mid_high', 0),
            '중파동위치퍼센트': waves.get('mid_pos_pct', 0),
            '중파동위치권': waves.get('mid_pos_label', ''),
            '중파동박스방향': waves.get('mid_box_dir', ''),
            '중파동각도': waves.get('mid_angle', 0),
            '중파동기울기': waves.get('mid_slope_pct', 0),
            '파란타점영역하단': waves.get('blue_zone_low', 0),
            '파란타점영역상단': waves.get('blue_zone_high', 0),
            '소파동디버그노트': waves.get('debug_note', ''),
            '소파동디버그컬럼': waves.get('debug_cols', ''),
            '소파동디버그길이': waves.get('debug_len', 0),
        }
        lines = []
        accum_tag = str(accum.get('label', '') or '').strip()
        accum_score = _v85_int(accum.get('score', 0), 0)
        accum_comment = str(accum.get('desc', '') or '').strip()
        if accum_tag and accum_tag != '매집봉 없음':
            lines.append(f"🪵 매집봉: {accum_tag} ({accum_score})" + (f" | {accum_comment}" if accum_comment else ''))
        lines.extend(_v85_wave_lines_from_row(d, include_debug=False))
        pos_label = str(pos.get('label', '') or '').strip()
        if pos_label:
            pos_score = _v85_int(pos.get('score', 0), 0)
            pos_desc = str(pos.get('desc', '') or '').strip()
            lines.append(f"🪑 자리평가: {pos_label} ({pos_score})" + (f" | {pos_desc}" if pos_desc else ''))
        return lines
    except Exception as e:
        return [f"🌀 파동진단", f"〰️ 소파동: 표시 실패 | {e}"]

try:
    _V85_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY = enrich_row_with_human_commentary
except Exception:
    _V85_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY = None

def enrich_row_with_human_commentary(row):
    if _V85_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY:
        try:
            base = _V85_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY(row)
        except Exception:
            base = _v85_row_dict(row)
    else:
        base = _v85_row_dict(row)
    try:
        source = _v85_row_dict(row)
        source.update(_v85_row_dict(base))
        block = str(base.get('interpretation_block', '') or '')
        if '〰️ 소파동:' not in block and '📶 중파동:' not in block:
            wave_lines = _v85_wave_lines_from_row(source, include_debug=False)
            wave_text = '\n'.join(wave_lines)
            if '✅ 최종 판정:' in block:
                block = block.replace('✅ 최종 판정:', wave_text + '\n✅ 최종 판정:', 1)
            elif '🧮 점수 해석:' in block:
                block = block.replace('🧮 점수 해석:', wave_text + '\n🧮 점수 해석:', 1)
            else:
                block = (block.rstrip() + '\n' + wave_text).strip()
            base['interpretation_block'] = block
    except Exception as e:
        try:
            base['interpretation_block'] = str(base.get('interpretation_block', '') or '').rstrip() + f"\n🌀 파동진단 표시 실패 | {e}"
        except Exception:
            pass
    return base

try:
    _V85_BASE_APPEND_TRADE_BLOCK_ONCE = _v5_append_trade_block_once
except Exception:
    _V85_BASE_APPEND_TRADE_BLOCK_ONCE = None

def _v5_append_trade_block_once(text, row):
    try:
        out = _V85_BASE_APPEND_TRADE_BLOCK_ONCE(text, row) if _V85_BASE_APPEND_TRADE_BLOCK_ONCE else str(text or '')
    except Exception:
        out = str(text or '')
    try:
        if '〰️ 소파동:' not in out and '📶 중파동:' not in out:
            wave_lines = _v85_wave_lines_from_row(row, include_debug=False)
            wave_text = '\n'.join(wave_lines)
            if '\n✅ 구조판정:' in out:
                out = out.replace('\n✅ 구조판정:', '\n' + wave_text + '\n\n✅ 구조판정:', 1)
            elif '✅ 구조판정:' in out:
                out = out.replace('✅ 구조판정:', wave_text + '\n\n✅ 구조판정:', 1)
            else:
                out = out.rstrip() + '\n' + wave_text
    except Exception as e:
        out = str(out).rstrip() + f"\n🌀 파동진단 표시 실패 | {e}"
    return str(out).rstrip() + '\n'

try:
    _V85_BASE_APPEND_INTERPRETATION_TO_BLOCK = append_interpretation_to_block
except Exception:
    _V85_BASE_APPEND_INTERPRETATION_TO_BLOCK = None

def append_interpretation_to_block(block, row):
    try:
        out = _V85_BASE_APPEND_INTERPRETATION_TO_BLOCK(block, row) if _V85_BASE_APPEND_INTERPRETATION_TO_BLOCK else str(block or '')
    except Exception:
        out = str(block or '')
    return _v5_append_trade_block_once(out, row)

def build_integrated_stock_block(block: str, row) -> str:
    return append_interpretation_to_block(block, row)

