def _v86_num(v, default=0.0):
    try:
        return _v85_num(v, default)
    except Exception:
        try:
            if v is None:
                return default
            s = str(v).replace(',', '').replace('%', '').strip()
            if not s:
                return default
            import re as _re
            m = _re.search(r'-?\d+(?:\.\d+)?', s)
            return float(m.group(0)) if m else default
        except Exception:
            return default


def _v86_int(v, default=0):
    try:
        return int(round(_v86_num(v, default)))
    except Exception:
        return default


def _v86_price(v):
    try:
        return _v85_price(v)
    except Exception:
        n = _v86_int(v, 0)
        return f"{n:,}" if n > 0 else '-'


def _v86_row_dict(row):
    try:
        return _v85_row_dict(row)
    except Exception:
        try:
            if isinstance(row, dict):
                return dict(row)
            if hasattr(row, 'to_dict'):
                return row.to_dict()
            return dict(row or {})
        except Exception:
            return {}


def _v86_get_current_price(row_or_dict):
    d = _v86_row_dict(row_or_dict)
    for key in (
        '현재가', '현재가격', '현재가_raw', 'current_price', 'price',
        'Close', 'close', '종가', '현재종가', 'last_close', 'Last', 'last'
    ):
        val = _v86_num(d.get(key), 0.0)
        if val > 0:
            return val
    return 0.0


def _v86_blue_zone_line(row_or_dict, bz_low=None, bz_high=None):
    d = _v86_row_dict(row_or_dict)
    low = _v86_num(bz_low if bz_low is not None else d.get('파란타점영역하단'), 0.0)
    high = _v86_num(bz_high if bz_high is not None else d.get('파란타점영역상단'), 0.0)
    if low <= 0 or high <= 0:
        return '🔵 파란타점 영역: 산출불가 | 소파동 박스 확인 필요'
    if high < low:
        low, high = high, low
    cur = _v86_get_current_price(d)
    low_s, high_s = _v86_price(low), _v86_price(high)
    if cur <= 0:
        return f"🔵 파란타점 영역: {low_s} ~ {high_s} | 현재가 확인 불가, 박스 안 지지 확인 구간"
    if cur < low:
        gap = ((low / cur) - 1.0) * 100.0 if cur > 0 else 0.0
        return f"🔵 파란타점 재안착대: {low_s} ~ {high_s} | 현재가 아래, 회복·재안착 확인 구간(+{gap:.1f}%)"
    if cur > high:
        gap = ((cur / high) - 1.0) * 100.0 if high > 0 else 0.0
        return f"🔵 파란타점 지지대: {low_s} ~ {high_s} | 이미 통과, 눌림 지지 확인 구간(+{gap:.1f}%)"
    return f"🔵 파란타점 영역: {low_s} ~ {high_s} | 현재가 구간 안, 박스 안 지지 확인 구간"


def _v86_wave_interp_from_row(row_or_dict):
    d = _v86_row_dict(row_or_dict)
    sdir = str(d.get('소파동박스방향', '') or '')
    mdir = str(d.get('중파동박스방향', '') or '')
    spos_label = str(d.get('소파동위치권', '') or '')
    mpos_label = str(d.get('중파동위치권', '') or '')
    s_pct = _v86_num(d.get('소파동위치퍼센트'), -999.0)
    m_pct = _v86_num(d.get('중파동위치퍼센트'), -999.0)
    bz_low = _v86_num(d.get('파란타점영역하단'), 0.0)
    bz_high = _v86_num(d.get('파란타점영역상단'), 0.0)
    cur = _v86_get_current_price(d)

    s_up = '상향' in sdir
    m_up = '상향' in mdir
    s_down = '하향' in sdir
    m_down = '하향' in mdir
    s_top = (s_pct >= 80) or ('상단' in spos_label) or ('전고점' in spos_label) or ('돌파' in spos_label)
    m_top = (m_pct >= 80) or ('상단' in mpos_label) or ('전고점' in mpos_label) or ('돌파' in mpos_label)
    s_low = (0 <= s_pct <= 25) or ('하단권' in spos_label)
    m_low = (0 <= m_pct <= 25) or ('하단권' in mpos_label)

    if cur > 0 and bz_low > 0 and bz_high > 0:
        if bz_high < bz_low:
            bz_low, bz_high = bz_high, bz_low
        if cur < bz_low:
            return '파란타점 재안착대 아래, 먼저 회복·재안착 확인이 필요합니다'
        if cur > bz_high and s_top:
            return '파란타점 지지대를 이미 통과한 상단부, 추격보다 눌림 지지 확인이 유리합니다'

    if s_down and m_down:
        return '소파동·중파동 모두 하향, 반등보다 하락각 둔화 확인이 우선입니다'
    if s_up and m_down:
        return '단기 반등은 있으나 중파동은 하향, 추격보다 저항 확인이 우선입니다'
    if s_down and m_up:
        return '중파동은 살아있지만 소파동이 눌림 중, 5일선 재안착과 재양봉 확인이 필요합니다'
    if s_up and m_up:
        if s_top or m_top:
            return '소파동·중파동 모두 상향이나 상단권, 눌림 지지 후 재상승 관찰이 유리합니다'
        return '소파동·중파동 모두 상향, 눌림 지지 후 재상승 관찰 구간입니다'
    if s_top:
        return '소파동 상단부, 매수는 눌림 재안착 확인이 유리합니다'
    if s_low and (m_up or '횡보' in mdir):
        return '소파동 하단권, 손절선 짧은 관찰 구간입니다'
    if m_low:
        return '중파동 하단권, 반등 확인 전까지는 분할 관찰이 유리합니다'
    return '박스 내부 위치 확인 후 지지·재양봉을 우선 확인합니다'


def _v86_wave_line(prefix, low, high, pct, label, direction, angle, slope):
    try:
        return _v85_wave_line(prefix, low, high, pct, label, direction, angle, slope)
    except Exception:
        if _v86_num(low, 0) <= 0 or _v86_num(high, 0) <= 0:
            return f"{prefix}: 산출불가"
        line = f"{prefix}: 박스 {_v86_price(low)}~{_v86_price(high)}"
        if _v86_num(pct, -999) > -900:
            line += f" | 위치 {_v86_num(pct, 0):.0f}%({label or ''})"
        if direction:
            line += f" | {direction} {_v86_num(angle, 0):+.1f}°({_v86_num(slope, 0):+.2f}%/봉)"
        return line


def _v86_wave_lines_from_row(row, include_debug=False):
    d = _v86_row_dict(row)
    lines = []
    small_low = _v86_num(d.get('소파동저점'), 0)
    small_high = _v86_num(d.get('소파동전고점'), 0)
    mid_low = _v86_num(d.get('중파동저점'), 0)
    mid_high = _v86_num(d.get('중파동전고점'), 0)

    if small_low > 0 and small_high > 0:
        lines.append(_v86_wave_line(
            '〰️ 소파동', small_low, small_high,
            d.get('소파동위치퍼센트', 0), d.get('소파동위치권', ''),
            d.get('소파동박스방향', ''), d.get('소파동각도', 0), d.get('소파동기울기', 0)
        ))
    else:
        note = str(d.get('소파동디버그노트', '') or '').strip()
        lines.append('〰️ 소파동: 산출불가' + (f' | {note}' if note else ''))

    if mid_low > 0 and mid_high > 0:
        lines.append(_v86_wave_line(
            '📶 중파동', mid_low, mid_high,
            d.get('중파동위치퍼센트', 0), d.get('중파동위치권', ''),
            d.get('중파동박스방향', ''), d.get('중파동각도', 0), d.get('중파동기울기', 0)
        ))
    else:
        note = str(d.get('소파동디버그노트', '') or '').strip()
        lines.append('📶 중파동: 산출불가' + (f' | {note}' if note else ''))

    lines.append(_v86_blue_zone_line(d))
    lines.append(f"🧭 파동해석: {_v86_wave_interp_from_row(d)}")

    if include_debug:
        lines.append(
            "🧪 파동디버그: "
            f"small={_v86_price(small_low)}~{_v86_price(small_high)} | "
            f"mid={_v86_price(mid_low)}~{_v86_price(mid_high)} | "
            f"cols={str(d.get('소파동디버그컬럼', '') or '-')} | "
            f"len={_v86_int(d.get('소파동디버그길이'), 0)} | "
            f"note={str(d.get('소파동디버그노트', '') or '-')}"
        )
    return lines


def _v86_patch_existing_wave_text(text, row):
    """기존 출력에 파동 라인이 있으면 파란타점 문구와 해석 누락만 보정한다."""
    try:
        import re as _re
        out = str(text or '')
        d = _v86_row_dict(row)
        blue_line = _v86_blue_zone_line(d)
        interp_line = f"🧭 파동해석: {_v86_wave_interp_from_row(d)}"

        # 기존 파란타점 라인을 현재가 위치별 문구로 교체
        if '🔵 파란타점' in out:
            out = _re.sub(r'🔵 파란타점[^\n]*', blue_line, out, count=1)

        # 기존 파동해석은 새 규칙으로 1회 교체, 없으면 파란타점/중파동 뒤에 삽입
        if '🧭 파동해석:' in out:
            out = _re.sub(r'🧭 파동해석:[^\n]*', interp_line, out, count=1)
        elif '🔵 파란타점' in out:
            out = _re.sub(r'(🔵 파란타점[^\n]*)(\n)', r'\1\2' + interp_line + '\n', out, count=1)
        elif '📶 중파동:' in out:
            out = _re.sub(r'(📶 중파동:[^\n]*)(\n)', r'\1\2' + interp_line + '\n', out, count=1)
        return out
    except Exception:
        return str(text or '')


def _v86_insert_or_patch_wave_text(text, row):
    out = str(text or '')
    try:
        if '〰️ 소파동:' in out or '📶 중파동:' in out or '🔵 파란타점' in out:
            return _v86_patch_existing_wave_text(out, row)
        wave_text = '\n'.join(_v86_wave_lines_from_row(row, include_debug=False))
        if '\n✅ 최종 판정:' in out:
            out = out.replace('\n✅ 최종 판정:', '\n' + wave_text + '\n✅ 최종 판정:', 1)
        elif '\n🧮 점수 해석:' in out:
            out = out.replace('\n🧮 점수 해석:', '\n' + wave_text + '\n🧮 점수 해석:', 1)
        elif '\n✅ 구조판정:' in out:
            out = out.replace('\n✅ 구조판정:', '\n' + wave_text + '\n\n✅ 구조판정:', 1)
        elif '✅ 구조판정:' in out:
            out = out.replace('✅ 구조판정:', wave_text + '\n\n✅ 구조판정:', 1)
        else:
            out = out.rstrip() + '\n' + wave_text
        return out
    except Exception as e:
        return str(out).rstrip() + f"\n🌀 파동진단 표시 실패 | {e}"


# build_wave_levels는 V8.5 계산식을 유지하되, 아래 overlay/출력 문구만 V8.6으로 덮어쓴다.
