def enrich_row_with_human_commentary(row):
    if _V86_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY:
        try:
            base = _V86_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY(row)
        except Exception:
            base = _v86_row_dict(row)
    else:
        base = _v86_row_dict(row)
    try:
        source = _v86_row_dict(row)
        source.update(_v86_row_dict(base))
        block = str(base.get('interpretation_block', '') or '')
        base['interpretation_block'] = _v86_insert_or_patch_wave_text(block, source).strip()
    except Exception as e:
        try:
            base['interpretation_block'] = str(base.get('interpretation_block', '') or '').rstrip() + f"\n🌀 파동진단 표시 실패 | {e}"
        except Exception:
            pass
    return base


