def _v87_jsonable(value):
    """JSON 저장용 안전 변환: pandas/numpy/NaN/Timestamp 방어."""
    try:
        if value is None:
            return ""
        try:
            if pd.isna(value):
                return ""
        except Exception:
            pass
        if isinstance(value, (str, int, float, bool)):
            return value
        if hasattr(value, "item"):
            try:
                return value.item()
            except Exception:
                pass
        if hasattr(value, "isoformat"):
            try:
                return value.isoformat()
            except Exception:
                pass
        if isinstance(value, dict):
            return {str(k): _v87_jsonable(v) for k, v in value.items()}
        if isinstance(value, (list, tuple, set)):
            return [_v87_jsonable(v) for v in value]
        return str(value)
    except Exception:
        return str(value)


def _v87_safe_float(value, default=0.0):
    try:
        if value is None:
            return default
        try:
            if pd.isna(value):
                return default
        except Exception:
            pass
        txt = str(value).replace(',', '').strip()
        if not txt:
            return default
        return float(txt)
    except Exception:
        return default


def _v87_safe_int(value, default=0):
    try:
        return int(round(_v87_safe_float(value, default)))
    except Exception:
        return default


def _v87_row_dict(row):
    try:
        if hasattr(row, 'to_dict'):
            return row.to_dict()
        if isinstance(row, dict):
            return dict(row)
        return dict(row)
    except Exception:
        return {}


def _v87_pick(d, *keys, default=""):
    for k in keys:
        try:
            v = d.get(k, "")
        except Exception:
            v = ""
        if v is None:
            continue
        try:
            if pd.isna(v):
                continue
        except Exception:
            pass
        if str(v).strip() != "":
            return v
    return default


def _v87_norm_code(value):
    try:
        s = ''.join(ch for ch in str(value or '') if ch.isdigit())
        return s.zfill(6)[-6:] if s else ''
    except Exception:
        return ''


def _v87_quick_block_reason(d):
    """빠른검색 기본 JSON에서 제외할 사유. full JSON에는 사유만 기록."""
    text_parts = []
    for k in [
        '추천단계', '매매판정', '최종판정', 'AI최종판정', '수박최종상태', '수박상태명',
        '수박정제태그', '수박정제코멘트', 'N구분', '저항구름태그', '후행유형', 'interpretation_block'
    ]:
        try:
            text_parts.append(str(d.get(k, '') or ''))
        except Exception:
            pass
    txt = ' '.join(text_parts)
    for bad in ['추격 금지', '보유자 대응', '후행수박', '가짜수박주의']:
        if bad in txt:
            return bad
    disp = _v87_safe_float(_v87_pick(d, '이격', 'Disparity', default=0), 0)
    rsi = _v87_safe_float(_v87_pick(d, 'RSI', 'RSI14', default=0), 0)
    if disp >= 115:
        return f'이격{disp:.0f}↑'
    if rsi >= 70:
        return f'RSI{rsi:.0f}↑'
    return ''


def _v87_row_to_candidate_item(row, source='후보군', rank=0):
    d = _v87_row_dict(row)
    code = _v87_norm_code(_v87_pick(d, 'code', '종목코드', 'Code', 'ticker', default=''))
    if not code:
        return None
    name = str(_v87_pick(d, '종목명', 'name', 'Name', '종목', default=code) or code).strip()
    status = str(_v87_pick(d, '수박최종상태', '수박상태명', '상태', '최종상태', '추천단계', default='') or '').strip()
    decision = str(_v87_pick(d, '매매판정', '최종판정', 'AI최종판정', '추천단계', default='') or '').strip()
    grade = str(_v87_pick(d, 'N등급', '등급', 'grade', default='') or '').strip()
    tag_bits = []
    for k in ['N조합', 'N구분', '수박정제태그', '저항구름태그', '5일재안착태그']:
        v = str(d.get(k, '') or '').strip()
        if v and v.lower() not in ('nan', 'none', 'null'):
            tag_bits.append(v)
    block_reason = _v87_quick_block_reason(d)
    return {
        'code': code,
        'name': name,
        '종목코드': code,
        '종목명': name,
        'source': source,
        'rank': rank,
        'status': status,
        '상태': status,
        'decision': decision,
        '판정': decision,
        'grade': grade,
        '등급': grade,
        'tags': ' '.join(tag_bits)[:300],
        '현재가': _v87_safe_int(_v87_pick(d, '현재가', 'Close', '종가', default=0)),
        '이격': round(_v87_safe_float(_v87_pick(d, '이격', 'Disparity', default=0), 0), 2),
        'RSI': round(_v87_safe_float(_v87_pick(d, 'RSI', 'RSI14', default=0), 0), 2),
        '안전점수': _v87_safe_int(_v87_pick(d, '안전점수', default=0)),
        'N점수': _v87_safe_int(_v87_pick(d, 'N점수', default=0)),
        '선취점수': _v87_safe_int(_v87_pick(d, '선취점수', '단테선취점수', default=0)),
        '돌파점수': _v87_safe_int(_v87_pick(d, '돌파점수', '흰구름돌파점수', default=0)),
        '수급': str(_v87_pick(d, '수급', '수급요약', default='') or '').strip(),
        '수급판정': str(_v87_pick(d, '수급판정', default='') or '').strip(),
        '저항구름': str(_v87_pick(d, '저항구름태그', '저항구름상태', default='') or '').strip(),
        '정제': str(_v87_pick(d, '수박정제태그', default='') or '').strip(),
        'quick_blocked': bool(block_reason),
        'quick_block_reason': block_reason,
    }


def _v87_df_to_candidate_items(df, source='후보군', limit=20, include_blocked=False):
    items = []
    try:
        if df is None or getattr(df, 'empty', True):
            return []
        work = df.head(limit).copy() if hasattr(df, 'head') else df
        for i, (_, row) in enumerate(work.iterrows(), 1):
            item = _v87_row_to_candidate_item(row, source=source, rank=i)
            if not item:
                continue
            if (not include_blocked) and item.get('quick_blocked'):
                continue
            items.append(item)
    except Exception as e:
        try:
            log_error(f"⚠️ 빠른검색 후보 변환 실패({source}): {e}")
        except Exception:
            pass
    return items


def _v87_dedupe_items(items, limit=40):
    seen = set()
    out = []
    for item in items:
        code = _v87_norm_code(item.get('code') or item.get('종목코드'))
        if not code or code in seen:
            continue
        seen.add(code)
        item['code'] = code
        item['종목코드'] = code
        out.append(item)
        if limit and len(out) >= limit:
            break
    return out


