# ✅ V9.0: 거래대금 상위 60개 빠른검색 우주 저장
# - 본진 스캔 우주 TOP_N(기본 700)과 별개로, 빠른검색 전용 amount_top60을 항상 저장
# - today_candidates.json 안에도 amount_top60 + strategy_candidates + merged quick_candidates를 함께 기록
# =============================================================

def _v90_amount_top_n():
    try:
        return max(1, _v87_safe_int(os.getenv('AMOUNT_TOP_N', '60'), 60))
    except Exception:
        return 60


def _v90_amount_raw_to_b(value):
    """거래대금 원 단위를 억 단위로 변환. 이미 억 단위처럼 작은 값이면 그대로 보정."""
    try:
        v = _v87_safe_float(value, 0.0)
        if v <= 0:
            return 0.0
        # KRX/FDR Amount는 보통 원 단위. 100만 초과면 억 단위 변환.
        return round(v / 100000000.0, 1) if v > 1000000 else round(v, 1)
    except Exception:
        return 0.0


def _v90_row_to_amount_item(row, rank=0):
    """거래대금 TOP60 원본 우주용 item. 과열/후행 필터를 걸지 않는다."""
    d = _v87_row_dict(row)
    code = _v87_norm_code(_v87_pick(d, 'code', '종목코드', 'Code', 'ticker', default=''))
    if not code:
        return None
    name = str(_v87_pick(d, '종목명', 'name', 'Name', '종목', default=code) or code).strip()
    amount_raw = _v87_pick(d, 'Amount', '거래대금', 'Value', 'Turnover', default=0)
    price = _v87_safe_int(_v87_pick(d, 'Close', 'Price', '현재가', '종가', default=0), 0)
    market = str(_v87_pick(d, 'Market', '시장', default='') or '').strip()
    change_rate = round(_v87_safe_float(_v87_pick(d, 'ChangeRate', 'Change', '등락률', default=0), 0.0), 2)
    return {
        'code': code,
        'name': name,
        '종목코드': code,
        '종목명': name,
        'source': '거래대금TOP60',
        'universe_group': 'amount_top60',
        'rank': int(rank or 0),
        '시장': market,
        '현재가': price,
        '등락률': change_rate,
        '거래대금': _v87_safe_int(amount_raw, 0),
        '거래대금B': _v90_amount_raw_to_b(amount_raw),
        'amount_b': _v90_amount_raw_to_b(amount_raw),
        'status': '거래대금상위',
        '상태': '거래대금상위',
        'decision': '빠른검색 우주',
        '판정': '빠른검색 우주',
        'tags': '거래대금상위60 빠른검색용',
        'quick_blocked': False,
        'quick_block_reason': '',
    }


def _v90_df_to_amount_items(df, limit=None):
    items = []
    try:
        if df is None or getattr(df, 'empty', True):
            return []
        n = int(limit or _v90_amount_top_n())
        work = df.copy()
        if 'Amount' in work.columns:
            try:
                work = coerce_numeric_columns(work, ['Amount'])
            except Exception:
                work['Amount'] = pd.to_numeric(work['Amount'], errors='coerce').fillna(0)
            work = work.sort_values('Amount', ascending=False, na_position='last')
        work = work.head(n)
        for i, (_, row) in enumerate(work.iterrows(), 1):
            item = _v90_row_to_amount_item(row, rank=i)
            if item:
                items.append(item)
    except Exception as e:
        try:
            log_error(f"⚠️ 거래대금 TOP60 변환 실패: {e}")
        except Exception:
            pass
    return items


def _v90_export_amount_top_json(amount_top60_df=None, amount_items=None):
    """amount_top60.json과 날짜별 백업을 별도 저장한다."""
    try:
        n = _v90_amount_top_n()
        if amount_items is None:
            amount_items = _v90_df_to_amount_items(amount_top60_df, limit=n)
        out_path = os.getenv('QUICK_AMOUNT_TOP_JSON', 'amount_top60.json') or 'amount_top60.json'
        date_key = str(globals().get('TODAY_STR', '') or '')
        if not date_key:
            try:
                date_key = NOW.strftime('%Y-%m-%d')
            except Exception:
                date_key = ''
        backup_path = f"quick_candidates/amount_top60_{date_key}.json" if date_key else "quick_candidates/amount_top60_latest.json"
        payload = {
            'generated_at': str(datetime.now(KST).strftime('%Y-%m-%d %H:%M:%S')) if 'KST' in globals() else str(datetime.now()),
            'date': date_key,
            'purpose': 'amount_top60 quick universe',
            'rules': '가격/시총/ETF·ETN·스팩·우선주 필터 후 거래대금 상위 60개',
            'amount_top60': amount_items or [],
        }
        ok1 = _v87_write_json(out_path, payload)
        ok2 = _v87_write_json(backup_path, payload)
        try:
            log_info(f"✅ 거래대금 TOP{n} JSON 생성 완료: {out_path} {len(amount_items or [])}개 / 백업 {backup_path}")
        except Exception:
            pass
        return ok1 and ok2
    except Exception as e:
        try:
            log_error(f"🚨 거래대금 TOP60 JSON 생성 실패: {e}")
        except Exception:
            pass
        return False


def _v87_write_json(path, data):
    try:
        p = Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        with p.open('w', encoding='utf-8-sig') as f:
            json.dump(_v87_jsonable(data), f, ensure_ascii=False, indent=2)
        return True
    except Exception as e:
        try:
            log_error(f"⚠️ 빠른검색 JSON 저장 실패({path}): {e}")
        except Exception:
            pass
        return False


def _v87_export_quick_candidates_json(**frames):
    """
    생성 파일
    - today_candidates.json: quick_open_checker.py 기본 입력. 거래대금 TOP60 + 전략 후보 병합.
    - today_candidates_full.json: 감사용 전체 후보. 제외 사유 포함.
    - amount_top60.json: 거래대금 상위 60개 빠른검색 우주 원본.
    - quick_candidates/today_candidates_YYYY-MM-DD.json: 날짜별 백업.
    """
    try:
        limit = _v87_safe_int(os.getenv('QUICK_CANDIDATE_LIMIT', '40'), 40)
        amount_limit = _v90_amount_top_n() if '_v90_amount_top_n' in globals() else 60
        merged_limit = _v87_safe_int(os.getenv('QUICK_MERGED_LIMIT', str(max(limit, amount_limit + 20))), max(limit, amount_limit + 20))
        out_path = os.getenv('QUICK_CANDIDATE_JSON', 'today_candidates.json') or 'today_candidates.json'
        full_path = os.getenv('QUICK_CANDIDATE_FULL_JSON', 'today_candidates_full.json') or 'today_candidates_full.json'
        date_key = str(globals().get('TODAY_STR', '') or '')
        if not date_key:
            try:
                date_key = NOW.strftime('%Y-%m-%d')
            except Exception:
                date_key = ''
        backup_path = f"quick_candidates/today_candidates_{date_key}.json" if date_key else "quick_candidates/today_candidates_latest.json"

        ordered_sources = [
            ('재점화/파란타점', frames.get('wm_blue_top5')),
            ('Blue-2스윙', frames.get('wm_blue2_top5')),
            ('수박빨강', frames.get('wm_red_top5')),
            ('선취후보', frames.get('dante_pick_df')),
            ('돌파후보', frames.get('breakout_pick_df')),
            ('돌파관찰', frames.get('breakout_watch_df')),
            ('눌림수박', frames.get('wm_pullback_top5')),
            ('선취관찰', frames.get('dante_watch_df')),
            ('초입수박', frames.get('wm_intro_top5')),
            ('TOP15', frames.get('telegram_targets')),
            ('전체AI후보', frames.get('ai_candidates')),
        ]

        quick_flat = []
        full_groups = {}
        for source, df in ordered_sources:
            full_items = _v87_df_to_candidate_items(df, source=source, limit=20, include_blocked=True)
            focus_items = [x for x in full_items if not x.get('quick_blocked')]
            if full_items:
                full_groups[source] = full_items
            quick_flat.extend(focus_items)

        # ✅ V9.0: 거래대금 TOP60은 전략 필터와 별개인 빠른검색 우주이므로 별도 선두 병합
        amount_items = []
        try:
            amount_items = _v90_df_to_amount_items(frames.get('amount_top60_df'), limit=amount_limit) if '_v90_df_to_amount_items' in globals() else []
        except Exception as e:
            try: log_error(f"⚠️ amount_top60 병합 실패: {e}")
            except Exception: pass
            amount_items = []
        if amount_items:
            full_groups['거래대금TOP60'] = amount_items
            try:
                _v90_export_amount_top_json(amount_items=amount_items)
            except Exception:
                pass

        strategy_items = _v87_dedupe_items(quick_flat, limit=limit)
        quick_items = _v87_dedupe_items((amount_items or []) + strategy_items, limit=merged_limit)
        payload = {
            'generated_at': str(datetime.now(KST).strftime('%Y-%m-%d %H:%M:%S')) if 'KST' in globals() else str(datetime.now()),
            'date': date_key,
            'purpose': 'quick_open_checker.py input',
            'rules': '거래대금TOP60 + 전략후보 병합. 전략후보는 추격금지/보유자대응/후행수박/가짜수박주의/이격115↑/RSI70↑ 기본 제외',
            'quick_candidates': quick_items,
            'amount_top60': amount_items,
            'strategy_candidates': strategy_items,
        }
        full_payload = {
            'generated_at': payload['generated_at'],
            'date': date_key,
            'purpose': 'audit_full_candidates_for_quick_open',
            'groups': full_groups,
            'amount_top60_count': len(amount_items or []),
            'strategy_candidate_count': len(strategy_items or []),
            'merged_quick_count': len(quick_items or []),
        }

        ok1 = _v87_write_json(out_path, payload)
        ok2 = _v87_write_json(full_path, full_payload)
        ok3 = _v87_write_json(backup_path, payload)
        try:
            log_info(f"✅ 빠른검색 JSON 생성 완료: {out_path} 병합 {len(quick_items)}개 = 거래대금TOP60 {len(amount_items or [])}개 + 전략 {len(strategy_items or [])}개 / 감사용 {full_path} / 백업 {backup_path}")
            if len(quick_items) == 0:
                log_error("⚠️ today_candidates.json 후보 0개 — 빠른검색은 실행되지만 후보 없음 메시지만 전송됩니다.")
        except Exception:
            pass
        return ok1 and ok2 and ok3
    except Exception as e:
        try:
            log_error(f"🚨 빠른검색 JSON 생성 전체 실패: {e}")
        except Exception:
            pass
        return False

