def append_interpretation_to_block(block, row):
    try:
        out = _V88_BASE_APPEND_INTERPRETATION_TO_BLOCK(block, row) if _V88_BASE_APPEND_INTERPRETATION_TO_BLOCK else str(block or '')
    except Exception:
        out = str(block or '')
    return _v88_insert_or_patch_wave_text(out, row).rstrip() + '\n'


def build_integrated_stock_block(block: str, row) -> str:
    return append_interpretation_to_block(block, row)

