    strong={'수주':16,'공급계약':16,'계약':12,'공급':10,'실적':12,'영업익':12,'흑자':12,'승인':14,'허가':14,'임상':12,'특허':10,'정책':12,'국책':12,'증설':12,'투자':10,'인수':10,'합병':8}
    theme={'ai':8,'인공지능':8,'반도체':8,'hbm':10,'온디바이스':8,'로봇':8,'전력':8,'전선':8,'원전':10,'우라늄':10,'방산':8,'데이터센터':10,'냉각':8,'조선':8,'해운':6,'바이오':6,'신약':8,'비만':6,'화장품':6,'철강':6}
    bad={'조회공시':8,'풍문':8,'부인':14,'해명':8,'무관':14,'소송':12,'상장폐지':55,'상장 폐지':55,'주식교환':45,'주식 교환':45,'공개매수':45,'거래정지':55,'정리매매':60,'관리종목':40,'감사의견':45,'횡령':60,'배임':60,'유상증자':20,'감자':35,'불성실':35,'투자주의환기':35}
    for dic in (strong,theme):
        for k,v in dic.items():
            if k.lower() in low: pos+=v; pr.append(f'{k}+{v}')
