    if any(k in supply for k in ['개인매도흡수','동반매수','강매집','외인매수','기관매수','쌍끌']): sup+=10; sr.append('수급동행+10')
    if pos<=0 and sup>18: sup=18; sr.append('직접재료부족:보조상한')
    ev=_v91_event_reason(item); raw=pos+sup-neg
    if ev: raw=min(raw,15); nr.insert(0,'이벤트주의:'+ev)
    score=max(0,min(100,int(raw)))
    if ev: tag='⛔이벤트주의'; base='상장폐지·주식교환·공개매수·거래정지성 키워드가 있어 차트점수와 별개로 신규매수 제외가 우선입니다.'
    elif score>=80: tag='🔥재료강함'; base='뉴스/공시 재료와 수급·가격 보조조건이 함께 살아 있습니다.'
    elif score>=60: tag='🟢재료유효'; base='재료는 유효하지만 후속 뉴스와 섹터 동행 확인이 필요합니다.'
    elif score>=40: tag='🟡재료확인'; base='재료 단서는 있으나 강한 지속성은 아직 확인 전입니다.'
    elif score>=20: tag='⚪재료약함'; base='테마/보조 단서는 있으나 공시·계약·실적 같은 직접 재료가 약합니다.'
