    detail=[f'직접재료 {pos}점',f'보조 {sup}점'] + ([f'주의 -{neg}점'] if neg else [])
    detail.append('근거 '+('/'.join(pr[:4]) if pr else '/'.join(sr[:4]) if sr else '없음'))
