try:
    _V93_BASE_MATERIAL_SCORE = calc_material_survival_score
except Exception:
    _V93_BASE_MATERIAL_SCORE = None


def calc_material_survival_score(item) -> dict:
    d = _v93_to_dict(item)
    text = _v93_text_blob(d)

    novelty_map = {
        '오늘': 3, '금일': 3, '공시': 5, '신규': 5, '최초': 5, '단독': 5,
        '수주': 6, '계약': 5, '공급계약': 7, '공급': 4, '승인': 6, '허가': 6,
        '증설': 5, '출시': 4, 'mou': 4, '양해각서': 4
    }
    strength_map = {
        '상한가': 8, '급등': 5, '수주': 7, '공급계약': 7, '대규모': 6,
        '흑자전환': 7, '최대': 6, '실적': 5, '영업익': 6, '매출': 4,
        '정책': 5, '정부': 5, '국책': 6, 'ai': 4, '로봇': 4, '반도체': 4,
        'hbm': 5, '원전': 5, '방산': 4, '전력': 4, '데이터센터': 5
    }
    sustain_map = {
        '장기': 4, '중장기': 5, '정책': 5, '수혜': 4, '공급망': 4, '증설': 5,
        '투자': 4, '수주잔고': 6, '실적개선': 5, '성장': 3, '확대': 3,
        '재평가': 4, '구조적': 5
    }
    spread_map = {
        '섹터': 5, '테마': 4, '업종': 4, '동반': 4, '관련주': 4,
        '대장주': 5, '전반': 3, '수혜주': 4, '밸류체인': 5, '확산': 4
    }
    bad_map = {
        '상장폐지': 45, '상장 폐지': 45, '거래정지': 45, '정리매매': 50,
        '관리종목': 35, '감사의견': 35, '횡령': 45, '배임': 45,
        '불성실': 30, '투자주의환기': 30, '감자': 30, '유상증자': 15,
        '주식교환': 35, '공개매수': 30, '소송': 18
    }

    novelty, novelty_hits = _v93_count_kw(text, novelty_map, 20)
    strength, strength_hits = _v93_count_kw(text, strength_map, 20)
    sustain, sustain_hits = _v93_count_kw(text, sustain_map, 20)
    spread, spread_hits = _v93_count_kw(text, spread_map, 20)
    negative, bad_hits = _v93_count_kw(text, bad_map, 50)

    # 수급보조는 총점에는 더하되, 순수재료 판정에는 섞지 않는다.
    flow = 0
    flow_hits = []
    full = " ".join(str(v) for v in d.values()).lower()
    for w, pts in [('쌍끌강', 6), ('쌍끌', 5), ('강매집', 5), ('기관매수', 4), ('외인매수', 4), ('개인매도흡수', 4), ('obv', 3), ('거래량', 3), ('매집', 3), ('수급전환', 4)]:
        if w.lower() in full:
            flow += pts
            flow_hits.append(f"{w}+{pts}")
    vr = _v93_float(_v93_pick(d, '거래량배수', 'vol_ratio', 'Volume_Ratio', 'V_Ratio', default=0), 0)
    if vr >= 2.5:
        flow += 6; flow_hits.append('거래량2.5배+6')
    elif vr >= 1.5:
        flow += 3; flow_hits.append('거래량1.5배+3')
    flow = min(20, flow)

    pure_score = max(0, min(80, novelty + strength + sustain + spread - negative))
    total_score = max(0, min(100, pure_score + flow))

    event_reason = ''
    try:
        event_reason = _v91_event_reason(d) if '_v91_event_reason' in globals() else ''
    except Exception:
        event_reason = ''
    if event_reason:
        total_score = min(total_score, 15)

    if event_reason or negative >= 35:
        tag = '🚫재료위험'
        verdict = '이벤트/리스크성 재료가 우선입니다. 차트가 좋아도 신규매수 제외가 먼저입니다.'
    elif pure_score >= 60 and total_score >= 75:
        tag = '🧨강재료'
        verdict = '순수재료와 수급보조가 함께 강합니다.'
    elif pure_score >= 40:
        tag = '🔥재료유효'
        verdict = '순수재료는 유효합니다. 후속 뉴스와 섹터 확산을 확인합니다.'
    elif pure_score >= 20:
        tag = '🟡재료확인'
        verdict = '직접 재료 단서는 있으나 강도나 지속성은 추가 확인이 필요합니다.'
    elif flow >= 14:
        tag = '⚪수급보조형'
        verdict = '뉴스 재료는 약하고 수급만 보조합니다. 재료주로 착각하면 안 됩니다.'
    else:
        tag = '⚠️재료부족'
        verdict = '확인 가능한 직접 재료가 부족하거나 이미 가격에 반영됐을 가능성이 큽니다.'

    hit_bits = []
    for label, hits in [('신규', novelty_hits), ('강도', strength_hits), ('지속', sustain_hits), ('확산', spread_hits), ('수급', flow_hits)]:
        if hits:
            hit_bits.append(label + ':' + '/'.join(hits[:3]))
    if bad_hits:
        hit_bits.append('주의:' + '/'.join(bad_hits[:3]))
    if event_reason:
        hit_bits.insert(0, '이벤트:' + event_reason)

    detail = (
        f"순수재료 {pure_score}/80 | 수급보조 {flow}/20 | 종합 {total_score}/100 | "
        f"신규성{novelty}/20, 강도{strength}/20, 지속성{sustain}/20, 확산성{spread}/20, 수급결합{flow}/20, 주의-{negative}"
    )
    reason = ' | '.join(hit_bits) if hit_bits else '직접 뉴스·공시 재료 미확인'

    return {
        'material_score': int(total_score),
        'material_tag': tag,
        'material_comment': verdict + ' | ' + detail + ' | 근거: ' + reason,
        'material_positive_score': int(novelty + strength),
        'material_support_score': int(sustain + spread + flow),
        'material_negative_score': int(negative),
        'material_pure_score': int(pure_score),
        'material_flow_score': int(flow),
        'material_total_score': int(total_score),
        'material_newness_score': int(novelty),
        'material_strength_score': int(strength),
        'material_sustain_score': int(sustain),
        'material_spread_score': int(spread),
        'material_detail': detail + ' | ' + reason,
        'material_event_reason': event_reason,
    }


try:
    _V93_BASE_APPLY_MATERIAL = apply_material_survival_to_df
except Exception:
    _V93_BASE_APPLY_MATERIAL = None


def apply_material_survival_to_df(df, *args, **kwargs):
    try:
        out = _V93_BASE_APPLY_MATERIAL(df, *args, **kwargs) if _V93_BASE_APPLY_MATERIAL else df
    except Exception:
        out = df
    try:
        if out is None or len(out) == 0:
            return out
        for idx, row in out.iterrows():
            m = calc_material_survival_score(row.to_dict())
            out.at[idx, '재료잔존점수'] = int(m.get('material_score', 0))
            out.at[idx, '재료잔존태그'] = str(m.get('material_tag', ''))
            out.at[idx, '재료잔존코멘트'] = str(m.get('material_comment', ''))
            out.at[idx, '순수재료점수'] = int(m.get('material_pure_score', 0))
            out.at[idx, '수급보조재료점수'] = int(m.get('material_flow_score', 0))
            out.at[idx, '종합재료점수'] = int(m.get('material_total_score', 0))
            out.at[idx, '재료직접점수'] = int(m.get('material_positive_score', 0))
            out.at[idx, '재료보조점수'] = int(m.get('material_support_score', 0))
            out.at[idx, '재료주의점수'] = int(m.get('material_negative_score', 0))
            out.at[idx, '재료신규성점수'] = int(m.get('material_newness_score', 0))
            out.at[idx, '재료강도점수'] = int(m.get('material_strength_score', 0))
            out.at[idx, '재료지속성점수'] = int(m.get('material_sustain_score', 0))
            out.at[idx, '재료확산성점수'] = int(m.get('material_spread_score', 0))
            out.at[idx, '재료수급결합점수'] = int(m.get('material_flow_score', 0))
            out.at[idx, '재료세부'] = str(m.get('material_detail', ''))
    except Exception:
        pass
    return out


