try:
    _V93_BASE_WAVE_TIMING = _v92_calc_wave_pullback_timing
except Exception:
    _V93_BASE_WAVE_TIMING = None


def _v92_calc_wave_pullback_timing(df, waves=None, position=None):
    out = {
        'wave_stage': '데이터부족',
        'wave_score': 0,
        'trend_turn_score': 0,
        'first_wave_score': 0,
        'pullback_health_score': 0,
        'restart_score': 0,
        'best_zone_low': 0.0,
        'best_zone_high': 0.0,
        'invalid_price': 0.0,
        'pivot_high': 0.0,
        'pivot_low': 0.0,
        'pullback_pct': 0.0,
        'wave_comment': '데이터가 부족해 파동 눌림 타점을 계산하지 못했습니다.',
        'wave_action': '관찰',
        'debug': '',
    }
    try:
        if df is None or len(df) < 30:
            return out
        cols = _v92_price_cols(df)
        ccol, hcol, lcol, ocol, vcol = cols.get('close'), cols.get('high'), cols.get('low'), cols.get('open'), cols.get('volume')
        if not ccol or not hcol or not lcol:
            return out
        close = _v92_series(df, ccol)
        high = _v92_series(df, hcol)
        low = _v92_series(df, lcol)
        open_ = _v92_series(df, ocol) if ocol else close
        volume = _v92_series(df, vcol) if vcol else close * 0
        n = len(close)
        cur = _v93_float(close.iloc[-1], 0)
        if cur <= 0:
            return out

        ma5 = close.rolling(5).mean()
        ma10 = close.rolling(10).mean()
        ma20 = close.rolling(20).mean()
        ma60 = close.rolling(60).mean() if n >= 60 else close.rolling(min(30, n)).mean()
        vol20 = volume.rolling(20).mean() if len(volume) else volume

        ma5v = _v93_float(ma5.iloc[-1], 0)
        ma10v = _v93_float(ma10.iloc[-1], 0)
        ma20v = _v93_float(ma20.iloc[-1], 0)
        ma60v = _v93_float(ma60.iloc[-1], 0)
        ma20_slope = _v92_slope_pct(ma20, 5)
        ma60_slope = _v92_slope_pct(ma60, 10)
        vol_ratio = _v93_float(volume.iloc[-1], 0) / max(_v93_float(vol20.iloc[-1], 0), 1.0) if len(volume) else 0.0
        day_up = bool(cur >= _v93_float(open_.iloc[-1], cur))
        prev_close = _v93_float(close.iloc[-2], cur) if n >= 2 else cur
        prev_high = _v93_float(high.iloc[-2], cur) if n >= 2 else cur

        look60 = min(60, n)
        base_low = _v93_float(low.iloc[-look60:].min(), 0)
        pivot_high = _v93_float(high.iloc[-look60:].max(), 0)
        recent20_high = _v93_float(high.iloc[-20:].max(), 0)
        recent20_low = _v93_float(low.iloc[-20:].min(), 0)
        prev_box_high = _v93_float(high.iloc[max(0, n-55):max(1, n-8)].max(), 0) if n > 15 else recent20_high
        impulse_pct = (pivot_high / base_low - 1.0) * 100.0 if base_low > 0 and pivot_high > 0 else 0.0

        blue_line = _v93_float((waves or {}).get('blue_line_price') or (waves or {}).get('blue_zone_high') or 0, 0)
        blue_gap = (cur / blue_line - 1.0) * 100.0 if blue_line > 0 else 0.0
        small_pos = _v93_float((waves or {}).get('small_pos_pct', 0), 0)
        small_dir = str((waves or {}).get('small_box_dir', '') or '')
        mid_dir = str((waves or {}).get('mid_box_dir', '') or '')

        # 1) 추세전환
        trend = 0
        if ma5v >= ma20v * 0.98 if ma20v > 0 else False: trend += 5
        if ma10v >= ma20v * 0.98 if ma20v > 0 else False: trend += 3
        if ma20_slope >= -0.5: trend += 5
        if ma20_slope > 0: trend += 4
        if ma60_slope > -1.5: trend += 3
        if cur >= ma20v * 0.97 if ma20v > 0 else False: trend += 4
        if blue_line > 0 and blue_gap >= -3.0: trend += 1
        trend = min(25, trend)

        # 2) 1파 발생
        first = 0
        if impulse_pct >= 8: first += 5
        if impulse_pct >= 15: first += 5
        if recent20_high >= prev_box_high * 0.985 if prev_box_high > 0 else False: first += 5
        try:
            vol_burst = _v93_float(volume.iloc[-20:].max(), 0) / max(_v93_float(vol20.iloc[-1], 0), 1.0)
            if vol_burst >= 1.5: first += 4
            if vol_burst >= 2.5: first += 3
        except Exception:
            pass
        if cur > ma20v if ma20v > 0 else False: first += 3
        if '상향' in small_dir or '상향' in mid_dir: first += 2
        first = min(25, first)

        wave_range = max(pivot_high - base_low, 0.0)
        retrace = ((pivot_high - cur) / wave_range * 100.0) if wave_range > 0 else 0.0
        fib38 = pivot_high - wave_range * 0.382 if wave_range > 0 else 0.0
        fib62 = pivot_high - wave_range * 0.618 if wave_range > 0 else 0.0
        zone_low = min(fib38, fib62) if fib38 > 0 and fib62 > 0 else 0.0
        zone_high = max(fib38, fib62) if fib38 > 0 and fib62 > 0 else 0.0

        # 3) 눌림 건강도
        pull = 0
        if 5.0 <= retrace <= 68.0: pull += 6
        if 15.0 <= retrace <= 55.0: pull += 5
        if vol_ratio <= 1.20: pull += 5
        elif vol_ratio <= 1.60: pull += 2
        if cur >= ma20v * 0.97 if ma20v > 0 else False: pull += 4
        if blue_line > 0 and -3.0 <= blue_gap <= 3.5: pull += 4
        elif blue_line > 0 and blue_gap > 0: pull += 2
        if 35 <= small_pos <= 88: pull += 2
        try:
            red_cnt = 0
            big_red = 0
            for i in range(max(0, n-3), n):
                o = _v93_float(open_.iloc[i], 0); c = _v93_float(close.iloc[i], 0)
                if c < o:
                    red_cnt += 1
                    if o > 0 and (c / o - 1.0) * 100.0 <= -4.0:
                        big_red += 1
            if red_cnt <= 1: pull += 2
            if big_red >= 1: pull -= 4
        except Exception:
            pass
        pull = max(0, min(25, pull))

        # 4) 재출발
        restart = 0
        if day_up: restart += 4
        if cur >= ma5v * 0.995 if ma5v > 0 else False: restart += 4
        if cur >= prev_close: restart += 3
        if cur >= prev_high * 0.997 if prev_high > 0 else False: restart += 4
        if 1.0 <= vol_ratio <= 2.8: restart += 3
        if vol_ratio >= 1.3: restart += 4
        if blue_line > 0 and cur >= blue_line * 0.995: restart += 3
        restart = min(25, restart)

        total = int(min(100, trend + first + pull + restart))

        invalid_candidates = [x for x in [recent20_low * 0.985 if recent20_low > 0 else 0, ma20v * 0.965 if ma20v > 0 else 0, blue_line * 0.97 if blue_line > 0 else 0] if x > 0]
        invalid = min(invalid_candidates) if invalid_candidates else 0.0

        if total >= 74 and pull >= 15 and restart >= 12:
            stage = '눌림타점형'
            action = '실행 우선후보'
            comment = '1파 이후 눌림이 과도하지 않고 재양봉·재안착 신호가 붙는 구간입니다.'
        elif total >= 62 and trend >= 14 and first >= 14 and pull >= 10:
            stage = '눌림대기형'
            action = '첫 눌림 확인'
            comment = '새 파동은 확인됐고 지금은 파란점선/20일선/돌파선 지지 여부가 핵심입니다.'
            total = max(total, 64)
        elif trend >= 14 and first >= 14:
            stage = '1파발생형'
            action = '추격보다 첫 눌림 대기'
            comment = '추세 전환 뒤 1파가 발생했습니다. 지금은 고점 추격보다 첫 눌림을 기다립니다.'
            total = max(total, 58)
        elif trend >= 14:
            stage = '추세전환형'
            action = '관찰 강화'
            comment = '하락/횡보 흐름에서 방향 전환 조짐이 있습니다. 1파 거래량과 5일선 재안착을 확인합니다.'
        elif total >= 45:
            stage = '바닥응축형'
            action = '소액 관찰'
            comment = '응축은 있으나 1파·눌림·재출발 중 일부 확인이 부족합니다.'
        else:
            stage = '관찰부족형'
            action = '보수 관찰'
            comment = '아직 새 상승파동이나 건강한 눌림 근거가 부족합니다.'

        out.update({
            'wave_stage': stage,
            'wave_score': int(total),
            'trend_turn_score': int(trend),
            'first_wave_score': int(first),
            'pullback_health_score': int(pull),
            'restart_score': int(restart),
            'best_zone_low': round(zone_low, 2),
            'best_zone_high': round(zone_high, 2),
            'invalid_price': round(invalid, 2),
            'pivot_high': round(pivot_high, 2),
            'pivot_low': round(base_low, 2),
            'pullback_pct': round(retrace, 1),
            'wave_comment': comment,
            'wave_action': action,
            'debug': f"v9.3 impulse={impulse_pct:.1f}, retrace={retrace:.1f}, vol={vol_ratio:.2f}, blue_gap={blue_gap:.1f}, ma20_slope={ma20_slope:.2f}",
        })
        return out
    except Exception as e:
        if _V93_BASE_WAVE_TIMING:
            try:
                return _V93_BASE_WAVE_TIMING(df, waves, position)
            except Exception:
                pass
        out['debug'] = f'v9.3 wave timing error: {e}'
        return out


def _v93_wave_eval_from_row(row):
    d = _v93_to_dict(row)
    stage = str(_v93_pick(d, '파동타점상태', 'wave_stage', default='') or '').strip()
    score = _v93_int(_v93_pick(d, '파동타점점수', 'wave_score', default=0), 0)
    trend = _v93_int(_v93_pick(d, '파동전환점수', 'trend_turn_score', default=0), 0)
    first = _v93_int(_v93_pick(d, '파동1파점수', 'first_wave_score', default=0), 0)
    pull = _v93_int(_v93_pick(d, '파동눌림점수', 'pullback_health_score', default=0), 0)
    restart = _v93_int(_v93_pick(d, '파동재출발점수', 'restart_score', default=0), 0)

    if not stage or score <= 0:
        # 폴백: 이미 계산된 소/중파동, 파란점선 상태만으로 최소 파동 후보를 만든다.
        blue_state = str(_v93_pick(d, '파란점선상태', 'blue_line_state', default='') or '')
        blue_gap = _v93_float(_v93_pick(d, '파란점선이격', 'blue_line_gap_pct', default=0), 0)
        small_pos = _v93_float(_v93_pick(d, '소파동위치퍼센트', default=0), 0)
        mid_pos = _v93_float(_v93_pick(d, '중파동위치퍼센트', default=0), 0)
        sdir = str(_v93_pick(d, '소파동박스방향', default='') or '')
        mdir = str(_v93_pick(d, '중파동박스방향', default='') or '')
        disp = _v93_float(_v93_pick(d, '이격', 'Disparity', default=100), 100)
        rsi = _v93_float(_v93_pick(d, 'RSI', 'RSI14', default=50), 50)

        trend = 12
        first = 10
        pull = 8
        restart = 6
        if '상향' in sdir: trend += 4; first += 3
        if '상향' in mdir: trend += 3; first += 3
        if '접촉' in blue_state or abs(blue_gap) <= 1.5: pull += 6; restart += 2
        elif '위안착' in blue_state: pull += 3; restart += 5
        elif '아래' in blue_state and blue_gap >= -3.5: pull += 3
        if 35 <= small_pos <= 80: pull += 4
        if 40 <= mid_pos <= 85: first += 2
        if 98 <= disp <= 112: pull += 3
        if rsi < 70: pull += 2
        score = min(100, trend + first + pull + restart)
        if score >= 70 and restart >= 12:
            stage = '눌림타점형'
        elif score >= 58 and pull >= 13:
            stage = '눌림대기형'
        elif score >= 50:
            stage = '1파발생형'
        else:
            stage = '파동관찰형'

    return {
        'stage': stage,
        'score': int(score),
        'trend': int(trend),
        'first': int(first),
        'pull': int(pull),
        'restart': int(restart),
        'low': _v93_float(_v93_pick(d, '파동최적하단', 'best_zone_low', default=0), 0),
        'high': _v93_float(_v93_pick(d, '파동최적상단', 'best_zone_high', default=0), 0),
        'invalid': _v93_float(_v93_pick(d, '파동무효화', 'invalid_price', default=0), 0),
        'comment': str(_v93_pick(d, '파동실행의견', 'wave_comment', default='') or '').strip(),
    }


def _v93_wave_lines_from_row(row):
    d = _v93_to_dict(row)
    ev = _v93_wave_eval_from_row(d)
    stage = ev['stage']; score = ev['score']
    if not stage:
        return []
    low = ev['low']; high = ev['high']; invalid = ev['invalid']
    if invalid <= 0:
        invalid = _v93_float(_v93_pick(d, '파란점선기준가', default=0), 0) * 0.97
    if low <= 0 or high <= 0:
        blue = _v93_float(_v93_pick(d, '파란점선기준가', default=0), 0)
        ma20 = _v93_float(_v93_pick(d, 'MA20', 'ma20', default=0), 0)
        vals = [x for x in [blue, ma20] if x > 0]
        if vals:
            low = min(vals) * 0.985
            high = max(vals) * 1.015
    action_map = {
        '눌림타점형': '재양봉·거래량 재유입 시 실행 우선',
        '눌림대기형': '첫 눌림 지지 확인',
        '1파발생형': '추격보다 첫 눌림 대기',
        '추세전환형': '거래량 붙는 1파 확인',
        '파동관찰형': '파란점선 회복/안착 확인',
    }
    lines = [
        f"🌊 파동타점: {stage} | 점수 {score}/100 | {action_map.get(stage, '관찰')}",
        f"🧮 파동점수: 전환{ev['trend']}/25 1파{ev['first']}/25 눌림{ev['pull']}/25 재출발{ev['restart']}/25",
    ]
    if low > 0 and high > 0:
        lines.append(f"🎯 최적눌림: {_v93_price(low)}~{_v93_price(high)}")
    if invalid > 0:
        lines.append(f"🧯 무효가격: {_v93_price(invalid)} 이탈 시 파동눌림 관점 약화")
    if ev['comment']:
        lines.append(f"🧭 파동타점 해석: {ev['comment'][:110]}")
    return lines


try:
    _V93_BASE_CONTEXT_LINES = _build_context_trace_lines
except Exception:
    _V93_BASE_CONTEXT_LINES = None


def _build_context_trace_lines(row):
    try:
        lines = _V93_BASE_CONTEXT_LINES(row) if _V93_BASE_CONTEXT_LINES else []
        if lines is None:
            lines = []
        if not isinstance(lines, list):
            lines = list(lines)
    except Exception:
        lines = []

    d = _v93_to_dict(row)

    # 기존 재료점수 문구 뒤에 순수재료/수급보조 분리 문구를 추가한다.
    pure = _v93_int(_v93_pick(d, '순수재료점수', 'material_pure_score', default=-1), -1)
    flow = _v93_int(_v93_pick(d, '수급보조재료점수', 'material_flow_score', '재료수급결합점수', default=-1), -1)
    total = _v93_int(_v93_pick(d, '종합재료점수', '재료잔존점수', 'material_total_score', default=-1), -1)
    if total >= 0 and not any('순수재료:' in str(x) for x in lines):
        if pure < 0:
            pure = max(0, total - max(flow, 0))
        if flow < 0:
            flow = 0
        material_msg = f"🧾 순수재료:{pure}/80 | 수급보조:{flow}/20 | 종합:{total}/100"
        if pure < 20 and flow >= 14:
            material_msg += " | 판정: 뉴스보다 수급 보조형"
        elif pure >= 40:
            material_msg += " | 판정: 재료 유효"
        else:
            material_msg += " | 판정: 직접재료 추가확인"
        lines.append(material_msg)

    # 개별 카드에 파동타점 블록 강제 표시
    wave_lines = _v93_wave_lines_from_row(d)
    if wave_lines and not any('파동타점:' in str(x) for x in lines):
        lines.extend(wave_lines)

    return lines


# ─────────────────────────────────────────────────────────────
# V9.3: 매매관점 압축용 파동 후보 3단계 셀렉터
# ─────────────────────────────────────────────────────────────
def _v92_pick_wave_pullback_rows(frames, limit=6):
    rows_all = []
    used = set()
    for fr in frames:
        try:
            if fr is None:
                continue
            if hasattr(fr, 'iterrows'):
                rows = [r.to_dict() for _, r in fr.iterrows()]
            elif isinstance(fr, list):
                rows = [_v93_to_dict(x) for x in fr]
            else:
                rows = []
            for r in rows:
                if not r:
                    continue
                code = str(_v93_pick(r, 'code', '종목코드', 'Code', default='') or '').strip()
                name = str(_v93_pick(r, '종목명', 'name', 'Name', default='') or '').strip()
                key = code or name
                if not key or key in used:
                    continue
                ev = _v93_wave_eval_from_row(r)
                r['_v93_wave_stage'] = ev['stage']
                r['_v93_wave_score'] = ev['score']
                r['_v93_wave_pull'] = ev['pull']
                r['_v93_wave_restart'] = ev['restart']
                used.add(key)
                rows_all.append(r)
        except Exception:
            continue

    def blocked(r):
        txt = ' '.join(str(_v93_pick(r, k, default='') or '') for k in ['매매판정', '최종판정', 'AI최종판정', '수박최종상태', '후행유형', '수박정제태그'])
        # 눌림타점 후보라도 과열/후행/가짜수박은 우선후보에서 낮춘다.
        if any(x in txt for x in ['추격 금지', '보유자 대응', '후행수박', '가짜수박주의']):
            return True
        disp = _v93_float(_v93_pick(r, '이격', 'Disparity', default=100), 100)
        rsi = _v93_float(_v93_pick(r, 'RSI', 'RSI14', default=50), 50)
        return disp >= 120 or rsi >= 78

    def rank(r):
        st = str(r.get('_v93_wave_stage', ''))
        score = _v93_int(r.get('_v93_wave_score', 0), 0)
        stage_bonus = {'눌림타점형': 300, '눌림대기형': 220, '1파발생형': 150, '추세전환형': 90, '파동관찰형': 60}.get(st, 0)
        if blocked(r):
            stage_bonus -= 120
        return stage_bonus + score

    candidates = []
    for r in sorted(rows_all, key=rank, reverse=True):
        st = str(r.get('_v93_wave_stage', ''))
        score = _v93_int(r.get('_v93_wave_score', 0), 0)
        if st in ('눌림타점형', '눌림대기형', '1파발생형') or score >= 55:
            candidates.append(r)
        if len(candidates) >= limit:
            break

    # 그래도 없으면 파란점선 접촉/위안착 종목으로 폴백한다.
    if not candidates:
        fallback = []
        for r in rows_all:
            blue = str(_v93_pick(r, '파란점선상태', default='') or '')
            gap = abs(_v93_float(_v93_pick(r, '파란점선이격', default=99), 99))
            if '접촉' in blue or '위안착' in blue or gap <= 2.5:
                fallback.append(r)
        candidates = sorted(fallback, key=rank, reverse=True)[:limit]

    return candidates[:limit]


def _v92_format_wave_bucket(rows):
    if not rows:
        return '- 해당 종목 없음'

    grouped = {'눌림타점형': [], '눌림대기형': [], '1파발생형': [], '기타': []}
    for r in rows:
        ev = _v93_wave_eval_from_row(r)
        st = ev['stage'] if ev['stage'] in grouped else '기타'
        grouped[st].append((r, ev))

    lines = []
    titles = [
        ('눌림타점형', '✅ 눌림타점형'),
        ('눌림대기형', '👀 눌림대기형'),
        ('1파발생형', '🌱 1파발생형'),
        ('기타', '🔎 파동관찰형'),
    ]
    rank_no = 1
    for key, title in titles:
        arr = grouped.get(key) or []
        if not arr:
            continue
        lines.append(title)
        for r, ev in arr[:3]:
            name = str(_v93_pick(r, '종목명', 'name', 'Name', default='') or '').strip()
            code = str(_v93_pick(r, 'code', '종목코드', 'Code', default='') or '').strip()
            blue = str(_v93_pick(r, '파란점선상태', default='') or '').strip()
            low = _v93_float(_v93_pick(r, '파동최적하단', 'best_zone_low', default=ev.get('low', 0)), 0)
            high = _v93_float(_v93_pick(r, '파동최적상단', 'best_zone_high', default=ev.get('high', 0)), 0)
            invalid = _v93_float(_v93_pick(r, '파동무효화', 'invalid_price', default=ev.get('invalid', 0)), 0)
            action = {'눌림타점형': '재양봉·거래량 재유입 확인 시 실행', '눌림대기형': '파란점선/20일선 지지 확인', '1파발생형': '추격 금지, 첫 눌림 대기'}.get(ev['stage'], '관찰')
            zone = f" | 최적:{_v93_price(low)}~{_v93_price(high)}" if low > 0 and high > 0 else ''
            inv = f" | 무효:{_v93_price(invalid)}" if invalid > 0 else ''
            lines.append(f"{rank_no}) {name}({code}) - {ev['stage']} {ev['score']}/100 | 파란점선:{blue or '-'}{zone}{inv}")
            lines.append(f"   → {action}")
            rank_no += 1
    return '\n'.join(lines) if lines else '- 해당 종목 없음'


