def _v90_row_to_amount_item(row, rank=0):
    d = _v93_to_dict(row)
    item = None
    try:
        item = _V93_BASE_ROW_TO_AMOUNT_ITEM(row, rank=rank) if _V93_BASE_ROW_TO_AMOUNT_ITEM else None
    except Exception:
        item = None
    if not item:
        code = str(_v93_pick(d, 'code', '종목코드', 'Code', default='') or '').zfill(6)
        item = {'code': code, '종목코드': code, 'rank': rank}
    try:
        m = calc_material_survival_score(d)
        ev = _v93_wave_eval_from_row(d)
        item.update({
            '재료점수': int(m.get('material_score', 0)),
            '순수재료점수': int(m.get('material_pure_score', 0)),
            '수급보조재료점수': int(m.get('material_flow_score', 0)),
            '종합재료점수': int(m.get('material_total_score', 0)),
            '재료태그': str(m.get('material_tag', '')),
            '재료코멘트': str(m.get('material_comment', ''))[:500],
            '재료세부': str(m.get('material_detail', '')),
            '파동타점상태': ev['stage'],
            '파동타점점수': ev['score'],
            '파동전환점수': ev['trend'],
            '파동1파점수': ev['first'],
            '파동눌림점수': ev['pull'],
            '파동재출발점수': ev['restart'],
        })
        for k in ('파동최적하단', '파동최적상단', '파동무효화', '파동실행의견'):
            if k in d:
                item[k] = d.get(k)
    except Exception:
        pass
    return item


