def _v94_float(x, default=0.0):
    try:
        return _v93_float(x, default)
    except Exception:
        try:
            if x is None:
                return default
            import re as _re
            s = str(x).replace(',', '').replace('%', '').strip()
            m = _re.search(r'-?\d+(?:\.\d+)?', s)
            return float(m.group(0)) if m else default
        except Exception:
            return default


def _v94_int(x, default=0):
    try:
        return int(round(_v94_float(x, default)))
    except Exception:
        return default


def _v94_pick(d, *keys, default=None):
    try:
        return _v93_pick(d, *keys, default=default)
    except Exception:
        for k in keys:
            try:
                v = d.get(k)
                if v is not None and str(v).strip() != '':
                    return v
            except Exception:
                pass
        return default


def _v94_to_dict(row):
    try:
        return _v93_to_dict(row)
    except Exception:
        try:
            if isinstance(row, dict):
                return dict(row)
            if hasattr(row, 'to_dict'):
                return row.to_dict()
        except Exception:
            pass
    return {}


def _v94_price(v):
    try:
        return _v93_price(v)
    except Exception:
        f = _v94_float(v, 0)
        return f"{int(round(f)):,}" if f > 0 else "0"


def _v94_current_price(d):
    for k in ('현재가', '현재가숫자', 'Close', 'close', '종가', 'price', '현재가격'):
        v = _v94_float(_v94_pick(d, k, default=0), 0)
        if v > 0:
            return v
    return 0.0


def _v94_code_name(row):
    d = _v94_to_dict(row)
    name = str(_v94_pick(d, '종목명', 'name', 'Name', default='') or '').strip()
    code = str(_v94_pick(d, 'code', '종목코드', 'Code', default='') or '').strip().replace('.0', '')
    if code.isdigit():
        code = code.zfill(6)
    return name, code


def _v94_text_blob(row):
    d = _v94_to_dict(row)
    keys = [
        '종목명','code','최종판정','매매판정','AI최종판정','구조판정','유형','추천단계',
        '수박최종상태','수박상태명','수박정제태그','수박정제코멘트','후행유형',
        '실행조건','action_summary','easy_interpretation','need_check','interpretation_block',
        '저항구름태그','저항구름코멘트','N조합','태그','tags'
    ]
    return ' '.join(str(d.get(k, '') or '') for k in keys)


def _v94_trade_action(row):
    try:
        return _v8_trade_action(row)[0]
    except Exception:
        txt = _v94_text_blob(row)
        if '추격 금지' in txt or '신규 매수 금지' in txt:
            return '추격 금지'
        if '보유자 대응' in txt:
            return '보유자 대응'
        if '눌림 대기' in txt:
            return '눌림 대기'
        if '선취' in txt:
            return '선취 관찰'
        return '관찰'


def _v94_execution_guard(row):
    d = _v94_to_dict(row)
    txt = _v94_text_blob(d)
    action = _v94_trade_action(d)
    disp = _v94_float(_v94_pick(d, '이격', 'Disparity', '과열이격도', default=100), 100)
    rsi = _v94_float(_v94_pick(d, 'RSI', 'RSI14', 'rsi', default=50), 50)
    reasons = []
    severe = False
    if '신규 매수 금지' in txt or action == '추격 금지' or '추격 금지' in txt:
        reasons.append('추격금지')
        severe = True
    if action == '보유자 대응' or '보유자 대응' in txt:
        reasons.append('보유자대응')
        severe = True
    if '후행수박' in txt or '후행형' in txt or '과열후행형' in txt or '보유관리후행형' in txt:
        reasons.append('후행형')
        severe = True
    if '가짜수박주의' in txt:
        reasons.append('가짜수박주의')
        severe = True
    if disp >= 115:
        reasons.append(f'이격{disp:.0f}↑')
    elif disp >= 112:
        reasons.append(f'이격{disp:.0f} 부담')
    if rsi >= 70:
        reasons.append(f'RSI{rsi:.0f}↑')
    elif rsi >= 67:
        reasons.append(f'RSI{rsi:.0f} 부담')
    blocked = severe or disp >= 115 or rsi >= 70
    return {
        'blocked': bool(blocked),
        'severe': bool(severe),
        'reasons': reasons,
        'reason_text': ' / '.join(reasons),
        'disparity': disp,
        'rsi': rsi,
        'action': action,
    }


def _v94_zone_relation(row, ev=None):
    d = _v94_to_dict(row)
    ev = ev or {}
    cur = _v94_current_price(d)
    low = _v94_float(ev.get('low') if isinstance(ev, dict) else 0, 0)
    high = _v94_float(ev.get('high') if isinstance(ev, dict) else 0, 0)
    if low <= 0:
        low = _v94_float(_v94_pick(d, '파동최적하단', 'best_zone_low', default=0), 0)
    if high <= 0:
        high = _v94_float(_v94_pick(d, '파동최적상단', 'best_zone_high', default=0), 0)
    if low > high > 0:
        low, high = high, low
    if cur <= 0 or low <= 0 or high <= 0 or high < low:
        return {'state': 'unknown', 'penalty': 0, 'comment': '', 'cur': cur, 'low': low, 'high': high, 'near': False}
    if low * 0.98 <= cur <= high * 1.02:
        return {'state': 'inside', 'penalty': 0, 'comment': '현재가가 최적눌림구간 안/근처', 'cur': cur, 'low': low, 'high': high, 'near': True}
    if cur > high * 1.03:
        gap = (cur / high - 1.0) * 100.0
        return {'state': 'above_far', 'penalty': 22, 'comment': f'현재가가 최적눌림구간보다 {gap:.1f}% 위', 'cur': cur, 'low': low, 'high': high, 'near': False}
    if cur > high:
        gap = (cur / high - 1.0) * 100.0
        return {'state': 'above_near', 'penalty': 8, 'comment': f'현재가가 최적눌림구간보다 {gap:.1f}% 위', 'cur': cur, 'low': low, 'high': high, 'near': True}
    if cur < low * 0.97:
        gap = (low / cur - 1.0) * 100.0 if cur > 0 else 0.0
        return {'state': 'below_far', 'penalty': 20, 'comment': f'현재가가 최적눌림구간보다 {gap:.1f}% 아래', 'cur': cur, 'low': low, 'high': high, 'near': False}
    gap = (low / cur - 1.0) * 100.0 if cur > 0 else 0.0
    return {'state': 'below_near', 'penalty': 8, 'comment': f'현재가가 최적눌림구간보다 {gap:.1f}% 아래', 'cur': cur, 'low': low, 'high': high, 'near': True}


try:
    _V94_BASE_WAVE_TIMING = _v92_calc_wave_pullback_timing
except Exception:
    _V94_BASE_WAVE_TIMING = None


def _v92_calc_wave_pullback_timing(df, waves=None, position=None):
    res = _V94_BASE_WAVE_TIMING(df, waves, position) if _V94_BASE_WAVE_TIMING else {}
    try:
        if not isinstance(res, dict):
            return res
        cur = 0.0
        try:
            cols = _v92_price_cols(df)
            ccol = cols.get('close')
            if ccol:
                cur = _v94_float(_v92_series(df, ccol).iloc[-1], 0)
        except Exception:
            cur = 0.0
        low = _v94_float(res.get('best_zone_low', 0), 0)
        high = _v94_float(res.get('best_zone_high', 0), 0)
        if low > high > 0:
            low, high = high, low
            res['best_zone_low'], res['best_zone_high'] = low, high
        if cur > 0 and low > 0 and high > 0:
            stage = str(res.get('wave_stage', '') or '')
            score = _v94_int(res.get('wave_score', 0), 0)
            cm = str(res.get('wave_comment', '') or '')
            if cur > high * 1.03 and stage == '눌림타점형':
                gap = (cur / high - 1.0) * 100.0
                res['wave_stage'] = '눌림대기형'
                res['wave_score'] = min(score, 68)
                res['wave_action'] = '첫 눌림 확인'
                res['wave_comment'] = (cm + f' 현재가가 최적눌림권보다 {gap:.1f}% 높아 즉시 타점이 아니라 눌림 대기입니다.').strip()
            elif cur < low * 0.97 and stage in ('눌림타점형', '눌림대기형'):
                gap = (low / cur - 1.0) * 100.0
                res['wave_stage'] = '회복확인형'
                res['wave_score'] = min(score, 55)
                res['wave_action'] = '회복 확인'
                res['wave_comment'] = (cm + f' 현재가가 최적눌림권보다 {gap:.1f}% 낮아 파란점선 회복 확인이 먼저입니다.').strip()
        return res
    except Exception:
        return res


try:
    _V94_BASE_WAVE_EVAL_FROM_ROW = _v93_wave_eval_from_row
except Exception:
    _V94_BASE_WAVE_EVAL_FROM_ROW = None


def _v93_wave_eval_from_row(row):
    base = _V94_BASE_WAVE_EVAL_FROM_ROW(row) if _V94_BASE_WAVE_EVAL_FROM_ROW else {}
    if not isinstance(base, dict):
        base = {}
    d = _v94_to_dict(row)
    ev = dict(base)
    structure_stage = str(ev.get('stage', '') or '')
    structure_score = _v94_int(ev.get('score', 0), 0)
    if not structure_stage:
        structure_stage = str(_v94_pick(d, '파동타점상태', 'wave_stage', default='파동관찰형') or '파동관찰형')
    if structure_score <= 0:
        structure_score = _v94_int(_v94_pick(d, '파동타점점수', 'wave_score', default=0), 0)
    ev['structure_stage'] = structure_stage
    ev['structure_score'] = int(structure_score)

    guard = _v94_execution_guard(d)
    zone = _v94_zone_relation(d, ev)
    penalty = 0
    if guard.get('severe'):
        penalty += 32
    if guard.get('disparity', 100) >= 115:
        penalty += 22
    elif guard.get('disparity', 100) >= 112:
        penalty += 8
    if guard.get('rsi', 50) >= 70:
        penalty += 20
    elif guard.get('rsi', 50) >= 67:
        penalty += 6
    penalty += int(zone.get('penalty', 0) or 0)
    exec_score = max(0, min(100, structure_score - penalty))

    exec_stage = structure_stage
    if guard.get('blocked'):
        exec_stage = '실행제외형'
        exec_score = min(exec_score, 49)
    elif zone.get('state') == 'above_far':
        exec_stage = '눌림대기형'
        exec_score = min(exec_score, 68)
    elif zone.get('state') == 'below_far':
        exec_stage = '회복확인형'
        exec_score = min(exec_score, 55)
    elif zone.get('state') in ('above_near', 'below_near') and structure_stage == '눌림타점형':
        exec_stage = '확인대기형'
        exec_score = min(exec_score, 72)

    reasons = []
    if guard.get('reason_text'):
        reasons.append(guard.get('reason_text'))
    if zone.get('comment') and zone.get('state') not in ('inside', 'unknown'):
        reasons.append(zone.get('comment'))
    reason_text = ' / '.join([x for x in reasons if x])

    ev.update({
        'stage': exec_stage,
        'score': int(exec_score),
        'exec_stage': exec_stage,
        'exec_score': int(exec_score),
        'is_blocked': bool(guard.get('blocked')),
        'blocked': bool(guard.get('blocked')),
        'guard_reasons': guard.get('reasons', []),
        'exec_reason': reason_text,
        'zone_state': zone.get('state'),
        'zone_comment': zone.get('comment'),
        'current_price': zone.get('cur') or _v94_current_price(d),
        'low': zone.get('low') or _v94_float(ev.get('low', 0), 0),
        'high': zone.get('high') or _v94_float(ev.get('high', 0), 0),
    })
    return ev


def _v94_is_wave_candidate_safe(row):
    ev = _v93_wave_eval_from_row(row)
    if ev.get('is_blocked'):
        return False
    st = str(ev.get('stage', ''))
    if st in ('실행제외형', '회복확인형'):
        return False
    if ev.get('zone_state') in ('above_far', 'below_far'):
        return False
    return True


def _v93_wave_lines_from_row(row):
    d = _v94_to_dict(row)
    ev = _v93_wave_eval_from_row(d)
    if not ev:
        return []
    st0 = str(ev.get('structure_stage', ev.get('stage', '')) or '')
    sc0 = _v94_int(ev.get('structure_score', ev.get('score', 0)), 0)
    st = str(ev.get('exec_stage', ev.get('stage', '')) or '')
    sc = _v94_int(ev.get('exec_score', ev.get('score', 0)), 0)
    if not st0 and not st:
        return []
    low = _v94_float(ev.get('low', 0), 0)
    high = _v94_float(ev.get('high', 0), 0)
    invalid = _v94_float(ev.get('invalid', 0), 0)
    if invalid <= 0:
        invalid = _v94_float(_v94_pick(d, '파란점선기준가', default=0), 0) * 0.97
    if low > high > 0:
        low, high = high, low
    action_map = {
        '눌림타점형': '재양봉·거래량 재유입 시 실행 우선',
        '눌림대기형': '첫 눌림 지지 확인',
        '1파발생형': '추격보다 첫 눌림 대기',
        '추세전환형': '거래량 붙는 1파 확인',
        '확인대기형': '현재가·파란점선 재확인',
        '회복확인형': '파란점선/5일선 회복 확인',
        '실행제외형': '신규 실행 제외',
        '파동관찰형': '파란점선 회복/안착 확인',
    }
    lines = []
    if st0 == st and sc0 == sc:
        lines.append(f"🌊 파동타점: {st} {sc}/100 | {action_map.get(st, '관찰')}")
    else:
        lines.append(f"🌊 파동구조: {st0} {sc0}/100")
        lines.append(f"🚦 실행판정: {st} {sc}/100 | {action_map.get(st, '관찰')}")
    lines.append(f"🧮 파동점수: 전환{_v94_int(ev.get('trend',0))}/25 1파{_v94_int(ev.get('first',0))}/25 눌림{_v94_int(ev.get('pull',0))}/25 재출발{_v94_int(ev.get('restart',0))}/25")
    if low > 0 and high > 0:
        cur = _v94_float(ev.get('current_price', 0), 0)
        pos = f" | 현재:{_v94_price(cur)}" if cur > 0 else ''
        zc = str(ev.get('zone_comment', '') or '')
        lines.append(f"🎯 최적눌림: {_v94_price(low)}~{_v94_price(high)}{pos}" + (f" | {zc}" if zc else ''))
    if invalid > 0:
        lines.append(f"🧯 무효가격: {_v94_price(invalid)} 이탈 시 파동눌림 관점 약화")
    if ev.get('exec_reason'):
        lines.append(f"⚠️ 실행제한: {ev.get('exec_reason')}")
    elif ev.get('comment'):
        lines.append(f"🧭 파동타점 해석: {str(ev.get('comment'))[:110]}")
    return lines


try:
    _V94_BASE_MATERIAL_SCORE = calc_material_survival_score
except Exception:
    _V94_BASE_MATERIAL_SCORE = None


def calc_material_survival_score(item) -> dict:
    m = _V94_BASE_MATERIAL_SCORE(item) if _V94_BASE_MATERIAL_SCORE else {}
    try:
        pure = _v94_int(m.get('material_pure_score', 0), 0)
        flow = _v94_int(m.get('material_flow_score', 0), 0)
        total = _v94_int(m.get('material_total_score', m.get('material_score', 0)), 0)
        tag = str(m.get('material_tag', '') or '')
        comment = str(m.get('material_comment', '') or '')
        if pure < 20 and flow >= 14 and '재료위험' not in tag:
            m['material_tag'] = '⚪수급보조형'
            strong = '직접재료 부족 / 수급은 보조근거 / 재료주 매매 금지'
            if strong not in comment:
                m['material_comment'] = strong + ' | ' + comment
        elif pure < 20 and total < 30 and '재료위험' not in tag:
            strong = '직접재료 추가확인 필요 / 뉴스만으로 매수 금지'
            if strong not in comment:
                m['material_comment'] = strong + ' | ' + comment
    except Exception:
        pass
    return m


try:
    _V94_BASE_CONTEXT_LINES = _build_context_trace_lines
except Exception:
    _V94_BASE_CONTEXT_LINES = None


def _build_context_trace_lines(row):
    try:
        lines = _V94_BASE_CONTEXT_LINES(row) if _V94_BASE_CONTEXT_LINES else []
        if lines is None:
            lines = []
        if not isinstance(lines, list):
            lines = list(lines)
    except Exception:
        lines = []
    d = _v94_to_dict(row)
    pure = _v94_int(_v94_pick(d, '순수재료점수', 'material_pure_score', default=-1), -1)
    flow = _v94_int(_v94_pick(d, '수급보조재료점수', 'material_flow_score', '재료수급결합점수', default=-1), -1)
    total = _v94_int(_v94_pick(d, '종합재료점수', '재료잔존점수', 'material_total_score', default=-1), -1)
    if total >= 0 and not any('재료판정:' in str(x) for x in lines):
        if pure < 0:
            pure = max(0, total - max(flow, 0))
        if flow < 0:
            flow = 0
        if pure < 20 and flow >= 14:
            verdict = '직접재료 부족 / 수급은 보조근거 / 재료주 매매 금지'
        elif pure >= 40:
            verdict = '직접재료 유효 / 후속 뉴스와 섹터 확산 확인'
        else:
            verdict = '직접재료 추가확인 / 뉴스만으로 매수 금지'
        lines.append(f"🧾 재료판정: 순수재료 {pure}/80 | 수급보조 {flow}/20 | 종합 {total}/100 | {verdict}")
    wave_lines = _v93_wave_lines_from_row(d)
    if wave_lines and not any(('파동구조:' in str(x) or '🚦 실행판정:' in str(x)) for x in lines):
        lines.extend(wave_lines)
    return lines


def _v92_pick_wave_pullback_rows(frames, limit=6):
    rows_all = []
    used = set()
    for fr in frames:
        try:
            if fr is None:
                continue
            if hasattr(fr, 'iterrows'):
                rows = [r.to_dict() for _, r in fr.iterrows()]
            elif isinstance(fr, list):
                rows = [_v94_to_dict(x) for x in fr]
            else:
                rows = []
            for r in rows:
                if not r:
                    continue
                code = str(_v94_pick(r, 'code', '종목코드', 'Code', default='') or '').strip()
                name = str(_v94_pick(r, '종목명', 'name', 'Name', default='') or '').strip()
                key = code or name
                if not key or key in used:
                    continue
                ev = _v93_wave_eval_from_row(r)
                r['_v94_wave_stage'] = ev.get('stage')
                r['_v94_wave_score'] = ev.get('score')
                r['_v94_wave_structure_stage'] = ev.get('structure_stage')
                r['_v94_wave_structure_score'] = ev.get('structure_score')
                r['_v94_wave_reason'] = ev.get('exec_reason')
                if _v94_is_wave_candidate_safe(r):
                    used.add(key)
                    rows_all.append(r)
        except Exception:
            continue

    def rank(r):
        ev = _v93_wave_eval_from_row(r)
        st = str(ev.get('stage', ''))
        score = _v94_int(ev.get('score', 0), 0)
        stage_bonus = {'눌림타점형': 320, '확인대기형': 250, '눌림대기형': 230, '1파발생형': 150, '추세전환형': 90, '파동관찰형': 40}.get(st, 0)
        if ev.get('zone_state') == 'inside':
            stage_bonus += 30
        return stage_bonus + score

    candidates = []
    for r in sorted(rows_all, key=rank, reverse=True):
        ev = _v93_wave_eval_from_row(r)
        st = str(ev.get('stage', ''))
        score = _v94_int(ev.get('score', 0), 0)
        if st in ('눌림타점형', '확인대기형', '눌림대기형', '1파발생형') or score >= 58:
            candidates.append(r)
        if len(candidates) >= limit:
            break
    return candidates[:limit]


def _v92_format_wave_bucket(rows):
    if not rows:
        return '- 해당 종목 없음'
    grouped = {'눌림타점형': [], '확인대기형': [], '눌림대기형': [], '1파발생형': [], '기타': []}
    for r in rows:
        ev = _v93_wave_eval_from_row(r)
        st = ev.get('stage') if ev.get('stage') in grouped else '기타'
        grouped[st].append((r, ev))
    titles = [
        ('눌림타점형', '✅ 실행가능 눌림타점형'),
        ('확인대기형', '🟦 근접 확인대기형'),
        ('눌림대기형', '👀 눌림대기형'),
        ('1파발생형', '🌱 1파발생형'),
        ('기타', '🔎 파동관찰형'),
    ]
    lines = []
    rank_no = 1
    for key, title in titles:
        arr = grouped.get(key) or []
        if not arr:
            continue
        lines.append(title)
        for r, ev in arr[:3]:
            name, code = _v94_code_name(r)
            blue = str(_v94_pick(r, '파란점선상태', 'blue_line_state', default='') or '').strip()
            cur = _v94_float(ev.get('current_price', 0), 0)
            low = _v94_float(ev.get('low', 0), 0)
            high = _v94_float(ev.get('high', 0), 0)
            invalid = _v94_float(ev.get('invalid', _v94_pick(r, '파동무효화', default=0)), 0)
            if low > high > 0:
                low, high = high, low
            action = {
                '눌림타점형': '재양봉·거래량 재유입 확인 시 실행',
                '확인대기형': '현재가·파란점선 재확인 후 실행',
                '눌림대기형': '최적권 재접근 또는 5일선/파란점선 지지 확인',
                '1파발생형': '추격 금지, 첫 눌림 대기',
            }.get(str(ev.get('stage')), '관찰')
            zone = f" | 최적:{_v94_price(low)}~{_v94_price(high)}" if low > 0 and high > 0 else ''
            cur_txt = f" | 현재:{_v94_price(cur)}" if cur > 0 else ''
            inv = f" | 무효:{_v94_price(invalid)}" if invalid > 0 else ''
            lines.append(f"{rank_no}) {name}({code}) - {ev.get('stage')} {ev.get('score')}/100 | 파란점선:{blue or '-'}{cur_txt}{zone}{inv}")
            lines.append(f"   → {action}")
            rank_no += 1
    return '\n'.join(lines) if lines else '- 해당 종목 없음'


try:
    _V94_BASE_ROW_TO_AMOUNT_ITEM = _v90_row_to_amount_item
except Exception:
    _V94_BASE_ROW_TO_AMOUNT_ITEM = None


def _v90_row_to_amount_item(row, rank=0):
    d = _v94_to_dict(row)
    try:
        item = _V94_BASE_ROW_TO_AMOUNT_ITEM(row, rank=rank) if _V94_BASE_ROW_TO_AMOUNT_ITEM else None
    except Exception:
        item = None
    if not item:
        code = str(_v94_pick(d, 'code', '종목코드', 'Code', default='') or '').replace('.0','')
        if code.isdigit():
            code = code.zfill(6)
        item = {'code': code, '종목코드': code, 'rank': rank}
    try:
        ev = _v93_wave_eval_from_row(d)
        m = calc_material_survival_score(d)
        item.update({
            '파동구조상태': ev.get('structure_stage'),
            '파동구조점수': int(ev.get('structure_score', 0) or 0),
            '파동실행상태': ev.get('exec_stage'),
            '파동실행점수': int(ev.get('exec_score', 0) or 0),
            '파동실행제한': ev.get('exec_reason', ''),
            '파동타점상태': ev.get('stage'),
            '파동타점점수': int(ev.get('score', 0) or 0),
            '순수재료점수': int(m.get('material_pure_score', item.get('순수재료점수', 0)) or 0),
            '수급보조재료점수': int(m.get('material_flow_score', item.get('수급보조재료점수', 0)) or 0),
            '종합재료점수': int(m.get('material_total_score', item.get('종합재료점수', item.get('재료점수', 0))) or 0),
            '재료코멘트': str(m.get('material_comment', item.get('재료코멘트', '')))[:600],
        })
    except Exception:
        pass
    return item

