try:
    _V95_BASE_WAVE_TIMING = _v92_calc_wave_pullback_timing
except Exception:
    _V95_BASE_WAVE_TIMING = None


def _v95_safe_float(x, default=0.0):
    try:
        if x is None:
            return default
        return float(x)
    except Exception:
        return default


def _v95_safe_int(x, default=0):
    try:
        return int(float(x))
    except Exception:
        return default


def _v95_series(df, col):
    try:
        return _v92_series(df, col)
    except Exception:
        return df[col]


def _v95_price_cols(df):
    try:
        return _v92_price_cols(df)
    except Exception:
        cols = {c.lower(): c for c in getattr(df, 'columns', [])}
        return {
            'open': cols.get('open') or cols.get('시가') or 'Open',
            'high': cols.get('high') or cols.get('고가') or 'High',
            'low': cols.get('low') or cols.get('저가') or 'Low',
            'close': cols.get('close') or cols.get('종가') or 'Close',
            'volume': cols.get('volume') or cols.get('거래량') or 'Volume',
        }


def _v95_downtrend_break_signal(df, waves=None):
    """하락추세선 돌파 후 첫 눌림 구조를 계산한다. 실패 시 score=0으로 조용히 폴백."""
    out = {
        'ok': False,
        'downtrend': False,
        'break_ok': False,
        'break_idx': -1,
        'break_days': 999,
        'line_today': 0.0,
        'line_prev': 0.0,
        'line_slope_pct': 0.0,
        'touch_count': 0,
        'trendline_score': 0,
        'first_pullback': False,
        'retest_ok': False,
        'volume_calm': False,
        'restart_ok': False,
        'retrace_pct': 0.0,
        'impulse_pct': 0.0,
        'zone_low': 0.0,
        'zone_high': 0.0,
        'invalid': 0.0,
        'note': '',
    }
    try:
        if df is None or len(df) < 45:
            out['note'] = 'bars<45'
            return out
        cols = _v95_price_cols(df)
        ccol, hcol, lcol, ocol, vcol = cols.get('close'), cols.get('high'), cols.get('low'), cols.get('open'), cols.get('volume')
        if not ccol or not hcol or not lcol:
            out['note'] = 'missing_ohlc'
            return out
        close = _v95_series(df, ccol).astype(float)
        high = _v95_series(df, hcol).astype(float)
        low = _v95_series(df, lcol).astype(float)
        open_ = _v95_series(df, ocol).astype(float) if ocol else close
        volume = _v95_series(df, vcol).astype(float) if vcol else close * 0
        n = len(close)
        cur = _v95_safe_float(close.iloc[-1], 0)
        if cur <= 0:
            out['note'] = 'no_current_price'
            return out

        look = min(120, n - 3)
        start = max(0, n - look)
        end_for_anchor = max(start + 8, n - 4)

        # 1) 스윙 고점 추출: 하락추세선의 두 기준점 찾기
        swings = []
        for i in range(start + 2, end_for_anchor - 2):
            try:
                hi = _v95_safe_float(high.iloc[i], 0)
                win = high.iloc[i-2:i+3]
                if hi > 0 and hi >= _v95_safe_float(win.max(), 0) * 0.995:
                    swings.append(i)
            except Exception:
                pass
        # 폴백: 스윙이 적으면 구간별 최고점으로 대체
        if len(swings) < 2:
            try:
                a_end = start + max(8, look // 2)
                b_start = start + max(10, look // 3)
                a = max(range(start, max(start + 1, min(a_end, n-10))), key=lambda k: _v95_safe_float(high.iloc[k], 0))
                b = max(range(max(a+8, b_start), max(max(a+9, b_start+1), n-3)), key=lambda k: _v95_safe_float(high.iloc[k], 0))
                swings = [a, b]
            except Exception:
                pass
        if len(swings) < 2:
            out['note'] = 'no_swings'
            return out

        best = None
        best_score = -10**9
        for ii, a in enumerate(swings):
            for b in swings[ii+1:]:
                if b <= a + 8:
                    continue
                h1 = _v95_safe_float(high.iloc[a], 0)
                h2 = _v95_safe_float(high.iloc[b], 0)
                if h1 <= 0 or h2 <= 0:
                    continue
                slope = (h2 - h1) / max(1, b - a)
                if slope >= 0:
                    continue
                drop_pct = (1.0 - h2 / max(h1, 1.0)) * 100.0
                if drop_pct < 2.0:
                    continue
                # 최근에 너무 멀지 않은 두 번째 고점 + 하락폭 + 기간을 함께 반영
                score = drop_pct * 3.0 + (b - a) * 0.18 - abs((n - 1) - b) * 0.02
                if score > best_score:
                    best_score = score
                    best = (a, b, h1, h2, slope, drop_pct)
        if not best:
            out['note'] = 'no_descending_pair'
            return out
        a, b, h1, h2, slope, drop_pct = best
        line_today = h1 + slope * ((n - 1) - a)
        line_prev = h1 + slope * ((n - 2) - a)
        if line_today <= 0:
            out['note'] = 'bad_line'
            return out
        slope_pct = slope / max(h1, 1.0) * 100.0

        # 2) 추세선 터치 횟수: 하락추세선 신뢰도
        touch_count = 0
        for k in range(a, min(n, b + 1)):
            lk = h1 + slope * (k - a)
            hk = _v95_safe_float(high.iloc[k], 0)
            if lk > 0 and abs(hk / lk - 1.0) <= 0.035:
                touch_count += 1

        # 3) 최근 추세선 돌파일 탐색
        break_idx = -1
        search_from = max(b + 1, n - 25)
        for k in range(search_from, n):
            lk = h1 + slope * (k - a)
            pk = h1 + slope * ((k - 1) - a) if k > 0 else lk
            ck = _v95_safe_float(close.iloc[k], 0)
            pc = _v95_safe_float(close.iloc[k-1], 0) if k > 0 else ck
            # 첫 돌파: 종가가 추세선 위로 올라오고 전일은 확실히 아래/근처였던 날
            if lk > 0 and ck >= lk * 1.005 and (k == 0 or pc <= pk * 1.008):
                break_idx = k
                break
        # 이미 위에 있지만 첫 돌파를 못 잡은 경우 최근 10봉 내 안착으로 폴백
        if break_idx < 0 and cur >= line_today * 1.005:
            for k in range(max(b+1, n-10), n):
                lk = h1 + slope * (k - a)
                if lk > 0 and _v95_safe_float(close.iloc[k], 0) >= lk * 1.005:
                    break_idx = k
                    break
        break_ok = break_idx >= 0
        break_days = (n - 1 - break_idx) if break_ok else 999

        # 4) 돌파 후 1파/첫 눌림/재출발 판정
        ma5 = close.rolling(5).mean()
        ma20 = close.rolling(20).mean()
        vol20 = volume.rolling(20).mean() if vcol else volume
        ma5v = _v95_safe_float(ma5.iloc[-1], 0)
        ma20v = _v95_safe_float(ma20.iloc[-1], 0)
        vol20v = max(_v95_safe_float(vol20.iloc[-1], 0), 1.0)
        cur_vol = _v95_safe_float(volume.iloc[-1], 0)
        vol_ratio = cur_vol / vol20v if vol20v > 0 else 0.0
        blue_line = _v95_safe_float((waves or {}).get('blue_line_price') or (waves or {}).get('blue_zone_high') or 0, 0)

        pre_low = 0.0
        post_high = 0.0
        impulse_pct = 0.0
        retrace_pct = 0.0
        if break_ok:
            pre_start = max(start, break_idx - 45)
            pre_low = _v95_safe_float(low.iloc[pre_start:break_idx+1].min(), 0)
            post_high = _v95_safe_float(high.iloc[break_idx:n].max(), 0)
            if pre_low > 0 and post_high > 0:
                impulse_pct = (post_high / pre_low - 1.0) * 100.0
                rng = post_high - pre_low
                retrace_pct = ((post_high - cur) / rng * 100.0) if rng > 0 else 0.0

        # 돌파 당시 거래량 대비 현재 눌림 거래량 감소 여부
        break_vol = _v95_safe_float(volume.iloc[break_idx], 0) if break_ok and vcol else 0
        volume_calm = bool((break_vol > 0 and cur_vol <= break_vol * 0.78) or (0 < vol_ratio <= 1.20))
        support_vals = [line_today]
        if ma20v > 0:
            support_vals.append(ma20v)
        if blue_line > 0:
            support_vals.append(blue_line)
        support_low = min([x for x in support_vals if x > 0]) if support_vals else line_today
        support_high = max([x for x in support_vals if x > 0]) if support_vals else line_today
        near_support = bool(cur >= support_low * 0.975 and cur <= support_high * 1.055)
        retest_ok = bool(break_ok and 1 <= break_days <= 12 and near_support and cur >= line_today * 0.985)
        day_up = bool(cur >= _v95_safe_float(open_.iloc[-1], cur))
        prev_close = _v95_safe_float(close.iloc[-2], cur) if n >= 2 else cur
        prev_high = _v95_safe_float(high.iloc[-2], cur) if n >= 2 else cur
        restart_ok = bool(day_up and cur >= prev_close * 0.997 and (cur >= ma5v * 0.99 if ma5v > 0 else True) and (vol_ratio >= 0.85 or cur >= prev_high * 0.997))
        first_pullback = bool(break_ok and 2 <= break_days <= 12 and impulse_pct >= 6.0 and 8.0 <= retrace_pct <= 68.0 and retest_ok and volume_calm)

        score = 0
        if slope_pct < -0.03: score += 4
        if drop_pct >= 8: score += 4
        elif drop_pct >= 4: score += 2
        if touch_count >= 2: score += 3
        if break_ok: score += 5
        if 0 <= break_days <= 12: score += 2
        if first_pullback: score += 5
        if restart_ok: score += 3
        score = min(25, score)

        zone_low = 0.0
        zone_high = 0.0
        if support_low > 0 and support_high > 0:
            zone_low = min(support_low * 0.985, support_high * 0.985)
            zone_high = max(support_low * 1.015, support_high * 1.035)
        invalids = [x for x in [line_today * 0.965, ma20v * 0.965 if ma20v > 0 else 0, blue_line * 0.97 if blue_line > 0 else 0] if x > 0]
        invalid = min(invalids) if invalids else 0.0

        out.update({
            'ok': True,
            'downtrend': True,
            'break_ok': bool(break_ok),
            'break_idx': int(break_idx),
            'break_days': int(break_days),
            'line_today': round(line_today, 2),
            'line_prev': round(line_prev, 2),
            'line_slope_pct': round(slope_pct, 4),
            'touch_count': int(touch_count),
            'trendline_score': int(score),
            'first_pullback': bool(first_pullback),
            'retest_ok': bool(retest_ok),
            'volume_calm': bool(volume_calm),
            'restart_ok': bool(restart_ok),
            'retrace_pct': round(retrace_pct, 1),
            'impulse_pct': round(impulse_pct, 1),
            'zone_low': round(zone_low, 2),
            'zone_high': round(zone_high, 2),
            'invalid': round(invalid, 2),
            'note': f"line={line_today:.0f}, break_days={break_days}, impulse={impulse_pct:.1f}, retrace={retrace_pct:.1f}, vol={vol_ratio:.2f}",
        })
        return out
    except Exception as e:
        out['note'] = f'v9.5 trendline error: {e}'
        return out


def _v92_calc_wave_pullback_timing(df, waves=None, position=None):
    base = _V95_BASE_WAVE_TIMING(df, waves, position) if _V95_BASE_WAVE_TIMING else {}
    if not isinstance(base, dict):
        base = {}
    try:
        res = dict(base)
        sig = _v95_downtrend_break_signal(df, waves=waves)
        if not sig.get('ok'):
            if res:
                dbg = str(res.get('debug', '') or '')
                res['debug'] = (dbg + ' | v9.5 ' + str(sig.get('note', ''))).strip(' |')
            return res

        trend = max(_v95_safe_int(res.get('trend_turn_score', 0), 0), 0)
        first = max(_v95_safe_int(res.get('first_wave_score', 0), 0), 0)
        pull = max(_v95_safe_int(res.get('pullback_health_score', 0), 0), 0)
        restart = max(_v95_safe_int(res.get('restart_score', 0), 0), 0)
        cur_stage = str(res.get('wave_stage', '') or '')
        cur_score = _v95_safe_int(res.get('wave_score', 0), 0)

        # 하락추세선 돌파는 단순 파동보다 우선순위를 높인다.
        if sig.get('break_ok'):
            trend = max(trend, min(25, 16 + min(7, _v95_safe_int(sig.get('trendline_score', 0), 0)//2)))
            first = max(first, 16 if sig.get('impulse_pct', 0) >= 6 else 13)
        if sig.get('first_pullback'):
            pull = max(pull, 18)
        elif sig.get('retest_ok'):
            pull = max(pull, 14)
        if sig.get('restart_ok'):
            restart = max(restart, 15)
        elif sig.get('break_ok') and _v95_safe_int(sig.get('break_days', 999), 999) <= 3:
            restart = min(max(restart, 8), 14)

        total = int(min(100, max(cur_score, trend + first + pull + restart)))
        break_days = _v95_safe_int(sig.get('break_days', 999), 999)
        stage = cur_stage or '파동관찰형'
        action = str(res.get('wave_action', '') or '관찰')
        comment = str(res.get('wave_comment', '') or '')

        if sig.get('first_pullback') and sig.get('restart_ok') and total >= 72:
            stage = '추세전환 눌림타점형'
            action = '재양봉·거래량 재유입 시 실행 우선'
            total = max(total, 82)
            comment = '하락추세선 돌파 후 1파가 나오고, 첫 눌림에서 거래량이 줄며 추세선/20일선/파란점선 지지를 확인하는 구간입니다.'
        elif sig.get('first_pullback') and total >= 64:
            stage = '추세전환 눌림대기형'
            action = '첫 눌림 지지 확인'
            total = max(total, 74)
            comment = '하락추세선 돌파 후 첫 눌림 구간입니다. 바로 매수보다 재양봉·전일고가 회복·거래량 재유입을 확인합니다.'
        elif sig.get('break_ok') and break_days <= 3 and total >= 58:
            stage = '1파발생형'
            action = '추격 금지, 첫 눌림 대기'
            total = max(total, 66)
            comment = '하락추세선 돌파로 새 1파가 발생한 구간입니다. 돌파봉 추격보다 첫 눌림을 기다리는 것이 유리합니다.'
        elif sig.get('break_ok') and total >= 55 and stage in ('관찰부족형', '바닥응축형', '파동관찰형', ''):
            stage = '추세전환형'
            action = '1파 거래량 확인'
            comment = '긴 하락추세선 위로 회복하는 전환 조짐입니다. 거래량이 붙는 1파와 이후 눌림 지지를 확인합니다.'

        # 추세선 리테스트가 계산되면 최적 눌림 구간을 추세선/20일선/파란점선 중심으로 보정한다.
        zlow = _v95_safe_float(sig.get('zone_low', 0), 0)
        zhigh = _v95_safe_float(sig.get('zone_high', 0), 0)
        if zlow > 0 and zhigh > 0 and stage in ('추세전환 눌림타점형', '추세전환 눌림대기형', '1파발생형'):
            res['best_zone_low'] = round(min(zlow, zhigh), 2)
            res['best_zone_high'] = round(max(zlow, zhigh), 2)
        if _v95_safe_float(sig.get('invalid', 0), 0) > 0:
            old_inv = _v95_safe_float(res.get('invalid_price', 0), 0)
            res['invalid_price'] = round(min([x for x in [old_inv, _v95_safe_float(sig.get('invalid', 0), 0)] if x > 0]), 2)

        res.update({
            'wave_stage': stage,
            'wave_score': int(min(100, total)),
            'trend_turn_score': int(min(25, trend)),
            'first_wave_score': int(min(25, first)),
            'pullback_health_score': int(min(25, pull)),
            'restart_score': int(min(25, restart)),
            'wave_action': action,
            'wave_comment': comment,
            'trendline_break': bool(sig.get('break_ok')),
            'trendline_first_pullback': bool(sig.get('first_pullback')),
            'trendline_price': sig.get('line_today', 0),
            'trendline_break_days': sig.get('break_days', 999),
            'trendline_retrace_pct': sig.get('retrace_pct', 0),
            'trendline_impulse_pct': sig.get('impulse_pct', 0),
            'debug': (str(res.get('debug', '') or '') + ' | v9.5 ' + str(sig.get('note', ''))).strip(' |'),
        })
        return res
    except Exception as e:
        try:
            if base:
                base['debug'] = (str(base.get('debug', '') or '') + f' | v9.5 timing error: {e}').strip(' |')
            return base
        except Exception:
            return {'wave_stage': '계산실패', 'wave_score': 0, 'wave_comment': str(e), 'wave_action': '관찰'}


try:
    _V95_BASE_WAVE_EVAL_FROM_ROW = _v93_wave_eval_from_row
except Exception:
    _V95_BASE_WAVE_EVAL_FROM_ROW = None


def _v93_wave_eval_from_row(row):
    ev = _V95_BASE_WAVE_EVAL_FROM_ROW(row) if _V95_BASE_WAVE_EVAL_FROM_ROW else {}
    if not isinstance(ev, dict):
        ev = {}
    try:
        d = _v94_to_dict(row)
    except Exception:
        d = row if isinstance(row, dict) else {}
    # 신규 stage가 실행 제외 로직에서 사라지지 않도록 stage 원본을 보존한다.
    stage = str(_v94_pick(d, '파동타점상태', 'wave_stage', default=ev.get('stage', '')) or ev.get('stage', '') or '')
    if stage in ('추세전환 눌림타점형', '추세전환 눌림대기형'):
        ev['structure_stage'] = ev.get('structure_stage') or stage
        ev['stage'] = ev.get('exec_stage') or ev.get('stage') or stage
        if ev.get('stage') in ('눌림타점형', '눌림대기형', '파동관찰형', ''):
            ev['stage'] = stage
            ev['exec_stage'] = stage
        score = _v94_int(_v94_pick(d, '파동타점점수', 'wave_score', default=ev.get('score', 0)), 0)
        if score:
            ev['score'] = max(_v94_int(ev.get('score', 0), 0), score)
            ev['exec_score'] = max(_v94_int(ev.get('exec_score', 0), 0), score)
    return ev


def _v95_wave_action(stage):
    return {
        '추세전환 눌림타점형': '재양봉·거래량 재유입 시 실행 우선',
        '추세전환 눌림대기형': '돌파추세선/20일선/파란점선 지지 확인',
        '눌림타점형': '재양봉·거래량 재유입 시 실행 우선',
        '확인대기형': '현재가·파란점선 재확인',
        '눌림대기형': '첫 눌림 지지 확인',
        '1파발생형': '추격 금지, 첫 눌림 대기',
        '추세전환형': '거래량 붙는 1파 확인',
        '회복확인형': '파란점선/5일선 회복 확인',
        '실행제외형': '신규 실행 제외',
        '파동관찰형': '파란점선 회복/안착 확인',
        '바닥응축형': '소액 관찰',
        '관찰부족형': '보수 관찰',
    }.get(str(stage), '관찰')


def _v93_wave_lines_from_row(row):
    try:
        d = _v94_to_dict(row)
    except Exception:
        d = row if isinstance(row, dict) else {}
    ev = _v93_wave_eval_from_row(d)
    if not ev:
        return []
    st0 = str(ev.get('structure_stage', ev.get('stage', '')) or '')
    sc0 = _v94_int(ev.get('structure_score', ev.get('score', 0)), 0)
    st = str(ev.get('exec_stage', ev.get('stage', '')) or '')
    sc = _v94_int(ev.get('exec_score', ev.get('score', 0)), 0)
    if not st0 and not st:
        return []
    low = _v94_float(ev.get('low', 0), 0)
    high = _v94_float(ev.get('high', 0), 0)
    invalid = _v94_float(ev.get('invalid', 0), 0)
    if invalid <= 0:
        invalid = _v94_float(_v94_pick(d, '파란점선기준가', default=0), 0) * 0.97
    if low > high > 0:
        low, high = high, low
    lines = []
    if st0 == st and sc0 == sc:
        lines.append(f"🌊 파동타점: {st} {sc}/100 | {_v95_wave_action(st)}")
    else:
        lines.append(f"🌊 파동구조: {st0} {sc0}/100")
        lines.append(f"🚦 실행판정: {st} {sc}/100 | {_v95_wave_action(st)}")
    lines.append(f"🧮 파동점수: 전환{_v94_int(ev.get('trend',0))}/25 1파{_v94_int(ev.get('first',0))}/25 눌림{_v94_int(ev.get('pull',0))}/25 재출발{_v94_int(ev.get('restart',0))}/25")
    if low > 0 and high > 0:
        cur = _v94_float(ev.get('current_price', 0), 0)
        pos = f" | 현재:{_v94_price(cur)}" if cur > 0 else ''
        zc = str(ev.get('zone_comment', '') or '')
        lines.append(f"🎯 최적눌림: {_v94_price(low)}~{_v94_price(high)}{pos}" + (f" | {zc}" if zc else ''))
    if invalid > 0:
        lines.append(f"🧯 무효가격: {_v94_price(invalid)} 이탈 시 파동눌림 관점 약화")
    # stage 자체가 추세전환형이면 해석 문구를 더 명확히 표시
    cmt = str(ev.get('comment') or _v94_pick(d, '파동실행의견', 'wave_comment', default='') or '')
    if st in ('추세전환 눌림타점형', '추세전환 눌림대기형'):
        lines.append("📐 추세선해석: 긴 하락추세선 돌파 후 첫 눌림인지 확인하는 전용 판정입니다.")
    if ev.get('exec_reason'):
        lines.append(f"⚠️ 실행제한: {ev.get('exec_reason')}")
    elif cmt:
        lines.append(f"🧭 파동타점 해석: {cmt[:110]}")
    return lines


def _v92_pick_wave_pullback_rows(frames, limit=6):
    rows_all = []
    used = set()
    for fr in frames:
        try:
            if fr is None:
                continue
            if hasattr(fr, 'iterrows'):
                rows = [r.to_dict() for _, r in fr.iterrows()]
            elif isinstance(fr, list):
                rows = [_v94_to_dict(x) for x in fr]
            else:
                rows = []
            for r in rows:
                if not r:
                    continue
                code = str(_v94_pick(r, 'code', '종목코드', 'Code', default='') or '').strip()
                name = str(_v94_pick(r, '종목명', 'name', 'Name', default='') or '').strip()
                key = code or name
                if not key or key in used:
                    continue
                ev = _v93_wave_eval_from_row(r)
                r['_v95_wave_stage'] = ev.get('stage')
                r['_v95_wave_score'] = ev.get('score')
                if _v94_is_wave_candidate_safe(r):
                    used.add(key)
                    rows_all.append(r)
        except Exception:
            continue

    def rank(r):
        ev = _v93_wave_eval_from_row(r)
        st = str(ev.get('stage', ''))
        score = _v94_int(ev.get('score', 0), 0)
        stage_bonus = {
            '추세전환 눌림타점형': 380,
            '눌림타점형': 320,
            '확인대기형': 260,
            '추세전환 눌림대기형': 255,
            '눌림대기형': 230,
            '1파발생형': 150,
            '추세전환형': 95,
            '바닥응축형': 65,
            '파동관찰형': 40,
        }.get(st, 0)
        if ev.get('zone_state') == 'inside':
            stage_bonus += 30
        return stage_bonus + score

    candidates = []
    allow = ('추세전환 눌림타점형','눌림타점형','확인대기형','추세전환 눌림대기형','눌림대기형','1파발생형')
    for r in sorted(rows_all, key=rank, reverse=True):
        ev = _v93_wave_eval_from_row(r)
        st = str(ev.get('stage', ''))
        score = _v94_int(ev.get('score', 0), 0)
        if st in allow or score >= 58:
            candidates.append(r)
        if len(candidates) >= limit:
            break
    return candidates[:limit]


def _v92_format_wave_bucket(rows):
    if not rows:
        return '- 해당 종목 없음'
    grouped = {
        '추세전환 눌림타점형': [],
        '눌림타점형': [],
        '확인대기형': [],
        '추세전환 눌림대기형': [],
        '눌림대기형': [],
        '1파발생형': [],
        '기타': [],
    }
    for r in rows:
        ev = _v93_wave_eval_from_row(r)
        st = ev.get('stage') if ev.get('stage') in grouped else '기타'
        grouped[st].append((r, ev))
    titles = [
        ('추세전환 눌림타점형', '✅ 추세전환 눌림타점형'),
        ('눌림타점형', '✅ 일반 눌림타점형'),
        ('확인대기형', '🟦 근접 확인대기형'),
        ('추세전환 눌림대기형', '👀 추세전환 눌림대기형'),
        ('눌림대기형', '👀 일반 눌림대기형'),
        ('1파발생형', '🌱 1파발생형'),
        ('기타', '🔎 파동관찰형'),
    ]
    lines = []
    rank_no = 1
    for key, title in titles:
        arr = grouped.get(key) or []
        if not arr:
            continue
        lines.append(title)
        for r, ev in arr[:3]:
            name, code = _v94_code_name(r)
            blue = str(_v94_pick(r, '파란점선상태', 'blue_line_state', default='') or '').strip()
            cur = _v94_float(ev.get('current_price', 0), 0)
            low = _v94_float(ev.get('low', 0), 0)
            high = _v94_float(ev.get('high', 0), 0)
            invalid = _v94_float(ev.get('invalid', _v94_pick(r, '파동무효화', default=0)), 0)
            if low > high > 0:
                low, high = high, low
            zone = f" | 최적:{_v94_price(low)}~{_v94_price(high)}" if low > 0 and high > 0 else ''
            cur_txt = f" | 현재:{_v94_price(cur)}" if cur > 0 else ''
            inv = f" | 무효:{_v94_price(invalid)}" if invalid > 0 else ''
            lines.append(f"{rank_no}) {name}({code}) - {ev.get('stage')} {ev.get('score')}/100 | 파란점선:{blue or '-'}{cur_txt}{zone}{inv}")
            lines.append(f"   → {_v95_wave_action(ev.get('stage'))}")
            rank_no += 1
    return '\n'.join(lines) if lines else '- 해당 종목 없음'


try:
    _V95_BASE_ACTION_BLOCK = build_trade_action_summary_block_from_frames
except Exception:
    _V95_BASE_ACTION_BLOCK = None


def build_trade_action_summary_block_from_frames(*args, **kwargs):
    try:
        base = _V95_BASE_ACTION_BLOCK(*args, **kwargs) if _V95_BASE_ACTION_BLOCK else ''
    except Exception as e:
        base = f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
    try:
        # positional args까지 최대한 흡수
        names = ['telegram_targets','wm_red_top5','wm_blue_top5','dante_pick_df','dante_watch_df','breakout_pick_df','breakout_watch_df','wm_pullback_top5','wm_late_top5','dante_ex_df']
        packed = dict(kwargs)
        for i, a in enumerate(args):
            if i < len(names) and names[i] not in packed:
                packed[names[i]] = a
        frames = []
        for k in names:
            if k in packed:
                frames.append(packed.get(k))
        rows = _v92_pick_wave_pullback_rows(frames, limit=5)
        insert = "\n🌊 추세전환 눌림타점 우선후보\n" + _v92_format_wave_bucket(rows) + "\n"
        b = str(base)
        if '📌 오늘 전략:' in b:
            b = _v95_rewrite_today_strategy(b)
        if '🌊 추세전환 눌림타점 우선후보' not in b and '🌊 파동 눌림타점 우선후보' not in b:
            for marker in ['🔥 조건부 실행 후보', '🔥 재점화 우선관찰 후보', '👀 눌림·회복 대기 후보', '👀 눌림 대기 후보']:
                if marker in b:
                    b = b.replace(marker, insert + '\n' + marker, 1)
                    break
            else:
                b = b.rstrip() + '\n' + insert
        guide = (
            "\n📘 추세전환 눌림 기준\n"
            "- 하락추세선 돌파봉은 1파발생형으로 보고 추격 금지\n"
            "- 첫 눌림은 거래량 감소 + 돌파추세선/20일선/파란점선 지지 확인\n"
            "- 재양봉·전일고가 회복·거래량 재유입이 붙으면 눌림타점형으로 격상\n"
            "- 돌파추세선 또는 파란점선 종가 이탈 시 관점 약화"
        )
        if '📘 추세전환 눌림 기준' not in b:
            if '🎯 [오늘 매매관점 압축]' in b:
                # 블록 맨 아래에 붙이면 텔레그램 가독성이 좋다.
                b = b.replace('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━', '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━', 1)
                b = b.rstrip();
                sep = '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━';
                if b.endswith(sep):
                    b = b[:-len(sep)].rstrip() + '\n' + guide + '\n' + sep
                else:
                    b = b + '\n' + guide
            else:
                b = b.rstrip() + '\n' + guide
        return b
    except Exception:
        return base


def _v95_rewrite_today_strategy(text):
    try:
        lines = str(text).splitlines()
        out = []
        for line in lines:
            if line.startswith('📌 오늘 전략:'):
                out.append('📌 오늘 전략: 강한 종목 추격보다 추세전환 후 첫 눌림·재안착·돌파추세선 지지 확인 우선')
            else:
                out.append(line)
        return '\n'.join(out)
    except Exception:
        return text


try:
    _V95_BASE_ROW_TO_AMOUNT_ITEM = _v90_row_to_amount_item
except Exception:
    _V95_BASE_ROW_TO_AMOUNT_ITEM = None


def _v90_row_to_amount_item(row, rank=0):
    d = _v94_to_dict(row)
    try:
        item = _V95_BASE_ROW_TO_AMOUNT_ITEM(row, rank=rank) if _V95_BASE_ROW_TO_AMOUNT_ITEM else {}
    except Exception:
        item = {}
    if not item:
        code = str(_v94_pick(d, 'code', '종목코드', 'Code', default='') or '').replace('.0','')
        if code.isdigit():
            code = code.zfill(6)
        item = {'code': code, '종목코드': code, 'rank': rank}
    try:
        ev = _v93_wave_eval_from_row(d)
        item.update({
            '파동타점상태': ev.get('stage'),
            '파동타점점수': int(ev.get('score', 0) or 0),
            '파동구조상태': ev.get('structure_stage', ev.get('stage')),
            '파동구조점수': int(ev.get('structure_score', ev.get('score', 0)) or 0),
            '파동실행상태': ev.get('exec_stage', ev.get('stage')),
            '파동실행점수': int(ev.get('exec_score', ev.get('score', 0)) or 0),
            '파동실행의견': str(_v94_pick(d, '파동실행의견', 'wave_comment', default=item.get('파동실행의견','')))[:600],
            'V95전략': '하락추세선돌파_첫눌림_전용판정',
        })
    except Exception:
        pass
    return item

