def _v96_text(*xs):
    try:
        return ' '.join([str(x or '') for x in xs if x is not None]).strip()
    except Exception:
        return ''


def _v96_has_any(text, keys):
    t = str(text or '')
    return any(k in t for k in keys)


def _v96_safe_pick(d, *keys, default=''):
    try:
        return _v94_pick(d, *keys, default=default)
    except Exception:
        if isinstance(d, dict):
            for k in keys:
                if k in d and d.get(k) not in (None, ''):
                    return d.get(k)
        return default


def _v96_num(d, *keys, default=0.0):
    try:
        return _v94_float(_v96_safe_pick(d, *keys, default=default), default)
    except Exception:
        try:
            return float(_v96_safe_pick(d, *keys, default=default) or default)
        except Exception:
            return default


def _v96_code_name(row):
    try:
        return _v94_code_name(row)
    except Exception:
        d = row if isinstance(row, dict) else {}
        code = str(d.get('code') or d.get('종목코드') or d.get('Code') or '').replace('.0','')
        if code.isdigit():
            code = code.zfill(6)
        name = str(d.get('종목명') or d.get('name') or d.get('Name') or code or '-')
        return name, code


def _v96_current_price(d):
    try:
        return _v94_current_price(d)
    except Exception:
        return _v96_num(d, '현재가', 'Close', 'close', '종가', default=0.0)


def _v96_price(x):
    try:
        return _v94_price(x)
    except Exception:
        try:
            v = float(x or 0)
            return f"{v:,.0f}"
        except Exception:
            return str(x)


def _v96_wyckoff_from_row(row, ev=None):
    """수박/저항구름/파란점선/파동타점 결과를 와이코프 단계로 번역한다."""
    try:
        d = _v94_to_dict(row)
    except Exception:
        d = row if isinstance(row, dict) else {}
    ev = ev if isinstance(ev, dict) else {}

    state = _v96_text(
        _v96_safe_pick(d, '상태', '수박상태', 'wm_state', 'watermelon_state', '최종상태', default=''),
        _v96_safe_pick(d, '유형', 'type', default='')
    )
    cloud = _v96_text(_v96_safe_pick(d, '저항구름', '저항구름상태', 'cloud_state', 'resistance_cloud', default=''))
    refine = _v96_text(_v96_safe_pick(d, '정제', '정제상태', '정제수박', 'wm_refine', 'refine_state', default=''))
    structure = _v96_text(_v96_safe_pick(d, '구조판정', 'structure_judgement', 'structure_state', default=''))
    trade = _v96_text(_v96_safe_pick(d, '매매판정', 'trade_decision', '최종판정', '최종 판정', default=''))
    tags = _v96_text(_v96_safe_pick(d, '태그', 'tags', 'N조합', 'n_combo', default=''))
    supply = _v96_text(_v96_safe_pick(d, '수급', '수급요약', '수급판정', 'supply', default=''))
    blue_state = _v96_text(_v96_safe_pick(d, '파란점선상태', 'blue_line_state', default=''))
    wave_stage = _v96_text(ev.get('stage') or _v96_safe_pick(d, '파동타점상태', 'wave_stage', default=''))
    wave_score = 0
    try:
        wave_score = _v94_int(ev.get('score', _v96_safe_pick(d, '파동타점점수', 'wave_score', default=0)), 0)
    except Exception:
        try:
            wave_score = int(float(_v96_safe_pick(d, '파동타점점수', 'wave_score', default=0) or 0))
        except Exception:
            wave_score = 0

    disp = _v96_num(d, '이격', 'disparity', 'Disparity', default=100.0)
    rsi = _v96_num(d, 'RSI', 'rsi', 'RSI14', default=50.0)
    cur = _v96_current_price(d)
    low = _v96_num(d, '파동최적하단', 'best_zone_low', default=ev.get('low', 0) or 0)
    high = _v96_num(d, '파동최적상단', 'best_zone_high', default=ev.get('high', 0) or 0)
    if low > high > 0:
        low, high = high, low
    invalid = _v96_num(d, '파동무효화', 'invalid_price', default=ev.get('invalid', 0) or 0)
    if invalid <= 0:
        blue_price = _v96_num(d, '파란점선기준가', 'blue_line_price', default=0)
        if blue_price > 0:
            invalid = blue_price * 0.97

    joined = _v96_text(state, cloud, refine, structure, trade, tags, supply, wave_stage, blue_state)
    is_late = _v96_has_any(joined, ['후행수박', '후행형', '보유자 대응']) or bool(ev.get('is_blocked') and _v96_has_any(joined, ['후행']))
    is_fake = _v96_has_any(joined, ['가짜수박주의', '정제주의', '실패', 'UTAD'])
    is_hot = bool(disp >= 115 or rsi >= 70 or _v96_has_any(joined, ['과열', '추격부담']))
    cloud_break = _v96_has_any(_v96_text(cloud, structure), ['저항돌파', '돌파확인', '재점화', '강한 진행형'])
    cloud_test = _v96_has_any(_v96_text(cloud, structure), ['저항테스트', '돌파테스트'])
    cloud_pre = _v96_has_any(_v96_text(cloud, structure), ['저항전', '선취'])
    refined = _v96_has_any(refine, ['✅정제수박', '정제수박']) and not is_fake
    observe_refine = _v96_has_any(refine, ['관찰수박'])
    intro_or_pullback = _v96_has_any(state, ['초입수박', '눌림수박'])
    blue_good = _v96_has_any(blue_state, ['접촉', '위안착'])
    blue_far = _v96_has_any(blue_state, ['위확장', '과이격'])
    zone_inside = str(ev.get('zone_state','')) == 'inside'
    lps_stage = _v96_has_any(wave_stage, ['눌림타점형']) and not _v96_has_any(wave_stage, ['대기'])
    lps_wait = _v96_has_any(wave_stage, ['눌림대기형', '확인대기형', '회복확인형', '1파발생형'])

    # 점수는 해석용 보조 점수. 실제 매수 추천 점수가 아니라 단계 신뢰도 표시다.
    score = 20
    if intro_or_pullback: score += 10
    if refined: score += 14
    elif observe_refine: score += 7
    if cloud_break: score += 14
    elif cloud_test: score += 9
    elif cloud_pre: score += 6
    if blue_good: score += 8
    elif blue_far: score -= 5
    if _v96_has_any(tags, ['OBV', 'OBV매집']) or _v96_has_any(supply, ['매집']): score += 8
    if _v96_has_any(supply, ['쌍끌', '외인', '기관']) and not _v96_has_any(supply, ['동반매도']): score += 6
    if _v96_has_any(tags, ['거래량', '재안착', '수급전환']): score += 6
    score += max(0, min(18, int(wave_score * 0.18)))
    if is_fake: score -= 20
    if is_late: score -= 12
    if is_hot: score -= 14
    if disp >= 125 or rsi >= 80: score -= 8
    score = max(0, min(100, int(score)))

    # 단계 판정: '좋은 돌파'와 '좋은 매수가'를 반드시 분리한다.
    if is_fake or (is_hot and (is_late or cloud_break)):
        stage = 'UTAD/실패돌파 주의'
        action = '신규 추격 금지, 보유자는 이탈선·분할 대응'
        comment = '상단 돌파처럼 보여도 과열·윗꼬리·후행·가짜수박 요소가 있어 박스 안 재진입 위험을 먼저 봅니다.'
        invalid_text = '돌파 기준선 아래 재진입 또는 거래량 실린 음봉이면 실패돌파로 봅니다.'
    elif lps_stage and (blue_good or zone_inside or cloud_break):
        stage = 'LPS 재지지 후보'
        action = '재양봉·거래량 재유입 시 실행 우선'
        comment = 'SOS 이후 눌림에서 파란점선/5일선/구름상단 지지를 확인하는 구간입니다. 추격보다 재지지 확인이 핵심입니다.'
        invalid_text = '파란점선 또는 눌림 저점 이탈 시 LPS 관점이 약화됩니다.'
    elif cloud_break and lps_wait:
        stage = 'SOS 돌파 후 LPS 대기'
        action = '박스상단·구름상단·파란점선 재지지 확인'
        comment = '박스 상단 돌파는 확인됐지만 아직 실전 타점은 눌림 재지지 확인 뒤가 유리합니다.'
        invalid_text = '돌파한 저항구름/박스 상단 아래로 종가가 밀리면 실패 가능성을 봅니다.'
    elif cloud_break:
        stage = 'SOS 돌파 확인형'
        action = '돌파 추격보다 LPS 눌림 대기'
        comment = '매집 구간 이후 상단 돌파가 나온 형태입니다. 거래량 유지와 돌파선 지지 전환을 확인합니다.'
        invalid_text = '돌파 기준선 아래 재진입 시 SOS 신뢰도가 낮아집니다.'
    elif cloud_test:
        stage = 'SOS 테스트형'
        action = '거래량 유지와 구름상단 안착 확인'
        comment = '아직 완전 돌파보다 저항구름을 시험하는 구간입니다. 종가 안착과 다음 봉 저점 보존이 필요합니다.'
        invalid_text = '저항 테스트 후 박스 안으로 밀리면 관찰 등급을 낮춥니다.'
    elif cloud_pre or (intro_or_pullback and (refined or observe_refine)):
        stage = 'Accumulation 후반 관찰형'
        action = '소액 관찰, SOS 돌파 전까지 확인 우선'
        comment = '매집 흔적은 있으나 아직 상단 돌파 전입니다. 거래량 보강과 양봉 마감이 먼저입니다.'
        invalid_text = '박스 하단 또는 주요 이평 이탈 시 매집 관점이 약화됩니다.'
    else:
        stage = '와이코프 관찰부족형'
        action = '매집·돌파·재지지 증거 추가 확인'
        comment = '현재 정보만으로는 매집 완료나 진짜 돌파를 단정하기 어렵습니다.'
        invalid_text = '거래량 없는 돌파와 박스 재진입은 보수적으로 봅니다.'

    # LPS/SOS라도 과열이면 액션만 한 단계 보수화한다.
    caution = []
    if is_fake: caution.append('가짜수박주의')
    if is_late: caution.append('후행')
    if disp >= 115: caution.append(f'이격 {disp:.0f}')
    if rsi >= 70: caution.append(f'RSI {rsi:.0f}')
    if blue_far: caution.append('파란점선 과이격')
    if caution and stage not in ('UTAD/실패돌파 주의',):
        action = '추격 금지, 눌림 재지지 확인 후 판단'

    return {
        'stage': stage,
        'score': score,
        'action': action,
        'comment': comment,
        'invalid_text': invalid_text,
        'caution': ' / '.join(caution),
        'cloud': cloud,
        'refine': refine,
        'blue_state': blue_state,
        'wave_stage': wave_stage,
        'wave_score': wave_score,
        'disparity': disp,
        'rsi': rsi,
        'current_price': cur,
        'low': low,
        'high': high,
        'invalid': invalid,
        'is_actionable': stage in ('LPS 재지지 후보',) and not caution,
        'is_wait': stage in ('SOS 돌파 후 LPS 대기', 'SOS 돌파 확인형', 'SOS 테스트형', 'Accumulation 후반 관찰형'),
        'is_risk': stage == 'UTAD/실패돌파 주의',
    }


try:
    _V96_BASE_WAVE_EVAL_FROM_ROW = _v93_wave_eval_from_row
except Exception:
    _V96_BASE_WAVE_EVAL_FROM_ROW = None


def _v93_wave_eval_from_row(row):
    base = _V96_BASE_WAVE_EVAL_FROM_ROW(row) if _V96_BASE_WAVE_EVAL_FROM_ROW else {}
    if not isinstance(base, dict):
        base = {}
    try:
        wy = _v96_wyckoff_from_row(row, base)
        base.update({
            'wyckoff_stage': wy.get('stage'),
            'wyckoff_score': wy.get('score'),
            'wyckoff_action': wy.get('action'),
            'wyckoff_comment': wy.get('comment'),
            'wyckoff_invalid_text': wy.get('invalid_text'),
            'wyckoff_caution': wy.get('caution'),
        })
    except Exception:
        pass
    return base


try:
    _V96_BASE_WAVE_LINES_FROM_ROW = _v93_wave_lines_from_row
except Exception:
    _V96_BASE_WAVE_LINES_FROM_ROW = None


def _v96_wyckoff_lines_from_row(row):
    try:
        ev = _v93_wave_eval_from_row(row)
    except Exception:
        ev = {}
    wy = _v96_wyckoff_from_row(row, ev)
    if not wy:
        return []
    lines = []
    lines.append(f"📦 와이코프 단계: {wy.get('stage')} | 점수 {wy.get('score')}/100")
    lines.append(f"📌 해석: {str(wy.get('comment',''))[:150]}")
    lines.append(f"🎯 실행: {wy.get('action')}")
    if wy.get('caution'):
        lines.append(f"⚠️ 주의: {wy.get('caution')}")
    invalid_txt = str(wy.get('invalid_text') or '')
    invalid_price = _v96_num(wy, 'invalid', default=0)
    if invalid_price > 0:
        lines.append(f"🧯 무효: {_v96_price(invalid_price)} 이탈 또는 {invalid_txt}")
    else:
        lines.append(f"🧯 무효: {invalid_txt}")
    return lines


def _v93_wave_lines_from_row(row):
    try:
        lines = list(_V96_BASE_WAVE_LINES_FROM_ROW(row) if _V96_BASE_WAVE_LINES_FROM_ROW else [])
    except Exception:
        lines = []
    try:
        joined = '\n'.join(map(str, lines))
        if '와이코프 단계' not in joined:
            lines.extend(_v96_wyckoff_lines_from_row(row))
    except Exception:
        pass
    return lines


def _v96_rows_from_frames(frames):
    rows = []
    used = set()
    for fr in frames:
        try:
            if fr is None:
                continue
            if hasattr(fr, 'iterrows'):
                iterable = [r.to_dict() for _, r in fr.iterrows()]
            elif isinstance(fr, list):
                iterable = [_v94_to_dict(x) for x in fr]
            elif isinstance(fr, dict):
                iterable = [fr]
            else:
                iterable = []
            for r in iterable:
                if not r:
                    continue
                name, code = _v96_code_name(r)
                key = code or name
                if not key or key in used:
                    continue
                used.add(key)
                rows.append(r)
        except Exception:
            continue
    return rows


def _v96_wyckoff_rank(row):
    try:
        ev = _v93_wave_eval_from_row(row)
        wy = _v96_wyckoff_from_row(row, ev)
        st = wy.get('stage')
        score = int(wy.get('score') or 0)
        bonus = {
            'LPS 재지지 후보': 500,
            'SOS 돌파 후 LPS 대기': 420,
            'SOS 돌파 확인형': 360,
            'SOS 테스트형': 300,
            'Accumulation 후반 관찰형': 220,
            'UTAD/실패돌파 주의': 80,
        }.get(st, 0)
        if wy.get('is_risk'):
            bonus -= 120
        return bonus + score
    except Exception:
        return 0


def _v96_format_wyckoff_bucket(rows, limit=6):
    if not rows:
        return '- 해당 종목 없음'
    rows = sorted(rows, key=_v96_wyckoff_rank, reverse=True)
    buckets = {
        'LPS 재지지 후보': [],
        'SOS 돌파 후 LPS 대기': [],
        'SOS 돌파 확인형': [],
        'SOS 테스트형': [],
        'Accumulation 후반 관찰형': [],
        'UTAD/실패돌파 주의': [],
    }
    for r in rows:
        ev = _v93_wave_eval_from_row(r)
        wy = _v96_wyckoff_from_row(r, ev)
        st = wy.get('stage')
        if st in buckets:
            buckets[st].append((r, wy))
    titles = [
        ('LPS 재지지 후보', '✅ LPS 재지지 실행 우선'),
        ('SOS 돌파 후 LPS 대기', '👀 SOS 돌파 후 LPS 대기'),
        ('SOS 돌파 확인형', '🚀 SOS 돌파 확인'),
        ('SOS 테스트형', '🧪 SOS 테스트 관찰'),
        ('Accumulation 후반 관찰형', '📦 Accumulation 후반 관찰'),
        ('UTAD/실패돌파 주의', '⛔ UTAD/실패돌파 주의'),
    ]
    lines = []
    n = 1
    shown = 0
    for key, title in titles:
        arr = buckets.get(key) or []
        if not arr:
            continue
        # 위험 후보는 오늘 압축에서 너무 길어지지 않게 3개까지만
        max_each = 2 if key == 'UTAD/실패돌파 주의' else 3
        lines.append(title)
        for r, wy in arr[:max_each]:
            if shown >= limit and key != 'UTAD/실패돌파 주의':
                break
            name, code = _v96_code_name(r)
            blue = wy.get('blue_state') or '-'
            wave = wy.get('wave_stage') or '-'
            cur = _v96_num(wy, 'current_price', default=0)
            low = _v96_num(wy, 'low', default=0)
            high = _v96_num(wy, 'high', default=0)
            zone = ''
            if low > 0 and high > 0:
                zone = f" | LPS:{_v96_price(low)}~{_v96_price(high)}"
            cur_txt = f" | 현재:{_v96_price(cur)}" if cur > 0 else ''
            caution = f" | 주의:{wy.get('caution')}" if wy.get('caution') else ''
            lines.append(f"{n}) {name}({code}) - {wy.get('stage')} {wy.get('score')}/100 | 파란점선:{blue} | 파동:{wave}{cur_txt}{zone}{caution}")
            lines.append(f"   → {wy.get('action')}")
            n += 1
            shown += 1
        if shown >= limit and key != 'UTAD/실패돌파 주의':
            break
    return '\n'.join(lines) if lines else '- 해당 종목 없음'


def _v96_insert_before_final_sep(text, insert):
    b = str(text or '')
    sep = '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
    if not insert:
        return b
    if b.rstrip().endswith(sep):
        return b.rstrip()[:-len(sep)].rstrip() + '\n' + insert.rstrip() + '\n' + sep
    return b.rstrip() + '\n' + insert.rstrip()


try:
    _V96_BASE_ACTION_BLOCK = build_trade_action_summary_block_from_frames
except Exception:
    _V96_BASE_ACTION_BLOCK = None


def build_trade_action_summary_block_from_frames(*args, **kwargs):
    try:
        base = _V96_BASE_ACTION_BLOCK(*args, **kwargs) if _V96_BASE_ACTION_BLOCK else ''
    except Exception as e:
        base = f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
    try:
        names = ['telegram_targets','wm_red_top5','wm_blue_top5','dante_pick_df','dante_watch_df','breakout_pick_df','breakout_watch_df','wm_pullback_top5','wm_late_top5','dante_ex_df']
        packed = dict(kwargs)
        for i, a in enumerate(args):
            if i < len(names) and i not in packed:
                packed[names[i]] = a
        frames = [packed.get(k) for k in names if k in packed]
        rows = _v96_rows_from_frames(frames)
        # 위험만 있는 경우를 피하고, LPS/SOS/Accumulation 후보 중심으로 보여준다.
        wy_rows = []
        for r in rows:
            ev = _v93_wave_eval_from_row(r)
            wy = _v96_wyckoff_from_row(r, ev)
            if wy.get('stage') in ('LPS 재지지 후보','SOS 돌파 후 LPS 대기','SOS 돌파 확인형','SOS 테스트형','Accumulation 후반 관찰형','UTAD/실패돌파 주의'):
                wy_rows.append(r)
        section = "\n📦 와이코프 SOS/LPS 후보\n" + _v96_format_wyckoff_bucket(wy_rows, limit=6) + "\n"
        b = str(base)
        if '📦 와이코프 SOS/LPS 후보' not in b:
            markers = ['🌊 추세전환 눌림타점 우선후보', '🌊 파동 눌림타점 우선후보', '🔥 재점화 우선관찰 후보', '✅ 조건부 실행 후보', '👀 눌림 대기 후보']
            inserted = False
            for m in markers:
                if m in b:
                    b = b.replace(m, section + '\n' + m, 1)
                    inserted = True
                    break
            if not inserted:
                b = b.rstrip() + '\n' + section
        guide = (
            "\n📘 와이코프 SOS/LPS 기준\n"
            "- Accumulation: 매집 박스·거래량 감소·OBV/수급 개선을 보는 관찰 단계\n"
            "- SOS: 박스 상단/저항구름을 거래량과 함께 돌파한 확인 단계, 단 추격은 보수적\n"
            "- LPS: 돌파 후 박스상단·구름상단·5일선·파란점선 재지지 확인 구간, 실전 타점 우선\n"
            "- UTAD/실패돌파: 돌파 후 박스 안 재진입, 긴 윗꼬리, 이격115↑, RSI70↑이면 신규 추격 금지"
        )
        if '📘 와이코프 SOS/LPS 기준' not in b:
            b = _v96_insert_before_final_sep(b, guide)
        # 오늘 전략 문구도 와이코프 설명을 살짝 보강
        try:
            lines = []
            for line in b.splitlines():
                if line.startswith('📌 오늘 전략:') and 'SOS/LPS' not in line:
                    lines.append('📌 오늘 전략: 강한 종목 추격보다 SOS 확인 후 LPS 재지지·파란점선/구름상단 지지 확인 우선')
                else:
                    lines.append(line)
            b = '\n'.join(lines)
        except Exception:
            pass
        return b
    except Exception:
        return base


