def _v97_to_dict(row):
    try:
        return _v94_to_dict(row)
    except Exception:
        try:
            return _v87_row_dict(row)
        except Exception:
            return row if isinstance(row, dict) else {}


def _v97_num(d, *keys, default=0.0):
    try:
        return _v96_num(d, *keys, default=default)
    except Exception:
        for k in keys:
            try:
                if isinstance(d, dict) and k in d and d.get(k) not in (None, ''):
                    return float(str(d.get(k)).replace(',', '').replace('%', ''))
            except Exception:
                pass
        return default


def _v97_txt(d, *keys, default=''):
    vals = []
    try:
        for k in keys:
            if isinstance(d, dict) and d.get(k) not in (None, ''):
                vals.append(str(d.get(k)))
        return ' '.join(vals).strip() or default
    except Exception:
        return default


def _v97_has(text, keys):
    t = str(text or '')
    return any(str(k) in t for k in keys)


def _v97_name_code(row):
    try:
        return _v96_code_name(row)
    except Exception:
        d = _v97_to_dict(row)
        code = str(d.get('code') or d.get('종목코드') or d.get('Code') or '').replace('.0', '')
        if code.isdigit(): code = code.zfill(6)
        return str(d.get('종목명') or d.get('name') or d.get('Name') or code or '-'), code


def _v97_price(x):
    try:
        return _v96_price(x)
    except Exception:
        try: return f"{float(x or 0):,.0f}"
        except Exception: return str(x)


def _v97_iter_rows(obj):
    rows = []
    try:
        if obj is None:
            return rows
        if hasattr(obj, 'iterrows'):
            for _, r in obj.iterrows():
                rows.append(r.to_dict())
        elif isinstance(obj, list):
            for x in obj:
                rows.append(_v97_to_dict(x))
        elif isinstance(obj, dict):
            rows.append(obj)
    except Exception:
        pass
    return rows


def _v97_collect_rows(*args, **kwargs):
    names = [
        'telegram_targets','ai_candidates','all_hits_df','all_hits_df_for_pre',
        'wm_red_top5','wm_blue_top5','wm_intro_top5','wm_pullback_top5','wm_late_top5',
        'dante_pick_df','dante_watch_df','dante_ex_df','breakout_pick_df','breakout_watch_df',
        'amount_top60_df'
    ]
    packed = dict(kwargs)
    for i, a in enumerate(args):
        if i < len(names) and names[i] not in packed:
            packed[names[i]] = a
    rows, used = [], set()
    for k in names:
        for r in _v97_iter_rows(packed.get(k)):
            if not r:
                continue
            name, code = _v97_name_code(r)
            key = code or name
            if not key or key in used:
                continue
            used.add(key)
            try:
                rr = dict(r)
                rr['_v97_source'] = k
                rows.append(rr)
            except Exception:
                rows.append(r)
    return rows


def _v97_dedicated_wyckoff_from_row(row):
    """전용 검색식으로 Accumulation/SOS/LPS를 별도 판정한다."""
    d = _v97_to_dict(row)
    try:
        ev = _v93_wave_eval_from_row(d)
    except Exception:
        ev = {}
    try:
        base = _v96_wyckoff_from_row(d, ev)
    except Exception:
        base = {'stage': '와이코프 관찰부족형', 'score': 0, 'action': '', 'comment': '', 'caution': ''}

    text = ' '.join([
        _v97_txt(d, '구분','N구분','태그','N조합','단계태그','수박정제태그','저항구름','저항구름상태','구조판정','매매판정','파동타점상태','파란점선상태','수급','수급요약','수급판정'),
        str(base.get('stage','')), str(base.get('caution',''))
    ])
    disp = _v97_num(d, '이격','Disparity','과열이격도', default=100.0)
    rsi = _v97_num(d, 'RSI','RSI14', default=50.0)
    vol_ratio = max(_v97_num(d, '거래량배수','vol_ratio', default=0.0), _v97_num(d, '매집거래량배율','Maejip_Vol_Ratio', default=0.0))
    obv = _v97_num(d, 'OBV기울기','OBV_Slope','OBV_SLOPE_5','OBV_SLOPE_10', default=0.0)
    ma_struct = _v97_num(d, '구조MA수렴도','MAConv_20_60_112','MA수렴', default=99.0)
    ma_short = _v97_num(d, '초단기MA수렴도','단기MA수렴도','MAConv_5_10_20','MAConv_5_20_60', default=99.0)
    box_small_pos = _v97_num(d, '소파동위치퍼센트','small_pos_pct', default=-1.0)
    box_mid_pos = _v97_num(d, '중파동위치퍼센트','mid_pos_pct', default=-1.0)
    small_angle = abs(_v97_num(d, '소파동각도','small_angle', default=0.0))
    mid_angle = abs(_v97_num(d, '중파동각도','mid_angle', default=0.0))
    force_score = _v97_num(d, '세력흔적점수','force_trace_score', default=0.0)
    refine_hist = _v97_num(d, '정제이력점수','recent_refine_score', default=0.0)
    maejip_score = _v97_num(d, '매집점수','Maejip_Score', default=0.0)
    maejip_days = max(_v97_num(d, '매집일수_10일','매집일수_20일','Green_Maejip_Days', default=0.0), _v97_num(d, '최근3일매집','Maejip_Recent3', default=0.0))
    breakout_score = _v97_num(d, '돌파점수','흰구름돌파점수', default=0.0)
    wave_score = _v97_num(d, '파동타점점수','wave_score', default=base.get('wave_score', 0) or 0)
    blue_state = _v97_txt(d, '파란점선상태','blue_line_state', default=str(base.get('blue_state','')))
    wave_stage = _v97_txt(d, '파동타점상태','wave_stage', default=str(base.get('wave_stage','')))
    cloud = _v97_txt(d, '저항구름상태','저항구름','cloud_state','resistance_cloud','구조판정', default=str(base.get('cloud','')))
    refine = _v97_txt(d, '수박정제태그','정제','정제상태','wm_refine','refine_state', default=str(base.get('refine','')))

    # 1) Accumulation: 박스/응축/매집 흔적
    acc_score = 0; acc_reasons = []
    if _v97_has(text, ['초입수박','눌림수박','정제수박','관찰수박']): acc_score += 18; acc_reasons.append('수박/정제 구조')
    if maejip_score >= 35 or maejip_days >= 3: acc_score += 16; acc_reasons.append('매집점수/매집일수')
    if force_score >= 18 or refine_hist >= 7: acc_score += 14; acc_reasons.append('세력흔적/정제이력')
    if ma_struct <= 8 or ma_short <= 6 or _v97_has(text, ['초단기수렴','구조수렴','브릿지수렴','좋은수렴']): acc_score += 14; acc_reasons.append('이평응축')
    if 25 <= box_small_pos <= 85 or 25 <= box_mid_pos <= 85: acc_score += 10; acc_reasons.append('박스 내부 위치')
    if small_angle <= 20 or mid_angle <= 20: acc_score += 6; acc_reasons.append('박스/완만 추세')

    # 2) SOS: 거래량/OBV 동반 상단 돌파
    sos_score = 0; sos_reasons = []
    if _v97_has(cloud + text, ['저항돌파','돌파확인','흰구름돌파형','재점화 확인형','BB40상단돌파']): sos_score += 24; sos_reasons.append('저항/구름 상단 돌파')
    elif _v97_has(cloud + text, ['저항테스트','돌파테스트','구름테스트']): sos_score += 14; sos_reasons.append('저항 테스트')
    if breakout_score >= 60: sos_score += 16; sos_reasons.append(f'돌파점수 {int(breakout_score)}')
    if vol_ratio >= 1.3 or _v97_has(text, ['거래량폭발','거래량3배','거래량','거래량 재유입']): sos_score += 14; sos_reasons.append('거래량 동반')
    if obv > 0 or _v97_has(text, ['OBV매집','OBV우상향','OBV매집돌파']): sos_score += 12; sos_reasons.append('OBV 개선')
    if _v97_has(text, ['쌍끌','외인','기관','수급전환','강매집']) and not _v97_has(text, ['동반매도']): sos_score += 8; sos_reasons.append('수급 결합')

    # 3) LPS: 돌파 후 눌림 재지지
    lps_score = 0; lps_reasons = []
    if _v97_has(wave_stage, ['눌림타점형']): lps_score += 28; lps_reasons.append('눌림타점형')
    elif _v97_has(wave_stage, ['눌림대기형','회복확인형','1파발생형']): lps_score += 14; lps_reasons.append('눌림대기/1파')
    if _v97_has(blue_state, ['접촉','위안착']): lps_score += 18; lps_reasons.append('파란점선 지지권')
    elif _v97_has(blue_state, ['아래']): lps_score += 6; lps_reasons.append('파란점선 회복 대기')
    if wave_score >= 80: lps_score += 12; lps_reasons.append(f'파동점수 {int(wave_score)}')
    if _v97_has(text, ['5일재안착','재안착','구름상단 지지','눌림 후 재양봉']): lps_score += 10; lps_reasons.append('재안착/재양봉')

    risk = []
    if _v97_has(text + refine, ['가짜수박주의','정제주의','UTAD','실패돌파']): risk.append('가짜/정제주의')
    if _v97_has(text, ['후행수박','후행형','보유자 대응']): risk.append('후행')
    if disp >= 115: risk.append(f'이격 {disp:.0f}')
    if rsi >= 70: risk.append(f'RSI {rsi:.0f}')
    if _v97_has(blue_state, ['과이격']) or _v97_num(d, '파란점선이격', default=0.0) >= 6: risk.append('파란점선 과이격')

    dedicated_score = max(0, min(100, int(0.34*acc_score + 0.36*sos_score + 0.30*lps_score + 20)))
    if risk:
        dedicated_score = max(0, dedicated_score - min(30, 7 * len(risk)))

    # 전용 검색식 단계 판정. 기존 V96 라벨보다 전용 조건을 우선 적용한다.
    if risk and sos_score >= 28 and (disp >= 115 or rsi >= 70 or _v97_has(text, ['후행수박','가짜수박주의'])):
        stage = 'UTAD/실패돌파 주의'
        action = '신규 추격 금지, 보유자는 이탈선·분할 대응'
        comment = '상단 돌파처럼 보여도 과열·후행·가짜수박 요소가 있어 박스 안 재진입 위험을 먼저 봅니다.'
    elif acc_score >= 36 and sos_score >= 38 and lps_score >= 36:
        stage = 'LPS 재지지 후보'
        action = '재양봉·거래량 재유입 시 실행 우선'
        comment = '매집 후 SOS가 확인되고, 눌림에서 파란점선·5일선·구름상단 재지지를 보는 실전 타점입니다.'
    elif acc_score >= 32 and sos_score >= 38 and lps_score >= 18:
        stage = 'SOS 돌파 후 LPS 대기'
        action = '박스상단·구름상단·파란점선 재지지 확인'
        comment = '매집 구간 상단 돌파는 보였지만, 추격보다 돌파선 지지 전환을 기다리는 구간입니다.'
    elif acc_score >= 28 and sos_score >= 38:
        stage = 'SOS 돌파 확인형'
        action = '돌파 추격보다 LPS 눌림 대기'
        comment = '거래량/OBV가 붙은 상단 돌파 후보입니다. 단기 과열 여부와 다음 봉 저점 보존을 봅니다.'
    elif acc_score >= 24 and sos_score >= 24:
        stage = 'SOS 테스트형'
        action = '거래량 유지와 구름상단 안착 확인'
        comment = '아직 완전 돌파보다는 저항을 시험하는 구간입니다. 종가 안착이 먼저입니다.'
    elif acc_score >= 34:
        stage = 'Accumulation 후반 관찰형'
        action = '소액 관찰, SOS 돌파 전까지 확인 우선'
        comment = '매집·응축 흔적은 있으나 아직 상단 돌파가 부족합니다. 거래량 동반 돌파를 기다립니다.'
    else:
        stage = base.get('stage', '와이코프 관찰부족형')
        action = base.get('action', '매집·돌파·재지지 증거 추가 확인')
        comment = base.get('comment', '와이코프 전용 검색식 기준으로는 아직 증거가 부족합니다.')
        dedicated_score = max(dedicated_score, int(base.get('score', 0) or 0))

    # LPS라도 위험이 있으면 실행 문구만 보수화한다.
    if risk and stage != 'UTAD/실패돌파 주의':
        action = '추격 금지, 눌림 재지지 확인 후 판단'

    out = dict(base)
    out.update({
        'stage': stage,
        'score': int(max(dedicated_score, int(base.get('score', 0) or 0)) if stage != 'UTAD/실패돌파 주의' else dedicated_score),
        'action': action,
        'comment': comment,
        'caution': ' / '.join(risk),
        'acc_score': int(acc_score), 'sos_score': int(sos_score), 'lps_score': int(lps_score),
        'acc_reasons': ', '.join(acc_reasons[:4]), 'sos_reasons': ', '.join(sos_reasons[:4]), 'lps_reasons': ', '.join(lps_reasons[:4]),
        'search_formula': 'Accumulation(박스/매집/응축)+SOS(거래량/OBV/상단돌파)+LPS(재지지/파란점선)',
    })
    return out


def _v97_is_wyckoff_candidate(row):
    wy = _v97_dedicated_wyckoff_from_row(row)
    st = str(wy.get('stage',''))
    if st in ('LPS 재지지 후보','SOS 돌파 후 LPS 대기','SOS 돌파 확인형','SOS 테스트형','Accumulation 후반 관찰형','UTAD/실패돌파 주의'):
        return True
    return int(wy.get('acc_score',0)) >= 34 or int(wy.get('sos_score',0)) >= 34


def _v97_wyckoff_rank(row):
    wy = _v97_dedicated_wyckoff_from_row(row)
    st = wy.get('stage')
    base = {
        'LPS 재지지 후보': 600,
        'SOS 돌파 후 LPS 대기': 520,
        'SOS 돌파 확인형': 450,
        'SOS 테스트형': 360,
        'Accumulation 후반 관찰형': 280,
        'UTAD/실패돌파 주의': 60,
    }.get(st, 0)
    return base + int(wy.get('score',0) or 0) + int(wy.get('sos_score',0) or 0)


def _v97_format_wyckoff_bucket(rows, limit=8):
    rows = [r for r in rows if _v97_is_wyckoff_candidate(r)]
    if not rows:
        return '- 해당 종목 없음'
    rows = sorted(rows, key=_v97_wyckoff_rank, reverse=True)
    bucket_order = [
        ('LPS 재지지 후보', '✅ LPS 재지지 실행 우선'),
        ('SOS 돌파 후 LPS 대기', '👀 SOS 돌파 후 LPS 대기'),
        ('SOS 돌파 확인형', '🚀 SOS 돌파 확인'),
        ('SOS 테스트형', '🧪 SOS 테스트 관찰'),
        ('Accumulation 후반 관찰형', '📦 Accumulation 후반 관찰'),
        ('UTAD/실패돌파 주의', '⛔ UTAD/실패돌파 주의'),
    ]
    buckets = {k: [] for k, _ in bucket_order}
    for r in rows:
        wy = _v97_dedicated_wyckoff_from_row(r)
        if wy.get('stage') in buckets:
            buckets[wy.get('stage')].append((r, wy))
    out, n, shown = [], 1, 0
    for st, title in bucket_order:
        arr = buckets.get(st) or []
        if not arr:
            continue
        out.append(title)
        max_each = 2 if st == 'UTAD/실패돌파 주의' else 4
        for r, wy in arr[:max_each]:
            if shown >= limit and st != 'UTAD/실패돌파 주의':
                break
            name, code = _v97_name_code(r)
            d = _v97_to_dict(r)
            cur = _v97_num(d, '현재가','Close','Price','종가', default=0)
            blue = _v97_txt(d, '파란점선상태', default=str(wy.get('blue_state','-') or '-'))
            wave = _v97_txt(d, '파동타점상태', default=str(wy.get('wave_stage','-') or '-'))
            low = _v97_num(d, '파동최적하단', default=wy.get('low',0) or 0)
            high = _v97_num(d, '파동최적상단', default=wy.get('high',0) or 0)
            zone = f" | LPS:{_v97_price(low)}~{_v97_price(high)}" if low > 0 and high > 0 else ''
            cur_txt = f" | 현재:{_v97_price(cur)}" if cur > 0 else ''
            caution = f" | 주의:{wy.get('caution')}" if wy.get('caution') else ''
            out.append(f"{n}) {name}({code}) - {wy.get('stage')} {wy.get('score')}/100 | A/S/L {wy.get('acc_score')}/{wy.get('sos_score')}/{wy.get('lps_score')} | 파란점선:{blue} | 파동:{wave}{cur_txt}{zone}{caution}")
            reason = ' / '.join([x for x in [wy.get('acc_reasons'), wy.get('sos_reasons'), wy.get('lps_reasons')] if x])
            if reason:
                out.append(f"   - 검색근거: {reason[:120]}")
            out.append(f"   → {wy.get('action')}")
            n += 1; shown += 1
        if shown >= limit and st != 'UTAD/실패돌파 주의':
            break
    return '\n'.join(out) if out else '- 해당 종목 없음'


def _v97_insert_wyckoff_section(base, rows):
    b = str(base or '')
    section = (
        "\n📦 와이코프 전용검색 결과\n"
        "- 검색식: Accumulation(박스/매집/응축) + SOS(거래량/OBV/상단돌파) + LPS(재지지/파란점선)\n"
        + _v97_format_wyckoff_bucket(rows, limit=8) + "\n"
    )
    if '📦 와이코프 전용검색 결과' in b:
        return b
    if '📦 와이코프 SOS/LPS 후보' in b:
        return b.replace('📦 와이코프 SOS/LPS 후보', section + '\n📦 와이코프 SOS/LPS 후보', 1)
    for m in ['🌊 추세전환 눌림타점 우선후보','🌊 파동 눌림타점 우선후보','🔥 재점화 우선관찰 후보','✅ 조건부 실행 후보','👀 눌림 대기 후보']:
        if m in b:
            return b.replace(m, section + '\n' + m, 1)
    sep = '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
    if b.rstrip().endswith(sep):
        return b.rstrip()[:-len(sep)].rstrip() + '\n' + section.rstrip() + '\n' + sep
    return b.rstrip() + '\n' + section.rstrip()


def build_trade_action_summary_block_from_frames(*args, **kwargs):
    try:
        base = _V97_BASE_ACTION_BLOCK(*args, **kwargs) if _V97_BASE_ACTION_BLOCK else ''
    except Exception as e:
        base = f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
    try:
        rows = _v97_collect_rows(*args, **kwargs)
        b = _v97_insert_wyckoff_section(base, rows)
        # 전략 문구를 V97 기준으로 한 번 더 보정
        try:
            lines=[]
            for line in b.splitlines():
                if line.startswith('📌 오늘 전략:') and '와이코프' not in line:
                    lines.append('📌 오늘 전략: 와이코프 SOS 돌파는 추격보다 LPS 재지지·파란점선/구름상단 지지 확인 우선')
                else:
                    lines.append(line)
            b='\n'.join(lines)
        except Exception:
            pass
        guide = (
            "\n📘 와이코프 전용검색 기준\n"
            "- A점수: 박스권·매집일수·세력흔적·정제이력·이평응축\n"
            "- S점수: 저항구름/박스 상단 돌파 + 거래량/OBV + 수급 결합\n"
            "- L점수: SOS 이후 눌림, 파란점선 접촉/위안착, 재양봉/재안착\n"
            "- 과열/후행/가짜수박주의는 UTAD 또는 추격금지로 보수화"
        )
        if '📘 와이코프 전용검색 기준' not in b:
            try:
                b = _v96_insert_before_final_sep(b, guide)
            except Exception:
                b = b.rstrip() + guide
        return b
    except Exception:
        return base


def _v81_build_today_action_summary_safe(**kwargs):
    try:
        return build_trade_action_summary_block_from_frames(**kwargs)
    except Exception as e:
        return f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"


def _v97_dedupe_items(items, limit=None):
    out, used = [], set()
    for it in items or []:
        if not isinstance(it, dict):
            continue
        code = str(it.get('code') or it.get('종목코드') or '').replace('.0','')
        if code.isdigit(): code = code.zfill(6)
        name = str(it.get('name') or it.get('종목명') or code or '').strip()
        key = code or name
        if not key or key in used:
            continue
        used.add(key); out.append(it)
        if limit and len(out) >= limit:
            break
    return out


def _v97_row_to_quick_item(row, rank=0):
    d = _v97_to_dict(row)
    name, code = _v97_name_code(d)
    wy = _v97_dedicated_wyckoff_from_row(d)
    cur = int(_v97_num(d, '현재가','Close','Price','종가', default=0) or 0)
    return {
        'code': code, '종목코드': code, 'name': name, '종목명': name,
        'source': '와이코프전용검색', 'universe_group': 'wyckoff_dedicated', 'rank': int(rank or 0),
        '현재가': cur,
        'status': wy.get('stage'), '상태': wy.get('stage'), 'decision': wy.get('action'), '판정': wy.get('action'),
        '와이코프단계': wy.get('stage'), '와이코프점수': int(wy.get('score',0) or 0),
        '와이코프A점수': int(wy.get('acc_score',0) or 0), '와이코프S점수': int(wy.get('sos_score',0) or 0), '와이코프L점수': int(wy.get('lps_score',0) or 0),
        '와이코프검색식': wy.get('search_formula'), '와이코프해석': wy.get('comment'), '와이코프주의': wy.get('caution'),
        'quick_blocked': bool(wy.get('stage') == 'UTAD/실패돌파 주의'),
        'quick_block_reason': wy.get('caution') or '',
        'V97전략': 'Wyckoff_Dedicated_Search_SOS_LPS',
    }


def _v87_export_quick_candidates_json(**frames):
    ok = True
    try:
        if _V97_BASE_QUICK_EXPORT:
            ok = _V97_BASE_QUICK_EXPORT(**frames)
    except Exception:
        ok = False
    try:
        rows = _v97_collect_rows(**frames)
        rows = [r for r in rows if _v97_is_wyckoff_candidate(r)]
        rows = sorted(rows, key=_v97_wyckoff_rank, reverse=True)[:12]
        wy_items = [_v97_row_to_quick_item(r, i+1) for i, r in enumerate(rows)]
        out_path = os.getenv('QUICK_CANDIDATE_JSON', 'today_candidates.json') or 'today_candidates.json'
        full_path = os.getenv('QUICK_CANDIDATE_FULL_JSON', 'today_candidates_full.json') or 'today_candidates_full.json'
        try:
            with open(out_path, 'r', encoding='utf-8-sig') as f:
                payload = json.load(f)
        except Exception:
            payload = {}
        payload['wyckoff_candidates'] = wy_items
        payload['rules'] = str(payload.get('rules','')) + ' + V9.7 와이코프 전용검색 후보 병합'
        payload['strategy_candidates'] = _v97_dedupe_items((payload.get('strategy_candidates') or []) + wy_items, limit=None)
        payload['quick_candidates'] = _v97_dedupe_items((payload.get('quick_candidates') or []) + [x for x in wy_items if not x.get('quick_blocked')], limit=_v87_safe_int(os.getenv('QUICK_MERGED_LIMIT','80'),80) if '_v87_safe_int' in globals() else 80)
        _v87_write_json(out_path, payload)
        try:
            with open(full_path, 'r', encoding='utf-8-sig') as f:
                full = json.load(f)
        except Exception:
            full = {'groups': {}}
        if 'groups' not in full or not isinstance(full.get('groups'), dict):
            full['groups'] = {}
        full['groups']['와이코프전용검색'] = wy_items
        full['wyckoff_candidate_count'] = len(wy_items)
        _v87_write_json(full_path, full)
        try:
            log_info(f"✅ V9.7 와이코프 전용검색 JSON 병합 완료: {len(wy_items)}개")
        except Exception:
            pass
    except Exception as e:
        try: log_error(f"⚠️ V9.7 와이코프 JSON 병합 실패: {e}")
        except Exception: pass
    return ok

