def _v98_filter_action_call(args, kwargs):
    """구버전 action block 함수가 모르는 kwargs(ai_candidates 등)를 제거한다."""
    try:
        fargs = tuple(args[:len(_V98_ACTION_KW)])
    except Exception:
        fargs = tuple(args or ())
    fkwargs = {}
    try:
        for k in _V98_ACTION_KW:
            if k in kwargs:
                fkwargs[k] = kwargs.get(k)
    except Exception:
        pass
    return fargs, fkwargs


def _v98_minimal_action_block():
    return """━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🎯 [오늘 매매관점 압축]

📌 오늘 전략: 와이코프 SOS 돌파는 추격보다 LPS 재지지·파란점선/구름상단 지지 확인 우선
📌 넥스트 주의: 09:00 이전 신호는 거래량 부족으로 속임수 가능성 있음
📌 09:15~09:18 검색 결과는 1차 검증용, 확정 매수는 09:30 이후 재확인 우대
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"""


def _v98_remove_section(text, start_marker, end_markers):
    b = str(text or '')
    s = b.find(start_marker)
    if s < 0:
        return b
    ends = []
    for m in end_markers:
        e = b.find(m, s + len(start_marker))
        if e >= 0:
            ends.append(e)
    if not ends:
        return b[:s].rstrip()
    e = min(ends)
    return (b[:s].rstrip() + '\n\n' + b[e:].lstrip()).strip()


def _v98_insert_before_final_sep(text, insert):
    try:
        return _v96_insert_before_final_sep(text, insert)
    except Exception:
        b = str(text or '')
        sep = '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
        if b.rstrip().endswith(sep):
            return b.rstrip()[:-len(sep)].rstrip() + '\n' + str(insert).rstrip() + '\n' + sep
        return b.rstrip() + '\n' + str(insert).rstrip()


def build_trade_action_summary_block_from_frames(*args, **kwargs):
    # 1) 기존 압축 블록은 구버전 호환 kwargs만 넘겨 생성한다.
    try:
        fargs, fkwargs = _v98_filter_action_call(args, kwargs)
        base = _V98_BASE_ACTION_BLOCK(*fargs, **fkwargs) if _V98_BASE_ACTION_BLOCK else ''
    except Exception as e:
        base = f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

    b = str(base or '')
    if (not b.strip()) or ('생성 실패:' in b):
        b = _v98_minimal_action_block()

    # 2) 기존 V96 SOS/LPS 보조 섹션은 V97 전용검색과 중복되므로 제거한다.
    b = _v98_remove_section(
        b,
        '📦 와이코프 SOS/LPS 후보',
        ['🌊 추세전환 눌림타점 우선후보','🌊 파동 눌림타점 우선후보','📘 추세전환 눌림 기준','📘 와이코프 SOS/LPS 기준','━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━']
    )

    # 3) V97 전용검색은 전체 kwargs(ai_candidates/all_hits_df 포함)로 다시 수집한다.
    try:
        rows = _v97_collect_rows(*args, **kwargs)
        if '📦 와이코프 전용검색 결과' not in b:
            b = _v97_insert_wyckoff_section(b, rows)
    except Exception:
        pass

    # 4) 전략 문구 보정
    try:
        lines = []
        for line in b.splitlines():
            if line.startswith('📌 오늘 전략:'):
                lines.append('📌 오늘 전략: 와이코프 SOS 돌파는 추격보다 LPS 재지지·파란점선/구름상단 지지 확인 우선')
            else:
                lines.append(line)
        b = '\n'.join(lines)
    except Exception:
        pass

    guide = (
        "\n📘 와이코프 전용검색 기준\n"
        "- A점수: 박스권·매집일수·세력흔적·정제이력·이평응축\n"
        "- S점수: 저항구름/박스 상단 돌파 + 거래량/OBV + 수급 결합\n"
        "- L점수: SOS 이후 눌림, 파란점선 접촉/위안착, 재양봉/재안착\n"
        "- 과열/후행/가짜수박주의는 UTAD 또는 추격금지로 보수화"
    )
    if '📘 와이코프 전용검색 기준' not in b:
        b = _v98_insert_before_final_sep(b, guide)
    return b


def _v81_build_today_action_summary_safe(**kwargs):
    try:
        return build_trade_action_summary_block_from_frames(**kwargs)
    except Exception as e:
        return f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"


def _v98_clean_wave_lines(lines):
    out = []
    seen = set()
    prefix_count = {}
    skip_wy = 0
    for raw in lines or []:
        line = str(raw).strip()
        if not line:
            continue
        if '와이코프 단계:' in line:
            skip_wy = 5
            continue
        if skip_wy > 0 and (line.startswith('📌 해석:') or line.startswith('🎯 실행:') or line.startswith('⚠️ 주의:') or line.startswith('🧯 무효:')):
            skip_wy -= 1
            continue
        skip_wy = 0
        key = ' '.join(line.split())
        if key in seen:
            continue
        seen.add(key)
        # 같은 성격의 실행판정/실행제한이 여러 번 누적되는 것을 차단한다.
        limited_prefix = None
        for p in ['🚦 실행판정:', '⚠️ 실행제한:', '🧮 파동점수:', '🎯 최적눌림:', '🧯 무효가격:']:
            if line.startswith(p):
                limited_prefix = p
                break
        if limited_prefix:
            cnt = prefix_count.get(limited_prefix, 0)
            if cnt >= 1:
                continue
            prefix_count[limited_prefix] = cnt + 1
        out.append(line)
    return out


def _v98_wyckoff_lines_from_row(row):
    try:
        wy = _v97_dedicated_wyckoff_from_row(row)
    except Exception:
        return []
    if not isinstance(wy, dict):
        return []
    stage = str(wy.get('stage') or '')
    score = int(wy.get('score') or 0)
    # 관찰부족형은 개별 카드에서는 생략해 가독성을 살린다.
    if (not stage) or ('관찰부족' in stage and score < 35):
        return []
    lines = [
        f"📦 와이코프: {stage} {score}/100 | A/S/L {wy.get('acc_score',0)}/{wy.get('sos_score',0)}/{wy.get('lps_score',0)}",
    ]
    comment = str(wy.get('comment') or '').strip()
    action = str(wy.get('action') or '').strip()
    caution = str(wy.get('caution') or '').strip()
    invalid_txt = str(wy.get('invalid_text') or '').strip()
    if comment:
        lines.append(f"📌 와이코프 해석: {comment[:120]}")
    if action:
        lines.append(f"🎯 와이코프 실행: {action}")
    if caution:
        lines.append(f"⚠️ 와이코프 주의: {caution}")
    if invalid_txt:
        lines.append(f"🧯 와이코프 무효: {invalid_txt[:120]}")
    return lines[:5]


def _v93_wave_lines_from_row(row):
    try:
        base_lines = list(_V98_BASE_WAVE_LINES(row) if _V98_BASE_WAVE_LINES else [])
    except Exception:
        base_lines = []
    lines = _v98_clean_wave_lines(base_lines)
    try:
        if not any('와이코프:' in str(x) or '와이코프 단계:' in str(x) for x in lines):
            lines.extend(_v98_wyckoff_lines_from_row(row))
    except Exception:
        pass
    return _v98_clean_wave_lines(lines)

