def _v99_norm_line(line):
    try:
        return ' '.join(str(line or '').strip().split())
    except Exception:
        return str(line or '').strip()


def _v99_line_prefix(line):
    s = str(line or '').strip()
    # 섹션 제목은 보존한다.
    if s.startswith('📦 와이코프 전용검색') or s.startswith('📦 와이코프 SOS/LPS 후보'):
        return ''
    managed = [
        '📦 와이코프:', '📌 와이코프 해석:', '🎯 와이코프 실행:', '⚠️ 와이코프 주의:', '🧯 와이코프 무효:',
        '🚦 실행판정:', '⚠️ 실행제한:', '🧮 파동점수:', '🎯 최적눌림:', '🧯 무효가격:',
        '🌊 파동구조:', '🌊 파동타점:', '🧭 파동타점 해석:',
    ]
    for p in managed:
        if s.startswith(p):
            return p
    return ''


def _v99_segment_start(line):
    s = str(line or '').strip()
    if not s:
        return False
    if s.startswith('━━━━━━━━━━━━━━━━') or s.startswith('────────────────') or s.startswith('⭐ '):
        return True
    try:
        import re as _re
        if _re.match(r'^\d+\)\s+.+\(\d{6}\)', s):
            return True
    except Exception:
        pass
    return False


def _v99_choose_longest(indices, lines):
    if not indices:
        return None
    best = indices[-1]
    best_len = -1
    for i in indices:
        ln = _v99_norm_line(lines[i])
        if len(ln) >= best_len:
            best = i
            best_len = len(ln)
    return best


def _v99_clean_segment(seg_lines):
    """한 종목 카드 안에서 반복되는 핵심 판단 라인을 1회로 축약한다."""
    try:
        lines = [str(x) for x in (seg_lines or [])]
        if len(lines) <= 2:
            return lines

        managed_positions = {}
        for i, line in enumerate(lines):
            p = _v99_line_prefix(line)
            if p:
                managed_positions.setdefault(p, []).append(i)
        if not managed_positions:
            return lines

        keep = set(range(len(lines)))

        # 1) 와이코프 카드 요약은 최종 판정 1세트만 유지한다.
        wy_group = ['📦 와이코프:', '📌 와이코프 해석:', '🎯 와이코프 실행:', '⚠️ 와이코프 주의:', '🧯 와이코프 무효:']
        wy_indices = []
        for p in wy_group:
            wy_indices.extend(managed_positions.get(p, []))
        if len(managed_positions.get('📦 와이코프:', [])) > 1:
            for i in wy_indices:
                keep.discard(i)
            last_wy = managed_positions.get('📦 와이코프:', [])[-1]
            keep.add(last_wy)
            for p in wy_group[1:]:
                cand = managed_positions.get(p, [])
                if not cand:
                    continue
                after = [i for i in cand if i > last_wy]
                keep.add((after or cand)[-1])

        # 2) 파동 구조 라인은 구조/타점 중 최종 1개만 유지한다.
        wave_stage_indices = []
        for p in ['🌊 파동구조:', '🌊 파동타점:']:
            wave_stage_indices.extend(managed_positions.get(p, []))
        if len(wave_stage_indices) > 1:
            for i in wave_stage_indices:
                keep.discard(i)
            keep.add(max(wave_stage_indices))

        # 3) 실행판정/파동점수/무효가격은 마지막 1개만 유지한다.
        for p in ['🚦 실행판정:', '🧮 파동점수:', '🧯 무효가격:', '🧭 파동타점 해석:']:
            idxs = managed_positions.get(p, [])
            if len(idxs) > 1:
                for i in idxs:
                    keep.discard(i)
                keep.add(idxs[-1])

        # 4) 실행제한/최적눌림은 정보가 가장 많은 1개만 유지한다.
        for p in ['⚠️ 실행제한:', '🎯 최적눌림:']:
            idxs = managed_positions.get(p, [])
            if len(idxs) > 1:
                chosen = _v99_choose_longest(idxs, lines)
                for i in idxs:
                    keep.discard(i)
                if chosen is not None:
                    keep.add(chosen)

        # 5) 완전 동일 관리 라인 중복 제거
        out, seen = [], set()
        for i, line in enumerate(lines):
            if i not in keep:
                continue
            key = _v99_norm_line(line)
            p = _v99_line_prefix(line)
            if p and key in seen:
                continue
            seen.add(key)
            out.append(line)
        return out
    except Exception:
        return list(seg_lines or [])


def _v99_sanitize_trade_text(text):
    """텔레그램/HTML 전송 직전 최종 가독성 정리."""
    try:
        b = str(text or '')
        if not b:
            return b
        hot = ['🚦 실행판정:', '⚠️ 실행제한:', '📦 와이코프:', '🌊 파동구조:', '🌊 파동타점:']
        if not any(b.count(x) >= 2 for x in hot):
            return b

        lines = b.splitlines()
        segments = []
        cur = []
        for line in lines:
            if cur and _v99_segment_start(line):
                segments.append(cur)
                cur = [line]
            else:
                cur.append(line)
        if cur:
            segments.append(cur)

        cleaned = []
        for seg in segments:
            cleaned.extend(_v99_clean_segment(seg))
        out = '\n'.join(cleaned)

        # 비정상 잔여 반복 한 번 더 방어
        final_lines = []
        seen_limited = set()
        for line in out.splitlines():
            s = _v99_norm_line(line)
            if (line.startswith('⚠️ 실행제한:') or line.startswith('🚦 실행판정:')) and s in seen_limited:
                continue
            if line.startswith('⚠️ 실행제한:') or line.startswith('🚦 실행판정:'):
                seen_limited.add(s)
            final_lines.append(line)
        return '\n'.join(final_lines)
    except Exception:
        return str(text or '')


def send_telegram_photo(message, image_paths=[]):
    if _V99_BASE_SEND_TELEGRAM_PHOTO:
        return _V99_BASE_SEND_TELEGRAM_PHOTO(_v99_sanitize_trade_text(message), image_paths)
    return None


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    if _V99_BASE_SEND_TELEGRAM_CHUNKS:
        return _V99_BASE_SEND_TELEGRAM_CHUNKS(_v99_sanitize_trade_text(message), title=title, max_len=max_len)
    return None


# HTML 리포트의 extra_panels/body에도 동일 정리 규칙 적용
def build_mobile_html_report(*args, **kwargs):
    if _V99_BASE_BUILD_MOBILE_HTML_REPORT is None:
        return None
    try:
        if 'extra_panels' in kwargs and kwargs.get('extra_panels'):
            panels = []
            for p in kwargs.get('extra_panels') or []:
                if isinstance(p, dict):
                    q = dict(p)
                    if 'body' in q:
                        q['body'] = _v99_sanitize_trade_text(q.get('body'))
                    panels.append(q)
                else:
                    panels.append(p)
            kwargs['extra_panels'] = panels
    except Exception:
        pass
    return _V99_BASE_BUILD_MOBILE_HTML_REPORT(*args, **kwargs)

