def _v100_readable_enabled():
    try:
        return (str(os.getenv('READABLE_REPORT_MODE', '1')).strip() != '0' and
                str(os.getenv('REPORT_VERBOSE_MODE', '0')).strip() != '1')
    except Exception:
        return True


def _v100_s(s):
    try:
        return str(s or '').strip()
    except Exception:
        return ''


def _v100_n(s):
    return ' '.join(_v100_s(s).split())


def _v100_trunc(s, n=130):
    s = _v100_s(s)
    return s if len(s) <= n else s[:n-1].rstrip() + '…'


def _v100_numbered_stock(s):
    try:
        import re as _re
        return bool(_re.match(r'^\d+\)\s+.+\(\d{6}\)', _v100_s(s)))
    except Exception:
        return False


def _v100_first(lines):
    for x in lines or []:
        if _v100_s(x):
            return _v100_s(x)
    return ''


def _v100_segment_start(line):
    s = _v100_s(line)
    return bool(s.startswith('━━━━━━━━━━━━━━━━') or s.startswith('────────────────') or s.startswith('⭐ ') or _v100_numbered_stock(s))


def _v100_is_detail_card(lines):
    txt = '\n'.join(map(str, lines or []))
    first = _v100_first(lines)
    if first.startswith('⭐ ') and ('💰 현재가:' in txt or '✅ 최종 판정:' in txt or '⏳ 매매판정:' in txt):
        return True
    if _v100_numbered_stock(first) and ('쉬운 해설:' in txt or '✅ 구조판정:' in txt or '⏳ 매매판정:' in txt or '최종 판정:' in txt):
        return True
    return False


def _v100_kind(line):
    s = _v100_s(line)
    mapping = [
        ('💡 한 줄 결론:', 'conclusion'), ('📦 와이코프:', 'wy'), ('📌 와이코프 해석:', 'wy_comment'),
        ('🎯 와이코프 실행:', 'wy_action'), ('⚠️ 와이코프 주의:', 'wy_caution'), ('🧯 와이코프 무효:', 'wy_invalid'),
        ('🌊 파동구조:', 'wave'), ('🌊 파동타점:', 'wave'), ('🚦 실행판정:', 'exec'),
        ('⚠️ 실행제한:', 'limit'), ('🎯 최적눌림:', 'pullback'), ('🔵 파란점선:', 'blue'),
        ('✅ 최종 판정:', 'final'), ('✅ 구조판정:', 'structure'), ('⏳ 매매판정:', 'trade'),
        ('📌 실행조건:', 'condition'), ('⚠️ 주의:', 'caution'), ('📌 목표1:', 'target'), ('점수:', 'score'),
        ('- 쉬운 해설:', 'easy'), ('- 최종 판정:', 'final'), ('- 점수 해석:', 'score_read'),
        ('- 대응 요약:', 'action_summary'), ('- 확인 필요:', 'need_check'), ('- 주의 포인트:', 'caution_point'),
        ('- 추천 대응:', 'recommend'), ('- 부족한 점:', 'weakness'), ('- 선정 이유:', 'reason'),
        ('- 상태:', 'state'), ('- 점수:', 'wm_score'), ('- 태그:', 'tag'), ('- 저항구름:', 'cloud'), ('- 정제:', 'refine'),
    ]
    for p, k in mapping:
        if s.startswith(p):
            return k
    return ''


def _v100_priority(line):
    s = _v100_s(line)
    if 'UTAD/실패돌파' in s or '추격 금지' in s or '실행제외형' in s:
        return 30
    if 'LPS 재지지' in s or '눌림타점' in s or '재양봉' in s:
        return 25
    if 'SOS 돌파' in s or '확인대기' in s:
        return 20
    return 10


def _v100_choose(lines):
    if not lines:
        return ''
    return sorted(lines, key=lambda x: (_v100_priority(x), len(_v100_n(x))), reverse=True)[0]


def _v100_short_line(line, n=130):
    s = str(line)
    if ':' in s:
        p, rest = s.split(':', 1)
        return p + ':' + _v100_trunc(rest, n)
    return _v100_trunc(s, n)


def _v100_compact_detail_card(seg):
    try:
        lines = [str(x) for x in (seg or [])]
        if not _v100_is_detail_card(lines):
            return lines
        header, buckets = [], {}
        first = _v100_first(lines)
        for line in lines:
            s = _v100_s(line)
            if not s:
                continue
            if (s.startswith('────────────────') or s.startswith('⭐ ') or s.startswith('🎯 ') or s.startswith('🏷️ ') or
                s.startswith('🪜 유형:') or s.startswith('📶 ') or s.startswith('💰 현재가:') or s.startswith('📊 초:') or
                s.startswith('🏦 수급:') or s.startswith('📌 수급요약:') or s.startswith('📍 수급판정:') or
                s.startswith('💵 최근1일:') or s.startswith('📦 최근3일:') or s.startswith('🧲 최근5일:')):
                header.append(line)
                continue
            if _v100_numbered_stock(first) and (_v100_numbered_stock(s) or s.startswith('- 상태:') or s.startswith('- 점수:') or s.startswith('- 태그:') or s.startswith('- 저항구름:') or s.startswith('- 정제:')):
                header.append(line)
                continue
            k = _v100_kind(s)
            if k:
                buckets.setdefault(k, []).append(line)

        out, seen = [], set()
        for line in header:
            key = _v100_n(line)
            if not key or key in seen:
                continue
            if key.startswith('📋 공시:') or key.startswith('📰 ') or key.startswith('💎 평단:') or key.startswith('📖 '):
                continue
            out.append(line); seen.add(key)

        order = ['conclusion','easy','state','wm_score','tag','cloud','refine','wy','wy_comment','wy_action','wy_caution','wy_invalid','wave','exec','pullback','limit','blue','final','structure','trade','condition','caution','action_summary','need_check','recommend','weakness','target','score','score_read']
        for k in order:
            cand = buckets.get(k) or []
            if not cand:
                continue
            chosen = _v100_choose(cand)
            if k in {'conclusion','easy','wy_comment','condition','caution','action_summary','need_check','recommend','weakness'}:
                chosen = _v100_short_line(chosen, 130)
            key = _v100_n(chosen)
            if key and key not in seen:
                out.append(chosen); seen.add(key)
        return out if len(out) >= 5 else lines
    except Exception:
        return list(seg or [])


def _v100_compact_text(text):
    try:
        if not _v100_readable_enabled():
            return str(text or '')
        b = str(text or '')
        hot = ['👀 [오늘의 관찰형 참고]', '🛡️ [오늘의 후행형 참고]', '🍉 [초입수박 TOP', '🍉 [눌림수박 TOP', '🧭 [선취 제외 후보']
        if not b.strip() or not any(h in b for h in hot):
            return b
        lines = b.splitlines()
        segs, cur = [], []
        for line in lines:
            if cur and _v100_segment_start(line):
                segs.append(cur); cur = [line]
            else:
                cur.append(line)
        if cur:
            segs.append(cur)
        cleaned = []
        for seg in segs:
            if _v100_is_detail_card(seg):
                if cleaned and cleaned[-1].strip():
                    cleaned.append('')
                cleaned.extend(_v100_compact_detail_card(seg))
            else:
                cleaned.extend(seg)
        out = '\n'.join(cleaned)
        while '\n\n\n\n' in out:
            out = out.replace('\n\n\n\n', '\n\n\n')
        return out
    except Exception:
        return str(text or '')


def send_telegram_photo(message, image_paths=[]):
    msg = _v100_compact_text(message)
    if _V100_BASE_SEND_TELEGRAM_PHOTO:
        return _V100_BASE_SEND_TELEGRAM_PHOTO(msg, image_paths)
    return None


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    msg = _v100_compact_text(message)
    if _V100_BASE_SEND_TELEGRAM_CHUNKS:
        return _V100_BASE_SEND_TELEGRAM_CHUNKS(msg, title=title, max_len=max_len)
    return None


def build_mobile_html_report(*args, **kwargs):
    if _V100_BASE_BUILD_MOBILE_HTML_REPORT is None:
        return None
    try:
        if 'extra_panels' in kwargs and kwargs.get('extra_panels'):
            panels = []
            for p in kwargs.get('extra_panels') or []:
                if isinstance(p, dict):
                    q = dict(p)
                    if 'body' in q:
                        q['body'] = _v100_compact_text(q.get('body'))
                    panels.append(q)
                else:
                    panels.append(p)
            kwargs['extra_panels'] = panels
    except Exception:
        pass
    return _V100_BASE_BUILD_MOBILE_HTML_REPORT(*args, **kwargs)

