def _v101_readable_enabled():
    try:
        return (str(os.getenv('READABLE_REPORT_MODE', '1')).strip() != '0' and
                str(os.getenv('REPORT_VERBOSE_MODE', '0')).strip() != '1')
    except Exception:
        return True


def _v101_s(x):
    try:
        return str(x or '').strip()
    except Exception:
        return ''


def _v101_n(x):
    return ' '.join(_v101_s(x).split())


def _v101_trunc(x, n=120):
    s = _v101_s(x)
    return s if len(s) <= n else s[:n-1].rstrip() + '…'


def _v101_numbered_stock(s):
    try:
        import re as _re
        return bool(_re.match(r'^\d+\)\s+.+\(\d{6}\)', _v101_s(s)))
    except Exception:
        return False


def _v101_first_nonempty(lines):
    for x in lines or []:
        if _v101_s(x):
            return _v101_s(x)
    return ''


def _v101_segment_start(line):
    s = _v101_s(line)
    return bool(s.startswith('━━━━━━━━━━━━━━━━') or s.startswith('────────────────') or
                s.startswith('⭐ ') or _v101_numbered_stock(s))


def _v101_is_card(lines):
    txt = '\n'.join(map(str, lines or []))
    first = _v101_first_nonempty(lines)
    if first.startswith('⭐ ') and ('💰 현재가:' in txt or '✅ 최종 판정:' in txt or '⏳ 매매판정:' in txt or '🔵 파란점선:' in txt):
        return True
    if _v101_numbered_stock(first) and ('저항구름:' in txt or '구조판정:' in txt or '매매판정:' in txt or '파란점선:' in txt):
        return True
    return False


def _v101_pick(lines, prefixes, contains=None, last=False):
    arr = []
    for line in lines or []:
        s = _v101_s(line)
        if not s:
            continue
        ok = any(s.startswith(p) for p in prefixes) if prefixes else True
        if contains:
            ok = ok and any(c in s for c in contains)
        if ok:
            arr.append(s)
    if not arr:
        return ''
    return arr[-1] if last else arr[0]


def _v101_pick_contains(lines, words, last=False):
    arr = []
    for line in lines or []:
        s = _v101_s(line)
        if s and any(w in s for w in words):
            arr.append(s)
    if not arr:
        return ''
    return arr[-1] if last else arr[0]


def _v101_re_float(pat, txt, default=None):
    try:
        import re as _re
        m = _re.search(pat, txt)
        if not m:
            return default
        return float(str(m.group(1)).replace(',', ''))
    except Exception:
        return default


def _v101_re_text(pat, txt, default=''):
    try:
        import re as _re
        m = _re.search(pat, txt)
        return _v101_s(m.group(1)) if m else default
    except Exception:
        return default


def _v101_extract_money(txt):
    return {
        'disparity': _v101_re_float(r'이격:([0-9]+(?:\.[0-9]+)?)', txt),
        'rsi': _v101_re_float(r'RSI:([0-9]+(?:\.[0-9]+)?)', txt),
        'over_pullback': _v101_re_float(r'최적눌림구간보다\s*([0-9]+(?:\.[0-9]+)?)%\s*위', txt),
    }


def _v101_blue_state(line):
    s = _v101_s(line)
    if not s:
        return ''
    for key in ['과이격', '아래', '위확장', '위안착', '접촉']:
        if f'| {key} |' in s or s.endswith('|' + key) or key in s:
            return key
    return ''


def _v101_short_payload(line):
    s = _v101_s(line)
    if ':' in s:
        s = s.split(':', 1)[1].strip()
    return _v101_trunc(s, 100)


def _v101_clean_stage(line):
    s = _v101_short_payload(line)
    s = s.replace(' | 신규 실행 제외', '')
    return s


def _v101_best_wyckoff(lines, txt):
    wy_lines = [_v101_s(x) for x in lines if _v101_s(x).startswith('📦 와이코프:')]
    if not wy_lines:
        return ''
    # 위험 경고가 있으면 UTAD를 우선 노출, 아니면 LPS, SOS 순서
    if 'UTAD/실패돌파' in txt:
        for x in reversed(wy_lines):
            if 'UTAD/실패돌파' in x:
                return x
    for key in ['LPS 재지지', 'SOS 돌파', 'SOS 테스트', 'Accumulation']:
        for x in reversed(wy_lines):
            if key in x:
                return x
    return wy_lines[-1]


def _v101_best_wave(lines, txt):
    wave_lines = [_v101_s(x) for x in lines if _v101_s(x).startswith('🌊 파동구조:') or _v101_s(x).startswith('🌊 파동타점:')]
    if not wave_lines:
        return ''
    for key in ['눌림타점형', '추세전환', '눌림대기형']:
        for x in reversed(wave_lines):
            if key in x:
                return x
    return wave_lines[-1]


def _v101_bool_good_supply(txt):
    bad = ('동반매도' in txt or '개인추격주의' in txt)
    good = any(k in txt for k in ['쌍끌강', '쌍끌', '동반매수', '강매집', '외인 중심 매집', '기관 중심 매집', '외인매수 우세', '기관매수 우세'])
    return good and not bad


def _v101_decide(lines):
    txt = '\n'.join(map(str, lines or []))
    m = _v101_extract_money(txt)
    disp = m.get('disparity')
    rsi = m.get('rsi')
    over = m.get('over_pullback')
    blue_line = _v101_pick(lines, ['🔵 파란점선:'], last=True)
    blue = _v101_blue_state(blue_line)

    fake = '가짜수박주의' in txt or '가짜/정제주의' in txt
    late = '후행형' in txt or '후행수박' in txt or '보유자대응' in txt or '보유자 대응' in txt
    utad = 'UTAD/실패돌파' in txt
    exec_exclude = '실행제외형' in txt or '신규 실행 제외' in txt or '신규 매수 금지' in txt
    chase_forbid = '추격 금지' in txt or '신규 추격 금지' in txt
    bad_supply = '동반매도' in txt or '개인추격주의' in txt
    lps = 'LPS 재지지' in txt
    sos = 'SOS 돌파' in txt or 'SOS 테스트' in txt
    pull_entry = '눌림타점형' in txt and '눌림대기형' not in _v101_best_wave(lines, txt)
    pull_wait = '눌림대기형' in txt
    cloud_test = '저항테스트' in txt or '구름테스트' in txt or '돌파테스트형' in txt
    cloud_break = '저항구름 돌파확인형' in txt or '저항돌파' in txt
    pre_entry = '저항전' in txt or '선취관찰형' in txt
    good_supply = _v101_bool_good_supply(txt)

    risk_reasons = []
    if late:
        risk_reasons.append('후행')
    if fake:
        risk_reasons.append('가짜/정제주의')
    if bad_supply:
        risk_reasons.append('수급 역방향')
    if disp is not None and disp >= 115:
        risk_reasons.append(f'이격 {disp:.0f}')
    if rsi is not None and rsi >= 70:
        risk_reasons.append(f'RSI {rsi:.0f}')
    if over is not None and over >= 5:
        risk_reasons.append(f'최적눌림 +{over:.1f}%')
    if blue in ['아래', '과이격']:
        risk_reasons.append(f'파란점선 {blue}')
    if utad:
        risk_reasons.append('UTAD/실패돌파')

    severe = False
    if exec_exclude or chase_forbid or utad:
        severe = True
    if disp is not None and disp >= 118:
        severe = True
    if rsi is not None and rsi >= 75:
        severe = True
    if over is not None and over >= 7:
        severe = True
    if fake and (bad_supply or blue in ['아래', '과이격'] or (disp is not None and disp >= 112) or (rsi is not None and rsi >= 70)):
        severe = True

    near_pull = ('최적눌림구간 안/근처' in txt) or (over is not None and over <= 3.0) or over is None
    blue_ok = blue in ['접촉', '위안착'] or (blue == '위확장' and not severe)
    execute_ready = (lps or pull_entry) and near_pull and blue_ok and good_supply and not severe and not late

    if severe:
        label = '추격 금지'
        emoji = '⛔'
        action = '신규 매수는 제외하고, 보유자는 5일선·파란점선·구름상단 이탈 기준으로 분할 대응합니다.'
    elif late:
        label = '보유자 대응'
        emoji = '🛡️'
        action = '신규 추격보다 눌림 재지지 확인이 먼저입니다. 보유자는 이탈선 관리와 분할 익절을 우선합니다.'
    elif execute_ready:
        label = '조건부 실행'
        emoji = '🟢'
        action = '재양봉 + 거래량 재유입 + 파란점선/5일선 지지 중 2개 이상 확인되면 분할 실행 후보입니다.'
    elif lps or pull_entry or cloud_break:
        label = '눌림 대기'
        emoji = '🟡'
        action = '구름상단 또는 5일선 눌림 뒤 재양봉과 거래량 재유입을 확인할 때만 대응합니다.'
    elif cloud_test or sos:
        label = '돌파확인 대기'
        emoji = '👀'
        action = '저항구름 상단 종가 안착과 다음 봉 지지를 확인하기 전까지는 관찰입니다.'
    elif pre_entry:
        label = '선취 관찰'
        emoji = '🔎'
        action = '소액 관찰 가능 구간이지만, 구름 돌파와 윗꼬리 축소 전까지 확정 매수는 보류합니다.'
    else:
        label = '확인 대기'
        emoji = '⚪'
        action = '방향성 확인 전까지 관찰합니다. 파란점선 회복과 거래량 보강이 우선입니다.'

    if not risk_reasons:
        if good_supply:
            risk_reasons.append('수급 양호')
        if blue:
            risk_reasons.append(f'파란점선 {blue}')
        if lps:
            risk_reasons.append('LPS')
        elif sos:
            risk_reasons.append('SOS')

    # 핵심 근거는 너무 길지 않게 3개만
    why = ' / '.join(dict.fromkeys([x for x in risk_reasons if x]))[:90]
    if not why:
        why = '구조·수급·타점 재확인 필요'

    return {
        'label': label,
        'emoji': emoji,
        'action': action,
        'why': why,
        'blue': blue,
        'risk_reasons': risk_reasons,
    }


def _v101_compact_card(seg):
    try:
        lines = [str(x) for x in (seg or [])]
        if not _v101_is_card(lines):
            return lines
        txt = '\n'.join(lines)
        decision = _v101_decide(lines)

        sep = _v101_pick(lines, ['────────────────'])
        title = _v101_pick(lines, ['⭐ ']) or _v101_first_nonempty(lines)
        if not title or title.startswith('━━━━━━━━'):
            # 번호형 카드
            for x in lines:
                if _v101_numbered_stock(x):
                    title = _v101_s(x)
                    break

        signal = _v101_pick(lines, ['🎯 '])
        tags = _v101_pick(lines, ['🏷️ '])
        typ = _v101_pick(lines, ['🪜 유형:'])
        pass_line = _v101_pick(lines, ['📶 '])
        money = _v101_pick(lines, ['💰 현재가:'])
        metrics = _v101_pick(lines, ['📊 초:'])
        supply = _v101_pick(lines, ['🏦 수급:'])
        supply_judge = _v101_pick(lines, ['📍 수급판정:'])
        recent5 = _v101_pick(lines, ['🧲 최근5일:'])
        state = _v101_pick(lines, ['- 상태:'])
        wm_score = _v101_pick(lines, ['- 점수:'])
        cloud = _v101_pick(lines, ['- 저항구름:'])
        refine = _v101_pick(lines, ['- 정제:'])

        wy = _v101_best_wyckoff(lines, txt)
        wave = _v101_best_wave(lines, txt)
        structure = _v101_pick(lines, ['✅ 구조판정:'], last=True)
        blue_line = _v101_pick(lines, ['🔵 파란점선:'], last=True)
        pull = _v101_pick_contains(lines, ['🎯 최적눌림:'], last=True)
        limit = _v101_pick(lines, ['⚠️ 실행제한:'], last=True)
        target = _v101_pick(lines, ['📌 목표1:'], last=True)
        score = _v101_pick(lines, ['점수:'], last=True)
        recommend = _v101_pick(lines, ['- 추천 대응:'], last=True)
        need = _v101_pick(lines, ['- 확인 필요:'], last=True)

        out = []
        if sep:
            out.append(sep)
        if title:
            out.append(title)
        if signal:
            out.append(signal)
        if tags and not _v101_numbered_stock(title):
            out.append(_v101_trunc(tags, 120))
        if typ:
            out.append(typ)
        if pass_line:
            out.append(_v101_trunc(pass_line, 110))
        if money:
            out.append(money)
        if metrics and not _v101_numbered_stock(title):
            out.append(metrics)
        if supply:
            out.append(supply)
        if supply_judge:
            out.append(_v101_trunc(supply_judge, 110))
        elif recent5:
            out.append(_v101_trunc(recent5, 110))

        # 번호형/수박 섹션은 상태·구름·정제를 먼저 보여준다
        if _v101_numbered_stock(title):
            for x in [state, wm_score, cloud, refine]:
                if x:
                    out.append(_v101_trunc(x, 110))

        out.append(f"✅ 최종판정(종합): {decision['emoji']} {decision['label']} | 근거: {decision['why']}")

        struct_bits = []
        if structure:
            struct_bits.append('구조=' + _v101_short_payload(structure))
        elif cloud:
            struct_bits.append('구름=' + _v101_short_payload(cloud))
        if wy:
            struct_bits.append('와이코프=' + _v101_clean_stage(wy))
        if wave:
            struct_bits.append('파동=' + _v101_clean_stage(wave))
        if struct_bits:
            out.append('🧭 구조요약: ' + _v101_trunc(' | '.join(struct_bits), 170))

        timing_bits = []
        if blue_line:
            timing_bits.append(_v101_short_payload(blue_line))
        if pull:
            timing_bits.append(_v101_short_payload(pull))
        if timing_bits:
            out.append('🔵 타점요약: ' + _v101_trunc(' | '.join(timing_bits), 170))

        out.append('📌 오늘 할 일: ' + _v101_trunc(decision['action'], 150))

        caution_bits = []
        if limit:
            caution_bits.append(_v101_short_payload(limit))
        if need and decision['label'] not in ['추격 금지', '보유자 대응']:
            caution_bits.append(_v101_short_payload(need))
        if recommend and decision['label'] in ['돌파확인 대기', '선취 관찰', '확인 대기']:
            caution_bits.append(_v101_short_payload(recommend))
        if not caution_bits and decision.get('risk_reasons'):
            _danger = [x for x in decision['risk_reasons'] if x not in ['수급 양호', 'LPS', 'SOS'] and not str(x).startswith('파란점선 접촉') and not str(x).startswith('파란점선 위안착')]
            if _danger:
                caution_bits.append(' / '.join(_danger[:4]))
        if caution_bits:
            out.append('⚠️ 주의/무효: ' + _v101_trunc(' | '.join(caution_bits), 170))

        if target:
            out.append(target)
        if score:
            out.append(score)

        # 중복 제거
        clean, seen = [], set()
        for x in out:
            k = _v101_n(x)
            if not k or k in seen:
                continue
            clean.append(x)
            seen.add(k)
        return clean if len(clean) >= 4 else lines
    except Exception:
        return list(seg or [])


def _v101_action_first_text(text):
    try:
        if not _v101_readable_enabled():
            return str(text or '')
        b = str(text or '')
        hot = ['👀 [오늘의 관찰형 참고]', '🛡️ [오늘의 후행형 참고]', '🍉 [초입수박 TOP', '🍉 [눌림수박 TOP',
               '🧭 [선취 제외 후보', '🚀 [흰구름 돌파 후보', '🚀 [흰구름 돌파 관찰']
        if not b.strip() or not any(h in b for h in hot):
            return b

        # V100 요약을 먼저 적용해 원문 중복을 줄인 뒤, V101에서 최종판정 중심으로 재작성
        try:
            if '_v100_compact_text' in globals():
                b = _v100_compact_text(b)
        except Exception:
            pass

        lines = b.splitlines()
        segs, cur = [], []
        for line in lines:
            if cur and _v101_segment_start(line):
                segs.append(cur)
                cur = [line]
            else:
                cur.append(line)
        if cur:
            segs.append(cur)

        cleaned = []
        for seg in segs:
            if _v101_is_card(seg):
                if cleaned and cleaned[-1].strip():
                    cleaned.append('')
                cleaned.extend(_v101_compact_card(seg))
            else:
                cleaned.extend(seg)

        out = '\n'.join(cleaned)
        while '\n\n\n\n' in out:
            out = out.replace('\n\n\n\n', '\n\n\n')
        return out
    except Exception:
        return str(text or '')


def send_telegram_photo(message, image_paths=[]):
    msg = _v101_action_first_text(message)
    if _V101_BASE_SEND_TELEGRAM_PHOTO:
        return _V101_BASE_SEND_TELEGRAM_PHOTO(msg, image_paths)
    return None


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    msg = _v101_action_first_text(message)
    if _V101_BASE_SEND_TELEGRAM_CHUNKS:
        return _V101_BASE_SEND_TELEGRAM_CHUNKS(msg, title=title, max_len=max_len)
    return None


def build_mobile_html_report(*args, **kwargs):
    if _V101_BASE_BUILD_MOBILE_HTML_REPORT is None:
        return None
    try:
        if 'extra_panels' in kwargs and kwargs.get('extra_panels'):
            panels = []
            for p in kwargs.get('extra_panels') or []:
                if isinstance(p, dict):
                    q = dict(p)
                    if 'body' in q:
                        q['body'] = _v101_action_first_text(q.get('body'))
                    panels.append(q)
                else:
                    panels.append(p)
            kwargs['extra_panels'] = panels
    except Exception:
        pass
    return _V101_BASE_BUILD_MOBILE_HTML_REPORT(*args, **kwargs)

