def _v102_debug_mode():
    try:
        return str(os.getenv('DEBUG_MODE', '0')).strip() == '1'
    except Exception:
        return False


def _v102_readable_enabled():
    try:
        return (str(os.getenv('READABLE_REPORT_MODE', '1')).strip() != '0' and
                str(os.getenv('REPORT_VERBOSE_MODE', '0')).strip() != '1')
    except Exception:
        return True


def _v102_s(x):
    try:
        return str(x or '').strip()
    except Exception:
        return ''


def _v102_n(x):
    return ' '.join(_v102_s(x).split())


def _v102_trunc(x, n=90):
    s = _v102_s(x)
    return s if len(s) <= n else s[:max(0, n-1)].rstrip() + '…'


def _v102_num(x, default=0.0):
    try:
        if x is None:
            return default
        if isinstance(x, str):
            x = x.replace(',', '').replace('원', '').replace('%', '').strip()
            if x in ('', '-', 'nan', 'None'):
                return default
        return float(x)
    except Exception:
        return default


def _v102_int_price(x):
    v = _v102_num(x, 0)
    try:
        return f"{int(round(v)):,}" if v > 0 else '-'
    except Exception:
        return '-'


def _v102_re_float(pat, txt, default=None):
    try:
        import re as _re
        m = _re.search(pat, str(txt or ''))
        if not m:
            return default
        return float(str(m.group(1)).replace(',', ''))
    except Exception:
        return default


def _v102_re_text(pat, txt, default=''):
    try:
        import re as _re
        m = _re.search(pat, str(txt or ''))
        return _v102_s(m.group(1)) if m else default
    except Exception:
        return default


def _v102_numbered_stock(s):
    try:
        import re as _re
        return bool(_re.match(r'^\d+\)\s+.+\(\d{6}\)', _v102_s(s)))
    except Exception:
        return False


def _v102_first_nonempty(lines):
    for x in lines or []:
        if _v102_s(x):
            return _v102_s(x)
    return ''


def _v102_segment_start(line):
    s = _v102_s(line)
    return bool(s.startswith('━━━━━━━━━━━━━━━━') or s.startswith('────────────────') or
                s.startswith('⭐ ') or _v102_numbered_stock(s))


def _v102_is_card(lines):
    txt = '\n'.join(map(str, lines or []))
    first = _v102_first_nonempty(lines)
    if first.startswith('⭐ ') and any(k in txt for k in ['💰 현재가:', '✅ 최종 판정:', '⏳ 매매판정:', '🔵 파란점선:', '📦 와이코프:', '🌊 파동']):
        return True
    if _v102_numbered_stock(first) and any(k in txt for k in ['저항구름:', '구조판정:', '매매판정:', '파란점선:', '와이코프:', '파동']):
        return True
    return False


def _v102_pick(lines, prefixes=None, contains=None, last=False):
    arr = []
    for line in lines or []:
        s = _v102_s(line)
        if not s:
            continue
        ok = True
        if prefixes:
            ok = any(s.startswith(p) for p in prefixes)
        if contains:
            ok = ok and any(c in s for c in contains)
        if ok:
            arr.append(s)
    if not arr:
        return ''
    return arr[-1] if last else arr[0]


def _v102_pick_contains(lines, words, last=False):
    return _v102_pick(lines, prefixes=None, contains=words, last=last)


def _v102_payload(line):
    s = _v102_s(line)
    if ':' in s:
        s = s.split(':', 1)[1].strip()
    return _v102_trunc(s, 100)


def _v102_clean_name(title):
    s = _v102_s(title)
    try:
        import re as _re
        m = _re.search(r'\[([^\]]+)\]', s)
        if m:
            return f"[{m.group(1).strip()}]"
        m = _re.match(r'^\d+\)\s+(.+?)\((\d{6})\)', s)
        if m:
            return f"[{m.group(1).strip()}]({m.group(2)})"
        if s.startswith('⭐'):
            m = _re.search(r'\s([가-힣A-Za-z0-9&._\- ]{2,})\s+\d[\d,]*원', s)
            if m:
                return f"[{m.group(1).strip()}]"
    except Exception:
        pass
    return s or '[종목명 확인]'


def _v102_blue_state(txt):
    s = _v102_s(txt)
    for key in ['과이격', '아래', '위확장', '위안착', '접촉', '산출불가']:
        if key in s:
            return key
    return ''


def _v102_good_supply(txt):
    bad = any(k in txt for k in ['동반매도', '개인추격주의', '외인매도', '기관매도'])
    good = any(k in txt for k in ['쌍끌강', '쌍끌', '동반매수', '강매집', '외인 중심 매집', '기관 중심 매집', '외인매수 우세', '기관매수 우세', '수급 양호'])
    return good and not bad


def _v102_dedupe_list(items, limit=3):
    out, seen = [], set()
    for x in items or []:
        s = _v102_s(x)
        if not s:
            continue
        k = _v102_n(s)
        if k in seen:
            continue
        out.append(s)
        seen.add(k)
        if len(out) >= limit:
            break
    return out


def _v102_decide(lines):
    txt = '\n'.join(map(str, lines or []))
    disp = _v102_re_float(r'이격:?\s*([0-9]+(?:\.[0-9]+)?)', txt)
    rsi = _v102_re_float(r'RSI:?\s*([0-9]+(?:\.[0-9]+)?)', txt)
    over = _v102_re_float(r'최적눌림구간보다\s*([0-9]+(?:\.[0-9]+)?)%\s*위', txt)
    blue_line = _v102_pick(lines, ['🔵 파란점선:'], last=True)
    blue = _v102_blue_state(blue_line or txt)

    fake = any(k in txt for k in ['가짜수박주의', '가짜/정제주의'])
    utad = 'UTAD/실패돌파' in txt or 'UTAD' in txt
    exec_exclude = any(k in txt for k in ['실행제외형', '신규 실행 제외', '신규 매수 금지'])
    chase_word = any(k in txt for k in ['추격 금지', '신규 추격 금지'])
    late = any(k in txt for k in ['후행형', '후행수박', '보유자대응', '보유자 대응'])
    bad_supply = any(k in txt for k in ['동반매도', '개인추격주의'])
    lps = 'LPS 재지지' in txt
    sos = 'SOS 돌파' in txt or 'SOS 테스트' in txt
    pull_entry = ('눌림타점형' in txt and '눌림대기형' not in txt)
    cloud_break = any(k in txt for k in ['저항구름 돌파확인형', '저항돌파', '돌파확인'])
    good_supply = _v102_good_supply(txt)
    near_pull = ('최적눌림구간 안/근처' in txt) or (over is not None and over <= 3.0) or over is None
    blue_ok = blue in ['접촉', '위안착'] or (blue == '위확장' and (over is None or over <= 3.0))

    hot = []
    if disp is not None and disp >= 115:
        hot.append(f'이격 {disp:.0f}')
    if rsi is not None and rsi >= 70:
        hot.append(f'RSI {rsi:.0f}')
    if over is not None and over >= 5:
        hot.append(f'눌림권 +{over:.1f}%')

    hard_risk = []
    if utad:
        hard_risk.append('UTAD')
    if fake:
        hard_risk.append('가짜수박주의')
    if exec_exclude or chase_word:
        hard_risk.append('신규 실행 제외')
    if blue == '아래':
        hard_risk.append('파란점선 아래')
    if bad_supply:
        hard_risk.append('수급 역방향')
    hard_risk.extend(hot)

    execute_ready = (lps or pull_entry) and near_pull and blue_ok and good_supply and not hard_risk and not late

    if hard_risk:
        label, emoji = '추격 금지', '⛔'
        action = '신규 진입은 보류하고, 파란점선·5일선·구름상단 회복을 다시 확인합니다.'
        invalid = '위험 사유 해소 전 신규 매수 금지'
        caution = '과열·실패돌파·파란점선 이탈은 추격보다 리스크 관리 우선'
        reasons = hard_risk
    elif late:
        label, emoji = '보유자 대응', '🛡️'
        action = '신규 진입보다 보유자 분할익절·이탈선 관리가 우선입니다.'
        invalid = '5일선/파란점선/구름상단 이탈 시 비중 축소'
        caution = '이미 한 박자 진행된 구간은 신규 추격 금지'
        reasons = ['한 박자 진행', '보유자 우선', blue and f'파란점선 {blue}']
    elif execute_ready:
        label, emoji = '조건부 실행', '🟢'
        action = '재양봉 + 거래량 재유입 + 파란점선/5일선 지지 중 2개 이상 확인 시 분할 실행'
        invalid = '파란점선 또는 당일 저점 이탈 시 관점 폐기'
        caution = '확인 없이 선진입하지 말고 조건 충족 후 분할 접근'
        reasons = ['LPS/눌림 타점', '파란점선 접촉·위안착', '수급 양호']
    else:
        label, emoji = '눌림 대기', '🟡'
        action = '구름상단·5일선·파란점선 눌림 후 재양봉과 거래량 재유입을 확인합니다.'
        invalid = '눌림 지지선 이탈 또는 거래량 동반 음봉이면 제외'
        caution = '구조가 좋아도 현재가가 높으면 첫 눌림 확인 전 추격 금지'
        reasons = []
        if cloud_break or sos:
            reasons.append('돌파 직후')
        if lps or pull_entry:
            reasons.append('눌림 후보')
        if blue:
            reasons.append(f'파란점선 {blue}')
        if good_supply:
            reasons.append('수급 양호')
        if not reasons:
            reasons.append('타점 재확인 필요')

    reasons = _v102_dedupe_list([x for x in reasons if x], 3)
    while len(reasons) < 3:
        filler = ['구조 확인', '수급 확인', '타점 확인'][len(reasons)]
        if filler not in reasons:
            reasons.append(filler)
        else:
            break

    priority = {'조건부 실행': 0, '눌림 대기': 1, '보유자 대응': 2, '추격 금지': 3}.get(label, 9)
    return {
        'label': label,
        'emoji': emoji,
        'reasons': reasons[:3],
        'action': action,
        'invalid': invalid,
        'caution': caution,
        'priority': priority,
        'blue': blue,
    }


def _v102_price_line(lines, row=None):
    row = row or {}
    txt = '\n'.join(map(str, lines or []))
    money = _v102_pick(lines, ['💰 현재가:'])
    cur = _v102_re_float(r'현재가:?\s*([0-9,]+)', money or txt)
    if not cur:
        cur = _v102_num(row.get('현재가') or row.get('Close') or row.get('close') or row.get('종가'), 0)

    pull = _v102_pick_contains(lines, ['🎯 최적눌림:'], last=True)
    pull_txt = '-'
    if pull:
        zone = _v102_re_text(r'([0-9,]+\s*~\s*[0-9,]+)', pull)
        if zone:
            pull_txt = zone.replace(' ', '')
        elif '파란점선/20일선' in pull:
            pull_txt = '파란점선/20일선 지지'
        else:
            pull_txt = _v102_trunc(_v102_payload(pull).split('|')[0], 35)

    stop_src = _v102_pick_contains(lines, ['🧯 무효가격:', '🧯 와이코프 무효:', '무효화', '손절'], last=True) or pull
    stop_txt = '-'
    if stop_src:
        stop_num = (_v102_re_text(r'무효(?:화|가격)?\s*([0-9,]+)', stop_src) or
                    _v102_re_text(r'손절\s*([0-9,]+)', stop_src) or
                    _v102_re_text(r'([0-9,]+)\s*이탈', stop_src))
        if stop_num:
            stop_txt = f"{stop_num} 이탈"
        else:
            stop_txt = _v102_trunc(_v102_payload(stop_src).split('|')[-1], 35)

    target = _v102_pick(lines, ['📌 목표1:'], last=True)
    target_txt = _v102_trunc(_v102_payload(target), 45) if target else '-'
    return f"{_v102_int_price(cur)} / {pull_txt} / {stop_txt} / {target_txt}"

def _v102_supply_line(lines, row=None):
    row = row or {}
    for cand in [
        _v102_pick(lines, ['📍 수급판정:'], last=True),
        _v102_pick(lines, ['🏦 수급:'], last=True),
        _v102_pick(lines, ['🧲 최근5일:'], last=True),
        _v102_pick(lines, ['📦 최근3일:'], last=True),
    ]:
        if cand:
            return _v102_trunc(_v102_payload(cand), 85)
    for k in ['수급판정', '수급요약', '수급', '기관외인수급']:
        if _v102_s(row.get(k)):
            return _v102_trunc(row.get(k), 85)
    return '수급 데이터 확인 필요'


def _v102_reference_line(lines):
    if not _v102_debug_mode():
        return ''
    bits = []
    for p in ['✅ 구조판정:', '📦 와이코프:', '🌊 파동구조:', '🌊 파동타점:', '🔵 파란점선:']:
        x = _v102_pick(lines, [p], last=True)
        if x:
            bits.append(_v102_payload(x))
    return '🧭 참고구조(DEBUG): ' + _v102_trunc(' | '.join(bits), 180) if bits else ''


def _v102_compact_card(seg, row=None):
    try:
        lines = [str(x) for x in (seg or [])]
        if not _v102_is_card(lines) and row is None:
            return lines
        decision = _v102_decide(lines)
        title = _v102_pick(lines, ['⭐ ']) or _v102_first_nonempty(lines)
        if not title or title.startswith('━━━━━━━━'):
            for x in lines:
                if _v102_numbered_stock(x):
                    title = _v102_s(x)
                    break
        name = _v102_clean_name(title)
        out = [name]
        out.append(f"✅ 최종판정(종합): {decision['label']}")
        out.append('📌 이유: ' + ' / '.join(decision['reasons'][:3]))
        out.append('🎯 실행조건: ' + _v102_trunc(decision['action'], 110))
        out.append('🧯 무효조건: ' + _v102_trunc(decision['invalid'], 100))
        out.append('💰 현재/눌림/손절/목표: ' + _v102_price_line(lines, row=row))
        out.append('🏦 수급 한 줄: ' + _v102_supply_line(lines, row=row))
        out.append('⚠️ 주의 한 줄: ' + _v102_trunc(decision['caution'], 100))
        ref = _v102_reference_line(lines)
        if ref:
            out.append(ref)
        clean, seen = [], set()
        for x in out:
            k = _v102_n(x)
            if k and k not in seen:
                clean.append(x)
                seen.add(k)
        return clean
    except Exception:
        return list(seg or [])


_V102_HIDE_PREFIXES = (
    '🚦 실행판정:', '⚠️ 실행제한:', '🎯 최적눌림:', '🎯 와이코프 실행:',
    '🧮 파동점수:', '🧯 무효가격:', '📌 와이코프 해석:', '⚠️ 와이코프 주의:',
    '🧯 와이코프 무효:', '📦 와이코프:', '🌊 파동구조:', '🌊 파동타점:',
    '🧪', '🔬', 'DEBUG:', '디버그:', '파동디버그'
)


def _v102_strip_debug_and_duplicates(text):
    try:
        if _v102_debug_mode():
            return str(text or '')
        out, seen_hot = [], set()
        for raw in str(text or '').splitlines():
            line = str(raw).rstrip()
            s = line.strip()
            if not s:
                if out and out[-1].strip():
                    out.append('')
                continue
            if any(s.startswith(p) for p in _V102_HIDE_PREFIXES):
                continue
            if any(k in s for k in ['실행판정:', '실행제한:', '와이코프 실행:', '파동디버그']):
                continue
            # 최적눌림은 카드의 가격 줄로 합쳐졌으므로 원문 반복은 숨김
            if '최적눌림:' in s:
                continue
            key = _v102_n(s)
            hot_prefix = ''
            for p in ['✅ 최종판정(종합):', '📌 이유:', '🎯 실행조건:', '🧯 무효조건:', '💰 현재/눌림/손절/목표:', '🏦 수급 한 줄:', '⚠️ 주의 한 줄:']:
                if s.startswith(p):
                    hot_prefix = p
                    break
            if hot_prefix:
                local_key = (hot_prefix, key)
                if local_key in seen_hot:
                    continue
                seen_hot.add(local_key)
            out.append(line)
        res = '\n'.join(out)
        while '\n\n\n' in res:
            res = res.replace('\n\n\n', '\n\n')
        return res.strip()
    except Exception:
        return str(text or '')


def _v102_action_first_text(text):
    try:
        if not _v102_readable_enabled():
            return str(text or '')
        b = str(text or '')
        if not b.strip():
            return b
        hot = ['👀 [오늘의 관찰형 참고]', '🛡️ [오늘의 후행형 참고]', '🍉 [초입수박 TOP', '🍉 [눌림수박 TOP',
               '🧭 [선취 제외 후보', '🚀 [흰구름 돌파 후보', '🚀 [흰구름 돌파 관찰', '⭐ ', '🔵 파란점선:', '📦 와이코프:', '🌊 파동']
        if not any(h in b for h in hot):
            return _v102_strip_debug_and_duplicates(b)

        lines = b.splitlines()
        segs, cur = [], []
        for line in lines:
            if cur and _v102_segment_start(line):
                segs.append(cur)
                cur = [line]
            else:
                cur.append(line)
        if cur:
            segs.append(cur)

        cleaned = []
        for seg in segs:
            if _v102_is_card(seg):
                if cleaned and cleaned[-1].strip():
                    cleaned.append('')
                cleaned.extend(_v102_compact_card(seg))
            else:
                cleaned.extend(seg)
        return _v102_strip_debug_and_duplicates('\n'.join(cleaned))
    except Exception:
        return str(text or '')


def _v102_to_dict(row):
    try:
        if hasattr(row, 'to_dict'):
            return dict(row.to_dict())
        if isinstance(row, dict):
            return dict(row)
    except Exception:
        pass
    return {}


def _v102_code_name(row):
    d = _v102_to_dict(row)
    code = _v102_s(d.get('code') or d.get('종목코드') or d.get('Code') or d.get('티커'))
    if code.endswith('.0'):
        code = code[:-2]
    if code.isdigit():
        code = code.zfill(6)
    name = _v102_s(d.get('종목명') or d.get('Name') or d.get('name') or d.get('종목')) or code or '종목명확인'
    return name, code


def _v102_rows_from_frames(*args, **kwargs):
    names = ['telegram_targets','wm_red_top5','wm_blue_top5','dante_pick_df','dante_watch_df','breakout_pick_df','breakout_watch_df','wm_pullback_top5','wm_late_top5','dante_ex_df','ai_candidates','all_hits_df']
    frames = []
    for a in args or []:
        frames.append(a)
    for k in names:
        if k in kwargs:
            frames.append(kwargs.get(k))
    rows, used = [], set()
    for fr in frames:
        try:
            if fr is None:
                continue
            if hasattr(fr, 'iterrows'):
                iterable = [r.to_dict() for _, r in fr.iterrows()]
            elif isinstance(fr, list):
                iterable = fr
            elif isinstance(fr, dict):
                iterable = [fr]
            else:
                iterable = []
            for r in iterable:
                d = _v102_to_dict(r)
                if not d:
                    continue
                name, code = _v102_code_name(d)
                key = code or name
                if not key or key in used:
                    continue
                used.add(key)
                rows.append(d)
        except Exception:
            continue
    return rows


def _v102_lines_from_row(row):
    d = _v102_to_dict(row)
    name, code = _v102_code_name(d)
    lines = [f"1) {name}({code})"]
    cur = _v102_num(d.get('현재가') or d.get('Close') or d.get('close') or d.get('종가'), 0)
    disp = _v102_num(d.get('이격') or d.get('Disparity') or d.get('disparity'), 0)
    rsi = _v102_num(d.get('RSI') or d.get('RSI14') or d.get('rsi'), 0)
    if cur > 0 or disp > 0 or rsi > 0:
        lines.append(f"💰 현재가:{_v102_int_price(cur)} | 이격:{disp:.0f} | RSI:{rsi:.0f}")
    for k in ['유형', '추천단계', '매매판정', '최종판정', 'AI최종판정', '수박최종상태', '수박상태명', '수박정제태그', '수박정제코멘트', '저항구름태그', '후행유형']:
        if _v102_s(d.get(k)):
            lines.append(f"{k}: {d.get(k)}")
    for k in ['수급판정', '수급요약', '수급']:
        if _v102_s(d.get(k)):
            lines.append(f"📍 수급판정: {d.get(k)}")
            break
    try:
        if '_v88_blue_line_text' in globals():
            bl = _v88_blue_line_text(d)
            if bl:
                lines.append(bl)
    except Exception:
        pass
    try:
        if '_v93_wave_lines_from_row' in globals():
            lines.extend([str(x) for x in (_v93_wave_lines_from_row(d) or []) if str(x).strip()])
    except Exception:
        pass
    try:
        if '_v97_dedicated_wyckoff_from_row' in globals():
            wy = _v97_dedicated_wyckoff_from_row(d)
            if isinstance(wy, dict) and wy.get('stage'):
                lines.append(f"📦 와이코프: {wy.get('stage')} {wy.get('score',0)}/100")
                if wy.get('action'):
                    lines.append(f"🎯 와이코프 실행: {wy.get('action')}")
                if wy.get('caution'):
                    lines.append(f"⚠️ 와이코프 주의: {wy.get('caution')}")
    except Exception:
        pass
    return lines


def _v102_make_today_action_block(rows, base=''):
    try:
        items = []
        for r in rows or []:
            lines = _v102_lines_from_row(r)
            dec = _v102_decide(lines)
            name, code = _v102_code_name(r)
            reason = ' / '.join(dec.get('reasons') or [])
            cur = _v102_int_price(_v102_num(r.get('현재가') or r.get('Close') or r.get('close') or r.get('종가'), 0))
            supply = _v102_supply_line(lines, r)
            items.append({
                'name': name,
                'code': code,
                'decision': dec,
                'reason': reason,
                'cur': cur,
                'supply': supply,
                'priority': dec.get('priority', 9),
                'score': _v102_num(r.get('N점수') or r.get('안전점수') or r.get('score'), 0),
            })
        items = sorted(items, key=lambda x: (x['priority'], -x['score'], x['name']))
        groups = [('조건부 실행', '🟢 조건부 실행'), ('눌림 대기', '🟡 눌림 대기'), ('보유자 대응', '🛡️ 보유자 대응'), ('추격 금지', '⛔ 추격 금지')]
        lines = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '🎯 [오늘 매매관점 압축]',
            '',
            '📌 오늘 전략: 최종판정(종합) 기준으로 조건부 실행만 우선, 나머지는 눌림·보유·제외로 분리',
            '📌 확인 순서: 파란점선/5일선 지지 → 재양봉 → 거래량 재유입 → 수급 유지',
        ]
        shown_total = 0
        for label, title in groups:
            arr = [x for x in items if x['decision']['label'] == label]
            if not arr:
                continue
            max_show = 5 if label in ['조건부 실행', '눌림 대기'] else 3
            lines.append('')
            lines.append(title)
            for i, it in enumerate(arr[:max_show], 1):
                code_part = f"({it['code']})" if it.get('code') else ''
                lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | 이유: {_v102_trunc(it['reason'], 55)}")
                if label == '조건부 실행':
                    lines.append('   → 실행: 재양봉+거래량 재유입+파란점선 지지 중 2개 이상 확인')
                elif label == '눌림 대기':
                    lines.append('   → 대기: 구름상단/5일선/파란점선 눌림 후 재지지 확인')
                elif label == '보유자 대응':
                    lines.append('   → 대응: 신규 추격보다 분할익절·이탈선 관리')
                else:
                    lines.append('   → 제외: 위험 사유 해소 전 신규 매수 금지')
                shown_total += 1
        if shown_total == 0:
            lines.append('')
            lines.append('- 조건부 실행 후보 없음. 오늘은 눌림 재지지 확인 우선')
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception:
        return str(base or '')


def build_trade_action_summary_block_from_frames(*args, **kwargs):
    try:
        base = _V102_BASE_ACTION_BLOCK(*args, **kwargs) if _V102_BASE_ACTION_BLOCK else ''
    except Exception as e:
        base = f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
    try:
        rows = _v102_rows_from_frames(*args, **kwargs)
        if rows:
            return _v102_make_today_action_block(rows, base=base)
        return _v102_strip_debug_and_duplicates(base)
    except Exception:
        return _v102_strip_debug_and_duplicates(base)


def _v81_build_today_action_summary_safe(**kwargs):
    try:
        return build_trade_action_summary_block_from_frames(**kwargs)
    except Exception as e:
        return f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘 매매관점 압축]\n- 생성 실패: {e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"


def send_telegram_photo(message, image_paths=[]):
    msg = _v102_action_first_text(message)
    if _V102_BASE_SEND_TELEGRAM_PHOTO:
        return _V102_BASE_SEND_TELEGRAM_PHOTO(msg, image_paths)
    return None


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    msg = _v102_action_first_text(message)
    if _V102_BASE_SEND_TELEGRAM_CHUNKS:
        return _V102_BASE_SEND_TELEGRAM_CHUNKS(msg, title=title, max_len=max_len)
    return None


def build_mobile_html_report(*args, **kwargs):
    if _V102_BASE_BUILD_MOBILE_HTML_REPORT is None:
        return None
    try:
        if 'extra_panels' in kwargs and kwargs.get('extra_panels'):
            panels = []
            for p in kwargs.get('extra_panels') or []:
                if isinstance(p, dict):
                    q = dict(p)
                    if 'body' in q:
                        q['body'] = _v102_action_first_text(q.get('body'))
                    panels.append(q)
                else:
                    panels.append(p)
            kwargs['extra_panels'] = panels
    except Exception:
        pass
    return _V102_BASE_BUILD_MOBILE_HTML_REPORT(*args, **kwargs)

