def _v1021_limit(name, default):
    try:
        return max(1, int(str(os.getenv(name, str(default))).strip()))
    except Exception:
        return default


def _v1021_iter_records(obj):
    try:
        if obj is None:
            return []
        if hasattr(obj, 'empty') and getattr(obj, 'empty'):
            return []
        if hasattr(obj, 'iterrows'):
            return [r.to_dict() for _, r in obj.iterrows()]
        if isinstance(obj, dict):
            stock_keys = {'종목명','Name','name','code','종목코드','Code','티커','현재가','Close','종가','N점수','안전점수'}
            if any(k in obj for k in stock_keys):
                return [dict(obj)]
            out = []
            for v in obj.values():
                out.extend(_v1021_iter_records(v))
            return out
        if isinstance(obj, (list, tuple, set)):
            out = []
            for v in obj:
                out.extend(_v1021_iter_records(v))
            return out
    except Exception:
        return []
    return []


def _v102_rows_from_frames(*args, **kwargs):
    rows, used = [], set()
    sources = []
    try:
        sources.extend(list(args or []))
        sources.extend(list((kwargs or {}).values()))
    except Exception:
        sources = list(args or [])
    for src_obj in sources:
        for r in _v1021_iter_records(src_obj):
            try:
                d = _v102_to_dict(r)
                if not d:
                    continue
                name, code = _v102_code_name(d)
                if not (name or code):
                    continue
                key = (code or '').strip() or (name or '').strip()
                if not key or key in used:
                    continue
                used.add(key)
                rows.append(d)
            except Exception:
                continue
    return rows


def _v1021_classify_item(row):
    lines = _v102_lines_from_row(row)
    dec = _v102_decide(lines)
    name, code = _v102_code_name(row)
    reason = ' / '.join(dec.get('reasons') or [])
    cur = _v102_int_price(_v102_num(row.get('현재가') or row.get('Close') or row.get('close') or row.get('종가'), 0))
    score = _v102_num(row.get('N점수') or row.get('안전점수') or row.get('score'), 0)
    return {'name': name, 'code': code, 'decision': dec, 'reason': reason, 'cur': cur, 'score': score, 'priority': dec.get('priority', 9)}


def _v102_make_today_action_block(rows, base=''):
    try:
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1021_classify_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used:
                    continue
                used.add(key)
                items.append(it)
            except Exception:
                continue
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5)
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 15)
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 5)
        avoid_limit = _v1021_limit('TODAY_ACTION_AVOID_LIMIT', 5)
        groups = [('조건부 실행','🟢 조건부 실행',cond_limit),('눌림 대기','🟡 관찰/눌림 대기',observe_limit),('보유자 대응','🛡️ 보유자 대응',holder_limit),('추격 금지','⛔ 추격 금지',avoid_limit)]
        lines = ['━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━','🎯 [오늘 매매관점 압축]','',f'📌 후보 수집: {total}개 | 관찰/눌림 표시 최대 {observe_limit}개','📌 오늘 전략: 최종판정(종합) 기준으로 조건부 실행만 우선, 나머지는 눌림·보유·제외로 분리','📌 확인 순서: 파란점선/5일선 지지 → 재양봉 → 거래량 재유입 → 수급 유지']
        shown_total = 0
        for label, title, max_show in groups:
            arr = [x for x in items if x['decision']['label'] == label]
            if not arr:
                continue
            lines.append('')
            suffix = f' ({min(len(arr), max_show)}/{len(arr)}개 표시)' if len(arr) > max_show else f' ({len(arr)}개)'
            lines.append(title + suffix)
            for i, it in enumerate(arr[:max_show], 1):
                code_part = f"({it['code']})" if it.get('code') else ''
                lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | 이유: {_v102_trunc(it['reason'], 55)}")
                if label == '조건부 실행':
                    lines.append('   → 실행: 재양봉+거래량 재유입+파란점선 지지 중 2개 이상 확인')
                elif label == '눌림 대기':
                    lines.append('   → 관찰: 구름상단/5일선/파란점선 눌림 후 재지지 확인')
                elif label == '보유자 대응':
                    lines.append('   → 대응: 신규 추격보다 분할익절·이탈선 관리')
                else:
                    lines.append('   → 제외: 위험 사유 해소 전 신규 매수 금지')
                shown_total += 1
        if shown_total == 0:
            lines.append('')
            lines.append('- 조건부 실행/관찰 후보 없음. 오늘은 눌림 재지지 확인 우선')
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception:
        return str(base or '')

# =============================================================
# ✅ END TRADE_CLARITY_V10_2_1_OBSERVE_COUNT_RESTORE_ACTIVE
# =============================================================

# =============================================================
# ✅ TRADE_CLARITY_V10_2_2_DETAIL_RESTORE_ACTIVE
# - V10.2의 최종판정 1개 원칙은 유지
# - 기존 실전 핵심정보(수급 상세/삼각수렴/N조합/단계/저항구름/정제/MA수렴)를 카드 안으로 복원
# - '위험 사유 해소'처럼 모호한 문구를 구체적 제외/회복 조건으로 변경
# - gate/intro_sub/red2_sub 등 디버그 원문은 DEBUG_MODE=1일 때만 노출
# =============================================================
print("✅ TRADE_CLARITY_V10_2_2_DETAIL_RESTORE_ACTIVE LOADED")


def _v1022_join_nonempty(parts, sep=' | ', limit=180):
    try:
        out, seen = [], set()
        for x in parts or []:
            s = _v102_s(x)
            if not s or s in ('-', 'nan', 'None'):
                continue
            k = _v102_n(s)
            if k in seen:
                continue
            seen.add(k)
            out.append(s)
        return _v102_trunc(sep.join(out), limit) if out else ''
    except Exception:
        return ''


def _v1022_clean_payload_line(line):
    try:
        s = _v102_s(line)
        for p in ['📍 수급판정:', '🏦 수급:', '💵 최근1일:', '📦 최근3일:', '🧲 최근5일:', 'N조합:', '단계:', '상태:', '저항구름:', '정제:', '정제검증:', '📊']:
            if s.startswith(p):
                return s.split(':', 1)[1].strip() if ':' in s else s
        return _v102_payload(s)
    except Exception:
        return _v102_s(line)


def _v1022_find_row_value(row, keys, default=''):
    try:
        d = _v102_to_dict(row or {})
        for k in keys:
            v = d.get(k)
            if _v102_s(v):
                return _v102_s(v)
    except Exception:
        pass
    return default


def _v1022_structure_line(lines, row=None):
    """기존 분석에서 사라지면 안 되는 구조/패턴/수렴 정보를 한 줄로 복원."""
    row = row or {}
    bits = []
    try:
        # 1) 원문 카드에서 우선 추출
        for p in ['- 단계:', '단계:', '- N조합:', 'N조합:', '- 저항구름:', '저항구름:', '- 정제:', '정제:', '- 정제검증:', '정제검증:', '✅ 구조판정:']:
            x = _v102_pick(lines, [p], last=True)
            if x:
                label = p.replace('-', '').replace(':', '').strip()
                bits.append(f"{label}:{_v1022_clean_payload_line(x)}")

        # 2) row 기반 복원
        step = _v1022_find_row_value(row, ['단계상태','추천단계','stage','Stage'])
        if step:
            bits.append(f"단계:{step}")
        ncombo = _v1022_find_row_value(row, ['N조합','n_combo','조합','combination','theme'])
        if ncombo:
            bits.append(f"N조합:{ncombo}")
        ngrade = _v1022_find_row_value(row, ['N등급','패턴등급','grade'])
        if ngrade and not any('등급:' in b for b in bits):
            bits.append(f"등급:{ngrade}")
        cloud = _v1022_join_nonempty([
            _v1022_find_row_value(row, ['저항구름태그','저항구름상태']),
            _v1022_find_row_value(row, ['저항구름코멘트'])
        ], ' ')
        if cloud:
            bits.append(f"저항구름:{cloud}")
        refine = _v1022_join_nonempty([
            _v1022_find_row_value(row, ['수박정제태그']),
            _v1022_find_row_value(row, ['수박정제코멘트'])
        ], ' ')
        if refine:
            bits.append(f"정제:{refine}")

        # 3) 삼각/수렴/MA 수렴 복원
        tag_text = ' '.join([_v102_s(x) for x in bits] + [_v102_s(row.get(k)) for k in ['N조합','태그','tags','수박정제태그','MA수렴코멘트'] if isinstance(row, dict)])
        tri = ''
        if any(k in tag_text for k in ['삼각', 'triangle', 'Triangle', '🔺']):
            tri = '삼각수렴'
        ma_vals = []
        # 기존 카드의 📊 초/단/구/BB40/OBV 줄
        for x in lines or []:
            sx = _v102_s(x)
            if sx.startswith('📊') or all(k in sx for k in ['초:', '단:', '구:']):
                ma_vals.append(_v102_trunc(sx.replace('📊', '').strip(), 110))
                break
        has_raw_ma_line = bool(ma_vals)
        if not has_raw_ma_line:
            for label, keys in [
                ('초', ['초단기MA수렴도','ma_ultra']),
                ('단', ['단기MA수렴도','ma_short']),
                ('구', ['구조MA수렴도','ma_structure','MAConv_20_60_112']),
                ('BB40', ['BB40','BB40폭','BB40Width']),
                ('OBV', ['OBV_SLOPE_5','OBV5','OBV'])
            ]:
                val = _v1022_find_row_value(row, keys)
                if val:
                    ma_vals.append(f"{label}:{val}")
        ma_comment = _v1022_find_row_value(row, ['MA수렴코멘트','ma_comment'])
        if ma_comment:
            ma_vals.append(ma_comment)
        if tri:
            ma_vals.insert(0, tri)
        if ma_vals:
            bits.append('수렴:' + _v1022_join_nonempty(ma_vals, ' / ', 130))

        line = _v1022_join_nonempty(bits, ' | ', 230)
        return '🧬 구조/패턴: ' + line if line else ''
    except Exception:
        return ''


def _v1022_supply_detail_line(lines, row=None):
    """한 줄 판정 + 최근 1/3/5일 수급을 최대한 보존."""
    row = row or {}
    try:
        verdict = ''
        details = []
        for p in ['📍 수급판정:', '🏦 수급:']:
            x = _v102_pick(lines, [p], last=True)
            if x:
                verdict = _v1022_clean_payload_line(x)
                break
        if not verdict:
            verdict = _v1022_find_row_value(row, ['수급판정','수급요약','수급','기관외인수급'])
        for p in ['💵 최근1일:', '📦 최근3일:', '🧲 최근5일:', '- 수급요약:', '수급요약:']:
            x = _v102_pick(lines, [p], last=True)
            if x:
                details.append(p.replace('-', '').replace(':','').strip() + ' ' + _v1022_clean_payload_line(x))
        # row에 숫자형/문자형 수급 요약이 들어있는 경우
        detail_text_now = ' '.join(details)
        for label, keys in [
            ('1일', ['최근1일수급','수급1일','net_1d','foreign_inst_1d']),
            ('3일', ['최근3일수급','수급3일','net_3d','foreign_inst_3d']),
            ('5일', ['최근5일수급','수급5일','net_5d','foreign_inst_5d']),
        ]:
            val = _v1022_find_row_value(row, keys)
            if val and f"최근{label}" not in detail_text_now:
                details.append(f"최근{label} {val}")
        line = _v1022_join_nonempty([verdict] + details, ' | ', 220)
        return line or '수급 데이터 확인 필요'
    except Exception:
        return _v102_supply_line(lines, row=row)


def _v1022_price_line(lines, row=None):
    try:
        base = _v102_price_line(lines, row=row)
        # 목표 줄에 손절이 중복 포함되는 문제 축약
        parts = [p.strip() for p in str(base).split('/')]
        if len(parts) >= 4:
            target = parts[-1]
            if '|' in target and '손절' in target:
                target = target.split('|', 1)[0].strip()
            parts[-1] = target
            return ' / '.join(parts)
        return base
    except Exception:
        return _v102_price_line(lines, row=row)


_V1022_BASE_DECIDE = _v102_decide

def _v1022_decide(lines):
    dec = _V1022_BASE_DECIDE(lines)
    try:
        label = dec.get('label')
        reasons = dec.get('reasons') or []
        reason_txt = ' '.join(map(str, reasons))
        if label == '추격 금지':
            dec['action'] = '신규 진입 보류. 파란점선·5일선 회복 후 재양봉/거래량 재유입까지 기다립니다.'
            if any(k in reason_txt for k in ['UTAD', '가짜수박주의']):
                dec['invalid'] = '실패돌파/가짜수박 신호가 남아 있거나 전고점 재돌파 실패 시 제외 유지'
            elif '파란점선 아래' in reason_txt:
                dec['invalid'] = '파란점선 아래 종가 유지 또는 5일선 회복 실패 시 제외 유지'
            elif any(k in reason_txt for k in ['이격', 'RSI', '눌림권']):
                dec['invalid'] = '과열 식힘 없이 추가 상승만 나오면 신규 매수 제외 유지'
            elif '수급 역방향' in reason_txt:
                dec['invalid'] = '외인·기관 매도 우위가 이어지면 신규 매수 제외 유지'
            else:
                dec['invalid'] = '파란점선/5일선 회복 전 또는 거래량 동반 음봉 시 제외 유지'
            dec['caution'] = '추격 금지는 “영원히 금지”가 아니라 회복 조건 확인 전 보류라는 뜻'
        elif label == '눌림 대기':
            dec['invalid'] = '눌림 자리에서 5일선·파란점선·구름상단을 회복하지 못하면 제외'
        elif label == '보유자 대응':
            dec['invalid'] = '5일선/파란점선 이탈 또는 거래량 실린 장대음봉이면 비중 축소'
    except Exception:
        pass
    return dec

# 기존 이름을 override해서 오늘 매매관점/카드 모두 V102.2 기준을 사용하게 함
def _v102_decide(lines):
    return _v1022_decide(lines)


def _v102_compact_card(seg, row=None):
    try:
        lines = [str(x) for x in (seg or [])]
        if not _v102_is_card(lines) and row is None:
            return lines
        decision = _v102_decide(lines)
        title = _v102_pick(lines, ['⭐ ']) or _v102_first_nonempty(lines)
        if not title or title.startswith('━━━━━━━━'):
            for x in lines:
                if _v102_numbered_stock(x):
                    title = _v102_s(x)
                    break
        name = _v102_clean_name(title)
        out = [name]
        out.append(f"✅ 최종판정(종합): {decision['label']}")
        out.append('📌 이유: ' + ' / '.join(decision['reasons'][:3]))
        struct = _v1022_structure_line(lines, row=row)
        if struct:
            out.append(struct)
        out.append('🎯 실행조건: ' + _v102_trunc(decision['action'], 125))
        out.append('🧯 무효조건: ' + _v102_trunc(decision['invalid'], 120))
        out.append('💰 현재/눌림/손절/목표: ' + _v1022_price_line(lines, row=row))
        out.append('🏦 수급: ' + _v1022_supply_detail_line(lines, row=row))
        out.append('⚠️ 주의: ' + _v102_trunc(decision['caution'], 110))
        ref = _v102_reference_line(lines)
        if ref:
            out.append(ref)
        clean, seen = [], set()
        for x in out:
            k = _v102_n(x)
            if k and k not in seen:
                clean.append(x)
                seen.add(k)
        return clean
    except Exception:
        return list(seg or [])


def _v102_lines_from_row(row):
    d = _v102_to_dict(row)
    name, code = _v102_code_name(d)
    lines = [f"1) {name}({code})"]
    cur = _v102_num(d.get('현재가') or d.get('Close') or d.get('close') or d.get('종가'), 0)
    disp = _v102_num(d.get('이격') or d.get('Disparity') or d.get('disparity'), 0)
    rsi = _v102_num(d.get('RSI') or d.get('RSI14') or d.get('rsi'), 0)
    if cur > 0 or disp > 0 or rsi > 0:
        lines.append(f"💰 현재가:{_v102_int_price(cur)} | 이격:{disp:.0f} | RSI:{rsi:.0f}")
    # 기존 핵심 필드 최대 보존
    for k in ['단계상태','추천단계','유형','N등급','N조합','time_sym_tag','수박최종상태','수박상태명','후행유형','저항구름태그','저항구름코멘트','수박정제태그','수박정제코멘트','MA수렴코멘트']:
        if _v102_s(d.get(k)):
            prefix = 'N조합' if k == 'N조합' else k
            lines.append(f"{prefix}: {d.get(k)}")
    ma_bits = []
    for label, key in [('초', '초단기MA수렴도'), ('단', '단기MA수렴도'), ('구', '구조MA수렴도'), ('BB40', 'BB40'), ('OBV', 'OBV_SLOPE_5')]:
        if _v102_s(d.get(key)):
            ma_bits.append(f"{label}:{d.get(key)}")
    if ma_bits:
        lines.append('📊 ' + ' | '.join(ma_bits))
    for k in ['수급판정', '수급요약', '수급']:
        if _v102_s(d.get(k)):
            lines.append(f"📍 수급판정: {d.get(k)}")
            break
    for label, keys in [('💵 최근1일:', ['최근1일수급','수급1일']), ('📦 최근3일:', ['최근3일수급','수급3일']), ('🧲 최근5일:', ['최근5일수급','수급5일'])]:
        for k in keys:
            if _v102_s(d.get(k)):
                lines.append(label + ' ' + _v102_s(d.get(k)))
                break
    try:
        if '_v88_blue_line_text' in globals():
            bl = _v88_blue_line_text(d)
            if bl:
                lines.append(bl)
    except Exception:
        pass
    try:
        if '_v93_wave_lines_from_row' in globals() and _v102_debug_mode():
            lines.extend([str(x) for x in (_v93_wave_lines_from_row(d) or []) if str(x).strip()])
    except Exception:
        pass
    try:
        if '_v97_dedicated_wyckoff_from_row' in globals() and _v102_debug_mode():
            wy = _v97_dedicated_wyckoff_from_row(d)
            if isinstance(wy, dict) and wy.get('stage'):
                lines.append(f"📦 와이코프: {wy.get('stage')} {wy.get('score',0)}/100")
                if wy.get('action'):
                    lines.append(f"🎯 와이코프 실행: {wy.get('action')}")
                if wy.get('caution'):
                    lines.append(f"⚠️ 와이코프 주의: {wy.get('caution')}")
    except Exception:
        pass
    return lines


def _v1021_classify_item(row):
    lines = _v102_lines_from_row(row)
    dec = _v102_decide(lines)
    name, code = _v102_code_name(row)
    reason = ' / '.join(dec.get('reasons') or [])
    cur = _v102_int_price(_v102_num(row.get('현재가') or row.get('Close') or row.get('close') or row.get('종가'), 0))
    score = _v102_num(row.get('N점수') or row.get('안전점수') or row.get('score'), 0)
    struct = _v1022_structure_line(lines, row=row)
    if struct.startswith('🧬 구조/패턴: '):
        struct = struct.replace('🧬 구조/패턴: ', '', 1)
    supply = _v1022_supply_detail_line(lines, row=row)
    return {'name': name, 'code': code, 'decision': dec, 'reason': reason, 'cur': cur, 'score': score, 'priority': dec.get('priority', 9), 'struct': struct, 'supply': supply}


def _v102_make_today_action_block(rows, base=''):
    try:
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1021_classify_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used:
                    continue
                used.add(key)
                items.append(it)
            except Exception:
                continue
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5) if '_v1021_limit' in globals() else 5
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 15) if '_v1021_limit' in globals() else 15
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 5) if '_v1021_limit' in globals() else 5
        avoid_limit = _v1021_limit('TODAY_ACTION_AVOID_LIMIT', 5) if '_v1021_limit' in globals() else 5
        groups = [('조건부 실행','🟢 조건부 실행',cond_limit),('눌림 대기','🟡 관찰/눌림 대기',observe_limit),('보유자 대응','🛡️ 보유자 대응',holder_limit),('추격 금지','⛔ 추격 금지',avoid_limit)]
        lines = ['━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━','🎯 [오늘 매매관점 압축]','',f'📌 후보 수집: {total}개 | 관찰/눌림 표시 최대 {observe_limit}개','📌 오늘 전략: 최종판정(종합)은 1개만 보고, 구조/수급/수렴은 보조 확인','📌 확인 순서: 파란점선/5일선 지지 → 재양봉 → 거래량 재유입 → 수급 유지']
        shown_total = 0
        for label, title, max_show in groups:
            arr = [x for x in items if x['decision']['label'] == label]
            if not arr:
                continue
            lines.append('')
            suffix = f' ({min(len(arr), max_show)}/{len(arr)}개 표시)' if len(arr) > max_show else f' ({len(arr)}개)'
            lines.append(title + suffix)
            for i, it in enumerate(arr[:max_show], 1):
                code_part = f"({it['code']})" if it.get('code') else ''
                lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | 이유: {_v102_trunc(it['reason'], 55)}")
                if it.get('struct'):
                    lines.append(f"   구조: {_v102_trunc(it['struct'], 95)}")
                if it.get('supply') and it.get('supply') != '수급 데이터 확인 필요':
                    lines.append(f"   수급: {_v102_trunc(it['supply'], 95)}")
                if label == '조건부 실행':
                    lines.append('   실행: 재양봉+거래량 재유입+파란점선/5일선 지지 중 2개 이상 확인')
                elif label == '눌림 대기':
                    lines.append('   관찰: 구름상단/5일선/파란점선 눌림 후 재지지 확인')
                elif label == '보유자 대응':
                    lines.append('   대응: 신규 추격보다 분할익절·이탈선 관리')
                else:
                    lines.append('   제외: 파란점선/5일선 회복 전 또는 실패돌파·과열 지속 시 신규 매수 보류')
                shown_total += 1
        if shown_total == 0:
            lines.append('')
            lines.append('- 조건부 실행/관찰 후보 없음. 오늘은 눌림 재지지 확인 우선')
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception:
        return str(base or '')

# 디버그/반복 제거 보강
_V1022_EXTRA_DEBUG_PREFIXES = ('- gate:', '- intro_sub:', '- red2_sub:', 'gate:', 'intro_sub:', 'red2_sub:', '- blue_sub:', 'blue_sub:', '- debug:', 'debug:')
_V1022_EXTRA_DEBUG_CONTAINS = ('blue_confirm=', 'red_raw=', 'blue1_onset=', 'blue2_onset=', 'intro_box=', 'pullback_box=', 'red2_raw=')

def _v102_strip_debug_and_duplicates(text):
    try:
        if _v102_debug_mode():
            return str(text or '')
        out, seen_hot = [], set()
        for raw in str(text or '').splitlines():
            line = str(raw).rstrip()
            s = line.strip()
            if not s:
                if out and out[-1].strip():
                    out.append('')
                continue
            if s.startswith(_V1022_EXTRA_DEBUG_PREFIXES) or any(k in s for k in _V1022_EXTRA_DEBUG_CONTAINS):
                continue
            if any(s.startswith(p) for p in _V102_HIDE_PREFIXES):
                continue
            if any(k in s for k in ['실행판정:', '실행제한:', '와이코프 실행:', '파동디버그']):
                continue
            if '최적눌림:' in s:
                continue
            key = _v102_n(s)
            hot_prefix = ''
            for p in ['✅ 최종판정(종합):', '📌 이유:', '🧬 구조/패턴:', '🎯 실행조건:', '🧯 무효조건:', '💰 현재/눌림/손절/목표:', '🏦 수급:', '🏦 수급 한 줄:', '⚠️ 주의:', '⚠️ 주의 한 줄:']:
                if s.startswith(p):
                    hot_prefix = p
                    break
            if hot_prefix:
                local_key = (hot_prefix, key)
                if local_key in seen_hot:
                    continue
                seen_hot.add(local_key)
            out.append(line)
        res = '\n'.join(out)
        while '\n\n\n' in res:
            res = res.replace('\n\n\n', '\n\n')
        return res.strip()
    except Exception:
        return str(text or '')

