def _v1023_env_int(name, default=0):
    try:
        return int(str(os.getenv(name, str(default))).strip())
    except Exception:
        return default


def _v1023_show_excluded_risk():
    try:
        if str(os.getenv('SHOW_EXCLUDED_RISK', '0')).strip().lower() in ('1', 'true', 'yes', 'y', 'on'):
            return True
        return _v1023_env_int('TODAY_ACTION_AVOID_LIMIT', 0) > 0
    except Exception:
        return False


def _v1023_hard_risk_text(txt):
    """실행/관찰 후보에서 제외해야 하는 위험 신호를 구체적으로 판정."""
    s = _v102_s(txt)
    risks = []
    if any(k in s for k in ['UTAD', '실패돌파']):
        risks.append('UTAD/실패돌파')
    if any(k in s for k in ['가짜수박주의', '가짜/정제주의']):
        risks.append('가짜수박주의')
    if any(k in s for k in ['신규 실행 제외', '실행제외형', '신규 매수 금지']):
        risks.append('신규 실행 제외')
    if any(k in s for k in ['파란점선 아래', '파란점선 이탈']):
        risks.append('파란점선 아래')
    if any(k in s for k in ['수급 역방향', '동반매도', '개인추격주의']):
        risks.append('수급 역방향')
    if any(k in s for k in ['후행수박', '후행형']) and not any(k in s for k in ['오늘의 후행형 참고', '후행수박 TOP']):
        risks.append('후행형')
    try:
        disp = _v102_re_float(r'이격[: ]+([0-9]+(?:\.[0-9]+)?)', s)
        if disp is not None and disp >= 115:
            risks.append(f'이격 {disp:.0f}')
    except Exception:
        pass
    try:
        rsi = _v102_re_float(r'RSI[: ]+([0-9]+(?:\.[0-9]+)?)', s)
        if rsi is not None and rsi >= 70:
            risks.append(f'RSI {rsi:.0f}')
    except Exception:
        pass
    return _v102_dedupe_list(risks, 5)


def _v1023_is_risk_item(row_or_text):
    try:
        if isinstance(row_or_text, dict) or hasattr(row_or_text, 'to_dict'):
            lines = _v102_lines_from_row(row_or_text)
            dec = _v102_decide(lines)
            if dec.get('label') == '추격 금지':
                return True, dec.get('reasons') or _v1023_hard_risk_text('\n'.join(lines))
            risks = _v1023_hard_risk_text('\n'.join(lines))
            return bool(risks), risks
        s = _v102_s(row_or_text)
        if '✅ 최종판정(종합): 추격 금지' in s:
            return True, _v1023_hard_risk_text(s) or ['추격 금지']
        risks = _v1023_hard_risk_text(s)
        return bool(risks), risks
    except Exception:
        return False, []


def _v1023_is_action_candidate_section(text):
    s = _v102_s(text)
    if any(k in s for k in ['선취 제외 후보', '후행수박 TOP', '오늘의 후행형 참고', '추격 금지', '제외/리스크']):
        return False
    return any(k in s for k in [
        '오늘의 실시간 TOP', '오늘의 선취형 후보', '오늘의 관찰형 참고',
        '선취 후보 TOP', '선취 관찰 후보 TOP', '흰구름 돌파 후보', '흰구름 돌파 관찰',
        '초입수박 TOP', '눌림수박 TOP', '수박상태 빨강 TOP', '파란점선 타점 TOP',
        'Blue-1 단기 TOP', 'Blue-2 예비 TOP', 'Blue-2 스윙 TOP'
    ])


def _v1023_is_card_start(line):
    try:
        s = _v102_s(line)
        if not s:
            return False
        if s.startswith('[TEST]'):
            return False
        if s.startswith('[') and ']' in s and not any(h in s for h in ['오늘', 'TOP', '후보', '참고', 'TEST MODE']):
            return True
        import re as _re
        return bool(_re.match(r'^\d+\)\s+.+\([A-Za-z0-9]{5,6}\)', s))
    except Exception:
        return False


def _v1023_filter_risk_cards_from_action_sections(text):
    """관찰/실행 섹션에서 추격금지·위험사유 카드를 제거한다."""
    try:
        body = str(text or '')
        if not _v1023_is_action_candidate_section(body):
            return body.replace('위험 사유 해소 전 신규 매수 금지', '파란점선/5일선 회복 전 또는 실패돌파·과열 지속 시 신규 매수 보류')
        lines = body.splitlines()
        out = []
        removed = []
        i = 0
        while i < len(lines):
            line = lines[i]
            if _v1023_is_card_start(line):
                block = [line]
                i += 1
                while i < len(lines) and not _v1023_is_card_start(lines[i]):
                    # 다음 큰 섹션이 시작되면 카드 블록 종료
                    if i > 0 and lines[i].strip().startswith('━━━━━━━━') and len(block) > 1:
                        break
                    block.append(lines[i])
                    i += 1
                btxt = '\n'.join(block)
                is_risk, reasons = _v1023_is_risk_item(btxt)
                if is_risk:
                    title = _v102_clean_name(block[0])
                    removed.append((title, reasons))
                    continue
                out.extend(block)
                continue
            out.append(line)
            i += 1
        if removed:
            # 비어 보이지 않게 섹션 하단에 짧은 안내만 남긴다.
            insert_line = f"- 위험사유 {len(removed)}개는 실행/관찰 후보에서 제외했습니다. 제외 사유: " + ' / '.join(_v102_dedupe_list([r for _, rs in removed for r in (rs or [])], 4))
            # 마지막 구분선 바로 앞에 삽입
            pos = len(out)
            for j in range(len(out)-1, -1, -1):
                if out[j].strip().startswith('━━━━━━━━'):
                    pos = j
                    break
            out.insert(pos, insert_line)
        res = '\n'.join(out)
        res = res.replace('위험 사유 해소 전 신규 매수 금지', '파란점선/5일선 회복 전 또는 실패돌파·과열 지속 시 신규 매수 보류')
        while '\n\n\n' in res:
            res = res.replace('\n\n\n', '\n\n')
        return res.strip()
    except Exception:
        return str(text or '')


def _v102_make_today_action_block(rows, base=''):
    """오늘 매매관점 압축: 위험사유 종목은 기본 상세 숨김, 실행/관찰 후보와 분리."""
    try:
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1021_classify_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used:
                    continue
                used.add(key)
                # 안전장치: 위험사유가 있으면 무조건 추격 금지 그룹으로 이동
                is_risk, risk_reasons = _v1023_is_risk_item(r)
                if is_risk:
                    it['decision']['label'] = '추격 금지'
                    it['decision']['priority'] = 3
                    it['priority'] = 3
                    if risk_reasons:
                        it['reason'] = ' / '.join(_v102_dedupe_list(risk_reasons, 3))
                items.append(it)
            except Exception:
                continue
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5) if '_v1021_limit' in globals() else 5
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 15) if '_v1021_limit' in globals() else 15
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 5) if '_v1021_limit' in globals() else 5
        avoid_limit = max(0, _v1023_env_int('TODAY_ACTION_AVOID_LIMIT', 0))
        show_excluded = _v1023_show_excluded_risk()
        lines = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '🎯 [오늘 매매관점 압축]',
            '',
            f'📌 후보 수집: {total}개 | 관찰/눌림 표시 최대 {observe_limit}개',
            '📌 오늘 전략: 위험사유 종목은 실행/관찰 후보에서 제외, 조건부 실행과 눌림 대기만 우선 확인',
            '📌 확인 순서: 파란점선/5일선 지지 → 재양봉 → 거래량 재유입 → 수급 유지'
        ]
        groups = [('조건부 실행','🟢 조건부 실행',cond_limit),('눌림 대기','🟡 관찰/눌림 대기',observe_limit),('보유자 대응','🛡️ 보유자 대응',holder_limit)]
        shown_total = 0
        excluded = [x for x in items if x['decision']['label'] == '추격 금지']
        for label, title, max_show in groups:
            arr = [x for x in items if x['decision']['label'] == label]
            if not arr:
                continue
            lines.append('')
            suffix = f' ({min(len(arr), max_show)}/{len(arr)}개 표시)' if len(arr) > max_show else f' ({len(arr)}개)'
            lines.append(title + suffix)
            for i, it in enumerate(arr[:max_show], 1):
                code_part = f"({it['code']})" if it.get('code') else ''
                lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | 이유: {_v102_trunc(it['reason'], 55)}")
                if it.get('struct'):
                    lines.append(f"   구조: {_v102_trunc(it['struct'], 95)}")
                if it.get('supply') and it.get('supply') != '수급 데이터 확인 필요':
                    lines.append(f"   수급: {_v102_trunc(it['supply'], 95)}")
                if label == '조건부 실행':
                    lines.append('   실행: 재양봉+거래량 재유입+파란점선/5일선 지지 중 2개 이상 확인')
                elif label == '눌림 대기':
                    lines.append('   관찰: 구름상단/5일선/파란점선 눌림 후 재지지 확인')
                elif label == '보유자 대응':
                    lines.append('   대응: 신규 추격보다 분할익절·이탈선 관리')
                shown_total += 1
        if excluded:
            lines.append('')
            lines.append(f'⛔ 제외/리스크 참고: {len(excluded)}개')
            if show_excluded and avoid_limit > 0:
                for i, it in enumerate(excluded[:avoid_limit], 1):
                    code_part = f"({it['code']})" if it.get('code') else ''
                    lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | 제외사유: {_v102_trunc(it['reason'], 55)}")
                    lines.append('   기준: 파란점선/5일선 회복 전 또는 실패돌파·과열 지속 시 신규 매수 보류')
            else:
                lines.append('   상세 숨김: SHOW_EXCLUDED_RISK=1 또는 TODAY_ACTION_AVOID_LIMIT>0이면 표시')
        if shown_total == 0:
            lines.append('')
            lines.append('- 조건부 실행/관찰 후보 없음. 오늘은 눌림 재지지 확인 우선')
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception:
        return str(base or '')


def _v102_action_first_text(text):
    try:
        msg = _V1023_BASE_ACTION_FIRST_TEXT(text)
        msg = _v1023_filter_risk_cards_from_action_sections(msg)
        msg = msg.replace('위험 사유 해소 전 신규 매수 금지', '파란점선/5일선 회복 전 또는 실패돌파·과열 지속 시 신규 매수 보류')
        return _v102_strip_debug_and_duplicates(msg)
    except Exception:
        return str(text or '')

# =============================================================
# ✅ END TRADE_CLARITY_V10_2_3_STRICT_RISK_EXCLUDE_ACTIVE
