# ✅ TRADE_CLARITY_V10_2_4_SIGNAL_SUMMARY_RESTORE_ACTIVE
# - 세력매집봉/매집파동자리 정보 복원
# - 타점요약/차트요약을 카드형 출력에 추가
# - 위험사유 제외 원칙(V10.2.3)은 유지하고, 실행/관찰 후보에는 핵심 판단 정보만 보강
# =============================================================
print("✅ TRADE_CLARITY_V10_2_4_SIGNAL_SUMMARY_RESTORE_ACTIVE LOADED")

_V1024_BASE_LINES_FROM_ROW = _v102_lines_from_row
_V1024_BASE_CLASSIFY_ITEM = _v1021_classify_item
_V1024_BASE_ACTION_FIRST_TEXT = _v102_action_first_text


def _v1024_fmt_price(v):
    try:
        n = float(str(v).replace(',', '').strip())
        if n <= 0:
            return ''
        return f"{int(round(n)):,}"
    except Exception:
        return ''


def _v1024_get(row, keys, default=''):
    try:
        d = _v102_to_dict(row or {})
        for k in keys:
            v = d.get(k)
            if _v102_s(v):
                return _v102_s(v)
    except Exception:
        pass
    return default


def _v1024_pick_line(lines, needles, last=True):
    try:
        arr = []
        for x in lines or []:
            sx = _v102_s(x)
            if any(n in sx for n in needles):
                arr.append(sx)
        if not arr:
            return ''
        return arr[-1] if last else arr[0]
    except Exception:
        return ''


def _v1024_line_payload(s):
    try:
        sx = _v102_s(s)
        if ':' in sx:
            return sx.split(':', 1)[1].strip()
        return sx
    except Exception:
        return _v102_s(s)


def _v1024_join(parts, sep=' | ', limit=170):
    try:
        out, seen = [], set()
        for x in parts or []:
            sx = _v102_s(x)
            if not sx or sx in ('-', 'None', 'nan', '0', '0.0'):
                continue
            key = _v102_n(sx)
            if key in seen:
                continue
            seen.add(key)
            out.append(sx)
        return _v102_trunc(sep.join(out), limit) if out else ''
    except Exception:
        return ''


def _v1024_accum_line(lines, row=None):
    """세력매집봉/매집봉/세력흔적 정보를 카드 한 줄로 복원."""
    row = row or {}
    try:
        raw = _v1024_pick_line(lines, ['🪵 매집봉:', '🕯️ 세력매집봉:', '세력매집봉:', '매집봉:'], last=True)
        raw_payload = ''
        if raw:
            raw_payload = _v1024_line_payload(raw)

        tag = _v1024_get(row, ['매집봉태그', 'accum_label', 'accum_tag'])
        score = _v1024_get(row, ['매집봉점수', 'accum_score'])
        grade = _v1024_get(row, ['매집봉등급', 'accum_grade'])
        comment = _v1024_get(row, ['매집봉코멘트', 'accum_comment', '매집봉설명'])
        high = _v1024_fmt_price(_v1024_get(row, ['매집봉고가', 'accum_high']))
        low = _v1024_fmt_price(_v1024_get(row, ['매집봉저가', 'accum_low']))
        force_tag = _v1024_get(row, ['세력흔적태그', 'force_trace_tag'])
        force_score = _v1024_get(row, ['세력흔적점수', 'force_trace_score'])
        force_comment = _v1024_get(row, ['세력흔적코멘트', 'force_trace_comment'])

        parts = []
        if raw_payload and '매집봉 없음' not in raw_payload:
            parts.append(raw_payload)
        if tag and tag != '매집봉 없음':
            p = tag
            if score:
                p += f" {score}점"
            if grade and grade != '없음':
                p += f"/{grade}"
            parts.append(p)
        if high and low:
            parts.append(f"매집봉 박스 {low}~{high}")
        if comment and comment not in ('데이터 부족', '없음'):
            parts.append(comment)
        if force_tag or force_score:
            p = force_tag or '세력흔적'
            if force_score:
                p += f" {force_score}점"
            if force_comment:
                p += f" | {force_comment}"
            parts.append(p)

        line = _v1024_join(parts, ' | ', 210)
        return f"🕯️ 세력매집봉: {line}" if line else ''
    except Exception:
        return ''


def _v1024_entry_summary_line(lines, row=None, decision=None):
    """파란점선/최적눌림/파동타점/자리평가를 실제 확인용 한 줄로 정리."""
    row = row or {}
    try:
        decision = decision or _v102_decide(lines)
        label = decision.get('label', '') if isinstance(decision, dict) else ''
        parts = []

        blue_state = _v1024_get(row, ['파란점선상태', 'blue_line_state'])
        blue_price = _v1024_fmt_price(_v1024_get(row, ['파란점선기준가', 'blue_line_price']))
        blue_gap = _v1024_get(row, ['파란점선이격', 'blue_line_gap_pct'])
        if blue_state or blue_price:
            p = blue_state or '파란점선 확인'
            if blue_price:
                p += f" {blue_price}원"
            if blue_gap:
                try:
                    p += f"({float(str(blue_gap).replace(',', '')):+.1f}%)"
                except Exception:
                    p += f"({blue_gap})"
            parts.append(p)

        bz_low = _v1024_fmt_price(_v1024_get(row, ['파란타점영역하단', 'blue_zone_low']))
        bz_high = _v1024_fmt_price(_v1024_get(row, ['파란타점영역상단', 'blue_zone_high']))
        if bz_low and bz_high:
            parts.append(f"파란타점 {bz_low}~{bz_high}")
        else:
            raw_blue = _v1024_pick_line(lines, ['🔵 파란타점 영역:', '파란타점 영역:', '파란점선:'], last=True)
            if raw_blue:
                parts.append(_v1024_line_payload(raw_blue))

        best_low = _v1024_fmt_price(_v1024_get(row, ['파동최적하단', '최적눌림하단', 'best_zone_low']))
        best_high = _v1024_fmt_price(_v1024_get(row, ['파동최적상단', '최적눌림상단', 'best_zone_high']))
        if best_low and best_high:
            parts.append(f"최적눌림 {best_low}~{best_high}")
        else:
            raw_best = _v1024_pick_line(lines, ['🎯 최적눌림:', '최적눌림:', '🌊 파동타점:'], last=True)
            if raw_best:
                parts.append(_v1024_line_payload(raw_best))

        pos_label = _v1024_get(row, ['자리평가라벨', 'position_label'])
        pos_score = _v1024_get(row, ['자리평가점수', 'position_score'])
        if pos_label:
            parts.append(f"자리 {pos_label}" + (f" {pos_score}점" if pos_score else ''))
        else:
            raw_pos = _v1024_pick_line(lines, ['🪑 자리평가:', '자리평가:'], last=True)
            if raw_pos:
                parts.append(_v1024_line_payload(raw_pos))

        invalid = _v1024_fmt_price(_v1024_get(row, ['파동무효화', '무효가격', '🚨손절가', '손절가']))
        if invalid:
            parts.append(f"무효 {invalid} 이탈")

        if label == '조건부 실행':
            parts.insert(0, '재양봉·거래량·파란점선 지지 중 2개 확인')
        elif label == '눌림 대기':
            parts.insert(0, '첫 눌림 지지 확인 전 추격 금지')
        elif label == '보유자 대응':
            parts.insert(0, '신규보다 이탈선/분할익절 관리')
        elif label == '추격 금지':
            parts.insert(0, '회복 신호 전 신규 제외')

        line = _v1024_join(parts, ' | ', 230)
        return f"📍 타점요약: {line}" if line else ''
    except Exception:
        return ''


def _v1024_chart_summary_line(lines, row=None):
    """삼각수렴/MA수렴/소파동/중파동/저항구름 중심으로 차트 한 줄 요약."""
    row = row or {}
    try:
        parts = []
        txt = ' '.join([_v102_s(x) for x in lines or []]) + ' ' + ' '.join([_v102_s(v) for v in _v102_to_dict(row).values()])
        if any(k in txt for k in ['삼각수렴', '🔺삼각', 'triangle', 'Triangle']):
            parts.append('삼각수렴')

        small_state = _v1024_get(row, ['소파동위치', 'small_state'])
        small_low = _v1024_fmt_price(_v1024_get(row, ['소파동저점', 'small_low']))
        small_high = _v1024_fmt_price(_v1024_get(row, ['소파동전고점', 'small_high']))
        if small_state:
            p = f"소파동 {small_state}"
            if small_low and small_high:
                p += f"({small_low}~{small_high})"
            parts.append(p)
        else:
            raw_small = _v1024_pick_line(lines, ['〰️ 소파동:', '소파동:'], last=True)
            if raw_small:
                parts.append(_v1024_line_payload(raw_small))

        mid_state = _v1024_get(row, ['중파동위치', 'mid_state'])
        mid_low = _v1024_fmt_price(_v1024_get(row, ['중파동저점', 'mid_low']))
        mid_high = _v1024_fmt_price(_v1024_get(row, ['중파동전고점', 'mid_high']))
        if mid_state:
            p = f"중파동 {mid_state}"
            if mid_low and mid_high:
                p += f"({mid_low}~{mid_high})"
            parts.append(p)
        else:
            raw_mid = _v1024_pick_line(lines, ['📶 중파동:', '중파동:'], last=True)
            if raw_mid:
                parts.append(_v1024_line_payload(raw_mid))

        cloud = _v1024_get(row, ['저항구름태그', '저항구름상태', '저항구름코멘트'])
        if cloud:
            parts.append(f"저항구름 {cloud}")
        else:
            raw_cloud = _v1024_pick_line(lines, ['저항구름:'], last=True)
            if raw_cloud:
                parts.append(_v1024_line_payload(raw_cloud))

        ma_line = _v1024_pick_line(lines, ['📊 ', '초:', '단:', '구:', 'BB40'], last=True)
        if ma_line:
            parts.append(_v102_trunc(ma_line.replace('📊', '').strip(), 90))
        else:
            ma_bits = []
            for label, keys in [
                ('초', ['초단기MA수렴도', 'ma_ultra']),
                ('단', ['단기MA수렴도', 'ma_short']),
                ('구', ['구조MA수렴도', 'ma_structure']),
                ('BB40', ['BB40', 'BB40폭', 'BB40Width']),
                ('OBV', ['OBV_SLOPE_5', 'OBV5', 'OBV'])
            ]:
                v = _v1024_get(row, keys)
                if v:
                    ma_bits.append(f"{label}:{v}")
            if ma_bits:
                parts.append(' / '.join(ma_bits))

        wave_comment = _v1024_get(row, ['파동실행의견', 'wave_comment'])
        if wave_comment:
            parts.append(wave_comment)

        line = _v1024_join(parts, ' | ', 250)
        return f"📈 차트요약: {line}" if line else ''
    except Exception:
        return ''


def _v102_lines_from_row(row):
    """기존 row 변환에 매집봉/타점/차트 요약 재료를 추가한다."""
    try:
        lines = list(_V1024_BASE_LINES_FROM_ROW(row) or [])
    except Exception:
        lines = []
    try:
        d = _v102_to_dict(row or {})
        block = _v102_s(d.get('매집파동자리블록'))
        if block:
            for raw in block.splitlines():
                sx = _v102_s(raw)
                if sx and any(k in sx for k in ['매집봉', '세력흔적', '소파동', '중파동', '파란타점', '자리평가', '자리세부']):
                    lines.append(sx)
        acc = _v1024_accum_line(lines, row=d)
        if acc:
            lines.append(acc)
        entry = _v1024_entry_summary_line(lines, row=d)
        if entry:
            lines.append(entry)
        chart = _v1024_chart_summary_line(lines, row=d)
        if chart:
            lines.append(chart)
        # 원문 중복이 있더라도 후단 중복 제거가 처리한다.
        return lines
    except Exception:
        return lines


def _v102_compact_card(seg, row=None):
    try:
        lines = [str(x) for x in (seg or [])]
        if row is not None:
            try:
                lines = _v102_lines_from_row(row)
            except Exception:
                pass
        if not _v102_is_card(lines) and row is None:
            return lines
        decision = _v102_decide(lines)
        title = _v102_pick(lines, ['⭐ ']) or _v102_first_nonempty(lines)
        if not title or title.startswith('━━━━━━━━'):
            for x in lines:
                if _v102_numbered_stock(x):
                    title = _v102_s(x)
                    break
        name = _v102_clean_name(title)
        out = [name]
        out.append(f"✅ 최종판정(종합): {decision['label']}")
        out.append('📌 이유: ' + ' / '.join(decision['reasons'][:3]))
        struct = _v1022_structure_line(lines, row=row)
        if struct:
            out.append(struct)
        accum = _v1024_accum_line(lines, row=row)
        if accum:
            out.append(accum)
        entry = _v1024_entry_summary_line(lines, row=row, decision=decision)
        if entry:
            out.append(entry)
        chart = _v1024_chart_summary_line(lines, row=row)
        if chart:
            out.append(chart)
        out.append('🎯 실행조건: ' + _v102_trunc(decision['action'], 125))
        out.append('🧯 무효조건: ' + _v102_trunc(decision['invalid'], 120))
        out.append('💰 현재/눌림/손절/목표: ' + _v1022_price_line(lines, row=row))
        out.append('🏦 수급: ' + _v1022_supply_detail_line(lines, row=row))
        out.append('⚠️ 주의: ' + _v102_trunc(decision['caution'], 110))
        ref = _v102_reference_line(lines)
        if ref:
            out.append(ref)
        clean, seen = [], set()
        for x in out:
            k = _v102_n(x)
            if k and k not in seen:
                clean.append(x)
                seen.add(k)
        return clean
    except Exception:
        return list(seg or [])


def _v1021_classify_item(row):
    try:
        it = _V1024_BASE_CLASSIFY_ITEM(row)
    except Exception:
        it = {}
    try:
        lines = _v102_lines_from_row(row)
        it['accum'] = _v1024_accum_line(lines, row=row).replace('🕯️ 세력매집봉: ', '')
        it['entry'] = _v1024_entry_summary_line(lines, row=row).replace('📍 타점요약: ', '')
        it['chart'] = _v1024_chart_summary_line(lines, row=row).replace('📈 차트요약: ', '')
    except Exception:
        pass
    return it


def _v102_make_today_action_block(rows, base=''):
    """오늘 매매관점 압축: 위험사유 제외 원칙 유지 + 매집봉/타점/차트 핵심 복원."""
    try:
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1021_classify_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used:
                    continue
                used.add(key)
                is_risk, risk_reasons = _v1023_is_risk_item(r)
                if is_risk:
                    it['decision']['label'] = '추격 금지'
                    it['decision']['priority'] = 3
                    it['priority'] = 3
                    if risk_reasons:
                        it['reason'] = ' / '.join(_v102_dedupe_list(risk_reasons, 3))
                items.append(it)
            except Exception:
                continue
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5) if '_v1021_limit' in globals() else 5
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 15) if '_v1021_limit' in globals() else 15
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 5) if '_v1021_limit' in globals() else 5
        avoid_limit = max(0, _v1023_env_int('TODAY_ACTION_AVOID_LIMIT', 0))
        show_excluded = _v1023_show_excluded_risk()
        lines = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '🎯 [오늘 매매관점 압축]',
            '',
            f'📌 후보 수집: {total}개 | 관찰/눌림 표시 최대 {observe_limit}개',
            '📌 오늘 전략: 위험사유 종목은 제외하고, 조건부 실행/눌림 대기만 매매 후보로 확인',
            '📌 확인 순서: 세력매집봉 → 파란점선/5일선 지지 → 재양봉 → 거래량 재유입 → 수급 유지'
        ]
        groups = [('조건부 실행','🟢 조건부 실행',cond_limit),('눌림 대기','🟡 관찰/눌림 대기',observe_limit),('보유자 대응','🛡️ 보유자 대응',holder_limit)]
        shown_total = 0
        excluded = [x for x in items if x['decision']['label'] == '추격 금지']
        for label, title, max_show in groups:
            arr = [x for x in items if x['decision']['label'] == label]
            if not arr:
                continue
            lines.append('')
            suffix = f' ({min(len(arr), max_show)}/{len(arr)}개 표시)' if len(arr) > max_show else f' ({len(arr)}개)'
            lines.append(title + suffix)
            for i, it in enumerate(arr[:max_show], 1):
                code_part = f"({it['code']})" if it.get('code') else ''
                lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | 이유: {_v102_trunc(it.get('reason',''), 55)}")
                if it.get('accum'):
                    lines.append(f"   매집: {_v102_trunc(it['accum'], 85)}")
                if it.get('entry'):
                    lines.append(f"   타점: {_v102_trunc(it['entry'], 95)}")
                if it.get('chart'):
                    lines.append(f"   차트: {_v102_trunc(it['chart'], 95)}")
                elif it.get('struct'):
                    lines.append(f"   구조: {_v102_trunc(it['struct'], 95)}")
                if it.get('supply') and it.get('supply') != '수급 데이터 확인 필요':
                    lines.append(f"   수급: {_v102_trunc(it['supply'], 95)}")
                if label == '조건부 실행':
                    lines.append('   실행: 재양봉+거래량 재유입+파란점선/5일선 지지 중 2개 이상 확인')
                elif label == '눌림 대기':
                    lines.append('   관찰: 구름상단/5일선/파란점선 눌림 후 재지지 확인')
                elif label == '보유자 대응':
                    lines.append('   대응: 신규 추격보다 분할익절·이탈선 관리')
                shown_total += 1
        if excluded:
            lines.append('')
            lines.append(f'⛔ 제외/리스크 참고: {len(excluded)}개')
            if show_excluded and avoid_limit > 0:
                for i, it in enumerate(excluded[:avoid_limit], 1):
                    code_part = f"({it['code']})" if it.get('code') else ''
                    lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | 제외사유: {_v102_trunc(it.get('reason',''), 55)}")
                    if it.get('entry'):
                        lines.append(f"   회복기준: {_v102_trunc(it['entry'], 90)}")
            else:
                lines.append('   상세 숨김: SHOW_EXCLUDED_RISK=1 또는 TODAY_ACTION_AVOID_LIMIT>0이면 표시')
        if shown_total == 0:
            lines.append('')
            lines.append('- 조건부 실행/관찰 후보 없음. 오늘은 눌림 재지지 확인 우선')
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception:
        return str(base or '')


def _v102_action_first_text(text):
    try:
        msg = _V1024_BASE_ACTION_FIRST_TEXT(text)
        # 신규 요약 라인 중복/공백 정리
        msg = _v102_strip_debug_and_duplicates(msg)
        return msg
    except Exception:
        return str(text or '')

