def _v1025_env_int(name, default):
    try:
        return int(str(os.environ.get(name, default)).strip())
    except Exception:
        return default


def _v1025_to_df_safe(obj):
    try:
        if obj is None:
            return pd.DataFrame()
        if isinstance(obj, pd.DataFrame):
            return obj.copy()
        if isinstance(obj, list):
            return pd.DataFrame(obj)
        return pd.DataFrame(obj)
    except Exception:
        return pd.DataFrame()


def _v1025_row_code(row):
    try:
        d = _v102_to_dict(row or {})
        for k in ['code', 'Code', '종목코드', '티커', 'ticker']:
            v = _v102_s(d.get(k))
            if v:
                v = v.replace('.0', '').strip()
                if v.isdigit():
                    return v.zfill(6)
                return v
    except Exception:
        pass
    return ''


def _v1025_row_name(row):
    try:
        d = _v102_to_dict(row or {})
        for k in ['종목명', 'Name', 'name', '종목', 'StockName']:
            v = _v102_s(d.get(k))
            if v:
                return v.strip()
    except Exception:
        pass
    return ''


def _v1025_make_lookup(*frames):
    """ai_candidates/all_hits/df_clean/amount_top60 등을 code/name으로 찾기 위한 통합 lookup."""
    by_code, by_name = {}, {}
    try:
        # 앞에 전달된 프레임일수록 우선순위가 높다. ai_candidates → all_hits → df_clean 순서 권장.
        for frame in frames:
            df = _v1025_to_df_safe(frame)
            if df.empty:
                continue
            for _, row in df.iterrows():
                code = _v1025_row_code(row)
                name = _v1025_row_name(row)
                if code and code not in by_code:
                    by_code[code] = row
                if name:
                    nkey = _v102_n(name)
                    if nkey and nkey not in by_name:
                        by_name[nkey] = row
    except Exception:
        pass
    return by_code, by_name


def _v1025_krx_name_map(df_clean=None, amount_top60_df=None):
    by_code, by_name = {}, {}
    try:
        for frame in [df_clean, amount_top60_df]:
            df = _v1025_to_df_safe(frame)
            if df.empty:
                continue
            for _, row in df.iterrows():
                code = _v1025_row_code(row)
                name = _v1025_row_name(row)
                if code and name and code not in by_code:
                    by_code[code] = name
                if name and code:
                    by_name[_v102_n(name)] = code
    except Exception:
        pass
    return by_code, by_name


def _v1025_tokenize_names(raw):
    try:
        s = _v102_s(raw)
        if not s:
            return []
        s = s.replace('·', ',').replace('/', ',').replace('|', ',').replace('，', ',')
        out = []
        for x in s.split(','):
            x = x.strip()
            x = re.sub(r'^[\-•▶→\s]+', '', x)
            x = re.sub(r'\([^)]*\)', '', x).strip()
            if not x or len(x) > 30:
                continue
            if any(bad in x for bad in ['이유', '테마', '해석', '키워드', '체크', 'ETF', '시장']):
                continue
            out.append(x)
        return _v102_dedupe_list(out, 20)
    except Exception:
        return []


def _v1025_extract_theme_names_from_text(text):
    """뉴스/미국시장 연결 텍스트에서 대장주·후발주·연동주 이름을 추출."""
    buckets = []
    try:
        cur_theme = '시황연결'
        for raw in str(text or '').splitlines():
            line = raw.strip()
            if not line:
                continue
            m_theme = re.search(r'\[테마\]\s*([^\n]+)', line)
            if m_theme:
                cur_theme = m_theme.group(1).strip() or cur_theme
                continue
            m_issue = re.search(r'\[이슈\]\s*([^\n]+)', line)
            if m_issue:
                cur_theme = _v102_trunc(m_issue.group(1).strip(), 18) or cur_theme
                continue
            m = re.search(r'(?:대장주|후발주|연동주|관련주)\s*[:：]\s*(.+)$', line)
            if not m:
                continue
            role = '대장주' if '대장주' in line else ('후발주' if '후발주' in line else ('연동주' if '연동주' in line else '관련주'))
            names = _v1025_tokenize_names(m.group(1))
            if names:
                buckets.append({'theme': cur_theme, 'role': role, 'names': names})
    except Exception:
        pass
    return buckets


def _v1025_sector_buckets(sector_results, code_name_map=None):
    """섹터 순환 레이더의 관련주 코드를 테마별 분석 대상으로 변환."""
    out = []
    code_name_map = code_name_map or {}
    try:
        top_theme_limit = _v1025_env_int('MARKET_LEADER_THEME_LIMIT', 4)
        for s in list(sector_results or [])[:top_theme_limit]:
            verdict = _v102_s(s.get('verdict')) if isinstance(s, dict) else ''
            if verdict not in ('추천', '관찰'):
                continue
            codes = []
            for c in (s.get('tickers', []) if isinstance(s, dict) else []):
                sc = _v102_s(c).replace('.0', '').strip()
                if sc.isdigit():
                    sc = sc.zfill(6)
                if sc:
                    codes.append(sc)
            names = [code_name_map.get(c, c) for c in codes]
            if codes or names:
                out.append({
                    'theme': _v102_s(s.get('sector', '섹터')),
                    'role': '섹터 관련주',
                    'codes': codes,
                    'names': names,
                    'verdict': verdict,
                    'score': s.get('score', '') if isinstance(s, dict) else '',
                })
    except Exception:
        pass
    return out


def _v1025_find_row(name='', code='', by_code=None, by_name=None):
    by_code, by_name = by_code or {}, by_name or {}
    try:
        scode = _v102_s(code).replace('.0', '').strip()
        if scode.isdigit():
            scode = scode.zfill(6)
        if scode and scode in by_code:
            return by_code[scode]
        nkey = _v102_n(name)
        if nkey and nkey in by_name:
            return by_name[nkey]
        # 공백/보통주 표기 차이를 약하게 허용
        if nkey:
            for k, row in by_name.items():
                if k == nkey or k.replace('보통주','') == nkey.replace('보통주',''):
                    return row
    except Exception:
        pass
    return None


def _v1025_analyze_leader_row(row, theme='', role='', fallback_name='', fallback_code=''):
    """시황 대장주 1개를 V102.4 카드 재료로 짧게 재판정."""
    try:
        if row is None:
            name = fallback_name or fallback_code or '종목명 확인 필요'
            code = fallback_code or ''
            code_part = f'({code})' if code else ''
            return {
                'name': name, 'code': code, 'label': '스캔 미포함', 'priority': 8,
                'line1': f'{name}{code_part} | {role} | 정밀 스캔 후보 미포함',
                'line2': '   → 오늘 Stock-Hunter 조건은 약하거나, 상장 직접 종목 확인이 필요합니다.',
                'risk': False,
            }
        lines = _v102_lines_from_row(row)
        decision = _v102_decide(lines)
        try:
            is_risk, risk_reasons = _v1023_is_risk_item(row)
        except Exception:
            is_risk, risk_reasons = (decision.get('label') == '추격 금지'), []
        if is_risk:
            decision['label'] = '추격 금지'
            if risk_reasons:
                decision['reasons'] = _v102_dedupe_list(risk_reasons, 3)
        code = _v1025_row_code(row)
        name = _v1025_row_name(row) or fallback_name or code
        cur = _v1024_fmt_price(_v1024_get(row, ['현재가','Close','Price','종가'])) or '-'
        accum = _v1024_accum_line(lines, row=row).replace('🕯️ 세력매집봉: ', '')
        entry = _v1024_entry_summary_line(lines, row=row, decision=decision).replace('📍 타점요약: ', '')
        chart = _v1024_chart_summary_line(lines, row=row).replace('📈 차트요약: ', '')
        supply = _v1022_supply_detail_line(lines, row=row) if '_v1022_supply_detail_line' in globals() else ''
        reason = ' / '.join((decision.get('reasons') or [])[:3])
        code_part = f'({code})' if code else ''
        label = decision.get('label','확인 필요')
        pmap = {'조건부 실행':0, '눌림 대기':1, '보유자 대응':2, '추격 금지':3}
        return {
            'name': name, 'code': code, 'label': label, 'priority': pmap.get(label, 7),
            'line1': f'{name}{code_part} | 현재 {cur} | {role} | 최종판정: {label}',
            'line2': f'   이유: {_v102_trunc(reason, 70)}' if reason else '',
            'accum': f'   매집: {_v102_trunc(accum, 85)}' if accum else '',
            'entry': f'   타점: {_v102_trunc(entry, 95)}' if entry else '',
            'chart': f'   차트: {_v102_trunc(chart, 95)}' if chart else '',
            'supply': f'   수급: {_v102_trunc(supply, 95)}' if supply and supply != '수급 데이터 확인 필요' else '',
            'risk': bool(is_risk or label == '추격 금지'),
        }
    except Exception as e:
        name = fallback_name or fallback_code or '종목'
        return {
            'name': name, 'code': fallback_code or '', 'label': '분석 실패', 'priority': 9,
            'line1': f'{name} | {role} | 분석 실패',
            'line2': f'   → {str(e)[:80]}',
            'risk': False,
        }


def _v1025_build_market_leader_analysis_block(
    sector_results=None,
    news_theme_text='',
    us_mapping_text='',
    ai_candidates=None,
    all_hits_df=None,
    amount_top60_df=None,
    df_clean=None,
):
    """시황이 뽑은 대장주/관련주를 실제 후보 데이터와 연결해 간단 분석 블록 생성."""
    try:
        if str(os.environ.get('SHOW_MARKET_LEADER_ANALYSIS', '1')).strip().lower() in ('0','false','no','off'):
            return ''
        code_name_map, name_code_map = _v1025_krx_name_map(df_clean=df_clean, amount_top60_df=amount_top60_df)
        by_code, by_name = _v1025_make_lookup(ai_candidates, all_hits_df, amount_top60_df, df_clean)
        buckets = []
        buckets.extend(_v1025_sector_buckets(sector_results, code_name_map=code_name_map))
        buckets.extend(_v1025_extract_theme_names_from_text(news_theme_text))
        buckets.extend(_v1025_extract_theme_names_from_text(us_mapping_text))
        if not buckets:
            return ''
        per_theme = _v1025_env_int('MARKET_LEADER_PER_THEME_LIMIT', 4)
        max_total = _v1025_env_int('MARKET_LEADER_TOTAL_LIMIT', 14)
        show_missing = str(os.environ.get('SHOW_MARKET_LEADER_MISSING', '0')).strip().lower() in ('1','true','yes','on')
        lines = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '👑 [시황 대장주 매매 분석]',
            '',
            '📌 기준: 섹터/뉴스/미국시장 연결에서 언급된 대장주를 Stock-Hunter 신호로 재판정',
            '📌 해석: 테마가 좋아도 최종판정이 추격 금지면 실행 후보에서 제외',
        ]
        seen = set()
        shown = 0
        excluded_count = 0
        missing_count = 0
        for b in buckets:
            if shown >= max_total:
                break
            theme = _v102_s(b.get('theme','시황'))
            role = _v102_s(b.get('role','대장주'))
            codes = list(b.get('codes') or [])
            names = list(b.get('names') or [])
            # code bucket이면 code 우선, text bucket이면 name 우선
            pairs = []
            if codes:
                for c in codes:
                    pairs.append((code_name_map.get(c, c), c))
            for n in names:
                code = name_code_map.get(_v102_n(n), '')
                pairs.append((n, code))
            theme_rows = []
            theme_seen = set()
            for name, code in pairs:
                if len(theme_rows) >= per_theme or shown + len(theme_rows) >= max_total:
                    break
                key = code or _v102_n(name)
                if not key or key in seen or key in theme_seen:
                    continue
                theme_seen.add(key)
                row = _v1025_find_row(name=name, code=code, by_code=by_code, by_name=by_name)
                if row is None and not show_missing:
                    missing_count += 1
                    continue
                analyzed = _v1025_analyze_leader_row(row, theme=theme, role=role, fallback_name=name, fallback_code=code)
                if analyzed.get('risk'):
                    excluded_count += 1
                theme_rows.append(analyzed)
                seen.add(key)
            if not theme_rows:
                continue
            verdict_extra = ''
            if b.get('verdict'):
                score = b.get('score')
                verdict_extra = f" | {b.get('verdict')}" + (f" {float(score):.1f}" if isinstance(score, (int,float)) else '')
            lines.append('')
            lines.append(f'[{theme}] {role}{verdict_extra}')
            # 같은 테마 내에서는 실행 가능성이 높은 순서로 표시
            theme_rows = sorted(theme_rows, key=lambda x: (x.get('priority', 9), x.get('name','')))
            for i, a in enumerate(theme_rows, 1):
                lines.append(f"{i}) {a.get('line1','')}")
                for k in ['line2','accum','entry','chart','supply']:
                    v = a.get(k, '')
                    if v:
                        lines.append(v)
                shown += 1
                if shown >= max_total:
                    break
        if shown == 0:
            return ''
        if excluded_count or missing_count:
            lines.append('')
            tail = []
            if excluded_count:
                tail.append(f'위험사유 제외 {excluded_count}개')
            if missing_count:
                tail.append(f'스캔 미포함 숨김 {missing_count}개')
            lines.append('📎 참고: ' + ' | '.join(tail))
            if missing_count:
                lines.append('   스캔 미포함 종목까지 보려면 SHOW_MARKET_LEADER_MISSING=1')
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception as e:
        try:
            return f'👑 [시황 대장주 매매 분석 실패]\n{str(e)[:160]}'
        except Exception:
            return ''

