def _v1026_env_bool(name, default=False):
    try:
        val = str(os.environ.get(name, '1' if default else '0')).strip().lower()
        return val in ('1', 'true', 'yes', 'on', 'y')
    except Exception:
        return default


def _v1026_join(parts, sep=' / ', limit=180):
    out, seen = [], set()
    for p in parts or []:
        s = _v102_s(p)
        if not s or s in ('-', 'nan', 'None'):
            continue
        s = re.sub(r'\s+', ' ', s).strip()
        k = _v102_n(s)
        if k in seen:
            continue
        out.append(s)
        seen.add(k)
    txt = sep.join(out)
    return _v102_trunc(txt, limit)


def _v1026_get(row, keys, default=''):
    try:
        d = _v102_to_dict(row or {})
        for k in keys:
            v = d.get(k)
            if _v102_s(v):
                return v
    except Exception:
        pass
    return default


def _v1026_find_line(lines, words, last=False):
    arr = []
    for x in lines or []:
        s = _v102_s(x)
        if not s:
            continue
        if any(w in s for w in words):
            arr.append(s)
    if not arr:
        return ''
    return arr[-1] if last else arr[0]


def _v1026_price(x):
    try:
        return _v1024_fmt_price(x) if '_v1024_fmt_price' in globals() else _v102_int_price(x)
    except Exception:
        return _v102_int_price(x)


def _v1026_extract_num(pat, txt, default=None):
    try:
        m = re.search(pat, str(txt or ''))
        if not m:
            return default
        return float(str(m.group(1)).replace(',', ''))
    except Exception:
        return default


def _v1026_real_risk(lines=None, row=None):
    """실제 제외 사유만 판단한다. '신규 실행 제외' 같은 생성 문구만으로는 제외하지 않는다."""
    lines = list(lines or [])
    try:
        if row is not None:
            lines += list(_v102_lines_from_row(row) or [])
    except Exception:
        pass
    txt = '\n'.join([_v102_s(x) for x in lines])
    reasons = []

    if 'UTAD' in txt or '실패돌파' in txt:
        reasons.append('UTAD/실패돌파')
    if '가짜수박주의' in txt or '가짜/정제주의' in txt:
        reasons.append('가짜수박주의')
    if '후행수박' in txt or '후행형' in txt:
        reasons.append('후행형')
    if '파란점선 아래' in txt or re.search(r'파란점선.*아래', txt):
        reasons.append('파란점선 아래')
    if any(k in txt for k in ['수급 역방향', '동반 매도', '동반매도', '개인추격주의']):
        reasons.append('수급 역방향')

    disp = _v1026_extract_num(r'이격:?\s*([0-9]+(?:\.[0-9]+)?)', txt)
    rsi = _v1026_extract_num(r'RSI:?\s*([0-9]+(?:\.[0-9]+)?)', txt)
    over = _v1026_extract_num(r'최적눌림구간보다\s*([0-9]+(?:\.[0-9]+)?)%\s*위', txt)
    if disp is not None and disp >= float(os.environ.get('RISK_DISPARITY_LIMIT', '115')):
        reasons.append(f'이격 과열 {disp:.0f}')
    if rsi is not None and rsi >= float(os.environ.get('RISK_RSI_LIMIT', '70')):
        reasons.append(f'RSI 과열 {rsi:.0f}')
    if over is not None and over >= float(os.environ.get('RISK_OPTIMAL_GAP_LIMIT', '15')):
        reasons.append(f'눌림권 +{over:.1f}%')

    reasons = _v102_dedupe_list(reasons, 4)
    return bool(reasons), reasons


def _v1026_decide(lines, row=None):
    try:
        dec = dict(_v102_decide(lines) or {})
    except Exception:
        dec = {'label': '눌림 대기', 'reasons': ['타점 재확인 필요'], 'action': '', 'invalid': '', 'caution': ''}
    real_risk, risk_reasons = _v1026_real_risk(lines, row=row)
    if real_risk:
        dec['label'] = '추격 금지'
        dec['emoji'] = '⛔'
        dec['priority'] = 3
        dec['reasons'] = _v102_dedupe_list(risk_reasons, 3)
        dec['action'] = '신규 매수 제외. 위험 신호가 사라지고 파란점선·5일선 회복 후 다시 봅니다.'
        dec['invalid'] = _v1026_invalid_text(dec, lines, row=row)
        dec['caution'] = '제외는 관심종목 삭제가 아니라, 오늘 신규 실행 후보에서 빼는 의미입니다.'
    elif dec.get('label') == '추격 금지':
        # 기존 생성 문구 때문에 추격 금지가 된 경우는 눌림 대기로 완화
        dec['label'] = '눌림 대기'
        dec['emoji'] = '🟡'
        dec['priority'] = 1
        rs = [r for r in (dec.get('reasons') or []) if r not in ('신규 실행 제외', '타점 확인', '구조 확인')]
        dec['reasons'] = _v102_dedupe_list(rs + ['타점 재확인', '눌림 확인'], 3)
        dec['action'] = '바로 추격하지 말고 5일선·파란점선 눌림 후 재양봉과 거래량 재유입을 확인합니다.'
        dec['invalid'] = '눌림 자리에서 5일선·파란점선 회복 실패 또는 거래량 동반 음봉이면 제외'
        dec['caution'] = '구조가 좋아도 타점이 맞지 않으면 기다리는 종목입니다.'
    else:
        dec['invalid'] = _v1026_invalid_text(dec, lines, row=row)
        if dec.get('label') == '조건부 실행':
            dec['action'] = '재양봉, 거래량 재유입, 파란점선·5일선 지지 중 2개 이상 확인 후 분할 접근합니다.'
            dec['caution'] = '확인 없이 먼저 들어가지 않는 것이 핵심입니다.'
        elif dec.get('label') == '눌림 대기':
            dec['action'] = '첫 눌림이 올 때 5일선·파란점선·구름상단 지지 여부를 확인합니다.'
            dec['caution'] = '현재가가 높으면 좋은 종목이어도 추격하지 않습니다.'
        elif dec.get('label') == '보유자 대응':
            dec['action'] = '신규 진입보다 보유자는 이탈선 관리와 분할익절이 우선입니다.'
            dec['caution'] = '이미 한 박자 진행된 자리는 신규 매수 기준을 낮추면 안 됩니다.'
    dec['reasons'] = _v102_dedupe_list(dec.get('reasons') or ['타점 재확인'], 3)
    return dec


def _v1026_invalid_text(dec, lines=None, row=None):
    txt = '\n'.join([_v102_s(x) for x in (lines or [])])
    label = _v102_s((dec or {}).get('label'))
    if '가짜수박주의' in txt or 'UTAD' in txt or '실패돌파' in txt:
        return '가짜수박/실패돌파 신호가 남아 있거나 전고점 재돌파에 실패하면 제외 유지'
    if '파란점선 아래' in txt or re.search(r'파란점선.*아래', txt):
        return '파란점선 아래 종가가 이어지거나 5일선 회복에 실패하면 제외 유지'
    if '수급 역방향' in txt or '동반매도' in txt:
        return '외인·기관 매도 우위가 이어지면 신규 매수 제외'
    if label == '조건부 실행':
        return '파란점선 또는 당일 저점 이탈 시 관점 폐기'
    if label == '눌림 대기':
        return '눌림 자리에서 5일선·파란점선·구름상단 회복 실패 시 제외'
    if label == '보유자 대응':
        return '5일선·파란점선·구름상단 이탈 시 비중 축소'
    return '회복 조건 확인 전 신규 매수 제외'


def _v1026_pattern_line(lines=None, row=None):
    lines = list(lines or [])
    d = _v102_to_dict(row or {})
    parts = []
    for k in ['검색패턴', '기법', '전략명', 'N조합', 'N구분', '추천단계', '수박최종상태', '단계상태', '구조판정', '저항구름태그', '수박정제태그']:
        v = _v102_s(d.get(k))
        if v:
            if k == '단계상태':
                v = v.replace('PASS_A', 'PASS_A 매집→응축→돌파준비').replace('PASS_B', 'PASS_B 돌파준비 관찰')
            parts.append(v)
    for line in lines:
        s = _v102_s(line)
        if not s:
            continue
        if s.startswith('🎯 ') and len(s) > 2:
            parts.append(s.replace('🎯', '').strip())
        elif s.startswith('🏷️ '):
            parts.append(s.replace('🏷️', '').strip())
        elif s.startswith('🪜 유형:'):
            parts.append(s.replace('🪜 유형:', '유형:').strip())
        elif '구조판정:' in s:
            parts.append(s.split('구조판정:',1)[-1].strip())
        elif '최종상태:' in s:
            parts.append(s.split('최종상태:',1)[-1].strip())
    text = _v1026_join(parts, ' / ', 160)
    return f'🔎 검색패턴: {text}' if text else ''


def _v1026_easy_line(name, dec, lines=None, row=None):
    label = _v102_s(dec.get('label'))
    reasons = ' / '.join((dec.get('reasons') or [])[:3])
    txt = '\n'.join([_v102_s(x) for x in (lines or [])])
    subject = _v102_s(name).strip('[]') or '이 종목'
    if label == '조건부 실행':
        body = f'{subject}은 구조와 타점이 맞아가는 후보입니다. 다만 확인매수 자리라서 {dec.get("action")}.'
    elif label == '눌림 대기':
        if '위확장' in txt or '상단권' in txt:
            body = f'{subject}은 이미 위로 한 번 움직인 자리입니다. 흐름은 좋지만 지금 바로 따라가기보다 첫 눌림에서 지지가 확인되는지 보는 종목입니다.'
        else:
            body = f'{subject}은 구조는 살아 있지만 아직 실행 신호가 부족합니다. 5일선·파란점선에서 다시 버티는지 확인하는 대기 후보입니다.'
    elif label == '보유자 대응':
        body = f'{subject}은 신규 진입보다 이미 보유한 사람의 관리가 우선인 자리입니다. 이탈선과 분할익절 기준을 먼저 봅니다.'
    else:
        body = f'{subject}은 오늘 신규 실행 후보에서 제외합니다. 이유는 {reasons or "위험 신호"}이며, 회복 조건이 나오기 전까지는 관찰만 합니다.'
    return '🧭 쉬운해설: ' + _v102_trunc(body, 210)


def _v1026_accum_line(lines=None, row=None):
    d = _v102_to_dict(row or {})
    parts = []
    tag = _v1026_get(d, ['매집봉태그', '세력매집봉태그', '매집강도등급'])
    score = _v1026_get(d, ['매집봉점수', '세력흔적점수', '매집점수'])
    days = _v1026_get(d, ['매집일수_10일', '매집일수'])
    ratio = _v1026_get(d, ['매집거래량배율', '거래량배율'])
    avg = _v1026_price(_v1026_get(d, ['세력평단_60일', '세력평단', '평단']))
    gap = _v1026_get(d, ['평단이격', '세력평단이격'])
    comment = _v1026_get(d, ['매집봉코멘트', '세력흔적코멘트'])
    if tag:
        parts.append(str(tag))
    if score not in ('', None):
        parts.append(f'{score}점')
    if days not in ('', None) or ratio not in ('', None):
        seg = '최근 매집'
        if days not in ('', None, ''):
            seg += f' {days}일'
        if ratio not in ('', None, ''):
            seg += f'({ratio}배)'
        parts.append(seg)
    if avg and avg != '-':
        seg = f'평단 {avg}원'
        if gap not in ('', None):
            try:
                seg += f' / 이격 {float(gap):+.1f}%'
            except Exception:
                seg += f' / 이격 {gap}'
        parts.append(seg)
    if comment:
        parts.append(comment)
    if not parts:
        raw = _v1024_accum_line(lines or [], row=row).replace('🕯️ 세력매집봉: ', '') if '_v1024_accum_line' in globals() else ''
        raw = raw.replace(' | ', ' / ')
        if raw:
            parts.append(raw)
    text = _v1026_join(parts, ' / ', 155)
    return f'🕯️ 세력매집봉: {text}' if text else '🕯️ 세력매집봉: 뚜렷한 매집봉 정보는 약함'


def _v1026_entry_line(lines=None, row=None, dec=None):
    lines = list(lines or [])
    d = _v102_to_dict(row or {})
    dec = dec or _v1026_decide(lines, row=row)
    label = dec.get('label')
    cur = _v1026_price(_v1026_get(d, ['현재가', 'Close', 'Price', '종가']))
    blue = _v1026_get(d, ['파란점선상태', '파란점선판정', 'blue_state'])
    blue_price = _v1026_price(_v1026_get(d, ['파란점선', '파란점선가격', 'blue_line']))
    low = _v1026_price(_v1026_get(d, ['파동최적하단', '최적눌림하단', 'best_zone_low', '눌림하단']))
    high = _v1026_price(_v1026_get(d, ['파동최적상단', '최적눌림상단', 'best_zone_high', '눌림상단']))
    if not blue:
        raw = _v1026_find_line(lines, ['파란점선'], last=True)
        blue = '아래' if '아래' in raw else ('위확장' if '위확장' in raw else ('위안착' if '위안착' in raw else ('접촉' if '접촉' in raw else '')))
        if blue_price == '-':
            m = re.search(r'([0-9][0-9,]{2,})', raw or '')
            if m:
                blue_price = m.group(1)
    zone = ''
    if low != '-' and high != '-':
        zone = f'눌림권 {low}~{high}'
    if label == '조건부 실행':
        guide = '재양봉·거래량 재유입·파란점선 지지 중 2개가 맞으면 분할 접근'
    elif label == '눌림 대기':
        guide = '지금은 기다렸다가 눌림 후 재지지 확인'
    elif label == '보유자 대응':
        guide = '신규보다 이탈선 관리와 분할익절 우선'
    else:
        guide = '오늘 신규 진입 제외, 회복 신호가 먼저 필요'
    parts = []
    if cur != '-':
        parts.append(f'현재 {cur}')
    if blue:
        parts.append(f'파란점선 {blue}' + (f'({blue_price})' if blue_price != '-' else ''))
    if zone:
        parts.append(zone)
    parts.append(guide)
    return '📍 타점요약: ' + _v1026_join(parts, ' / ', 180)


def _v1026_chart_line(lines=None, row=None):
    lines = list(lines or [])
    d = _v102_to_dict(row or {})
    raw = ''
    try:
        raw = _v1024_chart_summary_line(lines, row=row).replace('📈 차트요약: ', '')
    except Exception:
        raw = ''
    txt = raw + ' ' + '\n'.join(lines) + ' ' + ' '.join([_v102_s(v) for v in d.values()])
    parts = []
    if '삼각수렴' in txt or '🔺' in txt:
        parts.append('삼각수렴/수렴형')
    if '저항전' in txt:
        parts.append('저항구름 아래에서 선취 관찰')
    elif '저항테스트' in txt:
        parts.append('저항구름 테스트 중')
    elif '저항돌파' in txt or '저항구름 돌파' in txt:
        parts.append('저항구름 돌파 후 눌림 확인')
    if '소파동 상단' in txt:
        parts.append('소파동은 상단권이라 추격 부담')
    elif '소파동 중상단' in txt:
        parts.append('소파동은 중상단')
    elif '소파동 하단' in txt:
        parts.append('소파동은 하단권 반등 확인')
    if '중파동 상단' in txt:
        parts.append('중파동은 상단권 저항 체크')
    elif '중파동 하단' in txt:
        parts.append('중파동은 하단권 반등 체크')
    ma_bits = []
    for label, keys in [('초', ['초단기MA수렴도']), ('단', ['단기MA수렴도']), ('구', ['구조MA수렴도']), ('BB40', ['BB40', 'BB40폭'])]:
        v = _v1026_get(d, keys)
        if _v102_s(v):
            try:
                ma_bits.append(f'{label}:{float(v):.1f}')
            except Exception:
                ma_bits.append(f'{label}:{v}')
    if ma_bits:
        parts.append('수렴 ' + '/'.join(ma_bits))
    if not parts and raw:
        parts.append(raw)
    return '📈 차트요약: ' + _v1026_join(parts, ' / ', 175) if parts else ''


def _v1026_supply_line(lines=None, row=None):
    try:
        supply = _v1022_supply_detail_line(lines or [], row=row) if '_v1022_supply_detail_line' in globals() else ''
    except Exception:
        supply = ''
    if not supply or supply == '수급 데이터 확인 필요':
        d = _v102_to_dict(row or {})
        supply = _v1026_join([d.get('수급판정'), d.get('수급요약'), d.get('수급5일누적'), d.get('수급3일누적')], ' | ', 170)
    if not supply:
        supply = '수급 데이터 확인 필요'
    return '🏦 수급: ' + _v102_trunc(supply, 185)


def _v1026_price_line(lines=None, row=None):
    try:
        d = _v102_to_dict(row or {})
        cur = _v1026_price(_v1026_get(d, ['현재가','Close','Price','종가']))
        low = _v1026_price(_v1026_get(d, ['파동최적하단','최적눌림하단','best_zone_low','눌림하단']))
        high = _v1026_price(_v1026_get(d, ['파동최적상단','최적눌림상단','best_zone_high','눌림상단']))
        stop = _v1026_price(_v1026_get(d, ['🚨손절가','손절가','stop','무효가격']))
        t1 = _v1026_price(_v1026_get(d, ['🎯목표타점','목표1','target','목표가']))
        t2 = _v1026_price(_v1026_get(d, ['🎯목표2차','목표2','target2']))
        zone = f'{low}~{high}' if low != '-' and high != '-' else '-'
        target = t1 if t1 != '-' else '-'
        if t2 != '-' and t2 != t1:
            target += f' → {t2}'
        if cur != '-' or zone != '-' or stop != '-' or target != '-':
            return f'💰 가격: 현재 {cur} / 눌림 {zone} / 손절 {stop} / 목표 {target}'
    except Exception:
        pass
    try:
        return '💰 가격: ' + _v102_trunc(_v1022_price_line(lines or [], row=row), 150)
    except Exception:
        return '💰 가격: 현재/눌림/손절/목표 확인 필요'


def _v1026_compact_card(seg, row=None):
    try:
        lines = [str(x) for x in (seg or []) if str(x).strip()]
        if row is not None:
            try:
                lines = _v102_lines_from_row(row)
            except Exception:
                pass
        title = _v102_pick(lines, ['⭐ ']) or _v102_first_nonempty(lines)
        if not title or title.startswith('━━━━━━━━'):
            for x in lines:
                if _v102_numbered_stock(x):
                    title = _v102_s(x)
                    break
        name = _v102_clean_name(title)
        dec = _v1026_decide(lines, row=row)
        label = dec.get('label', '눌림 대기')
        badge = '⛔ 제외판정' if label == '추격 금지' else '✅ 최종판정(종합)'
        out = [name]
        out.append(f'{badge}: {label}')
        pat = _v1026_pattern_line(lines, row=row)
        if pat:
            out.append(pat)
        out.append(_v1026_easy_line(name, dec, lines, row=row))
        out.append('📌 핵심근거: ' + ' / '.join((dec.get('reasons') or [])[:3]))
        out.append(_v1026_accum_line(lines, row=row))
        out.append(_v1026_entry_line(lines, row=row, dec=dec))
        chart = _v1026_chart_line(lines, row=row)
        if chart:
            out.append(chart)
        out.append(_v1026_supply_line(lines, row=row))
        out.append(_v1026_price_line(lines, row=row))
        out.append('🧯 무효/보류: ' + _v102_trunc(dec.get('invalid'), 130))
        out.append('⚠️ 주의: ' + _v102_trunc(dec.get('caution'), 120))
        clean, seen = [], set()
        for x in out:
            s = _v102_s(x)
            if not s:
                continue
            k = _v102_n(s)
            if k in seen:
                continue
            seen.add(k)
            clean.append(s)
        return clean
    except Exception:
        try:
            return _V1026_BASE_COMPACT_CARD(seg, row=row) if '_V1026_BASE_COMPACT_CARD' in globals() and _V1026_BASE_COMPACT_CARD else list(seg or [])
        except Exception:
            return list(seg or [])


try:
    _V1026_BASE_COMPACT_CARD = _v102_compact_card
except Exception:
    _V1026_BASE_COMPACT_CARD = None
_v102_compact_card = _v1026_compact_card


def _v1026_rows_from_frames(*args, **kwargs):
    try:
        rows = _v102_rows_from_frames(*args, **kwargs)
        return rows or []
    except Exception:
        return []


def _v1026_item(row):
    d = _v102_to_dict(row or {})
    lines = _v102_lines_from_row(d)
    dec = _v1026_decide(lines, row=d)
    name, code = _v102_code_name(d)
    cur = _v1026_price(_v1026_get(d, ['현재가','Close','Price','종가']))
    return {
        'name': name,
        'code': code,
        'cur': cur,
        'decision': dec,
        'label': dec.get('label'),
        'priority': dec.get('priority', 9),
        'score': _v102_num(d.get('N점수') or d.get('안전점수') or d.get('score'), 0),
        'pattern': _v1026_pattern_line(lines, row=d).replace('🔎 검색패턴: ', ''),
        'easy': _v1026_easy_line(name, dec, lines, row=d).replace('🧭 쉬운해설: ', ''),
        'accum': _v1026_accum_line(lines, row=d).replace('🕯️ 세력매집봉: ', ''),
        'entry': _v1026_entry_line(lines, row=d, dec=dec).replace('📍 타점요약: ', ''),
        'chart': _v1026_chart_line(lines, row=d).replace('📈 차트요약: ', ''),
        'supply': _v1026_supply_line(lines, row=d).replace('🏦 수급: ', ''),
        'price': _v1026_price_line(lines, row=d).replace('💰 가격: ', ''),
    }


def _v102_make_today_action_block(rows, base=''):
    """V102.6: 오늘 매매관점 압축을 자연어 + 검색패턴 + 핵심 실전정보로 재구성."""
    try:
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1026_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used:
                    continue
                used.add(key)
                items.append(it)
            except Exception:
                continue
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5) if '_v1021_limit' in globals() else 5
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 10) if '_v1021_limit' in globals() else 10
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 4) if '_v1021_limit' in globals() else 4
        avoid_limit = max(0, _v1023_env_int('TODAY_ACTION_AVOID_LIMIT', 0)) if '_v1023_env_int' in globals() else 0
        show_excluded = _v1026_env_bool('SHOW_EXCLUDED_RISK', False)
        groups = [
            ('조건부 실행','🟢 조건부 실행',cond_limit),
            ('눌림 대기','🟡 관찰/눌림 대기',observe_limit),
            ('보유자 대응','🛡️ 보유자 대응',holder_limit),
        ]
        lines = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '🎯 [오늘 매매관점 압축]',
            '',
            f'📌 후보 수집: {total}개',
            '📌 오늘 전략: 위험사유 종목은 제외하고, 조건부 실행/눌림 대기만 실제 매매 후보로 확인',
            '📌 보는 순서: 검색패턴 → 쉬운해설 → 세력매집봉 → 타점 → 차트 → 수급',
        ]
        shown_total = 0
        for label, title, limit in groups:
            arr = [x for x in items if x.get('label') == label]
            if not arr:
                continue
            lines.append('')
            suffix = f' ({min(len(arr), limit)}/{len(arr)}개 표시)' if len(arr) > limit else f' ({len(arr)}개)'
            lines.append(title + suffix)
            for i, it in enumerate(arr[:limit], 1):
                code_part = f"({it['code']})" if it.get('code') else ''
                lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | {it['label']}")
                if it.get('pattern'):
                    lines.append(f"   검색: {_v102_trunc(it['pattern'], 80)}")
                if it.get('easy'):
                    lines.append(f"   해설: {_v102_trunc(it['easy'], 115)}")
                if it.get('accum'):
                    lines.append(f"   매집: {_v102_trunc(it['accum'], 80)}")
                if it.get('entry'):
                    lines.append(f"   타점: {_v102_trunc(it['entry'], 95)}")
                if it.get('chart'):
                    lines.append(f"   차트: {_v102_trunc(it['chart'], 95)}")
                if it.get('supply') and it.get('supply') != '수급 데이터 확인 필요':
                    lines.append(f"   수급: {_v102_trunc(it['supply'], 95)}")
                shown_total += 1
        excluded = [x for x in items if x.get('label') == '추격 금지']
        if excluded:
            lines.append('')
            lines.append(f'⛔ 제외/리스크 참고: {len(excluded)}개')
            if show_excluded and avoid_limit > 0:
                for i, it in enumerate(excluded[:avoid_limit], 1):
                    code_part = f"({it['code']})" if it.get('code') else ''
                    reasons = ' / '.join((it.get('decision') or {}).get('reasons') or [])
                    lines.append(f"{i}) {it['name']}{code_part} | 제외사유: {_v102_trunc(reasons, 70)}")
                    lines.append(f"   회복조건: {_v102_trunc((it.get('decision') or {}).get('invalid'), 90)}")
            else:
                lines.append('   상세는 기본 숨김입니다. 필요하면 SHOW_EXCLUDED_RISK=1, TODAY_ACTION_AVOID_LIMIT=5')
        if shown_total == 0:
            lines.append('')
            lines.append('- 조건부 실행/관찰 후보 없음. 오늘은 시황 대장주와 눌림 재지지 확인 우선')
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception:
        return str(base or '')


def _v1026_alias_code(name):
    aliases = {
        '삼성전자':'005930','SK하이닉스':'000660','SK hynix':'000660','sk hynix':'000660',
        '한미반도체':'042700','주성엔지니어링':'036930','테크윙':'089030','이수페타시스':'007660','하나마이크론':'067310','리노공업':'058470','DB하이텍':'000990',
        'S-Oil':'010950','에쓰오일':'010950','SK이노베이션':'096770','흥구석유':'024060','중앙에너비스':'000440','한국석유':'004090','대성에너지':'117580','흥아해운':'003280','STX그린로지스':'465770',
        'HD한국조선해양':'009540','삼성중공업':'010140','HMM':'011200','한화오션':'042660','HD현대중공업':'329180',
        'KB금융':'105560','신한지주':'055550','하나금융지주':'086790',
        'LG에너지솔루션':'373220','LG화학':'051910','삼성SDI':'006400',
        '한화에어로스페이스':'012450','한국항공우주':'047810','현대로템':'064350',
        '포스코인터내셔널':'047050','대한항공':'003490'
    }
    return aliases.get(_v102_s(name), '')


def _v1026_analyze_leader_row(row, theme='', role='', fallback_name='', fallback_code=''):
    try:
        if row is None:
            name = _v102_s(fallback_name or fallback_code or '종목명 확인 필요')
            code = _v102_s(fallback_code or _v1026_alias_code(name))
            cp = f'({code})' if code else ''
            return {
                'name': name, 'code': code, 'priority': 6, 'label': '정밀스캔 미포함', 'risk': False,
                'lines': [
                    f'{name}{cp} | {role} | 정밀스캔 미포함',
                    f'   해설: 시황상 {theme} 관심주지만 오늘 Stock-Hunter 정밀 후보에는 잡히지 않았습니다.',
                    '   체크: 거래대금 유입, 5일선 위 재양봉, 파란점선/저항구름 위치를 별도 확인하세요.',
                ]
            }
        d = _v102_to_dict(row)
        lines = _v102_lines_from_row(d)
        dec = _v1026_decide(lines, row=d)
        name = _v1025_row_name(d) if '_v1025_row_name' in globals() else _v102_code_name(d)[0]
        code = _v1025_row_code(d) if '_v1025_row_code' in globals() else _v102_code_name(d)[1]
        cur = _v1026_price(_v1026_get(d, ['현재가','Close','Price','종가']))
        risk = dec.get('label') == '추격 금지'
        out = [f'{name}({code}) | 현재 {cur} | {role} | 최종판정: {dec.get("label")}']
        pat = _v1026_pattern_line(lines, row=d).replace('🔎 검색패턴: ', '')
        if pat:
            out.append(f'   검색: {_v102_trunc(pat, 85)}')
        out.append(f'   해설: {_v102_trunc(_v1026_easy_line(name, dec, lines, row=d).replace("🧭 쉬운해설: ", ""), 120)}')
        out.append(f'   타점: {_v102_trunc(_v1026_entry_line(lines, row=d, dec=dec).replace("📍 타점요약: ", ""), 95)}')
        chart = _v1026_chart_line(lines, row=d).replace('📈 차트요약: ', '')
        if chart:
            out.append(f'   차트: {_v102_trunc(chart, 95)}')
        supply = _v1026_supply_line(lines, row=d).replace('🏦 수급: ', '')
        if supply and supply != '수급 데이터 확인 필요':
            out.append(f'   수급: {_v102_trunc(supply, 95)}')
        return {'name': name, 'code': code, 'priority': dec.get('priority', 9), 'label': dec.get('label'), 'risk': risk, 'lines': out}
    except Exception as e:
        name = _v102_s(fallback_name or fallback_code or '종목')
        return {'name': name, 'code': fallback_code or '', 'priority': 9, 'label': '분석 실패', 'risk': False, 'lines': [f'{name} | {role} | 분석 실패: {str(e)[:80]}']}


def _v1025_build_market_leader_analysis_block(sector_results=None, news_theme_text='', us_mapping_text='', ai_candidates=None, all_hits_df=None, amount_top60_df=None, df_clean=None):
    """V102.6: 시황 대장주 분석을 기본 노출하고, 스캔 미포함도 체크리스트로 표시."""
    try:
        if not _v1026_env_bool('SHOW_MARKET_LEADER_ANALYSIS', True):
            return ''
        code_name_map, name_code_map = _v1025_krx_name_map(df_clean=df_clean, amount_top60_df=amount_top60_df) if '_v1025_krx_name_map' in globals() else ({},{})
        by_code, by_name = _v1025_make_lookup(ai_candidates, all_hits_df, amount_top60_df, df_clean) if '_v1025_make_lookup' in globals() else ({},{})
        buckets = []
        if '_v1025_sector_buckets' in globals():
            buckets.extend(_v1025_sector_buckets(sector_results, code_name_map=code_name_map))
        if '_v1025_extract_theme_names_from_text' in globals():
            buckets.extend(_v1025_extract_theme_names_from_text(news_theme_text))
            buckets.extend(_v1025_extract_theme_names_from_text(us_mapping_text))
        if not buckets:
            return ''
        per_theme = _v1025_env_int('MARKET_LEADER_PER_THEME_LIMIT', 4) if '_v1025_env_int' in globals() else 4
        max_total = _v1025_env_int('MARKET_LEADER_TOTAL_LIMIT', 16) if '_v1025_env_int' in globals() else 16
        show_missing = _v1026_env_bool('SHOW_MARKET_LEADER_MISSING', True)
        lines = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '👑 [시황 대장주 매매 분석]',
            '',
            '📌 기준: 시황에서 언급된 대장주·후발주·연동주를 Stock-Hunter 신호로 다시 판정',
            '📌 원칙: 테마가 좋아도 차트/수급/타점이 안 맞으면 실행 후보에서 제외',
        ]
        seen, shown, excluded, missing = set(), 0, 0, 0
        for b in buckets:
            if shown >= max_total:
                break
            theme = _v102_s(b.get('theme','시황'))
            role = _v102_s(b.get('role','대장주'))
            pairs = []
            for c in list(b.get('codes') or []):
                sc = _v102_s(c).replace('.0','').strip()
                if sc.isdigit():
                    sc = sc.zfill(6)
                pairs.append((code_name_map.get(sc, sc), sc))
            for n in list(b.get('names') or []):
                code = name_code_map.get(_v102_n(n), '') or _v1026_alias_code(n)
                pairs.append((n, code))
            if not pairs:
                continue
            theme_rows, theme_seen = [], set()
            for name, code in pairs:
                if len(theme_rows) >= per_theme or shown + len(theme_rows) >= max_total:
                    break
                key = code or _v102_n(name)
                if not key or key in seen or key in theme_seen:
                    continue
                theme_seen.add(key)
                row = _v1025_find_row(name=name, code=code, by_code=by_code, by_name=by_name) if '_v1025_find_row' in globals() else None
                if row is None:
                    missing += 1
                    if not show_missing:
                        continue
                a = _v1026_analyze_leader_row(row, theme=theme, role=role, fallback_name=name, fallback_code=code)
                if a.get('risk'):
                    excluded += 1
                theme_rows.append(a)
                seen.add(key)
            if not theme_rows:
                continue
            verdict_extra = ''
            if b.get('verdict'):
                score = b.get('score')
                verdict_extra = f" | {b.get('verdict')}" + (f" {float(score):.1f}" if isinstance(score, (int,float)) else '')
            lines.append('')
            lines.append(f'[{theme}] {role}{verdict_extra}')
            theme_rows = sorted(theme_rows, key=lambda x: (x.get('priority', 9), x.get('name','')))
            for i, a in enumerate(theme_rows, 1):
                lines.append(f'{i}) ' + (a.get('lines') or [''])[0])
                for extra in (a.get('lines') or [])[1:]:
                    lines.append(extra)
                shown += 1
                if shown >= max_total:
                    break
        if shown == 0:
            return ''
        tail = []
        if excluded:
            tail.append(f'위험사유 판정 {excluded}개')
        if missing:
            tail.append(f'정밀스캔 미포함 {missing}개')
        if tail:
            lines.append('')
            lines.append('📎 참고: ' + ' | '.join(tail))
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception as e:
        return f'👑 [시황 대장주 매매 분석 실패]\n{str(e)[:160]}'


try:
    _V1026_BASE_ACTION_FIRST_TEXT = _v102_action_first_text
except Exception:
    _V1026_BASE_ACTION_FIRST_TEXT = None


def _v102_action_first_text(text):
    """V102.6: 카드 자연어화 + 관찰 섹션의 위험카드 기본 숨김."""
    try:
        if not _v102_readable_enabled():
            return str(text or '')
        b = str(text or '')
        if not b.strip():
            return b
        hot = ['👀 [오늘의 관찰형 참고]', '🛡️ [오늘의 후행형 참고]', '🍉 [초입수박 TOP', '🍉 [눌림수박 TOP',
               '🧭 [선취 제외 후보', '🚀 [흰구름 돌파 후보', '🚀 [흰구름 돌파 관찰', '⭐ ', '🔵 파란점선:', '📦 와이코프:', '🌊 파동', '👑 [시황 대장주']
        if not any(h in b for h in hot):
            return _v102_strip_debug_and_duplicates(b)
        lines = b.splitlines()
        segs, cur = [], []
        for line in lines:
            if cur and _v102_segment_start(line):
                segs.append(cur)
                cur = [line]
            else:
                cur.append(line)
        if cur:
            segs.append(cur)
        cleaned = []
        skipped_risk = 0
        current_heading = ''
        hide_risk_watch = not _v1026_env_bool('SHOW_RISK_CARDS_IN_WATCH', False)
        for seg in segs:
            first = _v102_first_nonempty(seg)
            if '[' in first and ']' in first and not _v102_is_card(seg):
                current_heading = first
            if _v102_is_card(seg):
                dec = _v1026_decide(seg)
                if hide_risk_watch and dec.get('label') == '추격 금지' and any(k in current_heading for k in ['관찰형', '초입수박', '눌림수박', '돌파 관찰', '선취 관찰']) and not any(k in current_heading for k in ['제외', '후행']):
                    skipped_risk += 1
                    continue
                if cleaned and cleaned[-1].strip():
                    cleaned.append('')
                cleaned.extend(_v1026_compact_card(seg))
            else:
                cleaned.extend(seg)
        if skipped_risk:
            cleaned.append('')
            cleaned.append(f'⛔ 위험사유 카드 {skipped_risk}개는 실행/관찰 섹션에서 숨겼습니다. 필요하면 SHOW_RISK_CARDS_IN_WATCH=1')
        return _v102_strip_debug_and_duplicates('\n'.join(cleaned))
    except Exception:
        return str(text or '')

