def _v1027_code_from_any(row=None, lines=None, title=''):
    try:
        d = _v102_to_dict(row or {})
        for k in ['code', 'Code', '종목코드', '티커', 'ticker']:
            v = _v102_s(d.get(k)).replace('.0', '').strip()
            if v:
                return v.zfill(6) if v.isdigit() else v
    except Exception:
        pass
    blob = '\n'.join([_v102_s(title)] + [_v102_s(x) for x in (lines or [])])
    m = re.search(r'\(([0-9A-Z]{6})\)', blob)
    if m:
        v = m.group(1)
        return v.zfill(6) if v.isdigit() else v
    return ''


def _v1027_name_from_any(row=None, lines=None, title=''):
    try:
        d = _v102_to_dict(row or {})
        for k in ['종목명', 'Name', 'name', '종목', 'StockName']:
            v = _v102_s(d.get(k)).strip()
            if v:
                return v
    except Exception:
        pass
    try:
        nm = _v102_clean_name(title or _v102_first_nonempty(lines or []))
        nm = re.sub(r'^\[|\]$', '', _v102_s(nm)).strip()
        return nm or '종목명 확인'
    except Exception:
        return '종목명 확인'


def _v1027_title(row=None, lines=None, title=''):
    name = _v1027_name_from_any(row=row, lines=lines, title=title)
    code = _v1027_code_from_any(row=row, lines=lines, title=title)
    return f'[{name}]({code})' if code else f'[{name}]'


def _v1027_display_label(dec, lines=None, row=None):
    """내부 분류는 유지하고, 사용자에게 보이는 최종판정만 행동형으로 바꾼다."""
    label = _v102_s((dec or {}).get('label'))
    txt = '\n'.join([_v102_s(x) for x in (lines or [])])
    try:
        if row is not None:
            txt += '\n' + ' '.join([_v102_s(v) for v in _v102_to_dict(row).values()])
    except Exception:
        pass
    if label == '조건부 실행':
        if '파란점선' in txt:
            return '5일선·파란점선 지지 확인 후 진입'
        return '5일선 눌림/지지 확인 후 진입'
    if label == '눌림 대기':
        if '위확장' in txt or '상단권' in txt:
            return '5일선 눌림 확인 후 대기'
        return '5일선·파란점선 재지지 확인 대기'
    if label == '보유자 대응':
        return '보유자 이탈선 관리'
    if label == '추격 금지':
        return '신규 진입 금지'
    return label or '5일선 기준 재확인'


def _v1027_get_num_price(row, keys):
    try:
        v = _v1026_get(row, keys)
        if _v102_s(v):
            return v
    except Exception:
        pass
    return ''


def _v1027_blue_line_info(lines=None, row=None):
    lines = list(lines or [])
    d = _v102_to_dict(row or {})
    raw = _v1026_find_line(lines, ['파란점선'], last=True) if '_v1026_find_line' in globals() else ''
    blue_val = _v1027_get_num_price(d, ['파란점선기준가', '파란점선', '파란점선가격', 'blue_line_price', 'blue_line'])
    if not _v102_s(blue_val) and raw:
        m = re.search(r'파란점선[^0-9]*([0-9][0-9,]{2,})', raw)
        if not m:
            m = re.search(r'([0-9][0-9,]{2,})', raw)
        if m:
            blue_val = m.group(1)
    blue_price = _v1026_price(blue_val) if '_v1026_price' in globals() else _v102_s(blue_val)

    cur_val = _v1027_get_num_price(d, ['현재가', 'Close', 'Price', '종가'])
    cur = _v1026_price(cur_val) if '_v1026_price' in globals() else _v102_s(cur_val)
    ma5_val = _v1027_get_num_price(d, ['MA5', 'ma5', '5일선', '이평5', 'MA_5'])
    ma5 = _v1026_price(ma5_val) if '_v1026_price' in globals() else _v102_s(ma5_val)
    state = _v102_s(_v1026_get(d, ['파란점선상태', '파란점선판정', 'blue_state']))
    if not state and raw:
        if '아래' in raw: state = '아래'
        elif '위확장' in raw: state = '위확장'
        elif '위안착' in raw: state = '위안착'
        elif '접촉' in raw: state = '접촉'
    gap = _v102_s(_v1026_get(d, ['파란점선이격', 'blue_line_gap_pct']))
    if not gap and raw:
        m = re.search(r'이격\s*([+\-]?[0-9]+(?:\.[0-9]+)?)%', raw)
        if m:
            gap = m.group(1)
    try:
        gap_txt = f'{float(str(gap).replace("%", "")):+.1f}%'
    except Exception:
        gap_txt = _v102_s(gap)
    if not gap_txt and cur != '-' and blue_price != '-':
        try:
            cv = float(str(cur_val).replace(',', ''))
            bv = float(str(blue_val).replace(',', ''))
            if bv:
                gap_txt = f'{(cv / bv - 1) * 100:+.1f}%'
        except Exception:
            pass

    if blue_price == '-' or not blue_price:
        base = '🔵 파란점선 기준: 산출불가 | 소파동/중파동 박스 먼저 확인'
    else:
        bits = [f'기준가 {blue_price}원']
        if cur != '-': bits.append(f'현재 {cur}원')
        if gap_txt: bits.append(f'이격 {gap_txt}')
        if state: bits.append(f'상태 {state}')
        if ma5 != '-': bits.append(f'5일선 {ma5}원')
        base = '🔵 파란점선 기준: ' + ' | '.join(bits)

    # 실제 기준 해설
    if state in ('아래', '이탈'):
        judge = '판단: 현재는 기준선 아래라서 종가 회복 전까지 신규 진입 보류'
    elif state in ('접촉', '위안착'):
        judge = '판단: 기준선 접촉/안착 구간이므로 5일선 지지와 재양봉 확인이 핵심'
    elif state == '위확장':
        judge = '판단: 기준선 위로 확장된 자리라서 추격보다 5일선 눌림 재지지 확인'
    else:
        judge = '판단: 기준가와 5일선 기준으로 지지/이탈을 함께 확인'
    return base + ' | ' + judge


def _v1027_entry_line(lines=None, row=None, dec=None):
    lines = list(lines or [])
    d = _v102_to_dict(row or {})
    dec = dec or _v1026_decide(lines, row=row)
    disp = _v1027_display_label(dec, lines=lines, row=row)
    blue = _v1027_blue_line_info(lines=lines, row=d)
    low = _v1026_price(_v1026_get(d, ['파동최적하단', '최적눌림하단', 'best_zone_low', '눌림하단']))
    high = _v1026_price(_v1026_get(d, ['파동최적상단', '최적눌림상단', 'best_zone_high', '눌림상단']))
    zone = f'눌림권 {low}~{high}원' if low != '-' and high != '-' else ''
    if dec.get('label') == '조건부 실행':
        guide = '실행: 5일선 또는 파란점선 지지 + 재양봉 + 거래량 재유입 중 2개 이상 확인 후 분할 진입'
    elif dec.get('label') == '눌림 대기':
        guide = '실행: 지금 추격하지 말고 5일선 눌림에서 재지지 확인 후 검토'
    elif dec.get('label') == '보유자 대응':
        guide = '실행: 신규 진입보다 5일선/파란점선 이탈선 관리 우선'
    else:
        guide = '실행: 오늘 신규 진입 금지. 기준가 회복과 위험사유 해소 후 재검토'
    parts = [disp, blue, zone, guide]
    return '📍 타점요약: ' + _v1026_join(parts, ' / ', 300)


def _v1027_supply_line(lines=None, row=None):
    """최근5일 → 최근3일 → 최근1일 순으로 보여준다."""
    try:
        raw = _v1022_supply_detail_line(lines or [], row=row) if '_v1022_supply_detail_line' in globals() else ''
    except Exception:
        raw = ''
    if not raw:
        try:
            raw = _v1026_supply_line(lines or [], row=row).replace('🏦 수급: ', '')
        except Exception:
            raw = ''
    d = _v102_to_dict(row or {})
    blob = ' | '.join([_v102_s(raw)] + [_v102_s(x) for x in (lines or [])] + [_v102_s(v) for v in d.values()])
    # 판정 문구
    verdict = ''
    m = re.search(r'(최근\s*5일\s*기준[^|\n]+)', blob)
    if m:
        verdict = m.group(1).strip()
    if not verdict:
        verdict = _v1026_join([d.get('수급판정'), d.get('수급요약')], ' | ', 80)
    # 기간별 세그먼트 추출
    def pick(day):
        pats = [
            rf'([💵📦🧲]?\s*최근\s*{day}일[^|\n]*(?:개인[^|\n]*)?(?:외인[^|\n]*)?(?:기관[^|\n]*)?)',
            rf'({day}일[^|\n]*(?:개인[^|\n]*)?(?:외인[^|\n]*)?(?:기관[^|\n]*)?)',
        ]
        for pat in pats:
            ms = re.findall(pat, blob)
            for s in ms:
                s = re.sub(r'\s+', ' ', _v102_s(s)).strip(' |')
                if '개인' in s or '외인' in s or '기관' in s:
                    return s
        # row direct fallbacks
        for k in [f'최근{day}일수급', f'수급{day}일', f'수급{day}일누적']:
            v = _v102_s(d.get(k))
            if v: return v
        return ''
    seg5, seg3, seg1 = pick(5), pick(3), pick(1)
    parts = []
    if verdict: parts.append('판정: ' + verdict)
    if seg5: parts.append('🧲 ' + re.sub(r'^[💵📦🧲]\s*', '', seg5))
    if seg3: parts.append('📦 ' + re.sub(r'^[💵📦🧲]\s*', '', seg3))
    if seg1: parts.append('💵 ' + re.sub(r'^[💵📦🧲]\s*', '', seg1))
    if not parts:
        parts.append('수급 데이터 확인 필요')
    return '🏦 수급: ' + _v1026_join(parts, ' | ', 260)


def _v1027_easy_line(name, dec, lines=None, row=None):
    subject = re.sub(r'^\[|\].*$', '', _v102_s(name)).strip() or '이 종목'
    label = _v102_s((dec or {}).get('label'))
    display = _v1027_display_label(dec, lines=lines, row=row)
    blue_txt = _v1027_blue_line_info(lines=lines, row=row)
    if label == '조건부 실행':
        body = f'{subject}은 바로 추격하는 종목이 아니라 {display}하는 종목입니다. 파란점선 기준가와 5일선 부근에서 가격이 버티고, 재양봉과 거래량 재유입이 같이 나와야 합니다.'
    elif label == '눌림 대기':
        body = f'{subject}은 구조는 살아 있지만 아직 타점 확인이 남았습니다. 5일선 쪽으로 눌릴 때 파란점선 기준가를 지키는지 확인하는 대기 후보입니다.'
    elif label == '보유자 대응':
        body = f'{subject}은 신규 진입보다 보유자의 이탈선 관리가 우선입니다. 5일선이나 파란점선이 깨지면 비중을 줄이는 쪽으로 봅니다.'
    elif label == '추격 금지':
        body = f'{subject}은 오늘 신규 진입 금지입니다. 파란점선 기준가를 회복하거나 위험사유가 사라지기 전까지는 실행 후보가 아닙니다.'
    else:
        body = f'{subject}은 5일선과 파란점선 기준으로 타점을 다시 확인해야 합니다.'
    return '🧭 쉬운해설: ' + _v102_trunc(body, 240)


def _v1027_compact_card(seg, row=None):
    try:
        lines = [str(x) for x in (seg or []) if str(x).strip()]
        if row is not None:
            try:
                lines = _v102_lines_from_row(row)
            except Exception:
                pass
        title = _v102_pick(lines, ['⭐ ']) or _v102_first_nonempty(lines)
        if not title or title.startswith('━━━━━━━━'):
            for x in lines:
                if _v102_numbered_stock(x):
                    title = _v102_s(x)
                    break
        name_title = _v1027_title(row=row, lines=lines, title=title)
        dec = _v1026_decide(lines, row=row)
        label = dec.get('label', '눌림 대기')
        display_label = _v1027_display_label(dec, lines=lines, row=row)
        badge = '⛔ 제외판정' if label == '추격 금지' else '✅ 최종판정'
        out = [name_title]
        out.append(f'{badge}: {display_label}')
        pat = _v1026_pattern_line(lines, row=row)
        if pat:
            out.append(pat)
        out.append(_v1027_easy_line(name_title, dec, lines, row=row))
        out.append('📌 핵심근거: ' + ' / '.join((dec.get('reasons') or [])[:3]))
        out.append(_v1026_accum_line(lines, row=row))
        out.append(_v1027_entry_line(lines, row=row, dec=dec))
        chart = _v1026_chart_line(lines, row=row)
        if chart:
            out.append(chart)
        out.append(_v1027_supply_line(lines, row=row))
        out.append(_v1026_price_line(lines, row=row))
        out.append('🧯 무효/보류: ' + _v102_trunc(dec.get('invalid'), 140))
        out.append('⚠️ 주의: ' + _v102_trunc(dec.get('caution'), 120))
        clean, seen = [], set()
        for x in out:
            s = _v102_s(x)
            if not s:
                continue
            k = _v102_n(s)
            if k in seen:
                continue
            seen.add(k)
            clean.append(s)
        return clean
    except Exception:
        return _v1026_compact_card(seg, row=row) if '_v1026_compact_card' in globals() else list(seg or [])


# override 카드 생성기
_v102_compact_card = _v1027_compact_card


def _v1026_item(row):
    d = _v102_to_dict(row or {})
    lines = _v102_lines_from_row(d)
    dec = _v1026_decide(lines, row=d)
    name, code = _v102_code_name(d)
    if not code:
        code = _v1027_code_from_any(row=d, lines=lines)
    cur = _v1026_price(_v1026_get(d, ['현재가','Close','Price','종가']))
    return {
        'name': name,
        'code': code,
        'cur': cur,
        'decision': dec,
        'label': dec.get('label'),
        'display_label': _v1027_display_label(dec, lines=lines, row=d),
        'priority': dec.get('priority', 9),
        'score': _v102_num(d.get('N점수') or d.get('안전점수') or d.get('score'), 0),
        'pattern': _v1026_pattern_line(lines, row=d).replace('🔎 검색패턴: ', ''),
        'easy': _v1027_easy_line(name, dec, lines, row=d).replace('🧭 쉬운해설: ', ''),
        'accum': _v1026_accum_line(lines, row=d).replace('🕯️ 세력매집봉: ', ''),
        'entry': _v1027_entry_line(lines, row=d, dec=dec).replace('📍 타점요약: ', ''),
        'blue': _v1027_blue_line_info(lines=lines, row=d).replace('🔵 파란점선 기준: ', ''),
        'chart': _v1026_chart_line(lines, row=d).replace('📈 차트요약: ', ''),
        'supply': _v1027_supply_line(lines, row=d).replace('🏦 수급: ', ''),
        'price': _v1026_price_line(lines, row=d).replace('💰 가격: ', ''),
    }


def _v102_make_today_action_block(rows, base=''):
    """V102.7: 오늘 매매관점 압축에도 행동형 최종판정/파란점선 기준/수급 5·3·1 순서 반영."""
    try:
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1026_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used:
                    continue
                used.add(key)
                items.append(it)
            except Exception:
                continue
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5) if '_v1021_limit' in globals() else 5
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 10) if '_v1021_limit' in globals() else 10
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 4) if '_v1021_limit' in globals() else 4
        avoid_limit = max(0, _v1023_env_int('TODAY_ACTION_AVOID_LIMIT', 0)) if '_v1023_env_int' in globals() else 0
        show_excluded = _v1026_env_bool('SHOW_EXCLUDED_RISK', False)
        groups = [
            ('조건부 실행','🟢 5일선·파란점선 지지 확인 후 진입',cond_limit),
            ('눌림 대기','🟡 5일선 눌림/재지지 대기',observe_limit),
            ('보유자 대응','🛡️ 보유자 이탈선 관리',holder_limit),
        ]
        lines = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '🎯 [오늘 매매관점 압축]',
            '',
            f'📌 후보 수집: {total}개',
            '📌 오늘 전략: 최종판정은 행동 기준으로 표시합니다. 조건부 실행은 5일선·파란점선 지지 확인 후 진입으로 봅니다.',
            '📌 보는 순서: 검색패턴 → 파란점선 기준가 → 5일선 지지 → 세력매집봉 → 수급 5/3/1일',
        ]
        shown_total = 0
        for label, title, limit in groups:
            arr = [x for x in items if x.get('label') == label]
            if not arr:
                continue
            lines.append('')
            suffix = f' ({min(len(arr), limit)}/{len(arr)}개 표시)' if len(arr) > limit else f' ({len(arr)}개)'
            lines.append(title + suffix)
            for i, it in enumerate(arr[:limit], 1):
                code_part = f"({it['code']})" if it.get('code') else ''
                lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | {it.get('display_label') or it['label']}")
                if it.get('pattern'):
                    lines.append(f"   검색: {_v102_trunc(it['pattern'], 78)}")
                if it.get('blue'):
                    lines.append(f"   파란점선: {_v102_trunc(it['blue'], 105)}")
                if it.get('easy'):
                    lines.append(f"   해설: {_v102_trunc(it['easy'], 120)}")
                if it.get('accum'):
                    lines.append(f"   매집: {_v102_trunc(it['accum'], 75)}")
                if it.get('supply') and it.get('supply') != '수급 데이터 확인 필요':
                    lines.append(f"   수급: {_v102_trunc(it['supply'], 120)}")
                shown_total += 1
        excluded = [x for x in items if x.get('label') == '추격 금지']
        if excluded:
            lines.append('')
            lines.append(f'⛔ 제외/리스크 참고: {len(excluded)}개')
            if show_excluded and avoid_limit > 0:
                for i, it in enumerate(excluded[:avoid_limit], 1):
                    code_part = f"({it['code']})" if it.get('code') else ''
                    reasons = ' / '.join((it.get('decision') or {}).get('reasons') or [])
                    lines.append(f"{i}) {it['name']}{code_part} | 제외사유: {_v102_trunc(reasons, 70)}")
                    if it.get('blue'):
                        lines.append(f"   파란점선: {_v102_trunc(it['blue'], 95)}")
            else:
                lines.append('   상세는 기본 숨김입니다. 필요하면 SHOW_EXCLUDED_RISK=1, TODAY_ACTION_AVOID_LIMIT=5')
        if shown_total == 0:
            lines.append('')
            lines.append('- 실행/관찰 후보 없음. 오늘은 시황 대장주와 5일선 눌림 재지지 확인 우선')
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception:
        return str(base or '')


def _v1026_analyze_leader_row(row, theme='', role='', fallback_name='', fallback_code=''):
    """V102.7: 시황 대장주 분석에도 종목코드/행동형 판정/파란점선 기준가를 표시."""
    try:
        if row is None:
            name = _v102_s(fallback_name or fallback_code or '종목명 확인 필요')
            code = _v102_s(fallback_code or _v1026_alias_code(name))
            cp = f'({code})' if code else ''
            return {
                'name': name, 'code': code, 'priority': 6, 'label': '정밀스캔 미포함', 'risk': False,
                'lines': [
                    f'{name}{cp} | {role} | 정밀스캔 미포함',
                    f'   해설: 시황상 {theme} 관심주지만 오늘 Stock-Hunter 정밀 후보에는 잡히지 않았습니다.',
                    '   체크: 거래대금 유입, 5일선 위 재양봉, 파란점선 기준가/저항구름 위치를 별도 확인하세요.',
                ]
            }
        d = _v102_to_dict(row)
        lines = _v102_lines_from_row(d)
        dec = _v1026_decide(lines, row=d)
        name = _v1025_row_name(d) if '_v1025_row_name' in globals() else _v102_code_name(d)[0]
        code = _v1025_row_code(d) if '_v1025_row_code' in globals() else _v102_code_name(d)[1]
        cur = _v1026_price(_v1026_get(d, ['현재가','Close','Price','종가']))
        risk = dec.get('label') == '추격 금지'
        display = _v1027_display_label(dec, lines=lines, row=d)
        out = [f'{name}({code}) | 현재 {cur} | {role} | 최종판정: {display}']
        pat = _v1026_pattern_line(lines, row=d).replace('🔎 검색패턴: ', '')
        if pat:
            out.append(f'   검색: {_v102_trunc(pat, 85)}')
        out.append(f'   해설: {_v102_trunc(_v1027_easy_line(name, dec, lines, row=d).replace("🧭 쉬운해설: ", ""), 120)}')
        out.append(f'   파란점선: {_v102_trunc(_v1027_blue_line_info(lines=lines, row=d).replace("🔵 파란점선 기준: ", ""), 105)}')
        out.append(f'   타점: {_v102_trunc(_v1027_entry_line(lines, row=d, dec=dec).replace("📍 타점요약: ", ""), 105)}')
        chart = _v1026_chart_line(lines, row=d).replace('📈 차트요약: ', '')
        if chart:
            out.append(f'   차트: {_v102_trunc(chart, 95)}')
        supply = _v1027_supply_line(lines, row=d).replace('🏦 수급: ', '')
        if supply and supply != '수급 데이터 확인 필요':
            out.append(f'   수급: {_v102_trunc(supply, 115)}')
        return {'name': name, 'code': code, 'priority': dec.get('priority', 9), 'label': dec.get('label'), 'risk': risk, 'lines': out}
    except Exception as e:
        name = _v102_s(fallback_name or fallback_code or '종목')
        return {'name': name, 'code': fallback_code or '', 'priority': 9, 'label': '분석 실패', 'risk': False, 'lines': [f'{name} | {role} | 분석 실패: {str(e)[:80]}']}

