# =============================================================
# ✅ TRADE_CLARITY_V10_2_8_POWER_KI_PATTERN_CONTEXT_ACTIVE
# - 전고점 이후 세력매집봉 흔적 복원
# - 끼점수/흡수점수/파동각도 등 종목의 끼 복원
# - BB20/10 하단 복귀형, 섹터 주도주/연동주 성격 해석 추가
# - 검색패턴/종목성격/시황대장주 분석을 자연어 카드로 정리
# =============================================================
print("✅ TRADE_CLARITY_V10_2_8_POWER_KI_PATTERN_CONTEXT_ACTIVE LOADED")


def _v1028_dict(row=None):
    try:
        if row is None:
            return {}
        return _v102_to_dict(row)
    except Exception:
        try:
            return dict(row)
        except Exception:
            return {}


def _v1028_blob(lines=None, row=None):
    d = _v1028_dict(row)
    vals = []
    try:
        vals.extend([_v102_s(x) for x in (lines or [])])
    except Exception:
        pass
    try:
        vals.extend([f'{_v102_s(k)}:{_v102_s(v)}' for k, v in d.items()])
    except Exception:
        pass
    return ' | '.join([x for x in vals if x])


def _v1028_get(row, keys, default=''):
    d = _v1028_dict(row)
    try:
        v = _v1026_get(d, keys)
        if _v102_s(v):
            return v
    except Exception:
        pass
    for k in keys:
        if k in d and _v102_s(d.get(k)):
            return d.get(k)
    return default


def _v1028_price(v):
    try:
        return _v1026_price(v)
    except Exception:
        s = _v102_s(v)
        try:
            return f'{float(s.replace(",", "")):,.0f}'
        except Exception:
            return s or '-'


def _v1028_num(v, default=None):
    try:
        if v is None:
            return default
        s = str(v).replace(',', '').replace('%', '').strip()
        if s in ('', '-', 'nan', 'None'):
            return default
        return float(s)
    except Exception:
        return default


def _v1028_find_any_line(lines, keywords):
    try:
        return _v1026_find_line(lines or [], keywords, last=False)
    except Exception:
        for x in lines or []:
            s = _v102_s(x)
            if all(k in s for k in keywords):
                return s
    return ''


def _v1028_search_pattern_line(lines=None, row=None):
    """종목이 어떤 검색/패턴으로 잡혔는지 한 줄로 정리."""
    d = _v1028_dict(row)
    blob = _v1028_blob(lines, d)
    parts = []
    key_groups = [
        ['검색패턴', '검색식', '검색분류', '스캔분류', '후보군', '유형', '패턴명'],
        ['최종상태', '수박상태', 'watermelon_state', '상태'],
        ['단계', 'stage', 'PASS', '시퀀스'],
        ['N조합', 'N구분', 'N패턴', 'combo', 'n_combo'],
        ['구조판정', '저항구름상태', '저항구름', '정제', '정제수박'],
    ]
    for keys in key_groups:
        v = _v1028_get(d, keys)
        if _v102_s(v):
            parts.append(_v102_s(v))
    # 텍스트 안에서 직접 감지되는 패턴
    detects = [
        ('BB20/10 하단 복귀형', ['BB20', 'BB10', '하단', '복귀']),
        ('BB20 하단 복귀형', ['BB20', '하단', '복귀']),
        ('BB10 하단 복귀형', ['BB10', '하단', '복귀']),
        ('엔벨로프 하단 반등형', ['엔벨로프', '하단']),
        ('삼각수렴', ['삼각수렴']),
        ('구조수렴', ['구조수렴']),
        ('저항구름 돌파형', ['저항구름', '돌파']),
        ('선취형', ['선취']),
        ('눌림수박', ['눌림수박']),
        ('초입수박', ['초입수박']),
        ('Blue-2 스윙', ['Blue-2']),
        ('세력매집봉', ['세력매집봉']),
    ]
    for label, kws in detects:
        if all(k in blob for k in kws):
            parts.append(label)
    # 중복 제거
    clean = []
    seen = set()
    for p in parts:
        s = re.sub(r'\s+', ' ', _v102_s(p)).strip(' |-/')
        if not s or s in seen or s.lower() == 'nan':
            continue
        seen.add(s)
        clean.append(s)
    if not clean:
        clean.append('검색패턴 확인 필요')
    return '🔎 검색패턴: ' + _v102_trunc(' / '.join(clean[:6]), 180)


def _v1028_character_line(lines=None, row=None, theme='', role=''):
    """BB하단 복귀형/섹터 주도주/연동주/테마형 등 종목 성격을 자연어로 표시."""
    d = _v1028_dict(row)
    blob = _v1028_blob(lines, d) + ' | ' + _v102_s(theme) + ' | ' + _v102_s(role)
    traits = []
    if ('BB20' in blob and 'BB10' in blob and '하단' in blob and ('복귀' in blob or '회복' in blob)):
        traits.append('BB20/10 하단 복귀형')
    elif ('BB20' in blob and '하단' in blob and ('복귀' in blob or '회복' in blob)):
        traits.append('BB20 하단 복귀형')
    elif ('BB10' in blob and '하단' in blob and ('복귀' in blob or '회복' in blob)):
        traits.append('BB10 하단 복귀형')
    if '엔벨로프' in blob and '하단' in blob:
        traits.append('엔벨로프 하단 반등형')
    if '삼각수렴' in blob or '구조수렴' in blob:
        traits.append('수렴 후 방향성 확인형')
    if any(x in blob for x in ['대장주', '주도주', '섹터대장', '섹터 주도']) or '대장' in _v102_s(role):
        traits.append('섹터 주도주 성격')
    elif any(x in blob for x in ['후발주', '연동주']) or any(x in _v102_s(role) for x in ['후발', '연동']):
        traits.append('섹터 후발/연동주 성격')
    if any(x in blob for x in ['뉴스', '테마', '재료']):
        traits.append('뉴스·테마 민감형')
    if any(x in blob for x in ['거래대금', '상위', '수급']):
        traits.append('거래대금·수급 확인형')
    # 섹터명 추출
    sector = _v102_s(_v1028_get(d, ['섹터', '테마', 'theme', 'sector', '관련섹터', '주도섹터'])) or _v102_s(theme)
    if sector and sector not in ('-', 'nan'):
        sector = _v102_trunc(sector, 30)
        traits.append(f'관심섹터: {sector}')
    clean = []
    for t in traits:
        if t and t not in clean:
            clean.append(t)
    if not clean:
        clean = ['패턴 성격은 차트·수급 재확인 필요']
    return '🧩 종목성격: ' + _v102_trunc(' / '.join(clean[:5]), 170)


def _v1028_ki_line(lines=None, row=None):
    """끼점수/흡수점수/파동각도점수 등 종목의 탄력·흥행성 복원."""
    d = _v1028_dict(row)
    blob = _v1028_blob(lines, d)
    ki = _v1028_get(d, ['끼점수', '끼', '끼_score', 'theme_power_score', '흥행점수', '급등끼점수'])
    absorb = _v1028_get(d, ['흡수점수', 'absorb_score', '매집흡수점수', '수급흡수점수'])
    angle = _v1028_get(d, ['파동각도점수', '각도점수', 'wave_angle_score', '파동각도'])
    comment = _v1028_get(d, ['끼코멘트', '끼해석', '흥행코멘트', '테마성코멘트'])
    if not _v102_s(ki):
        m = re.search(r'끼(?:점수)?\s*[:=]?\s*([0-9]+(?:\.[0-9]+)?)', blob)
        if m:
            ki = m.group(1)
    if not _v102_s(absorb):
        m = re.search(r'흡수(?:점수)?\s*[:=]?\s*([0-9]+(?:\.[0-9]+)?)', blob)
        if m:
            absorb = m.group(1)
    if not _v102_s(angle):
        m = re.search(r'각도(?:점수)?\s*[:=]?\s*([+\-]?[0-9]+(?:\.[0-9]+)?)', blob)
        if m:
            angle = m.group(1)
    parts = []
    if _v102_s(ki): parts.append(f'끼 {_v102_s(ki)}')
    if _v102_s(absorb): parts.append(f'흡수 {_v102_s(absorb)}')
    if _v102_s(angle): parts.append(f'파동각도 {_v102_s(angle)}')
    # 보조 추론
    if not parts:
        if any(x in blob for x in ['대장주', '주도주', '테마', '뉴스']):
            parts.append('테마 반응성 있음')
        if any(x in blob for x in ['거래대금', '거래량', '매집']):
            parts.append('거래대금/매집흔적 확인')
    if _v102_s(comment):
        parts.append(_v102_s(comment))
    if not parts:
        parts.append('끼점수 데이터 없음')
    # 해석 추가
    score = _v1028_num(ki)
    if score is not None:
        if score >= 80:
            parts.append('테마 붙으면 빠르게 움직일 수 있는 고탄력형')
        elif score >= 60:
            parts.append('탄력은 있으나 확인매수 우선')
        elif score >= 1:
            parts.append('끼는 약하므로 수급·차트 확인 우선')
    return '🔥 끼/흥행성: ' + _v102_trunc(' | '.join(parts), 170)


def _v1028_power_accum_line(lines=None, row=None):
    """전고점 이후 세력매집봉/흡수흔적을 최대한 복원해 표시."""
    d = _v1028_dict(row)
    blob = _v1028_blob(lines, d)
    prev_high = _v1028_get(d, ['전고점', '최근전고점', '직전고점', '박스상단', '저항상단', 'High20', 'high20', 'swing_high'])
    avg = _v1028_get(d, ['세력평단', '매집평단', '평단', 'avg_price', 'power_avg_price'])
    count = _v1028_get(d, ['세력매집봉수', '매집봉수', '매집봉개수', '매집일', '매집일수', 'accum_count', 'power_candle_count'])
    mult = _v1028_get(d, ['거래량배수', '매집배수', 'volume_multiple', 'vol_mult'])
    tag = _v1028_get(d, ['매집봉태그', '매집봉등급', '세력흔적태그', '세력흔적등급', '매집봉코멘트', '세력흔적코멘트'])
    # 기존 세력매집봉 라인 재활용
    try:
        old = _v1026_accum_line(lines or [], row=d).replace('🕯️ 세력매집봉: ', '')
    except Exception:
        old = ''
    if not _v102_s(count):
        m = re.search(r'매집\s*[:=]?\s*([0-9]+)일', blob)
        if m: count = m.group(1) + '일'
    if not _v102_s(mult):
        m = re.search(r'\(([0-9]+(?:\.[0-9]+)?)배\)', blob)
        if m: mult = m.group(1) + '배'
    if not _v102_s(avg):
        m = re.search(r'평단\s*[:=]?\s*([0-9,]+)원?', blob)
        if m: avg = m.group(1)
    parts = []
    if _v102_s(prev_high):
        parts.append(f'전고점/박스상단 {_v1028_price(prev_high)}원 기준')
    else:
        parts.append('전고점 기준값 산출불가')
    if _v102_s(count):
        parts.append(f'매집봉 흔적 {count}')
    else:
        parts.append('매집봉 개수 확인 필요')
    if _v102_s(mult):
        parts.append(f'거래량 {mult}')
    if _v102_s(avg):
        parts.append(f'추정평단 {_v1028_price(avg)}원')
    if _v102_s(tag):
        parts.append(_v102_s(tag))
    elif old:
        parts.append(old)
    return '🧲 전고점 이후 세력매집봉: ' + _v102_trunc(' | '.join(parts), 210)


def _v1028_chart_easy_line(lines=None, row=None):
    d = _v1028_dict(row)
    blob = _v1028_blob(lines, d)
    try:
        raw = _v1026_chart_line(lines or [], row=d).replace('📈 차트요약: ', '')
    except Exception:
        raw = ''
    parts = []
    # 저항구름
    if '저항돌파' in blob or '저항구름 돌파' in blob:
        parts.append('저항구름은 돌파 이후라 눌림 지지 확인이 핵심')
    elif '저항테스트' in blob:
        parts.append('저항구름을 시험하는 중이라 돌파 지속 여부 확인')
    elif '저항전' in blob:
        parts.append('아직 저항구름 아래라 회복 확인 전 선진입 금지')
    # 파동 위치
    if '소파동 상단권' in blob:
        parts.append('소파동은 상단권이라 추격보다 눌림 확인')
    elif '소파동 하단' in blob:
        parts.append('소파동은 하단권이라 반등 신호 확인')
    elif '소파동 중단' in blob:
        parts.append('소파동은 중단권이라 방향 확인')
    if '중파동 상단권' in blob:
        parts.append('중파동은 상단권이라 저항 확인 필요')
    elif '중파동 하단' in blob:
        parts.append('중파동은 하단권이라 반등 확인 필요')
    # 수렴/BB
    m = re.search(r'초\s*[:=]\s*([0-9.]+).*?단\s*[:=]\s*([0-9.]+).*?구\s*[:=]\s*([0-9.]+)', blob)
    if m:
        parts.append(f'수렴도 초/단/구 {m.group(1)}/{m.group(2)}/{m.group(3)}')
    if '삼각수렴' in blob or '구조수렴' in blob:
        parts.append('삼각/구조수렴 관점 포함')
    if not parts and raw:
        # 긴 raw를 그대로 붙이지 않고 핵심 토큰만 일부 사용
        short = []
        for token in raw.split('|'):
            t = token.strip()
            if any(k in t for k in ['저항', '소파동', '중파동', '수렴', 'BB40']):
                short.append(t)
            if len(short) >= 3:
                break
        parts = short
    if not parts:
        parts = ['차트 위치는 5일선·파란점선 기준으로 재확인 필요']
    return '📈 차트요약: ' + _v102_trunc(' / '.join(parts), 210)


def _v1028_easy_line(name, dec, lines=None, row=None):
    d = _v1028_dict(row)
    subject = re.sub(r'^\[|\].*$', '', _v102_s(name)).strip() or _v102_s(_v1028_get(d, ['종목명','Name'])) or '이 종목'
    label = _v102_s((dec or {}).get('label'))
    pattern = _v1028_search_pattern_line(lines, d).replace('🔎 검색패턴: ', '')
    char = _v1028_character_line(lines, d).replace('🧩 종목성격: ', '')
    if label == '조건부 실행':
        body = f'{subject}은 {char}으로 잡힌 후보입니다. 바로 추격하기보다 5일선과 파란점선에서 가격이 버티는지 확인한 뒤, 재양봉과 거래량 재유입이 붙을 때 분할 접근하는 종목입니다.'
    elif label == '눌림 대기':
        body = f'{subject}은 {pattern} 신호는 있으나 현재는 눌림 확인이 더 중요합니다. 5일선 또는 파란점선 근처에서 다시 지지받는 흐름이 나오면 관심도가 올라갑니다.'
    elif label == '보유자 대응':
        body = f'{subject}은 신규 매수보다 보유자의 관리 영역입니다. 이미 한 박자 진행된 자리라 5일선·파란점선 이탈 여부를 기준으로 대응합니다.'
    elif label == '추격 금지':
        body = f'{subject}은 현재 신규 진입 금지 쪽입니다. 패턴이 보여도 위험사유가 남아 있어, 파란점선 회복과 가짜/실패돌파 해소 전에는 실행 후보로 보지 않습니다.'
    else:
        body = f'{subject}은 {pattern} 관점에서 잡혔지만, 5일선·파란점선·수급을 다시 확인해야 합니다.'
    return '🧭 쉬운해설: ' + _v102_trunc(body, 260)


def _v1028_compact_card(seg, row=None):
    """V102.8: 데이터 나열형 카드 → 패턴/성격/매집/끼/타점 중심 자연어 카드."""
    try:
        lines = [str(x) for x in (seg or []) if str(x).strip()]
        if row is not None:
            try:
                lines = _v102_lines_from_row(row)
            except Exception:
                pass
        title = _v102_pick(lines, ['⭐ ']) or _v102_first_nonempty(lines)
        if not title or title.startswith('━━━━━━━━'):
            for x in lines:
                if _v102_numbered_stock(x):
                    title = _v102_s(x)
                    break
        name_title = _v1027_title(row=row, lines=lines, title=title) if '_v1027_title' in globals() else _v102_clean_name(title)
        dec = _v1026_decide(lines, row=row)
        label = dec.get('label', '눌림 대기')
        display_label = _v1027_display_label(dec, lines=lines, row=row) if '_v1027_display_label' in globals() else label
        badge = '⛔ 제외판정' if label == '추격 금지' else '✅ 최종판정'
        out = [
            name_title,
            f'{badge}: {display_label}',
            _v1028_search_pattern_line(lines, row),
            _v1028_character_line(lines, row),
            _v1028_easy_line(name_title, dec, lines, row),
            '📌 핵심근거: ' + ' / '.join((dec.get('reasons') or [])[:3]),
            _v1028_power_accum_line(lines, row),
            _v1028_ki_line(lines, row),
            _v1027_blue_line_info(lines=lines, row=row) if '_v1027_blue_line_info' in globals() else '',
            _v1027_entry_line(lines, row=row, dec=dec) if '_v1027_entry_line' in globals() else '',
            _v1028_chart_easy_line(lines, row),
            _v1027_supply_line(lines, row=row) if '_v1027_supply_line' in globals() else (_v1026_supply_line(lines, row=row) if '_v1026_supply_line' in globals() else ''),
            _v1026_price_line(lines, row=row) if '_v1026_price_line' in globals() else '',
            '🧯 무효/보류: ' + _v102_trunc(dec.get('invalid'), 140),
            '⚠️ 주의: ' + _v102_trunc(dec.get('caution'), 120),
        ]
        clean, seen = [], set()
        for x in out:
            s = _v102_s(x)
            if not s:
                continue
            # 너무 긴 raw 데이터 라인 제거
            if s.startswith(('gate:', 'intro_sub:', 'red2_sub:')):
                continue
            k = _v102_n(s)
            if k in seen:
                continue
            seen.add(k)
            clean.append(s)
        return clean
    except Exception:
        try:
            return _v1027_compact_card(seg, row=row)
        except Exception:
            return list(seg or [])


# 카드 생성기 재지정
_v102_compact_card = _v1028_compact_card


def _v1026_item(row):
    """V102.8: 오늘 매매관점 압축용 item에도 패턴성격/매집/끼를 포함."""
    d = _v1028_dict(row)
    lines = _v102_lines_from_row(d)
    dec = _v1026_decide(lines, row=d)
    try:
        name, code = _v102_code_name(d)
    except Exception:
        name, code = _v102_s(_v1028_get(d, ['종목명','Name'])), _v102_s(_v1028_get(d, ['code','종목코드']))
    if not code and '_v1027_code_from_any' in globals():
        code = _v1027_code_from_any(row=d, lines=lines)
    cur = _v1028_price(_v1028_get(d, ['현재가','Close','Price','종가']))
    return {
        'name': name,
        'code': code,
        'cur': cur,
        'decision': dec,
        'label': dec.get('label'),
        'display_label': _v1027_display_label(dec, lines=lines, row=d) if '_v1027_display_label' in globals() else dec.get('label'),
        'priority': dec.get('priority', 9),
        'score': _v102_num(d.get('N점수') or d.get('안전점수') or d.get('score'), 0),
        'pattern': _v1028_search_pattern_line(lines, row=d).replace('🔎 검색패턴: ', ''),
        'character': _v1028_character_line(lines, row=d).replace('🧩 종목성격: ', ''),
        'easy': _v1028_easy_line(name, dec, lines, row=d).replace('🧭 쉬운해설: ', ''),
        'accum': _v1028_power_accum_line(lines, row=d).replace('🧲 전고점 이후 세력매집봉: ', ''),
        'ki': _v1028_ki_line(lines, row=d).replace('🔥 끼/흥행성: ', ''),
        'entry': _v1027_entry_line(lines, row=d, dec=dec).replace('📍 타점요약: ', '') if '_v1027_entry_line' in globals() else '',
        'blue': _v1027_blue_line_info(lines=lines, row=d).replace('🔵 파란점선 기준: ', '') if '_v1027_blue_line_info' in globals() else '',
        'chart': _v1028_chart_easy_line(lines, row=d).replace('📈 차트요약: ', ''),
        'supply': _v1027_supply_line(lines, row=d).replace('🏦 수급: ', '') if '_v1027_supply_line' in globals() else '',
        'price': _v1026_price_line(lines, row=d).replace('💰 가격: ', '') if '_v1026_price_line' in globals() else '',
    }


def _v102_make_today_action_block(rows, base=''):
    """V102.8: 오늘 매매관점 압축에 검색패턴/종목성격/세력매집봉/끼를 추가."""
    try:
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1026_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used:
                    continue
                used.add(key)
                items.append(it)
            except Exception:
                continue
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5) if '_v1021_limit' in globals() else 5
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 10) if '_v1021_limit' in globals() else 10
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 4) if '_v1021_limit' in globals() else 4
        avoid_limit = max(0, _v1023_env_int('TODAY_ACTION_AVOID_LIMIT', 0)) if '_v1023_env_int' in globals() else 0
        show_excluded = _v1026_env_bool('SHOW_EXCLUDED_RISK', False) if '_v1026_env_bool' in globals() else False
        groups = [
            ('조건부 실행','🟢 5일선·파란점선 지지 확인 후 진입',cond_limit),
            ('눌림 대기','🟡 5일선 눌림/재지지 대기',observe_limit),
            ('보유자 대응','🛡️ 보유자 이탈선 관리',holder_limit),
        ]
        lines = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '🎯 [오늘 매매관점 압축]',
            '',
            f'📌 후보 수집: {total}개',
            '📌 오늘 전략: 종목성격·세력매집봉·끼를 먼저 보고, 5일선/파란점선 지지 확인 후 접근합니다.',
            '📌 보는 순서: 검색패턴 → 종목성격 → 전고점 이후 매집봉 → 끼 → 파란점선 → 수급 5/3/1일',
        ]
        shown_total = 0
        for label, title, limit in groups:
            arr = [x for x in items if x.get('label') == label]
            if not arr:
                continue
            lines.append('')
            suffix = f' ({min(len(arr), limit)}/{len(arr)}개 표시)' if len(arr) > limit else f' ({len(arr)}개)'
            lines.append(title + suffix)
            for i, it in enumerate(arr[:limit], 1):
                code_part = f"({it['code']})" if it.get('code') else ''
                lines.append(f"{i}) {it['name']}{code_part} | 현재 {it['cur']} | {it.get('display_label') or it['label']}")
                if it.get('pattern'):
                    lines.append(f"   검색: {_v102_trunc(it['pattern'], 82)}")
                if it.get('character'):
                    lines.append(f"   성격: {_v102_trunc(it['character'], 82)}")
                if it.get('accum'):
                    lines.append(f"   매집: {_v102_trunc(it['accum'], 92)}")
                if it.get('ki'):
                    lines.append(f"   끼: {_v102_trunc(it['ki'], 82)}")
                if it.get('blue'):
                    lines.append(f"   파란점선: {_v102_trunc(it['blue'], 100)}")
                if it.get('supply') and it.get('supply') != '수급 데이터 확인 필요':
                    lines.append(f"   수급: {_v102_trunc(it['supply'], 118)}")
                shown_total += 1
        excluded = [x for x in items if x.get('label') == '추격 금지']
        if excluded:
            lines.append('')
            lines.append(f'⛔ 제외/리스크 참고: {len(excluded)}개')
            if show_excluded and avoid_limit > 0:
                for i, it in enumerate(excluded[:avoid_limit], 1):
                    code_part = f"({it['code']})" if it.get('code') else ''
                    reasons = ' / '.join((it.get('decision') or {}).get('reasons') or [])
                    lines.append(f"{i}) {it['name']}{code_part} | 제외사유: {_v102_trunc(reasons, 70)}")
                    if it.get('character'):
                        lines.append(f"   성격: {_v102_trunc(it['character'], 70)}")
                    if it.get('blue'):
                        lines.append(f"   파란점선: {_v102_trunc(it['blue'], 92)}")
            else:
                lines.append('   상세는 기본 숨김입니다. 필요하면 SHOW_EXCLUDED_RISK=1, TODAY_ACTION_AVOID_LIMIT=5')
        if shown_total == 0:
            lines.append('')
            lines.append('- 실행/관찰 후보 없음. 오늘은 시황 대장주와 5일선 눌림 재지지 확인 우선')
        lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(lines)
    except Exception:
        return str(base or '')


def _v1026_analyze_leader_row(row, theme='', role='', fallback_name='', fallback_code=''):
    """V102.8: 시황 대장주도 패턴성격/매집/끼/파란점선으로 재판정."""
    try:
        if row is None:
            name = _v102_s(fallback_name or fallback_code or '종목명 확인 필요')
            code = _v102_s(fallback_code or (_v1026_alias_code(name) if '_v1026_alias_code' in globals() else ''))
            cp = f'({code})' if code else ''
            return {
                'name': name, 'code': code, 'priority': 6, 'label': '정밀스캔 미포함', 'risk': False,
                'lines': [
                    f'{name}{cp} | {role} | 정밀스캔 미포함',
                    f'   해설: 시황상 {theme} 관심주지만 오늘 Stock-Hunter 정밀 후보에는 잡히지 않았습니다.',
                    '   체크: 5일선 위 재양봉, 거래대금 유입, 파란점선 기준가, 전고점 이후 매집봉 흔적을 별도 확인하세요.',
                ]
            }
        d = _v1028_dict(row)
        lines = _v102_lines_from_row(d)
        dec = _v1026_decide(lines, row=d)
        name = _v1025_row_name(d) if '_v1025_row_name' in globals() else (_v102_code_name(d)[0] if '_v102_code_name' in globals() else _v102_s(_v1028_get(d, ['종목명','Name'])))
        code = _v1025_row_code(d) if '_v1025_row_code' in globals() else (_v102_code_name(d)[1] if '_v102_code_name' in globals() else _v102_s(_v1028_get(d, ['code','종목코드'])))
        cur = _v1028_price(_v1028_get(d, ['현재가','Close','Price','종가']))
        risk = dec.get('label') == '추격 금지'
        display = _v1027_display_label(dec, lines=lines, row=d) if '_v1027_display_label' in globals() else dec.get('label')
        out = [f'{name}({code}) | 현재 {cur} | {role} | 최종판정: {display}']
        out.append(f'   검색: {_v102_trunc(_v1028_search_pattern_line(lines, row=d).replace("🔎 검색패턴: ", ""), 88)}')
        out.append(f'   성격: {_v102_trunc(_v1028_character_line(lines, row=d, theme=theme, role=role).replace("🧩 종목성격: ", ""), 88)}')
        out.append(f'   해설: {_v102_trunc(_v1028_easy_line(name, dec, lines, row=d).replace("🧭 쉬운해설: ", ""), 125)}')
        out.append(f'   매집: {_v102_trunc(_v1028_power_accum_line(lines, row=d).replace("🧲 전고점 이후 세력매집봉: ", ""), 95)}')
        out.append(f'   끼: {_v102_trunc(_v1028_ki_line(lines, row=d).replace("🔥 끼/흥행성: ", ""), 85)}')
        if '_v1027_blue_line_info' in globals():
            out.append(f'   파란점선: {_v102_trunc(_v1027_blue_line_info(lines=lines, row=d).replace("🔵 파란점선 기준: ", ""), 100)}')
        out.append(f'   차트: {_v102_trunc(_v1028_chart_easy_line(lines, row=d).replace("📈 차트요약: ", ""), 98)}')
        if '_v1027_supply_line' in globals():
            supply = _v1027_supply_line(lines, row=d).replace('🏦 수급: ', '')
            if supply and supply != '수급 데이터 확인 필요':
                out.append(f'   수급: {_v102_trunc(supply, 115)}')
        return {'name': name, 'code': code, 'priority': dec.get('priority', 9), 'label': dec.get('label'), 'risk': risk, 'lines': out}
    except Exception as e:
        name = _v102_s(fallback_name or fallback_code or '종목')
        return {'name': name, 'code': fallback_code or '', 'priority': 9, 'label': '분석 실패', 'risk': False, 'lines': [f'{name} | {role} | 분석 실패: {str(e)[:80]}']}

