def _v1030_s(x):
    try:
        return _v102_s(x)
    except Exception:
        return str(x or '').strip()


def _v1030_dict(row=None):
    try:
        return _v1029_dict(row)
    except Exception:
        try:
            return _v1028_dict(row)
        except Exception:
            try:
                return dict(row or {})
            except Exception:
                return {}


def _v1030_num(v, default=None):
    try:
        if v is None:
            return default
        s = str(v).replace(',', '').replace('%', '').replace('배', '').replace('억', '').strip()
        if s in ('', '-', 'nan', 'None', 'N/A'):
            return default
        return float(s)
    except Exception:
        return default


def _v1030_get(row, keys, default=''):
    d = _v1030_dict(row)
    try:
        v = _v1029_get(d, keys, default='')
        if _v1030_s(v):
            return v
    except Exception:
        pass
    for k in keys:
        try:
            if k in d and _v1030_s(d.get(k)) not in ('', '-', 'nan', 'None'):
                return d.get(k)
        except Exception:
            pass
    return default


def _v1030_price(v):
    try:
        return _v1029_price(v)
    except Exception:
        try:
            return f"{float(str(v).replace(',', '')):,.0f}"
        except Exception:
            return _v1030_s(v) or '-'


def _v1030_blob(lines=None, row=None):
    parts = []
    try:
        parts.extend([_v1030_s(x) for x in (lines or []) if _v1030_s(x)])
    except Exception:
        pass
    try:
        d = _v1030_dict(row)
        parts.extend([f"{_v1030_s(k)}:{_v1030_s(v)}" for k, v in d.items() if _v1030_s(v)])
    except Exception:
        pass
    return ' | '.join(parts)


def _v1030_grade(score):
    n = _v1030_num(score, None)
    if n is None:
        return '미확인'
    if n >= 85:
        return '매우강함'
    if n >= 75:
        return '강함'
    if n >= 60:
        return '유효'
    if n >= 40:
        return '관찰'
    return '약함'


def _v1030_code(row=None, lines=None):
    d = _v1030_dict(row)
    try:
        name, code = _v102_code_name(d)
        if code:
            return _v1030_s(code)
    except Exception:
        pass
    code = _v1030_s(_v1030_get(d, ['code','Code','종목코드','티커','ticker']))
    if code:
        m = re.search(r'(\d{6})', code)
        if m:
            return m.group(1)
    try:
        for x in lines or []:
            m = re.search(r'\((\d{6})\)', str(x))
            if m:
                return m.group(1)
    except Exception:
        pass
    return ''


# -------------------------
# 세력매집 유형 분류
# -------------------------
def _v1030_accum_type(row=None, lines=None):
    d = _v1030_dict(row)
    blob = _v1030_blob(lines, d)
    accum_score = max(
        _v1030_num(_v1030_get(d, ['세력흔적점수','세력매집점수','매집강도점수','매집봉점수','accum_score','Maejip_Power']), 0) or 0,
        0,
    )
    strong_count = _v1030_num(_v1030_get(d, ['강한매집봉수','세력매집봉수','매집봉수','power_candle_count','accum_count']), None)
    accum_days = _v1030_num(_v1030_get(d, ['조용한매집일수','누적매집일수','매집일수','매집일수_20일','Maejip_Days_20','Green_Maejip_Days']), None)
    vol_mult = _v1030_num(_v1030_get(d, ['매집거래량배율','거래량배수','vol_mult','volume_multiple','Volume_Ratio_20']), None)
    obv = _v1030_s(_v1030_get(d, ['OBV방향','OBV','OBV흐름','OBV_SLOPE_5','OBV_SLOPE_10']))
    mfi = _v1030_num(_v1030_get(d, ['MFI','MFI14','mfi','MFI상승']), None)
    bb_width = _v1030_num(_v1030_get(d, ['BB40','BB40폭','BB40_WIDTH','bb40_width']), None)
    atr = _v1030_s(_v1030_get(d, ['ATR수축','ATR상태','ATR']))
    cur = _v1030_num(_v1030_get(d, ['현재가','Close','Price','종가']), None)
    avg = _v1030_num(_v1030_get(d, ['세력평단','매집평단','평단','avg_price','power_avg_price']), None)
    high = _v1030_num(_v1030_get(d, ['전고점','최근전고점','직전고점','박스상단','저항상단','High20','high20','swing_high']), None)
    # 텍스트 보조 파싱
    if strong_count is None:
        m = re.search(r'(?:강한)?매집봉(?:\s*흔적)?\s*([0-9]+)', blob)
        if m: strong_count = _v1030_num(m.group(1), None)
    if accum_days is None:
        m = re.search(r'매집\s*[:=]?\s*([0-9]+)일', blob)
        if m: accum_days = _v1030_num(m.group(1), None)
    if vol_mult is None:
        m = re.search(r'([0-9]+(?:\.[0-9]+)?)배', blob)
        if m: vol_mult = _v1030_num(m.group(1), None)
    one_shot = 0
    if (strong_count or 0) >= 1: one_shot += 1
    if (vol_mult or 0) >= 1.8: one_shot += 1
    if any(k in blob for k in ['장대양봉','고가권마감','아래꼬리흡수','세력매집봉','매집봉 강함']): one_shot += 1
    if accum_score >= 70 and (vol_mult or 0) >= 1.5: one_shot += 1
    quiet = 0
    if (accum_days or 0) >= 5: quiet += 1
    if any(k in blob for k in ['조용한매집','누적매집','박스권','응축','거래량 감소','변동성 축소','ATR수축']): quiet += 1
    if 'OBV' in blob and any(k in blob for k in ['우상향','상승','매집','+']): quiet += 1
    if mfi is not None and mfi >= 50: quiet += 1
    if bb_width is not None and bb_width <= 25: quiet += 1
    defense = 0
    if cur and avg and avg > 0 and cur >= avg * 0.98: defense += 1
    if cur and high and high > 0 and cur >= high * 0.90: defense += 1
    if any(k in blob for k in ['가격방어','중간값 위','매집봉 중간','저점 보존','방어 양호']): defense += 1
    if one_shot >= 2 and quiet >= 2:
        acc_type = '혼합매집형'
    elif one_shot >= 2:
        acc_type = '한방매집봉형'
    elif quiet >= 2:
        acc_type = '조용한 누적매집형'
    elif defense >= 2:
        acc_type = '매집 후 가격방어형'
    elif accum_score >= 40 or one_shot or quiet:
        acc_type = '매집흔적 관찰형'
    else:
        acc_type = '매집 약함/미확인'
    strength_seed = accum_score
    if strength_seed <= 0:
        strength_seed = min(100, one_shot*25 + quiet*20 + defense*10)
    grade = _v1030_grade(strength_seed)
    facts = []
    if strong_count is not None: facts.append(f'강한매집봉 {int(strong_count)}개')
    if accum_days is not None: facts.append(f'누적매집 {int(accum_days)}일')
    if vol_mult is not None and vol_mult > 0: facts.append(f'최대/매집 거래량 {vol_mult:.1f}배')
    if avg: facts.append(f'추정평단 {_v1030_price(avg)}원')
    if defense >= 2: facts.append('매집봉 이후 가격방어 양호')
    if high: facts.append(f'전고점/박스상단 {_v1030_price(high)}원 기준')
    if not facts:
        facts.append('전고점 이후 매집봉 개수·거래량 배수 추가확인')
    easy = {
        '혼합매집형': '한 번에 튀는 매집봉과 박스권 누적매집이 같이 보이는 형태입니다. 가장 좋은 쪽은 첫 눌림에서 가격방어가 확인되는 경우입니다.',
        '한방매집봉형': '거래량이 크게 터진 매집봉 중심입니다. 이후 가격이 무너지지 않는지 확인해야 진짜 매집으로 봅니다.',
        '조용한 누적매집형': '가격은 크게 안 움직이지만 OBV·수급·응축으로 천천히 모으는 형태입니다. 거래량 붙는 돌파가 필요합니다.',
        '매집 후 가격방어형': '강한 흔적 이후 가격을 방어하는 흐름입니다. 파란점선·5일선 이탈 여부가 핵심입니다.',
        '매집흔적 관찰형': '매집 흔적은 있으나 강도가 충분하지 않습니다. 거래량과 가격방어를 더 확인합니다.',
        '매집 약함/미확인': '현재 데이터만으로는 세력매집을 강하게 보기 어렵습니다.',
    }.get(acc_type, '')
    return {'type': acc_type, 'grade': grade, 'score': strength_seed, 'facts': facts, 'easy': easy}


def _v1030_accum_line(lines=None, row=None):
    info = _v1030_accum_type(row, lines)
    base = f"{info['type']}({info['grade']})"
    return '🧲 세력매집 유형: ' + _v102_trunc(base + ' | ' + ' / '.join(info['facts'][:5]), 230)


def _v1030_accum_easy_line(lines=None, row=None):
    info = _v1030_accum_type(row, lines)
    return '📘 매집해설: ' + _v102_trunc(info.get('easy') or '매집해설 데이터 확인 필요', 190)


# -------------------------
# 와이코프 A/S/L 쉬운 점수 표시
# -------------------------
def _v1030_wyckoff_data(row=None):
    d = _v1030_dict(row)
    try:
        if '_v97_dedicated_wyckoff_from_row' in globals():
            wy = _v97_dedicated_wyckoff_from_row(d)
            if isinstance(wy, dict): return wy
    except Exception:
        pass
    try:
        if '_v96_wyckoff_from_row' in globals():
            ev = _v93_wave_eval_from_row(d) if '_v93_wave_eval_from_row' in globals() else {}
            wy = _v96_wyckoff_from_row(d, ev)
            if isinstance(wy, dict): return wy
    except Exception:
        pass
    return {}


def _v1030_wyckoff_line(row=None, lines=None):
    wy = _v1030_wyckoff_data(row)
    if not wy:
        return '📦 와이코프: 데이터 없음 — 매집→돌파힘→눌림지지 순서로 추가 확인'
    stage = _v1030_s(wy.get('stage') or '관찰부족')
    total = _v1030_num(wy.get('score'), None)
    a = _v1030_num(wy.get('acc_score') or wy.get('A점수'), None)
    s = _v1030_num(wy.get('sos_score') or wy.get('S점수'), None)
    l = _v1030_num(wy.get('lps_score') or wy.get('L점수'), None)
    parts = []
    if a is not None: parts.append(f"매집 {a:.0f}점({_v1030_grade(a)})")
    if s is not None: parts.append(f"돌파힘 {s:.0f}점({_v1030_grade(s)})")
    if l is not None: parts.append(f"눌림지지 {l:.0f}점({_v1030_grade(l)})")
    score_txt = ' / '.join(parts) if parts else 'A/S/L 세부점수 미확인'
    total_txt = f"종합 {total:.0f}점({_v1030_grade(total)})" if total is not None else ''
    stage_txt = stage.replace('Accumulation', '매집').replace('SOS', '돌파힘').replace('LPS', '눌림지지')
    return '📦 와이코프: ' + _v102_trunc(f"{stage_txt}" + (f" | {total_txt}" if total_txt else '') + f" | {score_txt}", 230)


def _v1030_wyckoff_easy(row=None, lines=None):
    wy = _v1030_wyckoff_data(row)
    stage = _v1030_s(wy.get('stage'))
    a = _v1030_num(wy.get('acc_score') or wy.get('A점수'), 0) or 0
    s = _v1030_num(wy.get('sos_score') or wy.get('S점수'), 0) or 0
    l = _v1030_num(wy.get('lps_score') or wy.get('L점수'), 0) or 0
    if 'UTAD' in stage or '실패' in stage:
        msg = '가짜 돌파/실패돌파 가능성이 있어 신규 진입보다 제외가 우선입니다.'
    elif l >= 75 and a >= 60 and s >= 60:
        msg = '매집과 돌파힘이 확인된 뒤 눌림지지 점수가 강한 구간입니다. 5일선·파란점선 위 양봉 마감과 거래량 기준을 확인하면 실전 후보입니다.'
    elif s >= 75 and l < 60:
        msg = '돌파힘은 강하지만 눌림지지가 약합니다. 이미 튄 자리일 수 있어 첫 눌림 전 추격은 피합니다.'
    elif a >= 60 and s < 60:
        msg = '매집 흔적은 있지만 아직 힘 있는 돌파 확인 전입니다. 거래량이 붙는 돌파를 기다립니다.'
    elif 'LPS' in stage or '눌림' in stage:
        msg = '눌림에서 버티는지 보는 자리입니다. 파란점선·5일선 이탈 없이 다시 양봉이 나와야 의미가 있습니다.'
    else:
        msg = '와이코프는 매집, 돌파힘, 눌림지지 순서로 봅니다. 현재는 세 요소의 균형을 추가 확인해야 합니다.'
    return '📘 와이코프 해설: ' + _v102_trunc(msg, 200)


# -------------------------
# 기업정보 / 재무 컨텍스트
# -------------------------
_V1030_FUND_CACHE = {}

def _v1030_env_bool(name, default=False):
    try:
        return str(os.getenv(name, '1' if default else '0')).strip().lower() in ('1','true','yes','y','on')
    except Exception:
        return default


def _v1030_fund_from_pykrx(code):
    code = _v1030_s(code)
    if not re.fullmatch(r'\d{6}', code or ''):
        return {}
    if not _v1030_env_bool('ENABLE_FUNDAMENTAL_FETCH', True):
        return {}
    if code in _V1030_FUND_CACHE:
        return _V1030_FUND_CACHE.get(code) or {}
    try:
        import pandas as _pd
        from datetime import datetime as _dt, timedelta as _td
        # 전체 fundamental은 날짜별로 1회만 받는다.
        df_cache_key = '__fund_df__'
        df = _V1030_FUND_CACHE.get(df_cache_key)
        if df is None:
            df = None
            for i in range(0, 10):
                day = (_dt.now() - _td(days=i)).strftime('%Y%m%d')
                try:
                    tmp = stock.get_market_fundamental_by_ticker(day, market='ALL')
                    if tmp is not None and len(tmp) > 10:
                        df = tmp
                        break
                except Exception:
                    continue
            _V1030_FUND_CACHE[df_cache_key] = df if df is not None else False
        if df is False or df is None:
            _V1030_FUND_CACHE[code] = {}
            return {}
        if code not in df.index:
            _V1030_FUND_CACHE[code] = {}
            return {}
        r = df.loc[code]
        out = {k: r.get(k) for k in ['BPS','PER','PBR','EPS','DIV','DPS'] if k in r.index}
        try:
            bps = _v1030_num(out.get('BPS'), None)
            eps = _v1030_num(out.get('EPS'), None)
            if bps and eps is not None:
                out['ROE'] = round(eps / bps * 100, 1)
        except Exception:
            pass
        _V1030_FUND_CACHE[code] = out
        return out
    except Exception:
        _V1030_FUND_CACHE[code] = {}
        return {}


def _v1030_finance_values(row=None, lines=None):
    d = _v1030_dict(row)
    code = _v1030_code(d, lines)
    vals = {}
    keymap = {
        'PER': ['PER','per','PER(배)','주가수익비율'],
        'PBR': ['PBR','pbr','PBR(배)','주가순자산비율'],
        'EPS': ['EPS','eps','주당순이익','주당이익'],
        'ROE': ['ROE','roe','자기자본이익률','주당이익률'],
        'OPM': ['영업이익률','OPM','operating_margin','영업마진'],
        'DEBT': ['부채비율','debt_ratio','DebtRatio'],
        'SALES_G': ['매출성장률','매출액증가율','sales_growth'],
        'OP_G': ['영업이익증가율','op_growth','profit_growth'],
    }
    for outk, keys in keymap.items():
        v = _v1030_get(d, keys, '')
        if _v1030_s(v): vals[outk] = v
    py = _v1030_fund_from_pykrx(code)
    for k, v in py.items():
        if k == 'DIV':
            vals.setdefault('DIV', v)
        else:
            vals.setdefault(k, v)
    vals['GRADE'] = _v1030_get(d, ['재무','재무등급','finance_grade'], '')
    return vals


def _v1030_fmt_metric(v, suffix='', digits=1):
    n = _v1030_num(v, None)
    if n is None:
        return '-'
    if abs(n) >= 1000 and suffix == '원':
        return f'{n:,.0f}{suffix}'
    if float(n).is_integer():
        return f'{n:.0f}{suffix}'
    return f'{n:.{digits}f}{suffix}'


def _v1030_finance_line(lines=None, row=None):
    vals = _v1030_finance_values(row, lines)
    grade = _v1030_s(vals.get('GRADE')) or '미계산'
    per = _v1030_fmt_metric(vals.get('PER'), '배')
    pbr = _v1030_fmt_metric(vals.get('PBR'), '배')
    eps = _v1030_fmt_metric(vals.get('EPS'), '원')
    roe = _v1030_fmt_metric(vals.get('ROE'), '%')
    opm = _v1030_fmt_metric(vals.get('OPM'), '%')
    debt = _v1030_fmt_metric(vals.get('DEBT'), '%')
    return f'🏢 기업정보: 재무 {grade} | PER {per} / PBR {pbr} / EPS {eps} / ROE {roe} / 영업이익률 {opm} / 부채비율 {debt}'


def _v1030_finance_easy_line(lines=None, row=None):
    vals = _v1030_finance_values(row, lines)
    per = _v1030_num(vals.get('PER'), None)
    pbr = _v1030_num(vals.get('PBR'), None)
    eps = _v1030_num(vals.get('EPS'), None)
    roe = _v1030_num(vals.get('ROE'), None)
    opm = _v1030_num(vals.get('OPM'), None)
    grade = _v1030_s(vals.get('GRADE'))
    parts = []
    if eps is not None and eps < 0:
        parts.append('EPS가 적자라 재무보다 테마·수급 중심 단기 대응 성격이 강합니다')
    elif roe is not None and roe >= 15:
        parts.append('ROE가 높아 이익 효율은 좋은 편입니다')
    elif roe is not None and roe >= 8:
        parts.append('ROE는 무난한 편입니다')
    if opm is not None and opm >= 15:
        parts.append('영업이익률이 높아 본업 마진이 좋습니다')
    elif opm is not None and opm < 5:
        parts.append('영업이익률은 낮아 실적 체력 확인이 필요합니다')
    if pbr is not None and pbr >= 5:
        parts.append('PBR 부담이 있어 성장 기대가 꺾이면 변동성이 커질 수 있습니다')
    elif pbr is not None and pbr <= 1:
        parts.append('PBR 부담은 낮은 편입니다')
    if per is not None and per <= 0:
        parts.append('PER 산출이 불안정해 적자/일회성 이익 여부 확인이 필요합니다')
    elif per is not None and per >= 40:
        parts.append('PER은 높은 편이라 실적 성장 기대가 유지되는지 봐야 합니다')
    if not parts:
        if grade and grade not in ('미계산','N(미비)','-'):
            parts.append('재무는 기본 등급만 확인되며, 세부 밸류는 보조로 봅니다')
        else:
            parts.append('세부 재무 데이터가 부족해 차트·수급·거래대금 중심으로 판단합니다')
    return '📘 재무해석: ' + _v102_trunc(' / '.join(parts[:3]), 190)


# -------------------------
# V1030 카드/압축/시황대장주 출력 재정의
# -------------------------
try:
    _V1030_BASE_CARD = _v102_compact_card
except Exception:
    _V1030_BASE_CARD = None


def _v1030_compact_card(seg, row=None):
    try:
        lines = [str(x) for x in (seg or []) if str(x).strip()]
        if row is not None:
            try: lines = _v102_lines_from_row(row)
            except Exception: pass
        base = _V1030_BASE_CARD(seg, row=row) if _V1030_BASE_CARD else list(seg or [])
        out = []
        inserted_acc = inserted_fin = False
        for x in base:
            s = _v1030_s(x)
            if not s:
                continue
            # V1028의 긴 매집 한 줄은 V1030 세력매집 유형으로 교체
            if s.startswith(('🧲 전고점 이후 세력매집봉', '🧲 세력매집 유형')):
                if not inserted_acc:
                    out.append(_v1030_accum_line(lines, row))
                    out.append(_v1030_accum_easy_line(lines, row))
                    inserted_acc = True
                continue
            if s.startswith('📦 와이코프'):
                out.append(_v1030_wyckoff_line(row, lines))
                continue
            if s.startswith('📘 와이코프 해설'):
                out.append(_v1030_wyckoff_easy(row, lines))
                continue
            out.append(s)
            if s.startswith('🔥 끼/흥행성') and not inserted_fin:
                out.append(_v1030_finance_line(lines, row))
                out.append(_v1030_finance_easy_line(lines, row))
                inserted_fin = True
        if not inserted_acc:
            pos = 6 if len(out) > 6 else len(out)
            out[pos:pos] = [_v1030_accum_line(lines, row), _v1030_accum_easy_line(lines, row)]
        if not inserted_fin:
            # 수급 전 또는 가격 전 위치에 추가
            pos = len(out)
            for i, s in enumerate(out):
                if s.startswith(('🏦 수급', '💰 가격')):
                    pos = i; break
            out[pos:pos] = [_v1030_finance_line(lines, row), _v1030_finance_easy_line(lines, row)]
        clean, seen = [], set()
        for s in out:
            if s.startswith(('gate:', 'intro_sub:', 'red2_sub:')):
                continue
            k = re.sub(r'\s+', '', s)
            if k in seen:
                continue
            seen.add(k)
            clean.append(s)
        return clean
    except Exception:
        return _V1030_BASE_CARD(seg, row=row) if _V1030_BASE_CARD else list(seg or [])


_v102_compact_card = _v1030_compact_card

try:
    _V1030_BASE_ITEM = _v1026_item
except Exception:
    _V1030_BASE_ITEM = None


def _v1026_item(row):
    d = _v1030_dict(row)
    base = _V1030_BASE_ITEM(d) if _V1030_BASE_ITEM else {}
    if not isinstance(base, dict): base = {}
    lines = _v102_lines_from_row(d) if '_v102_lines_from_row' in globals() else []
    base['accum_type'] = _v1030_accum_line(lines, d).replace('🧲 세력매집 유형: ', '')
    base['accum_easy'] = _v1030_accum_easy_line(lines, d).replace('📘 매집해설: ', '')
    base['wyckoff'] = _v1030_wyckoff_line(d, lines).replace('📦 와이코프: ', '')
    base['wyckoff_easy'] = _v1030_wyckoff_easy(d, lines).replace('📘 와이코프 해설: ', '')
    base['finance'] = _v1030_finance_line(lines, d).replace('🏢 기업정보: ', '')
    base['finance_easy'] = _v1030_finance_easy_line(lines, d).replace('📘 재무해석: ', '')
    return base

try:
    _V1030_BASE_TODAY_BLOCK = _v102_make_today_action_block
except Exception:
    _V1030_BASE_TODAY_BLOCK = None


def _v102_make_today_action_block(rows, base=''):
    try:
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1026_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used: continue
                used.add(key); items.append(it)
            except Exception:
                continue
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5) if '_v1021_limit' in globals() else 5
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 10) if '_v1021_limit' in globals() else 10
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 4) if '_v1021_limit' in globals() else 4
        avoid_limit = max(0, _v1023_env_int('TODAY_ACTION_AVOID_LIMIT', 0)) if '_v1023_env_int' in globals() else 0
        show_excluded = _v1026_env_bool('SHOW_EXCLUDED_RISK', False) if '_v1026_env_bool' in globals() else False
        groups = [
            ('조건부 실행','🟢 5일선·파란점선 위 양봉마감 + 거래량 기준 확인 후 진입',cond_limit),
            ('눌림 대기','🟡 5일선 눌림/파란점선 재지지 대기',observe_limit),
            ('보유자 대응','🛡️ 보유자 이탈선 관리',holder_limit),
        ]
        out = ['━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━','🎯 [오늘 매매관점 압축]','',f'📌 후보 수집: {total}개','📌 보는 순서: 시황/검색패턴 → 세력매집 유형 → 와이코프 매집·돌파힘·눌림지지 → 끼 → 재무 → 파란점선/5일선 → 수급 5/3/1일','📌 진입 기준: 5일선·파란점선 위 양봉 마감 + 거래량 전일比 1.3배↑ 또는 5일평균比 1.2배↑']
        shown_total = 0
        for label, title, limit in groups:
            arr = [x for x in items if x.get('label') == label]
            if not arr: continue
            out.append('')
            suffix = f' ({min(len(arr), limit)}/{len(arr)}개 표시)' if len(arr) > limit else f' ({len(arr)}개)'
            out.append(title + suffix)
            for i, it in enumerate(arr[:limit], 1):
                code_part = f"({it['code']})" if it.get('code') else ''
                out.append(f"{i}) {it['name']}{code_part} | 현재 {it.get('cur','-')} | {it.get('display_label') or it.get('label')}")
                if it.get('pattern'): out.append(f"   검색: {_v102_trunc(it['pattern'], 76)}")
                if it.get('accum_type'): out.append(f"   매집유형: {_v102_trunc(it['accum_type'], 95)}")
                if it.get('wyckoff'): out.append(f"   와이코프: {_v102_trunc(it['wyckoff'], 110)}")
                if it.get('ki'): out.append(f"   끼: {_v102_trunc(it['ki'], 78)}")
                if it.get('finance'): out.append(f"   기업: {_v102_trunc(it['finance'], 92)}")
                if it.get('blue'): out.append(f"   파란점선: {_v102_trunc(it['blue'], 92)}")
                if it.get('entry_criteria') or it.get('entry'):
                    out.append(f"   진입기준: {_v102_trunc(it.get('entry_criteria') or it.get('entry'), 118)}")
                if it.get('supply') and it.get('supply') != '수급 데이터 확인 필요': out.append(f"   수급: {_v102_trunc(it['supply'], 108)}")
                shown_total += 1
        excluded = [x for x in items if x.get('label') == '추격 금지']
        if excluded:
            out.append(''); out.append(f'⛔ 제외/리스크 참고: {len(excluded)}개')
            if show_excluded and avoid_limit > 0:
                for i, it in enumerate(excluded[:avoid_limit], 1):
                    code_part = f"({it['code']})" if it.get('code') else ''
                    reasons = ' / '.join((it.get('decision') or {}).get('reasons') or [])
                    out.append(f"{i}) {it['name']}{code_part} | 제외사유: {_v102_trunc(reasons, 64)}")
                    if it.get('accum_type'): out.append(f"   매집유형: {_v102_trunc(it['accum_type'], 80)}")
                    if it.get('wyckoff'): out.append(f"   와이코프: {_v102_trunc(it['wyckoff'], 88)}")
            else:
                out.append('   상세는 기본 숨김입니다. 필요하면 SHOW_EXCLUDED_RISK=1, TODAY_ACTION_AVOID_LIMIT=5')
        if shown_total == 0:
            out.append(''); out.append('- 실행/관찰 후보 없음. 오늘은 시황 대장주와 5일선 눌림 재지지 확인 우선')
        out.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join(out)
    except Exception:
        return _V1030_BASE_TODAY_BLOCK(rows, base=base) if _V1030_BASE_TODAY_BLOCK else str(base or '')

