def _v1026_analyze_leader_row(row, theme='', role='', fallback_name='', fallback_code=''):
    base = _V1030_BASE_LEADER_ROW(row, theme=theme, role=role, fallback_name=fallback_name, fallback_code=fallback_code) if _V1030_BASE_LEADER_ROW else None
    if not isinstance(base, dict):
        base = {'name': fallback_name or '', 'code': fallback_code or '', 'lines': []}
    if row is not None:
        try:
            d = _v1030_dict(row)
            lines = _v102_lines_from_row(d) if '_v102_lines_from_row' in globals() else []
            arr = list(base.get('lines') or [])
            extras = [
                f"   매집유형: {_v102_trunc(_v1030_accum_line(lines, d).replace('🧲 세력매집 유형: ', ''), 95)}",
                f"   와이코프: {_v102_trunc(_v1030_wyckoff_line(d, lines).replace('📦 와이코프: ', ''), 105)}",
                f"   기업정보: {_v102_trunc(_v1030_finance_line(lines, d).replace('🏢 기업정보: ', ''), 100)}",
            ]
            if not any('매집유형:' in str(x) for x in arr):
                insert_at = min(len(arr), 5)
                arr[insert_at:insert_at] = extras
            base['lines'] = arr
        except Exception:
            pass
    else:
        arr = list(base.get('lines') or [])
        if not any('기업정보' in str(x) for x in arr):
            arr.append('   기업정보: 정밀스캔 미포함이라 PER/PBR/EPS는 별도 확인 필요')
            base['lines'] = arr
    return base

