def _v1031_s(x):
    try:
        return _v1030_s(x)
    except Exception:
        return str(x or '').strip()


def _v1031_trunc(x, n=180):
    try:
        return _v102_trunc(_v1031_s(x), n)
    except Exception:
        s = _v1031_s(x)
        return s if len(s) <= n else s[:max(0,n-1)] + '…'


def _v1031_clean_text(s):
    s = _v1031_s(s)
    # 문장 중간의 "하이브](352820)은" 같은 깨짐만 정리. 카드 제목의 [하이브](352820)는 유지.
    s = re.sub(r'([^\[])\]\((\d{6})\)', r'\1(\2)', s)
    s = s.replace('..', '.')
    s = s.replace('조건부 실행', '5일선·파란점선 확인 후 진입')
    s = s.replace('눌림 대기', '5일선 눌림/재지지 대기')
    s = s.replace('재양봉, 거래량 재유입, 파란점선·5일선 지지 중 2개 이상', '5일선·파란점선 위 양봉 마감 + 거래량 기준')
    s = s.replace('재양봉·거래량 재유입·파란점선 지지 중 2개', '5일선·파란점선 위 양봉 마감 + 거래량 기준')
    # 빈 placeholder 정리
    s = s.replace('접촉()', '접촉').replace('아래()', '아래').replace('위안착()', '위안착').replace('위확장()', '위확장')
    s = s.replace(' | 5일선 원', '').replace('5일선 원 | ', '').replace('5일선 원', '')
    s = re.sub(r'현재\s*/\s*', '', s)
    s = re.sub(r'현재\s+/', '', s)
    s = re.sub(r'눌림권\s*~\s*/\s*', '', s)
    s = re.sub(r'눌림\s*~\s*/\s*', '', s)
    s = re.sub(r'가격: 현재\s*/\s*눌림\s*~\s*/\s*손절\s*/\s*목표\s*', '가격: 기준값 산출불가', s)
    s = re.sub(r'\s{2,}', ' ', s).strip()
    return s


def _v1031_skip_line(s):
    s0 = _v1031_s(s)
    s = _v1031_clean_text(s0)
    if not s:
        return True
    bad_exact = {'💰 가격: 기준값 산출불가', '📍 타점요약:', '💰 가격:'}
    if s in bad_exact:
        return True
    # 숫자/실제 기준 없이 빈 틀만 있는 줄은 숨김
    if s.startswith('📍 타점요약') and not re.search(r'\d', s) and ('기다렸다가' not in s and '신규' not in s):
        return True
    if s.startswith('💰 가격') and not re.search(r'\d', s):
        return True
    return False


def _v1031_header_from_card(lines):
    for x in lines or []:
        s = _v1031_clean_text(x)
        if re.match(r'^\[[^\]]+\](?:\(\d{6}\))?', s):
            return s
    return ''


def _v1031_categorize_card(lines):
    cat = {
        'header': [], 'decision': [], 'easy': [], 'reason': [], 'pattern': [],
        'accum': [], 'wyckoff': [], 'ki': [], 'finance': [], 'blue': [],
        'entry': [], 'chart': [], 'supply': [], 'price': [], 'invalid': [], 'caution': [], 'other': []
    }
    for raw in lines or []:
        if _v1031_skip_line(raw):
            continue
        s = _v1031_clean_text(raw)
        if not s:
            continue
        if re.match(r'^\[[^\]]+\](?:\(\d{6}\))?', s): cat['header'].append(s)
        elif s.startswith(('✅', '⛔')): cat['decision'].append(s)
        elif s.startswith('🧭 쉬운해설'): cat['easy'].append(s)
        elif s.startswith('📌 핵심근거'): cat['reason'].append(s)
        elif s.startswith('🔎'): cat['pattern'].append(s)
        elif s.startswith(('🧲', '🕯️', '📘 매집')): cat['accum'].append(s)
        elif s.startswith(('📦 와이코프', '📘 와이코프')): cat['wyckoff'].append(s)
        elif s.startswith('🔥'): cat['ki'].append(s)
        elif s.startswith(('🏢', '📘 재무')): cat['finance'].append(s)
        elif s.startswith('🔵'): cat['blue'].append(s)
        elif s.startswith(('📍', '🎯 실행조건', '🎯 진입')): cat['entry'].append(s)
        elif s.startswith('📈'): cat['chart'].append(s)
        elif s.startswith('🏦'): cat['supply'].append(s)
        elif s.startswith('💰'): cat['price'].append(s)
        elif s.startswith('🧯'): cat['invalid'].append(s)
        elif s.startswith('⚠️'): cat['caution'].append(s)
        else: cat['other'].append(s)
    return cat


def _v1031_dedupe(seq):
    out, seen = [], set()
    for x in seq or []:
        s = _v1031_clean_text(x)
        if not s: continue
        k = re.sub(r'\s+', '', s)
        if k in seen: continue
        seen.add(k); out.append(s)
    return out


def _v1031_supply_lines(raw, prefix=''):
    raw = _v1031_clean_text(raw).replace('🏦 수급:', '').strip()
    if not raw or raw == '수급 데이터 확인 필요':
        return []
    parts = [p.strip() for p in raw.split('|') if p.strip()]
    if len(parts) <= 1:
        return [prefix + '🏦 수급: ' + _v1031_trunc(raw, 180)]
    out = [prefix + '🏦 수급']
    for p in parts[:5]:
        out.append(prefix + '   - ' + _v1031_trunc(p, 120))
    return out


try:
    _V1031_BASE_COMPACT_CARD = _v1030_compact_card
except Exception:
    try:
        _V1031_BASE_COMPACT_CARD = _v102_compact_card
    except Exception:
        _V1031_BASE_COMPACT_CARD = None


def _v1031_compact_card(seg, row=None):
    try:
        base = _V1031_BASE_COMPACT_CARD(seg, row=row) if _V1031_BASE_COMPACT_CARD else list(seg or [])
        base = [_v1031_clean_text(x) for x in (base or []) if _v1031_clean_text(x)]
        cat = _v1031_categorize_card(base)
        out = []
        header = _v1031_dedupe(cat['header'])
        if header:
            out.extend(header[:1])
            out.append('────────────────────')
        order = ['decision','easy','reason','pattern','accum','wyckoff','ki','finance','blue','entry','chart','supply','price','invalid','caution','other']
        for key in order:
            vals = _v1031_dedupe(cat.get(key) or [])
            if not vals:
                continue
            if key == 'supply':
                for v in vals[:1]:
                    out.extend(_v1031_supply_lines(v))
                continue
            # 너무 긴 섹션은 한두 줄로 제한하되 정보 종류는 유지
            limit = 2 if key in ('accum','wyckoff','finance') else 1
            for v in vals[:limit]:
                out.append(_v1031_trunc(v, 260 if key in ('entry','blue','chart') else 220))
        clean = []
        for s in out:
            if _v1031_skip_line(s):
                continue
            clean.append(_v1031_clean_text(s))
        return clean
    except Exception:
        try:
            return _V1031_BASE_COMPACT_CARD(seg, row=row) if _V1031_BASE_COMPACT_CARD else list(seg or [])
        except Exception:
            return list(seg or [])

# 최신 카드 포맷을 기본 카드 함수로 지정
_v102_compact_card = _v1031_compact_card
_v1026_compact_card = _v1031_compact_card


def _v1031_env_bool(name, default=False):
    try:
        v = str(os.environ.get(name, '1' if default else '0')).strip().lower()
        return v in ('1','true','yes','on','y')
    except Exception:
        return default


try:
    _V1031_BASE_ACTION_FIRST_TEXT = _v102_action_first_text
except Exception:
    _V1031_BASE_ACTION_FIRST_TEXT = None


def _v102_action_first_text(text):
    """V1031: 관찰형/선취형/눌림수박 카드 가독성 재정렬 + 시황대장주 블록 제거."""
    try:
        b = str(text or '')
        if not b.strip():
            return b
        if '👑 [시황 대장주 매매 분석]' in b:
            # 이 블록은 요청에 따라 제거. 다른 브리핑/섹터 리포트는 유지.
            return ''
        hot = ['👀 [오늘의 관찰형 참고]', '🛡️ [오늘의 후행형 참고]', '🍉 [초입수박 TOP', '🍉 [눌림수박 TOP',
               '🧭 [선취 후보', '🧭 [선취 관찰 후보', '🧭 [선취 제외 후보', '🚀 [흰구름 돌파 후보',
               '🚀 [흰구름 돌파 관찰', '🎯 [오늘 매매관점 압축]']
        if not any(h in b for h in hot):
            return _v102_strip_debug_and_duplicates(b) if '_v102_strip_debug_and_duplicates' in globals() else b
        lines = b.splitlines()
        segs, cur = [], []
        for line in lines:
            try:
                start = _v102_segment_start(line) if '_v102_segment_start' in globals() else bool(re.match(r'^\[[^\]]+\]', str(line)))
            except Exception:
                start = bool(re.match(r'^\[[^\]]+\]', str(line)))
            if cur and start:
                segs.append(cur); cur = [line]
            else:
                cur.append(line)
        if cur: segs.append(cur)
        cleaned = []
        skipped_risk = 0
        current_heading = ''
        hide_risk_watch = not _v1031_env_bool('SHOW_RISK_CARDS_IN_WATCH', False)
        for seg in segs:
            first = ''
            try: first = _v102_first_nonempty(seg)
            except Exception: first = next((str(x) for x in seg if str(x).strip()), '')
            is_card = False
            try: is_card = _v102_is_card(seg)
            except Exception: is_card = bool(re.match(r'^\[[^\]]+\]', first))
            if '[' in first and ']' in first and not is_card:
                current_heading = first
            if is_card:
                dec = {}
                try: dec = _v1026_decide(seg)
                except Exception: dec = {}
                if hide_risk_watch and dec.get('label') == '추격 금지' and any(k in current_heading for k in ['관찰형', '초입수박', '눌림수박', '돌파 관찰', '선취 관찰']) and not any(k in current_heading for k in ['제외', '후행']):
                    skipped_risk += 1
                    continue
                if cleaned and cleaned[-1].strip():
                    cleaned.append('')
                cleaned.extend(_v1031_compact_card(seg))
            else:
                # 기존 제목/구분선은 유지하되 시황대장주 잔여 라인은 제거
                for x in seg:
                    sx = _v1031_clean_text(x)
                    if '👑 [시황 대장주 매매 분석]' in sx:
                        continue
                    cleaned.append(sx)
        if skipped_risk:
            cleaned.append('')
            cleaned.append(f'⛔ 위험사유 카드 {skipped_risk}개는 실행/관찰 섹션에서 숨겼습니다. 필요하면 SHOW_RISK_CARDS_IN_WATCH=1')
        out = '\n'.join([x for x in cleaned if x is not None])
        while '\n\n\n\n' in out:
            out = out.replace('\n\n\n\n', '\n\n\n')
        return _v102_strip_debug_and_duplicates(out) if '_v102_strip_debug_and_duplicates' in globals() else out
    except Exception:
        return str(text or '')

