print("✅ TRADE_CLARITY_V10_3_2_WAVE_POSITION_ELLIOTT_ACTIVE LOADED")


def _v1032_s(x):
    try: return _v1031_s(x)
    except Exception: return str(x or '').strip()


def _v1032_dict(row):
    try: return _v1030_dict(row)
    except Exception:
        if isinstance(row, dict): return row
        try: return row.to_dict()
        except Exception: return {}


def _v1032_num(v, default=0.0):
    try:
        if v is None or v == '': return default
        if isinstance(v, str): v = v.replace(',', '').replace('%', '').replace('원','').strip()
        return float(v)
    except Exception: return default


def _v1032_get(d, keys, default=''):
    d = _v1032_dict(d)
    for k in keys:
        try:
            v = d.get(k)
            if _v1032_s(v) not in ('', '-', 'nan', 'None'): return v
        except Exception: pass
    return default


def _v1032_price(v):
    n = _v1032_num(v, 0)
    return f"{n:,.0f}원" if n > 0 else '-'


def _v1032_pos_label(p):
    p = _v1032_num(p, -1)
    if p < 0: return '위치확인'
    if p < 20: return '하단권'
    if p < 40: return '하단~중단'
    if p < 60: return '중단권'
    if p < 80: return '중상단'
    return '상단권'


def _v1032_angle_label(a):
    a = _v1032_num(a, 0)
    if a >= 45: return '과속상승'
    if a >= 25: return '탄력상승'
    if a >= 10: return '완만상승'
    if a > -5: return '횡보/전환확인'
    if a > -20: return '완만조정'
    return '하락압력'


def _v1032_score_label(s):
    s = _v1032_num(s, 0)
    if s >= 85: return '매우강함'
    if s >= 75: return '강함'
    if s >= 60: return '유효'
    if s >= 40: return '관찰'
    return '약함'


def _v1032_wave_position(row=None, lines=None):
    d = _v1032_dict(row or {})
    sl, sh = _v1032_get(d, ['소파동저점','small_low']), _v1032_get(d, ['소파동전고점','small_high'])
    sp = _v1032_num(_v1032_get(d, ['소파동위치퍼센트','small_pos_pct']), -1)
    sa = _v1032_num(_v1032_get(d, ['소파동각도','small_angle']), 0)
    sp_label = _v1032_s(_v1032_get(d, ['소파동위치권','소파동위치','small_pos_label','small_state'])) or _v1032_pos_label(sp)
    ml, mh = _v1032_get(d, ['중파동저점','mid_low']), _v1032_get(d, ['중파동전고점','mid_high'])
    mp = _v1032_num(_v1032_get(d, ['중파동위치퍼센트','mid_pos_pct']), -1)
    ma = _v1032_num(_v1032_get(d, ['중파동각도','mid_angle']), 0)
    mp_label = _v1032_s(_v1032_get(d, ['중파동위치권','중파동위치','mid_pos_label','mid_state'])) or _v1032_pos_label(mp)
    parts = []
    if sp >= 0 or _v1032_num(sl,0)>0 or _v1032_num(sh,0)>0:
        rng = f" / 박스 {_v1032_price(sl)}~{_v1032_price(sh)}" if _v1032_num(sl,0)>0 and _v1032_num(sh,0)>0 else ''
        parts.append(f"소파동 {sp_label}({sp:.0f}%) / {sa:.1f}° {_v1032_angle_label(sa)}{rng}")
    if mp >= 0 or _v1032_num(ml,0)>0 or _v1032_num(mh,0)>0:
        rng = f" / 박스 {_v1032_price(ml)}~{_v1032_price(mh)}" if _v1032_num(ml,0)>0 and _v1032_num(mh,0)>0 else ''
        parts.append(f"중파동 {mp_label}({mp:.0f}%) / {ma:.1f}° {_v1032_angle_label(ma)}{rng}")
    return '🌊 파동위치: ' + (' | '.join(parts[:2]) if parts else '소파동/중파동 위치 데이터 확인 필요')


def _v1032_estimate_elliott(row=None, lines=None):
    d = _v1032_dict(row or {})
    turn = _v1032_num(_v1032_get(d, ['파동전환점수','trend_turn_score']), 0)
    w1 = _v1032_num(_v1032_get(d, ['파동1파점수','first_wave_score']), 0)
    pb = _v1032_num(_v1032_get(d, ['파동눌림점수','pullback_health_score']), 0)
    restart = _v1032_num(_v1032_get(d, ['파동재출발점수','restart_score']), 0)
    retr = _v1032_num(_v1032_get(d, ['파동되돌림률','pullback_pct']), -1)
    stage = _v1032_s(_v1032_get(d, ['파동타점상태','wave_stage']))
    sp = _v1032_num(_v1032_get(d, ['소파동위치퍼센트','small_pos_pct']), -1)
    mp = _v1032_num(_v1032_get(d, ['중파동위치퍼센트','mid_pos_pct']), -1)
    sa = _v1032_num(_v1032_get(d, ['소파동각도','small_angle']), 0)
    if ('UTAD' in stage) or ('실패' in stage): label, why = '실패파동/분산 주의', '가짜 돌파 가능성이 있어 신규 진입 제외 우선'
    elif restart >= 70: label, why = '3파 초입/재출발 후보', '1파 돌파 후 눌림을 거치고 다시 출발하려는 구간'
    elif pb >= 60 and w1 >= 50: label, why = '2파 눌림/LPS 확인 구간', '첫 상승 이후 눌림에서 지지 확인 중'
    elif w1 >= 65 and pb < 50: label, why = '1파 진행 후 첫 눌림 대기', '초동 상승은 확인됐지만 2파 지지는 아직 부족'
    elif turn >= 60 and w1 < 60: label, why = '1파 전환 후보', '상승 전환 시도는 있으나 돌파힘 확인 전'
    elif sp >= 80 and mp >= 70 and sa >= 25: label, why = '5파/상단권 가능성', '소파동·중파동이 상단권이라 신규 추격 부담'
    elif sp >= 60 and mp < 60 and sa >= 20: label, why = '3파 진행 가능성', '단기 탄력은 살아 있고 중파동은 과열 전'
    elif sp < 40 and mp < 50: label, why = '1파 전환 후보', '하단권에서 반등 확인이 필요한 자리'
    else: label, why = '파동 카운트 관찰', '명확한 1·2·3파 조건 부족, 기준선 지지 확인 우선'
    scores = f"전환 {turn:.0f}({_v1032_score_label(turn)}) / 1파 {w1:.0f}({_v1032_score_label(w1)}) / 눌림 {pb:.0f}({_v1032_score_label(pb)}) / 재출발 {restart:.0f}({_v1032_score_label(restart)})"
    if retr >= 0: scores += f" / 되돌림 {retr:.1f}%"
    return label, why, scores


def _v1032_elliott_line(row=None, lines=None):
    label, why, scores = _v1032_estimate_elliott(row, lines)
    return '〰️ 엘리어트(추정): ' + f"{label} | {scores} | 해석: {why}"


def _v1032_wave_easy_line(row=None, lines=None):
    label, why, scores = _v1032_estimate_elliott(row, lines)
    if '3파' in label: msg = '상승 탄력이 붙을 수 있는 구간입니다. 파란점선·5일선 지지와 거래량 기준이 맞을 때만 분할 접근합니다.'
    elif '2파' in label or '눌림' in label: msg = '실전 관심도가 높은 눌림 확인 구간입니다. 양봉 마감과 거래량 재유입을 봅니다.'
    elif '1파' in label: msg = '상승 전환 초입일 수 있지만 아직 확인 전입니다. 첫 돌파와 거래량이 붙는지 봅니다.'
    elif '5파' in label or '상단' in label: msg = '이미 파동이 많이 진행됐을 수 있어 신규 추격보다 눌림이나 이탈선 관리가 우선입니다.'
    elif '실패' in label: msg = '가짜 돌파 가능성이 있어 신규 진입보다 회복 여부 확인이 먼저입니다.'
    else: msg = '파동 카운트가 명확하지 않으므로 파란점선·5일선 기준으로 단순하게 확인합니다.'
    return '📘 파동해설: ' + msg

try: _V1032_BASE_COMPACT_CARD = _v102_compact_card
except Exception: _V1032_BASE_COMPACT_CARD = None

def _v1032_compact_card(seg, row=None):
    try:
        lines = [str(x) for x in (seg or []) if str(x).strip()]
        if row is not None:
            try: lines = _v102_lines_from_row(row)
            except Exception: pass
        base = _V1032_BASE_COMPACT_CARD(seg, row=row) if _V1032_BASE_COMPACT_CARD else list(seg or [])
        d = _v1032_dict(row or {})
        out, inserted = [], False
        for x in base:
            s = _v1032_s(x)
            if not s: continue
            out.append(s)
            if (not inserted) and (s.startswith('🔥') or s.startswith('📈 차트요약')):
                out.extend([_v1032_wave_position(d, lines), _v1032_elliott_line(d, lines), _v1032_wave_easy_line(d, lines)])
                inserted = True
        if not inserted:
            pos = len(out)
            for i, s in enumerate(out):
                if s.startswith(('🏦 수급','💰 가격','🔵')): pos = i; break
            out[pos:pos] = [_v1032_wave_position(d, lines), _v1032_elliott_line(d, lines), _v1032_wave_easy_line(d, lines)]
        clean, seen = [], set()
        for s in out:
            if s.startswith(('gate:', 'intro_sub:', 'red2_sub:')): continue
            k = re.sub(r'\s+', '', s)
            if k in seen: continue
            seen.add(k); clean.append(s)
        return clean
    except Exception:
        return _V1032_BASE_COMPACT_CARD(seg, row=row) if _V1032_BASE_COMPACT_CARD else list(seg or [])

_v102_compact_card = _v1032_compact_card
_v1026_compact_card = _v1032_compact_card

try: _V1032_BASE_ITEM = _v1026_item
except Exception: _V1032_BASE_ITEM = None

def _v1026_item(row):
    d = _v1032_dict(row)
    base = _V1032_BASE_ITEM(d) if _V1032_BASE_ITEM else {}
    if not isinstance(base, dict): base = {}
    try: lines = _v102_lines_from_row(d)
    except Exception: lines = []
    base['wave_position'] = _v1032_wave_position(d, lines).replace('🌊 파동위치: ', '')
    base['elliott'] = _v1032_elliott_line(d, lines).replace('〰️ 엘리어트(추정): ', '')
    base['wave_easy'] = _v1032_wave_easy_line(d, lines).replace('📘 파동해설: ', '')
    return base

try: _V1032_BASE_TODAY_BLOCK = _v102_make_today_action_block
except Exception: _V1032_BASE_TODAY_BLOCK = None

def _v102_make_today_action_block(rows, base=''):
    try:
        # V1031 기본 가독성 블록을 그대로 쓰되, 파동/엘리어트는 item 필드로 추가되어 자동 노출된다.
        txt = _V1032_BASE_TODAY_BLOCK(rows, base=base) if _V1032_BASE_TODAY_BLOCK else ''
        # V1031 블록이 wave 필드를 모르므로 핵심 안내 문구만 보강한다. 개별카드는 관찰형/상세카드에서 노출.
        if '🎯 [오늘 매매관점 압축]' in txt and '파동위치/엘리어트' not in txt:
            txt = txt.replace('📌 진입 숫자 기준:', '📌 파동 참고: 소파동·중파동 위치와 엘리어트 추정은 관찰형 상세카드에서 확인\n📌 진입 숫자 기준:')
        return txt
    except Exception:
        return str(base or '')

