# ✅ TRADE_CLARITY_V10_3_3_CARD_HEADER_RISK_CLEANUP_ACTIVE
# - 종목명/종목코드 중복 및 카드 하단 깨진 헤더 제거
# - 종목 헤더를 카드 맨 위에 1회만 표시
# - 위험사유 숨김 안내 반복 출력 제거
# - 자잘한 문구/조사/중복 코드 정리
# =============================================================
print("✅ TRADE_CLARITY_V10_3_3_CARD_HEADER_RISK_CLEANUP_ACTIVE LOADED")

try:
    os.environ.setdefault('SHOW_HIDDEN_RISK_NOTICE', '0')
except Exception:
    pass


def _v1033_s(x):
    try:
        return _v1032_s(x)
    except Exception:
        try:
            return _v1031_s(x)
        except Exception:
            return str(x or '').strip()


def _v1033_dict(row):
    try:
        return _v1032_dict(row)
    except Exception:
        if isinstance(row, dict):
            return row
        try:
            return row.to_dict()
        except Exception:
            return {}


def _v1033_trunc(x, n=260):
    try:
        return _v1031_trunc(x, n)
    except Exception:
        s = _v1033_s(x)
        return s if len(s) <= n else s[:max(0, n-1)] + '…'


def _v1033_code(x):
    s = _v1033_s(x)
    m = re.search(r'\b(\d{6})\b', s)
    return m.group(1) if m else ''


def _v1033_pick(d, keys):
    d = _v1033_dict(d)
    for k in keys:
        try:
            v = d.get(k)
            sv = _v1033_s(v)
            if sv and sv not in ('-', 'nan', 'None'):
                return sv
        except Exception:
            pass
    return ''


def _v1033_extract_name_code(lines=None, row=None):
    d = _v1033_dict(row or {})
    name = _v1033_pick(d, ['종목명','Name','name','stock_name','종목','회사명'])
    code = _v1033_code(_v1033_pick(d, ['code','Code','종목코드','ticker','티커']))

    src = []
    try:
        src.extend([_v1033_s(x) for x in (lines or [])])
    except Exception:
        pass
    # row 값에 이름/코드가 없을 때 카드 라인에서 추출
    for s in src:
        if not s:
            continue
        # 정상 마크다운/카드 헤더: [신한지주](055550), [신한지주](055550)(055550)
        m = re.search(r'^\s*\[?\s*([^\[\]\(\)\|]{1,30}?)\s*\]?\s*\(?\b(\d{6})\b\)?(?:\s*\(?\2\)?)*\s*$', s)
        if m:
            if not name: name = m.group(1).strip()
            if not code: code = m.group(2)
            break
        # 깨진 footer: [신한지주(055550)(055550)
        if s.startswith('[') and re.search(r'\b\d{6}\b', s) and len(s) <= 60:
            cs = re.findall(r'\b\d{6}\b', s)
            tmp = re.sub(r'\(?\b\d{6}\b\)?', '', s)
            tmp = tmp.replace('[','').replace(']','').replace('(','').replace(')','').strip()
            if tmp and not name: name = tmp
            if cs and not code: code = cs[0]
            break
    if name:
        # 이름 안에 코드가 섞인 경우 제거
        name = re.sub(r'\(?\b\d{6}\b\)?', '', name)
        name = name.replace('[','').replace(']','').replace('(','').replace(')','').strip()
        name = re.sub(r'\s+', ' ', name)
    return name, code


def _v1033_format_header(name, code):
    name = _v1033_s(name)
    code = _v1033_code(code)
    if name and code:
        return f"📌 {name}({code})"
    if name:
        return f"📌 {name}"
    if code:
        return f"📌 {code}"
    return ''


def _v1033_is_stock_header_or_footer(s):
    s = _v1033_s(s)
    if not s:
        return False
    if s.startswith('📌 '):
        return False
    # 정상/깨진 종목명+코드 라인은 본문에서 제거하고 헤더로만 1회 출력
    if re.match(r'^\s*\[?\s*[^\[\]\(\)\|]{1,35}\s*\]?\s*\(?\b\d{6}\b\)?(?:\s*\(?\d{6}\)?)*\s*\]?\s*$', s):
        # 수급/가격 같은 데이터 라인을 오인하지 않도록 짧은 라인만 제거
        return len(s) <= 65 and not any(ch in s for ch in ['|','/','원','현재','최근','기준가'])
    return False


def _v1033_fix_particle(match):
    name = match.group(1)
    # 아주 단순화: 종목명 뒤는 문장 가독성을 위해 '은/는' 대신 '은' 유지보다 '는'이 대체로 자연스러움
    return f"{name}는"


def _v1033_clean_line(s):
    try:
        s = _v1031_clean_text(s)
    except Exception:
        s = _v1033_s(s)
    if not s:
        return ''
    # 코드 중복 제거: (055550)(055550) -> (055550)
    s = re.sub(r'\((\d{6})\)\s*\(\1\)', r'(\1)', s)
    s = re.sub(r'\b(\d{6})\b\s*\(\1\)', r'\1', s)
    # 깨진 마크다운 잔재 정리: 하이브](352820)은 -> 하이브는
    s = re.sub(r'([가-힣A-Za-z0-9·&\.\- ]{1,30})\]\(\d{6}\)(은|는)', lambda m: _v1033_fix_particle(m), s)
    # 신한지주은/하이브은 같은 어색한 조사 완화
    s = re.sub(r'([가-힣A-Za-z0-9·&\.\-]{2,30})은 ', r'\1는 ', s)
    s = s.replace('기본 기준를', '기본 기준을')
    s = s.replace('기본 기준 확인 시', '기본 기준을 확인하면')
    s = s.replace('현재 원', '현재가 확인 필요')
    # 빈 괄호/중복 공백
    s = s.replace('접촉()', '접촉').replace('아래()', '아래').replace('위안착()', '위안착').replace('위확장()', '위확장')
    s = re.sub(r'\s{2,}', ' ', s).strip()
    return s


def _v1033_dedupe(lines):
    out, seen = [], set()
    for x in lines or []:
        s = _v1033_clean_line(x)
        if not s:
            continue
        k = re.sub(r'\s+', '', s)
        if k in seen:
            continue
        seen.add(k)
        out.append(s)
    return out

try:
    _V1033_BASE_COMPACT_CARD = _v102_compact_card
except Exception:
    _V1033_BASE_COMPACT_CARD = None


def _v1033_compact_card(seg, row=None):
    try:
        base = _V1033_BASE_COMPACT_CARD(seg, row=row) if _V1033_BASE_COMPACT_CARD else list(seg or [])
        raw_for_header = []
        try: raw_for_header.extend([_v1033_s(x) for x in (seg or [])])
        except Exception: pass
        try: raw_for_header.extend([_v1033_s(x) for x in (base or [])])
        except Exception: pass
        name, code = _v1033_extract_name_code(raw_for_header, row=row)
        header = _v1033_format_header(name, code)
        body = []
        for x in base or []:
            s = _v1033_clean_line(x)
            if not s:
                continue
            if _v1033_is_stock_header_or_footer(s):
                continue
            if s.startswith('⛔ 위험사유 카드'):
                continue
            if header and s == header:
                continue
            body.append(s)
        body = _v1033_dedupe(body)
        out = []
        if header:
            out.append(header)
            out.append('────────────────────')
        out.extend(body)
        return out
    except Exception:
        try:
            return _V1033_BASE_COMPACT_CARD(seg, row=row) if _V1033_BASE_COMPACT_CARD else list(seg or [])
        except Exception:
            return list(seg or [])

# 최신 카드 포맷을 기본으로 지정
_v102_compact_card = _v1033_compact_card
_v1026_compact_card = _v1033_compact_card
try:
    _v1031_compact_card = _v1033_compact_card
    _v1032_compact_card = _v1033_compact_card
except Exception:
    pass

try:
    _V1033_BASE_ACTION_FIRST_TEXT = _v102_action_first_text
except Exception:
    _V1033_BASE_ACTION_FIRST_TEXT = None

_V1033_RISK_NOTICE_SHOWN = False


def _v1033_env_bool(name, default=False):
    try:
        v = str(os.environ.get(name, '1' if default else '0')).strip().lower()
        return v in ('1','true','yes','on','y')
    except Exception:
        return default


def _v1033_cleanup_text(text):
    global _V1033_RISK_NOTICE_SHOWN
    s = str(text or '')
    removed = len(re.findall(r'^⛔ 위험사유 카드 .*$', s, flags=re.MULTILINE))
    s = re.sub(r'\n?⛔ 위험사유 카드 .*?(?:\n|$)', '\n', s)
    # 카드 하단에 남은 깨진 종목 footer 제거. 정상 헤더는 📌로 이미 재생성됨.
    s = re.sub(r'\n\[[^\n\[\]\|]{1,35}\(\d{6}\)(?:\(\d{6}\))*\]?\s*(?=\n|$)', '\n', s)
    s = re.sub(r'\((\d{6})\)\s*\(\1\)', r'(\1)', s)
    s = s.replace('기본 기준를', '기본 기준을')
    s = s.replace('현재 원', '현재가 확인 필요')
    # 빈 관찰형 참고 섹션 반복을 조금 줄임
    s = re.sub(r'(\[TEST\]\n)?👀 \[오늘의 관찰형 참고\]\n\n?────────────────────────────\n\s*(?=(?:\[TEST\]\n)?👀 \[오늘의 관찰형 참고\]|\[TEST\]|$)', '', s)
    if removed and _v1033_env_bool('SHOW_HIDDEN_RISK_NOTICE', False) and not _V1033_RISK_NOTICE_SHOWN:
        _V1033_RISK_NOTICE_SHOWN = True
        s = s.rstrip() + f"\n\n⛔ 위험사유 카드 {removed}개 숨김: SHOW_RISK_CARDS_IN_WATCH=1이면 표시"
    while '\n\n\n\n' in s:
        s = s.replace('\n\n\n\n', '\n\n\n')
    return s.strip('\n')


def _v102_action_first_text(text):
    try:
        base = _V1033_BASE_ACTION_FIRST_TEXT(text) if _V1033_BASE_ACTION_FIRST_TEXT else str(text or '')
        return _v1033_cleanup_text(base)
    except Exception:
        return _v1033_cleanup_text(text)

