print("✅ TRADE_CLARITY_V10_3_4_SIGNAL_LINK_CLEANUP_ACTIVE LOADED")
print("✅ TRADE_CLARITY_V10_3_5_SPEED_DEDUP_ACTIVE LOADED")


def _v1034_s(x):
    try:
        return _v1033_s(x)
    except Exception:
        return str(x or '').strip()


def _v1034_num(x, default=None):
    try:
        if x is None or x == '':
            return default
        if isinstance(x, str):
            x = x.replace(',', '').replace('%', '').replace('원', '').strip()
        return float(x)
    except Exception:
        return default


def _v1034_price(x):
    n = _v1034_num(x, None)
    if n is None or n <= 0:
        return ''
    return f"{n:,.0f}원"


def _v1034_angle_label(a):
    a = _v1034_num(a, 0) or 0
    if a >= 45: return '과속상승'
    if a >= 25: return '탄력상승'
    if a >= 10: return '완만상승'
    if a > -5: return '횡보/전환확인'
    if a > -20: return '완만조정'
    return '하락압력'


def _v1034_score_label(s):
    s = _v1034_num(s, 0) or 0
    if s >= 85: return '매우강함'
    if s >= 75: return '강함'
    if s >= 60: return '유효'
    if s >= 40: return '관찰'
    return '약함'


def _v1034_pick(d, keys):
    try:
        d = _v1033_dict(d)
    except Exception:
        d = d if isinstance(d, dict) else {}
    for k in keys:
        try:
            v = d.get(k)
            sv = _v1034_s(v)
            if sv and sv not in ('-', 'nan', 'None', '0', '0.0'):
                return v
        except Exception:
            pass
    return ''


def _v1034_parse_wave_lines(lines):
    """원본 리포트의 〰️ 소파동 / 📶 중파동 라인을 직접 파싱한다."""
    out = {}
    for raw in lines or []:
        s = _v1034_s(raw)
        if not s:
            continue
        label = None
        if '소파동' in s and ('박스' in s or '위치' in s):
            label = 'small'
        elif '중파동' in s and ('박스' in s or '위치' in s):
            label = 'mid'
        if not label:
            continue
        # 박스 243,500~278,000 | 위치 56%(중단권) | 횡보박스 -1.1°
        m_box = re.search(r'박스\s*([0-9,]+)\s*[~\-]\s*([0-9,]+)', s)
        if m_box:
            out[f'{label}_low'] = m_box.group(1)
            out[f'{label}_high'] = m_box.group(2)
        m_pos = re.search(r'위치\s*([0-9.]+)\s*%\s*\(([^\)]*)\)', s)
        if m_pos:
            out[f'{label}_pos'] = float(m_pos.group(1))
            out[f'{label}_label'] = m_pos.group(2).strip()
        # 각도: +39.0° 또는 -1.1°
        m_ang = re.search(r'([+\-]?[0-9.]+)\s*°', s)
        if m_ang:
            out[f'{label}_angle'] = float(m_ang.group(1))
    return out


def _v1034_row_wave(row=None, lines=None):
    d = None
    try:
        d = _v1033_dict(row or {})
    except Exception:
        d = {}
    parsed = _v1034_parse_wave_lines(lines or [])
    def val(keys, parsed_key, default=None):
        v = _v1034_pick(d, keys)
        if _v1034_s(v):
            return v
        return parsed.get(parsed_key, default)
    w = {
        'small_low': val(['소파동저점','small_low'], 'small_low', ''),
        'small_high': val(['소파동전고점','small_high'], 'small_high', ''),
        'small_pos': _v1034_num(val(['소파동위치퍼센트','small_pos_pct'], 'small_pos', None), None),
        'small_label': _v1034_s(val(['소파동위치권','소파동위치','small_pos_label','small_state'], 'small_label', '')),
        'small_angle': _v1034_num(val(['소파동각도','small_angle'], 'small_angle', None), None),
        'mid_low': val(['중파동저점','mid_low'], 'mid_low', ''),
        'mid_high': val(['중파동전고점','mid_high'], 'mid_high', ''),
        'mid_pos': _v1034_num(val(['중파동위치퍼센트','mid_pos_pct'], 'mid_pos', None), None),
        'mid_label': _v1034_s(val(['중파동위치권','중파동위치','mid_pos_label','mid_state'], 'mid_label', '')),
        'mid_angle': _v1034_num(val(['중파동각도','mid_angle'], 'mid_angle', None), None),
    }
    return w


def _v1034_wave_position(row=None, lines=None):
    w = _v1034_row_wave(row, lines)
    parts = []
    if w['small_pos'] is not None or _v1034_num(w['small_low'], 0) or _v1034_num(w['small_high'], 0):
        label = w['small_label'] or (_v1032_pos_label(w['small_pos']) if ' _v1032_pos_label' in globals() else '')
        pct = f"{w['small_pos']:.0f}%" if w['small_pos'] is not None else '위치확인'
        ang = f" / {w['small_angle']:.1f}° {_v1034_angle_label(w['small_angle'])}" if w['small_angle'] is not None else ''
        box = ''
        if _v1034_price(w['small_low']) and _v1034_price(w['small_high']):
            box = f" / 박스 {_v1034_price(w['small_low'])}~{_v1034_price(w['small_high'])}"
        parts.append(f"소파동 {label}({pct}){ang}{box}")
    if w['mid_pos'] is not None or _v1034_num(w['mid_low'], 0) or _v1034_num(w['mid_high'], 0):
        label = w['mid_label'] or (_v1032_pos_label(w['mid_pos']) if ' _v1032_pos_label' in globals() else '')
        pct = f"{w['mid_pos']:.0f}%" if w['mid_pos'] is not None else '위치확인'
        ang = f" / {w['mid_angle']:.1f}° {_v1034_angle_label(w['mid_angle'])}" if w['mid_angle'] is not None else ''
        box = ''
        if _v1034_price(w['mid_low']) and _v1034_price(w['mid_high']):
            box = f" / 박스 {_v1034_price(w['mid_low'])}~{_v1034_price(w['mid_high'])}"
        parts.append(f"중파동 {label}({pct}){ang}{box}")
    if not parts:
        return ''
    return '🌊 파동위치: ' + ' | '.join(parts[:2])


def _v1034_elliott(row=None, lines=None):
    d = None
    try: d = _v1033_dict(row or {})
    except Exception: d = {}
    w = _v1034_row_wave(row, lines)
    # 명시 점수 있으면 사용, 없으면 파동 위치 기반 추정만 사용한다.
    turn = _v1034_num(_v1034_pick(d, ['파동전환점수','trend_turn_score']), None)
    w1 = _v1034_num(_v1034_pick(d, ['파동1파점수','first_wave_score']), None)
    pb = _v1034_num(_v1034_pick(d, ['파동눌림점수','pullback_health_score']), None)
    restart = _v1034_num(_v1034_pick(d, ['파동재출발점수','restart_score']), None)
    sp, mp, sa = w['small_pos'], w['mid_pos'], w['small_angle']
    if all(v is None for v in [turn, w1, pb, restart]) and sp is None and mp is None:
        return '', ''
    if restart is not None and restart >= 70:
        label, why = '3파 초입/재출발 후보', '눌림 이후 다시 출발하려는 신호가 있습니다.'
    elif pb is not None and w1 is not None and pb >= 60 and w1 >= 50:
        label, why = '2파 눌림/LPS 확인 구간', '첫 상승 이후 눌림에서 지지를 확인하는 자리입니다.'
    elif sp is not None and mp is not None and sp >= 80 and mp >= 70:
        label, why = '5파/상단권 가능성', '소파동·중파동이 모두 높은 위치라 추격 부담이 큽니다.'
    elif sp is not None and mp is not None and sp >= 60 and mp < 60 and (sa or 0) >= 20:
        label, why = '3파 진행 가능성', '단기 탄력은 살아 있고 중파동은 아직 과열 전입니다.'
    elif sp is not None and sp >= 40 and sp < 75 and mp is not None and mp <= 60:
        label, why = '1파 진행 후 2파 눌림 대기', '초동 상승 뒤 기준선에서 지지 확인이 필요한 구간입니다.'
    elif sp is not None and sp < 40 and (mp is None or mp < 60):
        label, why = '1파 전환 후보', '하단권에서 반등을 시도하는 구간입니다.'
    else:
        label, why = '파동 카운트 관찰', '명확한 1·2·3파 조건은 부족해 기준선 지지가 더 중요합니다.'
    scores = []
    if turn is not None: scores.append(f"전환 {turn:.0f}({_v1034_score_label(turn)})")
    if w1 is not None: scores.append(f"1파 {w1:.0f}({_v1034_score_label(w1)})")
    if pb is not None: scores.append(f"눌림 {pb:.0f}({_v1034_score_label(pb)})")
    if restart is not None: scores.append(f"재출발 {restart:.0f}({_v1034_score_label(restart)})")
    detail = ' / '.join(scores) if scores else '위치 기반 추정'
    line = f"〰️ 엘리어트(추정): {label} | {detail} | 해석: {why}"
    if '3파' in label:
        easy = '📘 파동해설: 상승 탄력이 붙을 수 있는 구간입니다. 기준선 지지와 거래량 기준이 맞을 때만 분할 접근합니다.'
    elif '2파' in label or '눌림' in label:
        easy = '📘 파동해설: 실전 관심도가 높은 눌림 확인 구간입니다. 양봉 마감과 거래량 재유입을 봅니다.'
    elif '5파' in label or '상단' in label:
        easy = '📘 파동해설: 이미 많이 진행됐을 수 있어 신규 추격보다 눌림이나 이탈선 관리가 우선입니다.'
    elif '1파' in label:
        easy = '📘 파동해설: 상승 전환 초입일 수 있지만 아직 확인 전입니다. 첫 돌파와 거래량을 함께 봅니다.'
    else:
        easy = '📘 파동해설: 파동 카운트보다 5일선·파란점선 기준으로 단순하게 확인합니다.'
    return line, easy


def _v1034_wyckoff_valid(line):
    s = _v1034_s(line)
    if not s:
        return False
    bad = ['A/S/L 세부점수 미확인', '매집·돌파·재지지 증거가 더 필요', '현재는 세 요소의 균형을 추가 확인']
    if any(b in s for b in bad):
        return False
    if re.search(r'매집\s*0점|돌파힘\s*0점|눌림지지\s*0점', s) and not re.search(r'(60|7\d|8\d|9\d)점', s):
        return False
    return True


def _v1034_fix_blue(lines):
    # entry line에서 파란점선 기준가를 뽑아 산출불가 라인을 보정한다.
    blue_price = ''
    for s in lines:
        m = re.search(r'파란점선\s*([0-9,]+원)', _v1034_s(s))
        if m:
            blue_price = m.group(1); break
    out = []
    for s in lines:
        t = _v1034_s(s)
        if t.startswith('🔵 파란점선 기준:'):
            if '산출불가' in t and blue_price:
                # 기존 판단 문구는 유지
                judge = ''
                m = re.search(r'판단:\s*(.*)$', t)
                if m: judge = m.group(1).strip()
                t = f'🔵 파란점선 기준: 기준가 {blue_price}' + (f' | 판단: {judge}' if judge else '')
            t = t.replace(' | 현재가 확인 필요', '')
        out.append(t)
    return out


def _v1034_clean_korean(s):
    s = _v1034_s(s)
    fixes = {
        '가격는': '가격은', '거래량는': '거래량은', '저항구름는': '저항구름은',
        '소파동는': '소파동은', '중파동는': '중파동은', '매집 흔적는': '매집 흔적은',
        '흔적는': '흔적은', 'PER는': 'PER은', 'PBR는': 'PBR은', 'ROE는': 'ROE는',
        '부담는': '부담은', '효율는': '효율은', '한화오션는': '한화오션은',
        '비에이치아이은': '비에이치아이는', 'NAVER는': 'NAVER는',
    }
    for a,b in fixes.items(): s = s.replace(a,b)
    # 일반명사 조사 보정
    s = re.sub(r'(가격|거래량|저항구름|소파동|중파동|매집 흔적|PER|PBR|부담|효율)는', r'\1은', s)
    s = s.replace('기본 기준을 확인하면 관심도 상승', '기본 기준을 충족하면 관심도 상승')
    s = s.replace('기본 기준을 만족할 때만', '기본 기준을 충족할 때만')
    return s

try:
    _V1034_BASE_COMPACT_CARD = _v102_compact_card
except Exception:
    _V1034_BASE_COMPACT_CARD = None


def _v1034_compact_card(seg, row=None):
    try:
        raw = []
        try: raw.extend([_v1034_s(x) for x in (seg or [])])
        except Exception: pass
        base = _V1034_BASE_COMPACT_CARD(seg, row=row) if _V1034_BASE_COMPACT_CARD else list(seg or [])
        try: raw.extend([_v1034_s(x) for x in (base or [])])
        except Exception: pass
        # 파동 라인 재계산
        wave_line = _v1034_wave_position(row, raw)
        elliott_line, wave_easy = _v1034_elliott(row, raw)
        out = []
        inserted_wave = False
        skip_next_wave_easy = False
        wyckoff_line_present = False
        for x in base or []:
            s = _v1034_clean_korean(_v1034_s(x))
            if not s:
                continue
            # 신뢰 불가/기본값 파동 라인은 제거
            if s.startswith('🌊 파동위치:'):
                if wave_line and not inserted_wave:
                    out.append(wave_line); inserted_wave = True
                    if elliott_line: out.append(elliott_line)
                    if wave_easy: out.append(wave_easy)
                skip_next_wave_easy = True
                continue
            if s.startswith('〰️ 엘리어트'):
                if not inserted_wave and wave_line:
                    out.append(wave_line); inserted_wave = True
                    if elliott_line: out.append(elliott_line)
                    if wave_easy: out.append(wave_easy)
                skip_next_wave_easy = True
                continue
            if s.startswith('📘 파동해설'):
                if skip_next_wave_easy:
                    skip_next_wave_easy = False
                    continue
                if not wave_line:
                    continue
            # 와이코프가 실제 점수 없이 일반 설명만 나오면 숨김
            if s.startswith('📦 와이코프'):
                if _v1034_wyckoff_valid(s):
                    out.append(s); wyckoff_line_present = True
                continue
            if s.startswith('📘 와이코프 해설'):
                if wyckoff_line_present and _v1034_wyckoff_valid(s):
                    out.append(s)
                continue
            # 재무 미계산인데 수치가 있으면 재무 참고로 완화
            if s.startswith('🏢 기업정보: 재무 미계산') and re.search(r'PER\s*(?!-)|PBR\s*(?!-)|EPS\s*(?!-)', s):
                s = s.replace('재무 미계산', '재무 참고')
            out.append(s)
            if (not inserted_wave) and wave_line and s.startswith('🔥 끼/흥행성'):
                out.append(wave_line); inserted_wave = True
                if elliott_line: out.append(elliott_line)
                if wave_easy: out.append(wave_easy)
        if not inserted_wave and wave_line:
            pos = len(out)
            for i, s in enumerate(out):
                if s.startswith(('🏢 기업정보','🔵 파란점선','📍 타점요약','🏦 수급')):
                    pos = i; break
            out[pos:pos] = [wave_line] + ([elliott_line] if elliott_line else []) + ([wave_easy] if wave_easy else [])
        out = _v1034_fix_blue(out)
        # 중복/빈값 정리
        clean, seen = [], set()
        for s in out:
            s = _v1034_clean_korean(s)
            if not s or s in ('[TEST]',):
                continue
            if '현재가 확인 필요' in s and s.startswith('🔵'):
                s = s.replace(' | 현재가 확인 필요', '')
            k = re.sub(r'\s+', '', s)
            if k in seen: continue
            seen.add(k); clean.append(s)
        return clean
    except Exception:
        try:
            return _V1034_BASE_COMPACT_CARD(seg, row=row) if _V1034_BASE_COMPACT_CARD else list(seg or [])
        except Exception:
            return list(seg or [])

_v102_compact_card = _v1034_compact_card
