try:
    _V1034_BASE_CLEANUP_TEXT = _v1033_cleanup_text
except Exception:
    _V1034_BASE_CLEANUP_TEXT = None


def _v1034_cleanup_text(text):
    s = _V1034_BASE_CLEANUP_TEXT(text) if _V1034_BASE_CLEANUP_TEXT else str(text or '')
    s = _v1034_clean_korean(s)
    # 파동/엘리어트가 기본값으로 떨어진 라인은 완전히 제거
    s = re.sub(r'\n?🌊 파동위치: 소파동/중파동 위치 데이터 확인 필요\n?', '\n', s)
    s = re.sub(r'\n?〰️ 엘리어트\(추정\): 1파 전환 후보 \| 전환 0\(약함\) / 1파 0\(약함\) / 눌림 0\(약함\) / 재출발 0\(약함\) \| 해석: 하단권에서 반등 확인이 필요한 자리\n?', '\n', s)
    s = re.sub(r'\n?📘 파동해설: 상승 전환 초입일 수 있지만 아직 확인 전입니다\. 첫 돌파와 거래량이 붙는지 봅니다\.\n?', '\n', s)
    # 일반 와이코프 해설만 남는 경우 제거
    s = re.sub(r'\n?📘 와이코프 해설: 와이코프는 매집, 돌파힘, 눌림지지 순서로 봅니다\. 현재는 세 요소의 균형을 추가 확인해야 합니다\.\n?', '\n', s)
    # 빈 TEST 반복 제거
    s = re.sub(r'(?:\n?\[TEST\]\s*){2,}', '\n[TEST]\n', s)
    s = re.sub(r'\n\[TEST\]\n(?=\[TEST\]|\s*$)', '\n', s)
    while '\n\n\n\n' in s:
        s = s.replace('\n\n\n\n', '\n\n\n')
    return s.strip('\n')

try:
    _V1034_BASE_ACTION_FIRST_TEXT = _v102_action_first_text
except Exception:
    _V1034_BASE_ACTION_FIRST_TEXT = None


def _v102_action_first_text(text):
    try:
        base = _V1034_BASE_ACTION_FIRST_TEXT(text) if _V1034_BASE_ACTION_FIRST_TEXT else str(text or '')
        return _v1034_cleanup_text(base)
    except Exception:
        return _v1034_cleanup_text(text)

