def _v1036_env_on(name, default='1'):
    try:
        return str(os.getenv(name, default)).strip().lower() not in ('0', 'false', 'no', 'off', '')
    except Exception:
        return str(default).strip() not in ('0', '')


def _v1036_clean_message(message):
    """가벼운 문자열 정리만 수행한다. 무거운 정규식 후처리는 하지 않는다."""
    try:
        s = str(message or '')
    except Exception:
        s = ''
    if not s.strip():
        return ''

    # 단독 [TEST] 라인 반복 제거
    out = []
    blank = False
    for line in s.splitlines():
        t = line.strip()
        if t == '[TEST]':
            continue
        if not t:
            if blank:
                continue
            blank = True
            out.append('')
            continue
        blank = False
        out.append(line.rstrip())
    s = '\n'.join(out).strip()

    # 조사/문구 보정
    repl = {
        '가격는': '가격은', '거래량는': '거래량은', '저항구름는': '저항구름은',
        '소파동는': '소파동은', '중파동는': '중파동은', '흔적는': '흔적은',
        'PER는': 'PER은', 'PBR는': 'PBR은', '부담는': '부담은', '효율는': '효율은',
        '기본 기준를': '기본 기준을', '기본 기준을 만족': '기본 기준을 충족',
    }
    for a, b in repl.items():
        s = s.replace(a, b)
    return s.strip()


def _v1036_effectively_empty(s):
    t = str(s or '').strip()
    if not t:
        return True
    t = t.replace('━', '').replace('─', '').replace('[TEST]', '').strip()
    return not t


