def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    msg = _v1036_clean_message(message)
    if _v1036_effectively_empty(msg):
        return None
    # FAST 모드에서는 긴 원문 상세 섹션을 보내지 않는다.
    if _v1036_env_on('STOCKHUNTER_FAST_REPORT', '1'):
        legacy_heads = [
            '🍉 [수박 상태 가이드]', '🍉 [수박 상태 요약]', '🍉 [수박상태 빨강 TOP 5]',
            '🍉 [파란점선 타점 TOP 5]', '🧭 [선취 후보 TOP 5]', '🧭 [선취 관찰 후보 TOP 5]',
            '🚀 [흰구름 돌파 후보 TOP 5]', '🚀 [흰구름 돌파 관찰 TOP 5]', '🧭 [선취 제외 후보 TOP 5]',
            '🍉 [초입수박 TOP 5]', '🍉 [눌림수박 TOP 5]', '🍉 [후행수박 TOP 5]',
            '🍉 [Blue-1 단기 TOP 5]', '🍉 [Blue-2 예비 TOP 5]', '🍉 [Blue-2 스윙 TOP 5]',
        ]
        if any(h in msg for h in legacy_heads):
            return None
    if _V1036_BASE_SEND_TELEGRAM_CHUNKS:
        return _V1036_BASE_SEND_TELEGRAM_CHUNKS(msg, title=title, max_len=max_len)
    return None


def send_telegram_photo(message, image_paths=[]):
    msg = _v1036_clean_message(message)
    if _v1036_effectively_empty(msg):
        return None
    if _v1036_env_on('STOCKHUNTER_FAST_REPORT', '1') and '📢 [오늘의 실시간 TOP 15]' in msg:
        return None
    if _V1036_BASE_SEND_TELEGRAM_PHOTO:
        return _V1036_BASE_SEND_TELEGRAM_PHOTO(msg, image_paths)
    return None

