# ✅ TRADE_CLARITY_V10_4_0_DETAIL_SYNC_ACTIVE
# - 오늘 매매관점 압축 후보와 상세카드 후보를 1:1 동기화
# - 압축 리스트에 없는 상세카드는 기본 숨김하여 속도/가독성 개선
# - 같은 종목 상세카드 중복 전송 차단
# - 실행제외형 40~49점 표기를 보류형으로 완화
# =============================================================
print("✅ TRADE_CLARITY_V10_4_0_DETAIL_SYNC_ACTIVE LOADED")

try:
    _V1040_BASE_SEND_TELEGRAM_CHUNKS = send_telegram_chunks
except Exception:
    _V1040_BASE_SEND_TELEGRAM_CHUNKS = None
try:
    _V1040_BASE_SEND_TELEGRAM_PHOTO = send_telegram_photo
except Exception:
    _V1040_BASE_SEND_TELEGRAM_PHOTO = None

_V1040_ACTION_CODES = []
_V1040_SENT_DETAIL_CODES = set()
_V1040_SECTION_SENT = {'watch': 0, 'pre': 0, 'top': 0, 'late': 0}

def _v1040_env_on(name: str, default: str = '0') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return False

def _v1040_env_int(name: str, default: int) -> int:
    try:
        return int(str(os.getenv(name, str(default))).strip())
    except Exception:
        return default

def _v1040_codes_from_text(text: str):
    try:
        return re.findall(r'\(([0-9]{6})\)', str(text or ''))
    except Exception:
        return []

def _v1040_remember_action_codes(msg: str):
    global _V1040_ACTION_CODES
    s = str(msg or '')
    if '🎯 [오늘 매매관점 압축]' not in s and '🟡 [관찰 후보]' not in s:
        return
    codes = _v1040_codes_from_text(s)
    if not codes:
        return
    old = list(_V1040_ACTION_CODES or [])
    for c in codes:
        if c not in old:
            old.append(c)
    _V1040_ACTION_CODES = old[:_v1040_env_int('ACTION_DETAIL_POOL_LIMIT', 14)]

def _v1040_kind(msg: str):
    s = str(msg or '')
    if '👀 [오늘의 관찰형 참고]' in s:
        return 'watch'
    if '🛡️ [오늘의 후행형 참고]' in s:
        return 'late'
    if '📌 [오늘의 선취형 후보]' in s:
        return 'pre'
    if '📢 [오늘의 실시간 TOP 15]' in s:
        return 'top'
    return None

def _v1040_primary_code(msg: str):
    codes = _v1040_codes_from_text(msg)
    return codes[0] if codes else ''

def _v1040_is_detail_card(msg: str) -> bool:
    s = str(msg or '')
    if _v1040_kind(s) is None:
        return False
    return ('⭐' in s or '💰 현재가:' in s or '점수:' in s or '📌 목표1:' in s)

def _v1040_should_send_synced_detail(msg: str) -> bool:
    if _v1040_env_on('SHOW_ALL_DETAIL_CARDS', '0'):
        return True
    if not _v1040_env_on('DETAIL_SYNC_WITH_ACTION', '1'):
        return True
    if not _v1040_is_detail_card(msg):
        return True
    code = _v1040_primary_code(msg)
    if not code:
        return True
    if not _V1040_ACTION_CODES:
        return True
    if code not in _V1040_ACTION_CODES:
        return False
    top_n = _v1040_env_int('ACTION_DETAIL_LIMIT', 6)
    if code not in _V1040_ACTION_CODES[:top_n]:
        return False
    if code in _V1040_SENT_DETAIL_CODES:
        return False
    kind = _v1040_kind(msg) or 'watch'
    _V1040_SENT_DETAIL_CODES.add(code)
    _V1040_SECTION_SENT[kind] = _V1040_SECTION_SENT.get(kind, 0) + 1
    return True

def _v1040_normalize_output(msg: str) -> str:
    s = str(msg or '')
    def _exec_soft(m):
        try:
            score = int(m.group(1))
        except Exception:
            score = 0
        if 40 <= score <= 49:
            return f'🚦 실행판정: 보류형 {score}/100 | 확인 전 신규 실행 보류'
        return m.group(0)
    s = re.sub(r'🚦\s*실행판정:\s*실행제외형\s*(\d{1,3})/100\s*\|\s*신규 실행 제외', _exec_soft, s)
    s = re.sub(r'📦\s*와이코프:\s*UTAD/실패돌파 주의\s*(4[0-9])/100', r'📦 와이코프: UTAD/실패돌파 점검 \1/100', s)
    s = re.sub(r'(?m)^\s*\[TEST\]\s*$', '', s)
    s = re.sub(r'\n{4,}', '\n\n\n', s)
    return s.strip()

def _v1040_clean_outgoing(msg):
    try:
        s = _v1039_clean_outgoing(msg)
    except Exception:
        s = str(msg or '')
    s = _v1040_normalize_output(s)
    _v1040_remember_action_codes(s)
    return s.strip()

def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    msg = _v1040_clean_outgoing(message)
    try:
        if _v1036_effectively_empty(msg):
            return None
    except Exception:
        if not msg:
            return None
    if not _v1040_should_send_synced_detail(msg):
        return None
    if _V1040_BASE_SEND_TELEGRAM_CHUNKS:
        return _V1040_BASE_SEND_TELEGRAM_CHUNKS(msg, title=title, max_len=max_len)
    return None

def send_telegram_photo(message, image_paths=[]):
    msg = _v1040_clean_outgoing(message)
    try:
        if _v1036_effectively_empty(msg):
            return None
    except Exception:
        if not msg:
            return None
    if not _v1040_should_send_synced_detail(msg):
        return None
    if _V1040_BASE_SEND_TELEGRAM_PHOTO:
        return _V1040_BASE_SEND_TELEGRAM_PHOTO(msg, image_paths)
    return None

# =============================================================
# ✅ END TRADE_CLARITY_V10_4_0_DETAIL_SYNC_ACTIVE
# =============================================================



# =============================================================
# ✅ TRADE_CLARITY_V10_4_1_DETAIL_CARD_FILTER_ACTIVE
# - V1040 보강: 한 메시지 안에 여러 상세카드가 묶여 있어도 종목별로 분해 후 필터링
# - 오늘 매매관점 압축에 나온 종목명/코드 기준으로 상세카드만 전송
# - 카드 제목에 코드가 없는 형식([하이브])도 압축 리스트의 종목명→코드 매핑으로 동기화
# - 상세카드/상세블록은 유지하되, 압축 후보 밖의 상세카드는 숨겨 속도 개선
# =============================================================
print("✅ TRADE_CLARITY_V10_4_1_DETAIL_CARD_FILTER_ACTIVE LOADED")

try:
    _V1041_BASE_SEND_TELEGRAM_CHUNKS = send_telegram_chunks
except Exception:
    _V1041_BASE_SEND_TELEGRAM_CHUNKS = None
try:
    _V1041_BASE_SEND_TELEGRAM_PHOTO = send_telegram_photo
except Exception:
    _V1041_BASE_SEND_TELEGRAM_PHOTO = None

_V1041_ACTION_ITEMS = []       # [{'code':'055550','name':'신한지주'}, ...]
_V1041_SENT_DETAIL_CODES = set()


def _v1041_s(x):
    try:
        return str(x or '').strip()
    except Exception:
        return ''


def _v1041_norm_name(name: str) -> str:
    s = _v1041_s(name)
    s = re.sub(r'^[\s\[\]⭐👑💎🚀🌌🎯S\+]+', '', s)
    s = re.sub(r'\s+', '', s)
    return s


def _v1041_env_on(name: str, default: str = '0') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return False


def _v1041_env_int(name: str, default: int) -> int:
    try:
        return int(str(os.getenv(name, str(default))).strip())
    except Exception:
        return default


def _v1041_codes_from_text(text: str):
    try:
        return re.findall(r'\(([0-9]{6})\)', str(text or ''))
    except Exception:
        return []


def _v1041_stock_name_from_card(text: str) -> str:
    """상세카드 제목의 [종목명] 추출. [오늘의 ...] 같은 섹션 제목은 제외."""
    try:
        s = str(text or '')
        m = re.search(r'(?m)^\s*⭐[^\n]*\[([^\]\n]+)\]', s)
        if m:
            nm = _v1041_s(m.group(1))
            if nm and '오늘' not in nm and '후보' not in nm and '참고' not in nm:
                return nm
        # 보조: 번호형 상세가 들어오는 경우
        m = re.search(r'(?m)^\s*\d+\)\s*([^\(\|\n]+)\(([0-9]{6})\)', s)
        if m:
            return _v1041_s(m.group(1))
    except Exception:
        pass
    return ''


def _v1041_remember_action_items(msg: str):
    """오늘 매매관점 압축에서 종목명/코드 순서를 기억한다."""
    global _V1041_ACTION_ITEMS, _V1040_ACTION_CODES
    try:
        s = str(msg or '')
        if '🎯 [오늘 매매관점 압축]' not in s and '🟡 [관찰 후보]' not in s:
            return
        found = []
        # 1) 압축 블록: 1) 신한지주(055550) | 현재 ...
        for m in re.finditer(r'(?m)^\s*\d+\)\s*([^\(\|\n]+)\(([0-9]{6})\)', s):
            name = _v1041_s(m.group(1))
            code = _v1041_s(m.group(2)).zfill(6)
            if name and code:
                found.append({'name': name, 'code': code})
        # 2) 후보 카드형 예외: 📌 신한지주(055550)
        for m in re.finditer(r'(?m)^\s*📌\s*([^\(\|\n]+)\(([0-9]{6})\)', s):
            name = _v1041_s(m.group(1))
            code = _v1041_s(m.group(2)).zfill(6)
            if name and code:
                found.append({'name': name, 'code': code})
        if not found:
            return
        old = list(_V1041_ACTION_ITEMS or [])
        seen = {x.get('code') for x in old if x.get('code')}
        for it in found:
            if it['code'] not in seen:
                old.append(it)
                seen.add(it['code'])
        limit = _v1041_env_int('ACTION_DETAIL_POOL_LIMIT', 14)
        _V1041_ACTION_ITEMS = old[:limit]
        # V1040 전역도 같이 보강해서 기존 로직과 호환
        try:
            cur = list(globals().get('_V1040_ACTION_CODES', []) or [])
            for it in _V1041_ACTION_ITEMS:
                if it['code'] not in cur:
                    cur.append(it['code'])
            _V1040_ACTION_CODES = cur[:limit]
        except Exception:
            pass
    except Exception:
        return


def _v1041_action_code_by_name(name: str) -> str:
    nn = _v1041_norm_name(name)
    if not nn:
        return ''
    for it in _V1041_ACTION_ITEMS or []:
        if _v1041_norm_name(it.get('name')) == nn:
            return it.get('code', '')
    return ''


def _v1041_code_for_detail_card(card: str) -> str:
    codes = _v1041_codes_from_text(card)
    if codes:
        return codes[0]
    name = _v1041_stock_name_from_card(card)
    if name:
        return _v1041_action_code_by_name(name)
    return ''


def _v1041_allowed_action_codes():
    try:
        limit = _v1041_env_int('ACTION_DETAIL_LIMIT', 6)
        codes = [it.get('code') for it in (_V1041_ACTION_ITEMS or []) if it.get('code')]
        if not codes:
            codes = list(globals().get('_V1040_ACTION_CODES', []) or [])
        return codes[:limit]
    except Exception:
        return []


def _v1041_is_detail_message(msg: str) -> bool:
    s = str(msg or '')
    if not any(k in s for k in ['📢 [오늘의 실시간 TOP 15]', '📌 [오늘의 선취형 후보]', '👀 [오늘의 관찰형 참고]', '🛡️ [오늘의 후행형 참고]']):
        return False
    return ('⭐' in s and ('💰 현재가:' in s or '점수:' in s or '📌 목표1:' in s or '🪜 유형:' in s))


def _v1041_split_star_cards(msg: str):
    """섹션 헤더 + ⭐ 카드들을 분리한다. 반환: (header, [card...])"""
    s = str(msg or '')
    try:
        # 카드 시작: 구분선 다음 ⭐ 또는 줄 시작 ⭐
        pat = re.compile(r'(?ms)(?:^\s*────────────────────────────\s*\n)?^\s*⭐ .+?(?=^\s*────────────────────────────\s*\n\s*⭐ |^\s*⭐ |\Z)')
        matches = list(pat.finditer(s))
        if not matches:
            return s, []
        header = s[:matches[0].start()].strip()
        cards = [m.group(0).strip() for m in matches if m.group(0).strip()]
        return header, cards
    except Exception:
        return s, []


def _v1041_filter_detail_cards(msg: str) -> str:
    """여러 종목이 묶인 상세 메시지에서 오늘 매매관점 압축 후보의 상세카드만 남긴다."""
    try:
        s = str(msg or '').strip()
        if not s:
            return ''
        if _v1041_env_on('SHOW_ALL_DETAIL_CARDS', '0'):
            return s
        if not _v1041_env_on('DETAIL_SYNC_WITH_ACTION', '1'):
            return s
        if not _v1041_is_detail_message(s):
            return s

        allowed = _v1041_allowed_action_codes()
        # 압축 블록이 아직 전송 전이면 안전하게 원문 유지
        if not allowed:
            return s

        header, cards = _v1041_split_star_cards(s)
        if not cards:
            return s

        kept = []
        for card in cards:
            code = _v1041_code_for_detail_card(card)
            if not code:
                # 코드/종목명 매칭이 안 되는 상세카드는 동기화 모드에서 숨김
                continue
            if code not in allowed:
                continue
            if code in _V1041_SENT_DETAIL_CODES:
                continue
            _V1041_SENT_DETAIL_CODES.add(code)
            try:
                globals().setdefault('_V1040_SENT_DETAIL_CODES', set()).add(code)
            except Exception:
                pass
            kept.append(card)

        if not kept:
            return ''
        out = []
        if header:
            out.append(header)
        out.extend(kept)
        return '\n\n'.join(out).strip()
    except Exception:
        return str(msg or '').strip()


def _v1041_clean_outgoing(msg):
    try:
        s = _v1040_clean_outgoing(msg)
    except Exception:
        try:
            s = _v1039_clean_outgoing(msg)
        except Exception:
            s = str(msg or '')
    _v1041_remember_action_items(s)
    s = _v1041_filter_detail_cards(s)
    # 카드 필터 후 남은 TEST/공백 정리
    s = re.sub(r'(?m)^\s*\[TEST\]\s*$', '', str(s or ''))
    s = re.sub(r'\n{4,}', '\n\n\n', s)
    return s.strip()


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    msg = _v1041_clean_outgoing(message)
    try:
        if _v1036_effectively_empty(msg):
            return None
    except Exception:
        if not msg:
            return None
    if _V1041_BASE_SEND_TELEGRAM_CHUNKS:
        return _V1041_BASE_SEND_TELEGRAM_CHUNKS(msg, title=title, max_len=max_len)
    return None


def send_telegram_photo(message, image_paths=[]):
    msg = _v1041_clean_outgoing(message)
    try:
        if _v1036_effectively_empty(msg):
            return None
    except Exception:
        if not msg:
            return None
    if _V1041_BASE_SEND_TELEGRAM_PHOTO:
        return _V1041_BASE_SEND_TELEGRAM_PHOTO(msg, image_paths)
    return None

# =============================================================
# ✅ END TRADE_CLARITY_V10_4_1_DETAIL_CARD_FILTER_ACTIVE
# =============================================================


# =============================================================
# ✅ TRADE_CLARITY_V10_4_2_SAFE_TELEGRAM_SPLIT_ACTIVE
# - V1041 보강: 4000자 hard slice 때문에 카드가 중간에서 잘리는 문제 방지
# - 오늘 매매관점 압축처럼 내부 구분선이 없는 긴 블록도 번호/카드 단위로 안전 분할
# - send_telegram_photo 직접 호출도 3900자 이하로 재분할 후 전송
# =============================================================
print("✅ TRADE_CLARITY_V10_4_2_SAFE_TELEGRAM_SPLIT_ACTIVE LOADED")

try:
    _V1042_BASE_SEND_TELEGRAM_CHUNKS = send_telegram_chunks
except Exception:
    _V1042_BASE_SEND_TELEGRAM_CHUNKS = None
try:
    _V1042_BASE_SEND_TELEGRAM_PHOTO = send_telegram_photo
except Exception:
    _V1042_BASE_SEND_TELEGRAM_PHOTO = None

_V1042_SAFE_MAX = 3600


def _v1042_safe_int(x, default=3600):
    try:
        v = int(str(x).strip())
        return max(1000, min(v, 3900))
    except Exception:
        return default


def _v1042_clean_before_split(message):
    try:
        s = _v1041_clean_outgoing(message)
    except Exception:
        try:
            s = _v1040_clean_outgoing(message)
        except Exception:
            s = str(message or '')
    try:
        s = re.sub(r'(?m)^\s*\[TEST\]\s*$', '', str(s or ''))
        s = re.sub(r'\n{4,}', '\n\n\n', s)
    except Exception:
        pass
    return str(s or '').strip()


def _v1042_is_unit_start(line: str) -> bool:
    """긴 텍스트를 자를 때 새 묶음으로 볼 줄인지 판단한다."""
    try:
        t = str(line or '').strip()
        if not t:
            return False
        if re.match(r'^\d+\)\s+.+\([0-9]{6}\)', t):
            return True
        if t.startswith('⭐ '):
            return True
        if t.startswith('────────────────'):
            return True
        if t.startswith('━━━━━━━━━━━━━━━━'):
            return True
        if re.match(r'^[🎯🟡🔥👀🛡️📌📢🏆🔄🌍📰🇺🇸]', t) and '[' in t and ']' in t:
            return True
    except Exception:
        pass
    return False


def _v1042_group_units(text: str):
    """번호형 후보/상세카드를 가능하면 한 묶음으로 유지한다."""
    lines = str(text or '').splitlines()
    units, cur = [], []
    for line in lines:
        if cur and _v1042_is_unit_start(line):
            units.append('\n'.join(cur).rstrip())
            cur = [line]
        else:
            cur.append(line)
    if cur:
        units.append('\n'.join(cur).rstrip())
    return [u for u in units if str(u or '').strip()]


def _v1042_split_long_unit(unit: str, max_len: int):
    """한 종목 카드 자체가 너무 길 때만 줄 단위로 추가 분할한다."""
    s = str(unit or '')
    if len(s) <= max_len:
        return [s]
    out, cur = [], ''
    for line in s.splitlines():
        line = str(line or '')
        candidate = (cur + '\n' + line).strip() if cur else line
        if len(candidate) > max_len and cur.strip():
            out.append(cur.strip())
            cur = line
        else:
            cur = candidate
        # 극단적으로 한 줄이 3900자를 넘을 때만 문자 단위 분할
        while len(cur) > max_len:
            out.append(cur[:max_len].rstrip())
            cur = cur[max_len:].lstrip()
    if cur.strip():
        out.append(cur.strip())
    return out


def _v1042_safe_split_message(message: str, max_len: int = None):
    max_len = _v1042_safe_int(max_len or _V1042_SAFE_MAX, _V1042_SAFE_MAX)
    s = str(message or '').strip()
    if not s:
        return []
    if len(s) <= max_len:
        return [s]

    units = []
    for u in _v1042_group_units(s):
        units.extend(_v1042_split_long_unit(u, max_len))

    chunks, cur = [], ''
    for unit in units:
        unit = str(unit or '').strip()
        if not unit:
            continue
        candidate = (cur + '\n\n' + unit).strip() if cur else unit
        if len(candidate) > max_len and cur.strip():
            chunks.append(cur.strip())
            cur = unit
        else:
            cur = candidate
    if cur.strip():
        chunks.append(cur.strip())

    # 혹시라도 남은 초과 청크는 최종 줄분할
    final = []
    for c in chunks:
        if len(c) <= max_len:
            final.append(c)
        else:
            final.extend(_v1042_split_long_unit(c, max_len))
    return [c for c in final if str(c or '').strip()]


def _v1042_direct_send_text(text: str):
    """기존 텔레그램 전송기를 사용하되, 4000자 이하 청크만 넘긴다."""
    if not str(text or '').strip():
        return None
    if _V1042_BASE_SEND_TELEGRAM_PHOTO:
        return _V1042_BASE_SEND_TELEGRAM_PHOTO(str(text or '').strip(), [])
    return None


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    msg = _v1042_clean_before_split(message)
    try:
        if _v1036_effectively_empty(msg):
            return None
    except Exception:
        if not msg:
            return None
    if title:
        msg = (str(title).strip() + '\n\n' + msg).strip()
    safe_len = min(_v1042_safe_int(max_len, 3800), _V1042_SAFE_MAX)
    chunks = _v1042_safe_split_message(msg, safe_len)
    total = len(chunks)
    for idx, chunk in enumerate(chunks, 1):
        out = chunk
        if total > 1:
            out = f"({idx}/{total})\n" + out
        _v1042_direct_send_text(out)
    return None


def send_telegram_photo(message, image_paths=[]):
    msg = _v1042_clean_before_split(message)
    try:
        if _v1036_effectively_empty(msg):
            return None
    except Exception:
        if not msg:
            return None

    # 사진이 있는 경우 캡션 1000자 제한을 고려해 텍스트만 안전 분할 후, 이미지는 마지막 호출에 맡긴다.
    # 현재 프로젝트의 주요 호출은 텍스트 전송이므로 텍스트 보호를 우선한다.
    if len(msg) <= _V1042_SAFE_MAX:
        if _V1042_BASE_SEND_TELEGRAM_PHOTO:
            return _V1042_BASE_SEND_TELEGRAM_PHOTO(msg, image_paths)
        return None

    chunks = _v1042_safe_split_message(msg, _V1042_SAFE_MAX)
    total = len(chunks)
    for idx, chunk in enumerate(chunks, 1):
        out = f"({idx}/{total})\n{chunk}" if total > 1 else chunk
        # 긴 메시지 분할 시 이미지를 매 청크마다 붙이지 않는다.
        _v1042_direct_send_text(out)
    # 이미지가 따로 있으면 짧은 알림과 함께 한 번만 전송
    if image_paths and _V1042_BASE_SEND_TELEGRAM_PHOTO:
        try:
            return _V1042_BASE_SEND_TELEGRAM_PHOTO('📎 첨부 이미지', image_paths)
        except Exception:
            return None
    return None


