def _v1043_df_nonempty(df):
    try:
        return df is not None and hasattr(df, 'empty') and (not df.empty)
    except Exception:
        return False


def _v1043_norm_code_value(v):
    try:
        s = str(v or '').strip()
        if s.endswith('.0'):
            s = s[:-2]
        s = re.sub(r'[^0-9]', '', s)
        return s.zfill(6) if s else ''
    except Exception:
        return ''


def _v1043_normalize_target_df(df):
    """상세카드 루프가 요구하는 최소 컬럼을 안전하게 맞춘다."""
    try:
        import pandas as _pd
        if df is None:
            return _pd.DataFrame()
        out = df.copy()
        if not hasattr(out, 'columns'):
            return _pd.DataFrame()

        # 종목명 보정
        if '종목명' not in out.columns:
            for c in ['Name', 'name', '종목', '종목명칭']:
                if c in out.columns:
                    out['종목명'] = out[c]
                    break
        if '종목명' not in out.columns:
            out['종목명'] = ''

        # 코드 보정
        if 'code' not in out.columns:
            for c in ['Code', '종목코드', '티커', 'ticker']:
                if c in out.columns:
                    out['code'] = out[c]
                    break
        if 'code' not in out.columns:
            out['code'] = ''
        out['code'] = out['code'].map(_v1043_norm_code_value)

        # 현재가 보정
        if '현재가' not in out.columns:
            for c in ['Close', 'close', '종가', '현재가격']:
                if c in out.columns:
                    out['현재가'] = out[c]
                    break
        if '현재가' not in out.columns:
            out['현재가'] = 0

        # 상세카드 기본값
        defaults = {
            '추천단계': '관찰형',
            'N등급': 'S+',
            'N조합': '🔍기본',
            'N구분': '',
            '안전점수': 0,
            'N점수': 0,
            'RSI': 0,
            '이격': 0,
            '초단기MA수렴도': 0,
            '단기MA수렴도': 0,
            '구조MA수렴도': 0,
            'BB40': 0,
            'OBV기울기': 0,
            '수급': '-',
            '재무': '-',
            '에너지': '',
            '기상': '',
        }
        for k, v in defaults.items():
            if k not in out.columns:
                out[k] = v
        return out
    except Exception:
        try:
            import pandas as _pd
            return _pd.DataFrame()
        except Exception:
            return df


def _v1043_order_by_action_codes(df, limit=10):
    try:
        import pandas as _pd
        out = _v1043_normalize_target_df(df)
        if not _v1043_df_nonempty(out):
            return _pd.DataFrame()
        action_items = list(globals().get('_V1041_ACTION_ITEMS', []) or [])
        codes = [_v1043_norm_code_value(x.get('code')) for x in action_items if isinstance(x, dict) and x.get('code')]
        codes = [c for c in codes if c]
        if not codes:
            return out.head(limit).reset_index(drop=True)
        out['_v1043_code'] = out['code'].map(_v1043_norm_code_value)
        found = []
        seen = set()
        for code in codes:
            if code in seen:
                continue
            rows = out[out['_v1043_code'] == code]
            if not rows.empty:
                found.append(rows.iloc[[0]])
                seen.add(code)
            if len(found) >= limit:
                break
        if found:
            res = _pd.concat(found, ignore_index=True)
            if '_v1043_code' in res.columns:
                res = res.drop(columns=['_v1043_code'])
            return res.reset_index(drop=True)
        if '_v1043_code' in out.columns:
            out = out.drop(columns=['_v1043_code'])
        return out.head(limit).reset_index(drop=True)
    except Exception:
        try:
            return df.head(limit).reset_index(drop=True)
        except Exception:
            return df


def _v1043_build_top15_fallback_targets(current_df, source_frames=None, limit=10):
    """telegram_targets가 비어 있을 때 오늘 매매관점 압축 후보 순서로 상세카드용 DF를 복구한다."""
    try:
        if _v1043_df_nonempty(current_df):
            return current_df
        import pandas as _pd
        source_frames = source_frames or []
        normalized = []
        for df in source_frames:
            ndf = _v1043_normalize_target_df(df)
            if _v1043_df_nonempty(ndf):
                normalized.append(ndf)
        if not normalized:
            return current_df
        pool = _pd.concat(normalized, ignore_index=True)
        if 'code' in pool.columns:
            pool['code'] = pool['code'].map(_v1043_norm_code_value)
            pool = pool[pool['code'].astype(str).str.len() == 6]
            pool = pool.drop_duplicates(subset=['code'], keep='first')
        res = _v1043_order_by_action_codes(pool, limit=limit)
        if _v1043_df_nonempty(res):
            try:
                log_info(f"🛠️ V1043 TOP15 fallback 복구: {len(res)}개")
            except Exception:
                pass
            return res
        return current_df
    except Exception as e:
        try:
            log_info(f"⚠️ V1043 TOP15 fallback 실패: {e}")
        except Exception:
            pass
        return current_df


def _v1043_has_real_top15_body(msg: str) -> bool:
    """빈 TOP15 헤더만 전송되는 것을 막는다."""
    try:
        s = str(msg or '').strip()
        if not s:
            return False
        body = s.replace('📢 [오늘의 실시간 TOP 15]', '').replace('[TEST]', '').strip()
        if not body:
            return False
        # 실제 상세카드는 별표 카드 또는 목표/점수/현재가 라인이 있어야 한다.
        if re.search(r'(?m)^\s*⭐\s+', body):
            return True
        if '💰 현재가:' in body or '점수:' in body or '📌 목표1:' in body:
            return True
        return False
    except Exception:
        return bool(str(msg or '').strip())

