# ✅ TRADE_CLARITY_V10_4_5_YMGP_BB40_RUNTIME_SAFE_ACTIVE
# - 역매공파 조건 재정의: 과거 역배열 → MA5가 MA112~MA224 사이 회복 → BB40 동적저항 돌파/눌림
# - BB40 상단은 단독 신호가 아니라 저항선/재지지선으로 해석
# - 실행시간 방어: ThreadPoolExecutor가 미완료 스레드를 기다리며 30분 이상 멈추는 문제 방지
# =============================================================

def _v1045_env_int(name: str, default: int) -> int:
    try:
        v = int(float(str(os.getenv(name, str(default))).strip()))
        return max(0, v)
    except Exception:
        try:
            return int(default)
        except Exception:
            return 0


def _v1045_num(x, default=0.0):
    try:
        if x is None:
            return default
        if isinstance(x, str):
            x = x.replace(',', '').replace('%', '').replace('원', '').strip()
            if x == '' or x.lower() == 'nan':
                return default
        v = float(x)
        if pd.isna(v):
            return default
        return v
    except Exception:
        return default


def _v1045_bool_series_any(s):
    try:
        return bool(s.fillna(False).astype(bool).any())
    except Exception:
        try:
            return bool(s.any())
        except Exception:
            return False


def _v1045_ma_between(ma5, ma112, ma224, tol=0.03):
    try:
        ma5 = _v1045_num(ma5, 0)
        ma112 = _v1045_num(ma112, 0)
        ma224 = _v1045_num(ma224, 0)
        if ma5 <= 0 or ma112 <= 0 or ma224 <= 0:
            return False
        lo = min(ma112, ma224) * (1 - tol)
        hi = max(ma112, ma224) * (1 + tol)
        return lo <= ma5 <= hi
    except Exception:
        return False


def _v1045_light_ymgp_prefilter_raw(raw_df) -> bool:
    """get_indicators 전 빠른 역매공파 후보 예외 필터.
    기존 거래대금/거래량 필터를 없애지 않고, 장기선 회복형 후보만 추가로 살린다.
    """
    try:
        df = raw_df.copy()
        if df is None or len(df) < 260:
            return False
        close = df['Close'].astype(float)
        high = df['High'].astype(float) if 'High' in df.columns else close
        low = df['Low'].astype(float) if 'Low' in df.columns else close
        vol = df['Volume'].astype(float) if 'Volume' in df.columns else pd.Series(0, index=df.index)
        ma5 = close.rolling(5).mean()
        ma20 = close.rolling(20).mean()
        ma40 = close.rolling(40).mean()
        ma112 = close.rolling(112).mean()
        ma224 = close.rolling(224).mean()
        std40 = close.rolling(40).std()
        bb40_up = ma40 + std40 * 2

        last = len(df) - 1
        c = close.iloc[last]
        if c <= 0:
            return False
        recent_amount_b = float((close * vol).tail(5).mean() / 1e8)
        if recent_amount_b < _v1045_env_int('YMGP_MIN_AMOUNT_B', 8):
            return False

        had_bear = _v1045_bool_series_any((ma5 < ma112) & (ma112 < ma224)).tail(180)
        ma_between = _v1045_ma_between(ma5.iloc[last], ma112.iloc[last], ma224.iloc[last], tol=0.04)
        if not (had_bear and ma_between):
            return False

        brk = (close > bb40_up) & (close.shift(1) <= bb40_up.shift(1))
        brk_recent = _v1045_bool_series_any(brk.tail(25))
        near_bb40 = bool(c >= float(bb40_up.iloc[last]) * 0.96) if _v1045_num(bb40_up.iloc[last], 0) > 0 else False
        ma5_hold = bool(c >= float(ma5.iloc[last]) * 0.95) if _v1045_num(ma5.iloc[last], 0) > 0 else False
        disp = (c / float(ma20.iloc[last]) * 100.0) if _v1045_num(ma20.iloc[last], 0) > 0 else 100.0
        not_too_hot = disp <= 114.0
        return bool(brk_recent and near_bb40 and ma5_hold and not_too_hot)
    except Exception:
        return False


def _v1045_recent_break_age(mask, lookback=25):
    try:
        tail = list(mask.tail(lookback).fillna(False).astype(bool).values)
        for i in range(len(tail) - 1, -1, -1):
            if tail[i]:
                return len(tail) - 1 - i
    except Exception:
        pass
    return 999


def _v1045_calc_ymgp_bb40_bundle(df, row, prev):
    """역매공파 + BB40 동적저항/재지지 상태 계산."""
    empty = {
        'context': False, 'score': 0, 'tag': '', 'state': '', 'comment': '',
        'bb40_role': '', 'bb40_break_recent': False, 'bb40_retest': False,
        'ma5_between_112_224': False, 'bear_recent': False, 'pullback_after_break': False,
    }
    try:
        if df is None or len(df) < 230:
            return empty
        close = df['Close'].astype(float)
        high = df['High'].astype(float)
        low = df['Low'].astype(float)
        ma5 = df['MA5'].astype(float) if 'MA5' in df.columns else close.rolling(5).mean()
        ma20 = df['MA20'].astype(float) if 'MA20' in df.columns else close.rolling(20).mean()
        ma112 = df['MA112'].astype(float) if 'MA112' in df.columns else close.rolling(112).mean()
        ma224 = df['MA224'].astype(float) if 'MA224' in df.columns else close.rolling(224).mean()
        bb40_up = df['BB40_Upper'].astype(float) if 'BB40_Upper' in df.columns else close.rolling(40).mean() + close.rolling(40).std() * 2
        vol = df['Volume'].astype(float) if 'Volume' in df.columns else pd.Series(0, index=df.index)
        vma20 = df['VMA20'].astype(float) if 'VMA20' in df.columns else vol.rolling(20).mean()

        c = _v1045_num(row.get('Close'), 0)
        h = _v1045_num(row.get('High'), c)
        l = _v1045_num(row.get('Low'), c)
        p_c = _v1045_num(prev.get('Close'), 0)
        up = _v1045_num(row.get('BB40_Upper', bb40_up.iloc[-1]), 0)
        p_up = _v1045_num(prev.get('BB40_Upper', bb40_up.iloc[-2] if len(bb40_up) >= 2 else 0), 0)
        if c <= 0 or up <= 0:
            return empty

        had_bear = _v1045_bool_series_any(((ma5 < ma112) & (ma112 < ma224)).tail(180))
        bear_days = int(((ma5 < ma112) & (ma112 < ma224)).tail(180).fillna(False).sum())
        ma_between = _v1045_ma_between(row.get('MA5', ma5.iloc[-1]), row.get('MA112', ma112.iloc[-1]), row.get('MA224', ma224.iloc[-1]), tol=0.035)

        brk_mask = (close > bb40_up) & (close.shift(1) <= bb40_up.shift(1))
        brk_recent = _v1045_bool_series_any(brk_mask.tail(25))
        brk_age = _v1045_recent_break_age(brk_mask, 25)
        bb40_close_break_today = bool(p_c <= p_up and c > up)
        bb40_test = bool(h >= up * 0.995 and c < up * 1.005 and c < up)
        bb40_retest = bool(brk_recent and l <= up * 1.035 and c >= up * 0.985)
        pullback_after_break = bool(brk_recent and 1 <= brk_age <= 20 and l <= up * 1.05 and c >= up * 0.97)

        disp = _v1045_num(row.get('Disparity'), 100)
        rsi = _v1045_num(row.get('RSI'), 50)
        obv_ok = bool(_v1045_num(row.get('OBV_Slope', row.get('OBV기울기', 0)), 0) > 0 or _v1045_num(row.get('OBV_SLOPE_5', 0), 0) > 0)
        mfi_ok = bool(_v1045_num(row.get('MFI'), 0) >= 45)
        vol_alive = bool(_v1045_num(row.get('Volume'), 0) >= max(1, _v1045_num(row.get('VMA20'), 0)) * 0.9)
        acc_ok = bool(obv_ok or mfi_ok or vol_alive)
        ma5_hold = bool(c >= _v1045_num(row.get('MA5', 0), c) * 0.97)
        safe_ok = bool(disp <= 113 and rsi <= 69)

        score = 0
        if had_bear: score += 18
        if ma_between: score += 22
        if brk_recent: score += 18
        if bb40_close_break_today: score += 12
        if bb40_retest: score += 16
        elif pullback_after_break: score += 12
        if ma5_hold: score += 8
        if acc_ok: score += 8
        if safe_ok: score += 8
        if disp >= 115 or rsi >= 70:
            score -= 25

        context = bool(score >= 55 and had_bear and ma_between and (brk_recent or bb40_test or c >= up * 0.97))
        if not context:
            return dict(empty, score=max(0, int(score)), bear_recent=had_bear, ma5_between_112_224=ma_between, bb40_break_recent=brk_recent)

        if disp >= 115 or rsi >= 70:
            state = 'BB40 후행주의'
            tag = '⛔BB40후행주의'
            role = 'BB40 돌파 후 과열/후행'
        elif bb40_retest and pullback_after_break:
            state = 'BB40 재지지 확인'
            tag = '✅BB40재지지'
            role = 'BB40 상단이 저항에서 지지선 후보로 전환'
        elif pullback_after_break:
            state = 'BB40 돌파 후 눌림'
            tag = '🟡BB40돌파후눌림'
            role = 'BB40 상단 돌파 후 첫 눌림 재지지 확인 구간'
        elif bb40_close_break_today:
            state = 'BB40 저항돌파'
            tag = '🚀BB40저항돌파'
            role = 'BB40 상단 저항선 종가 돌파 확인'
        elif bb40_test:
            state = 'BB40 저항테스트'
            tag = '🧪BB40저항테스트'
            role = 'BB40 상단 저항을 찔렀으나 종가 안착 확인 필요'
        else:
            state = 'BB40 저항전'
            tag = '🚧BB40저항전'
            role = 'BB40 상단 저항선 돌파 전 관찰'

        comment = f"역배열이력 {bear_days}일 → MA5가 MA112~MA224 사이 회복 → {state}. BB40은 단독 신호가 아니라 저항/재지지선으로 확인"
        return {
            'context': True, 'score': max(0, min(100, int(score))), 'tag': tag, 'state': state,
            'comment': comment, 'bb40_role': role, 'bb40_break_recent': bool(brk_recent),
            'bb40_retest': bool(bb40_retest), 'ma5_between_112_224': bool(ma_between),
            'bear_recent': bool(had_bear), 'pullback_after_break': bool(pullback_after_break),
            'bb40_break_age': int(brk_age), 'disparity': float(disp), 'rsi': float(rsi),
        }
    except Exception:
        return empty


# V1045 출력 문구 보강: 역매공파BB40 컬럼이 있으면 상세카드에 한 줄 추가
try:
    _V1045_BASE_ENRICH_HUMAN = enrich_row_with_human_commentary
except Exception:
    _V1045_BASE_ENRICH_HUMAN = None


def enrich_row_with_human_commentary(row):
    try:
        out = _V1045_BASE_ENRICH_HUMAN(row) if _V1045_BASE_ENRICH_HUMAN else row
    except Exception:
        out = row
    try:
        d = out.copy() if isinstance(out, dict) else dict(out)
    except Exception:
        return out
    try:
        if bool(d.get('역매공파BB40맥락', False)):
            line = f"🏆 역매공파/BB40: {d.get('역매공파BB40상태','')} | {d.get('역매공파BB40역할','')}"
            interp = str(d.get('interpretation_block', '') or '').strip()
            if line and line not in interp:
                d['interpretation_block'] = (interp + "\n" + line).strip() if interp else line
            ng = str(d.get('N구분', '') or '')
            tag = str(d.get('역매공파BB40태그', '') or '').strip()
            if tag and tag not in ng:
                d['N구분'] = (ng + ' ' + tag).strip()
    except Exception:
        pass
    return d


# V1045 런타임 방어: with ThreadPoolExecutor가 미완료 thread를 끝까지 기다리는 문제를 막는다.
try:
    _V1045_BASE_ANALYZE_FINAL = analyze_final
except Exception:
    _V1045_BASE_ANALYZE_FINAL = None


def run_scan_with_timeout(target_dict, weather_data, global_env, leader_env, sector_master_map, timeout_per_stock=10):
    all_hits = []
    pairs = list(zip(target_dict.keys(), target_dict.values()))
    total = len(pairs)
    if total <= 0:
        return all_hits
    per_stock = _v1045_env_int('SCAN_TIMEOUT_PER_STOCK', 4)
    max_workers = _v1045_env_int('SCAN_MAX_WORKERS', 28)
    global_timeout = _v1045_env_int('SCAN_GLOBAL_TIMEOUT', max(480, min(900, per_stock * total // max(1, max_workers) + 420)))
    max_workers = max(4, min(max_workers, 40))
    try:
        log_info(f"⚡ V1045 병렬 스캔: {total}개 | workers {max_workers} | 종목기준 {per_stock}초 | 전체상한 {global_timeout}초")
    except Exception:
        pass

    executor = ThreadPoolExecutor(max_workers=max_workers)
    future_map = {}
    try:
        for code, name in pairs:
            fut = executor.submit(analyze_final, code, name, weather_data, global_env, leader_env, sector_master_map)
            future_map[fut] = (code, name)

        done_count = 0
        try:
            iterator = as_completed(future_map, timeout=global_timeout)
            for future in iterator:
                code, name = future_map.get(future, ('', ''))
                done_count += 1
                try:
                    result = future.result(timeout=0)
                    if result:
                        all_hits.extend(result)
                except FuturesTimeoutError:
                    try: log_error(f"⏰ [{name}] 타임아웃 스킵")
                    except Exception: pass
                except Exception as e:
                    try: log_error(f"🚨 [{name}] 오류: {e}")
                    except Exception: pass
                try: log_progress(done_count, total)
                except Exception: pass
        except FuturesTimeoutError:
            pending = [f for f in future_map if not f.done()]
            try:
                log_error(f"⏰ V1045 전체 스캔 상한 도달: 완료 {done_count}/{total}, 미완료 {len(pending)}개는 취소하고 현재 결과로 진행")
            except Exception:
                pass
            for f in pending:
                try: f.cancel()
                except Exception: pass
    finally:
        try:
            executor.shutdown(wait=False, cancel_futures=True)
        except TypeError:
            try: executor.shutdown(wait=False)
            except Exception: pass
        except Exception:
            pass
    return all_hits


