def _v1046_env_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() not in ('0', 'false', 'no', 'off', '')
    except Exception:
        return str(default).strip().lower() not in ('0', 'false', 'no', 'off', '')


def _v1046_env_int(name: str, default: int) -> int:
    try:
        return max(0, int(float(str(os.getenv(name, str(default))).strip())))
    except Exception:
        return int(default)


def _v1046_norm_code(v) -> str:
    try:
        s = str(v or '').strip()
        if s.endswith('.0'):
            s = s[:-2]
        s = re.sub(r'[^0-9]', '', s)
        return s.zfill(6) if s else ''
    except Exception:
        return ''


def _v1046_num(x, default=0.0):
    try:
        if x is None:
            return default
        if isinstance(x, str):
            x = x.replace(',', '').replace('%', '').replace('원', '').strip()
            if x == '' or x.lower() == 'nan':
                return default
        v = float(x)
        if pd.isna(v):
            return default
        return v
    except Exception:
        return default


def _v1046_s(x, default=''):
    try:
        if x is None:
            return default
        s = str(x).strip()
        if s.lower() == 'nan':
            return default
        return s
    except Exception:
        return default


def _v1046_has_detail_card(msg: str) -> bool:
    """TOP15 전송 시 빈 헤더만 보내지 않기 위한 카드 존재 검사."""
    try:
        s = str(msg or '').strip()
        if not s:
            return False
        body = s.replace('📢 [오늘의 실시간 TOP 15]', '').replace('[TEST]', '').strip()
        if not body:
            return False
        if re.search(r'(?m)^\s*⭐\s+', body):
            return True
        if any(k in body for k in ['💰 현재가:', '점수:', '📌 목표1:', '🪜 유형:']):
            return True
        return False
    except Exception:
        return bool(str(msg or '').strip())


def _v1046_send_top15_detail(msg: str, max_len: int = 3300):
    """상세 TOP15는 사진 캡션 경로 대신 텍스트 청크 경로로 안전 전송."""
    try:
        if not _v1046_has_detail_card(msg):
            try: log_info('🛡️ V1046: TOP15 빈 헤더/빈 상세 전송 생략')
            except Exception: pass
            return None
        return send_telegram_chunks(msg, max_len=max_len)
    except Exception as e:
        try: log_error(f'⚠️ V1046 TOP15 상세 전송 실패: {e}')
        except Exception: pass
        return None


def _v1046_build_ymgp_bb40_top5_df(df, limit: int = 5):
    """역매공파/BB40 재정의 후보 별도 TOP5."""
    try:
        import pandas as _pd
        if df is None or not hasattr(df, 'empty') or df.empty:
            return _pd.DataFrame()
        out = df.copy()
        if 'code' not in out.columns:
            for c in ['Code', '종목코드', '티커']:
                if c in out.columns:
                    out['code'] = out[c]
                    break
        if '종목명' not in out.columns:
            for c in ['Name', 'name', '종목']:
                if c in out.columns:
                    out['종목명'] = out[c]
                    break
        if '현재가' not in out.columns:
            for c in ['Close', 'close', '종가']:
                if c in out.columns:
                    out['현재가'] = out[c]
                    break
        if '역매공파BB40맥락' not in out.columns:
            return _pd.DataFrame()
        mask = out['역매공파BB40맥락'].fillna(False).astype(bool)
        out = out[mask].copy()
        if out.empty:
            return _pd.DataFrame()
        for c in ['역매공파BB40점수', '안전점수', 'N점수', '현재가', 'RSI', '이격', 'BB40']:
            if c not in out.columns:
                out[c] = 0
            out[c] = _pd.to_numeric(out[c], errors='coerce').fillna(0)
        for c in ['역매공파BB40상태', '역매공파BB40태그', '역매공파BB40코멘트', '역매공파BB40역할']:
            if c not in out.columns:
                out[c] = ''
        out['_v1046_overheat'] = ((out['RSI'] >= 70) | (out['이격'] >= 115)).astype(int)
        if 'code' in out.columns:
            out['_v1046_code'] = out['code'].map(_v1046_norm_code)
        else:
            out['_v1046_code'] = ''
        out = out.sort_values(
            by=['_v1046_overheat', '역매공파BB40점수', '안전점수', 'N점수'],
            ascending=[True, False, False, False]
        )
        out = out.drop_duplicates(subset=['_v1046_code'], keep='first')
        return out.head(limit).reset_index(drop=True)
    except Exception as e:
        try: log_error(f'⚠️ V1046 역매공파 TOP5 구성 실패: {e}')
        except Exception: pass
        try:
            import pandas as _pd
            return _pd.DataFrame()
        except Exception:
            return df


def _v1046_build_ymgp_bb40_block(df, title='역매공파/BB40 재정의 TOP 5') -> str:
    try:
        if not _v1046_env_on('SHOW_YMGP_BB40_TOP5', '1'):
            return ''
        header_lines = [
            '🏆 [역매공파/BB40 재정의 TOP 5]',
            '',
            '기준: 과거 역배열 → MA5가 MA112~MA224 사이 회복 → BB40 상단을 저항/재지지선으로 확인',
            ''
        ]
        if df is None or not hasattr(df, 'empty') or df.empty:
            return '\n'.join(header_lines + ['- 해당 종목 없음']).strip()
        lines = list(header_lines)
        for i, row in df.iterrows():
            d = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            name = _v1046_s(d.get('종목명') or d.get('Name'))
            code = _v1046_norm_code(d.get('code') or d.get('Code'))
            price = int(_v1046_num(d.get('현재가') or d.get('Close'), 0))
            score = int(_v1046_num(d.get('역매공파BB40점수'), 0))
            state = _v1046_s(d.get('역매공파BB40상태'))
            tag = _v1046_s(d.get('역매공파BB40태그'))
            role = _v1046_s(d.get('역매공파BB40역할'))
            comment = _v1046_s(d.get('역매공파BB40코멘트'))
            rsi = int(_v1046_num(d.get('RSI'), 0))
            disp = int(_v1046_num(d.get('이격'), 0))
            bb40 = _v1046_num(d.get('BB40'), 0)
            pblue = int(_v1046_num(d.get('파란점선') or d.get('BB30시프트선') or d.get('기준가'), 0))
            supply = _v1046_s(d.get('수급요약') or d.get('수급판정') or d.get('수급'), '-')
            stop = int(_v1046_num(d.get('🚨손절가'), 0))
            t1 = int(_v1046_num(d.get('🎯목표타점'), 0))
            lines.append(f"{i+1}) {name}({code}) | 현재 {price:,} | 점수 {score}")
            lines.append(f"   🏷️ {tag or state} | {state}")
            lines.append(f"   📌 해석: {role or 'BB40 상단을 저항선으로 보고 돌파 후 눌림/재지지 확인'}")
            if comment:
                lines.append(f"   🧠 맥락: {comment[:90]}")
            lines.append(f"   📊 이격 {disp} | RSI {rsi} | BB40폭 {bb40:.1f}")
            if pblue > 0:
                lines.append(f"   🔵 기준선: {pblue:,}원 재지지/종가 안착 확인")
            if t1 > 0 or stop > 0:
                lines.append(f"   🎯 목표 {t1:,} / 손절 {stop:,}" if t1 > 0 and stop > 0 else f"   🎯 목표/손절: {t1:,}/{stop:,}")
            if supply and supply != '-':
                lines.append(f"   🏦 수급: {supply[:70]}")
            lines.append('')
        return '\n'.join(lines).strip()
    except Exception as e:
        try: log_error(f'⚠️ V1046 역매공파 TOP5 블록 생성 실패: {e}')
        except Exception: pass
        return ''

