# ✅ TRADE_CLARITY_V10_4_8_TOP15_FAST_SEND_GUARD_FIX_ACTIVE
# - 원인: V1036의 send_telegram_photo 빠른모드 보호 로직이
#   '📢 [오늘의 실시간 TOP 15]' 문구가 들어간 메시지를 무조건 차단하고 있었음.
# - V1042 safe splitter는 내부적으로 photo 전송 경로를 사용하므로,
#   TOP15 상세카드만 조용히 누락되는 현상이 발생했다.
# - 해결: safe splitter의 최종 텍스트 전송 경로(_v1042_direct_send_text)를
#   기존 photo wrapper 체인이 아닌 Telegram sendMessage 직접 경로로 우회한다.
# - 범위: 텍스트 청크 전송만 보정. HTML/시트/AI 무거운 후처리 생략 정책은 유지.
# =============================================================
print("✅ TRADE_CLARITY_V10_4_8_TOP15_FAST_SEND_GUARD_FIX_ACTIVE LOADED")


def _v1048_raw_send_text_to_telegram(text: str):
    """기존 send_telegram_photo wrapper의 FAST TOP15 차단을 우회하는 순수 텍스트 전송기."""
    msg = str(text or '').strip()
    if not msg:
        return None
    try:
        token = globals().get('TELEGRAM_TOKEN', '')
        if not token:
            try: log_error('⚠️ TELEGRAM_TOKEN 없음 — 텍스트 전송 생략')
            except Exception: pass
            return None

        try:
            target_chat_ids, mode_label = get_target_chat_ids()
        except Exception:
            target_chat_ids, mode_label = [], ''

        if not target_chat_ids:
            try: log_error('⚠️ 전송 대상 chat_id 없음 — 텍스트 전송 생략')
            except Exception: pass
            return None

        # 원본 전송기와 동일하게 TEST 모드 표시는 유지하되 중복은 방지
        try:
            if bool(globals().get('TEST_MODE', False)) and not msg.startswith('[TEST]'):
                msg_to_send = ('[TEST]\n' + msg).strip()
            else:
                msg_to_send = msg
        except Exception:
            msg_to_send = msg

        url = f"https://api.telegram.org/bot{token}/sendMessage"
        for chat_id in target_chat_ids:
            try:
                requests.post(
                    url,
                    data={
                        'chat_id': chat_id,
                        'text': msg_to_send[:4090],
                        'disable_web_page_preview': True,
                    },
                    timeout=30,
                )
            except Exception as e:
                try: log_error(f'⚠️ V1048 텍스트 직접 전송 실패 ({chat_id}): {e}')
                except Exception: pass
        return None
    except Exception as e:
        try: log_error(f'⚠️ V1048 텍스트 직접 전송 예외: {e}')
        except Exception: pass
        return None


# V1042 safe splitter가 호출하는 최종 전송 함수를 교체한다.
# 이렇게 하면 TOP15 상세카드가 V1036 photo guard에 막히지 않는다.
def _v1042_direct_send_text(text: str):
    return _v1048_raw_send_text_to_telegram(text)


# TOP15 전송 함수에도 방어 로그를 추가한다. 실제 전송은 send_telegram_chunks → V1042 splitter → V1048 raw sender 경로.
