def _v1049_env_on(name: str, default: str = '0') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return str(default).strip().lower() in ('1', 'true', 'yes', 'y', 'on')


def _v1049_env_int(name: str, default: int) -> int:
    try:
        return int(float(str(os.getenv(name, str(default))).strip()))
    except Exception:
        return int(default)


def _v1049_s(x, default=''):
    try:
        if x is None:
            return default
        s = str(x).strip()
        if s.lower() == 'nan':
            return default
        return s
    except Exception:
        return default


def _v1049_num(x, default=0.0):
    try:
        if x is None:
            return default
        if isinstance(x, str):
            x = x.replace(',', '').replace('%', '').replace('원', '').replace('억', '').strip()
            if x == '' or x.lower() == 'nan':
                return default
        v = float(x)
        try:
            if pd.isna(v):
                return default
        except Exception:
            pass
        return v
    except Exception:
        return default


def _v1049_core_first_enabled() -> bool:
    return _v1049_env_on('STOCKHUNTER_CORE_FIRST', '1')


# ─────────────────────────────────────────────────────────────
# 1) 수급 점수: TOP15 정렬에 직접 반영
# ─────────────────────────────────────────────────────────────
def _v1049_supply_score(item) -> int:
    try:
        txt = ' '.join([
            _v1049_s(item.get('수급', '')),
            _v1049_s(item.get('수급요약', '')),
            _v1049_s(item.get('수급판정', '')),
            _v1049_s(item.get('수급당일', '')),
            _v1049_s(item.get('수급3일누적', '')),
            _v1049_s(item.get('수급5일누적', '')),
            _v1049_s(item.get('수급경고', '')),
        ])
        score = 0
        # 강한 우대: 개인 물량을 외인/기관이 받는 형태
        positive_rules = [
            ('외인·기관 동반 강매집', 30), ('외인·기관 동반매수 강함', 28), ('쌍끌강', 26),
            ('동반 강매집', 24), ('쌍끌', 20), ('기관 중심 강매집', 18), ('외인 중심 강매집', 18),
            ('기관매수 강함', 16), ('외인매수 강함', 16), ('기관 중심 매집', 12), ('외인 중심 매집', 12),
            ('개인매도흡수', 10), ('외인매수 우세', 8), ('기관매수 우세', 8),
        ]
        negative_rules = [
            ('외인·기관 동반 매도', -34), ('동반매도', -30), ('개인추격주의', -18),
            ('외인 매도 우세', -14), ('기관 매도 우세', -12), ('매도 우세', -10),
        ]
        for key, val in positive_rules:
            if key in txt:
                score += val
                break
        for key, val in negative_rules:
            if key in txt:
                score += val
                break

        # 기존 수급 표시 컬럼의 짧은 태그도 반영
        if '🔵외인강' in txt or '🔴기관강' in txt:
            score += 12
        elif '🔵외인' in txt or '🔴기관' in txt:
            score += 6
        if '🤝' in txt:
            score += 10
        if '🔻' in txt:
            score -= 16

        return int(max(-40, min(40, score)))
    except Exception:
        return 0


try:
    _V1049_BASE_BUILD_AND_SORT_CANDIDATES = build_and_sort_candidates
except Exception:
    _V1049_BASE_BUILD_AND_SORT_CANDIDATES = None


def build_and_sort_candidates(all_hits_sorted, top_k=50):
    """V1049 최종 정렬: 구조/N점수 + 안전점수 + 수급점수를 함께 반영한다."""
    if not all_hits_sorted:
        return pd.DataFrame()
    enriched_rows = []
    for x in all_hits_sorted:
        item = dict(x)
        try:
            if '재료잔존점수' not in item:
                m = calc_material_survival_score(item)
                item['재료잔존점수'] = int(m.get('material_score', 0))
                item['재료잔존태그'] = m.get('material_tag', '')
                item['재료잔존코멘트'] = m.get('material_comment', '')
        except Exception:
            item.setdefault('재료잔존점수', 0)
        try:
            item['맥락보너스점수'] = calc_context_bonus_score(item)
        except Exception:
            item['맥락보너스점수'] = 0
        item['수급정렬점수'] = _v1049_supply_score(item)

        base_safe = int(_v1049_num(item.get('안전점수', 0), 0))
        base_n = int(_v1049_num(item.get('N점수', 0), 0))
        ctx_bonus = int(_v1049_num(item.get('맥락보너스점수', 0), 0))
        supply_bonus = int(_v1049_num(item.get('수급정렬점수', 0), 0))

        # 수급은 종목 선별에 영향을 주되, 차트 구조점수를 완전히 뒤집지는 않도록 가중치 제한
        item['맥락안전점수'] = base_safe + ctx_bonus + int(supply_bonus * 1.2)
        item['맥락N점수'] = base_n + int(ctx_bonus * 0.6) + int(supply_bonus * 2.0)
        item['TOP15정렬점수'] = (
            int(_v1049_num(item.get('단계랭크', 0), 0)) * 45
            + item['맥락N점수'] * 1.0
            + item['맥락안전점수'] * 0.42
            + supply_bonus * 6
        )
        enriched_rows.append(item)

    # 1차는 너무 좁히지 않고 넉넉히 가져온 뒤, 최종 TOP15는 _apply_recommendation_alignment에서 재정렬
    n_top = sorted(
        enriched_rows,
        key=lambda x: (
            x.get('TOP15정렬점수', 0),
            x.get('맥락N점수', x.get('N점수', 0)),
            x.get('맥락안전점수', x.get('안전점수', 0)),
        ),
        reverse=True,
    )[:max(int(top_k or 50), 80)]
    ranked = sorted(
        n_top,
        key=lambda x: (
            x.get('추천정렬점수', x.get('TOP15정렬점수', 0)),
            x.get('단계랭크', 0),
            x.get('맥락안전점수', x.get('안전점수', 0)),
            x.get('맥락N점수', x.get('N점수', 0)),
        ),
        reverse=True,
    )[:int(top_k or 50)]
    return pd.DataFrame(ranked)


try:
    _V1049_BASE_APPLY_RECOMMENDATION_ALIGNMENT = _apply_recommendation_alignment
except Exception:
    _V1049_BASE_APPLY_RECOMMENDATION_ALIGNMENT = None


def _apply_recommendation_alignment(df: pd.DataFrame) -> pd.DataFrame:
    """추천단계 정렬 후에도 수급정렬점수를 보조 반영한다."""
    if df is None or df.empty:
        return df
    out = df.copy()
    try:
        out['추천단계'] = out.apply(_recommendation_phase, axis=1)
        out['추천정렬점수'] = out.apply(_recommendation_priority_score, axis=1)
    except Exception:
        if _V1049_BASE_APPLY_RECOMMENDATION_ALIGNMENT:
            try:
                out = _V1049_BASE_APPLY_RECOMMENDATION_ALIGNMENT(out)
            except Exception:
                pass
    if '수급정렬점수' not in out.columns:
        out['수급정렬점수'] = out.apply(lambda r: _v1049_supply_score(r), axis=1)
    for c in ['추천정렬점수', '단계랭크', '안전점수', 'N점수', '수급정렬점수']:
        if c not in out.columns:
            out[c] = 0
        try:
            out[c] = pd.to_numeric(out[c], errors='coerce').fillna(0)
        except Exception:
            pass
    out['추천정렬점수'] = out['추천정렬점수'] + out['수급정렬점수'] * 5
    return out.sort_values(
        by=['추천정렬점수', '수급정렬점수', '단계랭크', '안전점수', 'N점수'],
        ascending=False,
    ).reset_index(drop=True)


