def enrich_hits_with_supply_and_financial(all_hits_sorted, top_k_supply=80, top_k_financial=30):
    supply_cap = _v1049_env_int('FAST_SUPPLY_TOP_K', 120)
    fin_cap = _v1049_env_int('FAST_FINANCIAL_TOP_K', 0)
    tuned_supply = min(int(top_k_supply or 0), supply_cap) if supply_cap > 0 else 0
    tuned_fin = min(int(top_k_financial or 0), fin_cap) if fin_cap > 0 else 0
    try:
        log_info(f"⚡ V1049 1단계 후처리: 수급 {top_k_supply}→{tuned_supply}, 재무 {top_k_financial}→{tuned_fin}(2단계)")
    except Exception:
        pass
    if _V1049_BASE_ENRICH_SUPPLY_FINANCIAL:
        return _V1049_BASE_ENRICH_SUPPLY_FINANCIAL(
            all_hits_sorted,
            top_k_supply=tuned_supply,
            top_k_financial=tuned_fin,
        )
    return all_hits_sorted


try:
    _V1049_BASE_ENRICH_DISCLOSURE = enrich_with_disclosure
except Exception:
    _V1049_BASE_ENRICH_DISCLOSURE = None


def enrich_with_disclosure(hits, top_k=100):
    cap = _v1049_env_int('FAST_DISCLOSURE_TOP_K', 0)
    tuned = min(int(top_k or 0), cap) if cap > 0 else 0
    if tuned <= 0 and _v1049_core_first_enabled():
        try:
            for item in hits or []:
                item.setdefault('공시태그', '⚙️2단계')
        except Exception:
            pass
        try: log_info('⚡ V1049 공시 조회 2단계 처리: 핵심 리포트에서는 미조회 표시')
        except Exception: pass
        return hits
    if _V1049_BASE_ENRICH_DISCLOSURE:
        return _V1049_BASE_ENRICH_DISCLOSURE(hits, top_k=tuned)
    return hits


try:
    _V1049_BASE_FETCH_STOCK_NEWS = _fetch_stock_news
except Exception:
    _V1049_BASE_FETCH_STOCK_NEWS = None

_V1049_NEWS_CACHE = {}
_V1049_NEWS_CALLS = 0


def _fetch_stock_news(code: str, name: str) -> str:
    global _V1049_NEWS_CALLS
    key = (_v1049_s(code).zfill(6), _v1049_s(name))
    if key in _V1049_NEWS_CACHE:
        return _V1049_NEWS_CACHE[key]
    if _v1049_core_first_enabled() and not _v1049_env_on('RUN_STOCK_NEWS_STAGE2', '0'):
        _V1049_NEWS_CACHE[key] = ''
        return ''
    max_calls = _v1049_env_int('FAST_STOCK_NEWS_TOP_K', 0)
    if max_calls > 0 and _V1049_NEWS_CALLS >= max_calls:
        _V1049_NEWS_CACHE[key] = ''
        return ''
    _V1049_NEWS_CALLS += 1
    try:
        res = _V1049_BASE_FETCH_STOCK_NEWS(code, name) if _V1049_BASE_FETCH_STOCK_NEWS else ''
    except Exception:
        res = ''
    _V1049_NEWS_CACHE[key] = _v1049_s(res)[:160]
    return _V1049_NEWS_CACHE[key]


# ─────────────────────────────────────────────────────────────
# 3) AI 토너먼트/AI 심판은 기본 2단계. 켜면 제한시간만 허용.
# ─────────────────────────────────────────────────────────────
def _v1049_rule_based_tournament(candidate_list, title='AI 2단계 대기') -> str:
    try:
        df = candidate_list.copy() if hasattr(candidate_list, 'copy') else pd.DataFrame(candidate_list or [])
        if df is None or df.empty:
            return ''
        if '수급정렬점수' not in df.columns:
            df['수급정렬점수'] = df.apply(lambda r: _v1049_supply_score(r), axis=1)
        for c in ['추천정렬점수', '단계랭크', '안전점수', 'N점수', '수급정렬점수', 'RSI', '이격']:
            if c not in df.columns:
                df[c] = 0
            df[c] = pd.to_numeric(df[c], errors='coerce').fillna(0)
        safe = df[(df['RSI'] < 70) & (df['이격'] < 115)].copy()
        if safe.empty:
            safe = df.copy()
        safe['_rule_score'] = safe['추천정렬점수'] + safe['수급정렬점수'] * 8 + safe['안전점수'] * 0.1 + safe['N점수'] * 0.05
        top = safe.sort_values('_rule_score', ascending=False).head(3).reset_index(drop=True)
        if top.empty:
            return ''
        def _line(row):
            name = _v1049_s(row.get('종목명') or row.get('Name'))
            code = _v1049_s(row.get('code') or row.get('Code')).zfill(6)
            phase = _v1049_s(row.get('추천단계') or _recommendation_phase(row))
            supply = _v1049_s(row.get('수급요약') or row.get('수급판정') or row.get('수급'), '-')
            return name, code, phase, supply
        n1, c1, p1, s1 = _line(top.iloc[0])
        n2, c2, p2, s2 = _line(top.iloc[1]) if len(top) > 1 else (n1, c1, p1, s1)
        return (
            '🏆 [AI 토너먼트 결승]\n'
            '모델상태: CORE_FIRST=ON | AI 심층분석은 2단계 처리\n\n'
            '🏆 [단타 1위]\n'
            f'- 종목명(코드): {n1}({c1})\n'
            f'- 핵심 판단: {p1} / 수급점수 반영 상위 후보\n'
            f'- 수급/시황 해석: {s1}\n'
            '- 진입 시나리오: 5일선·파란점선 재지지 + 양봉 마감 + 거래량 재유입 확인\n'
            '- 한 줄 총평: AI 호출을 기다리지 않고 1단계 룰 기반으로 먼저 전송한 후보입니다.\n\n'
            '🎯 [스윙 1위]\n'
            f'- 종목명(코드): {n2}({c2})\n'
            f'- 핵심 판단: {p2} / 구조와 수급을 함께 반영한 후보\n'
            f'- 수급/시황 해석: {s2}\n'
            '- 진입 시나리오: 눌림 후 재양봉, 기준선 이탈 금지 확인\n'
            '- 한 줄 총평: 상세 AI 토너먼트는 RUN_AI_TOURNAMENT=1 설정 시 수행됩니다.'
        )
    except Exception:
        return ''


try:
    _V1049_BASE_RUN_AI_TOURNAMENT = run_ai_tournament
except Exception:
    _V1049_BASE_RUN_AI_TOURNAMENT = None


def run_ai_tournament(candidate_list, issues):
    if _v1049_core_first_enabled() and not _v1049_env_on('RUN_AI_TOURNAMENT', '0'):
        try: log_info('⚡ V1049 AI 토너먼트 2단계 처리: TOP15 전송 지연 방지')
        except Exception: pass
        return _v1049_rule_based_tournament(candidate_list)
    if not _V1049_BASE_RUN_AI_TOURNAMENT:
        return _v1049_rule_based_tournament(candidate_list)
    timeout = _v1049_env_int('AI_TOURNAMENT_TIMEOUT', 90)
    try:
        from concurrent.futures import ThreadPoolExecutor as _TPE, TimeoutError as _TO
        ex = _TPE(max_workers=1)
        fut = ex.submit(_V1049_BASE_RUN_AI_TOURNAMENT, candidate_list, issues)
        try:
            return fut.result(timeout=timeout)
        except _TO:
            try: log_error(f'⏰ V1049 AI 토너먼트 {timeout}초 초과 — 룰기반 결과로 대체')
            except Exception: pass
            try: ex.shutdown(wait=False, cancel_futures=True)
            except TypeError: ex.shutdown(wait=False)
            return _v1049_rule_based_tournament(candidate_list)
    except Exception as e:
        try: log_error(f'⚠️ V1049 AI 토너먼트 실패 — 룰기반 대체: {e}')
        except Exception: pass
        return _v1049_rule_based_tournament(candidate_list)


