def _v1051_prepare_stage1_targets(primary_df=None, fallback_frames=None, limit: int = 15):
    """뉴스/AI/차트 이전에 쓸 1단계 TOP15를 확정한다."""
    try:
        lim = int(limit or _v1050_env_int('TOP15_COMPACT_LIMIT', 15))
    except Exception:
        lim = 15
    try:
        base = primary_df.copy() if primary_df is not None and hasattr(primary_df, 'copy') else pd.DataFrame()
        if base is not None and hasattr(base, 'empty') and not base.empty:
            try:
                base = _apply_recommendation_alignment(base)
            except Exception:
                pass
        out = _v1050_build_from_fallback_frames(base, fallback_frames=fallback_frames, limit=lim)
        if out is None or not hasattr(out, 'empty') or out.empty:
            out = _v1050_build_from_fallback_frames(primary_df, fallback_frames=fallback_frames, limit=lim)
        if out is None or not hasattr(out, 'empty'):
            return pd.DataFrame()
        return out.head(lim).reset_index(drop=True)
    except Exception as e:
        try: log_error(f'⚠️ V1051 1단계 TOP15 구성 실패: {e}')
        except Exception: pass
        try:
            return primary_df.head(limit).reset_index(drop=True)
        except Exception:
            return pd.DataFrame()


def _v1051_fill_fast_ai_tip(df):
    """AI 호출 없이 오늘 매매관점용 한 줄 힌트를 보강한다."""
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return df
        if 'ai_tip' not in df.columns:
            df['ai_tip'] = ''
        for idx, row in df.iterrows():
            cur = str(row.get('ai_tip', '') or '').strip()
            if cur and cur not in ('AI 분석 불가 (API 키 없음 또는 호출 실패)', '브리핑 생성 실패'):
                continue
            try:
                df.at[idx, 'ai_tip'] = generate_stage_ai_tip(row)
            except Exception:
                try:
                    df.at[idx, 'ai_tip'] = _recommendation_summary_line(row)
                except Exception:
                    df.at[idx, 'ai_tip'] = '5일선·파란점선·거래량 재확인 필요'
        return df
    except Exception:
        return df


def _v1051_first_sector_names(sector_results, limit=3):
    names = []
    try:
        for x in sector_results or []:
            if isinstance(x, dict):
                n = x.get('sector') or x.get('name') or x.get('섹터') or x.get('title')
            else:
                n = getattr(x, 'sector', '') or getattr(x, 'name', '')
            n = str(n or '').strip()
            if n and n not in names:
                names.append(n)
            if len(names) >= limit:
                break
    except Exception:
        pass
    return names


