def _v1051_send_stage1_core_report(
    *, briefing='', sector_report='', oil_briefing='', news_theme_text='', us_mapping_text='',
    sector_results=None, ai_candidates=None, all_hits_df_for_pre=None, amount_top60_df=None, df_clean=None,
    m_ndx=None, m_sp5=None, m_vix=None, m_fx=None, m_wti=None,
    telegram_targets=None, wm_red_top5=None, wm_blue_top5=None, dante_pick_df=None, dante_watch_df=None,
    breakout_pick_df=None, breakout_watch_df=None, wm_pullback_top5=None, wm_late_top5=None,
    dante_ex_df=None, wm_intro_top5=None, ymgp_bb40_block='', triangle_pre_squeeze_block='', triangle_squeeze_block='', fallback_frames=None
) -> bool:
    """1단계 핵심 리포트를 원하는 순서대로 즉시 전송한다."""
    try:
        if not _v1051_stage1_enabled():
            return False
        lim = _v1050_env_int('TOP15_COMPACT_LIMIT', 15)
        targets = _v1051_prepare_stage1_targets(telegram_targets if telegram_targets is not None else ai_candidates, fallback_frames=fallback_frames, limit=lim)
        targets = _v1051_fill_fast_ai_tip(targets)
        if targets is None or not hasattr(targets, 'empty') or targets.empty:
            try: log_error('⚠️ V1051: 1단계 TOP15 후보가 없어 핵심 전송을 건너뜀')
            except Exception: pass
            return False

        market_leader_analysis_text = _v1051_build_market_leader_text_safe(
            sector_results=sector_results,
            news_theme_text=news_theme_text,
            us_mapping_text=us_mapping_text,
            ai_candidates=ai_candidates,
            all_hits_df=all_hits_df_for_pre,
            amount_top60_df=amount_top60_df,
            df_clean=df_clean,
        )
        macro_briefing_result = _v1051_build_light_macro_result(
            telegram_targets=targets, sector_results=sector_results,
            m_ndx=m_ndx, m_sp5=m_sp5, m_vix=m_vix, m_fx=m_fx, m_wti=m_wti,
        )
        try:
            macro_briefing_text = format_macro_briefing_for_telegram(macro_briefing_result)
        except Exception:
            macro_briefing_text = '🌍 [시장 통합 브리핑]\n- CORE_FIRST: 차트/구조/수급 중심으로 1단계 후보를 먼저 전송합니다.'

        pre_briefing_msg = (
            f"{briefing}\n\n"
            f"{sector_report}\n\n"
            f"{oil_briefing}\n\n"
            f"{news_theme_text}\n\n"
            f"{us_mapping_text}\n\n"
            f"{market_leader_analysis_text}\n\n"
            f"{macro_briefing_text}"
        ).strip()
        if pre_briefing_msg:
            send_telegram_chunks(pre_briefing_msg, max_len=3500)

        trade_action_summary_block = _v81_build_today_action_summary_safe(
            telegram_targets=targets,
            wm_red_top5=wm_red_top5,
            wm_blue_top5=wm_blue_top5,
            dante_pick_df=dante_pick_df,
            dante_watch_df=dante_watch_df,
            breakout_pick_df=breakout_pick_df,
            breakout_watch_df=breakout_watch_df,
            wm_pullback_top5=wm_pullback_top5,
            wm_late_top5=wm_late_top5,
            dante_ex_df=dante_ex_df,
            ai_candidates=ai_candidates,
            all_hits_df=all_hits_df_for_pre,
            wm_intro_top5=wm_intro_top5,
            amount_top60_df=amount_top60_df,
        )
        if str(trade_action_summary_block or '').strip():
            send_telegram_chunks(trade_action_summary_block, max_len=3500)

        sent_top15 = _v1050_send_forced_top15(targets, fallback_frames=fallback_frames, limit=lim)
        if not sent_top15:
            block = _v1050_build_compact_top15_block(targets, limit=lim)
            if str(block or '').strip():
                send_telegram_chunks(block, max_len=3500)
                sent_top15 = True

        if str(triangle_pre_squeeze_block or '').strip():
            send_telegram_chunks(triangle_pre_squeeze_block, max_len=3400)

        if str(triangle_squeeze_block or '').strip():
            send_telegram_chunks(triangle_squeeze_block, max_len=3400)

        if str(ymgp_bb40_block or '').strip():
            send_telegram_chunks(ymgp_bb40_block, max_len=3400)

        try:
            log_info(f'✅ V1051: 1단계 핵심 리포트 전송 완료 | TOP15 {min(_v1051_safe_len(targets), lim)}개 | 예비삼각TOP3 {"있음" if str(triangle_pre_squeeze_block or "").strip() else "없음"} | 삼각수렴블록 {"있음" if str(triangle_squeeze_block or "").strip() else "없음"} | 저평가1파블록 {"있음" if str(ymgp_bb40_block or "").strip() else "없음"}')
        except Exception:
            pass
        return bool(sent_top15)
    except Exception as e:
        try: log_error(f'⚠️ V1051 1단계 핵심 리포트 전송 실패: {e}')
        except Exception: pass
        return False

