print("✅ TRADE_CLARITY_V10_5_2_FIBONACCI_REGRESSION_RESTORE_ACTIVE LOADED")

try:
    os.environ.setdefault('V1052_SHOW_FIBONACCI', '1')
    os.environ.setdefault('V1052_SHOW_FIB_REGRESSION', '1')
    os.environ.setdefault('V1052_FIB_ONE_LINE', '1')
except Exception:
    pass


def _v1052_env_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return str(default).strip().lower() in ('1', 'true', 'yes', 'y', 'on')


def _v1052_dict(row):
    try:
        if isinstance(row, dict):
            return row
        return row.to_dict()
    except Exception:
        return {}


def _v1052_s(x):
    try:
        if x is None:
            return ''
        if isinstance(x, float) and pd.isna(x):
            return ''
    except Exception:
        pass
    return str(x).strip()


def _v1052_num(x, default=0.0):
    try:
        if x is None:
            return default
        if isinstance(x, str):
            x = x.replace(',', '').replace('원', '').replace('%', '').strip()
            if not x or x.lower() in ('nan', 'none', '-'):
                return default
        v = float(x)
        try:
            if pd.isna(v):
                return default
        except Exception:
            pass
        return v
    except Exception:
        return default


def _v1052_pick_num(d, keys, default=0.0):
    d = _v1052_dict(d)
    for k in keys:
        try:
            if k in d:
                v = _v1052_num(d.get(k), default=None)
                if v is not None and v > 0:
                    return float(v)
        except Exception:
            pass
    return default


def _v1052_money(v):
    try:
        v = float(v)
        if v <= 0:
            return '-'
        return f"{v:,.0f}"
    except Exception:
        return '-'


def _v1052_level_name(label: str) -> str:
    m = {
        'Fib236': '23.6', 'Fib382': '38.2', 'Fib500': '50',
        'Fib618': '61.8', 'Fib786': '78.6', 'Fib100': '100',
    }
    return m.get(label, label.replace('Fib', ''))


def _v1052_fib_pack(row) -> dict:
    """종목 row에 이미 들어간 Fib382/Fib500/Fib618로 피보나치/회귀 해석을 만든다."""
    try:
        d = _v1052_dict(row)
        close = _v1052_pick_num(d, ['현재가', 'Close', 'close', '종가', 'Price'], 0.0)
        f236 = _v1052_pick_num(d, ['Fib236', 'fib_236', 'FIB236', '피보236'], 0.0)
        f382 = _v1052_pick_num(d, ['Fib382', 'fib_382', 'FIB382', '피보382'], 0.0)
        f500 = _v1052_pick_num(d, ['Fib500', 'fib_500', 'FIB500', '피보500'], 0.0)
        f618 = _v1052_pick_num(d, ['Fib618', 'fib_618', 'FIB618', '피보618'], 0.0)
        f786 = _v1052_pick_num(d, ['Fib786', 'fib_786', 'FIB786', '피보786'], 0.0)
        vals = [('Fib236', f236), ('Fib382', f382), ('Fib500', f500), ('Fib618', f618), ('Fib786', f786)]
        vals = [(k, float(v)) for k, v in vals if v and v > 0]
        if not vals:
            return {}

        # 보기 좋은 핵심 3선: 38.2 / 50 / 61.8
        core_parts = []
        if f382 > 0: core_parts.append(f"38.2 {_v1052_money(f382)}")
        if f500 > 0: core_parts.append(f"50 {_v1052_money(f500)}")
        if f618 > 0: core_parts.append(f"61.8 {_v1052_money(f618)}")
        if not core_parts:
            core_parts = [f"{_v1052_level_name(k)} {_v1052_money(v)}" for k, v in vals[:3]]

        # fib 값은 보통 23.6 > 38.2 > 50 > 61.8 > 78.6 순서. 현재가 위치로 회귀권 분류.
        zone = '피보 구간 확인'
        if close > 0:
            if f382 > 0 and close >= f382:
                zone = '38.2 위 강세회귀권'
            elif f382 > 0 and f500 > 0 and f500 <= close < f382:
                zone = '38.2~50 얕은회귀권'
            elif f500 > 0 and f618 > 0 and f618 <= close < f500:
                zone = '50~61.8 황금회귀권'
            elif f618 > 0 and close < f618:
                zone = '61.8 하단 깊은회귀권'
            elif f500 > 0 and close >= f500:
                zone = '50선 위 회복권'

        above = []
        below = []
        if close > 0:
            for k, v in vals:
                if v > close:
                    above.append((k, v))
                elif v < close:
                    below.append((k, v))
        above = sorted(above, key=lambda x: x[1])
        below = sorted(below, key=lambda x: x[1], reverse=True)
        rec_parts = [zone]
        if above:
            k, v = above[0]
            rec_parts.append(f"회복 {_v1052_level_name(k)} {_v1052_money(v)}")
        if below:
            k, v = below[0]
            rec_parts.append(f"지지 {_v1052_level_name(k)} {_v1052_money(v)}")

        fib_text = ' / '.join(core_parts)
        regression_text = ' · '.join(rec_parts)
        one_line = f"{fib_text} | {regression_text}" if regression_text else fib_text
        return {
            'fib_text': fib_text,
            'fib_regression_text': regression_text,
            'fib_one_line': one_line,
            'fib_zone': zone,
        }
    except Exception:
        return {}


def _v1052_fib_line(row, prefix='📐 피보/회귀: ') -> str:
    try:
        if not _v1052_env_on('V1052_SHOW_FIBONACCI', '1'):
            return ''
        p = _v1052_fib_pack(row)
        if not p:
            return ''
        if _v1052_env_on('V1052_SHOW_FIB_REGRESSION', '1'):
            return prefix + p.get('fib_one_line', '')
        return prefix + p.get('fib_text', '')
    except Exception:
        return ''


try:
    _V1052_BASE_ITEM = _v1026_item
except Exception:
    _V1052_BASE_ITEM = None


def _v1026_item(row):
    """오늘 매매관점 압축 item에 피보나치/피보회귀 필드를 보강."""
    try:
        base = _V1052_BASE_ITEM(row) if _V1052_BASE_ITEM else {}
    except Exception:
        base = {}
    if not isinstance(base, dict):
        base = {}
    try:
        pack = _v1052_fib_pack(row)
        if pack:
            base['fib'] = pack.get('fib_text', '')
            base['fib_regression'] = pack.get('fib_regression_text', '')
            base['fib_line'] = pack.get('fib_one_line', '')
    except Exception:
        pass
    return base


try:
    _V1052_BASE_TODAY_BLOCK = _v102_make_today_action_block
except Exception:
    _V1052_BASE_TODAY_BLOCK = None


def _v102_make_today_action_block(rows, base=''):
    """V1052: 오늘 매매관점 압축 카드에 피보나치/피보회귀를 함께 표시."""
    try:
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1026_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used:
                    continue
                used.add(key); items.append(it)
            except Exception:
                continue
        if not items:
            return _V1052_BASE_TODAY_BLOCK(rows, base=base) if _V1052_BASE_TODAY_BLOCK else str(base or '')
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5) if '_v1021_limit' in globals() else 5
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 10) if '_v1021_limit' in globals() else 10
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 4) if '_v1021_limit' in globals() else 4
        avoid_limit = max(0, _v1023_env_int('TODAY_ACTION_AVOID_LIMIT', 0)) if '_v1023_env_int' in globals() else 0
        show_excluded = _v1031_env_bool('SHOW_EXCLUDED_RISK', False) if '_v1031_env_bool' in globals() else False
        groups = [
            ('조건부 실행','🟢 [진입 후보] 5일선·파란점선 위 양봉마감 + 거래량 기준 확인'),
            ('눌림 대기','🟡 [관찰 후보] 5일선 눌림/파란점선 재지지 대기'),
            ('보유자 대응','🛡️ [보유자] 이탈선 관리 우선'),
        ]
        limits = {'조건부 실행': cond_limit, '눌림 대기': observe_limit, '보유자 대응': holder_limit}
        out = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '🎯 [오늘 매매관점 압축]',
            '',
            f'📌 후보 수집: {total}개',
            '📌 시황 대장주 별도 분석은 생략하고, 실제 스캔 후보만 정리합니다.',
            '📌 파동 참고: 소파동·중파동 위치와 엘리어트 추정은 관찰형 상세카드에서 확인',
            '📌 피보 참고: 38.2/50/61.8 되돌림과 현재가 회귀권을 함께 확인',
            '📌 진입 숫자 기준: 5일선·파란점선 위 양봉 마감 + 거래량 전일比 1.3배↑ 또는 5일평균比 1.2배↑',
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
        ]
        shown_total = 0
        for label, title in groups:
            arr = [x for x in items if x.get('label') == label]
            if not arr:
                continue
            limit = limits.get(label, 5)
            out.append('')
            suffix = f' {min(len(arr), limit)}/{len(arr)}개' if len(arr) > limit else f' {len(arr)}개'
            out.append(title + suffix)
            out.append('────────────────────')
            for i, it in enumerate(arr[:limit], 1):
                name = _v1031_clean_text(it.get('name') or '-') if '_v1031_clean_text' in globals() else str(it.get('name') or '-')
                code_part = f"({it['code']})" if it.get('code') else ''
                cur = it.get('cur') or '-'
                out.append(f'{i}) {name}{code_part} | 현재 {cur}')
                out.append(f"   ✅ 대응: {_v1031_trunc(it.get('display_label') or it.get('label') or '-', 80)}")
                if it.get('pattern'):
                    out.append(f"   🔎 검색패턴: {_v1031_trunc(it['pattern'], 110)}")
                if it.get('accum_type'):
                    out.append(f"   🧲 매집: {_v1031_trunc(it['accum_type'], 120)}")
                if it.get('wyckoff'):
                    out.append(f"   📦 와이코프: {_v1031_trunc(it['wyckoff'], 130)}")
                if it.get('ki'):
                    out.append(f"   🔥 끼: {_v1031_trunc(it['ki'], 90)}")
                if it.get('finance'):
                    out.append(f"   🏢 기업: {_v1031_trunc(it['finance'], 115)}")
                if it.get('blue'):
                    out.append(f"   🔵 기준: {_v1031_trunc(_v1031_clean_text(it['blue']), 130)}")
                if it.get('fib_line'):
                    out.append(f"   📐 피보/회귀: {_v1031_trunc(it['fib_line'], 145)}")
                if it.get('supply_fib_commentary'):
                    out.append(f"   🧭 해설: {_v1031_trunc(it['supply_fib_commentary'], 145)}")
                entry_txt = it.get('entry_criteria') or it.get('entry')
                if entry_txt:
                    out.append(f"   🎯 진입: {_v1031_trunc(_v1031_clean_text(entry_txt), 145)}")
                try:
                    out.extend(_v1031_supply_block_for_item(it, indent='   '))
                except Exception:
                    if it.get('supply') and it.get('supply') != '수급 데이터 확인 필요':
                        out.append(f"   🏦 수급: {_v1031_trunc(it['supply'], 108)}")
                out.append('')
                shown_total += 1
        excluded = [x for x in items if x.get('label') == '추격 금지']
        if excluded:
            out.append(f'⛔ 제외/리스크 참고: {len(excluded)}개')
            if show_excluded and avoid_limit > 0:
                for i, it in enumerate(excluded[:avoid_limit], 1):
                    code_part = f"({it['code']})" if it.get('code') else ''
                    reasons = ' / '.join((it.get('decision') or {}).get('reasons') or [])
                    out.append(f"   {i}) {it.get('name','-')}{code_part} | {_v1031_trunc(reasons, 90)}")
            else:
                out.append('   상세는 기본 숨김입니다. 필요하면 SHOW_EXCLUDED_RISK=1, TODAY_ACTION_AVOID_LIMIT=5')
        if shown_total == 0:
            out.append('')
            out.append('- 실행/관찰 후보 없음. 오늘은 5일선 눌림과 파란점선 재지지만 확인합니다.')
        out.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        return '\n'.join([x for x in out if x is not None])
    except Exception:
        return _V1052_BASE_TODAY_BLOCK(rows, base=base) if _V1052_BASE_TODAY_BLOCK else str(base or '')


try:
    _V1052_BASE_TOP15_BLOCK = _v1050_build_compact_top15_block
except Exception:
    _V1052_BASE_TOP15_BLOCK = None


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    """V1052: compact TOP15에 피보나치/피보회귀 한 줄을 추가."""
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return ''
        limit = max(1, int(limit or 15))
        out = _v1050_sort_df_for_top15(df).head(limit).reset_index(drop=True)
        if out.empty:
            return ''
        lines = []
        lines.append(f"📢 [{title}]")
        lines.append('')
        lines.append('기준: 차트/구조/수급 우선 1단계 분석입니다. 재무·뉴스·AI 심층분석은 2단계 보조로 분리합니다.')
        lines.append('진입 공통조건: 5일선·파란점선 위 양봉 마감 + 거래량 전일比 1.3배↑ 또는 5일평균比 1.2배↑')
        lines.append('피보 기준: 38.2/50/61.8 되돌림과 현재가의 피보회귀권을 함께 확인합니다.')
        lines.append('')
        for i, row in out.iterrows():
            name = _v1050_first(row, ['종목명', 'Name', 'name'], '-')
            code = _v1050_norm_code(_v1050_first(row, ['code', 'Code', '종목코드'], ''))
            price = _v1050_num(row.get('현재가', row.get('Close', 0)), 0)
            phase = _v1050_phase(row)
            stage = _v1050_stage(row)
            sig = _v1050_signal(row)
            pattern = _v1050_pattern(row)
            supply = _v1050_supply_text(row)
            entry = _v1050_entry_text(row)
            action = _v1050_action_text(row)
            target = _v1050_target_text(row)
            fib_line = _v1052_fib_line(row, prefix='')
            safe = _v1050_int(row.get('안전점수', 0), 0)
            nscore = _v1050_int(row.get('N점수', 0), 0)
            rsi = _v1050_num(row.get('RSI', 0), 0)
            disp = _v1050_num(row.get('이격', 0), 0)
            bb40 = _v1050_num(row.get('BB40', 0), 0)
            obv = _v1050_num(row.get('OBV기울기', 0), 0)
            header_code = f"({code})" if code else ''
            price_s = f"{price:,.0f}원" if price > 0 else '-'
            lines.append(f"{i+1}) {name}{header_code} | 현재 {price_s} | 유형 {phase}")
            lines.append(f"   🎯 신호: {sig}")
            if stage:
                lines.append(f"   📶 단계: {stage}")
            lines.append(f"   🔎 구조: {pattern}")
            lines.append(f"   📊 지표: 이격 {disp:.0f} / RSI {rsi:.0f} / BB40 {bb40:.1f} / OBV {obv:+.0f} / 안전{safe}·N{nscore}")
            lines.append(f"   🏦 수급: {supply}")
            lines.append(f"   🔵 기준: {entry}")
            if fib_line:
                lines.append(f"   📐 피보/회귀: {fib_line[:170]}")
            lines.append(f"   ✅ 대응: {action}")
            lines.append(f"   🎯 가격: {target}")
            lines.append('')
        return '\n'.join(lines).strip()
    except Exception as e:
        try: log_error(f'⚠️ V1052 TOP15 피보/회귀 compact block 생성 실패: {e}')
        except Exception: pass
        if _V1052_BASE_TOP15_BLOCK:
            try:
                return _V1052_BASE_TOP15_BLOCK(df, limit=limit, title=title)
            except Exception:
                pass
        return ''

