def _v1053_late_fib_safety_text(fib_text: str, row) -> str:
    try:
        txt = str(fib_text or '').strip()
        if not txt:
            return txt
        if not _v1053_env_on('V1053_LATE_FIB_SAFETY_TEXT', '1'):
            return txt
        if not _v1053_is_late_row(row):
            return txt
        if '후행형' in txt or '추격금지' in txt or '추격 금지' in txt:
            return txt
        return txt + ' · 후행형: 추격금지, 38.2 재지지 확인'
    except Exception:
        return fib_text


def _v1052_fib_line(row, prefix='📐 피보/회귀: ') -> str:
    try:
        if _V1053_BASE_FIB_LINE:
            base = _V1053_BASE_FIB_LINE(row, prefix='')
        else:
            base = ''
        base = _v1053_late_fib_safety_text(base, row)
        return (prefix or '') + base if base else ''
    except Exception:
        try:
            return _V1053_BASE_FIB_LINE(row, prefix=prefix) if _V1053_BASE_FIB_LINE else ''
        except Exception:
            return ''


