def _v1053_build_late_reference_block() -> str:
    try:
        if not _v1053_env_on('V1053_SHOW_LATE_REFERENCE', '1'):
            return ''
        ref = globals().get('_V1053_LATE_REFERENCE_DF', pd.DataFrame())
        if ref is None or not hasattr(ref, 'empty') or ref.empty:
            return ''
        lim = max(0, _v1053_env_int('V1053_LATE_REFERENCE_LIMIT', 5))
        if lim <= 0:
            return ''
        ref = ref.head(lim).reset_index(drop=True)
        lines = []
        lines.append('🛡️ [후행 참고 TOP]')
        lines.append('TOP15에서는 후행형을 최대 3개만 유지하고, 초과 후행형은 보유관리 참고로 분리합니다.')
        lines.append('')
        for i, row in ref.iterrows():
            name = _v1050_first(row, ['종목명', 'Name', 'name'], '-')
            code = _v1053_code(row)
            price = _v1050_num(row.get('현재가', row.get('Close', 0)), 0)
            sig = _v1050_signal(row)
            rsi = _v1050_num(row.get('RSI', 0), 0)
            disp = _v1050_num(row.get('이격', 0), 0)
            entry = _v1050_entry_text(row)
            fib_line = _v1052_fib_line(row, prefix='')
            code_s = f'({code})' if code else ''
            price_s = f'{price:,.0f}원' if price > 0 else '-'
            fib_short = ''
            if fib_line:
                fib_short = ' | ' + str(fib_line).split('|')[-1].strip()[:80]
            lines.append(f"{i+1}) {name}{code_s} | 현재 {price_s} | 후행 참고")
            lines.append(f"   신호 {sig} | 이격 {disp:.0f} / RSI {rsi:.0f}{fib_short}")
            lines.append(f"   대응 신규 추격 금지, 5일선·파란점선·38.2 재지지 확인 | {entry[:70]}")
        return '\n'.join(lines).strip()
    except Exception as e:
        try: log_error(f'⚠️ V1053 후행 참고 블록 생성 실패: {e}')
        except Exception: pass
        return ''


try:
    _V1053_BASE_TOP15_BLOCK = _v1050_build_compact_top15_block
except Exception:
    _V1053_BASE_TOP15_BLOCK = None


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    """V1053: 피보/회귀 유지 + 후행형 최대 3개 제한 + 후행 참고 분리."""
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return ''
        limit = max(1, int(limit or 15))
        # 입력이 이미 V1053에서 15개로 선별된 경우 late reference 전역값을 보존한다.
        update_ref = False
        try:
            update_ref = len(df) > limit
        except Exception:
            update_ref = True
        out = _v1053_select_top15_with_late_cap(df, limit=limit, update_late_ref=update_ref).head(limit).reset_index(drop=True)
        if out.empty:
            return ''
        late_max = _v1053_env_int('V1053_TOP15_LATE_MAX', 3)
        lines = []
        lines.append(f"📢 [{title}]")
        lines.append('')
        lines.append('기준: 차트/구조/수급 우선 1단계 분석입니다. 재무·뉴스·AI 심층분석은 2단계 보조로 분리합니다.')
        lines.append(f'정렬 보정: 후행형은 TOP15 안에서 최대 {late_max}개까지만 유지하고, 초과분은 후행 참고로 분리합니다.')
        lines.append('진입 공통조건: 5일선·파란점선 위 양봉 마감 + 거래량 전일比 1.3배↑ 또는 5일평균比 1.2배↑')
        lines.append('피보 기준: 38.2/50/61.8 되돌림과 현재가의 피보회귀권을 함께 확인합니다.')
        lines.append('')
        for i, row in out.iterrows():
            name = _v1050_first(row, ['종목명', 'Name', 'name'], '-')
            code = _v1053_code(row)
            price = _v1050_num(row.get('현재가', row.get('Close', 0)), 0)
            phase = _v1050_phase(row)
            stage = _v1050_stage(row)
            sig = _v1050_signal(row)
            pattern = _v1050_pattern(row)
            supply = _v1050_supply_text(row)
            entry = _v1050_entry_text(row)
            action = _v1050_action_text(row)
            target = _v1050_target_text(row)
            fib_line = _v1052_fib_line(row, prefix='')
            safe = _v1050_int(row.get('안전점수', 0), 0)
            nscore = _v1050_int(row.get('N점수', 0), 0)
            rsi = _v1050_num(row.get('RSI', 0), 0)
            disp = _v1050_num(row.get('이격', 0), 0)
            bb40 = _v1050_num(row.get('BB40', 0), 0)
            obv = _v1050_num(row.get('OBV기울기', 0), 0)
            header_code = f"({code})" if code else ''
            price_s = f"{price:,.0f}원" if price > 0 else '-'
            lines.append(f"{i+1}) {name}{header_code} | 현재 {price_s} | 유형 {phase}")
            lines.append(f"   🎯 신호: {sig}")
            if stage:
                lines.append(f"   📶 단계: {stage}")
            lines.append(f"   🔎 구조: {pattern}")
            lines.append(f"   📊 지표: 이격 {disp:.0f} / RSI {rsi:.0f} / BB40 {bb40:.1f} / OBV {obv:+.0f} / 안전{safe}·N{nscore}")
            lines.append(f"   🏦 수급: {supply}")
            lines.append(f"   🔵 기준: {entry}")
            if fib_line:
                lines.append(f"   📐 피보/회귀: {fib_line[:185]}")
            fib_comment = _v1055_supply_fib_commentary(row) if '_v1055_supply_fib_commentary' in globals() else ''
            if fib_comment:
                lines.append(f"   🧭 해설: {fib_comment[:185]}")
            lines.append(f"   ✅ 대응: {action}")
            lines.append(f"   🎯 가격: {target}")
            lines.append('')
        late_ref_block = _v1053_build_late_reference_block()
        if late_ref_block:
            lines.append(late_ref_block)
            lines.append('')
        return _v1053_cleanup_message('\n'.join(lines).strip())
    except Exception as e:
        try: log_error(f'⚠️ V1053 TOP15 후행형 cap compact block 생성 실패: {e}')
        except Exception: pass
        if _V1053_BASE_TOP15_BLOCK:
            try:
                return _V1053_BASE_TOP15_BLOCK(df, limit=limit, title=title)
            except Exception:
                pass
        return ''


