def _v1054_env_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return str(default).strip().lower() in ('1', 'true', 'yes', 'y', 'on')


try:
    _V1054_BASE_CLEANUP_MESSAGE = _v1053_cleanup_message
except Exception:
    _V1054_BASE_CLEANUP_MESSAGE = None


def _v1054_cleanup_message(text):
    """V1054: Telegram split/direct 전송 전 공통 문자열 정리."""
    try:
        s = str(text or '')
        if _V1054_BASE_CLEANUP_MESSAGE:
            try:
                s = _V1054_BASE_CLEANUP_MESSAGE(s)
            except Exception:
                pass
        if _v1054_env_on('V1054_FORCE_AVOID_LINEBREAK_FIX', '1'):
            # 가장 자주 깨지는 줄: ...TODAY_ACTION_AVOID_LIMIT=5━━━━━━━━
            try:
                s = re.sub(r'(TODAY_ACTION_AVOID_LIMIT\s*=\s*5)\s*(?=━{3,})', r'\1\n', s)
                s = re.sub(r'(TODAY_ACTION_AVOID_LIMIT\s*>\s*0)\s*(?=━{3,})', r'\1\n', s)
                s = re.sub(r'(SHOW_EXCLUDED_RISK\s*=\s*1,\s*TODAY_ACTION_AVOID_LIMIT\s*=\s*5)\s*(?=━{3,})', r'\1\n', s)
            except Exception:
                pass
        if _v1054_env_on('V1054_SHOW_EMPTY_SECTOR_AS_NONE', '1'):
            try:
                s = re.sub(r'(-\s*불리섹터:\s*)\n', r'\1해당 없음\n', s)
                s = re.sub(r'(-\s*유리섹터:\s*)\n', r'\1해당 없음\n', s)
            except Exception:
                pass
        return s
    except Exception:
        return text


# V1053 cleanup 함수 자체도 보강한다.
def _v1053_cleanup_message(text):
    return _v1054_cleanup_message(text)


