def _v1054_build_late_reference_from_full_pool(sorted_df, selected_df, ref_limit: int = 5):
    """선택된 TOP15 밖에 있는 후행형을 전체 후보 pool에서 다시 수집한다."""
    try:
        if sorted_df is None or not hasattr(sorted_df, 'empty') or sorted_df.empty:
            return pd.DataFrame()
        selected_codes = set()
        try:
            if selected_df is not None and hasattr(selected_df, 'iterrows') and not selected_df.empty:
                for _, srow in selected_df.iterrows():
                    code = _v1053_code(srow)
                    key = code or str(_v1050_first(srow, ['종목명', 'Name', 'name'], ''))
                    if key:
                        selected_codes.add(key)
        except Exception:
            selected_codes = set()

        ref_rows = []
        ref_codes = set()
        for _, row in sorted_df.iterrows():
            if not _v1053_is_late_row(row):
                continue
            code = _v1053_code(row)
            key = code or str(_v1050_first(row, ['종목명', 'Name', 'name'], ''))
            if not key or key in selected_codes or key in ref_codes:
                continue
            ref_rows.append(row)
            ref_codes.add(key)
            if len(ref_rows) >= int(ref_limit or 5):
                break
        return pd.DataFrame(ref_rows).reset_index(drop=True) if ref_rows else pd.DataFrame()
    except Exception as e:
        try: log_error(f'⚠️ V1054 후행 참고 pool 수집 실패: {e}')
        except Exception: pass
        return pd.DataFrame()


def _v1053_select_top15_with_late_cap(df, limit: int = 15, update_late_ref: bool = True):
    """V1054: V1053 선정 결과는 유지하되 후행 참고는 전체 pool에서 다시 수집."""
    try:
        if _V1054_BASE_SELECT_TOP15_WITH_LATE_CAP:
            selected = _V1054_BASE_SELECT_TOP15_WITH_LATE_CAP(df, limit=limit, update_late_ref=update_late_ref)
        else:
            selected = _v1050_sort_df_for_top15(df).head(limit).reset_index(drop=True)

        if update_late_ref and _v1054_env_on('V1054_COLLECT_LATE_REFERENCE_FROM_FULL_POOL', '1'):
            try:
                sorted_df = _v1050_sort_df_for_top15(df).reset_index(drop=True)
                ref_limit = max(0, _v1053_env_int('V1053_LATE_REFERENCE_LIMIT', 5)) if '_v1053_env_int' in globals() else 5
                ref = _v1054_build_late_reference_from_full_pool(sorted_df, selected, ref_limit=ref_limit)
                globals()['_V1053_LATE_REFERENCE_DF'] = ref
            except Exception:
                pass
        return selected
    except Exception as e:
        try: log_error(f'⚠️ V1054 TOP15 후행 참고 보강 실패: {e}')
        except Exception: pass
        try:
            return _v1050_sort_df_for_top15(df).head(limit).reset_index(drop=True)
        except Exception:
            return pd.DataFrame()


