def _v1055_env_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return str(default).strip().lower() in ('1', 'true', 'yes', 'y', 'on')


def _v1055_env_int(name: str, default: int = 0) -> int:
    try:
        return int(float(os.getenv(name, str(default))))
    except Exception:
        return int(default)


def _v1055_is_missing_supply_text(text) -> bool:
    try:
        s = str(text or '').strip()
        if not s:
            return True
        bads = ['미계산', '수급 확인 필요', '수급 데이터 확인 필요', '미확인']
        if any(b in s for b in bads):
            # 외인/기관 실숫자가 같이 있으면 미계산으로 보지 않는다.
            if re.search(r'(외인|기관)\s*[+\-]?[0-9,.]+\s*억', s):
                return False
            return True
        return False
    except Exception:
        return True


def _v1055_get_row_code(row) -> str:
    try:
        if '_v1053_code' in globals():
            code = _v1053_code(row)
            if code:
                return code
    except Exception:
        pass
    try:
        return _v1050_norm_code(_v1050_first(row, ['code', 'Code', '종목코드', '티커'], ''))
    except Exception:
        return ''


def _v1055_get_row_price(row) -> float:
    try:
        return _v1050_num(row.get('현재가', row.get('Close', row.get('종가', 0))), 0)
    except Exception:
        return 0.0


try:
    _V1055_BASE_SUPPLY_TEXT = _v1050_supply_text
except Exception:
    _V1055_BASE_SUPPLY_TEXT = None


def _v1055_supply_profile_to_text(prof: dict) -> str:
    try:
        if not isinstance(prof, dict) or not prof:
            return ''
        tag = str(prof.get('tag', '') or prof.get('summary', '') or '').strip()
        today = str(prof.get('today_text', '') or '').strip()
        d3 = str(prof.get('cum3_text', '') or '').strip()
        d5 = str(prof.get('cum5_text', '') or '').strip()
        if not tag or _v1055_is_missing_supply_text(tag):
            return ''
        details = []
        if today:
            details.append('1일 ' + today[:44])
        if d3:
            details.append('3일 ' + d3[:44])
        elif d5:
            details.append('5일 ' + d5[:44])
        if details:
            return tag[:42] + ' | ' + ' / '.join(details)[:88]
        return tag[:90]
    except Exception:
        return ''


def _v1055_supply_missing_reason(row) -> str:
    try:
        code = _v1055_get_row_code(row)
        name = _v1050_first(row, ['종목명', 'Name', 'name'], '') if '_v1050_first' in globals() else ''
        # 신규상장/스팩성/거래 데이터 부족 가능성이 있는 경우를 너무 단정하지 않고 표시
        hints = []
        if code and (code.startswith('45') or code.startswith('46') or code.startswith('47') or code.startswith('48') or code.startswith('49')):
            hints.append('신규·최근상장 가능')
        if name and any(k in str(name) for k in ['스팩', 'SPAC']):
            hints.append('스팩/특수종목 가능')
        hints.append('pykrx·네이버 수급표 지연/미제공 가능')
        return ' / '.join(hints[:2])
    except Exception:
        return '데이터 지연/미제공 가능'


def _v1050_supply_text(row):
    """V1055: 수급 미계산이면 프로필 fallback 조회 후, 그래도 없으면 사유를 표시."""
    try:
        base = _V1055_BASE_SUPPLY_TEXT(row) if _V1055_BASE_SUPPLY_TEXT else ''
    except Exception:
        base = ''
    try:
        if not _v1055_is_missing_supply_text(base):
            return base
        if _v1055_env_on('V1055_SUPPLY_FALLBACK_ENRICH', '1'):
            code = _v1055_get_row_code(row)
            price = _v1055_get_row_price(row)
            if code and 'get_supply_profile' in globals():
                try:
                    prof = get_supply_profile(code, price)
                    txt = _v1055_supply_profile_to_text(prof)
                    if txt and not _v1055_is_missing_supply_text(txt):
                        return txt
                except Exception:
                    pass
        if _v1055_env_on('V1055_SHOW_SUPPLY_MISSING_REASON', '1'):
            reason = _v1055_supply_missing_reason(row)
            return f'수급 미계산({reason}) | 피보·기준선 중심 보수 확인'
        return base or '수급 확인 필요'
    except Exception:
        return base or '수급 확인 필요'


def _v1055_supply_bias_from_text(s: str) -> str:
    try:
        t = str(s or '')
        if _v1055_is_missing_supply_text(t):
            return 'missing'
        if any(k in t for k in ['동반매수', '강매집', '매수 강함', '매수 우세', '외인매수', '기관매수', '개인매도흡수']):
            return 'positive'
        if any(k in t for k in ['동반매도', '매도 우세', '외인매도', '기관매도', '개인추격주의']):
            return 'negative'
        return 'neutral'
    except Exception:
        return 'missing'


def _v1055_fib_comment_core(row) -> dict:
    try:
        pack = _v1052_fib_pack(row) if '_v1052_fib_pack' in globals() else {}
        zone = str(pack.get('fib_zone', '') or '').strip()
        one = str(pack.get('fib_one_line', '') or '').strip()
        # 회복/지지 키워드만 짧게 추출
        recovery = ''
        support = ''
        m = re.search(r'회복\s*([^·|]+)', one)
        if m:
            recovery = m.group(1).strip()
        m = re.search(r'지지\s*([^·|]+)', one)
        if m:
            support = m.group(1).strip()
        return {'zone': zone, 'recovery': recovery, 'support': support, 'one': one}
    except Exception:
        return {'zone': '', 'recovery': '', 'support': '', 'one': ''}


def _v1055_supply_fib_commentary(row) -> str:
    """수급 상태와 피보 회귀권을 결합한 실전 해설 한 줄."""
    try:
        if not _v1055_env_on('V1055_SHOW_SUPPLY_FIB_COMMENTARY', '1'):
            return ''
        supply = _v1050_supply_text(row)
        bias = _v1055_supply_bias_from_text(supply)
        fib = _v1055_fib_comment_core(row)
        zone = fib.get('zone') or '피보 위치 확인 필요'
        rec = fib.get('recovery')
        sup = fib.get('support')
        phase = _v1050_phase(row) if '_v1050_phase' in globals() else ''
        parts = []
        if bias == 'positive':
            parts.append('수급 받침')
        elif bias == 'negative':
            parts.append('수급 약세/개인추격 주의')
        elif bias == 'missing':
            parts.append('수급 확인 전이라 확신 한 단계 낮춤')
        else:
            parts.append('수급 중립')
        parts.append(zone)
        if rec and sup:
            parts.append(f'회복 {rec}·지지 {sup} 확인')
        elif rec:
            parts.append(f'회복 {rec} 확인')
        elif sup:
            parts.append(f'지지 {sup} 이탈 여부 확인')
        else:
            parts.append('5일선·파란점선 동시 확인')
        if '후행' in str(phase):
            parts.append('후행형은 신규추격 금지')
        elif bias == 'missing':
            parts.append('거래량 재유입 전 소액관찰')
        maxlen = max(80, _v1055_env_int('V1055_SUPPLY_FIB_COMMENTARY_MAXLEN', 150))
        return ' · '.join([p for p in parts if p])[:maxlen]
    except Exception:
        return ''


try:
    _V1055_BASE_ITEM = _v1026_item
except Exception:
    _V1055_BASE_ITEM = None


def _v1026_item(row):
    """V1055: 오늘 매매관점 압축 item에 수급+피보 해설 필드 추가."""
    try:
        base = _V1055_BASE_ITEM(row) if _V1055_BASE_ITEM else {}
    except Exception:
        base = {}
    if not isinstance(base, dict):
        base = {}
    try:
        base['supply_fib_commentary'] = _v1055_supply_fib_commentary(row)
        # 기존 supply가 비어 있거나 미계산이면 출력용 supply도 보강
        s = str(base.get('supply', '') or '')
        if _v1055_is_missing_supply_text(s):
            base['supply'] = _v1050_supply_text(row)
    except Exception:
        pass
    return base

