def _v1055_supply_fib_commentary(row) -> str:
    """V1056: 수급+피보 해설을 쉬운 자연어 문장으로 표시."""
    try:
        if not _v1056_env_on('V1056_NATURAL_COMMENTARY', '1'):
            return _V1056_BASE_SUPPLY_FIB_COMMENTARY(row) if _V1056_BASE_SUPPLY_FIB_COMMENTARY else ''
        supply = _v1050_supply_text(row) if '_v1050_supply_text' in globals() else ''
        tone = _v1056_supply_tone(supply)
        fib_sentence = _v1056_fib_sentence(row)
        phase = _v1050_phase(row) if '_v1050_phase' in globals() else ''
        action_tail = ''
        if '후행' in str(phase):
            action_tail = ' 다만 후행형이라 새로 쫓아가기보다는 눌림 재지지를 기다리는 쪽이 낫습니다.'
        elif tone.get('tone') == 'missing':
            action_tail = ' 수급이 확인되기 전까지는 비중을 낮추고 관찰하는 편이 좋습니다.'
        elif tone.get('tone') == 'weak':
            action_tail = ' 그래서 양봉 마감과 거래량 재유입이 확인될 때만 접근하는 편이 좋습니다.'
        else:
            action_tail = ' 그래도 진입은 5일선·파란점선 재지지와 거래량 재유입을 확인한 뒤가 좋습니다.'
        msg = f"{tone.get('sentence','수급 확인이 필요합니다')}. {fib_sentence}.{action_tail}"
        maxlen = max(120, _v1056_env_int('V1056_COMMENTARY_MAXLEN', 190))
        return re.sub(r'\s+', ' ', msg).strip()[:maxlen]
    except Exception:
        try:
            return _V1056_BASE_SUPPLY_FIB_COMMENTARY(row) if _V1056_BASE_SUPPLY_FIB_COMMENTARY else ''
        except Exception:
            return ''


try:
    _V1056_BASE_TARGET_TEXT = _v1050_target_text
except Exception:
    _V1056_BASE_TARGET_TEXT = None


def _v1050_target_text(row):
    """V1056: 목표1/목표2가 역전되어 보이지 않도록 낮은 목표를 목표1로 정렬."""
    try:
        if not _v1056_env_on('V1056_FIX_TARGET_ORDER', '1'):
            return _V1056_BASE_TARGET_TEXT(row) if _V1056_BASE_TARGET_TEXT else ''
        t1 = _v1050_num(row.get('🎯목표타점', row.get('목표1', 0)), 0)
        t2 = _v1050_num(row.get('🎯목표2차', row.get('목표2', 0)), 0)
        st = _v1050_num(row.get('🚨손절가', row.get('손절가', 0)), 0)
        targets = sorted([x for x in [t1, t2] if x and x > 0])
        parts = []
        if len(targets) >= 1:
            parts.append(f"목표1 {targets[0]:,.0f}")
        if len(targets) >= 2 and abs(targets[1] - targets[0]) > 1e-6:
            parts.append(f"목표2 {targets[1]:,.0f}")
        if st > 0:
            parts.append(f"손절 {st:,.0f}")
        return ' / '.join(parts) if parts else '목표·손절은 상세카드 기준 확인'
    except Exception:
        try:
            return _V1056_BASE_TARGET_TEXT(row) if _V1056_BASE_TARGET_TEXT else ''
        except Exception:
            return '목표·손절은 상세카드 기준 확인'


