def _v1031_supply_lines(raw, prefix=''):
    """V1056: '🏦 수급'만 나오고 내용이 비는 현상 방지."""
    try:
        if not _v1056_env_on('V1056_SUPPLY_LINE_NO_EMPTY', '1'):
            return _V1056_BASE_SUPPLY_LINES(raw, prefix=prefix) if _V1056_BASE_SUPPLY_LINES else []
        txt = _v1031_clean_text(raw).replace('🏦 수급:', '').strip() if '_v1031_clean_text' in globals() else str(raw or '').replace('🏦 수급:', '').strip()
        if not txt or txt in ('수급 데이터 확인 필요', '미계산'):
            return []
        parts = [p.strip(' -') for p in txt.split('|') if p.strip(' -')]
        if not parts:
            return []
        if len(parts) == 1:
            return [prefix + '🏦 수급: ' + (_v1031_trunc(parts[0], 180) if '_v1031_trunc' in globals() else parts[0][:180])]
        out = [prefix + '🏦 수급: ' + (_v1031_trunc(parts[0], 120) if '_v1031_trunc' in globals() else parts[0][:120])]
        for p in parts[1:5]:
            if p:
                out.append(prefix + '   - ' + (_v1031_trunc(p, 120) if '_v1031_trunc' in globals() else p[:120]))
        return out
    except Exception:
        try:
            return _V1056_BASE_SUPPLY_LINES(raw, prefix=prefix) if _V1056_BASE_SUPPLY_LINES else []
        except Exception:
            return []


