def _v1055_is_missing_supply_text(text) -> bool:
    """V1057: 🧲 nan 같은 무의미 수급을 미계산으로 인식."""
    try:
        if _v1057_env_on('V1057_CLEAN_NAN_SUPPLY', '1') and _v1057_is_nan_like_supply(text):
            return True
        cleaned = _v1057_clean_supply_text(text)
        if not cleaned:
            return True
        if _V1057_PREV_IS_MISSING_SUPPLY:
            return _V1057_PREV_IS_MISSING_SUPPLY(cleaned)
        return False
    except Exception:
        return True


