def _v1031_supply_lines(raw, prefix=''):
    """V1057: 오늘 매매관점 압축에서 🧲 nan 또는 빈 수급 라인을 막는다."""
    try:
        txt = _v1057_clean_supply_text(raw)
        if not txt or _v1057_is_nan_like_supply(txt):
            return []
        # 이미 미확인 문구가 있으면 한 줄만 짧게 표시
        if _v1055_is_missing_supply_text(txt):
            if '수급 미확인' in txt:
                return [prefix + '🏦 수급: ' + (_v1031_trunc(txt, 120) if '_v1031_trunc' in globals() else txt[:120])]
            return []
        parts = [p.strip(' -') for p in re.split(r'\s*\|\s*', txt) if p.strip(' -')]
        parts = [_v1057_clean_supply_text(p) for p in parts]
        parts = [p for p in parts if p and not _v1057_is_nan_like_supply(p)]
        if not parts:
            return []
        if len(parts) == 1:
            return [prefix + '🏦 수급: ' + (_v1031_trunc(parts[0], 180) if '_v1031_trunc' in globals() else parts[0][:180])]
        out = [prefix + '🏦 수급: ' + (_v1031_trunc(parts[0], 120) if '_v1031_trunc' in globals() else parts[0][:120])]
        for p in parts[1:5]:
            out.append(prefix + '   - ' + (_v1031_trunc(p, 120) if '_v1031_trunc' in globals() else p[:120]))
        return out
    except Exception:
        try:
            return _V1057_PREV_SUPPLY_LINES(raw, prefix=prefix) if _V1057_PREV_SUPPLY_LINES else []
        except Exception:
            return []


