def _v1057_trim_sentence(text: str, maxlen: int = 165) -> str:
    try:
        s = re.sub(r'\s+', ' ', str(text or '')).strip()
        if len(s) <= maxlen:
            return s
        cut = s[:maxlen]
        # 문장 끝을 최대한 살린다.
        last = max(cut.rfind('.'), cut.rfind('다.'), cut.rfind('요.'))
        if last >= 80:
            return cut[:last+1].strip()
        return cut.rstrip(' ,·/') + '…'
    except Exception:
        return str(text or '')[:maxlen]


def _v1055_supply_fib_commentary(row) -> str:
    """V1057: 자연스럽지만 너무 길지 않은 해설. nan 수급은 보수 해석."""
    try:
        if not _v1057_env_on('V1057_CONCISE_NATURAL_COMMENTARY', '1'):
            return _V1057_PREV_SUPPLY_FIB_COMMENTARY(row) if _V1057_PREV_SUPPLY_FIB_COMMENTARY else ''
        supply = _v1050_supply_text(row) if '_v1050_supply_text' in globals() else ''
        tone = _v1056_supply_tone(supply)
        fib_sentence = _v1056_fib_sentence(row) if '_v1056_fib_sentence' in globals() else '피보 위치와 기준선을 함께 확인합니다'
        phase = _v1050_phase(row) if '_v1050_phase' in globals() else ''

        if '후행' in str(phase):
            tail = '후행형이라 새로 쫓아가기보다 눌림 재지지를 기다리는 쪽이 낫습니다.'
        elif tone.get('tone') == 'missing':
            tail = '수급이 확인되기 전까지는 비중을 낮추고 관찰하는 편이 안전합니다.'
        elif tone.get('tone') == 'weak':
            tail = '양봉 마감과 거래량 재유입이 확인될 때만 접근하는 편이 좋습니다.'
        else:
            tail = '진입은 5일선·파란점선 재지지와 거래량 재유입을 확인한 뒤가 좋습니다.'

        msg = f"{tone.get('sentence','수급 확인이 필요합니다')}. {fib_sentence}. {tail}"
        maxlen = max(130, _v1056_env_int('V1056_COMMENTARY_MAXLEN', 165) if '_v1056_env_int' in globals() else 165)
        return _v1057_trim_sentence(msg, maxlen)
    except Exception:
        try:
            return _V1057_PREV_SUPPLY_FIB_COMMENTARY(row) if _V1057_PREV_SUPPLY_FIB_COMMENTARY else ''
        except Exception:
            return ''


try:
    _V1057_PREV_ITEM = _v1026_item
except Exception:
    _V1057_PREV_ITEM = None


def _v1026_item(row):
    """V1057: 오늘 매매관점 압축 item 최종 정리. supply=nan 제거."""
    try:
        base = _V1057_PREV_ITEM(row) if _V1057_PREV_ITEM else {}
    except Exception:
        base = {}
    if not isinstance(base, dict):
        base = {}
    try:
        supply = _v1057_clean_supply_text(base.get('supply', ''))
        if not supply or _v1055_is_missing_supply_text(supply):
            supply = _v1050_supply_text(row) if '_v1050_supply_text' in globals() else ''
        supply = _v1057_clean_supply_text(supply)
        if supply and not _v1057_is_nan_like_supply(supply):
            base['supply'] = supply
        else:
            base.pop('supply', None)
        base['supply_fib_commentary'] = _v1055_supply_fib_commentary(row)
    except Exception:
        pass
    return base

