def _v1059_env_int(name: str, default: int = 0) -> int:
    try:
        return int(float(str(os.getenv(name, str(default))).strip()))
    except Exception:
        return int(default)


def _v1059_num(x, default=0.0):
    try:
        if x is None:
            return default
        if isinstance(x, str):
            x = x.replace(',', '').replace('%', '').replace('원', '').strip()
            if x == '' or x.lower() in ('nan', 'none', 'null'):
                return default
        v = float(x)
        if not np.isfinite(v):
            return default
        return v
    except Exception:
        return default


def _v1059_money_values(text: str, label: str):
    try:
        vals = []
        for m in re.finditer(rf'{re.escape(label)}\s*([+\-]?[0-9,.]+)\s*억', str(text or '')):
            try:
                vals.append(float(m.group(1).replace(',', '')))
            except Exception:
                pass
        return vals
    except Exception:
        return []


def _v1059_first_money(text: str, label: str, default=0.0) -> float:
    vals = _v1059_money_values(text, label)
    return vals[0] if vals else float(default)


def _v1059_second_money(text: str, label: str, default=0.0) -> float:
    vals = _v1059_money_values(text, label)
    return vals[1] if len(vals) >= 2 else float(default)


def _v1059_has_supply_numbers(text: str) -> bool:
    try:
        return bool(re.search(r'(개인|외인|기관)\s*[+\-]?[0-9,.]+\s*억', str(text or '')))
    except Exception:
        return False


def _v1059_supply_label_from_numbers(text: str) -> str:
    """실제 1일/3일 개인·외인·기관 금액으로 표시 라벨을 다시 만든다.
    기존 🔴기관강/🤝쌍끌 라벨이 수치와 안 맞는 경우를 바로잡기 위한 최종 라벨러.
    """
    try:
        s = _v1057_clean_supply_text(text) if '_v1057_clean_supply_text' in globals() else str(text or '').strip()
        if not _v1059_has_supply_numbers(s):
            return ''
        p1 = _v1059_first_money(s, '개인')
        f1 = _v1059_first_money(s, '외인')
        i1 = _v1059_first_money(s, '기관')
        p3 = _v1059_second_money(s, '개인')
        f3 = _v1059_second_money(s, '외인')
        i3 = _v1059_second_money(s, '기관')
        smart1 = f1 + i1
        smart3 = f3 + i3
        abs_smart1 = abs(smart1)

        # 1일 수급을 최우선, 3일 수급은 보조 확인으로만 반영한다.
        if f1 > 0 and i1 > 0:
            if smart1 >= max(10.0, abs(p1) * 0.35):
                return '🤝쌍끌강'
            return '🤝쌍끌'
        if p1 > 0 and f1 < 0 and i1 < 0:
            return '⚠️개인수급/외인기관매도'
        if f1 > 0 and i1 <= 0:
            if f1 >= max(10.0, abs(i1) * 1.2):
                return '🔵외인강'
            return '🔵외인우세'
        if i1 > 0 and f1 <= 0:
            if i1 >= max(10.0, abs(f1) * 1.2):
                return '🔴기관강'
            return '🔴기관우세'
        if smart1 < 0:
            if smart3 > 0:
                return '⚠️단기수급부담/3일혼조'
            return '⚠️수급부담'
        if abs_smart1 < 3.0 and smart3 > 0:
            return '➖단기중립/3일개선'
        if abs_smart1 < 3.0:
            return '➖수급중립'
        return '➖수급혼조'
    except Exception:
        return ''


def _v1059_strip_old_supply_label(text: str) -> str:
    try:
        s = _v1057_clean_supply_text(text) if '_v1057_clean_supply_text' in globals() else str(text or '').strip()
        if not s:
            return ''
        parts = [p.strip() for p in re.split(r'\s*\|\s*', s) if p.strip()]
        if not parts:
            return s
        # 첫 조각이 수급 금액을 포함하지 않고 라벨처럼 보이면 제거한다.
        first = parts[0]
        if not _v1059_has_supply_numbers(first):
            if any(k in first for k in ['쌍끌', '외인', '기관', '수급', '개인', '매수', '매도', '강', '우세', '중립', '부담']) or re.search(r'[🔵🔴🤝⚠️➖]', first):
                parts = parts[1:]
        return ' | '.join(parts).strip()
    except Exception:
        return str(text or '').strip()


try:
    _V1059_PREV_SUPPLY_TEXT = _v1050_supply_text
except Exception:
    _V1059_PREV_SUPPLY_TEXT = None


def _v1050_supply_text(row):
    """V1059: 수급 라벨과 실제 금액이 충돌하지 않도록 1일/3일 금액 기준 라벨을 재작성."""
    try:
        txt = _V1059_PREV_SUPPLY_TEXT(row) if _V1059_PREV_SUPPLY_TEXT else ''
    except Exception:
        txt = ''
    try:
        txt = _v1057_clean_supply_text(txt) if '_v1057_clean_supply_text' in globals() else str(txt or '').strip()
        if not txt:
            return _v1057_unknown_supply_text() if '_v1057_unknown_supply_text' in globals() else '수급 미확인: 데이터 지연/미제공 가능'
        if not _v1059_env_on('V1059_SUPPLY_RELABEL_BY_NUMBERS', '1'):
            return txt
        if '_v1055_is_missing_supply_text' in globals() and _v1055_is_missing_supply_text(txt):
            return txt
        label = _v1059_supply_label_from_numbers(txt)
        if not label:
            return txt
        body = _v1059_strip_old_supply_label(txt)
        if body:
            return f'{label} | {body}'
        return label
    except Exception:
        return txt or (_v1057_unknown_supply_text() if '_v1057_unknown_supply_text' in globals() else '수급 미확인')


try:
    _V1059_PREV_SUPPLY_TONE = _v1056_supply_tone
except Exception:
    _V1059_PREV_SUPPLY_TONE = None


def _v1056_supply_tone(supply_text: str) -> dict:
    """V1059: 자연어 해설도 재작성된 라벨보다 실제 수치를 더 우선한다."""
    try:
        s = _v1057_clean_supply_text(supply_text) if '_v1057_clean_supply_text' in globals() else str(supply_text or '').strip()
        if not s or ('_v1055_is_missing_supply_text' in globals() and _v1055_is_missing_supply_text(s)):
            return {'tone': 'missing', 'sentence': '수급 자료가 아직 깔끔하게 확인되지 않습니다'}
        if _v1059_has_supply_numbers(s):
            label = _v1059_supply_label_from_numbers(s)
            if label.startswith('🤝'):
                return {'tone': 'strong', 'sentence': '외인과 기관이 함께 들어와 수급은 좋은 편입니다'}
            if '개인수급/외인기관매도' in label or '수급부담' in label:
                return {'tone': 'weak', 'sentence': '개인이 받는 동안 외인·기관 매도가 있어 수급은 조심스럽습니다'}
            if label.startswith('🔵'):
                return {'tone': 'positive', 'sentence': '외인이 받쳐주지만 기관 수급은 아직 더 확인이 필요합니다'}
            if label.startswith('🔴'):
                return {'tone': 'positive', 'sentence': '기관은 들어오지만 외인 흐름은 한 번 더 확인이 필요합니다'}
            if label.startswith('➖'):
                return {'tone': 'neutral', 'sentence': '수급은 아직 강하게 한쪽으로 쏠리진 않았습니다'}
        # 수치가 부족한 경우만 이전 라벨 기반 톤 사용
        if _V1059_PREV_SUPPLY_TONE:
            return _V1059_PREV_SUPPLY_TONE(s)
        return {'tone': 'neutral', 'sentence': '수급은 중립으로 보고 확인이 필요합니다'}
    except Exception:
        return {'tone': 'neutral', 'sentence': '수급은 중립으로 보고 확인이 필요합니다'}


def _v1059_elliott_wave1_bundle(df, row=None, prev=None) -> dict:
    """역매공파 회복 구간에서 엘리어트 1파 초동 후보를 탐지한다.
    정의: 최근 저점 형성 후 첫 MA5/MA20 회복, MA5 우상향, 거래량 재유입, RSI 회복, 과열 전 구간.
    """
    empty = {'ok': False, 'score': 0, 'tag': '', 'comment': '', 'low_age': 999, 'rise_from_low': 0.0}
    try:
        if df is None or len(df) < 230:
            return empty
        d = df.copy()
        close = d['Close'].astype(float)
        high = d['High'].astype(float) if 'High' in d.columns else close
        low = d['Low'].astype(float) if 'Low' in d.columns else close
        vol = d['Volume'].astype(float) if 'Volume' in d.columns else pd.Series(0, index=d.index)
        ma5 = d['MA5'].astype(float) if 'MA5' in d.columns else close.rolling(5).mean()
        ma20 = d['MA20'].astype(float) if 'MA20' in d.columns else close.rolling(20).mean()
        ma112 = d['MA112'].astype(float) if 'MA112' in d.columns else close.rolling(112).mean()
        ma224 = d['MA224'].astype(float) if 'MA224' in d.columns else close.rolling(224).mean()
        vma20 = d['VMA20'].astype(float) if 'VMA20' in d.columns else vol.rolling(20).mean()
        rsi_s = d['RSI'].astype(float) if 'RSI' in d.columns else pd.Series(50, index=d.index)
        bb40_up = d['BB40_Upper'].astype(float) if 'BB40_Upper' in d.columns else close.rolling(40).mean() + close.rolling(40).std() * 2

        c = _v1059_num(close.iloc[-1], 0)
        if c <= 0:
            return empty
        tail_n = min(35, len(d))
        tail_low = low.tail(tail_n)
        rel_low_pos = int(np.argmin(tail_low.values))
        low_age = tail_n - 1 - rel_low_pos
        pivot_low = _v1059_num(tail_low.iloc[rel_low_pos], 0)
        rise = ((c / pivot_low) - 1.0) * 100.0 if pivot_low > 0 else 0.0

        had_bear = bool(((ma5 < ma112) & (ma112 < ma224)).tail(180).fillna(False).any())
        ma_between = _v1045_ma_between(ma5.iloc[-1], ma112.iloc[-1], ma224.iloc[-1], tol=0.05) if '_v1045_ma_between' in globals() else bool(min(ma112.iloc[-1], ma224.iloc[-1])*0.95 <= ma5.iloc[-1] <= max(ma112.iloc[-1], ma224.iloc[-1])*1.05)
        first_leg_age_ok = bool(1 <= low_age <= 18)
        first_leg_rise_ok = bool(3.0 <= rise <= 24.0)
        ma5_turn = bool(_v1059_num(ma5.iloc[-1], 0) > _v1059_num(ma5.iloc[-4] if len(ma5) >= 4 else ma5.iloc[-1], 0))
        ma20_reclaim = bool(c >= _v1059_num(ma20.iloc[-1], c) * 0.985)
        ma5_reclaim = bool(c >= _v1059_num(ma5.iloc[-1], c) * 0.995)
        hh_short = bool(_v1059_num(high.iloc[-1], 0) >= _v1059_num(high.tail(6).iloc[:-1].max(), 0) * 0.995) if len(high) >= 6 else False
        vol_reentry = bool(_v1059_num(vol.iloc[-1], 0) >= max(1.0, _v1059_num(vma20.iloc[-1], 0)) * 1.05 or _v1059_num(vol.tail(3).mean(), 0) >= max(1.0, _v1059_num(vma20.iloc[-1], 0)) * 0.95)
        rsi_now = _v1059_num(rsi_s.iloc[-1], 50)
        rsi_prev5 = _v1059_num(rsi_s.iloc[-6] if len(rsi_s) >= 6 else rsi_s.iloc[-1], 50)
        rsi_recover = bool(42 <= rsi_now <= 68 and rsi_now >= rsi_prev5 - 1.0)
        disp = (c / _v1059_num(ma20.iloc[-1], c) * 100.0) if _v1059_num(ma20.iloc[-1], 0) > 0 else 100.0
        not_hot = bool(disp <= 114.0 and rsi_now <= 69.5)
        bb40_near = bool(c >= _v1059_num(bb40_up.iloc[-1], c) * 0.94) if _v1059_num(bb40_up.iloc[-1], 0) > 0 else False

        checks = [had_bear, ma_between, first_leg_age_ok, first_leg_rise_ok, ma5_turn, ma20_reclaim or ma5_reclaim, vol_reentry, rsi_recover, not_hot]
        score = int(sum(1 for x in checks if x))
        ok = bool(score >= 7 and had_bear and first_leg_age_ok and first_leg_rise_ok and (ma20_reclaim or ma5_reclaim) and not_hot)
        # BB40이 아직 멀어도 1파 초동은 인정하되, 역매공파 TOP5 편입은 기존 맥락과 함께 점수로 조절한다.
        tag = '🌊1파초동' if ok else ''
        comment = ''
        if ok:
            comment = f"최근저점 {low_age}봉 전 → 저점대비 +{rise:.1f}% 첫 상승파동. MA5/MA20 회복과 거래량 재유입이 동반되면 엘리어트 1파 초동 후보"
            if not bb40_near:
                comment += '이며, 아직 BB40 저항선까지는 거리 확인 필요'
        return {'ok': ok, 'score': score, 'tag': tag, 'comment': comment, 'low_age': int(low_age), 'rise_from_low': float(rise), 'bb40_near': bool(bb40_near)}
    except Exception:
        return empty


try:
    _V1059_PREV_YMGP_CALC = _v1045_calc_ymgp_bb40_bundle
except Exception:
    _V1059_PREV_YMGP_CALC = None


def _v1045_calc_ymgp_bb40_bundle(df, row, prev):
    """V1059: 기존 역매공파/BB40 해석에 엘리어트 1파 초동 후보를 합친다."""
    try:
        base = _V1059_PREV_YMGP_CALC(df, row, prev) if _V1059_PREV_YMGP_CALC else {}
    except Exception:
        base = {}
    if not isinstance(base, dict):
        base = {}
    try:
        if not _v1059_env_on('V1059_YMGP_ELLIOTT_WAVE1', '1'):
            return base
        wave = _v1059_elliott_wave1_bundle(df, row, prev)
        if not wave.get('ok'):
            return base
        bonus = max(0, _v1059_env_int('V1059_YMGP_WAVE1_SCORE_BONUS', 8))
        base['score'] = max(0, min(100, int(_v1059_num(base.get('score'), 0)) + bonus))
        tag = str(base.get('tag', '') or '').strip()
        if '1파' not in tag:
            base['tag'] = (tag + ' 🌊1파초동').strip()
        role = str(base.get('bb40_role', '') or '').strip()
        wave_role = '엘리어트 1파 초동: 최근 저점 이후 첫 회복파동'
        base['bb40_role'] = (role + ' / ' + wave_role).strip(' /') if role else wave_role
        comment = str(base.get('comment', '') or '').strip()
        wcomment = str(wave.get('comment', '') or '').strip()
        if wcomment and '1파' not in comment:
            base['comment'] = (comment + ' → ' + wcomment).strip(' →') if comment else wcomment
        base['elliott_wave1'] = True
        base['elliott_wave1_score'] = int(wave.get('score', 0) or 0)
        base['elliott_wave1_comment'] = wcomment

        # 기존 BB40 문맥 점수가 아주 살짝 모자라더라도, 역배열 회복+1파 초동이면 TOP5 후보로 승격한다.
        if not bool(base.get('context', False)) and _v1059_env_on('V1059_YMGP_WAVE1_PROMOTE', '1'):
            if bool(base.get('bear_recent', False)) and bool(base.get('ma5_between_112_224', False)) and int(wave.get('score', 0) or 0) >= 7:
                base['context'] = True
                base['state'] = str(base.get('state') or '엘리어트 1파 초동/BB40 저항전')
                base['tag'] = str(base.get('tag') or '🌊1파초동 🚧BB40저항전')
                if not base.get('bb40_role'):
                    base['bb40_role'] = '역배열 회복 뒤 첫 상승파동. BB40은 다음 저항선으로 확인'
                base['score'] = max(int(base.get('score', 0) or 0), 62)
        return base
    except Exception:
        return base


try:
    _V1059_PREV_YMGP_BLOCK = _v1046_build_ymgp_bb40_block
except Exception:
    _V1059_PREV_YMGP_BLOCK = None


def _v1046_build_ymgp_bb40_block(df, title='역매공파/BB40 재정의 TOP 5') -> str:
    """V1059: 역매공파 TOP5 출력에 엘리어트 1파 초동 설명을 명시한다."""
    try:
        if not _v1046_env_on('SHOW_YMGP_BB40_TOP5', '1'):
            return ''
        header_lines = [
            '🏆 [역매공파/BB40 재정의 TOP 5]',
            '',
            '기준: 과거 역배열 → MA5가 MA112~MA224 사이 회복 → BB40 상단 저항/재지지 + 엘리어트 1파 초동 여부 확인',
            ''
        ]
        if df is None or not hasattr(df, 'empty') or df.empty:
            return '\n'.join(header_lines + ['- 해당 종목 없음']).strip()
        lines = list(header_lines)
        for i, row in df.iterrows():
            d = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            name = _v1046_s(d.get('종목명') or d.get('Name'))
            code = _v1046_norm_code(d.get('code') or d.get('Code'))
            price = int(_v1046_num(d.get('현재가') or d.get('Close'), 0))
            score = int(_v1046_num(d.get('역매공파BB40점수'), 0))
            state = _v1046_s(d.get('역매공파BB40상태'))
            tag = _v1046_s(d.get('역매공파BB40태그'))
            role = _v1046_s(d.get('역매공파BB40역할'))
            comment = _v1046_s(d.get('역매공파BB40코멘트'))
            rsi = int(_v1046_num(d.get('RSI'), 0))
            disp = int(_v1046_num(d.get('이격'), 0))
            bb40 = _v1046_num(d.get('BB40'), 0)
            pblue = int(_v1046_num(d.get('파란점선') or d.get('BB30시프트선') or d.get('기준가'), 0))
            supply = _v1046_s(d.get('수급요약') or d.get('수급판정') or d.get('수급'), '-')
            try:
                if supply and '_v1050_supply_text' in globals():
                    # row 안의 수급도 최종 라벨러로 한번 더 정리
                    supply = _v1050_supply_text(d)
            except Exception:
                pass
            stop = int(_v1046_num(d.get('🚨손절가'), 0))
            t1 = int(_v1046_num(d.get('🎯목표타점'), 0))
            wave1 = ('1파' in (tag + role + comment)) or bool(d.get('엘리어트1파초동', False))
            lines.append(f"{i+1}) {name}({code}) | 현재 {price:,} | 점수 {score}")
            lines.append(f"   🏷️ {tag or state} | {state}")
            lines.append(f"   📌 해석: {role or 'BB40 상단을 저항선으로 보고 돌파 후 눌림/재지지 확인'}")
            if wave1:
                lines.append("   🌊 1파: 최근 저점 이후 첫 회복파동 후보입니다. 바로 추격보다 2파 눌림이 얕게 끝나고 재상승하는지 확인합니다.")
            if comment:
                lines.append(f"   🧠 맥락: {comment[:120]}")
            lines.append(f"   📊 이격 {disp} | RSI {rsi} | BB40폭 {bb40:.1f}")
            if pblue > 0:
                lines.append(f"   🔵 기준선: {pblue:,}원 재지지/종가 안착 확인")
            if t1 > 0 or stop > 0:
                lines.append(f"   🎯 목표 {t1:,} / 손절 {stop:,}" if t1 > 0 and stop > 0 else f"   🎯 목표/손절: {t1:,}/{stop:,}")
            if supply and supply != '-':
                lines.append(f"   🏦 수급: {supply[:90]}")
            lines.append('')
        return '\n'.join(lines).strip()
    except Exception as e:
        try: log_error(f'⚠️ V1059 역매공파 TOP5 블록 생성 실패: {e}')
        except Exception: pass
        try:
            return _V1059_PREV_YMGP_BLOCK(df, title=title) if _V1059_PREV_YMGP_BLOCK else ''
        except Exception:
            return ''

