# =============================================================
# ✅ TRADE_CLARITY_V10_6_0_YMGP_WAVE_PHASE_ACTIVE
# - 역매공파/BB40 TOP5에 엘리어트 파동 위치를 항상 표시
# - 1파초동/1파진행/2파눌림/후행주의를 쉬운 말로 구분
# - 수급 한 줄이 잘리면서 "기관"처럼 끊기는 문제 방어
# =============================================================
print("✅ TRADE_CLARITY_V10_6_0_YMGP_WAVE_PHASE_ACTIVE LOADED")

try:
    os.environ.setdefault('V1060_YMGP_ALWAYS_SHOW_WAVE_PHASE', '1')
    os.environ.setdefault('V1060_YMGP_WAVE_TAG_ON_LABEL', '1')
    os.environ.setdefault('V1060_YMGP_SUPPLY_SAFE_SHORTEN', '1')
except Exception:
    pass


def _v1060_txt(x, default=''):
    try:
        if x is None:
            return default
        s = str(x).strip()
        if s.lower() in ('nan', 'none', 'null'):
            return default
        return s
    except Exception:
        return default


def _v1060_num(x, default=0.0):
    try:
        return _v1059_num(x, default) if '_v1059_num' in globals() else safe_float(x, default)
    except Exception:
        return default


def _v1060_env_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() not in ('0', 'false', 'no', 'off', '')
    except Exception:
        return str(default).strip().lower() not in ('0', 'false', 'no', 'off', '')


def _v1060_pick(d: dict, *keys, default=''):
    for k in keys:
        try:
            v = d.get(k)
            if v is not None and str(v).strip() and str(v).strip().lower() not in ('nan', 'none', 'null'):
                return v
        except Exception:
            pass
    return default


def _v1060_supply_short(supply: str, max_len: int = 150) -> str:
    """수급 문자열을 자르되 '기관'처럼 항목명만 남는 끊김을 막는다."""
    try:
        s = _v1057_clean_supply_text(supply) if '_v1057_clean_supply_text' in globals() else str(supply or '').strip()
        if not s:
            return ''
        parts = [p.strip() for p in re.split(r'\s*\|\s*', s) if p and p.strip()]
        clean = []
        for idx, p in enumerate(parts):
            # 첫 조각은 라벨이므로 유지, 이후는 숫자/억/수급문구가 있는 것만 유지
            if idx == 0:
                clean.append(p)
                continue
            if re.search(r'[+\-]?[0-9,.]+\s*억', p) or any(k in p for k in ['미확인','데이터','수급','매수','매도']):
                clean.append(p)
        if clean:
            s = ' | '.join(clean)
        if len(s) <= max_len:
            return s
        # 항목 단위로 최대 길이에 맞춘다.
        out = []
        for p in clean:
            cand = ' | '.join(out + [p])
            if len(cand) <= max_len:
                out.append(p)
            else:
                break
        res = ' | '.join(out).strip()
        return res if res else s[:max_len].rstrip(' |/')
    except Exception:
        return str(supply or '').strip()[:max_len]


def _v1060_ymgp_wave_phase(d: dict) -> dict:
    """역매공파/BB40 상태를 엘리어트 관점으로 쉬운 단계로 해석한다.
    실제 1파 초동만 억지로 찍지 않고, 1파초동/1파진행/2파눌림/후행주의를 구분한다.
    """
    try:
        state = _v1060_txt(_v1060_pick(d, '역매공파BB40상태', 'ymgp_state', 'state'))
        tag = _v1060_txt(_v1060_pick(d, '역매공파BB40태그', 'tag'))
        role = _v1060_txt(_v1060_pick(d, '역매공파BB40역할', 'role'))
        comment = _v1060_txt(_v1060_pick(d, '역매공파BB40코멘트', 'comment'))
        wave_stage = _v1060_txt(_v1060_pick(d, '파동타점상태', 'wave_stage'))
        first = _v1060_num(_v1060_pick(d, '파동1파점수', 'first_wave_score', default=0), 0)
        pull = _v1060_num(_v1060_pick(d, '파동눌림점수', 'pullback_health_score', default=0), 0)
        restart = _v1060_num(_v1060_pick(d, '파동재출발점수', 'restart_score', default=0), 0)
        rsi = _v1060_num(_v1060_pick(d, 'RSI', default=0), 0)
        disp = _v1060_num(_v1060_pick(d, '이격', 'Disparity', default=100), 100)
        bb40_state_blob = ' '.join([state, tag, role, comment])

        # 이미 기존 파동엔진이 명시적으로 잡은 경우를 최우선으로 사용
        if any(x in wave_stage for x in ['눌림타점형', '재출발']):
            return {
                'tag': '🌊3파초입후보',
                'state': '3파 초입 후보',
                'line': '1파 뒤 눌림을 거치고 다시 힘이 붙는 자리입니다. 그래도 재양봉과 거래량 재유입이 확인될 때만 실행하는 편이 좋습니다.',
            }
        if any(x in wave_stage for x in ['눌림대기형', '확인대기형', '회복확인형']):
            return {
                'tag': '🌊2파눌림대기',
                'state': '2파 눌림 대기',
                'line': '첫 상승파동 뒤 눌림을 기다리는 구간입니다. 눌림이 깊지 않고 기준선 위에서 재지지되면 다음 상승파동 후보로 봅니다.',
            }
        if '1파발생형' in wave_stage or (first >= 18 and pull < 18 and rsi <= 69 and disp <= 114):
            return {
                'tag': '🌊1파초동',
                'state': '1파 초동',
                'line': '최근 저점 이후 첫 상승파동이 막 시작된 후보입니다. 바로 추격하기보다 첫 눌림이 얕게 끝나는지 확인하는 게 좋습니다.',
            }

        # 역매공파/BB40 상태 기반 보조 판정
        if '돌파후눌림' in bb40_state_blob or '재지지' in bb40_state_blob:
            return {
                'tag': '🌊2파눌림확인',
                'state': '2파 눌림 확인',
                'line': 'BB40 저항을 한 번 넘긴 뒤 눌림을 보는 자리입니다. 눌림이 BB40·기준선 위에서 버티면 다음 상승파동으로 이어질 수 있습니다.',
            }
        if '저항돌파' in bb40_state_blob:
            if rsi >= 70 or disp >= 115:
                return {
                    'tag': '🌊1파후반주의',
                    'state': '1파 후반/후행 주의',
                    'line': '이미 BB40 저항을 넘겼지만 단기 이격이나 RSI 부담이 있습니다. 신규 추격보다 눌림 재지지를 확인하는 쪽이 안전합니다.',
                }
            return {
                'tag': '🌊1파진행',
                'state': '1파 진행',
                'line': '역배열 회복 뒤 첫 상승파동이 진행 중인 모습입니다. 여기서는 돌파봉 추격보다 2파 눌림이 얕게 끝나는지 확인합니다.',
            }
        if '저항전' in bb40_state_blob:
            if 38 <= rsi <= 62 and 92 <= disp <= 108:
                return {
                    'tag': '🌊1파초동관찰',
                    'state': '1파 초동 관찰',
                    'line': '아직 BB40 저항 돌파 전이지만 역배열 회복 뒤 첫 상승파동이 시작될 수 있는 자리입니다. 5일선과 기준선 지지를 먼저 확인합니다.',
                }
            return {
                'tag': '🌊전환관찰',
                'state': '전환 관찰',
                'line': '아직 1파가 확정된 자리는 아닙니다. BB40 저항 돌파와 거래량 재유입이 붙는지 확인합니다.',
            }
        if rsi >= 70 or disp >= 115:
            return {
                'tag': '🌊후행주의',
                'state': '후행 주의',
                'line': '파동상으로는 이미 많이 진행됐을 수 있습니다. 신규 진입보다는 눌림과 재지지 확인이 우선입니다.',
            }
        return {
            'tag': '🌊파동관찰',
            'state': '파동 관찰',
            'line': '1파 초동으로 단정하기는 이릅니다. 기준선 회복과 거래량 재유입이 같이 붙는지 확인합니다.',
        }
    except Exception:
        return {'tag': '🌊파동관찰', 'state': '파동 관찰', 'line': '파동 위치는 추가 확인이 필요합니다.'}


try:
    _V1060_PREV_YMGP_BLOCK = _v1046_build_ymgp_bb40_block
except Exception:
    _V1060_PREV_YMGP_BLOCK = None


def _v1046_build_ymgp_bb40_block(df, title='역매공파/BB40 재정의 TOP 5') -> str:
    """V1060: 역매공파 TOP5에 1파초동/1파진행/2파눌림을 항상 표시한다."""
    try:
        if '_v1046_env_on' in globals() and not _v1046_env_on('SHOW_YMGP_BB40_TOP5', '1'):
            return ''
        header_lines = [
            '🏆 [역매공파/BB40 재정의 TOP 5]',
            '',
            '기준: 과거 역배열 → MA5가 MA112~MA224 사이 회복 → BB40 상단 저항/재지지 + 엘리어트 파동 위치 확인',
            ''
        ]
        if df is None or not hasattr(df, 'empty') or df.empty:
            return '\n'.join(header_lines + ['- 해당 종목 없음']).strip()
        lines = list(header_lines)
        for n, (_, row) in enumerate(df.iterrows(), start=1):
            d = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            name = _v1046_s(d.get('종목명') or d.get('Name')) if '_v1046_s' in globals() else _v1060_txt(d.get('종목명') or d.get('Name'))
            code = _v1046_norm_code(d.get('code') or d.get('Code')) if '_v1046_norm_code' in globals() else _v1060_txt(d.get('code') or d.get('Code'))
            price = int(_v1060_num(d.get('현재가') or d.get('Close'), 0))
            score = int(_v1060_num(d.get('역매공파BB40점수'), 0))
            state = _v1060_txt(d.get('역매공파BB40상태'))
            tag = _v1060_txt(d.get('역매공파BB40태그'))
            role = _v1060_txt(d.get('역매공파BB40역할'))
            comment = _v1060_txt(d.get('역매공파BB40코멘트'))
            wave = _v1060_ymgp_wave_phase(d)
            if _v1060_env_on('V1060_YMGP_WAVE_TAG_ON_LABEL', '1') and wave.get('tag') and wave.get('tag') not in tag:
                # 저항전/돌파/눌림 상태 앞에 파동 태그를 붙여 한눈에 보이게 한다.
                tag = (tag + ' ' + wave.get('tag')).strip()
            rsi = int(_v1060_num(d.get('RSI'), 0))
            disp = int(_v1060_num(d.get('이격'), 0))
            bb40 = _v1060_num(d.get('BB40'), 0)
            pblue = int(_v1060_num(d.get('파란점선') or d.get('BB30시프트선') or d.get('기준가'), 0))
            supply = _v1060_txt(d.get('수급요약') or d.get('수급판정') or d.get('수급'), '')
            try:
                if '_v1050_supply_text' in globals():
                    supply = _v1050_supply_text(d)
            except Exception:
                pass
            supply = _v1060_supply_short(supply, 155) if _v1060_env_on('V1060_YMGP_SUPPLY_SAFE_SHORTEN', '1') else supply
            stop = int(_v1060_num(d.get('🚨손절가'), 0))
            t1 = int(_v1060_num(d.get('🎯목표타점'), 0))
            lines.append(f"{n}) {name}({code}) | 현재 {price:,} | 점수 {score}")
            lines.append(f"   🏷️ {tag or state} | {state}")
            lines.append(f"   📌 해석: {role or 'BB40 상단을 저항선으로 보고 돌파 후 눌림/재지지 확인'}")
            if _v1060_env_on('V1060_YMGP_ALWAYS_SHOW_WAVE_PHASE', '1'):
                lines.append(f"   🌊 파동: {wave.get('state')} — {wave.get('line')}")
            if comment:
                lines.append(f"   🧠 맥락: {comment[:125]}")
            lines.append(f"   📊 이격 {disp} | RSI {rsi} | BB40폭 {bb40:.1f}")
            if pblue > 0:
                lines.append(f"   🔵 기준선: {pblue:,}원 재지지/종가 안착 확인")
            if t1 > 0 or stop > 0:
                lines.append(f"   🎯 목표 {t1:,} / 손절 {stop:,}" if t1 > 0 and stop > 0 else f"   🎯 목표/손절: {t1:,}/{stop:,}")
            if supply:
                lines.append(f"   🏦 수급: {supply}")
            lines.append('')
        return '\n'.join(lines).strip()
    except Exception as e:
        try:
            log_error(f'⚠️ V1060 역매공파 TOP5 블록 생성 실패: {e}')
        except Exception:
            pass
        try:
            return _V1060_PREV_YMGP_BLOCK(df, title=title) if _V1060_PREV_YMGP_BLOCK else ''
        except Exception:
            return ''

