def _v1061_env_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() not in ('0', 'false', 'no', 'off', '')
    except Exception:
        return str(default).strip().lower() not in ('0', 'false', 'no', 'off', '')


def _v1061_env_int(name: str, default: int = 0) -> int:
    try:
        return int(float(str(os.getenv(name, str(default))).strip()))
    except Exception:
        return int(default)


def _v1061_txt(x, default=''):
    try:
        if x is None:
            return default
        try:
            if isinstance(x, float) and pd.isna(x):
                return default
        except Exception:
            pass
        s = str(x).strip()
        if s.lower() in ('nan', 'none', 'null'):
            return default
        return s
    except Exception:
        return default


def _v1061_num(x, default=0.0):
    try:
        if '_v1060_num' in globals():
            return _v1060_num(x, default)
        if '_v1059_num' in globals():
            return _v1059_num(x, default)
        return safe_float(x, default)
    except Exception:
        return default


def _v1061_int(x, default=0):
    try:
        return int(round(_v1061_num(x, default)))
    except Exception:
        return int(default)


def _v1061_trunc(text: str, max_len: int = 120) -> str:
    try:
        s = re.sub(r'\s+', ' ', _v1061_txt(text)).strip()
        if len(s) <= max_len:
            return s
        cut = s[:max_len]
        # 문장 중간에서 너무 어색하게 끊기지 않도록 구분자 기준으로 자른다.
        pos = max(cut.rfind('.'), cut.rfind('다.'), cut.rfind('요.'), cut.rfind(' / '), cut.rfind(' · '))
        if pos >= max(45, max_len // 2):
            return cut[:pos+1].rstrip(' /·,')
        return cut.rstrip(' /·,') + '…'
    except Exception:
        return str(text or '')[:max_len]


def _v1061_pick(row, keys, default=''):
    for k in keys:
        try:
            v = row.get(k, None)
        except Exception:
            try:
                v = row[k]
            except Exception:
                v = None
        s = _v1061_txt(v, '')
        if s:
            return s
    return default


def _v1061_ai_comment(row, max_len=None) -> str:
    """기존 AI코멘트/ai_tip이 있으면 우선 사용하고, 없으면 빠른 룰 기반 코멘트로 대체."""
    try:
        if not _v1061_env_on('V1061_SHOW_AI_COMMENT', '1'):
            return ''
        max_len = max_len or _v1061_env_int('V1061_AI_COMMENT_MAXLEN', 118)
        candidates = []
        # 1) 실제 AI 심판/AI 요약 계열 우선
        for keys in [
            ['AI최종판정', 'AI심판요약'],
            ['AI강한근거', 'AI기술의견'],
            ['AI수급의견', 'AI시황의견'],
            ['ai_tip', 'AI코멘트', 'AI_COMMENT', 'AI요약'],
        ]:
            vals = []
            for k in keys:
                try:
                    v = _v1061_txt(row.get(k, ''), '')
                except Exception:
                    v = ''
                if v and v not in ('브리핑 생성 실패', 'AI 분석 불가 (API 키 없음 또는 호출 실패)', '타이밍 애매, 추가 확인 필요'):
                    vals.append(v)
            if vals:
                candidates.append(' / '.join(vals))
        # 2) 1단계 fast ai tip이 이미 생성됐으면 사용
        try:
            fast = _v1061_txt(row.get('ai_tip', ''), '')
            if fast and fast not in ('브리핑 생성 실패', 'AI 분석 불가 (API 키 없음 또는 호출 실패)'):
                candidates.append(fast)
        except Exception:
            pass
        # 3) 없으면 룰 기반 빠른 코멘트 생성
        if not candidates and 'generate_stage_ai_tip' in globals():
            try:
                candidates.append(generate_stage_ai_tip(row))
            except Exception:
                pass
        msg = ''
        for c in candidates:
            c = _v1061_txt(c, '')
            if c:
                msg = c
                break
        if not msg:
            return ''
        # 너무 반복적인 문구는 줄인다.
        msg = re.sub(r'\s+', ' ', msg).strip()
        msg = msg.replace('입니다. 입니다.', '입니다.')
        return _v1061_trunc(msg, max_len)
    except Exception:
        return ''


def _v1061_wave_line(row, max_len=None) -> str:
    """소파동·중파동 박스와 현재 위치를 compact하게 표시."""
    try:
        if not _v1061_env_on('V1061_SHOW_WAVE_LINES', '1'):
            return ''
        max_len = max_len or _v1061_env_int('V1061_WAVE_LINE_MAXLEN', 145)
        small_low = _v1061_num(_v1061_pick(row, ['소파동저점', 'small_low']), 0)
        small_high = _v1061_num(_v1061_pick(row, ['소파동전고점', 'small_high']), 0)
        mid_low = _v1061_num(_v1061_pick(row, ['중파동저점', 'mid_low']), 0)
        mid_high = _v1061_num(_v1061_pick(row, ['중파동전고점', 'mid_high']), 0)
        s_pos = _v1061_pick(row, ['소파동위치권', '소파동위치', 'small_pos_label', 'small_state'], '')
        m_pos = _v1061_pick(row, ['중파동위치권', '중파동위치', 'mid_pos_label', 'mid_state'], '')
        s_dir = _v1061_pick(row, ['소파동박스방향', 'small_box_dir'], '')
        m_dir = _v1061_pick(row, ['중파동박스방향', 'mid_box_dir'], '')
        s_ang = _v1061_num(_v1061_pick(row, ['소파동각도', 'small_angle'], 0), 0)
        m_ang = _v1061_num(_v1061_pick(row, ['중파동각도', 'mid_angle'], 0), 0)
        parts = []
        if small_low > 0 and small_high > 0:
            p = f"소 {small_low:,.0f}~{small_high:,.0f}"
            if s_pos: p += f" {s_pos}"
            if s_dir: p += f"/{s_dir}"
            if abs(s_ang) > 0.01: p += f" 각{s_ang:.1f}"
            parts.append(p)
        if mid_low > 0 and mid_high > 0:
            p = f"중 {mid_low:,.0f}~{mid_high:,.0f}"
            if m_pos: p += f" {m_pos}"
            if m_dir: p += f"/{m_dir}"
            if abs(m_ang) > 0.01: p += f" 각{m_ang:.1f}"
            parts.append(p)
        if not parts:
            # 파동 박스가 없더라도 기존 파동 단계가 있으면 짧게 표시
            phase = _v1061_pick(row, ['파동타점상태', 'wave_stage', '파동상태'], '')
            if phase:
                return _v1061_trunc(f"🌊 파동: {phase}", max_len)
            return ''
        # 간단한 해석 추가
        interp = ''
        txt = ' '.join([s_pos, m_pos, s_dir, m_dir])
        if '상단' in txt or '전고점' in txt:
            interp = '추격보다 눌림 확인'
        elif '하단' in txt:
            interp = '손절 짧은 관찰'
        elif '상향' in txt:
            interp = '눌림 지지 후 재상승 관찰'
        elif '하향' in txt:
            interp = '저항 확인 우선'
        line = '〰️/📶 파동: ' + ' | '.join(parts)
        if interp:
            line += f" · {interp}"
        return _v1061_trunc(line, max_len)
    except Exception:
        return ''


try:
    _V1061_BASE_ITEM = _v1026_item
except Exception:
    _V1061_BASE_ITEM = None


def _v1026_item(row):
    """V1061: 오늘 매매관점 압축 item에 AI코멘트와 소/중파동 요약을 추가."""
    try:
        base = _V1061_BASE_ITEM(row) if _V1061_BASE_ITEM else {}
    except Exception:
        base = {}
    if not isinstance(base, dict):
        base = {}
    try:
        base['ai_comment'] = _v1061_ai_comment(row)
        base['wave_line'] = _v1061_wave_line(row)
        # 해설과 AI를 너무 길게 합치지 않고, 기존 해설은 유지한다.
        if not base.get('supply_fib_commentary') and '_v1055_supply_fib_commentary' in globals():
            base['supply_fib_commentary'] = _v1055_supply_fib_commentary(row)
    except Exception:
        pass
    return base


try:
    _V1061_BASE_TODAY_BLOCK = _v102_make_today_action_block
except Exception:
    _V1061_BASE_TODAY_BLOCK = None


def _v102_make_today_action_block(rows, base=''):
    """V1061: 오늘 매매관점 압축에 소/중파동과 AI코멘트 복구."""
    try:
        if not _v1061_env_on('V1061_TODAY_ACTION_AI_WAVE', '1'):
            return _V1061_BASE_TODAY_BLOCK(rows, base=base) if _V1061_BASE_TODAY_BLOCK else str(base or '')
        items, used = [], set()
        for r in rows or []:
            try:
                it = _v1026_item(r)
                key = it.get('code') or it.get('name')
                if not key or key in used:
                    continue
                used.add(key)
                items.append(it)
            except Exception:
                continue
        if not items:
            return _V1061_BASE_TODAY_BLOCK(rows, base=base) if _V1061_BASE_TODAY_BLOCK else str(base or '')
        items = sorted(items, key=lambda x: (x.get('priority', 9), -x.get('score', 0), x.get('name','')))
        total = len(items)
        cond_limit = _v1021_limit('TODAY_ACTION_EXECUTE_LIMIT', 5) if '_v1021_limit' in globals() else 5
        observe_limit = _v1021_limit('TODAY_ACTION_OBSERVE_LIMIT', 10) if '_v1021_limit' in globals() else 10
        holder_limit = _v1021_limit('TODAY_ACTION_HOLDER_LIMIT', 4) if '_v1021_limit' in globals() else 4
        avoid_limit = max(0, _v1023_env_int('TODAY_ACTION_AVOID_LIMIT', 0)) if '_v1023_env_int' in globals() else 0
        show_excluded = _v1031_env_bool('SHOW_EXCLUDED_RISK', False) if '_v1031_env_bool' in globals() else False
        groups = [
            ('조건부 실행','🟢 [진입 후보] 5일선·파란점선 위 양봉마감 + 거래량 기준 확인'),
            ('눌림 대기','🟡 [관찰 후보] 5일선 눌림/파란점선 재지지 대기'),
            ('보유자 대응','🛡️ [보유자] 이탈선 관리 우선'),
        ]
        limits = {'조건부 실행': cond_limit, '눌림 대기': observe_limit, '보유자 대응': holder_limit}
        out = [
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
            '🎯 [오늘 매매관점 압축]',
            '',
            f'📌 후보 수집: {total}개',
            '📌 시황 대장주 별도 분석은 생략하고, 실제 스캔 후보만 정리합니다.',
            '📌 파동 참고: 소파동·중파동 위치와 엘리어트 1파/2파 흐름을 함께 확인합니다.',
            '📌 피보 참고: 38.2/50/61.8 되돌림과 현재가 회귀권을 함께 확인합니다.',
            '📌 AI 참고: AI코멘트는 보조 의견이며, 최종 진입은 5일선·파란점선·거래량으로 확인합니다.',
            '📌 진입 숫자 기준: 5일선·파란점선 위 양봉 마감 + 거래량 전일比 1.3배↑ 또는 5일평균比 1.2배↑',
            '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
        ]
        shown_total = 0
        for label, title in groups:
            arr = [x for x in items if x.get('label') == label]
            if not arr:
                continue
            limit = limits.get(label, 5)
            out.append('')
            suffix = f' {min(len(arr), limit)}/{len(arr)}개' if len(arr) > limit else f' {len(arr)}개'
            out.append(title + suffix)
            out.append('────────────────────')
            for i, it in enumerate(arr[:limit], 1):
                name = _v1031_clean_text(it.get('name') or '-') if '_v1031_clean_text' in globals() else str(it.get('name') or '-')
                code_part = f"({it['code']})" if it.get('code') else ''
                cur = it.get('cur') or '-'
                out.append(f'{i}) {name}{code_part} | 현재 {cur}')
                out.append(f"   ✅ 대응: {_v1031_trunc(it.get('display_label') or it.get('label') or '-', 80)}")
                if it.get('pattern'):
                    out.append(f"   🔎 검색패턴: {_v1031_trunc(it['pattern'], 110)}")
                if it.get('accum_type'):
                    out.append(f"   🧲 매집: {_v1031_trunc(it['accum_type'], 120)}")
                if it.get('wyckoff'):
                    out.append(f"   📦 와이코프: {_v1031_trunc(it['wyckoff'], 130)}")
                if it.get('ki'):
                    out.append(f"   🔥 끼: {_v1031_trunc(it['ki'], 90)}")
                if it.get('finance'):
                    out.append(f"   🏢 기업: {_v1031_trunc(it['finance'], 115)}")
                if it.get('blue'):
                    out.append(f"   🔵 기준: {_v1031_trunc(_v1031_clean_text(it['blue']), 130)}")
                if it.get('wave_line'):
                    out.append(f"   〰️ 파동: {_v1031_trunc(it['wave_line'].replace('〰️/📶 파동: ', ''), 135)}")
                if it.get('fib_line'):
                    out.append(f"   📐 피보/회귀: {_v1031_trunc(it['fib_line'], 145)}")
                if it.get('supply_fib_commentary'):
                    out.append(f"   🧭 해설: {_v1031_trunc(it['supply_fib_commentary'], 170)}")
                if it.get('ai_comment'):
                    out.append(f"   🤖 AI코멘트: {_v1031_trunc(it['ai_comment'], 130)}")
                entry_txt = it.get('entry_criteria') or it.get('entry')
                if entry_txt:
                    out.append(f"   🎯 진입: {_v1031_trunc(_v1031_clean_text(entry_txt), 145)}")
                try:
                    out.extend(_v1031_supply_block_for_item(it, indent='   '))
                except Exception:
                    if it.get('supply') and it.get('supply') != '수급 데이터 확인 필요':
                        out.append(f"   🏦 수급: {_v1031_trunc(it['supply'], 108)}")
                out.append('')
                shown_total += 1
        excluded = [x for x in items if x.get('label') == '추격 금지']
        if excluded:
            out.append(f'⛔ 제외/리스크 참고: {len(excluded)}개')
            if show_excluded and avoid_limit > 0:
                for i, it in enumerate(excluded[:avoid_limit], 1):
                    code_part = f"({it['code']})" if it.get('code') else ''
                    reasons = ' / '.join((it.get('decision') or {}).get('reasons') or [])
                    out.append(f"   {i}) {it.get('name','-')}{code_part} | {_v1031_trunc(reasons, 90)}")
            else:
                out.append('   상세는 기본 숨김입니다. 필요하면 SHOW_EXCLUDED_RISK=1, TODAY_ACTION_AVOID_LIMIT=5')
        if shown_total == 0:
            out.append('')
            out.append('- 실행/관찰 후보 없음. 오늘은 5일선 눌림과 파란점선 재지지만 확인합니다.')
        out.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
        msg = '\n'.join([x for x in out if x is not None])
        return _v1054_cleanup_message(msg) if '_v1054_cleanup_message' in globals() else msg
    except Exception as e:
        try: log_error(f'⚠️ V1061 오늘 매매관점 AI/파동 복구 실패: {e}')
        except Exception: pass
        return _V1061_BASE_TODAY_BLOCK(rows, base=base) if _V1061_BASE_TODAY_BLOCK else str(base or '')


try:
    _V1061_BASE_TOP15_BLOCK = _v1050_build_compact_top15_block
except Exception:
    _V1061_BASE_TOP15_BLOCK = None


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    """V1061: TOP15 compact에 AI코멘트와 소/중파동 요약을 복구."""
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return ''
        limit = max(1, int(limit or 15))
        update_ref = False
        try:
            update_ref = len(df) > limit
        except Exception:
            update_ref = True
        out_df = _v1053_select_top15_with_late_cap(df, limit=limit, update_late_ref=update_ref).head(limit).reset_index(drop=True)
        if out_df.empty:
            return ''
        late_max = _v1053_env_int('V1053_TOP15_LATE_MAX', 3) if '_v1053_env_int' in globals() else 3
        lines = []
        lines.append(f"📢 [{title}]")
        lines.append('')
        lines.append('기준: 차트/구조/수급 우선 1단계 분석입니다. 재무·뉴스·AI 심층분석은 2단계 보조로 분리합니다.')
        lines.append(f'정렬 보정: 후행형은 TOP15 안에서 최대 {late_max}개까지만 유지하고, 초과분은 후행 참고로 분리합니다.')
        lines.append('진입 공통조건: 5일선·파란점선 위 양봉 마감 + 거래량 전일比 1.3배↑ 또는 5일평균比 1.2배↑')
        lines.append('피보/파동 기준: 38.2/50/61.8 회귀권과 소파동·중파동 위치를 함께 확인합니다.')
        lines.append('AI코멘트: 1단계 빠른 보조 의견이며, 최종 진입은 기준선·거래량으로 확인합니다.')
        lines.append('')
        for i, row in out_df.iterrows():
            name = _v1050_first(row, ['종목명', 'Name', 'name'], '-')
            code = _v1053_code(row) if '_v1053_code' in globals() else _v1050_norm_code(_v1050_first(row, ['code', 'Code', '종목코드'], ''))
            price = _v1050_num(row.get('현재가', row.get('Close', 0)), 0)
            phase = _v1050_phase(row)
            stage = _v1050_stage(row)
            sig = _v1050_signal(row)
            pattern = _v1050_pattern(row)
            supply = _v1050_supply_text(row)
            entry = _v1050_entry_text(row)
            action = _v1050_action_text(row)
            target = _v1050_target_text(row)
            fib_line = _v1052_fib_line(row, prefix='') if '_v1052_fib_line' in globals() else ''
            wave_line = _v1061_wave_line(row)
            ai_comment = _v1061_ai_comment(row)
            fib_comment = _v1055_supply_fib_commentary(row) if '_v1055_supply_fib_commentary' in globals() else ''
            safe = _v1050_int(row.get('안전점수', 0), 0)
            nscore = _v1050_int(row.get('N점수', 0), 0)
            rsi = _v1050_num(row.get('RSI', 0), 0)
            disp = _v1050_num(row.get('이격', 0), 0)
            bb40 = _v1050_num(row.get('BB40', 0), 0)
            obv = _v1050_num(row.get('OBV기울기', 0), 0)
            header_code = f"({code})" if code else ''
            price_s = f"{price:,.0f}원" if price > 0 else '-'
            lines.append(f"{i+1}) {name}{header_code} | 현재 {price_s} | 유형 {phase}")
            lines.append(f"   🎯 신호: {sig}")
            if stage:
                lines.append(f"   📶 단계: {stage}")
            lines.append(f"   🔎 구조: {pattern}")
            lines.append(f"   📊 지표: 이격 {disp:.0f} / RSI {rsi:.0f} / BB40 {bb40:.1f} / OBV {obv:+.0f} / 안전{safe}·N{nscore}")
            lines.append(f"   🏦 수급: {supply}")
            lines.append(f"   🔵 기준: {entry}")
            if wave_line:
                lines.append(f"   {wave_line}")
            if fib_line:
                lines.append(f"   📐 피보/회귀: {_v1061_trunc(fib_line, 175)}")
            if fib_comment:
                lines.append(f"   🧭 해설: {_v1061_trunc(fib_comment, 170)}")
            if ai_comment:
                lines.append(f"   🤖 AI코멘트: {_v1061_trunc(ai_comment, 125)}")
            lines.append(f"   ✅ 대응: {action}")
            lines.append(f"   🎯 가격: {target}")
            lines.append('')
        late_ref_block = _v1053_build_late_reference_block() if '_v1053_build_late_reference_block' in globals() else ''
        if late_ref_block:
            lines.append(late_ref_block)
            lines.append('')
        msg = '\n'.join(lines).strip()
        return _v1054_cleanup_message(msg) if '_v1054_cleanup_message' in globals() else msg
    except Exception as e:
        try: log_error(f'⚠️ V1061 TOP15 AI/파동 compact block 생성 실패: {e}')
        except Exception: pass
        try:
            return _V1061_BASE_TOP15_BLOCK(df, limit=limit, title=title) if _V1061_BASE_TOP15_BLOCK else ''
        except Exception:
            return ''


try:
    _V1061_BASE_YMGP_BLOCK = _v1046_build_ymgp_bb40_block
except Exception:
    _V1061_BASE_YMGP_BLOCK = None


def _v1061_value_wave_title(title='') -> str:
    try:
        if not _v1061_env_on('V1061_RENAME_YMGP_TO_VALUE_WAVE', '1'):
            return title or '역매공파/BB40 재정의 TOP 5'
        return '저평가 1파/BB40 회복 TOP 5'
    except Exception:
        return '저평가 1파/BB40 회복 TOP 5'


def _v1046_build_ymgp_bb40_block(df, title='저평가 1파/BB40 회복 TOP 5') -> str:
    """V1061: 역매공파 명칭을 저평가 1파/BB40 회복으로 변경하고 파동/AI 보조 해설을 함께 표시."""
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return ''
        title = _v1061_value_wave_title(title)
        lines = []
        lines.append(f'🏆 [{title}]')
        lines.append('')
        lines.append('기준: 저평가·소외 구간에서 바닥을 다진 뒤, MA5가 MA112~MA224 구간으로 회복하고 BB40 저항/재지지와 1파 초동 여부를 함께 확인합니다.')
        lines.append('')
        for i, row in df.head(5).reset_index(drop=True).iterrows():
            d = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            name = _v1046_s(d.get('종목명') or d.get('Name')) if '_v1046_s' in globals() else _v1061_txt(d.get('종목명') or d.get('Name'))
            code = _v1046_norm_code(d.get('code') or d.get('Code')) if '_v1046_norm_code' in globals() else _v1061_txt(d.get('code') or d.get('Code'))
            price = _v1061_int(d.get('현재가') or d.get('Close'), 0)
            score = _v1061_int(d.get('역매공파BB40점수'), 0)
            state = _v1061_txt(d.get('역매공파BB40상태'))
            tag = _v1061_txt(d.get('역매공파BB40태그'))
            role = _v1061_txt(d.get('역매공파BB40역할'))
            comment = _v1061_txt(d.get('역매공파BB40코멘트'))
            wave = _v1060_ymgp_wave_phase(d) if '_v1060_ymgp_wave_phase' in globals() else {'tag':'', 'label':'파동 확인', 'comment':'파동 위치를 함께 확인합니다.'}
            if wave.get('tag') and wave.get('tag') not in tag:
                tag = (tag + ' ' + wave.get('tag')).strip()
            wave_box = _v1061_wave_line(d, max_len=135)
            ai_comment = _v1061_ai_comment(d, max_len=105)
            rsi = _v1061_int(d.get('RSI'), 0)
            disp = _v1061_int(d.get('이격'), 0)
            bb40 = _v1061_num(d.get('BB40'), 0)
            pblue = _v1061_int(d.get('파란점선') or d.get('BB30시프트선') or d.get('기준가'), 0)
            supply = _v1061_txt(d.get('수급요약') or d.get('수급판정') or d.get('수급'), '')
            if not supply and '_v1050_supply_text' in globals():
                try:
                    supply = _v1050_supply_text(d)
                except Exception:
                    supply = ''
            supply = _v1060_supply_short(supply, 155) if '_v1060_supply_short' in globals() else _v1061_trunc(supply, 155)
            stop = _v1061_int(d.get('🚨손절가'), 0)
            t1 = _v1061_int(d.get('🎯목표타점'), 0)
            code_s = f'({code})' if code else ''
            lines.append(f"{i+1}) {name}{code_s} | 현재 {price:,} | 점수 {score}")
            lines.append(f"   🏷️ {tag or '-'} | {role or state or '-'}")
            lines.append(f"   📌 해석: {comment or 'BB40 저항/재지지와 1파 위치를 함께 확인'}")
            lines.append(f"   🌊 파동: {wave.get('label','파동 확인')} — {wave.get('comment','소파동·중파동과 1파/2파 위치를 함께 확인합니다.')}")
            if wave_box:
                lines.append(f"   {wave_box}")
            ctx = f"저평가/소외 이력 {int(_v1061_num(d.get('역배열이력일수', d.get('역배열이력', 0)), 0) or 0)}일 → MA5가 MA112~MA224 사이 회복 → {role or state}. BB40은 단독 신호가 아니라 저항/재지지선으로 확인"
            lines.append(f"   🧠 맥락: {_v1061_trunc(ctx, 145)}")
            lines.append(f"   📊 이격 {disp} | RSI {rsi} | BB40폭 {bb40:.1f}")
            if pblue > 0:
                lines.append(f"   🔵 기준선: {pblue:,}원 재지지/종가 안착 확인")
            if ai_comment:
                lines.append(f"   🤖 AI코멘트: {ai_comment}")
            if t1 > 0 or stop > 0:
                lines.append(f"   🎯 목표 {t1:,} / 손절 {stop:,}")
            if supply:
                lines.append(f"   🏦 수급: {supply}")
            lines.append('')
        msg = '\n'.join(lines).strip()
        return _v1054_cleanup_message(msg) if '_v1054_cleanup_message' in globals() else msg
    except Exception as e:
        try: log_error(f'⚠️ V1061 저평가 1파/BB40 블록 생성 실패: {e}')
        except Exception: pass
        try:
            return _V1061_BASE_YMGP_BLOCK(df, title='저평가 1파/BB40 회복 TOP 5') if _V1061_BASE_YMGP_BLOCK else ''
        except Exception:
            return ''

