# ✅ TRADE_CLARITY_V10_6_2_AI_COMMENT_CLEAN_VALUE_WAVE_ACTIVE
# - AI코멘트에서 DROP/내부 단계명/중복 문구 제거
# - AI코멘트를 진입 판단용 짧은 자연어 코멘트로 정리
# - 저평가 1파/BB40 회복 블록의 맥락/파동 문구를 자연스럽게 보정
# - 후행 참고 TOP의 피보 문장 잘림 보정
# =============================================================
print("✅ TRADE_CLARITY_V10_6_2_AI_COMMENT_CLEAN_VALUE_WAVE_ACTIVE LOADED")

try:
    os.environ.setdefault('V1062_CLEAN_AI_COMMENT', '1')
    os.environ.setdefault('V1062_AI_COMMENT_MAXLEN', '92')
    os.environ.setdefault('V1062_VALUE_WAVE_CONTEXT_NATURAL', '1')
    os.environ.setdefault('V1062_LATE_REFERENCE_CLEAN', '1')
except Exception:
    pass


def _v1062_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() not in ('0', 'false', 'no', 'off', '')
    except Exception:
        return str(default).strip().lower() not in ('0', 'false', 'no', 'off', '')


def _v1062_int_env(name: str, default: int = 92) -> int:
    try:
        return int(float(str(os.getenv(name, str(default))).strip()))
    except Exception:
        return int(default)


def _v1062_txt(x, default=''):
    try:
        if x is None:
            return default
        try:
            if isinstance(x, float) and pd.isna(x):
                return default
        except Exception:
            pass
        s = str(x).strip()
        if s.lower() in ('nan', 'none', 'null'):
            return default
        return s
    except Exception:
        return default


def _v1062_num(x, default=0.0):
    try:
        if '_v1061_num' in globals():
            return _v1061_num(x, default)
        if '_v1060_num' in globals():
            return _v1060_num(x, default)
        return safe_float(x, default)
    except Exception:
        return default


def _v1062_trunc(text: str, max_len: int = 92) -> str:
    try:
        s = re.sub(r'\s+', ' ', _v1062_txt(text)).strip()
        s = s.replace('..', '.').replace(' .', '.')
        if len(s) <= max_len:
            return s
        cut = s[:max_len]
        # 문장 끝이 있으면 거기서 끊고, 없으면 너무 어색하지 않게 말줄임표 처리
        pos = max(cut.rfind('다.'), cut.rfind('요.'), cut.rfind('. '), cut.rfind(' 확인'))
        if pos >= max(38, max_len // 2):
            end = cut[:pos+2].rstrip(' /·,')
            return end
        return cut.rstrip(' /·,') + '…'
    except Exception:
        return str(text or '')[:max_len]


def _v1062_contains_internal_ai_terms(s: str) -> bool:
    bad = [
        'DROP 단계', 'DROP', 'stage', 'Stage', '단계로 분류', '종합 점수가 높아',
        '안전점수가 높은 편이라', '무너지기 전까지는', '다만 무효화 기',
        '현재 구조의 위치 해석이 가능합니다', 'OBV 기울기가 살아 있어 수급의 방향성은 나쁘지 않습니다',
    ]
    return any(b in s for b in bad)


def _v1062_supply_label(row) -> str:
    try:
        if '_v1050_supply_text' in globals():
            return _v1062_txt(_v1050_supply_text(row), '')
    except Exception:
        pass
    for k in ['수급요약', '수급판정', '수급']:
        try:
            s = _v1062_txt(row.get(k, ''), '')
            if s:
                return s
        except Exception:
            pass
    return ''


def _v1062_simple_ai_comment(row, max_len=None) -> str:
    """기존 AI 문구가 길거나 내부용어일 때 대체하는 사용자용 짧은 판단 코멘트."""
    try:
        max_len = max_len or _v1062_int_env('V1062_AI_COMMENT_MAXLEN', 92)
        rsi = _v1062_num(row.get('RSI', 0), 0) if hasattr(row, 'get') else 0
        disp = _v1062_num(row.get('이격', row.get('Disparity', 100)), 100) if hasattr(row, 'get') else 100
        phase = ''
        sig = ''
        pattern = ''
        try:
            phase = _v1050_phase(row) if '_v1050_phase' in globals() else _v1062_txt(row.get('유형',''))
        except Exception:
            phase = _v1062_txt(row.get('유형','')) if hasattr(row, 'get') else ''
        try:
            sig = _v1050_signal(row) if '_v1050_signal' in globals() else _v1062_txt(row.get('대표신호',''))
        except Exception:
            sig = _v1062_txt(row.get('대표신호','')) if hasattr(row, 'get') else ''
        try:
            pattern = _v1050_pattern(row) if '_v1050_pattern' in globals() else _v1062_txt(row.get('검색패턴',''))
        except Exception:
            pattern = _v1062_txt(row.get('검색패턴','')) if hasattr(row, 'get') else ''
        supply = _v1062_supply_label(row)
        blob = ' '.join([phase, sig, pattern, supply])

        if '후행' in blob or rsi >= 70 or disp >= 115:
            msg = '이미 파동이 꽤 진행된 자리입니다. 새로 쫓기보다 눌림 재지지와 거래량 재유입을 기다리는 쪽이 안전합니다.'
        elif any(x in blob for x in ['개인수급', '외인기관매도', '단기수급부담']):
            msg = '수급 부담이 있어 보수적으로 봅니다. 회복선 위 안착과 거래량 재유입이 확인될 때만 접근하는 편이 좋습니다.'
        elif any(x in blob for x in ['쌍끌강', '쌍끌', '외인강', '기관강', '외인우세', '기관우세']):
            msg = '수급은 받쳐주는 편입니다. 다만 바로 추격하기보다 5일선·파란점선 재지지 확인 후 접근이 좋습니다.'
        elif any(x in blob for x in ['RSI-DIV', '저항전', '하단', '깊은회귀권']):
            msg = '바닥 회복을 보는 자리입니다. 바로 매수보다 회복선 위 안착과 거래량 증가가 먼저 확인돼야 합니다.'
        elif any(x in blob for x in ['거래량폭발', '초동', '돌파']):
            msg = '초동 돌파 성격은 있지만 확인이 필요합니다. 첫 눌림에서 기준선이 버티는지 보는 전략이 좋습니다.'
        else:
            msg = '구조는 관찰할 만하지만 아직 확정 구간은 아닙니다. 기준선 지지와 거래량 재유입을 먼저 확인하세요.'
        if '가짜수박주의' in blob:
            msg += ' 가짜수박주의가 있어 종가 안착 전 추격은 피합니다.'
        return _v1062_trunc(msg, max_len)
    except Exception:
        return ''


# V1061 함수명을 그대로 덮어써 기존 출력 경로가 자동으로 짧은 자연어 코멘트를 쓰게 한다.
def _v1061_ai_comment(row, max_len=None) -> str:
    try:
        if not _v1062_on('V1062_CLEAN_AI_COMMENT', '1'):
            return ''
        max_len = max_len or _v1062_int_env('V1062_AI_COMMENT_MAXLEN', 92)
        # 실제 외부 AI 판정이 있고 내부 용어가 없을 때만 짧게 사용한다.
        raw = ''
        for k in ['AI최종판정', 'AI심판요약', 'AI강한근거', 'AI기술의견', 'AI수급의견', 'AI코멘트', 'AI요약']:
            try:
                raw = _v1062_txt(row.get(k, ''), '')
            except Exception:
                raw = ''
            if raw:
                break
        if raw and not _v1062_contains_internal_ai_terms(raw):
            raw = re.sub(r'\s+', ' ', raw).strip()
            return _v1062_trunc(raw, max_len)
        return _v1062_simple_ai_comment(row, max_len=max_len)
    except Exception:
        return _v1062_simple_ai_comment(row, max_len=max_len or 92)


def _v1062_value_wave_context(d: dict, role: str, state: str, comment: str) -> str:
    try:
        inv_days = int(round(_v1062_num(d.get('역배열이력일수', d.get('역배열이력', d.get('과거역배열일수', 0))), 0)))
        if inv_days <= 1:
            # 값이 1로 잘못 들어오는 경우가 많아, 확정 숫자 대신 자연어로 표현한다.
            head = '과거 역배열·소외 구간을 거친 뒤'
        else:
            head = f'과거 역배열·소외 구간 {inv_days}일 이력 후'
        state_txt = role or state or comment or 'BB40 저항/재지지 확인 구간'
        return f'{head}, MA5가 MA112~MA224 구간으로 회복하고 {state_txt}을 확인하는 자리입니다. BB40은 매수 신호가 아니라 저항/재지지 기준선으로 봅니다.'
    except Exception:
        return '과거 역배열·소외 구간 이후 MA5 회복과 BB40 저항/재지지를 확인하는 자리입니다.'


def _v1062_wave_phase_for_value(d: dict) -> dict:
    try:
        wave = _v1060_ymgp_wave_phase(d) if '_v1060_ymgp_wave_phase' in globals() else {'tag':'🌊파동관찰','state':'파동 관찰','line':'파동 위치는 추가 확인이 필요합니다.'}
        tag = _v1062_txt(wave.get('tag',''))
        state = _v1062_txt(wave.get('state') or wave.get('label') or '파동 관찰')
        line = _v1062_txt(wave.get('line') or wave.get('comment') or '소파동·중파동과 1파/2파 위치를 함께 확인합니다.')
        # V1061에서 label/comment 키를 기대하면서 generic하게 찍힌 문제 보정
        if not line or '소파동·중파동과 1파/2파 위치' in line:
            blob = ' '.join([_v1062_txt(d.get('역매공파BB40상태','')), _v1062_txt(d.get('역매공파BB40태그','')), _v1062_txt(d.get('역매공파BB40역할',''))])
            rsi = _v1062_num(d.get('RSI',0),0); disp = _v1062_num(d.get('이격',100),100)
            if '재지지' in blob or '돌파후눌림' in blob:
                tag, state, line = '🌊2파눌림확인', '2파 눌림 확인', '첫 상승파동 뒤 눌림을 확인하는 자리입니다. 기준선과 BB40 위에서 버티면 다음 상승파동 후보입니다.'
            elif '저항돌파' in blob:
                if rsi >= 70 or disp >= 115:
                    tag, state, line = '🌊1파후반주의', '1파 후반 주의', '이미 1파가 많이 진행됐을 수 있습니다. 신규 추격보다 2파 눌림 재지지를 기다리는 편이 안전합니다.'
                else:
                    tag, state, line = '🌊1파진행', '1파 진행', '역배열 회복 뒤 첫 상승파동이 진행 중입니다. 돌파 추격보다 2파 눌림을 기다리는 전략이 좋습니다.'
            elif '저항테스트' in blob:
                tag, state, line = '🌊1파초동', '1파 초동', 'BB40 저항을 시험하는 초동 구간입니다. 종가 안착과 거래량 재유입이 붙는지 확인합니다.'
            elif '저항전' in blob:
                tag, state, line = '🌊1파초동관찰', '1파 초동 관찰', '아직 BB40 저항 돌파 전입니다. 5일선과 기준선 지지가 살아나는지 먼저 확인합니다.'
        return {'tag': tag, 'state': state, 'line': line}
    except Exception:
        return {'tag':'🌊파동관찰','state':'파동 관찰','line':'파동 위치는 추가 확인이 필요합니다.'}


try:
    _V1062_PREV_YMGP_BLOCK = _v1046_build_ymgp_bb40_block
except Exception:
    _V1062_PREV_YMGP_BLOCK = None


def _v1046_build_ymgp_bb40_block(df, title='저평가 1파/BB40 회복 TOP 5') -> str:
    """V1062: 저평가 1파/BB40 블록의 파동/맥락/AI코멘트를 사용자용 자연어로 정리."""
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return '🏆 [저평가 1파/BB40 회복 TOP 5]\n\n- 해당 종목 없음'
        lines = [
            '🏆 [저평가 1파/BB40 회복 TOP 5]',
            '',
            '기준: 저평가·소외 구간에서 바닥을 다진 뒤, MA5가 MA112~MA224 구간으로 회복하고 BB40 저항/재지지와 1파·2파 위치를 함께 확인합니다.',
            ''
        ]
        for i, row in df.head(5).reset_index(drop=True).iterrows():
            d = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            name = _v1046_s(d.get('종목명') or d.get('Name')) if '_v1046_s' in globals() else _v1062_txt(d.get('종목명') or d.get('Name'))
            code = _v1046_norm_code(d.get('code') or d.get('Code')) if '_v1046_norm_code' in globals() else _v1062_txt(d.get('code') or d.get('Code'))
            price = int(_v1062_num(d.get('현재가') or d.get('Close'), 0))
            score = int(_v1062_num(d.get('역매공파BB40점수'), 0))
            state = _v1062_txt(d.get('역매공파BB40상태'))
            tag = _v1062_txt(d.get('역매공파BB40태그'))
            role = _v1062_txt(d.get('역매공파BB40역할'))
            comment = _v1062_txt(d.get('역매공파BB40코멘트'))
            wave = _v1062_wave_phase_for_value(d)
            if wave.get('tag') and wave.get('tag') not in tag:
                tag = (tag + ' ' + wave.get('tag')).strip()
            wave_box = _v1061_wave_line(d, max_len=128) if '_v1061_wave_line' in globals() else ''
            ai_comment = _v1061_ai_comment(d, max_len=88)
            rsi = int(_v1062_num(d.get('RSI'), 0))
            disp = int(_v1062_num(d.get('이격'), 0))
            bb40 = _v1062_num(d.get('BB40'), 0)
            pblue = int(_v1062_num(d.get('파란점선') or d.get('BB30시프트선') or d.get('기준가'), 0))
            supply = ''
            try:
                supply = _v1050_supply_text(d) if '_v1050_supply_text' in globals() else _v1062_txt(d.get('수급요약') or d.get('수급판정') or d.get('수급'))
            except Exception:
                supply = _v1062_txt(d.get('수급요약') or d.get('수급판정') or d.get('수급'))
            supply = _v1060_supply_short(supply, 135) if '_v1060_supply_short' in globals() else _v1062_trunc(supply, 135)
            stop = int(_v1062_num(d.get('🚨손절가'), 0))
            t1 = int(_v1062_num(d.get('🎯목표타점'), 0))
            lines.append(f"{i+1}) {name}({code}) | 현재 {price:,} | 점수 {score}")
            lines.append(f"   🏷️ {tag or state or '-'} | {role or state or '-'}")
            lines.append(f"   📌 해석: {comment or role or 'BB40 저항/재지지와 파동 위치를 함께 확인하는 자리'}")
            lines.append(f"   🌊 파동: {wave.get('state','파동 관찰')} — {_v1062_trunc(wave.get('line',''), 120)}")
            if wave_box:
                lines.append(f"   {wave_box}")
            lines.append(f"   🧠 맥락: {_v1062_trunc(_v1062_value_wave_context(d, role, state, comment), 150)}")
            lines.append(f"   📊 이격 {disp} | RSI {rsi} | BB40폭 {bb40:.1f}")
            if pblue > 0:
                lines.append(f"   🔵 기준선: {pblue:,}원 재지지/종가 안착 확인")
            if ai_comment:
                lines.append(f"   🤖 AI코멘트: {ai_comment}")
            if t1 > 0 or stop > 0:
                lines.append(f"   🎯 목표 {t1:,} / 손절 {stop:,}")
            if supply:
                lines.append(f"   🏦 수급: {supply}")
            lines.append('')
        msg = '\n'.join(lines).strip()
        return _v1054_cleanup_message(msg) if '_v1054_cleanup_message' in globals() else msg
    except Exception as e:
        try: log_error(f'⚠️ V1062 저평가 1파/BB40 블록 생성 실패: {e}')
        except Exception: pass
        try:
            return _V1062_PREV_YMGP_BLOCK(df, title=title) if _V1062_PREV_YMGP_BLOCK else ''
        except Exception:
            return ''


# 후행 참고 TOP에서 피보 문구가 잘려 "38.2"만 남는 문제 보정
try:
    _V1062_PREV_LATE_REF = _v1053_build_late_reference_block
except Exception:
    _V1062_PREV_LATE_REF = None


def _v1062_late_fib_short(row) -> str:
    try:
        fib = _v1052_fib_line(row, prefix='') if '_v1052_fib_line' in globals() else ''
        fib = _v1062_txt(fib, '')
        if not fib:
            return '피보 기준 확인 필요'
        # 후행 참고는 너무 긴 피보 라인 대신 핵심 대응만 표시
        if '61.8 하단' in fib:
            return '깊은회귀권 · 61.8 회복 확인'
        if '50~61.8' in fib:
            return '황금회귀권 · 50 회복/61.8 지지 확인'
        if '38.2~50' in fib:
            return '얕은회귀권 · 38.2 회복/50 지지 확인'
        if '38.2 위' in fib:
            return '38.2 위 강세권 · 38.2 재지지 확인'
        return _v1062_trunc(fib, 55)
    except Exception:
        return '피보 기준 확인 필요'


def _v1053_build_late_reference_block() -> str:
    try:
        if not _v1062_on('V1062_LATE_REFERENCE_CLEAN', '1'):
            return _V1062_PREV_LATE_REF() if _V1062_PREV_LATE_REF else ''
        ref = globals().get('_V1053_LATE_REFERENCE_ROWS', None)
        if ref is None or not hasattr(ref, 'empty') or ref.empty:
            return ''
        limit = _v1053_env_int('V1053_LATE_REFERENCE_LIMIT', 5) if '_v1053_env_int' in globals() else 5
        lines = [
            '🛡️ [후행 참고 TOP]',
            'TOP15에서 제외한 후행형입니다. 신규 추격보다 보유관리·눌림 재지지 확인용입니다.',
            ''
        ]
        for i, (_, row) in enumerate(ref.head(limit).iterrows(), 1):
            name = _v1050_first(row, ['종목명','Name','name'], '-') if '_v1050_first' in globals() else _v1062_txt(row.get('종목명') or row.get('Name'), '-')
            code = _v1053_code(row) if '_v1053_code' in globals() else _v1062_txt(row.get('code') or row.get('Code'))
            price = _v1062_num(row.get('현재가', row.get('Close', 0)), 0)
            rsi = _v1062_num(row.get('RSI', 0), 0)
            disp = _v1062_num(row.get('이격', row.get('Disparity', 0)), 0)
            sig = _v1050_signal(row) if '_v1050_signal' in globals() else _v1062_txt(row.get('대표신호',''))
            entry = _v1050_entry_text(row) if '_v1050_entry_text' in globals() else ''
            fib = _v1062_late_fib_short(row)
            code_s = f'({code})' if code else ''
            lines.append(f"{i}) {name}{code_s} | 현재 {price:,.0f}원 | 이격 {disp:.0f} / RSI {rsi:.0f}")
            lines.append(f"   신호 {sig} | {fib}")
            lines.append(f"   대응 추격금지 · 5일선/파란점선/피보 재지지 확인 | {entry}")
            lines.append('')
        msg = '\n'.join(lines).strip()
        return _v1054_cleanup_message(msg) if '_v1054_cleanup_message' in globals() else msg
    except Exception as e:
        try: log_error(f'⚠️ V1062 후행 참고 TOP 정리 실패: {e}')
        except Exception: pass
        return _V1062_PREV_LATE_REF() if _V1062_PREV_LATE_REF else ''

