def _v1054_cleanup_message(msg: str) -> str:
    """V1063: 전체 텔레그램 메시지의 잔여 어색한 표현을 최종 정리."""
    try:
        s = _V1063_PREV_CLEANUP_MESSAGE(msg) if _V1063_PREV_CLEANUP_MESSAGE else str(msg or '')
    except Exception:
        s = str(msg or '')
    try:
        if not _v1063_on('V1063_FINAL_LANGUAGE_POLISH', '1'):
            return s
        repl = {
            '후행형: 추격금지, 38.2 재지지 확인': '후행형: 추격금지, 회귀선 재지지 확인',
            '확인을 확인하는 자리입니다': '확인하는 자리입니다',
            '확인을 확인': '확인',
            'BB40 상단 저항선 종가 돌파 확인을 확인': 'BB40 상단 저항 돌파를 확인',
            'BB40 상단이 저항에서 지지선 후보로 전환을 확인': 'BB40 상단의 재지지 전환을 확인',
            'BB40 상단 저항선 돌파 전 관찰을 확인': 'BB40 상단 저항 돌파 전 구간을 관찰',
            '역배열이력': '소외/저평가 이력',
            '역배열·소외': '소외/저평가',
            '과거 역배열': '과거 소외/저평가',
        }
        for a, b in repl.items():
            s = s.replace(a, b)
        return s
    except Exception:
        return s


# V1062 함수명을 다시 덮어써 모든 출력 경로의 AI코멘트를 세밀화한다.
def _v1062_simple_ai_comment(row, max_len=None) -> str:
    """V1063: 수급 유형별로 조금 더 정확한 짧은 AI코멘트."""
    try:
        max_len = max_len or int(float(os.getenv('V1063_AI_COMMENT_MAXLEN', os.getenv('V1062_AI_COMMENT_MAXLEN', '105'))))
    except Exception:
        max_len = 105
    try:
        rsi = _v1063_num(row.get('RSI', 0), 0) if hasattr(row, 'get') else 0
        disp = _v1063_num(row.get('이격', row.get('Disparity', 100)), 100) if hasattr(row, 'get') else 100
        phase = ''
        sig = ''
        pattern = ''
        try:
            phase = _v1050_phase(row) if '_v1050_phase' in globals() else _v1063_txt(row.get('유형',''))
        except Exception:
            phase = _v1063_txt(row.get('유형','')) if hasattr(row, 'get') else ''
        try:
            sig = _v1050_signal(row) if '_v1050_signal' in globals() else _v1063_txt(row.get('대표신호',''))
        except Exception:
            sig = _v1063_txt(row.get('대표신호','')) if hasattr(row, 'get') else ''
        try:
            pattern = _v1050_pattern(row) if '_v1050_pattern' in globals() else _v1063_txt(row.get('검색패턴',''))
        except Exception:
            pattern = _v1063_txt(row.get('검색패턴','')) if hasattr(row, 'get') else ''
        supply = _v1063_supply_text(row)
        label = _v1063_supply_label(supply)
        blob = ' '.join([phase, sig, pattern, supply, label])

        # 리스크/후행 조건 우선
        if '후행' in blob or rsi >= 70 or disp >= 115:
            msg = '이미 파동이 진행된 자리입니다. 새로 쫓기보다 눌림 재지지와 거래량 재유입을 기다리는 쪽이 안전합니다.'
        elif '개인수급/외인기관매도' in label or '수급부담' in label or '단기수급부담' in label:
            msg = '수급 부담이 있어 보수적으로 봅니다. 회복선 위 안착과 거래량 재유입이 확인될 때만 접근하는 편이 좋습니다.'
        elif '쌍끌강' in label:
            msg = '외인과 기관이 함께 받쳐주는 수급입니다. 다만 급하게 쫓기보다 기준선 재지지를 확인한 뒤가 좋습니다.'
        elif '쌍끌' in label:
            msg = '외인·기관이 같이 들어오지만 강도는 확인이 필요합니다. 5일선과 파란점선 재지지를 봅니다.'
        elif '외인강' in label:
            msg = '외인 수급은 좋지만 기관은 아직 확인이 필요합니다. 추격보다 눌림 재지지 확인 후 접근이 좋습니다.'
        elif '외인우세' in label:
            msg = '외인이 받쳐주는 흐름입니다. 기관 수급이 붙는지 보면서 기준선 재지지를 확인합니다.'
        elif '기관강' in label:
            msg = '기관 수급은 좋지만 외인 매도가 부담입니다. 추격보다 눌림 재지지 확인이 좋습니다.'
        elif '기관우세' in label:
            msg = '기관은 들어오지만 외인 흐름은 더 확인이 필요합니다. 회복선 안착 후 접근이 좋습니다.'
        elif any(x in blob for x in ['RSI-DIV', '저항전', '하단', '깊은회귀권']):
            msg = '바닥 회복을 보는 자리입니다. 바로 매수보다 회복선 위 안착과 거래량 증가가 먼저 확인돼야 합니다.'
        elif any(x in blob for x in ['거래량폭발', '초동', '돌파']):
            msg = '초동 돌파 성격은 있지만 확인이 필요합니다. 첫 눌림에서 기준선이 버티는지 보는 전략이 좋습니다.'
        else:
            msg = '구조는 관찰할 만하지만 아직 확정 구간은 아닙니다. 기준선 지지와 거래량 재유입을 먼저 확인하세요.'
        if '가짜수박주의' in blob:
            msg += ' 가짜수박주의가 있어 종가 안착 전 추격은 피합니다.'
        return _v1063_trunc(msg, max_len)
    except Exception:
        return ''


