def _v1046_build_ymgp_bb40_block(df, title='저평가 1파/BB40 회복 TOP 5') -> str:
    """V1063: 저평가 블록의 용어/문장을 최종 자연화."""
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return '🏆 [저평가 1파/BB40 회복 TOP 5]\n\n- 해당 종목 없음'
        lines = [
            '🏆 [저평가 1파/BB40 회복 TOP 5]',
            '',
            '기준: 소외·저평가 구간에서 바닥을 다진 뒤, MA5가 MA112~MA224 구간으로 회복하고 BB40 저항/재지지와 1파·2파 위치를 함께 확인합니다.',
            ''
        ]
        for i, row in df.head(5).reset_index(drop=True).iterrows():
            d = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            name = _v1046_s(d.get('종목명') or d.get('Name')) if '_v1046_s' in globals() else _v1063_txt(d.get('종목명') or d.get('Name'))
            code = _v1046_norm_code(d.get('code') or d.get('Code')) if '_v1046_norm_code' in globals() else _v1063_txt(d.get('code') or d.get('Code'))
            price = int(_v1063_num(d.get('현재가') or d.get('Close'), 0))
            score = int(_v1063_num(d.get('역매공파BB40점수'), 0))
            state = _v1063_txt(d.get('역매공파BB40상태'))
            tag = _v1063_txt(d.get('역매공파BB40태그'))
            role = _v1063_txt(d.get('역매공파BB40역할'))
            comment = _v1063_clean_ymgp_comment(d.get('역매공파BB40코멘트'), d.get('역배열이력일수', 0))
            wave = _v1062_wave_phase_for_value(d) if '_v1062_wave_phase_for_value' in globals() else {'tag':'','state':'파동 관찰','line':'파동 위치는 추가 확인이 필요합니다.'}
            if wave.get('tag') and wave.get('tag') not in tag:
                tag = (tag + ' ' + wave.get('tag')).strip()
            wave_box = _v1061_wave_line(d, max_len=128) if '_v1061_wave_line' in globals() else ''
            ai_comment = _v1061_ai_comment(d, max_len=102) if '_v1061_ai_comment' in globals() else ''
            rsi = int(_v1063_num(d.get('RSI'), 0))
            disp = int(_v1063_num(d.get('이격'), 0))
            bb40 = _v1063_num(d.get('BB40'), 0)
            pblue = int(_v1063_num(d.get('파란점선') or d.get('BB30시프트선') or d.get('기준가'), 0))
            try:
                supply = _v1050_supply_text(d) if '_v1050_supply_text' in globals() else _v1063_txt(d.get('수급요약') or d.get('수급판정') or d.get('수급'))
            except Exception:
                supply = _v1063_txt(d.get('수급요약') or d.get('수급판정') or d.get('수급'))
            supply = _v1060_supply_short(supply, 135) if '_v1060_supply_short' in globals() else _v1063_trunc(supply, 135)
            stop = int(_v1063_num(d.get('🚨손절가'), 0))
            t1 = int(_v1063_num(d.get('🎯목표타점'), 0))
            clean_role = _v1063_clean_bb40_phrase(role or state)
            lines.append(f"{i+1}) {name}({code}) | 현재 {price:,} | 점수 {score}")
            lines.append(f"   🏷️ {tag or state or '-'} | {clean_role or '-'}")
            lines.append(f"   📌 해석: {comment or (clean_role + '를 확인하는 자리')}")
            lines.append(f"   🌊 파동: {wave.get('state','파동 관찰')} — {_v1063_trunc(wave.get('line',''), 120)}")
            if wave_box:
                lines.append(f"   {wave_box}")
            lines.append(f"   🧠 맥락: {_v1063_trunc(_v1062_value_wave_context(d, role, state, comment), 155)}")
            lines.append(f"   📊 이격 {disp} | RSI {rsi} | BB40폭 {bb40:.1f}")
            if pblue > 0:
                lines.append(f"   🔵 기준선: {pblue:,}원 재지지/종가 안착 확인")
            if ai_comment:
                lines.append(f"   🤖 AI코멘트: {ai_comment}")
            if t1 > 0 or stop > 0:
                lines.append(f"   🎯 목표 {t1:,} / 손절 {stop:,}")
            if supply:
                lines.append(f"   🏦 수급: {supply}")
            lines.append('')
        msg = '\n'.join(lines).strip()
        return _v1054_cleanup_message(msg)
    except Exception as e:
        try: log_error(f'⚠️ V1063 저평가 1파/BB40 블록 생성 실패: {e}')
        except Exception: pass
        try:
            return _V1063_PREV_YMGP_BLOCK(df, title=title) if _V1063_PREV_YMGP_BLOCK else ''
        except Exception:
            return ''

