def _v1064_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.getenv(name, default)).strip().lower() not in ('0', 'false', 'no', 'off', '')
    except Exception:
        return str(default).strip().lower() not in ('0', 'false', 'no', 'off', '')


def _v1064_clean_text(x, default=''):
    try:
        if x is None:
            return default
        s = str(x).strip()
        if s.lower() in ('nan', 'none', 'null'):
            return default
        return re.sub(r'\s+', ' ', s).strip()
    except Exception:
        return default


def _v1064_split_supply_line(line: str) -> list:
    """한 줄 수급을 모바일에서 읽기 좋게 1일/3일 라인으로 분리한다.

    예)
      🏦 수급: 🤝쌍끌강 | 1일 개인 -1.4억 | 외인 +1.5억 | 기관 +0.0억 / 3일 개인 -0.7억 | 외인 +0.5억 | 기관 +0.0억
    ->
      🏦 수급: 🤝쌍끌강
         ├ 1일: 개인 -1.4억 | 외인 +1.5억 | 기관 +0.0억
         └ 3일: 개인 -0.7억 | 외인 +0.5억 | 기관 +0.0억
    """
    try:
        raw = str(line or '')
        if '🏦 수급:' not in raw:
            return [raw]
        if '1일' not in raw or '3일' not in raw:
            return [raw]
        if ' / 3일' not in raw and '/ 3일' not in raw:
            return [raw]

        indent = re.match(r'^(\s*)', raw).group(1)
        body = raw[len(indent):]

        # 기본 패턴: 라벨 | 1일 ... / 3일 ...
        m = re.match(r'^(🏦\s*수급:\s*)(.*?)(?:\s*\|\s*)?1일\s+(.*?)(?:\s*/\s*)3일\s+(.*)$', body)
        if not m:
            return [raw]

        head, label, day1, day3 = m.groups()
        label = _v1064_clean_text(label)
        day1 = _v1064_clean_text(day1)
        day3 = _v1064_clean_text(day3)

        # 너무 긴 3일 뒤 잔여 중복이 붙는 경우를 가볍게 정리
        day1 = day1.replace(' /', '').strip()
        day3 = day3.replace(' /', '').strip()
        if not day1 or not day3:
            return [raw]

        # label이 없으면 첫 줄만 단순 표기
        first = f"{indent}{head}{label}".rstrip()
        if not label:
            first = f"{indent}{head.rstrip()}"
        return [
            first,
            f"{indent}   ├ 1일: {day1}",
            f"{indent}   └ 3일: {day3}",
        ]
    except Exception:
        return [line]


def _v1064_format_supply_lines_in_message(msg: str) -> str:
    """텔레그램 전체 메시지에서 수급 한 줄 표기를 1일/3일 줄 분리로 일괄 보정."""
    try:
        if not _v1064_on('V1064_SUPPLY_DAY_SPLIT', '1'):
            return str(msg or '')
        out = []
        for line in str(msg or '').splitlines():
            if '🏦 수급:' in line and '1일' in line and '3일' in line:
                out.extend(_v1064_split_supply_line(line))
            else:
                out.append(line)
        return '\n'.join(out)
    except Exception:
        return str(msg or '')


