def _v1054_cleanup_message(msg: str) -> str:
    """V1064: 최종 메시지 언어 보정 + 수급 1일/3일 줄 분리."""
    try:
        s = _V1064_PREV_CLEANUP_MESSAGE(msg) if _V1064_PREV_CLEANUP_MESSAGE else str(msg or '')
    except Exception:
        s = str(msg or '')
    try:
        if _v1064_on('V1064_VALUE_TERM_ORDER', '1'):
            replacements = {
                '소외·저평가': '저평가·소외',
                '소외/저평가': '저평가/소외',
                '재지지 전환를': '재지지 전환을',
                '상단의 재지지 전환를': '상단의 재지지 전환을',
                '전환를 확인': '전환을 확인',
                '관찰를 확인': '관찰을 확인',
                '돌파를 확인하는 자리입니다': '돌파를 확인하는 자리입니다',
            }
            for a, b in replacements.items():
                s = s.replace(a, b)
        s = _v1064_format_supply_lines_in_message(s)
        return s
    except Exception:
        return s


