def _v1054_cleanup_message(msg: str) -> str:
    """V1065: 기존 언어/수급 정리 후 끼 해석 라인을 추가."""
    try:
        s = _V1065_PREV_CLEANUP_MESSAGE(msg) if _V1065_PREV_CLEANUP_MESSAGE else str(msg or '')
    except Exception:
        s = str(msg or '')
    try:
        return _v1065_format_kki_lines_in_message(s)
    except Exception:
        return s


