# -*- coding: utf-8 -*-
"""
Stock-Hunter V1069 실전판정/분할진입/수급흡수 해석 교체형 통합 패치
적용 형태: legacy_main_patched.py 전체 교체형 파일에 사전 삽입됨
목적:
1) 종목별 해석 블록에 최종판정/진입이유/매매전략 자동 추가
2) 개인수급을 무조건 감점하지 않고 '개인 대량 흡수' 가능성을 별도 해석
3) 1일/3일 수급을 보기 쉬운 한 줄 포맷으로 정리
4) 재료/테마/진입이유를 기존 row 데이터와 키워드로 자동 추정
"""

print("✅ V1069_TRADE_DECISION_REPLACEMENT_FINAL LOADED")
print("✅ V1067_TRADE_DECISION_ABSORB_MATERIAL_PATCH LOADED")

import os as _v1067_os
import re as _v1067_re
import math as _v1067_math

# =============================================================
# V1067 공통 유틸
# =============================================================

def _v1067_env_on(name: str, default: str = "1") -> bool:
    try:
        return str(_v1067_os.getenv(name, default)).strip().lower() not in ("0", "false", "no", "off", "n", "")
    except Exception:
        return True


def _v1067_txt(x, default: str = "") -> str:
    try:
        if x is None:
            return default
        s = str(x).strip()
        if s.lower() in ("nan", "none", "null", "inf", "-inf"):
            return default
        return _v1067_re.sub(r"\s+", " ", s)
    except Exception:
        return default


def _v1067_num(x, default: float = 0.0) -> float:
    try:
        if x is None:
            return default
        if isinstance(x, str):
            s = x.replace(",", "").replace("%", "").strip()
            if s.lower() in ("", "-", "nan", "none", "null", "inf", "-inf"):
                return default
            x = s
        v = float(x)
        if not _v1067_math.isfinite(v):
            return default
        return v
    except Exception:
        return default


def _v1067_int(x, default: int = 0) -> int:
    try:
        return int(round(_v1067_num(x, default)))
    except Exception:
        return default


def _v1067_rowdict(row):
    try:
        if hasattr(row, "to_dict"):
            return row.to_dict()
        if isinstance(row, dict):
            return dict(row)
        return dict(row)
    except Exception:
        return {}


def _v1067_get(d, *keys, default=""):
    for k in keys:
        try:
            v = d.get(k, None)
        except Exception:
            v = None
        if _v1067_txt(v, "") != "":
            return v
    return default


def _v1067_fmt_price(v) -> str:
    n = _v1067_int(v, 0)
    return f"{n:,}" if n else "-"


def _v1067_fmt_amt(v) -> str:
    f = _v1067_num(v, 0.0)
    if abs(f) < 0.05:
        return "+0.0억"
    return f"{f:+.1f}억"

# =============================================================
# V1067 수급 파싱/판정
# =============================================================

def _v1067_parse_amount_from_text(text: str, who: str):
    """'개인 -27.3억 | 외인 +26.1억 | 기관 +0.3억' 형태에서 숫자 추출"""
    try:
        s = _v1067_txt(text, "")
        if not s:
            return None
        # 외국인/외인 둘 다 허용
        if who == "외인":
            who_pat = r"(?:외인|외국인)"
        else:
            who_pat = _v1067_re.escape(who)
        m = _v1067_re.search(who_pat + r"\s*([+-]?\d+(?:\.\d+)?)\s*억?", s)
        if m:
            return _v1067_num(m.group(1), 0.0)
    except Exception:
        pass
    return None


def _v1067_supply_values(d: dict, prefix: str = "1d") -> dict:
    """1일/3일 수급값을 row 필드 또는 문자열에서 안전 추출."""
    if prefix == "3d":
        text_keys = ["수급3일누적", "최근3일", "3일수급", "supply_3d", "수급_3일"]
        p_keys = ["개인3일", "개인_3일", "개인3일누적", "supply_personal_3d", "개인_3d"]
        f_keys = ["외인3일", "외국인3일", "외인_3일", "외인3일누적", "supply_foreign_3d", "외인_3d"]
        i_keys = ["기관3일", "기관_3일", "기관3일누적", "supply_inst_3d", "기관_3d"]
    else:
        text_keys = ["수급당일", "최근1일", "1일수급", "supply_1d", "수급_1일"]
        p_keys = ["개인1일", "개인_1일", "개인당일", "supply_personal_1d", "개인_1d"]
        f_keys = ["외인1일", "외국인1일", "외인_1일", "외인당일", "supply_foreign_1d", "외인_1d"]
        i_keys = ["기관1일", "기관_1일", "기관당일", "supply_inst_1d", "기관_1d"]

    text = ""
    for k in text_keys:
        text = _v1067_txt(d.get(k, ""), "")
        if text:
            break

    def pick_num(keys, who):
        for k in keys:
            if k in d and _v1067_txt(d.get(k, ""), "") != "":
                return _v1067_num(d.get(k), 0.0)
        parsed = _v1067_parse_amount_from_text(text, who)
        return parsed if parsed is not None else 0.0

    return {
        "개인": pick_num(p_keys, "개인"),
        "외인": pick_num(f_keys, "외인"),
        "기관": pick_num(i_keys, "기관"),
        "raw": text,
    }


def _v1067_supply_line(v: dict) -> str:
    return f"개인 {_v1067_fmt_amt(v.get('개인', 0))} | 외인 {_v1067_fmt_amt(v.get('외인', 0))} | 기관 {_v1067_fmt_amt(v.get('기관', 0))}"


def _v1067_basis_state(d: dict) -> tuple:
    price = _v1067_num(_v1067_get(d, "현재가", "Close", "종가", "price", default=0), 0)
    basis = _v1067_num(_v1067_get(d, "기준가", "파란점선", "파란점선기준", "기준선", default=0), 0)
    if price <= 0 or basis <= 0:
        return price, basis, 0.0, "미확인"
    gap = (price / basis - 1.0) * 100.0
    if gap >= 5:
        state = "위확장"
    elif gap >= 0:
        state = "위안착"
    elif gap >= -2.5:
        state = "접촉"
    else:
        state = "아래"
    return price, basis, gap, state


def _v1067_is_personal_absorption(d: dict, one: dict, three: dict) -> tuple:
    """개인수급을 무조건 감점하지 않고, 대량 흡수 가능성을 따로 판정."""
    try:
        p1, f1, i1 = one["개인"], one["외인"], one["기관"]
        p3, f3, i3 = three["개인"], three["외인"], three["기관"]
        price, basis, gap, basis_state = _v1067_basis_state(d)
        obv = _v1067_num(_v1067_get(d, "OBV기울기", "OBV", "obv_slope", default=0), 0)
        rsi = _v1067_num(_v1067_get(d, "RSI", "rsi", default=50), 50)
        disp = _v1067_num(_v1067_get(d, "이격", "Disparity", "disparity", default=100), 100)
        pattern = " ".join([
            _v1067_txt(_v1067_get(d, "검색패턴", "N구분", "대표신호", "신호", default="")),
            _v1067_txt(_v1067_get(d, "수박정제태그", "저항구름태그", default="")),
        ])

        # 개인이 크게 받았는데 가격이 기준선 근처에서 버티고, OBV/구조가 무너지지 않으면 흡수 관찰로 완화
        heavy_personal = (p1 >= 30.0) or (p3 >= 80.0)
        foreign_inst_sell = (f1 + i1 < -10.0) or (f3 + i3 < -30.0)
        price_holding = basis_state in ("접촉", "위안착", "위확장") or gap >= -3.0
        structure_alive = (obv >= 0) or any(k in pattern for k in ["저항돌파", "5일재안착", "정제수박", "삼각수렴", "BB", "수렴"])
        not_overheat = rsi < 72 and disp < 116

        if heavy_personal and foreign_inst_sell and price_holding and structure_alive and not_overheat:
            return True, "🟡 개인대량흡수 관찰"
        if heavy_personal and foreign_inst_sell:
            return False, "⚠️ 개인수급 부담"
        return False, ""
    except Exception:
        return False, ""


def _v1067_supply_judgement(d: dict) -> dict:
    one = _v1067_supply_values(d, "1d")
    three = _v1067_supply_values(d, "3d")
    p1, f1, i1 = one["개인"], one["외인"], one["기관"]
    p3, f3, i3 = three["개인"], three["외인"], three["기관"]

    personal_absorb, absorb_label = _v1067_is_personal_absorption(d, one, three)

    if (f1 > 0 and i1 > 0) and (f3 + i3 > 0):
        label = "🤝쌍끌강"
        score = 18
        tone = "strong"
    elif (f1 + i1 > 0) and (f3 + i3 > 0):
        label = "🤝쌍끌"
        score = 12
        tone = "good"
    elif f1 > 0 and f3 > 0:
        label = "🔵외인강"
        score = 10
        tone = "good"
    elif i1 > 0 and i3 > 0:
        label = "🔴기관강"
        score = 10
        tone = "good"
    elif personal_absorb:
        label = absorb_label
        score = 3  # 감점이 아니라 약한 플러스/중립
        tone = "absorb"
    elif (p1 > 0 and f1 < 0 and i1 < 0):
        label = "⚠️개인수급/외인기관매도"
        score = -12
        tone = "weak"
    elif (f1 + i1 < 0) and (f3 + i3 < 0):
        label = "⚠️수급부담"
        score = -10
        tone = "weak"
    elif f1 > 0 or f3 > 0:
        label = "🔵외인우세"
        score = 6
        tone = "neutral_good"
    elif i1 > 0 or i3 > 0:
        label = "🔴기관우세"
        score = 6
        tone = "neutral_good"
    else:
        label = "미계산"
        score = 0
        tone = "unknown"

    return {
        "label": label,
        "score": score,
        "tone": tone,
        "one": one,
        "three": three,
        "line1": _v1067_supply_line(one),
        "line3": _v1067_supply_line(three),
        "personal_absorb": personal_absorb,
    }

# =============================================================
# V1067 재료/테마/진입이유 추정
