def _v1067_material_reason(d: dict) -> str:
    explicit_keys = [
        "재료", "진입이유", "AI재료", "AI강한근거", "뉴스테마", "테마", "관련테마", "주도섹터", "섹터", "섹터명",
        "이슈", "뉴스키워드", "market_issue", "theme_reason",
    ]
    vals = []
    for k in explicit_keys:
        s = _v1067_txt(d.get(k, ""), "")
        if s and s not in vals and len(s) <= 90:
            vals.append(s)
    if vals:
        return " / ".join(vals[:2])

    name = _v1067_txt(_v1067_get(d, "종목명", "Name", "name", default=""))
    code = _v1067_txt(_v1067_get(d, "code", "종목코드", "Code", default=""))
    blob = " ".join([
        name, code,
        _v1067_txt(_v1067_get(d, "검색패턴", "N구분", "대표신호", "신호", default="")),
        _v1067_txt(_v1067_get(d, "섹터", "주도섹터", "테마", default="")),
    ])

    rules = [
        (["유비쿼스", "티이엠씨", "로체", "램테크", "하나마이크론", "한미반도체", "테크윙", "주성엔지니어링"], "반도체/장비 순환매 및 미국 반도체 강세 연동"),
        (["한화오션", "HD현대", "삼성중공업", "조선", "해운"], "조선·방산·해양플랜트 모멘텀 및 수주 기대감"),
        (["두산에너빌리티", "한전기술", "우진", "비에이치아이", "원전", "우라늄"], "원전/우라늄 글로벌 강세 연동"),
        (["에코프로", "포스코퓨처", "삼성SDI", "LG에너지", "2차전지", "배터리"], "2차전지 순환매 및 낙폭 회복 관찰"),
        (["현대무벡스", "로봇", "자동화"], "로봇/자동화 테마와 물류 자동화 기대감"),
        (["HLB", "셀비온", "바이오"], "바이오 섹터 리스크온 및 개별 파이프라인 기대감"),
        (["키움증권", "부국증권", "대신증권", "증권", "금융"], "증권/금융주 순환매 및 거래대금 증가 기대감"),
        (["삼각", "수렴", "BB", "응축"], "삼각수렴·볼린저밴드 응축으로 변동성 확대 전 예비 구간"),
    ]
    for kws, reason in rules:
        if any(k in blob for k in kws):
            return reason
    return "차트 구조·수급·기준선 재지지 중심의 기술적 후보"


def _v1067_entry_reasons(d: dict, supply: dict) -> list:
    reasons = []
    pattern = _v1067_txt(_v1067_get(d, "검색패턴", "N구분", "대표신호", "신호", default=""))
    refine = _v1067_txt(_v1067_get(d, "수박정제태그", "저항구름태그", "역매공파BB40태그", default=""))
    fib = _v1067_txt(_v1067_get(d, "피보회귀", "피보/회귀", "fib_text", default=""))
    price, basis, gap, basis_state = _v1067_basis_state(d)
    rsi = _v1067_num(_v1067_get(d, "RSI", "rsi", default=50), 50)
    disp = _v1067_num(_v1067_get(d, "이격", "Disparity", "disparity", default=100), 100)
    bb40 = _v1067_num(_v1067_get(d, "BB40", "BB40폭", "bb40", default=0), 0)

    mat = _v1067_material_reason(d)
    if mat:
        reasons.append(mat)
    if supply.get("tone") in ("strong", "good"):
        reasons.append(f"수급 {supply.get('label')} 확인")
    elif supply.get("personal_absorb"):
        reasons.append("개인 매수세가 단순 부담보다 흡수 관찰 성격")
    if basis_state in ("접촉", "위안착"):
        reasons.append("5일선·파란점선 근처 재지지 확인 구간")
    elif basis_state == "위확장":
        reasons.append("기준선 위 흐름은 유지, 다만 눌림 재지지 필요")
    if "38.2 위" in fib or "강세회귀" in fib:
        reasons.append("피보 38.2 위 강세 회귀권")
    elif "50~61.8" in fib or "황금회귀" in fib:
        reasons.append("피보 50~61.8 되돌림권에서 반등 확인 필요")
    if any(k in pattern + refine for k in ["삼각", "수렴", "응축"]):
        reasons.append("삼각수렴/응축 이후 에너지 분출 후보")
    if 45 <= rsi <= 68 and 97 <= disp <= 112:
        reasons.append("RSI·이격이 과열권 전 안정 구간")
    elif disp >= 113 or rsi >= 70:
        reasons.append("이격/RSI 부담으로 추격보다 눌림 확인 필요")
    if 0 < bb40 <= 18:
        reasons.append("BB40 폭 축소로 변동성 응축")
    return reasons[:5]

# =============================================================
# V1067 최종판정/전략
# =============================================================

def _v1067_final_decision(d: dict, supply: dict) -> dict:
    price, basis, gap, basis_state = _v1067_basis_state(d)
    rsi = _v1067_num(_v1067_get(d, "RSI", "rsi", default=50), 50)
    disp = _v1067_num(_v1067_get(d, "이격", "Disparity", "disparity", default=100), 100)
    phase = _v1067_txt(_v1067_get(d, "유형", "추천단계", "phase", default=""))
    pattern = _v1067_txt(_v1067_get(d, "검색패턴", "N구분", "대표신호", "신호", default=""))
    refine = _v1067_txt(_v1067_get(d, "수박정제태그", "저항구름태그", default=""))
    fib = _v1067_txt(_v1067_get(d, "피보회귀", "피보/회귀", "fib_text", default=""))

    fake = "가짜수박주의" in (pattern + refine)
    late = "후행" in phase or "후행" in pattern
    overheat = rsi >= 72 or disp >= 116
    mild_overheat = rsi >= 70 or disp >= 113
    supply_good = supply.get("tone") in ("strong", "good", "neutral_good")
    supply_absorb = bool(supply.get("personal_absorb"))
    supply_bad = supply.get("tone") == "weak"
    near_or_above = basis_state in ("접촉", "위안착")
    extended = basis_state == "위확장"
    below = basis_state == "아래"
    has_entry_signal = any(k in pattern + refine for k in ["5일재안착", "거래량폭발", "저항돌파", "정제수박", "종베", "삼각", "BB40", "BB30", "수렴"])
    deep_recover_needed = "61.8 하단" in fib or "깊은회귀" in fib

    # 점수는 문구 결정을 위한 내부값
    score = 0
    score += 18 if supply_good else 0
    score += 8 if supply_absorb else 0
    score -= 14 if supply_bad and not supply_absorb else 0
    score += 14 if near_or_above else 0
    score += 6 if extended else 0
    score -= 10 if below else 0
    score += 12 if has_entry_signal else 0
    score -= 18 if overheat else 0
    score -= 10 if mild_overheat and not overheat else 0
    score -= 12 if fake else 0
    score -= 12 if late else 0
    score -= 8 if deep_recover_needed else 0

    if overheat or (late and mild_overheat):
        label = "🔴 신규진입 보류"
        mode = "avoid"
    elif fake and below:
        label = "🔴 신규진입 보류"
        mode = "avoid"
    elif near_or_above and has_entry_signal and (supply_good or supply_absorb) and not mild_overheat and not late:
        label = "🟢 지금 분할진입 가능"
        mode = "partial_now"
    elif near_or_above and has_entry_signal and not overheat and not fake:
        label = "🟡 소액 분할진입 가능"
        mode = "small_partial"
    elif extended and not overheat:
        label = "🟡 눌림 확인 후 진입"
        mode = "pullback"
    elif below or deep_recover_needed:
        label = "🟠 회복선 돌파 확인 후 진입"
        mode = "breakout_confirm"
    else:
        label = "🟡 눌림 확인 후 진입"
        mode = "pullback"

    return {
        "label": label,
        "mode": mode,
        "score": score,
        "basis_state": basis_state,
        "basis_gap": gap,
        "rsi": rsi,
        "disp": disp,
        "late": late,
        "fake": fake,
        "mild_overheat": mild_overheat,
    }


def _v1067_trade_strategy(d: dict, decision: dict) -> list:
    price, basis, gap, basis_state = _v1067_basis_state(d)
    mode = decision.get("mode", "pullback")

    fib382 = _v1067_num(_v1067_get(d, "Fib382", "피보382", "fib382", default=0), 0)
    fib50 = _v1067_num(_v1067_get(d, "Fib50", "피보50", "fib50", default=0), 0)
    fib618 = _v1067_num(_v1067_get(d, "Fib618", "피보618", "fib618", default=0), 0)
    target1 = _v1067_num(_v1067_get(d, "목표1", "목표타점", "target1", default=0), 0)
    target2 = _v1067_num(_v1067_get(d, "목표2", "목표2차", "target2", default=0), 0)
    stop = _v1067_num(_v1067_get(d, "손절", "손절가", "stop", default=0), 0)

    # 손절 기준이 없으면 보수적으로 계산
    if stop <= 0 and price > 0:
        candidates = []
        if fib50 > 0:
            candidates.append(fib50 * 0.985)
        if basis > 0:
            candidates.append(basis * 0.97)
        candidates.append(price * 0.95)
        stop = max(1, min(candidates))

    lines = []
    if mode == "partial_now":
        lines.append("1차: 현재가 부근 20~30% 소액 분할")
        if basis > 0:
            lines.append(f"2차: 5일선·파란점선 {int(basis):,}원 부근 눌림 재지지 시 추가")
    elif mode == "small_partial":
        lines.append("1차: 현재가 추격보다 소액만 확인 진입")
        if basis > 0:
            lines.append(f"2차: {int(basis):,}원 위 재안착 + 거래량 재유입 시 추가")
    elif mode == "pullback":
        lines.append("1차: 지금 추격보다 5일선·파란점선 눌림 대기")
        if basis > 0:
            lines.append(f"진입: {int(basis):,}원 전후 재지지 + 양봉 마감 확인")
    elif mode == "breakout_confirm":
        rec = fib618 or fib50 or basis
        if rec > 0:
            lines.append(f"진입: 회복선 {int(rec):,}원 위 종가 안착 확인 후")
        else:
            lines.append("진입: 기준선 회복과 거래량 증가 확인 후")
    else:
        lines.append("신규: 무리한 추격 금지, 회복선 재안착 전 관찰")

    if fib50 > 0:
        lines.append(f"손절: 10일선 또는 피보 50 {int(fib50):,}원 이탈 시 축소/손절")
    elif stop > 0:
        lines.append(f"손절: {int(stop):,}원 이탈 시 축소/손절")
    else:
        lines.append("손절: 기준선 이탈 또는 장대음봉 발생 시 축소")

    if target1 > 0:
        if target2 > 0 and target2 > target1:
            lines.append(f"목표: 1차 {int(target1):,}원 / 2차 {int(target2):,}원")
        else:
            lines.append(f"목표: 1차 {int(target1):,}원")
    lines.append("무효: 거래량 없이 기준선 이탈하거나 외인·기관 동반 매도 확대")
    return lines[:5]


def _v1067_build_trade_decision_block(row) -> str:
    if not _v1067_env_on("V1067_TRADE_DECISION_BLOCK", "1"):
        return ""
    d = _v1067_rowdict(row)
    supply = _v1067_supply_judgement(d)
    decision = _v1067_final_decision(d, supply)
    reasons = _v1067_entry_reasons(d, supply)
    strategies = _v1067_trade_strategy(d, decision)

    lines = []
    lines.append(f"🧭 최종판정: {decision['label']}")
    lines.append("📌 진입이유: " + " / ".join(reasons[:4]))
    lines.append(f"🏦 수급해석: {supply['label']}")
    lines.append(f"   ├ 1일: {supply['line1']}")
    lines.append(f"   └ 3일: {supply['line3']}")
    lines.append("🎯 매매전략:")
    for s in strategies:
        lines.append(f"   - {s}")
    return "\n".join(lines).strip()

