try:
    _V1067_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY = enrich_row_with_human_commentary
except Exception:
    _V1067_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY = None


def enrich_row_with_human_commentary(row):
    try:
        base = _V1067_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY(row) if _V1067_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY else row
    except Exception:
        base = row
    try:
        d = _v1067_rowdict(base)
        block = _v1067_build_trade_decision_block(d)
        if block:
            old = _v1067_txt(d.get("interpretation_block", ""), "")
            # 중복 방지
            if "🧭 최종판정:" not in old:
                d["interpretation_block"] = (block + "\n" + old).strip() if old else block
            # 모바일/정렬용 필드도 같이 주입
            supply = _v1067_supply_judgement(d)
            decision = _v1067_final_decision(d, supply)
            d["최종판정"] = decision.get("label", "")
            d["final_label"] = decision.get("label", "")
            d["V1067수급판정"] = supply.get("label", "")
            d["V1067수급1일"] = supply.get("line1", "")
            d["V1067수급3일"] = supply.get("line3", "")
        return d
    except Exception as e:
        try:
            d = _v1067_rowdict(base)
            old = _v1067_txt(d.get("interpretation_block", ""), "")
            d["interpretation_block"] = (old + f"\n⚠️ V1067 실전판정 생성 실패: {e}").strip()
            return d
        except Exception:
            return base

