def _v1062_simple_ai_comment(row, max_len=None):
    try:
        d = _v1067_rowdict(row)
        sj = _v1067_supply_judgement(d)
        decision = _v1067_final_decision(d, sj)
        if decision.get("mode") == "partial_now":
            msg = "현재가 부근 소액 분할은 가능하지만, 5일선·파란점선 눌림 재지지에서 추가하는 전략이 안전합니다."
        elif decision.get("mode") == "small_partial":
            msg = "조건은 나쁘지 않지만 추격보다 소액 확인 진입 후 눌림 재지지를 기다리는 편이 좋습니다."
        elif decision.get("mode") == "pullback":
            msg = "구조는 살아 있지만 지금은 눌림 확인이 우선입니다. 기준선 재지지와 거래량 재유입을 봅니다."
        elif decision.get("mode") == "breakout_confirm":
            msg = "회복선 위 안착 전에는 보수적으로 봅니다. 돌파 확인 후 접근하는 편이 좋습니다."
        else:
            msg = "신규 진입은 보류하고, 과열 해소 또는 기준선 회복을 기다리는 편이 안전합니다."
        if sj.get("personal_absorb"):
            msg += " 개인 매수는 단순 부담보다 대량 흡수 가능성도 함께 봅니다."
        max_len = max_len or 120
        return msg[:max_len].rstrip()
    except Exception:
        if _V1067_BASE_SIMPLE_AI_COMMENT:
            try:
                return _V1067_BASE_SIMPLE_AI_COMMENT(row, max_len=max_len)
            except Exception:
                pass
        return "기준선·거래량·수급 확인 후 접근합니다."


