# V1070 최종판정/분할진입/진입이유/재료 강화 교체형
# - V1069의 실전판정 로직을 더 명확하게 재정의
# - 오늘 매매관점 압축 / TOP15 / 상세카드에 최종판정·분할진입·진입이유·재료 삽입
# =============================================================
print("✅ V1070_FINAL_PARTIAL_ENTRY_MATERIAL_ACTIVE LOADED")

import re as _v1070_re
import math as _v1070_math


def _v1070_txt(x, default: str = "") -> str:
    try:
        if x is None:
            return default
        s = str(x).strip()
        if s.lower() in ("", "nan", "none", "null", "inf", "-inf"):
            return default
        return _v1070_re.sub(r"\s+", " ", s)
    except Exception:
        return default


def _v1070_num(x, default: float = 0.0) -> float:
    try:
        if x is None:
            return default
        if isinstance(x, str):
            s = x.replace(',', '').replace('%', '').replace('원', '').strip()
            if s.lower() in ('', '-', 'nan', 'none', 'null'):
                return default
            x = s
        v = float(x)
        if not _v1070_math.isfinite(v):
            return default
        return v
    except Exception:
        return default


def _v1070_int(x, default: int = 0) -> int:
    try:
        return int(round(_v1070_num(x, default)))
    except Exception:
        return default


def _v1070_fmt_price(v) -> str:
    n = _v1070_int(v, 0)
    return f"{n:,}원" if n > 0 else "-"


def _v1070_rowdict(row):
    try:
        if hasattr(row, 'to_dict'):
            return row.to_dict()
        if isinstance(row, dict):
            return dict(row)
        return dict(row)
    except Exception:
        return {}


def _v1070_get(d, *keys, default=""):
    for k in keys:
        try:
            v = d.get(k, None)
        except Exception:
            v = None
        if _v1070_txt(v, "") != "":
            return v
    return default


def _v1070_clean_line(s: str, max_len: int = 120) -> str:
    s = _v1070_re.sub(r"\s+", " ", _v1070_txt(s)).strip(' /|')
    if len(s) <= max_len:
        return s
    return s[:max_len].rstrip(' /|,') + '…'


def _v1070_blob(d: dict) -> str:
    keys = [
        '종목명','Name','name','code','Code','종목코드',
        '검색패턴','N구분','대표신호','신호','태그','섹터','주도섹터','테마','관련테마','뉴스테마',
        'AI재료분류','AI강한근거','AI심판요약','news_sentiment','최근뉴스','뉴스','공시내용','공시태그',
        '시장키워드','오늘키워드','이슈','재료','진입이유'
    ]
    vals = []
    for k in keys:
        try:
            v = _v1070_txt(d.get(k, ''), '')
            if v:
                vals.append(v)
        except Exception:
            pass
    return ' '.join(vals)


def _v1070_material_reason(d: dict) -> str:
    """종목명/테마/뉴스/섹터 텍스트에서 재료와 진입 배경을 사람이 읽는 문장으로 추정."""
    # 명시 필드가 있으면 우선 사용
    explicit_keys = ['재료', '진입이유', 'AI재료분류', 'AI강한근거', '뉴스테마', '관련테마', '테마', '주도섹터', '섹터', '이슈']
    explicit = []
    for k in explicit_keys:
        s = _v1070_txt(d.get(k, ''), '')
        if s and len(s) <= 110 and s not in explicit:
            explicit.append(s)
    if explicit:
        return _v1070_clean_line(' / '.join(explicit[:2]), 135)

    name = _v1070_txt(_v1070_get(d, '종목명', 'Name', 'name', default=''))
