def enrich_row_with_human_commentary(row):
    try:
        base = _V1071_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY(row) if _V1071_BASE_ENRICH_ROW_WITH_HUMAN_COMMENTARY else row
    except Exception:
        base = row
    try:
        d = _v1071_rowdict(base)
        block = _v1067_build_trade_decision_block(d)
        old = _v1071_txt(d.get('interpretation_block', ''), '')
        # 기존 V1069/V1070 블록이 있으면 중복 삽입하지 않고 V1071 필드만 보강
        if block and '🛠 기술근거:' not in old:
            d['interpretation_block'] = (block + '\n' + old).strip() if old else block
        supply = _v1071_supply_judgement(d)
        decision = _v1071_final_decision(d, supply)
        d['최종판정'] = decision.get('label', '')
        d['final_label'] = decision.get('label', '')
        d['분할진입전략'] = ' / '.join(_v1071_trade_strategy(d, decision)[:3])
        d['진입이유'] = ' / '.join(_v1071_entry_reasons(d, supply)[:3])
        d['재료'] = _v1071_material_reason(d)
        d['기술근거'] = _v1071_technical_reason(d)
        d['V1071수급판정'] = supply.get('label', '')
        d['V1071수급1일'] = supply.get('line1', '')
        d['V1071수급3일'] = supply.get('line3', '')
        return d
    except Exception as e:
        try:
            d = _v1071_rowdict(base)
            old = _v1071_txt(d.get('interpretation_block', ''), '')
            d['interpretation_block'] = (old + f"\n⚠️ V1071 실전판정 생성 실패: {e}").strip()
            return d
        except Exception:
            return base


