def _v1072_amt_from_text(text: str, who: str):
    try:
        s = _v1071_txt(text, '')
        if not s:
            return None
        who_pat = r'(?:외인|외국인)' if who == '외인' else _v1071_re.escape(who)
        m = _v1071_re.search(who_pat + r'\s*([+-]?\d+(?:\.\d+)?)\s*억?', s)
        if m:
            return _v1071_num(m.group(1), 0.0)
    except Exception:
        pass
    return None


def _v1072_pick_supply_text(d: dict, prefix: str) -> str:
    if prefix == '3d':
        keys = [
            'V1072수급3일','V1071수급3일','V1070수급3일','V1067수급3일',
            '수급3일누적','최근3일수급','수급3일','3일수급','supply_3d','supply_three','수급_3일',
        ]
        marker_re = r'(?:└\s*)?3일\s*[:：]?\s*([^\n]+)'
    else:
        keys = [
            'V1072수급1일','V1071수급1일','V1070수급1일','V1067수급1일',
            '수급당일','최근1일수급','수급1일','1일수급','supply_today','supply_1d','수급_1일',
        ]
        marker_re = r'(?:├\s*)?1일\s*[:：]?\s*([^\n]+)'
    for k in keys:
        s = _v1071_txt(d.get(k, ''), '')
        if s and any(w in s for w in ('개인','외인','외국인','기관')):
            return s.replace(' - ', ' | ')
    for k in ('수급', '수급요약', 'supply', 'supply_text', '수급상세', 'interpretation_block'):
        raw = _v1071_txt(d.get(k, ''), '')
        if not raw:
            continue
        m = _v1071_re.search(marker_re, raw)
        if m:
            return m.group(1).strip().replace(' - ', ' | ')
        if prefix == '1d' and all(w in raw for w in ('개인','외인','기관')) and ('1일' not in raw and '3일' not in raw):
            return raw
    return ''


def _v1072_pick_actor_value(d: dict, prefix: str, who: str, text: str) -> float:
    if prefix == '3d':
        key_map = {
            '개인': ['개인3일','개인_3일','개인3일누적','개인순매수3일','개인순매수_3일','supply_personal_3d','개인_3d'],
            '외인': ['외인3일','외국인3일','외인_3일','외인3일누적','외국인순매수3일','외인순매수3일','supply_foreign_3d','외인_3d'],
            '기관': ['기관3일','기관_3일','기관3일누적','기관순매수3일','기관순매수_3일','supply_inst_3d','기관_3d'],
        }
    else:
        key_map = {
            '개인': ['개인1일','개인_1일','개인당일','개인순매수1일','개인순매수_1일','supply_personal_1d','개인_1d'],
            '외인': ['외인1일','외국인1일','외인_1일','외인당일','외국인순매수1일','외인순매수1일','supply_foreign_1d','외인_1d'],
            '기관': ['기관1일','기관_1일','기관당일','기관순매수1일','기관순매수_1일','supply_inst_1d','기관_1d'],
        }
    for k in key_map.get(who, []):
        if k in d and _v1071_txt(d.get(k, ''), '') != '':
            return _v1071_num(d.get(k), 0.0)
    parsed = _v1072_amt_from_text(text, who)
    return parsed if parsed is not None else 0.0


def _v1072_supply_values(d: dict, prefix: str = '1d') -> dict:
    text = _v1072_pick_supply_text(d, prefix)
    return {
        '개인': _v1072_pick_actor_value(d, prefix, '개인', text),
        '외인': _v1072_pick_actor_value(d, prefix, '외인', text),
        '기관': _v1072_pick_actor_value(d, prefix, '기관', text),
        'raw': text,
    }


def _v1072_fmt_amt(v) -> str:
    f = _v1071_num(v, 0.0)
    if abs(f) < 0.05:
        return '+0.0억'
    return f'{f:+.1f}억'


def _v1072_supply_line(v: dict) -> str:
    return f"개인 {_v1072_fmt_amt(v.get('개인', 0))} | 외인 {_v1072_fmt_amt(v.get('외인', 0))} | 기관 {_v1072_fmt_amt(v.get('기관', 0))}"


def _v1072_supply_label_from_values(d: dict, one: dict, three: dict) -> dict:
    p1, f1, i1 = one.get('개인',0.0), one.get('외인',0.0), one.get('기관',0.0)
    p3, f3, i3 = three.get('개인',0.0), three.get('외인',0.0), three.get('기관',0.0)
    pc = _v1072_price_context(d) if '_v1072_price_context' in globals() else _v1071_price_context(d)
    has_any = any(abs(x) >= 0.05 for x in (p1,f1,i1,p3,f3,i3))
    if not has_any:
        return {'label':'미계산','score':0,'tone':'unknown','personal_absorb':False}
    personal_absorb = False
    if (p1 > 0 and (f1 + i1) < 0) or (p3 > 0 and (f3 + i3) < 0):
        if pc.get('fib_state') in ('38.2위','38.2~50','50~61.8') or pc.get('basis_state') in ('접촉','위안착','위확장'):
            personal_absorb = True
    if (f1 > 0 and i1 > 0) and (f3 + i3 > 0):
        return {'label':'🤝쌍끌강','score':18,'tone':'strong','personal_absorb':False}
    if (f1 + i1 > 0) and (f3 + i3 > 0):
        return {'label':'🤝쌍끌','score':13,'tone':'good','personal_absorb':False}
    if f1 > 0 and f3 > 0:
        return {'label':'🔵외인강','score':11,'tone':'good','personal_absorb':False}
    if i1 > 0 and i3 > 0:
        return {'label':'🔴기관강','score':11,'tone':'good','personal_absorb':False}
    if f1 > 0 or f3 > 0:
        return {'label':'🔵외인우세','score':7,'tone':'neutral_good','personal_absorb':False}
    if i1 > 0 or i3 > 0:
        return {'label':'🔴기관우세','score':7,'tone':'neutral_good','personal_absorb':False}
    if personal_absorb:
        return {'label':'🟡 개인대량흡수 관찰','score':3,'tone':'absorb','personal_absorb':True}
    if (p1 > 0 and f1 < 0 and i1 < 0) or ((f1 + i1) < 0 and (f3 + i3) < 0):
        return {'label':'⚠️수급부담','score':-10,'tone':'weak','personal_absorb':False}
    return {'label':'혼조','score':0,'tone':'mixed','personal_absorb':False}


def _v1072_supply_judgement(d: dict) -> dict:
    # V1072는 재귀 위험을 막기 위해 이전 supply 함수 호출 없이 row 원천값에서 직접 판정한다.
    base = {'label':'미계산','tone':'unknown','score':0,'line1':'','line3':'','personal_absorb':False}
    one = _v1072_supply_values(d, '1d')
    three = _v1072_supply_values(d, '3d')
    fixed = _v1072_supply_label_from_values(d, one, three)
    line1 = _v1072_supply_line(one)
    line3 = _v1072_supply_line(three)
    has_any = any(abs(x) >= 0.05 for x in (one['개인'], one['외인'], one['기관'], three['개인'], three['외인'], three['기관']))
    base_label = _v1071_txt(d.get('수급') or d.get('수급요약') or d.get('수급판정') or d.get('supply_label') or base.get('label','미계산'), '미계산') if isinstance(base, dict) else '미계산'
    if has_any:
        fixed.update({'one':one,'three':three,'line1':line1,'line3':line3})
        return fixed
    # 숫자 추출이 실패했지만 기존 라벨이 유효하면 tone을 보정해서 사용
    if base_label and base_label != '미계산':
        label = base_label
        tone = 'strong' if '쌍끌강' in label else 'good' if any(k in label for k in ['쌍끌','외인강','기관강']) else 'neutral_good' if any(k in label for k in ['외인','기관']) else 'weak' if any(k in label for k in ['부담','매도']) else 'mixed'
        return {'label':label,'score':base.get('score',0) if isinstance(base,dict) else 0,'tone':tone,'line1':line1,'line3':line3,'personal_absorb':'흡수' in label}
    return {'label':'미계산','score':0,'tone':'unknown','one':one,'three':three,'line1':line1,'line3':line3,'personal_absorb':False}


def _v1072_oil_trend() -> str:
    try:
        # V1071 추정값을 우선 사용하되, 전역 텍스트에서 WTI 퍼센트도 보조 검색
        trend = _v1071_oil_trend()
        if trend != 'unknown':
            return trend
        txt = ' '.join(_v1071_txt(globals().get(k,''),'') for k in ['market_briefing_text','market_summary_text','oil_briefing_text'])
        m = _v1071_re.search(r'WTI[^\n\(]*\(([+-]?\d+(?:\.\d+)?)%\)', txt)
        if m:
            v = _v1071_num(m.group(1), 0)
            if v > 0.15: return 'up'
            if v < -0.15: return 'down'
    except Exception:
        pass
    return 'unknown'


