def _v1072_material_reason(d: dict) -> str:
    name = _v1071_txt(_v1071_get(d, '종목명','Name','name', default=''))
    code = _v1071_txt(_v1071_get(d, 'code','Code','종목코드', default='')).zfill(6)
    oil = _v1072_oil_trend()
    if code == '003490' or '대한항공' in name or '항공' in name:
        if oil == 'down':
            return '유가 하락에 따른 항공유 비용 부담 완화 수혜 기대'
        if oil == 'up':
            return '항공 수요 회복·외인 수급 유입은 긍정이나 유가 상승은 비용 부담 요인'
        return '항공 수요 회복과 유가 변동성에 따른 비용 민감주 모멘텀'
    if code in _V1072_MATERIAL_BY_CODE:
        return _V1072_MATERIAL_BY_CODE[code]
    blob = _v1071_blob(d)
    # 에너지/정유는 종목명·섹터에 명확히 있을 때만 유가 재료를 붙인다.
    energy_name_hit = any(k in name for k in ['S-Oil','SK이노베이션','GS칼텍스','흥구석유','중앙에너비스']) or any(k in blob for k in ['정유주','정유/에너지','석유','LPG'])
    if energy_name_hit:
        if oil == 'up': return '유가 상승·중동 정세 변동에 따른 정유·에너지 모멘텀'
        if oil == 'down': return '유가 하락 부담은 있으나 에너지 변동성 확대에 따른 단기 테마 관찰'
        return '유가·중동 정세에 따른 정유·에너지 변동성 모멘텀'
    rules = [
        (['테크윙','한미반도체','주성엔지니어링','리노공업','하나마이크론','램테크','이수페타시스','DB하이텍','반도체','SOXX','SMH','HBM'], '미국 반도체 강세와 국내 반도체 장비·소부장 순환매 기대'),
        (['두산에너빌리티','한전기술','한전산업','우리기술','비에이치아이','원전','우라늄','URA','NLR'], '미국 원전·우라늄 강세와 국내 원전 밸류체인 순환매 기대'),
        (['한화오션','삼성중공업','조선','해운','선박','LNG'], '조선·해운 수주 기대와 산업재 순환매 연결'),
        (['현대로템','한화시스템','한화에어로','LIG넥스원','파이버프로','방산','우주','위성'], '방산·우주 테마와 수주 모멘텀'),
        (['현대모비스','HL만도','자동차','전장'], '자동차 부품·전장 밸류체인 순환매 기대'),
        (['아모레퍼시픽','화장품','중국','소비재'], '소비재·화장품 저점 회복과 실적 턴어라운드 기대'),
        (['삼성바이오','셀트리온','에이비엘바이오','HLB','바이오','펩타이드','CDMO','신약'], '바이오·신약/CDMO 모멘텀 및 리스크온 순환매'),
        (['금융','은행','증권','밸류업','주주환원'], '금융·지주/은행/증권주 수급 순환과 주주환원 기대'),
        (['전력','변압기','전선','스마트그리드'], 'AI 전력 인프라·전력기기/전선 테마 순환매'),
        (['2차전지','배터리','에코프로','리튬','전기차'], '2차전지·전기차 낙폭 이후 순환매 기대'),
        (['로봇','자동화','현대무벡스','레인보우','로보티즈','두산로보틱스'], '로봇·자동화 글로벌 테마 강세와 국내 관련주 순환매'),
    ]
    for kws, reason in rules:
        if any(k in blob or k in name for k in kws):
            return reason
    # 명시 재료는 마지막에 사용하되, 이전 버전이 생성한 기술/오매칭성 문구는 제외한다.
    bad_words = ('삼각수렴','볼린저','BB40','피보','파란점선','유가 하락 부담','에너지 변동성')
    for k in ['뉴스테마','관련테마','테마','주도섹터','섹터','AI재료분류','이슈']:
        s = _v1071_txt(d.get(k,''), '')
        if s and len(s) <= 100 and not any(b in s for b in bad_words):
            return _v1071_clean_line(s, 120)
    return '개별 재료는 미확인, 차트 구조 중심의 기술적 후보'


def _v1072_price_context(d: dict) -> dict:
    # V1072는 이전 price_context 호출 없이 직접 산출한다.
    pc = {}
    price = _v1071_num(_v1071_get(d, '현재가','Close','종가','price', default=0), 0)
    exec_line = _v1071_num(_v1071_get(d, '실행기준선','파란점선','파란점선기준','기준가','기준선','blue_line', default=0), 0)
    upper_line = _v1071_num(_v1071_get(d, '상단회복선','회복선','BB30시프트선','shift_line','bb30_shift', default=0), 0)
    ma5 = _v1071_num(_v1071_get(d, 'MA5','ma5','5일선','MA_5','SMA5','ma_5', default=0), 0)
    ma10 = _v1071_num(_v1071_get(d, 'MA10','ma10','10일선','MA_10','SMA10','ma_10', default=0), 0)
    basis = exec_line or upper_line
    gap = 0.0
    if price > 0 and basis > 0:
        gap = (price / basis - 1.0) * 100.0
    if price <= 0 or basis <= 0:
        basis_state = '미확인'
    elif gap >= 5:
        basis_state = '위확장'
    elif gap >= 0:
        basis_state = '위안착'
    elif gap >= -2.5:
        basis_state = '접촉'
    else:
        basis_state = '아래'
    fib382 = _v1071_num(_v1071_get(d, 'Fib382','피보382','fib382','피보38.2', default=0), 0)
    fib50 = _v1071_num(_v1071_get(d, 'Fib50','피보50','fib50', default=0), 0)
    fib618 = _v1071_num(_v1071_get(d, 'Fib618','피보618','fib618','피보61.8', default=0), 0)
    fib_text = _v1071_txt(_v1071_get(d, '피보회귀','피보/회귀','fib_text', default=''))
    if (fib382 <= 0 or fib50 <= 0 or fib618 <= 0) and fib_text:
        try:
            m382 = _v1071_re.search(r'38\.2\s*([0-9,]+)', fib_text)
            m50 = _v1071_re.search(r'\b50\s*([0-9,]+)', fib_text)
            m618 = _v1071_re.search(r'61\.8\s*([0-9,]+)', fib_text)
            if m382 and fib382 <= 0: fib382 = _v1071_num(m382.group(1), 0)
            if m50 and fib50 <= 0: fib50 = _v1071_num(m50.group(1), 0)
            if m618 and fib618 <= 0: fib618 = _v1071_num(m618.group(1), 0)
        except Exception:
            pass
    fib_state = '미확인'
    if price > 0 and fib382 > 0 and price >= fib382:
        fib_state = '38.2위'
    elif price > 0 and fib50 > 0 and price >= fib50:
        fib_state = '38.2~50'
    elif price > 0 and fib618 > 0 and price >= fib618:
        fib_state = '50~61.8'
    elif price > 0 and fib618 > 0:
        fib_state = '61.8아래'
    supports = []
    for v in (basis, ma5, fib382, fib50, fib618):
        if price > 0 and v > 0 and v <= price * 1.015:
            supports.append(v)
    nearest_support = max(supports) if supports else 0
    stop_candidates = []
    if ma10 > 0: stop_candidates.append(ma10)
    if fib50 > 0: stop_candidates.append(fib50)
    if fib618 > 0: stop_candidates.append(fib618)
    if basis > 0: stop_candidates.append(basis * 0.97)
    stop_line = 0
    if price > 0 and stop_candidates:
        below = [v for v in stop_candidates if 0 < v < price]
        stop_line = max(below) if below else min(stop_candidates)
    risk_pct = 99.0
    if price > 0 and stop_line > 0:
        risk_pct = max(0.0, (price - stop_line) / price * 100.0)
    pc.update({'price':price,'basis':basis,'blue':exec_line,'exec_line':exec_line,'upper_line':upper_line,'ma5':ma5,'ma10':ma10,'basis_gap':gap,'basis_state':basis_state,'fib382':fib382,'fib50':fib50,'fib618':fib618,'fib_state':fib_state,'nearest_support':nearest_support,'stop_line':stop_line,'risk_pct':risk_pct})
    return pc


def _v1072_basis_line(row) -> str:
    d = _v1071_rowdict(row)
    pc = _v1072_price_context(d)
    parts = []
    if pc.get('exec_line'):
        parts.append(f"실행기준선 {_v1071_fmt_price(pc.get('exec_line'))}")
    if pc.get('upper_line') and abs(pc.get('upper_line') - (pc.get('exec_line') or 0)) > 1:
        parts.append(f"상단회복선 {_v1071_fmt_price(pc.get('upper_line'))}")
    if pc.get('ma5'):
        parts.append(f"5일선 {_v1071_fmt_price(pc.get('ma5'))}")
    if pc.get('ma10'):
        parts.append(f"10일선 {_v1071_fmt_price(pc.get('ma10'))}")
    if pc.get('price') and pc.get('basis'):
        parts.append(f"현재이격 {pc.get('basis_gap',0):+.1f}%")
    parts.append(pc.get('basis_state','미확인'))
    return ' / '.join([p for p in parts if p]) or '기준선 산출불가 / 5일선·전일저점 기준 확인'


def _v1072_technical_reason(d: dict) -> str:
    pattern = _v1071_txt(_v1071_get(d, '검색패턴','N구분','대표신호','신호', default=''))
    refine = _v1071_txt(_v1071_get(d, '수박정제태그','저항구름태그','역매공파BB40태그', default=''))
    pc = _v1072_price_context(d)
    bb40 = _v1071_num(_v1071_get(d, 'BB40','BB40폭','bb40', default=0), 0)
    parts = []
    blob = pattern + ' ' + refine
    if any(k in blob for k in ['삼각','수렴']): parts.append('삼각수렴')
    if bb40 > 0:
        parts.append(('BB40 응축 ' if bb40 <= 15 else 'BB40 수렴 ' if bb40 <= 22 else 'BB40 폭 ') + f'{bb40:.1f}')
    if pc.get('fib_state') == '38.2위': parts.append(f"피보38.2 {_v1071_fmt_price(pc.get('fib382'))} 위")
    elif pc.get('fib_state') == '38.2~50': parts.append('피보38.2~50 얕은 눌림')
    elif pc.get('fib_state') == '50~61.8': parts.append('피보50~61.8 되돌림')
    if pc.get('exec_line'):
        parts.append(f"실행기준선 {_v1071_fmt_price(pc.get('exec_line'))} {pc.get('basis_state','')}")
    if pc.get('upper_line') and pc.get('price') and pc.get('price') < pc.get('upper_line'):
        parts.append(f"상단회복선 {_v1071_fmt_price(pc.get('upper_line'))} 회복 필요")
    if any(k in blob for k in ['거래량폭발','저항돌파','5일재안착','OBV','MFI','독사','돌반지','수박']):
        parts.append('돌파/재안착 신호 포함')
    if not parts: parts.append('가격·수급·기준선 재지지 확인형')
    return _v1071_clean_line(' + '.join(parts[:5]), 145)


def _v1072_entry_reasons(d: dict, supply: dict) -> list:
    reasons = []
    mat = _v1072_material_reason(d)
    tech = _v1072_technical_reason(d)
    if mat and '개별 재료는 미확인' not in mat:
        reasons.append(mat)
    pc = _v1072_price_context(d)
    tone = supply.get('tone','')
    label = _v1071_txt(supply.get('label',''))
    if tone in ('strong','good'):
        reasons.append(f'수급 {label} 확인')
    elif tone == 'neutral_good':
        reasons.append(f'수급 {label} 우세')
    elif supply.get('personal_absorb'):
        reasons.append('개인 대량 흡수 가능성은 가격 지지 여부로 확인')
    elif tone == 'unknown':
        reasons.append('수급 미계산이라 비중 축소 필요')
    elif tone == 'weak':
        reasons.append('수급 부담은 있으나 지지 유지 시 흡수 여부 확인')
    if pc['basis_state'] in ('접촉','위안착'):
        reasons.append('실행기준선 근처라 손절 기준이 짧은 자리')
    elif pc['basis_state'] == '위확장':
        reasons.append('기준선 위지만 추격보다 눌림 재지지 확인 필요')
    elif pc['basis_state'] == '아래':
        reasons.append('실행기준선 아래라 회복선 안착 확인 필요')
    if pc.get('upper_line') and pc.get('price') and pc.get('price') < pc.get('upper_line'):
        reasons.append(f"상단회복선 {_v1071_fmt_price(pc.get('upper_line'))} 회복 시 추가매수 조건")
    if pc['fib_state'] == '38.2위': reasons.append('피보 38.2 위 강세 회귀권')
    elif pc['fib_state'] == '38.2~50': reasons.append('피보 38.2~50 얕은 눌림권')
    elif pc['fib_state'] == '50~61.8': reasons.append('피보 50~61.8 되돌림권에서 반등 확인 필요')
    elif pc['fib_state'] == '61.8아래': reasons.append('61.8 아래라 먼저 회복 확인 필요')
    if pc.get('risk_pct',99) <= 5.5: reasons.append(f"손절 기준 약 {pc.get('risk_pct',0):.1f}%로 짧은 편")
    if tech: reasons.append(tech)
    out=[]
    for r in reasons:
        r=_v1071_clean_line(r,94)
        if r and r not in out: out.append(r)
    return out[:5]


def _v1072_final_decision(d: dict, supply: dict) -> dict:
    # V1071 로직을 재사용하되, V1072 기준선/수급 보정값으로 다시 계산한다.
    pc = _v1072_price_context(d)
    rsi = _v1071_num(_v1071_get(d, 'RSI','rsi', default=50), 50)
    disp = _v1071_num(_v1071_get(d, '이격','Disparity','disparity', default=100), 100)
    phase = _v1071_txt(_v1071_get(d, '유형','추천단계','phase', default=''))
    pattern = _v1071_txt(_v1071_get(d, '검색패턴','N구분','대표신호','신호', default=''))
    refine = _v1071_txt(_v1071_get(d, '수박정제태그','저항구름태그','해설', default=''))
    blob = pattern + ' ' + refine + ' ' + phase
    fake = '가짜수박주의' in blob
    late = '후행' in blob
    overheat = rsi >= 72 or disp >= 115
    mild_overheat = rsi >= 70 or disp >= 110
    supply_tone = supply.get('tone','unknown')
    supply_label = _v1071_txt(supply.get('label','미계산'),'미계산')
    supply_unknown = supply_tone == 'unknown' or supply_label == '미계산'
    supply_good = supply_tone in ('strong','good','neutral_good')
    supply_absorb = bool(supply.get('personal_absorb')) and not supply_unknown
    supply_bad = supply_tone == 'weak' and not supply_absorb
    has_signal = any(k in blob for k in ['5일재안착','거래량폭발','저항돌파','정제수박','종베','삼각','수렴','BB40','BB30','독사','눌림목','돌반지','OBV','MFI'])
    near_line = pc['basis_state'] in ('접촉','위안착')
    near_fib = pc['fib_state'] in ('38.2위','38.2~50','50~61.8')
    extended = pc['basis_state'] == '위확장'
    below = pc['basis_state'] == '아래'
    deep = pc['fib_state'] == '61.8아래'
    short_risk = pc.get('risk_pct',99) <= 5.5 or (abs(pc.get('basis_gap',99)) <= 2.2 and pc.get('basis',0)>0)
    basis_missing = pc.get('basis_state') == '미확인' and pc.get('fib_state') == '미확인'
    late_confirmed = late and near_line and near_fib and supply_good and not mild_overheat and short_risk
    score = 0
    score += 20 if supply_good else 0
    score += 7 if supply_absorb else 0
    score -= 12 if supply_unknown else 0
    score -= 12 if supply_bad else 0
    score += 18 if near_line else 0
    score += 12 if near_fib else 0
    score += 8 if short_risk else 0
    score += 12 if has_signal else 0
    score += 5 if extended else 0
    score -= 10 if below else 0
    score -= 16 if deep else 0
    score -= 22 if overheat else 0
    score -= 10 if mild_overheat and not overheat else 0
    score -= 15 if fake else 0
    score -= 10 if late and not late_confirmed else 0
    score -= 16 if basis_missing else 0
    if basis_missing and supply_unknown:
        label, mode = '🔴 신규진입 보류', 'avoid'
    elif overheat or (late and mild_overheat):
        label, mode = '🔴 신규진입 보류', 'avoid'
    elif fake and (below or deep or supply_unknown):
        label, mode = '🔴 신규진입 보류', 'avoid'
    elif (near_line or near_fib) and has_signal and short_risk and supply_good and not supply_unknown and not fake and not mild_overheat and not below and (not late or late_confirmed):
        label, mode = '🟢 지금 1차 분할진입 가능', 'partial_now'
    elif (near_line or near_fib) and has_signal and not overheat and not deep and not fake and not supply_bad:
        label, mode = '🟡 소액 분할진입 가능', 'small_partial'
    elif extended and not overheat:
        label, mode = '🟡 눌림 확인 후 진입', 'pullback'
    elif below or deep:
        label, mode = '🟠 회복선 돌파 확인 후 진입', 'breakout_confirm'
    else:
        label, mode = '🟡 눌림 확인 후 진입', 'pullback'
    return {'label':label,'mode':mode,'score':score,'basis_state':pc['basis_state'],'basis_gap':pc['basis_gap'],'fib_state':pc['fib_state'],'risk_pct':pc.get('risk_pct',99),'rsi':rsi,'disp':disp,'late':late,'fake':fake,'mild_overheat':mild_overheat,'supply_unknown':supply_unknown,'short_risk':short_risk}


def _v1072_recovery_line(pc: dict) -> float:
    price=pc.get('price',0); upper=pc.get('upper_line',0); basis=pc.get('basis',0); fib382=pc.get('fib382',0); fib50=pc.get('fib50',0); fib618=pc.get('fib618',0)
    if price > 0 and fib382 > 0 and price < fib382: return fib382
    if price > 0 and fib50 > 0 and price < fib50: return fib50
    if price > 0 and fib618 > 0 and price < fib618: return fib618
    if price > 0 and upper > 0 and price < upper: return upper
    if price > 0 and basis > 0 and price < basis: return basis
    return basis or upper or fib382 or fib50 or fib618


def _v1072_trade_strategy(d: dict, decision: dict) -> list:
    pc = _v1072_price_context(d)
    price=pc.get('price',0); basis=pc.get('basis',0); upper=pc.get('upper_line',0); ma5=pc.get('ma5',0); ma10=pc.get('ma10',0); fib382=pc.get('fib382',0); fib50=pc.get('fib50',0); fib618=pc.get('fib618',0)
    mode=decision.get('mode','pullback')
    target1=_v1071_num(_v1071_get(d,'🎯목표타점','목표타점','목표1','target1',default=0),0)
    target2=_v1071_num(_v1071_get(d,'🎯목표2차','목표2차','목표2','target2',default=0),0)
    stop=_v1071_num(_v1071_get(d,'🚨손절가','손절가','손절','stop',default=0),0)
    if stop <= 0 and price > 0:
        c=[]
        if ma10>0: c.append(ma10)
        if fib50>0: c.append(fib50*0.985)
        if fib618>0: c.append(fib618*0.985)
        if basis>0: c.append(basis*0.97)
        c.append(price*0.95)
        below=[v for v in c if 0<v<price]
        stop=max(below) if below else min(c)
    add_ref = ma5 or upper or basis or fib382 or fib50
    first_ref = pc.get('nearest_support') or fib382 or basis or price
    lines=[]
    if mode=='partial_now':
        lines.append(f"1차: 현재가~{_v1071_fmt_price(first_ref)} 부근 20~30% 분할")
        if add_ref>0: lines.append(f"2차: {_v1071_fmt_price(add_ref)} 재지지/재안착 시 추가")
    elif mode=='small_partial':
        lines.append('1차: 현재가 추격보다 소액 10~20% 확인 진입')
        rec=_v1072_recovery_line(pc)
        if rec>0: lines.append(f"2차: {_v1071_fmt_price(rec)} 위 재안착 + 거래량 재유입 시 추가")
    elif mode=='pullback':
        ref=pc.get('nearest_support') or basis or fib382 or fib50
        lines.append('1차: 지금 추격보다 눌림 대기')
        if ref>0: lines.append(f"진입: {_v1071_fmt_price(ref)} 전후 재지지 + 양봉 마감 확인")
    elif mode=='breakout_confirm':
        rec=_v1072_recovery_line(pc)
        lines.append(f"진입: 회복선 {_v1071_fmt_price(rec)} 위 종가 안착 확인 후" if rec>0 else '진입: 기준선 회복과 거래량 증가 확인 후')
    else:
        lines.append('신규: 무리한 추격 금지, 회복선 재안착 전 관찰')
    if ma10>0 and fib50>0: lines.append(f"손절: 10일선 또는 피보50 {_v1071_fmt_price(fib50)} 이탈 시 축소/손절")
    elif fib50>0: lines.append(f"손절: 피보50 {_v1071_fmt_price(fib50)} 이탈 시 축소/손절")
    elif stop>0: lines.append(f"손절: {_v1071_fmt_price(stop)} 이탈 시 축소/손절")
    else: lines.append('손절: 기준선 이탈 또는 장대음봉 발생 시 축소')
    if target1>0:
        lines.append(f"목표: 1차 {_v1071_fmt_price(target1)}" + (f" / 2차 {_v1071_fmt_price(target2)}" if target2>target1 else ''))
    lines.append('무효: 거래량 없이 기준선 이탈하거나 외인·기관 동반 매도 확대')
    return lines[:5]


def _v1072_fib_line(row) -> str:
    d=_v1071_rowdict(row); pc=_v1072_price_context(d); vals=[]
    if pc.get('fib382'): vals.append(f"38.2 {_v1071_fmt_price(pc.get('fib382'))}")
    if pc.get('fib50'): vals.append(f"50 {_v1071_fmt_price(pc.get('fib50'))}")
    if pc.get('fib618'): vals.append(f"61.8 {_v1071_fmt_price(pc.get('fib618'))}")
    return ' / '.join(vals)


def _v1072_response_action(row) -> str:
    d=_v1071_rowdict(row); supply=_v1072_supply_judgement(d); dec=_v1072_final_decision(d,supply); mode=dec.get('mode')
    warn=[]; raw=_v1071_txt(_v1071_get(d,'실행제한','수박정제태그','매매판정','최종판정','N구분',default=''))
    rsi=_v1071_num(_v1071_get(d,'RSI','rsi',default=0),0); disp=_v1071_num(_v1071_get(d,'이격','disparity',default=0),0)
    if rsi>=70: warn.append(f'RSI{rsi:.0f}↑')
    if disp>=110: warn.append(f'이격{disp:.0f} 부담')
    if '가짜수박주의' in raw: warn.append('가짜수박주의')
    if supply.get('label')=='미계산': warn.append('수급미계산')
    if mode=='partial_now': base='1차 20~30% 분할진입 가능, 추가매수는 실행기준선·상단회복선 재지지 확인'
    elif mode=='small_partial': base='소액 10~20% 확인 진입만 가능, 추가매수는 기준선 재안착 후'
    elif mode=='pullback': base='지금 추격 금지, 눌림 재지지와 거래량 재유입 확인 후 진입'
    elif mode=='breakout_confirm': base='지금 추격 금지, 회복선 위 종가 안착 확인 후 진입'
    else: base='신규진입 보류, 회복선 재안착 전 관찰'
    if warn: base += ' / 주의: ' + ', '.join(dict.fromkeys(warn))
    return _v1071_clean_line(base,135)


def _v1072_short_decision_lines(row, indent='   ', include_supply=False) -> list:
    d=_v1071_rowdict(row); supply=_v1072_supply_judgement(d); decision=_v1072_final_decision(d,supply)
    material=_v1072_material_reason(d); tech=_v1072_technical_reason(d); reasons=_v1072_entry_reasons(d,supply); strategies=_v1072_trade_strategy(d,decision)
    lines=[f"{indent}🧭 최종판정: {decision['label']}"]
    if material: lines.append(f"{indent}🧩 재료/테마: {_v1071_clean_line(material,88)}")
    if tech: lines.append(f"{indent}🛠 기술근거: {_v1071_clean_line(tech,112)}")
    if reasons: lines.append(f"{indent}📌 진입이유: {_v1071_clean_line(' / '.join(reasons[:3]),118)}")
    if strategies: lines.append(f"{indent}🎯 분할진입: {_v1071_clean_line(' / '.join(strategies[:3]),155)}")
    bl=_v1072_basis_line(d)
    if bl: lines.append(f"{indent}🔵 기준선: {_v1071_clean_line(bl,125)}")
    fl=_v1072_fib_line(d)
    if fl: lines.append(f"{indent}📐 피보: {_v1071_clean_line(fl,105)}")
    if include_supply:
        lines.append(f"{indent}🏦 수급해석: {supply.get('label','미계산')}")
        lines.append(f"{indent}   ├ 1일: {supply.get('line1','')}")
        lines.append(f"{indent}   └ 3일: {supply.get('line3','')}")
    return lines

