def _v1067_build_trade_decision_block(row) -> str:
    try:
        d=_v1071_rowdict(row); supply=_v1072_supply_judgement(d); decision=_v1072_final_decision(d,supply)
        material=_v1072_material_reason(d); tech=_v1072_technical_reason(d); reasons=_v1072_entry_reasons(d,supply); strategies=_v1072_trade_strategy(d,decision)
        lines=[f"🧭 최종판정: {decision['label']}", f"🧩 재료/테마: {_v1071_clean_line(material,100)}", f"🛠 기술근거: {_v1071_clean_line(tech,115)}"]
        if reasons: lines.append('📌 진입이유: ' + ' / '.join([_v1071_clean_line(r,58) for r in reasons[:4]]))
        lines.append('🎯 분할진입:')
        for s in strategies[:4]: lines.append(f'   - {s}')
        lines.append('🔵 기준선: ' + _v1072_basis_line(d))
        fl=_v1072_fib_line(d)
        if fl: lines.append('📐 피보: ' + fl)
        lines.append(f"🏦 수급해석: {supply.get('label','미계산')}")
        lines.append(f"   ├ 1일: {supply.get('line1','')}")
        lines.append(f"   └ 3일: {supply.get('line3','')}")
        return '\n'.join(lines).strip()
    except Exception:
        return ''


def _v1062_simple_ai_comment(row, max_len=None) -> str:
    try:
        d=_v1071_rowdict(row); sj=_v1072_supply_judgement(d); dec=_v1072_final_decision(d,sj); mat=_v1072_material_reason(d); mode=dec.get('mode')
        if mode=='partial_now': msg='현재가는 1차 분할 가능권입니다. 추가매수는 실행기준선·상단회복선 재지지 후가 좋습니다.'
        elif mode=='small_partial': msg='소액 확인 진입만 가능하고, 추가매수는 기준선 재안착과 거래량 재유입 이후가 좋습니다.'
        elif mode=='pullback': msg='구조와 재료는 살아 있지만 지금은 추격보다 눌림 재지지 확인이 우선입니다.'
        elif mode=='breakout_confirm': msg='아직 회복선 확인이 필요합니다. 회복선 위 종가 안착 후 접근하는 편이 안전합니다.'
        else: msg='신규 진입은 보류하고, 과열 해소 또는 기준선 회복을 기다리는 편이 안전합니다.'
        if sj.get('personal_absorb'): msg += ' 개인 매수는 대량 흡수 가능성도 함께 봅니다.'
        if mat and '미확인' not in mat and mode in ('partial_now','small_partial'): msg += ' 재료는 ' + _v1071_clean_line(mat,34) + '입니다.'
        return _v1071_clean_line(msg, max_len or 140)
    except Exception:
        return '기준선·거래량·수급 확인 후 접근합니다.'


