def _v1073_unique_keep(seq, limit=6):
    out = []
    for x in seq or []:
        s = _v1071_txt(x, '') if '_v1071_txt' in globals() else str(x).strip()
        if s and s not in out:
            out.append(s)
        if len(out) >= limit:
            break
    return out


def _v1073_sector_split(sector_results=None):
    rec, watch, avoid = [], [], []
    for s in list(sector_results or []):
        try:
            name = _v1071_txt(s.get('sector', ''), '')
            verdict = _v1071_txt(s.get('verdict', ''), '')
            if not name:
                continue
            if verdict == '추천':
                rec.append(name)
            elif verdict == '관찰':
                watch.append(name)
            elif verdict == '회피':
                avoid.append(name)
        except Exception:
            pass
    return {
        'recommend': _v1073_unique_keep(rec, 5),
        'watch': _v1073_unique_keep(watch, 5),
        'avoid': _v1073_unique_keep(avoid, 5),
    }


def format_sector_rotation_report(sector_results, directions):
    global _V1073_LAST_SECTOR_SPLIT, _V1073_LAST_OIL_DIRECTION
    try:
        _V1073_LAST_SECTOR_SPLIT = _v1073_sector_split(sector_results)
        _V1073_LAST_OIL_DIRECTION = (directions or {}).get('oil', 'unknown') or 'unknown'
    except Exception:
        pass
    if _V1073_BASE_SECTOR_FORMAT:
        return _V1073_BASE_SECTOR_FORMAT(sector_results, directions)
    return ''


def _v1073_join_or_none(xs):
    xs = _v1073_unique_keep(xs, 5)
    return ', '.join(xs) if xs else '해당 없음'


