def _v1073_basis_unified_line(row) -> str:
    try:
        d = _v1071_rowdict(row)
        pc = _v1072_price_context(d)
        parts = []
        if pc.get('exec_line'):
            parts.append(f"실행기준선 {_v1073_fmt_price(pc.get('exec_line'))}")
        if pc.get('upper_line') and abs(float(pc.get('upper_line') or 0) - float(pc.get('exec_line') or 0)) > 1:
            parts.append(f"상단회복선 {_v1073_fmt_price(pc.get('upper_line'))}")
        if pc.get('ma5'):
            parts.append(f"5일선 {_v1073_fmt_price(pc.get('ma5'))}")
        if pc.get('price') and pc.get('basis'):
            parts.append(f"이격 {pc.get('basis_gap',0):+.1f}%/{pc.get('basis_state','')}")
        if pc.get('fib382'):
            parts.append(f"피보38.2 {_v1073_fmt_price(pc.get('fib382'))}")
        if pc.get('fib50'):
            parts.append(f"50 {_v1073_fmt_price(pc.get('fib50'))}")
        if pc.get('fib618'):
            parts.append(f"61.8 {_v1073_fmt_price(pc.get('fib618'))}")
        if pc.get('stop_line'):
            parts.append(f"손절참고 {_v1073_fmt_price(pc.get('stop_line'))}")
        return ' / '.join(parts) if parts else '기준선 산출불가'
    except Exception:
        try:
            return _v1072_basis_line(row)
        except Exception:
            return '기준선 산출불가'


