def _v1073_parse_today_order(base_text: str, row_map: dict, limit: int = 10):
    out, seen = [], set()
    try:
        header_re = _v1071_re.compile(r'^\s*(\d+)\)\s+([^()|\n]+?)(?:\(([^)]+)\))?\s*\|\s*현재\s*([0-9,.-]+)?', _v1071_re.M)
        for m in header_re.finditer(str(base_text or '')):
            name = _v1071_txt(m.group(2), '')
            code = _v1071_txt(m.group(3), '')
            key = code.zfill(6) if code else name
            if not key or key in seen:
                continue
            d = None
            if code:
                d = row_map.get(code) or row_map.get(code.zfill(6))
            if d is None and name:
                d = row_map.get(name)
            if d is None:
                d = {'종목명': name, 'code': code, '현재가': m.group(4)}
            out.append(d)
            seen.add(key)
            if len(out) >= limit:
                break
    except Exception:
        pass
    return out


