def _v1074_rowdict(row):
    try:
        return _v1071_rowdict(row)
    except Exception:
        try:
            return dict(row)
        except Exception:
            return {}


def _v1074_bool_false(d: dict, *keys) -> bool:
    for k in keys:
        if k not in d:
            continue
        v = d.get(k)
        if isinstance(v, bool):
            return not v
        try:
            if isinstance(v, (int, float)) and not isinstance(v, bool):
                # 점수형 컬럼은 0을 미통과로 해석하되 None/NaN은 제외
                return float(v) == 0.0
        except Exception:
            pass
        s = str(v).strip().lower()
        if s in ('false','0','no','n','x','none','nan','미통과','부족','약함','실패'):
            return True
        if any(x in s for x in ['false', '미통과', '부족', '약함', '실패', '불량']):
            return True
    return False


def _v1074_bool_true(d: dict, *keys) -> bool:
    for k in keys:
        if k not in d:
            continue
        v = d.get(k)
        if isinstance(v, bool):
            return bool(v)
        s = str(v).strip().lower()
        if s in ('true','1','yes','y','ok','통과','확인'):
            return True
        if any(x in s for x in ['true', '통과', '확인', '양호']):
            return True
    return False


def _v1074_is_fake_watermelon(row) -> bool:
    d = _v1074_rowdict(row)
    try:
        blob = ' '.join(str(d.get(k, '') or '') for k in [
            '수박정제태그','검색패턴','N구분','대표신호','신호','구조','해설','AI코멘트','실행제한','매매판정'
        ])
        if '가짜수박주의' in blob or '가짜수박' in blob or '가짜/정제주의' in blob:
            return True
        if _v1074_bool_true(d, '수박정제주의', 'fake_watermelon', 'fake_flag'):
            return True
    except Exception:
        pass
    return False


def _v1074_fake_watermelon_reason(row, max_items: int = 3) -> str:
    """가짜수박주의 원인을 짧게 요약한다.
    우선 실제 정제 플래그를 보고, 없으면 RSI/이격/수급/구름/피보 위치로 추정한다.
    """
    d = _v1074_rowdict(row)
    reasons = []
    def add(x):
        x = str(x or '').strip()
        if x and x not in reasons:
            reasons.append(x)
    try:
        if _v1074_bool_true(d, '수박정제_hard_fail', 'hard_fail'):
            add('정제 하드필터 미통과')
        if _v1074_bool_false(d, '수박정제_vol_ok', 'vol_ok', 'volume_ok'):
            add('거래량 부족')
        if _v1074_bool_false(d, '수박정제_reclaim_ok', 'reclaim_ok', 'ma5_reclaim_ok'):
            add('5일선 재안착 미확정')
        if _v1074_bool_false(d, '수박정제_candle_ok', 'candle_ok'):
            add('양봉/종가 유지 약함')
        if _v1074_bool_false(d, '수박정제_wick_ok', 'wick_ok'):
            add('윗꼬리 부담')
        if _v1074_bool_false(d, '수박정제_long_ok', 'long_ok'):
            add('장기이평·저항 위치 부담')
        if _v1074_bool_false(d, '수박정제_cloud_ok', 'cloud_ok'):
            add('저항구름 안착 미확인')
        if _v1074_bool_false(d, '수박정제_obv_ok', 'obv_ok'):
            add('OBV/매집 둔화')

        # 정제 플래그가 없으면 보조 추정
        blob = ' '.join(str(d.get(k, '') or '') for k in [
            '수박정제태그','검색패턴','N구분','대표신호','신호','구조','해설','피보회귀','피보/회귀','저항구름태그','저항구름상태'
        ])
        rsi = _v1071_num(_v1071_get(d, 'RSI', 'rsi', default=0), 0) if '_v1071_num' in globals() else 0
        disp = _v1071_num(_v1071_get(d, '이격', 'Disparity', 'disparity', default=0), 0) if '_v1071_num' in globals() else 0
        if rsi >= 70:
            add('RSI 과열')
        if disp >= 112:
            add('이격 부담')
        try:
            pc = _v1072_price_context(d)
            if pc.get('basis_state') == '아래':
                add('기준선 아래')
            elif pc.get('basis_state') == '위확장' and abs(float(pc.get('basis_gap') or 0)) >= 6:
                add('기준선 이격 과다')
            if pc.get('fib_state') == '61.8아래':
                add('피보 61.8 하단')
            elif pc.get('fib_state') == '50~61.8':
                add('피보 회복 확인 필요')
        except Exception:
            pass
        if 'UTAD' in blob or '실패돌파' in blob:
            add('실패돌파/UTAD 위험')
        if '저항전' in blob:
            add('저항구름 아래')
        elif '저항테스트' in blob:
            add('저항 안착 전')
        try:
            sj = _v1072_supply_judgement(d)
            if sj.get('tone') == 'weak':
                add('수급 부담')
            elif sj.get('personal_absorb'):
                add('개인흡수 확인 필요')
        except Exception:
            pass
    except Exception:
        pass
    if not reasons:
        reasons = ['정제조건 일부 미통과']
    return '·'.join(reasons[:max_items])


def _v1074_fake_label(row) -> str:
    if not _v1074_is_fake_watermelon(row):
        return ''
    return '⚠️가짜수박주의(' + _v1074_fake_watermelon_reason(row, 3) + ')'


def _v1074_decorate_fake_text(text, row) -> str:
    s = str(text or '')
    label = _v1074_fake_label(row)
    if not label:
        return s
    # 이미 이유가 붙어 있으면 중복 방지
    if '가짜수박주의(' in s:
        return s
    if '⚠️가짜수박주의' in s:
        return s.replace('⚠️가짜수박주의', label, 1)
    if '가짜수박주의' in s:
        return s.replace('가짜수박주의', label.replace('⚠️',''), 1)
    if '가짜/정제주의' in s:
        return s.replace('가짜/정제주의', label.replace('⚠️',''), 1)
    return s


def _v1072_technical_reason(d: dict) -> str:
    base = ''
    try:
        base = _V1074_BASE_TECHNICAL_REASON(d) if _V1074_BASE_TECHNICAL_REASON else ''
    except Exception:
        base = ''
    if _v1074_is_fake_watermelon(d):
        detail = _v1074_fake_label(d)
        if detail and detail not in base:
            base = (base + ' + ' if base else '') + detail
    return _v1071_clean_line(base, 150) if '_v1071_clean_line' in globals() else base


def _v1072_response_action(row) -> str:
    base = ''
    try:
        base = _V1074_BASE_RESPONSE_ACTION(row) if _V1074_BASE_RESPONSE_ACTION else ''
    except Exception:
        base = ''
    if not base:
        base = '기준선·거래량·수급 확인 후 접근합니다.'
    return _v1074_decorate_fake_text(base, row)

