def _v1073_compact_action_card(row, idx: int) -> list:
    """V1074: 오늘 매매관점 압축 카드에도 가짜수박 원인을 표시한다."""
    d = _v1071_rowdict(row)
    name = _v1071_txt(_v1071_get(d, '종목명','Name','name', default='-'), '-')
    code = _v1071_txt(_v1071_get(d, 'code','Code','종목코드', default=''), '')
    price = _v1071_num(_v1071_get(d, '현재가','Close','종가','price', default=0), 0)
    price_s = f"{price:,.0f}" if price > 0 else '-'
    sj = _v1072_supply_judgement(d)
    dec = _v1072_final_decision(d, sj)
    mat = _v1072_material_reason(d)
    tech = _v1072_technical_reason(d)
    strat = _v1072_trade_strategy(d, dec)
    action = _v1072_response_action(d)
    target = _v1074_target_line(row)
    code_s = f"({code})" if code else ''
    lines = [f"{idx}) {name}{code_s} | 현재 {price_s}"]
    lines.append(f"   🧭 {dec.get('label','')}")
    lines.append(f"   🧩 {_v1071_clean_line(mat, 72)}")
    lines.append(f"   🛠 {_v1071_clean_line(tech, 96)}")
    if strat:
        lines.append(f"   🎯 {_v1071_clean_line(' / '.join(strat[:3]), 120)}")
    lines.append(f"   🏦 {sj.get('label','미계산')} | 1일 {sj.get('line1','')} | 3일 {sj.get('line3','')}")
    lines.append(f"   🔵 {_v1071_clean_line(_v1073_basis_unified_line(d), 122)}")
    lines.append(f"   ✅ {_v1071_clean_line(action, 125)}")
    if target:
        lines.append(f"   🎯 가격: {target}")
    return lines


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    """V1074: TOP15 압축판에 가짜수박주의 이유와 V1074 버전 문구를 반영한다."""
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return ''
        limit = max(1, int(limit or 15))
        try:
            out_df = _v1053_select_top15_with_late_cap(df, limit=limit, update_late_ref=(len(df) > limit)).head(limit).reset_index(drop=True)
        except Exception:
            out_df = df.head(limit).reset_index(drop=True)
        if out_df.empty:
            return ''
        late_max = _v1053_env_int('V1053_TOP15_LATE_MAX', 3) if '_v1053_env_int' in globals() else 3
        lines=[]
        lines.append(f'📢 [{title}]')
        lines.append('')
        lines.append('기준: 차트/구조/수급 우선 1단계 압축판입니다. 상세 파동·긴 해설은 후속 섹션/HTML에서 확인합니다.')
        lines.append(f'정렬 보정: 후행형은 TOP15 안에서 최대 {late_max}개까지만 유지합니다.')
        lines.append('진입 공통조건: 5일선·실행기준선 위 양봉 마감 + 거래량 전일比 1.3배↑ 또는 5일평균比 1.2배↑')
        lines.append('V1074: 가짜수박주의 이유 표시 / 실행기준선·상단회복선 분리 / 시황동기화 압축판')
        lines.append('')
        for i,row in out_df.iterrows():
            d=_v1071_rowdict(row)
            name=_v1050_first(row,['종목명','Name','name'],'-') if '_v1050_first' in globals() else _v1071_txt(d.get('종목명') or d.get('Name') or d.get('name') or '-')
            try:
                code=_v1053_code(row) if '_v1053_code' in globals() else _v1050_norm_code(_v1050_first(row,['code','Code','종목코드'],''))
            except Exception:
                code=_v1071_txt(d.get('code') or d.get('Code') or d.get('종목코드') or '')
            price=_v1050_num(row.get('현재가', row.get('Close',0)),0) if '_v1050_num' in globals() and hasattr(row,'get') else _v1071_num(d.get('현재가') or d.get('Close'),0)
            phase=_v1050_phase(row) if '_v1050_phase' in globals() else _v1071_txt(d.get('유형') or d.get('추천단계'))
            sig=_v1050_signal(row) if '_v1050_signal' in globals() else _v1071_txt(d.get('신호') or d.get('N조합'))
            pattern=_v1050_pattern(row) if '_v1050_pattern' in globals() else _v1071_txt(d.get('검색패턴') or d.get('N구분'))
            pattern=_v1074_pattern_with_fake_reason(pattern, d)
            target=_v1050_target_text(row) if '_v1050_target_text' in globals() else ''
            safe=_v1050_int(row.get('안전점수',0),0) if '_v1050_int' in globals() and hasattr(row,'get') else _v1071_int(d.get('안전점수'),0)
            nscore=_v1050_int(row.get('N점수',0),0) if '_v1050_int' in globals() and hasattr(row,'get') else _v1071_int(d.get('N점수'),0)
            rsi=_v1071_num(d.get('RSI'),0); disp=_v1071_num(d.get('이격'),0); bb40=_v1071_num(d.get('BB40'),0); obv=_v1071_num(d.get('OBV기울기'),0)
            sj=_v1072_supply_judgement(d); dec=_v1072_final_decision(d,sj)
            mat=_v1072_material_reason(d); tech=_v1072_technical_reason(d); reasons=_v1072_entry_reasons(d,sj); strat=_v1072_trade_strategy(d,dec)
            code_s=f'({code})' if code else ''; price_s=f'{price:,.0f}원' if price>0 else '-'
            lines.append(f'{i+1}) {name}{code_s} | 현재 {price_s} | 유형 {phase}')
            lines.append(f'   🎯 {sig} | {pattern}')
            lines.append(f'   📊 이격 {disp:.0f} / RSI {rsi:.0f} / BB40 {bb40:.1f} / OBV {obv:+.0f} / 안전{safe}·N{nscore}')
            lines.append(f"   🧭 최종판정: {dec['label']}")
            lines.append(f'   🧩 재료: {_v1071_clean_line(mat,86)}')
            lines.append(f'   🛠 근거: {_v1071_clean_line(tech,112)}')
            if reasons:
                # 이유 안에도 가짜수박 디테일이 들어가면 중복되므로 앞 2개만 유지
                lines.append(f"   📌 이유: {_v1071_clean_line(' / '.join(reasons[:2]),108)}")
            if strat:
                lines.append(f"   🎯 전략: {_v1071_clean_line(' / '.join(strat[:3]),140)}")
            lines.append(f"   🏦 수급: {sj.get('label','미계산')} | 1일 {sj.get('line1','')} | 3일 {sj.get('line3','')}")
            lines.append(f"   🔵 기준/피보: {_v1071_clean_line(_v1073_basis_unified_line(d),105)}")
            lines.append(f"   ✅ 대응: {_v1072_response_action(d)}")
            if target:
                lines.append(f'   🎯 가격: {target}')
            lines.append('')
        late_ref_block = _v1053_build_late_reference_block() if '_v1053_build_late_reference_block' in globals() else ''
        if late_ref_block:
            lines.append(late_ref_block); lines.append('')
        msg='\n'.join(lines).strip()
        return _v1054_cleanup_message(msg) if '_v1054_cleanup_message' in globals() else msg
    except Exception as e:
        try:
            log_error(f'⚠️ V1074 TOP15 압축 생성 실패: {e}')
        except Exception:
            pass
        try:
            return _V1074_BASE_TOP15_BLOCK(df, limit=limit, title=title) if _V1074_BASE_TOP15_BLOCK else ''
        except Exception:
            return ''

