def _v1075_decision_bucket(row) -> str:
    """오늘 매매관점 압축용 섹션 분류.
    실전 후보에는 실제 진입 검토 가능한 🟢/🟡만 넣고,
    🔴 신규진입 보류는 리스크 참고로 분리한다.
    """
    try:
        d = _v1071_rowdict(row)
        sj = _v1072_supply_judgement(d)
        dec = _v1072_final_decision(d, sj)
        label = str(dec.get('label', '') or '')
        mode = str(dec.get('mode', '') or '')
        if '🔴' in label or mode in ('avoid', 'risk', 'hold'):
            return 'risk'
        if '🟠' in label or mode in ('breakout_confirm', 'recover_confirm') or '회복선' in label:
            return 'recovery'
        if '눌림 확인' in label or mode == 'pullback':
            return 'pullback'
        if '🟢' in label or '소액 분할진입 가능' in label or mode in ('partial_now', 'small_partial'):
            return 'partial'
        # 기준선 산출불가/수급미계산+불명확 종목은 실전 후보가 아니라 참고로 둔다.
        pc = _v1072_price_context(d)
        if pc.get('basis_state') == '미확인':
            return 'risk'
        return 'pullback'
    except Exception:
        return 'risk'


def _v1075_section_title(bucket: str, count: int) -> str:
    if bucket == 'partial':
        return f'🟢 [분할진입 후보] 지금/소액 진입 검토 {count}개'
    if bucket == 'pullback':
        return f'🟡 [눌림 확인 후보] 재지지 확인 후 진입 {count}개'
    if bucket == 'recovery':
        return f'🟠 [회복 확인 후보] 회복선 돌파 확인 {count}개'
    return f'⚠️ [리스크 참고/신규진입 보류] 실전 후보 제외 {count}개'


def _v1075_render_section(bucket: str, rows: list, start_idx: int = 1) -> list:
    lines = []
    lines.append(_v1075_section_title(bucket, len(rows)))
    if not rows:
        if bucket == 'partial':
            lines.append('   - 지금 바로 1차/소액 분할진입 조건을 만족한 종목 없음')
        elif bucket == 'pullback':
            lines.append('   - 눌림 재지지 확인 후보 없음')
        elif bucket == 'recovery':
            lines.append('   - 회복선 돌파 확인 후보 없음')
        else:
            lines.append('   - 신규진입 보류/리스크 참고 종목 없음')
        return lines
    lines.append('────────────────────')
    for i, r in enumerate(rows, start_idx):
        try:
            lines.extend(_v1073_compact_action_card(r, i))
        except Exception as e:
            try:
                d = _v1071_rowdict(r)
                name = _v1071_txt(_v1071_get(d, '종목명','Name','name', default='-'), '-')
                code = _v1071_txt(_v1071_get(d, 'code','Code','종목코드', default=''), '')
                code_s = f'({code})' if code else ''
                lines.append(f'{i}) {name}{code_s} | 카드 생성 실패: {e}')
            except Exception:
                lines.append(f'{i}) 카드 생성 실패')
        lines.append('')
    return lines


def _v1073_compact_today_block(base: str, row_map: dict) -> str:
    """V1075: 오늘 매매관점 압축을 실전 후보/리스크 참고로 분리한다."""
    total = None
    excluded = None
    try:
        m = _v1071_re.search(r'후보\s*수집\s*[:：]\s*([0-9,]+)\s*개', str(base or ''))
        if m:
            total = m.group(1)
        e = _v1071_re.search(r'제외/리스크\s*참고\s*[:：]\s*([0-9,]+)\s*개', str(base or ''))
        if e:
            excluded = e.group(1)
    except Exception:
        pass
    try:
        limit = int(_v1071_os.environ.get('TODAY_ACTION_OBSERVE_LIMIT', '10')) if '_v1071_os' in globals() else 10
    except Exception:
        limit = 10
    try:
        rows = _v1073_parse_today_order(base, row_map, limit=max(1, limit))
    except Exception:
        rows = []
    if not rows:
        try:
            return _V1075_BASE_TODAY_COMPACT_BLOCK(base, row_map) if _V1075_BASE_TODAY_COMPACT_BLOCK else base
        except Exception:
            return base

    groups = {'partial': [], 'pullback': [], 'recovery': [], 'risk': []}
    for r in rows:
        groups[_v1075_decision_bucket(r)].append(r)

    actionable_count = len(groups['partial']) + len(groups['pullback']) + len(groups['recovery'])
    lines = [
        '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
        '🎯 [오늘 매매관점 압축]',
        '',
        f'📌 후보 수집: {total or len(rows)}개',
        '📌 압축 기준: 분할진입 후보 → 눌림 확인 후보 → 회복 확인 후보 → 리스크 참고',
        '📌 실행 조건: 실행기준선·5일선 위 양봉 마감 + 거래량 전일比 1.3배↑ 또는 5일평균比 1.2배↑',
        '📌 원칙: 🔴 신규진입 보류 종목은 실전 후보가 아니라 리스크 참고로 분리합니다.',
        '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━',
        ''
    ]
    if actionable_count <= 0:
        lines.append('🟢/🟡 [실전 진입 가능 후보] 0개')
        lines.append('   - 오늘은 조건을 만족한 실전 진입 후보가 없습니다.')
        lines.append('   - 무리한 매수보다 TOP15/리스크 참고에서 회복 조건만 확인합니다.')
        lines.append('')
    else:
        idx = 1
        for bucket in ('partial', 'pullback', 'recovery'):
            rows_b = groups[bucket]
            if rows_b:
                lines.extend(_v1075_render_section(bucket, rows_b, idx))
                idx += len(rows_b)
                lines.append('')

    if groups['risk']:
        # 리스크 참고는 번호를 새로 시작해서 실전 후보와 분리감을 준다.
        lines.extend(_v1075_render_section('risk', groups['risk'], 1))
        lines.append('')

    if excluded is not None:
        lines.append(f'⛔ 제외/리스크 참고: {excluded}개')
        lines.append('   상세는 기본 숨김입니다. 필요하면 SHOW_EXCLUDED_RISK=1, TODAY_ACTION_AVOID_LIMIT=5')
    lines.append('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━')
    msg = '\n'.join(lines).strip()
    try:
        return _v1054_cleanup_message(msg) if '_v1054_cleanup_message' in globals() else msg
    except Exception:
        return msg


