def _v1076_text_has(s, keys):
    s = str(s or '')
    return any(str(k) in s for k in keys)


def _v1076_reason_items(row):
    """V1074 원인 문자열을 리스트화하되, 거래량 마름의 성격을 재분류한다."""
    try:
        raw = _V1076_BASE_FAKE_REASON(row, 6) if _V1076_BASE_FAKE_REASON else ''
    except Exception:
        raw = ''
    items = []
    for x in str(raw or '').replace(',', '·').split('·'):
        x = x.strip()
        if x and x not in items:
            items.append(x)
    if not items:
        items = ['정제조건 일부 미통과']

    # 거래량 부족이 지지선 위의 마른 눌림인지 구분한다.
    try:
        d = _v1071_rowdict(row)
        pc = _v1072_price_context(d)
        sj = _v1072_supply_judgement(d)
        rsi = _v1071_num(_v1071_get(d, 'RSI', 'rsi', default=50), 50)
        disp = _v1071_num(_v1071_get(d, '이격', 'Disparity', 'disparity', default=100), 100)
        basis_ok = pc.get('basis_state') in ('접촉', '위안착')
        fib_ok = pc.get('fib_state') in ('38.2위', '38.2~50', '50~61.8')
        not_bad_candle = not any(_v1076_text_has(x, ['윗꼬리', '종가 유지 약함', '양봉/종가', 'OBV/매집 둔화']) for x in items)
        not_resistance_fail = not any(_v1076_text_has(x, ['저항구름 아래', '저항구름 안착 미확인', '기준선 아래', '피보 61.8 하단']) for x in items)
        supply_ok = sj.get('tone') in ('strong', 'good', 'neutral_good') or sj.get('personal_absorb') or sj.get('tone') == 'unknown'
        not_hot = rsi < 70 and disp < 112
        dry_good = ('거래량 부족' in items) and basis_ok and fib_ok and not_bad_candle and not_resistance_fail and supply_ok and not_hot
        if dry_good:
            items = [('거래량응축(양호)' if x == '거래량 부족' else x) for x in items]
    except Exception:
        pass
    return items


def _v1076_fake_profile(row) -> dict:
    """가짜수박/정제주의의 강도와 성격을 계산한다.
    severity: none/dry_good/weak/medium/strong
    """
    try:
        is_fake = _v1074_is_fake_watermelon(row) if '_v1074_is_fake_watermelon' in globals() else False
    except Exception:
        is_fake = False
    if not is_fake:
        return {'is_fake': False, 'severity': 'none', 'label': '', 'items': []}

    items = _v1076_reason_items(row)
    txt = '·'.join(items)
    if '거래량응축(양호)' in txt:
        # 마른 눌림 자체는 부정 신호가 아니므로 관찰수박으로 낮춘다.
        label_items = []
        for x in items:
            if x == '거래량응축(양호)':
                label_items.append('거래량응축')
            elif x in ('5일선 재안착 미확정', '저항 안착 전'):
                label_items.append(x)
        if not label_items:
            label_items = ['거래량응축']
        return {'is_fake': True, 'severity': 'dry_good', 'label': '🟨관찰수박(약: ' + '·'.join(label_items[:3]) + ')', 'items': items}

    strong_keys = ['정제 하드필터', '기준선 아래', '피보 61.8 하단', 'OBV/매집 둔화', '수급 부담', '실패돌파', 'UTAD']
    medium_keys = ['윗꼬리', '양봉/종가 유지 약함', '5일선 재안착 미확정', '저항구름 안착 미확인', '저항구름 아래', '저항 안착 전', '장기이평', '이격 부담', 'RSI 과열', '피보 회복 확인']
    if _v1076_text_has(txt, strong_keys):
        sev, icon = 'strong', '🚫'
        sev_kr = '강'
    elif _v1076_text_has(txt, medium_keys):
        sev, icon = 'medium', '⚠️'
        sev_kr = '중'
    else:
        sev, icon = 'weak', '⚠️'
        sev_kr = '약'
    label = f"{icon}가짜수박주의({sev_kr}: " + '·'.join(items[:3]) + ')'
    return {'is_fake': True, 'severity': sev, 'label': label, 'items': items}


def _v1074_fake_watermelon_reason(row, max_items: int = 3) -> str:
    """V1076: 기존 원인 산출 후 거래량 마름을 응축/부족/실패로 재분류."""
    try:
        items = _v1076_reason_items(row)
        return '·'.join(items[:max_items]) if items else '정제조건 일부 미통과'
    except Exception:
        return '정제조건 일부 미통과'


def _v1074_fake_label(row) -> str:
    prof = _v1076_fake_profile(row)
    return prof.get('label', '')


def _v1076_fake_severity(row) -> str:
    return _v1076_fake_profile(row).get('severity', 'none')


def _v1072_final_decision(d: dict, supply: dict) -> dict:
    """V1076: 가짜수박 강도에 따라 최종판정을 보수화한다.
    - 거래량응축(양호)은 가짜로 보지 않고 기존 판정 허용
    - 약: 🟢 가능하되 사실상 소액/비중축소 성격
    - 중: 🟢 금지, 최대 눌림/소액
    - 강: 신규진입 보류 또는 회복확인
    """
    try:
        dec = dict(_V1076_BASE_FINAL_DECISION(d, supply)) if _V1076_BASE_FINAL_DECISION else {}
    except Exception:
        dec = {}
    if not dec:
        dec = {'label': '🟡 눌림 확인 후 진입', 'mode': 'pullback', 'score': 0}
    try:
        prof = _v1076_fake_profile(d)
        sev = prof.get('severity', 'none')
        pc = _v1072_price_context(d)
        # 중/강은 초록 금지. 강은 보류 우선.
        if sev == 'strong':
            if pc.get('basis_state') == '아래' or pc.get('fib_state') in ('61.8아래', '미확인'):
                dec['label'], dec['mode'] = '🔴 신규진입 보류', 'avoid'
            else:
                dec['label'], dec['mode'] = '🟡 눌림 확인 후 진입', 'pullback'
        elif sev == 'medium':
            if '🟢' in str(dec.get('label', '')) or dec.get('mode') == 'partial_now':
                dec['label'], dec['mode'] = '🟡 눌림 확인 후 진입', 'pullback'
            elif dec.get('mode') == 'small_partial':
                dec['label'] = '🟡 소액 분할진입 가능'
        elif sev == 'weak':
            if '🟢' in str(dec.get('label', '')):
                dec['label'], dec['mode'] = '🟡 소액 분할진입 가능', 'small_partial'
        elif sev == 'dry_good':
            # 거래량응축은 매집/눌림 관점에서는 양호. 다만 응답 문구에서 재유입 확인을 붙인다.
            pass
        dec['fake_severity'] = sev
        dec['fake_label'] = prof.get('label', '')
    except Exception:
        pass
    return dec


