def _v1072_entry_reasons(d: dict, supply: dict) -> list:
    """V1076: 실행기준선과 상단회복선을 혼동하지 않게 이유 문구를 정리한다."""
    try:
        reasons = _V1076_BASE_ENTRY_REASONS(d, supply) if _V1076_BASE_ENTRY_REASONS else []
    except Exception:
        reasons = []
    out = []
    try:
        pc = _v1072_price_context(d)
        price = pc.get('price', 0)
        exec_line = pc.get('exec_line', 0)
        upper_line = pc.get('upper_line', 0)
        for r in list(reasons or []):
            s = str(r or '')
            if '실행기준선 아래라 회복선 안착 확인 필요' in s:
                if exec_line and price and price >= exec_line and upper_line and price < upper_line:
                    s = f"실행기준선 위는 유지 중이나, 상단회복선 {_v1071_fmt_price(upper_line)} 회복 전에는 추가매수 대기"
                elif (not exec_line) and upper_line and price and price < upper_line:
                    s = f"상단회복선 {_v1071_fmt_price(upper_line)} 아래라 회복 확인 필요"
            if s and s not in out:
                out.append(s)
        prof = _v1076_fake_profile(d)
        sev = prof.get('severity', 'none')
        if sev == 'dry_good':
            msg = '거래량은 마른 눌림/응축 성격, 단 재양봉과 거래량 재유입 확인 필요'
            if msg not in out:
                out.insert(0, msg)
        elif sev in ('weak', 'medium', 'strong'):
            msg = prof.get('label', '')
            if msg and msg not in ' / '.join(out):
                out.append(msg)
    except Exception:
        out = list(reasons or [])
    clean = []
    for r in out:
        try:
            r = _v1071_clean_line(r, 96)
        except Exception:
            r = str(r)
        if r and r not in clean:
            clean.append(r)
    return clean[:5]


