_v1070_entry_reasons = _v1072_entry_reasons


def _v1073_basis_unified_line(row) -> str:
    """V1076: 실행기준선과 상단회복선을 항상 분리해서 보여준다."""
    try:
        d = _v1071_rowdict(row)
        pc = _v1072_price_context(d)
        parts = []
        exec_line = pc.get('exec_line', 0)
        upper_line = pc.get('upper_line', 0)
        if exec_line:
            parts.append(f"실행기준선 {_v1073_fmt_price(exec_line)}")
        else:
            parts.append('실행기준선 미확인')
        if upper_line:
            parts.append(f"상단회복선 {_v1073_fmt_price(upper_line)}")
        else:
            parts.append('상단회복선 미확인')
        if pc.get('price') and pc.get('basis'):
            parts.append(f"이격 {pc.get('basis_gap',0):+.1f}%/{pc.get('basis_state','')}")
        fibs = []
        if pc.get('fib382'):
            fibs.append(f"38.2 {_v1073_fmt_price(pc.get('fib382'))}")
        if pc.get('fib50'):
            fibs.append(f"50 {_v1073_fmt_price(pc.get('fib50'))}")
        if pc.get('fib618'):
            fibs.append(f"61.8 {_v1073_fmt_price(pc.get('fib618'))}")
        if fibs:
            parts.append('피보 ' + ' / '.join(fibs))
        if pc.get('stop_line'):
            parts.append(f"손절참고 {_v1073_fmt_price(pc.get('stop_line'))}")
        return ' / '.join(parts) if parts else '기준선 산출불가'
    except Exception:
        return '실행기준선 미확인 / 상단회복선 미확인 / 피보 확인 필요'


