def format_news_theme_for_telegram(analysis):
    """V1076: 뉴스 테마가 섹터 레이더와 충돌하면 추격 금지 문구를 강하게 붙인다."""
    try:
        txt = _V1076_BASE_NEWS_THEME_FORMAT(analysis) if _V1076_BASE_NEWS_THEME_FORMAT else str(analysis)
    except Exception:
        txt = str(analysis)
    try:
        oil_dir = globals().get('_V1073_LAST_OIL_DIRECTION', 'unknown')
        energy_avoid = _v1076_sector_avoid_has('정유/에너지')
        defense_avoid = _v1076_sector_avoid_has('방산')
        if oil_dir == 'up' and energy_avoid and any(k in txt for k in ['에너지', '원유', '유가', '정유']):
            txt = txt.replace('에너지 및 방산 관련 주식 상승 예상', '에너지/방산 이슈는 있으나 ETF·대표주 약세로 추격 금지')
            txt = txt.replace('에너지 관련 주식 및 자원 관련 주식의 상승 가능성', '유가 이슈는 있으나 에너지 ETF·대표주 약세로 추격 금지')
            txt = txt.replace('에너지 관련 주식 상승 기대', '에너지주는 ETF·대표주 동반 확인 전 추격 금지')
            warn = '⚠️ [시황충돌 보정] 유가는 상승했지만 정유·에너지 ETF/대표주가 약하면 단순 유가 상승만으로 추격하지 않습니다. 국내 관련주는 거래대금·수급 동반 종목만 단기 관찰합니다.'
            if warn not in txt:
                txt += '\n\n' + warn
        if defense_avoid and any(k in txt for k in ['방산', '전쟁', '중동', '지정학']):
            warn = '⚠️ [방산 보정] 지정학 뉴스가 있어도 방산 ETF/대표주가 약하면 추격보다 수급 동반 여부를 먼저 확인합니다.'
            if warn not in txt:
                txt += '\n\n' + warn
    except Exception:
        pass
    return txt


def _v1076_dedupe_theme_blocks(text: str) -> str:
    """[테마] 중복 블록 제거 + 약세 테마를 주의테마로 보정."""
    s = str(text or '')
    try:
        # 블록 단위 분리: [테마] 또는 [주의테마] 헤더부터 다음 헤더 전까지
        pattern = _v1071_re.compile(r'(\[(?:주의)?테마\]\s*([^\n]+)\n(?:.*?))(?=\n\[(?:주의)?테마\]|\Z)', _v1071_re.S)
        seen = set()
        out = []
        last_end = 0
        for m in pattern.finditer(s):
            out.append(s[last_end:m.start()])
            block = m.group(1)
            name = m.group(2).strip()
            key = name.replace(' ', '')
            if key in seen:
                # 중복 테마는 제거
                last_end = m.end()
                continue
            seen.add(key)
            if name == '반도체' and any(k in block for k in ['약세', '하락', '부진', 'SOXX -', 'SMH -']):
                block = block.replace('[테마] 반도체', '[주의테마] 반도체', 1)
                if '- 대응:' not in block:
                    block = block.rstrip() + '\n- 대응: 대장주도 신규 추격보다 눌림 확인'
            if name in ('고베타 성장주', '2차전지/EV') and any(k in block for k in ['약세', '하락', '부진']):
                block = block.replace('[테마]', '[주의테마]', 1)
            out.append(block)
            last_end = m.end()
        out.append(s[last_end:])
        s = ''.join(out)
    except Exception:
        pass
    return s


def format_us_mapping_for_telegram(*args, **kwargs):
    try:
        txt = _V1076_BASE_US_MAPPING_FORMAT(*args, **kwargs) if _V1076_BASE_US_MAPPING_FORMAT else ''
    except Exception as e:
        try:
            log_error(f'⚠️ V1076 미국→한국 테마 포맷 실패: {e}')
        except Exception:
            pass
        txt = ''
    return _v1076_dedupe_theme_blocks(txt)

