def _v1077_first_num(d: dict, *keys, default=0.0) -> float:
    try:
        return _v1071_num(_v1071_get(d, *keys, default=default), default)
    except Exception:
        return default


def _v1072_price_context(d: dict) -> dict:
    """V1077: 실행기준선 fallback 강화.
    기존 V1076에서 실행기준선이 계속 미확인으로 나오던 케이스를 보완한다.
    fallback 순서: 실행기준선/파란점선 → 파란점선기준가/blue_line_price → 기준가 → 5일선 → MA5.
    """
    try:
        pc = dict(_V1077_BASE_PRICE_CONTEXT(d)) if _V1077_BASE_PRICE_CONTEXT else {}
    except Exception:
        pc = {}
    try:
        price = _v1071_num(pc.get('price') or _v1071_get(d, '현재가','Close','종가','price', default=0), 0)
        exec_line = _v1071_num(pc.get('exec_line') or 0, 0)
        if exec_line <= 0:
            exec_line = _v1077_first_num(
                d,
                '실행기준선','파란점선','파란점선기준','파란점선기준가','blue_line','blue_line_price',
                '기준가','기준선','기준선가격','entry_line','action_line','base_line',
                default=0
            )
        ma5 = _v1071_num(pc.get('ma5') or 0, 0)
        if ma5 <= 0:
            ma5 = _v1077_first_num(d, 'MA5','ma5','5일선','MA_5','SMA5','ma_5', default=0)
        # 그래도 실행기준선이 없으면 5일선을 최소 실행 참고선으로 사용한다.
        if exec_line <= 0 and ma5 > 0:
            exec_line = ma5
        upper_line = _v1071_num(pc.get('upper_line') or 0, 0)
        if upper_line <= 0:
            upper_line = _v1077_first_num(d, '상단회복선','회복선','BB30시프트선','shift_line','bb30_shift', default=0)
        basis = exec_line or upper_line
        gap = 0.0
        if price > 0 and basis > 0:
            gap = (price / basis - 1.0) * 100.0
        if price <= 0 or basis <= 0:
            basis_state = '미확인'
        elif gap >= 5:
            basis_state = '위확장'
        elif gap >= 0:
            basis_state = '위안착'
        elif gap >= -2.5:
            basis_state = '접촉'
        else:
            basis_state = '아래'
        pc['price'] = price
        pc['exec_line'] = exec_line
        pc['blue'] = exec_line
        pc['ma5'] = ma5
        pc['upper_line'] = upper_line
        pc['basis'] = basis
        pc['basis_gap'] = gap
        pc['basis_state'] = basis_state
        # nearest/stop도 실행기준선 보강 후 재계산한다.
        fib382 = _v1071_num(pc.get('fib382') or 0, 0)
        fib50 = _v1071_num(pc.get('fib50') or 0, 0)
        fib618 = _v1071_num(pc.get('fib618') or 0, 0)
        supports = []
        for v in (basis, ma5, fib382, fib50, fib618):
            if price > 0 and v > 0 and v <= price * 1.015:
                supports.append(v)
        pc['nearest_support'] = max(supports) if supports else pc.get('nearest_support', 0)
        stop_candidates = []
        ma10 = _v1071_num(pc.get('ma10') or _v1071_get(d, 'MA10','ma10','10일선','MA_10','SMA10','ma_10', default=0), 0)
        if ma10 > 0: stop_candidates.append(ma10)
        if fib50 > 0: stop_candidates.append(fib50)
        if fib618 > 0: stop_candidates.append(fib618)
        if basis > 0: stop_candidates.append(basis * 0.97)
        if price > 0 and stop_candidates:
            below = [v for v in stop_candidates if 0 < v < price]
            pc['stop_line'] = max(below) if below else min(stop_candidates)
            if pc.get('stop_line'):
                pc['risk_pct'] = max(0.0, (price - pc.get('stop_line')) / price * 100.0)
    except Exception:
        pass
    return pc

# 기존 alias들이 새 price_context를 쓰도록 재연결
_v1071_price_context = _v1072_price_context
