def _v1072_final_decision(d: dict, supply: dict) -> dict:
    """V1077: 실전 후보 과대분류 방지.
    - 가짜수박 강은 무조건 신규진입 보류 우선
    - 가짜수박 중은 초록 금지
    - 상단회복선이 10% 이상 위에 있으면 분할진입보다 회복 확인/보류 쪽으로 보수화
    """
    try:
        dec = dict(_V1077_BASE_FINAL_DECISION(d, supply)) if _V1077_BASE_FINAL_DECISION else {}
    except Exception:
        dec = {}
    if not dec:
        dec = {'label': '🟡 눌림 확인 후 진입', 'mode': 'pullback', 'score': 0}
    try:
        pc = _v1072_price_context(d)
        price = _v1071_num(pc.get('price'), 0)
        upper = _v1071_num(pc.get('upper_line'), 0)
        prof = _v1076_fake_profile(d) if '_v1076_fake_profile' in globals() else {'severity':'none'}
        sev = prof.get('severity','none')
        upper_gap = 0.0
        if price > 0 and upper > 0:
            upper_gap = (price / upper - 1.0) * 100.0
        if sev == 'strong':
            dec['label'], dec['mode'] = '🔴 신규진입 보류', 'avoid'
        elif sev == 'medium' and (dec.get('mode') == 'partial_now' or '🟢' in str(dec.get('label',''))):
            dec['label'], dec['mode'] = '🟡 눌림 확인 후 진입', 'pullback'
        # 상단회복선이 매우 멀면 지금 분할 후보가 아니라 회복 확인 후보 성격.
        if upper > 0 and price > 0 and upper_gap <= -10.0 and dec.get('mode') in ('partial_now','small_partial','pullback'):
            dec['label'], dec['mode'] = '🟠 회복선 돌파 확인 후 진입', 'breakout_confirm'
            dec['upper_far_gap'] = upper_gap
        elif upper > 0 and price > 0 and upper_gap <= -5.0 and dec.get('mode') == 'partial_now':
            dec['label'], dec['mode'] = '🟡 눌림 확인 후 진입', 'pullback'
            dec['upper_far_gap'] = upper_gap
        dec['fake_severity'] = sev
        if prof.get('label'):
            dec['fake_label'] = prof.get('label')
    except Exception:
        pass
    return dec

_v1071_final_decision = _v1072_final_decision
_v1070_final_decision = _v1072_final_decision


def _v1077_ai_pick_enabled() -> bool:
    if _v1077_env_bool('DISABLE_AI_PICK', False):
        return False
    if not _v1077_env_bool('ENABLE_AI_PICK', True):
        return False
    try:
        if TEST_MODE and should_skip_ai() and not _v1077_env_bool('ENABLE_AI_PICK_IN_TEST', True):
            return False
    except Exception:
        pass
    try:
        if not OPENAI_API_KEY or OpenAI is None:
            return False
    except Exception:
        return False
    return True


def _v1077_code_name(row):
    d = _v1071_rowdict(row)
    name = _v1071_txt(_v1071_get(d, '종목명','Name','name', default=''), '')
    code = _v1071_txt(_v1071_get(d, 'code','Code','종목코드', default=''), '')
    if code and code.endswith('.0'):
        code = code[:-2]
    if code and code.isdigit():
        code = code.zfill(6)
    return code, name, d


def _v1077_ai_brief_for_row(row) -> dict:
    code, name, d = _v1077_code_name(row)
    try:
        supply = _v1072_supply_judgement(d)
    except Exception:
        supply = {'label':'미계산','tone':'unknown'}
    try:
        dec = _v1072_final_decision(d, supply)
    except Exception:
        dec = {'label':'미확인','mode':'unknown'}
    try:
        pc = _v1072_price_context(d)
    except Exception:
        pc = {}
    try:
        prof = _v1076_fake_profile(d) if '_v1076_fake_profile' in globals() else {'severity':'none','label':''}
    except Exception:
        prof = {'severity':'none','label':''}
    pattern = _v1071_txt(_v1071_get(d, '검색패턴','N구분','N조합','대표신호','신호', default=''), '')
    refine = _v1071_txt(_v1071_get(d, '수박정제태그','저항구름태그','역매공파BB40태그', default=''), '')
    wave = _v1071_txt(_v1071_get(d, '소파동', '중파동', '파동', 'wave_text', default=''), '')
    if not wave:
        try:
            wave = _v1071_clean_line(_wave_line_from_row(row), 120) if '_wave_line_from_row' in globals() else ''
        except Exception:
            wave = ''
    angle = _v1071_num(_v1071_get(d, '파동각도','wave_angle','angle', default=0), 0)
    absorb = _v1071_num(_v1071_get(d, '흡수','흡수점수','absorb','absorb_score', default=0), 0)
    fib_txt = ''
    try:
        fib_parts = []
        if pc.get('fib382'): fib_parts.append('38.2 '+_v1071_fmt_price(pc.get('fib382')))
        if pc.get('fib50'): fib_parts.append('50 '+_v1071_fmt_price(pc.get('fib50')))
        if pc.get('fib618'): fib_parts.append('61.8 '+_v1071_fmt_price(pc.get('fib618')))
        fib_txt = ' / '.join(fib_parts)
    except Exception:
        fib_txt = ''
    brief = {
        'code': code,
        'name': name,
        'current': _v1071_fmt_price(pc.get('price') or _v1071_get(d, '현재가','Close','종가', default=0)),
        'pattern': _v1071_clean_line(pattern, 90),
        'structure': _v1071_clean_line(refine, 90),
        'decision': _v1071_txt(dec.get('label',''), ''),
        'material': _v1071_clean_line(_v1072_material_reason(d) if '_v1072_material_reason' in globals() else _v1071_txt(_v1071_get(d, '재료','테마', default=''), ''), 100),
        'basis': {
            'exec': _v1071_fmt_price(pc.get('exec_line')) if pc.get('exec_line') else '미확인',
            'upper': _v1071_fmt_price(pc.get('upper_line')) if pc.get('upper_line') else '미확인',
            'state': pc.get('basis_state','미확인'),
            'gap': round(float(pc.get('basis_gap') or 0), 1),
        },
        'fib': fib_txt,
        'wave': _v1071_clean_line(wave, 120),
        'angle': round(float(angle), 1) if angle else 0,
        'absorb': round(float(absorb), 1) if absorb else 0,
        'supply': _v1071_clean_line(str(supply.get('label','미계산')), 80),
        'fake_risk': prof.get('label','') or '없음',
        'volume_context': '거래량응축' if '거래량응축' in str(prof.get('label','')) else ('가짜수박위험' if prof.get('severity') in ('medium','strong') else '일반'),
    }
    return brief


def _v1077_prepare_ai_candidates(df, limit=15) -> list:
    if df is None or not hasattr(df, 'empty') or df.empty:
        return []
    rows = []
    try:
        view = df.head(limit).copy()
    except Exception:
        view = df
    try:
        iterator = view.iterrows()
    except Exception:
        return []
    for _, row in iterator:
        try:
            b = _v1077_ai_brief_for_row(row)
            if b.get('name') or b.get('code'):
                rows.append(b)
        except Exception:
            continue
    return rows


def _v1077_parse_ai_pick_response(text: str, candidates: list) -> tuple:
    picks, reasons = set(), {}
    if not text:
        return picks, reasons
    try:
        s = str(text).strip()
        m = _v1071_re.search(r'\{.*\}', s, _v1071_re.S)
        if m:
            s = m.group(0)
        data = json.loads(s)
        arr = data.get('picks', data if isinstance(data, list) else [])
        cand_by_code = {str(c.get('code','')).zfill(6): c for c in candidates if str(c.get('code','')).strip()}
        cand_by_name = {str(c.get('name','')).strip(): c for c in candidates if str(c.get('name','')).strip()}
        for item in arr:
            if not isinstance(item, dict):
                continue
            code = str(item.get('code','')).strip()
            name = str(item.get('name','')).strip()
            if code.endswith('.0'):
                code = code[:-2]
            if code.isdigit():
                code = code.zfill(6)
            key_code = code if code in cand_by_code else ''
            key_name = name if name in cand_by_name else ''
            if key_code:
                picks.add(key_code)
                reasons[key_code] = _v1071_clean_line(item.get('reason','AI 관점 우선 후보'), 42)
            if key_name:
                picks.add(key_name)
                reasons[key_name] = _v1071_clean_line(item.get('reason','AI 관점 우선 후보'), 42)
    except Exception:
        pass
    return picks, reasons


def _v1077_ai_pick_batch(df, limit=15) -> tuple:
    """TOP15를 1회 AI 호출로 평가한다. 실패하면 빈 set을 반환해 기존 출력 유지."""
    global _V1077_LAST_AI_PICK_SET, _V1077_LAST_AI_PICK_REASON
    candidates = _v1077_prepare_ai_candidates(df, limit=limit)
    key = tuple((c.get('code'), c.get('name'), c.get('current'), c.get('decision')) for c in candidates)
    if key in _V1077_AI_PICK_CACHE:
        picks, reasons = _V1077_AI_PICK_CACHE[key]
        _V1077_LAST_AI_PICK_SET, _V1077_LAST_AI_PICK_REASON = picks, reasons
        return picks, reasons
    picks, reasons = set(), {}
    if not candidates or not _v1077_ai_pick_enabled():
        _V1077_AI_PICK_CACHE[key] = (picks, reasons)
        _V1077_LAST_AI_PICK_SET, _V1077_LAST_AI_PICK_REASON = picks, reasons
        return picks, reasons
    try:
        max_pick = int(os.environ.get('AI_PICK_MAX', '4') or '4')
    except Exception:
        max_pick = 4
    max_pick = max(1, min(max_pick, 5))
    model = os.environ.get('AI_PICK_MODEL', 'gpt-4o-mini')
    system_prompt = (
        '너는 한국 주식 단기/스윙 후보를 구조적으로 고르는 보조 AI다. '
        '내부 점수는 보지 않고 패턴, 현재가 위치, 기준선, 피보, 파동, 수급, 재료, 위험만 보고 판단한다. '
        '신규진입 보류, 가짜수박 강, 기준선/상단회복선 큰 이탈, 수급 미계산+위험이 큰 종목은 원칙적으로 고르지 않는다. '
        '무조건 고르지 말고, 좋아 보이는 종목이 적으면 적게 골라라. 매수 추천이 아니라 관찰 우선 후보 표시다.'
    )
    user_prompt = {
        'task': f'TOP15 후보 중 AI 관점에서 상대적으로 구조가 좋은 종목 최대 {max_pick}개를 골라라. 점수는 제공하지 않는다.',
        'output_format': {'picks': [{'code':'종목코드', 'name':'종목명', 'reason':'20자 안팎의 짧은 이유'}]},
        'candidates': candidates,
    }
    try:
        client = OpenAI(api_key=OPENAI_API_KEY, timeout=25)
        res = client.chat.completions.create(
            model=model,
            messages=[
                {'role':'system','content':system_prompt},
                {'role':'user','content':json.dumps(user_prompt, ensure_ascii=False)},
            ],
            temperature=0.15,
            max_tokens=500,
            response_format={'type':'json_object'},
        )
        text = res.choices[0].message.content.strip()
        picks, reasons = _v1077_parse_ai_pick_response(text, candidates)
        # 최대 개수 제한
        if len(picks) > max_pick * 2:  # code/name가 같이 들어가므로 2배까지 허용
            limited = set()
            for c in candidates:
                if c.get('code') in picks or c.get('name') in picks:
                    limited.add(c.get('code'))
                    limited.add(c.get('name'))
                if len(limited) >= max_pick * 2:
                    break
            picks = {x for x in limited if x}
        try:
            log_info(f"🤖 V1077 AI Pick 완료: {len(picks)}개 키")
        except Exception:
            pass
    except Exception as e:
        try:
            log_error(f"⚠️ V1077 AI Pick 실패: {e}")
        except Exception:
            pass
        picks, reasons = set(), {}
    _V1077_AI_PICK_CACHE[key] = (picks, reasons)
    _V1077_LAST_AI_PICK_SET, _V1077_LAST_AI_PICK_REASON = picks, reasons
    return picks, reasons


def _v1077_mark_ai_pick_in_block(msg: str, picks: set, reasons: dict) -> str:
    if not msg or not picks:
        return msg
    s = str(msg)
    # 각 종목 헤더 라인에만 표시한다.
    for key in sorted([x for x in picks if x], key=len, reverse=True):
        try:
            reason = reasons.get(key, '')
            tag = ' 🤖 AI Pick'
            if reason:
                tag += f'({reason})'
            # code key: 종목명(000000) 형태의 헤더를 잡는다.
            if str(key).isdigit() or len(str(key)) >= 5:
                pat = r'(?m)^(\d+\)\s+[^\n\(]+\(' + _v1071_re.escape(str(key)) + r'\))(?=\s*\|)'
                s = _v1071_re.sub(lambda m: m.group(1) + ('' if 'AI Pick' in m.group(1) else tag), pat, s, count=1)
            else:
                # name key fallback
                pat = r'(?m)^(\d+\)\s+' + _v1071_re.escape(str(key)) + r'(\([^\n\)]*\))?)(?=\s*\|)'
                s = _v1071_re.sub(lambda m: m.group(1) + ('' if 'AI Pick' in m.group(1) else tag), pat, s, count=1)
        except Exception:
            continue
    return s


