_V1078_LAST_AI_PICK_REASON = {}
_V1078_LAST_AI_PICK_SUMMARY = ''


def _v1078_tier_label(tier: str) -> str:
    tier = str(tier or '').lower()
    if tier in ('strong', 'pick', 'ai_pick'):
        return '🤖 AI Pick'
    if tier in ('watch', 'observe', 'candidate'):
        return '🤖 AI 관찰 Pick'
    if tier in ('conservative', 'cautious', '보수'):
        return '🤖 보수적 AI Pick'
    return '🤖 AI 관찰 Pick'


def _v1078_normalize_code(code) -> str:
    s = str(code or '').strip()
    if s.endswith('.0'):
        s = s[:-2]
    if s.isdigit():
        s = s.zfill(6)
    return s


def _v1078_add_pick_item(item, tier: str, candidates: list, tier_map: dict, reasons: dict):
    if not isinstance(item, dict):
        return
    code = _v1078_normalize_code(item.get('code',''))
    name = str(item.get('name','')).strip()
    reason = _v1071_clean_line(item.get('reason','AI 관점 관찰 후보'), 38) if '_v1071_clean_line' in globals() else str(item.get('reason','AI 관점 관찰 후보'))[:38]
    cand_by_code = {_v1078_normalize_code(c.get('code')): c for c in candidates if _v1078_normalize_code(c.get('code'))}
    cand_by_name = {str(c.get('name','')).strip(): c for c in candidates if str(c.get('name','')).strip()}
    real_code = code if code in cand_by_code else ''
    real_name = name if name in cand_by_name else ''
    # 신규진입 보류/강위험은 strong으로 두지 않고 conservative로 낮춘다.
    c = cand_by_code.get(real_code) or cand_by_name.get(real_name) or {}
    dec = str(c.get('decision',''))
    fake = str(c.get('fake_risk',''))
    if tier == 'strong' and ('신규진입 보류' in dec or '강:' in fake or '강위험' in fake):
        tier = 'conservative'
        if not reason or reason == 'AI 관점 관찰 후보':
            reason = '위험 확인 필요'
    for k in (real_code, real_name):
        if k:
            tier_map[k] = tier
            reasons[k] = reason


def _v1078_candidate_score(c: dict) -> float:
    s = 0.0
    dec = str(c.get('decision',''))
    supply = str(c.get('supply',''))
    fake = str(c.get('fake_risk',''))
    basis = c.get('basis') or {}
    basis_state = str(basis.get('state',''))
    gap = 0.0
    try:
        gap = float(basis.get('gap') or 0)
    except Exception:
        gap = 0.0
    pat = str(c.get('pattern','')) + ' ' + str(c.get('structure','')) + ' ' + str(c.get('volume_context',''))
    angle = 0.0
    try:
        angle = float(c.get('angle') or 0)
    except Exception:
        angle = 0.0
    absorb = 0.0
    try:
        absorb = float(c.get('absorb') or 0)
    except Exception:
        absorb = 0.0
    if '신규진입 보류' in dec:
        s -= 5
    if '강:' in fake or '강위험' in fake:
        s -= 5
    if '중:' in fake or '중간위험' in fake:
        s -= 1.5
    if '🟢' in dec:
        s += 3
    elif '소액' in dec:
        s += 2
    elif '눌림' in dec:
        s += 1.5
    elif '회복선' in dec or '회복' in dec:
        s += 0.5
    if any(k in supply for k in ['쌍끌강','쌍끌','외인강','기관강']):
        s += 2
    elif any(k in supply for k in ['외인우세','기관우세']):
        s += 1
    elif '수급미계산' in supply or '미계산' in supply:
        s -= 1.2
    elif '수급부담' in supply:
        s -= 2
    if basis_state in ('위안착','접촉'):
        s += 1.2
    elif basis_state == '위확장':
        s += 0.3
    elif basis_state == '아래':
        s -= 1.5
    if -1.5 <= gap <= 4.0:
        s += 0.8
    if any(k in pat for k in ['BB40 응축','BB40 수렴','정제수박','관찰수박','5일재안착','돌반지','독사']):
        s += 1
    if '거래량응축' in pat:
        s += 0.8
    if 5 <= angle <= 30:
        s += 0.8
    elif angle >= 45:
        s -= 0.8
    if absorb > 0:
        s += 0.5
    return s


def _v1078_fallback_watch_picks(candidates: list, max_watch: int = 3) -> tuple:
    """AI가 강한 Pick을 비웠을 때, 위험 종목을 제외하고 관찰 Pick 후보를 만든다."""
    scored = []
    for c in candidates or []:
        dec = str(c.get('decision',''))
        fake = str(c.get('fake_risk',''))
        if '신규진입 보류' in dec or '강:' in fake or '강위험' in fake:
            continue
        sc = _v1078_candidate_score(c)
        if sc >= 2.2:
            scored.append((sc, c))
    scored.sort(key=lambda x: x[0], reverse=True)
    tier_map, reasons = {}, {}
    for sc, c in scored[:max(1, max_watch)]:
        code = _v1078_normalize_code(c.get('code'))
        name = str(c.get('name','')).strip()
        reason = '강한 확신 전 관찰 우선'
        dec = str(c.get('decision',''))
        supply = str(c.get('supply',''))
        fake = str(c.get('fake_risk',''))
        if '🟢' in dec and any(k in supply for k in ['쌍끌','외인강','기관강']):
            reason = '수급·기준선 양호'
            tier = 'watch'  # 강한 매수표시보다 관찰 Pick으로 안전하게 표기
        elif '눌림' in dec:
            reason = '눌림 재지지형'
            tier = 'watch'
        elif '소액' in dec:
            reason = '소액 확인형'
            tier = 'watch'
        elif '중:' in fake:
            reason = '위험 낮춘 관찰형'
            tier = 'conservative'
        else:
            tier = 'watch'
        for k in (code, name):
            if k:
                tier_map[k] = tier
                reasons[k] = reason
    return tier_map, reasons


def _v1078_parse_ai_tier_response(text: str, candidates: list) -> tuple:
    tier_map, reasons, summary = {}, {}, ''
    if not text:
        return tier_map, reasons, summary
    try:
        s = str(text).strip()
        m = _v1071_re.search(r'\{.*\}', s, _v1071_re.S)
        if m:
            s = m.group(0)
        data = json.loads(s)
        if isinstance(data, list):
            data = {'strong': data}
        summary = _v1071_clean_line(data.get('summary',''), 90) if isinstance(data, dict) else ''
        # 호환: picks는 strong으로 취급
        for item in (data.get('strong') or data.get('picks') or []):
            _v1078_add_pick_item(item, 'strong', candidates, tier_map, reasons)
        for item in (data.get('watch') or data.get('observe') or data.get('candidates') or []):
            _v1078_add_pick_item(item, 'watch', candidates, tier_map, reasons)
        for item in (data.get('conservative') or data.get('cautious') or []):
            _v1078_add_pick_item(item, 'conservative', candidates, tier_map, reasons)
    except Exception:
        pass
    return tier_map, reasons, summary


def _v1078_ai_pick_batch(df, limit=15) -> tuple:
    """V1078: 강한 Pick/관찰 Pick/보수적 Pick 3단계. 강한 Pick이 없어도 관찰 Pick을 표시한다."""
    global _V1078_LAST_AI_PICK_TIER, _V1078_LAST_AI_PICK_REASON, _V1078_LAST_AI_PICK_SUMMARY
    try:
        candidates = _v1077_prepare_ai_candidates(df, limit=limit)
    except Exception:
        candidates = []
    key = tuple((c.get('code'), c.get('name'), c.get('current'), c.get('decision'), c.get('fake_risk')) for c in candidates)
    if key in _V1078_AI_PICK_CACHE:
        tier_map, reasons, summary = _V1078_AI_PICK_CACHE[key]
        _V1078_LAST_AI_PICK_TIER, _V1078_LAST_AI_PICK_REASON, _V1078_LAST_AI_PICK_SUMMARY = tier_map, reasons, summary
        return set(tier_map.keys()), reasons, tier_map, summary
    tier_map, reasons, summary = {}, {}, ''
    if candidates and _v1077_ai_pick_enabled():
        try:
            max_strong = int(os.environ.get('AI_PICK_MAX', '3') or '3')
        except Exception:
            max_strong = 3
        max_strong = max(0, min(max_strong, 4))
        try:
            max_watch = int(os.environ.get('AI_WATCH_PICK_MAX', '3') or '3')
        except Exception:
            max_watch = 3
        max_watch = max(1, min(max_watch, 5))
        model = os.environ.get('AI_PICK_MODEL', 'gpt-4o-mini')
        system_prompt = (
            '너는 한국 주식 단기/스윙 후보를 구조적으로 고르는 보조 AI다. '
            '점수는 보지 않고 패턴, 현재가 위치, 실행기준선, 상단회복선, 피보, 파동, 흡수, 각도, 수급, 재료, 위험만 본다. '
            '매수 추천이 아니라 관찰 우선순위 표시다. '
            '강한 확신 후보가 없으면 strong은 비워도 되지만, 신규진입 보류와 가짜수박 강을 제외한 관찰 후보가 있으면 watch에 1~3개를 고른다. '
            '가짜수박 강, 신규진입 보류, 기준선 큰 이탈 종목은 strong 금지다.'
        )
        user_prompt = {
            'task': 'TOP15 후보를 AI 관점으로 3단계 분류하라. strong은 확신 후보, watch는 관찰 우선 후보, conservative는 보수적 관찰 후보이다.',
            'rules': [
                f'strong은 최대 {max_strong}개, 조건이 부족하면 0개 가능',
                f'watch는 strong이 없더라도 가능하면 1~{max_watch}개 선택',
                '신규진입 보류/가짜수박 강은 strong 금지',
                'reason은 20자 안팎으로 짧게 작성',
            ],
            'output_format': {
                'strong': [{'code':'종목코드','name':'종목명','reason':'짧은 이유'}],
                'watch': [{'code':'종목코드','name':'종목명','reason':'짧은 이유'}],
                'conservative': [{'code':'종목코드','name':'종목명','reason':'짧은 이유'}],
                'summary': '강한 확신 후보 없음/있음 요약',
            },
            'candidates': candidates,
        }
        try:
            client = OpenAI(api_key=OPENAI_API_KEY, timeout=25)
            res = client.chat.completions.create(
                model=model,
                messages=[
                    {'role':'system','content':system_prompt},
                    {'role':'user','content':json.dumps(user_prompt, ensure_ascii=False)},
                ],
                temperature=0.12,
                max_tokens=700,
                response_format={'type':'json_object'},
            )
            text = res.choices[0].message.content.strip()
            tier_map, reasons, summary = _v1078_parse_ai_tier_response(text, candidates)
        except Exception as e:
            try:
                log_error(f'⚠️ V1078 AI Pick 실패: {e}')
            except Exception:
                pass
            tier_map, reasons, summary = {}, {}, ''
        # AI가 비워두면 관찰 Pick fallback. 단, 강한 Pick이 아니라 관찰 Pick으로만 표시한다.
        if not tier_map:
            tier_map, reasons = _v1078_fallback_watch_picks(candidates, max_watch=max_watch if 'max_watch' in locals() else 3)
            if tier_map:
                summary = '강한 확신 Pick 없음, 관찰 우선 후보만 표시'
            else:
                summary = '강한 확신 Pick 없음'
    _V1078_AI_PICK_CACHE[key] = (tier_map, reasons, summary)
    _V1078_LAST_AI_PICK_TIER, _V1078_LAST_AI_PICK_REASON, _V1078_LAST_AI_PICK_SUMMARY = tier_map, reasons, summary
    return set(tier_map.keys()), reasons, tier_map, summary


def _v1078_mark_ai_pick_in_block(msg: str, tier_map: dict, reasons: dict) -> str:
    if not msg or not tier_map:
        return msg
    s = str(msg)
    # code와 name이 동시에 들어오므로 긴 key부터 처리하되 이미 Pick 태그가 붙은 라인은 중복 방지
    for key in sorted([x for x in tier_map if x], key=len, reverse=True):
        try:
            tier = tier_map.get(key, 'watch')
            reason = reasons.get(key, '')
            tag = ' ' + _v1078_tier_label(tier)
            if reason:
                tag += f'({reason})'
            def add_tag(m):
                line = m.group(1)
                if 'AI Pick' in line:
                    return line
                return line + tag
            if str(key).isdigit() or len(str(key)) >= 5:
                pat = r'(?m)^(\d+\)\s+[^\n\(]+\(' + _v1071_re.escape(str(key)) + r'\))(?=\s*\|)'
                s = _v1071_re.sub(add_tag, pat, s, count=1)
            else:
                pat = r'(?m)^(\d+\)\s+' + _v1071_re.escape(str(key)) + r'(\([^\n\)]*\))?)(?=\s*\|)'
                s = _v1071_re.sub(add_tag, pat, s, count=1)
        except Exception:
            continue
    return s


def _v1078_ai_pick_header(tier_map: dict, summary: str) -> str:
    if not tier_map:
        return 'AI Pick 기준: 강한 확신 후보 없음'
    strong_names, watch_names, cons_names = [], [], []
    # 이름 key만 모아 중복을 줄인다.
    try:
        for k, t in tier_map.items():
            if str(k).isdigit():
                continue
            if t == 'strong':
                strong_names.append(k)
            elif t == 'conservative':
                cons_names.append(k)
            else:
                watch_names.append(k)
    except Exception:
        pass
    def uniq(xs):
        out = []
        for x in xs:
            if x and x not in out:
                out.append(x)
        return out[:4]
    strong_names, watch_names, cons_names = uniq(strong_names), uniq(watch_names), uniq(cons_names)
    parts = []
    if strong_names:
        parts.append('AI Pick ' + ', '.join(strong_names))
    else:
        parts.append('강한 확신 Pick 없음')
    if watch_names:
        parts.append('AI 관찰 Pick ' + ', '.join(watch_names))
    if cons_names:
        parts.append('보수적 Pick ' + ', '.join(cons_names))
    return 'AI Pick 기준: ' + ' / '.join(parts)


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    try:
        _pick_keys, reasons, tier_map, summary = _v1078_ai_pick_batch(df, limit=limit)
    except Exception:
        reasons, tier_map, summary = {}, {}, ''
    try:
        msg = _V1078_BASE_TOP15_BLOCK(df, limit=limit, title=title) if _V1078_BASE_TOP15_BLOCK else ''
        msg = str(msg or '')
        for old in [
            'V1077: AI Pick 배치판정 / 거래량응축·가짜수박 약중강 / 강위험 실전후보 제외',
            'V1076: 거래량응축 분리 / 가짜수박 약중강 / 중강은 🟢 제한',
            'V1075: 실전후보 섹션분리 / 가짜수박주의 이유 표시 / 신규진입 보류 분리',
        ]:
            msg = msg.replace(old, 'V1078: AI Pick 등급화 / 강한 Pick 없음→관찰 Pick 표시 / 뉴스 보수화')
        msg = _v1078_mark_ai_pick_in_block(msg, tier_map, reasons)
        common = '진입 공통조건: 5일선·실행기준선 위 양봉 마감 + 거래량 전일比 1.3배↑ 또는 5일평균比 1.2배↑'
        if 'AI Pick 기준:' not in msg and common in msg:
            msg = msg.replace(common, common + '\n' + _v1078_ai_pick_header(tier_map, summary))
        return msg
    except Exception as e:
        try:
            log_error(f'⚠️ V1078 TOP15 생성 실패: {e}')
        except Exception:
            pass
        return ''


def _v1073_compact_today_block(base: str, row_map: dict) -> str:
    try:
        msg = _V1078_BASE_TODAY_BLOCK(base, row_map) if _V1078_BASE_TODAY_BLOCK else str(base or '')
    except Exception:
        msg = str(base or '')
    try:
        old = '📌 V1076: 거래량응축은 양호 신호로 분리, 가짜수박 중/강은 🟢 판정 제한'
        new = '📌 V1078: AI Pick 등급화 + 거래량응축/가짜수박 강도 + 실행기준선 보정'
        if old in msg:
            msg = msg.replace(old, new)
        elif '📌 V1078:' not in msg:
            anchor = '📌 원칙: 🔴 신규진입 보류 종목은 실전 후보가 아니라 리스크 참고로 분리합니다.'
            if anchor in msg:
                msg = msg.replace(anchor, anchor + '\n' + new)
    except Exception:
        pass
    return msg


def _v1078_conservative_news_text(txt: str) -> str:
    s = str(txt or '')
    try:
        # 에너지/정유 관련 공격적 원문을 보수적으로 치환
        s = _v1071_re.sub(
            r'- 해석: ([^\n]*(?:에너지|정유|석유|유가)[^\n]*)(?:긍정적인 영향을 미칠 것으로 예상됨|상승 예상|상승 기대|상승 가능성)',
            '- 해석: 유가/석유 이슈는 관심 재료이나 ETF·대표주 동반 확인 전 정유·에너지주는 추격 금지입니다.',
            s
        )
        s = _v1071_re.sub(
            r'SK이노베이션의 주가\s*10%\s*이상\s*상승\s*시\s*매수\s*검토\.?',
            '정유·에너지 ETF/대표주와 국내 거래대금·수급 동반 확인 전 추격 금지.',
            s
        )
        s = s.replace('매수 검토.', '거래대금·수급 동반 확인.')
        s = s.replace('매수 검토', '거래대금·수급 동반 확인')
        # 방산도 회피 섹터일 때 공격적 문구 완화
        if _v1076_sector_avoid_has('방산') if '_v1076_sector_avoid_has' in globals() else False:
            s = s.replace('방산 관련 주식 상승 예상', '방산 이슈는 있으나 ETF·대표주 동반 확인 전 추격 금지')
            s = s.replace('방산 관련 정부 정책 발표 여부', '방산 ETF·대표주 수급 동반 여부')
    except Exception:
        pass
    return s


