def _v1080_env_on(name: str, default: str = '0') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return str(default).strip().lower() in ('1', 'true', 'yes', 'y', 'on')


def _v1080_env_int(name: str, default: int) -> int:
    try:
        return int(float(str(os.environ.get(name, str(default))).strip()))
    except Exception:
        return int(default)


def _v1080_env_float(name: str, default: float) -> float:
    try:
        return float(str(os.environ.get(name, str(default))).strip())
    except Exception:
        return float(default)




def _v1080_backtest_output_mode() -> str:
    """성과검증 결과 출력 방식: FILE / TELEGRAM / BOTH.
    - FILE: reports/*.txt, *.csv 파일 저장만
    - TELEGRAM: 텔레그램 전송만
    - BOTH: 파일 저장 + 텔레그램 전송
    """
    try:
        mode = str(os.environ.get('V1080_BACKTEST_OUTPUT_MODE', 'BOTH')).strip().upper()
        aliases = {
            'FILES': 'FILE',
            'ARTIFACT': 'FILE',
            'ARTIFACTS': 'FILE',
            'TG': 'TELEGRAM',
            'TELE': 'TELEGRAM',
            'TEL': 'TELEGRAM',
            'ALL': 'BOTH',
        }
        mode = aliases.get(mode, mode)
        if mode in ('FILE', 'TELEGRAM', 'BOTH'):
            return mode
    except Exception:
        pass
    return 'BOTH'


def _v1080_should_save_backtest_file() -> bool:
    mode = _v1080_backtest_output_mode()
    if mode == 'FILE':
        return True
    if mode == 'TELEGRAM':
        return False
    if mode == 'BOTH':
        return True
    return _v1080_env_on('V1080_BACKTEST_SAVE_FILE', '1')


def _v1080_should_send_backtest_telegram() -> bool:
    mode = _v1080_backtest_output_mode()
    if mode == 'FILE':
        return False
    if mode == 'TELEGRAM':
        return True
    if mode == 'BOTH':
        return True
    return _v1080_env_on('V1080_BACKTEST_SEND_TELEGRAM', '1')

def _v1080_s(v, default: str = '') -> str:
    try:
        if v is None:
            return default
        try:
            if pd.isna(v):
                return default
        except Exception:
            pass
        s = str(v).strip()
        if s.lower() in ('nan', 'none', 'nat'):
            return default
        return s
    except Exception:
        return default


def _v1080_num(v, default: float = 0.0) -> float:
    try:
        if v is None:
            return default
        if isinstance(v, str):
            v = v.replace(',', '').replace('%', '').replace('원', '').replace('억', '').strip()
            if not v or v.lower() in ('nan', 'none'):
                return default
        out = float(v)
        try:
            if pd.isna(out):
                return default
        except Exception:
            pass
        return out
    except Exception:
        return default


def _v1080_norm_code(v) -> str:
    try:
        if '_v1050_norm_code' in globals():
            return _v1050_norm_code(v)
    except Exception:
        pass
    try:
        s = str(v or '').strip()
        if s.endswith('.0'):
            s = s[:-2]
        s = re.sub(r'[^0-9A-Za-z]', '', s)
        if re.fullmatch(r'\d{1,6}', s):
            return s.zfill(6)
        return s
    except Exception:
        return ''


def _v1080_first(row, keys, default=''):
    for k in keys:
        try:
            if hasattr(row, 'get'):
                v = row.get(k, '')
            else:
                v = row[k]
            sv = _v1080_s(v, '')
            if sv:
                return sv
        except Exception:
            pass
    return default


def _v1080_infer_volume_state(row) -> str:
    raw = ' '.join(_v1080_s(_v1080_first(row, [k], '')) for k in [
        '거래량상태', '거래량판정', '거래량응축상태', '볼륨상태', '거래량분류', 'N구분', '검색패턴', '최종판정', '매매판정'
    ])
    if '거래량실패' in raw or '거래량 실패' in raw:
        return '거래량실패(위험)'
    if '거래량부족' in raw or '거래량 부족' in raw:
        return '거래량부족(주의)'
    if '거래량응축' in raw or '거래량 응축' in raw or '응축(양호)' in raw:
        return '거래량응축(양호)'
    try:
        vol_ratio = _v1080_num(_v1080_first(row, ['거래량배율', '거래량비율', 'VolumeRatio', 'VolRatio', '매집거래량배율'], 0), 0)
        if vol_ratio >= 1.3:
            return '거래량유입(확인)'
        if 0 < vol_ratio < 0.7:
            return '거래량부족(주의)'
    except Exception:
        pass
    return '미분류'


def _v1080_infer_fake_severity(row) -> str:
    raw = ' '.join(_v1080_s(_v1080_first(row, [k], '')) for k in [
        '가짜수박강도', '가짜수박', 'fake_severity', 'fake_label', '수박정제태그', '정제', 'N구분', '최종판정', '매매판정'
    ])
    if any(k in raw for k in ['가짜수박 강', '가짜수박강', '강위험', '강(위험)', 'strong']):
        return '가짜수박 강'
    if any(k in raw for k in ['가짜수박 중', '가짜수박중', '중주의', '중(주의)', 'medium']):
        return '가짜수박 중'
    if any(k in raw for k in ['가짜수박 약', '가짜수박약', '약주의', '약(주의)', 'weak']):
        return '가짜수박 약'
    if '가짜수박' in raw:
        return '가짜수박 미세분류'
    return '해당없음'


def _v1080_ai_tier_from_globals(code: str, name: str) -> tuple:
    try:
        tier_map = globals().get('_V1078_LAST_AI_PICK_TIER', {}) or {}
        reasons = globals().get('_V1078_LAST_AI_PICK_REASON', {}) or {}
        tier = tier_map.get(code) or tier_map.get(name) or ''
        reason = reasons.get(code) or reasons.get(name) or ''
        if tier and '_v1078_tier_label' in globals():
            label = _v1078_tier_label(tier)
        elif tier == 'strong':
            label = '🤖 AI Pick'
        elif tier == 'watch':
            label = '🤖 AI 관찰 Pick'
        elif tier == 'conservative':
            label = '🛡 보수적 AI Pick'
        else:
            label = 'AI Pick 없음'
        return label, _v1080_s(reason, '')
    except Exception:
        return 'AI Pick 없음', ''


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    try:
        name = _v1080_first(row, ['종목명', 'Name', 'name', '종목'], '')
        code = _v1080_norm_code(_v1080_first(row, ['code', 'Code', '종목코드', '티커'], ''))
        price = _v1080_num(_v1080_first(row, ['현재가', 'Close', '종가', 'price'], 0), 0)
        ai_label, ai_reason = _v1080_ai_tier_from_globals(code, name)
        # 최종판정은 dict 함수가 있으면 다시 계산하지 않고 기존 문자열 중심으로 보존한다.
        final_decision = _v1080_first(row, ['최종판정', '매매판정', '추천단계', '유형'], '')
        decision_mode = _v1080_first(row, ['decision_mode', 'mode', '진입모드'], '')
        upper_gap = _v1080_num(_v1080_first(row, ['상단회복선이격', '상단회복선거리', 'upper_far_gap', 'upper_gap'], 0), 0)
        return {
            'signal_date': _v1080_s(globals().get('TODAY_STR', ''), datetime.now().strftime('%Y-%m-%d')),
            'recorded_at': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            'source': source,
            'rank': int(rank or 0),
            'code': code,
            'name': name,
            'entry_price': round(price, 4),
            'phase': _v1080_first(row, ['추천단계', '유형', '단계상태'], ''),
            'strategy': _v1080_first(row, ['N조합', '검색패턴', '수박최종상태', 'N구분'], ''),
            'pattern': _v1080_first(row, ['검색패턴', '저항구름태그', '수박정제태그'], ''),
            'final_decision': final_decision,
            'decision_mode': decision_mode,
            'ai_pick_tier': ai_label,
            'ai_pick_reason': ai_reason,
            'volume_state': _v1080_infer_volume_state(row),
            'fake_severity': _v1080_infer_fake_severity(row),
            'upper_recovery_gap_pct': round(upper_gap, 3),
            'rsi': round(_v1080_num(_v1080_first(row, ['RSI', 'rsi'], 0), 0), 3),
            'disparity': round(_v1080_num(_v1080_first(row, ['이격', 'Disparity', 'disparity'], 0), 0), 3),
            'bb40': round(_v1080_num(_v1080_first(row, ['BB40', 'bb40'], 0), 0), 3),
            'obv_slope': round(_v1080_num(_v1080_first(row, ['OBV기울기', 'OBV_Slope', 'obv_slope'], 0), 0), 3),
            'safe_score': round(_v1080_num(_v1080_first(row, ['안전점수', 'safe_score'], 0), 0), 3),
            'n_score': round(_v1080_num(_v1080_first(row, ['N점수', 'n_score'], 0), 0), 3),
        }
    except Exception:
        return {}


def _v1080_record_signal_df(df, source: str = 'TOP15', limit: int = 15) -> str:
    """오늘 출력된 후보를 CSV에 누적 저장한다. GitHub Actions에서는 artifacts/upload 또는 Google Sheet와 함께 쓰는 것을 권장."""
    if not _v1080_env_on('V1080_RECORD_TOP15_SIGNALS', '1'):
        return ''
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return ''
        lim = max(1, int(limit or _v1080_env_int('TOP15_COMPACT_LIMIT', 15)))
        out = df.copy()
        if '_v1050_sort_df_for_top15' in globals():
            out = _v1050_sort_df_for_top15(out)
        out = out.head(lim).reset_index(drop=True)
        rows = []
        for i, (_, row) in enumerate(out.iterrows(), start=1):
            r = _v1080_signal_row_from_series(row, rank=i, source=source)
            if r.get('code') and r.get('name') and r.get('entry_price', 0) > 0:
                rows.append(r)
        if not rows:
            return ''
        save_path = Path(os.environ.get('V1080_SIGNAL_CSV', 'reports/v1080_stockhunter_signals.csv'))
        save_path.parent.mkdir(parents=True, exist_ok=True)
        new_df = pd.DataFrame(rows)
        if save_path.exists():
            old_df = pd.read_csv(save_path, dtype={'code': str})
            all_df = pd.concat([old_df, new_df], ignore_index=True, sort=False)
        else:
            all_df = new_df
        # 같은 날짜/소스/코드는 최신 1개만 유지한다. 순위 변화는 최신 실행 기준으로 본다.
        all_df['code'] = all_df['code'].map(_v1080_norm_code)
        all_df = all_df.drop_duplicates(subset=['signal_date', 'source', 'code'], keep='last')
        all_df = all_df.sort_values(by=['signal_date', 'source', 'rank'], ascending=[True, True, True])
        all_df.to_csv(save_path, index=False, encoding='utf-8-sig')
        try:
            log_info(f'✅ V1080: {source} 신호 {len(rows)}개 저장 완료 → {save_path}')
        except Exception:
            pass
        return str(save_path)
    except Exception as e:
        try:
            log_error(f'⚠️ V1080 신호 저장 실패: {e}')
        except Exception:
            pass
        return ''


try:
    _V1080_BASE_SEND_FORCED_TOP15 = _v1050_send_forced_top15
except Exception:
    _V1080_BASE_SEND_FORCED_TOP15 = None


def _v1050_send_forced_top15(primary_df=None, fallback_frames=None, limit=None) -> bool:
    """V1080 wrapper: 기존 TOP15 전송은 그대로 유지하고, 전송 후보를 성과검증용 CSV에 누적 저장한다."""
    lim = int(limit or _v1050_env_int('TOP15_COMPACT_LIMIT', 15)) if '_v1050_env_int' in globals() else int(limit or 15)
    selected_df = pd.DataFrame()
    try:
        if '_v1050_build_from_fallback_frames' in globals():
            selected_df = _v1050_build_from_fallback_frames(primary_df, fallback_frames=fallback_frames, limit=lim)
    except Exception:
        selected_df = pd.DataFrame()
    ok = False
    try:
        ok = _V1080_BASE_SEND_FORCED_TOP15(primary_df, fallback_frames=fallback_frames, limit=lim) if _V1080_BASE_SEND_FORCED_TOP15 else False
    except Exception as e:
        try:
            log_error(f'⚠️ V1080 TOP15 wrapper 전송 실패: {e}')
        except Exception:
            pass
        ok = False
    try:
        if selected_df is not None and hasattr(selected_df, 'empty') and not selected_df.empty:
            _v1080_record_signal_df(selected_df, source='TOP15', limit=lim)
    except Exception:
        pass
    return ok


def _v1080_read_signal_file(path: str = '') -> pd.DataFrame:
    try:
        p = Path(path or os.environ.get('V1080_SIGNAL_CSV', 'reports/v1080_stockhunter_signals.csv'))
        if not p.exists():
            return pd.DataFrame()
        if p.suffix.lower() in ('.xlsx', '.xls'):
            df = pd.read_excel(p, dtype={'code': str})
        else:
            df = pd.read_csv(p, dtype={'code': str})
        if df is None or df.empty:
            return pd.DataFrame()
        df['code'] = df['code'].map(_v1080_norm_code)
        df['signal_date'] = pd.to_datetime(df['signal_date'], errors='coerce')
        df = df.dropna(subset=['signal_date', 'code'])
        return df.reset_index(drop=True)
    except Exception as e:
        try:
            log_error(f'⚠️ V1080 신호 파일 읽기 실패: {e}')
        except Exception:
            pass
        return pd.DataFrame()


_V1080_PRICE_CACHE = {}


def _v1080_fetch_price_after(code: str, signal_date, hold_days: int = 5) -> pd.DataFrame:
    try:
        code = _v1080_norm_code(code)
        sig_ts = pd.to_datetime(signal_date)
        start = (sig_ts - pd.Timedelta(days=5)).strftime('%Y-%m-%d')
        end = (sig_ts + pd.Timedelta(days=max(20, hold_days * 4))).strftime('%Y-%m-%d')
        key = (code, start, end)
        if key not in _V1080_PRICE_CACHE:
            _V1080_PRICE_CACHE[key] = fdr.DataReader(code, start, end)
        df = _V1080_PRICE_CACHE[key]
        if df is None or df.empty:
            return pd.DataFrame()
        out = df.copy()
        out.index = pd.to_datetime(out.index)
        return out.sort_index()
    except Exception:
        return pd.DataFrame()


def _v1080_evaluate_one_signal(row, hold_days: int = 5, stop_pct: float = -5.0) -> dict:
    try:
        code = _v1080_norm_code(row.get('code', ''))
        sig_date = pd.to_datetime(row.get('signal_date'))
        entry = _v1080_num(row.get('entry_price', 0), 0)
        price_df = _v1080_fetch_price_after(code, sig_date, hold_days=hold_days)
        if price_df.empty:
            return {'eval_status': '가격데이터없음'}
        # 신호일 종가 기준 진입. entry가 없으면 신호일 또는 직전 거래일 종가로 보정.
        before_or_same = price_df[price_df.index <= sig_date]
        if entry <= 0 and not before_or_same.empty:
            entry = _v1080_num(before_or_same.iloc[-1].get('Close', 0), 0)
        if entry <= 0:
            return {'eval_status': '진입가없음'}
        future = price_df[price_df.index > sig_date].head(max(1, hold_days))
        if future.empty:
            return {'eval_status': '미래데이터부족'}
        closes = future['Close'] if 'Close' in future.columns else future.iloc[:, 0]
        highs = future['High'] if 'High' in future.columns else closes
        lows = future['Low'] if 'Low' in future.columns else closes
        def ret(v):
            return (float(v) / entry - 1.0) * 100.0 if entry > 0 else 0.0
        close1 = ret(closes.iloc[min(0, len(closes)-1)]) if len(closes) >= 1 else np.nan
        close3 = ret(closes.iloc[min(2, len(closes)-1)]) if len(closes) >= 1 else np.nan
        close5 = ret(closes.iloc[min(4, len(closes)-1)]) if len(closes) >= 1 else np.nan
        max_up = ret(highs.max())
        max_down = ret(lows.min())
        plus2_hit = bool(max_up >= 2.0)
        plus3_hit = bool(max_up >= 3.0)
        plus5_hit = bool(max_up >= 5.0)
        stop_hit = bool(max_down <= stop_pct)
        first_event = 'none'
        first_target = ''
        for _, r in future.iterrows():
            low_ret = ret(r.get('Low', r.get('Close', 0)))
            high_ret = ret(r.get('High', r.get('Close', 0)))
            # 보수 평가: 같은 날 목표와 손절이 모두 터지면 손절 우선으로 본다.
            if low_ret <= stop_pct:
                first_event = 'stop'
                first_target = 'stop'
                break
            if high_ret >= 5.0:
                first_event = 'plus5'
                first_target = '+5'
                break
            if high_ret >= 3.0:
                first_event = 'plus3'
                first_target = '+3'
                break
            if high_ret >= 2.0:
                first_event = 'plus2'
                first_target = '+2'
                break
        plus3_first = first_event in ('plus3', 'plus5')
        plus5_first = first_event == 'plus5'
        stop_first = first_event == 'stop'
        return {
            'eval_status': 'OK',
            'entry_price_eval': round(entry, 4),
            'next1_close_ret': round(close1, 4),
            'next3_close_ret': round(close3, 4),
            'next5_close_ret': round(close5, 4),
            'max_up_5d': round(max_up, 4),
            'max_down_5d': round(max_down, 4),
            'plus2_hit': plus2_hit,
            'plus3_hit': plus3_hit,
            'plus5_hit': plus5_hit,
            'stop_hit': stop_hit,
            'plus3_first': plus3_first,
            'plus5_first': plus5_first,
            'stop_first': stop_first,
            'first_event': first_event,
            'first_target': first_target,
            'last_eval_date': future.index[-1].strftime('%Y-%m-%d'),
        }
    except Exception as e:
        return {'eval_status': f'평가오류:{e}'}


def _v1080_add_week_columns(df: pd.DataFrame) -> pd.DataFrame:
    out = df.copy()
    out['signal_date'] = pd.to_datetime(out['signal_date'], errors='coerce')
    out['week_start'] = out['signal_date'] - pd.to_timedelta(out['signal_date'].dt.weekday, unit='D')
    out['week_end'] = out['week_start'] + pd.Timedelta(days=6)
    out['week_label'] = out['week_start'].dt.strftime('%Y-%m-%d') + ' ~ ' + out['week_end'].dt.strftime('%Y-%m-%d')
    return out


def _v1080_eval_signals(df: pd.DataFrame, hold_days: int = 5, stop_pct: float = -5.0) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    rows = []
    for _, row in df.iterrows():
        base = row.to_dict()
        ev = _v1080_evaluate_one_signal(base, hold_days=hold_days, stop_pct=stop_pct)
        base.update(ev)
        rows.append(base)
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    out = _v1080_add_week_columns(out)
    return out


def _v1080_rate(series) -> float:
    try:
        s = pd.Series(series).dropna()
        if len(s) == 0:
            return 0.0
        return float(s.astype(bool).mean() * 100.0)
    except Exception:
        return 0.0


def _v1080_summary_table(df: pd.DataFrame, group_cols) -> pd.DataFrame:
    try:
        ok = df[df.get('eval_status', '') == 'OK'].copy()
        if ok.empty:
            return pd.DataFrame()
        if isinstance(group_cols, str):
            group_cols = [group_cols]
        rows = []
        for keys, g in ok.groupby(group_cols, dropna=False):
            if not isinstance(keys, tuple):
                keys = (keys,)
            r = {c: keys[i] for i, c in enumerate(group_cols)}
            r.update({
                '검증수': int(len(g)),
                '다음날승률': round((pd.to_numeric(g['next1_close_ret'], errors='coerce') > 0).mean() * 100.0, 1),
                '3일평균': round(pd.to_numeric(g['next3_close_ret'], errors='coerce').mean(), 2),
                '5일평균': round(pd.to_numeric(g['next5_close_ret'], errors='coerce').mean(), 2),
                '+2도달': round(_v1080_rate(g['plus2_hit']), 1),
                '+3먼저': round(_v1080_rate(g['plus3_first']), 1),
                '+5먼저': round(_v1080_rate(g['plus5_first']), 1),
                '손절먼저': round(_v1080_rate(g['stop_first']), 1),
                '평균최대상승': round(pd.to_numeric(g['max_up_5d'], errors='coerce').mean(), 2),
                '평균최대하락': round(pd.to_numeric(g['max_down_5d'], errors='coerce').mean(), 2),
            })
            rows.append(r)
        out = pd.DataFrame(rows)
        sort_col = group_cols[0]
        if sort_col in out.columns:
            out = out.sort_values(by=sort_col)
        return out.reset_index(drop=True)
    except Exception:
        return pd.DataFrame()


def _v1080_overall_summary(df: pd.DataFrame) -> dict:
    try:
        ok = df[df.get('eval_status', '') == 'OK'].copy()
        if ok.empty:
            return {}
        return {
            '검증수': int(len(ok)),
            '다음날승률': round((pd.to_numeric(ok['next1_close_ret'], errors='coerce') > 0).mean() * 100.0, 1),
            '3일평균': round(pd.to_numeric(ok['next3_close_ret'], errors='coerce').mean(), 2),
            '5일평균': round(pd.to_numeric(ok['next5_close_ret'], errors='coerce').mean(), 2),
            '+2도달': round(_v1080_rate(ok['plus2_hit']), 1),
            '+3먼저': round(_v1080_rate(ok['plus3_first']), 1),
            '+5먼저': round(_v1080_rate(ok['plus5_first']), 1),
            '손절먼저': round(_v1080_rate(ok['stop_first']), 1),
            '평균최대상승': round(pd.to_numeric(ok['max_up_5d'], errors='coerce').mean(), 2),
            '평균최대하락': round(pd.to_numeric(ok['max_down_5d'], errors='coerce').mean(), 2),
        }
    except Exception:
        return {}


def _v1080_table_lines(title: str, tab: pd.DataFrame, max_rows: int = 12) -> list:
    lines = []
    if tab is None or tab.empty:
        return lines
    lines.append(f'[{title}]')
    # 첫 컬럼을 분류명으로 사용
    cat_col = tab.columns[0]
    for _, r in tab.head(max_rows).iterrows():
        lines.append(
            f"- {r.get(cat_col, '-')}: {int(r.get('검증수', 0))}개 | 5일 {r.get('5일평균', 0):+.2f}% | +3먼저 {r.get('+3먼저', 0):.1f}% | 손절먼저 {r.get('손절먼저', 0):.1f}%"
        )
    lines.append('')
    return lines


def _v1080_build_weekly_report(eval_df: pd.DataFrame, weeks: int = 8) -> str:
    try:
        if eval_df is None or eval_df.empty:
            return '🧪 [V1080 주간 성과검증]\n- 검증할 신호가 없습니다.'
        ok = eval_df[eval_df.get('eval_status', '') == 'OK'].copy()
        if ok.empty:
            bad_cnt = len(eval_df)
            return f'🧪 [V1080 주간 성과검증]\n- 가격데이터가 부족해 평가 가능한 신호가 없습니다. 원신호 {bad_cnt}개'
        ok = _v1080_add_week_columns(ok)
        week_labels = list(ok.sort_values('week_start')['week_label'].drop_duplicates())
        if weeks and weeks > 0:
            keep = set(week_labels[-weeks:])
            ok = ok[ok['week_label'].isin(keep)].copy()
        overall = _v1080_overall_summary(ok)
        lines = []
        lines.append('🧪 [V1080 주간 성과검증]')
        if not ok.empty:
            lines.append(f"기간: {ok['signal_date'].min().strftime('%Y-%m-%d')} ~ {ok['signal_date'].max().strftime('%Y-%m-%d')} | 주차: {ok['week_label'].nunique()}개")
        lines.append('')
        lines.append('[전체]')
        lines.append(f"- 검증 {overall.get('검증수', 0)}개 | 다음날승률 {overall.get('다음날승률', 0):.1f}% | 3일평균 {overall.get('3일평균', 0):+.2f}% | 5일평균 {overall.get('5일평균', 0):+.2f}%")
        lines.append(f"- +2도달 {overall.get('+2도달', 0):.1f}% | +3먼저 {overall.get('+3먼저', 0):.1f}% | +5먼저 {overall.get('+5먼저', 0):.1f}% | 손절먼저 {overall.get('손절먼저', 0):.1f}%")
        lines.append(f"- 평균최대상승 {overall.get('평균최대상승', 0):+.2f}% | 평균최대하락 {overall.get('평균최대하락', 0):+.2f}%")
        lines.append('')
        week_tab = _v1080_summary_table(ok, 'week_label')
        lines += _v1080_table_lines('주차별', week_tab, max_rows=20)
        ai_tab = _v1080_summary_table(ok, 'ai_pick_tier')
        if not ai_tab.empty:
            ai_tab['_sort'] = ai_tab['ai_pick_tier'].map({'🤖 AI Pick':0, '🤖 AI 관찰 Pick':1, '🛡 보수적 AI Pick':2, 'AI Pick 없음':3}).fillna(9)
            ai_tab = ai_tab.sort_values(['_sort','검증수'], ascending=[True, False]).drop(columns=['_sort'])
        lines += _v1080_table_lines('AI Pick 등급별', ai_tab, max_rows=10)
        vol_tab = _v1080_summary_table(ok, 'volume_state')
        lines += _v1080_table_lines('거래량 상태별', vol_tab, max_rows=10)
        fake_tab = _v1080_summary_table(ok, 'fake_severity')
        lines += _v1080_table_lines('가짜수박 강도별', fake_tab, max_rows=10)
        decision_tab = _v1080_summary_table(ok, 'final_decision')
        lines += _v1080_table_lines('최종판정별', decision_tab, max_rows=10)
        # 자동 해석
        lines.append('[핵심 해석]')
        try:
            ai_good = ai_tab[ai_tab['ai_pick_tier'].astype(str).str.contains('AI Pick|관찰|보수', regex=True, na=False)]
            ai_none = ai_tab[ai_tab['ai_pick_tier'].astype(str).str.contains('없음', na=False)]
            if not ai_good.empty and not ai_none.empty:
                good_avg = float(pd.to_numeric(ai_good['5일평균'], errors='coerce').mean())
                none_avg = float(pd.to_numeric(ai_none['5일평균'], errors='coerce').mean())
                if good_avg > none_avg:
                    lines.append(f'- AI Pick 계열 5일평균이 없음 대비 우위입니다. ({good_avg:+.2f}% vs {none_avg:+.2f}%)')
                else:
                    lines.append(f'- AI Pick 계열이 아직 없음 대비 확실한 우위를 보이지 않습니다. ({good_avg:+.2f}% vs {none_avg:+.2f}%)')
        except Exception:
            pass
        try:
            strong_fake = fake_tab[fake_tab['fake_severity'].astype(str).str.contains('강', na=False)]
            if not strong_fake.empty and float(strong_fake.iloc[0].get('손절먼저', 0)) >= overall.get('손절먼저', 0):
                lines.append('- 가짜수박 강은 손절선도달이 높아 실전 후보 제외 원칙을 유지합니다.')
        except Exception:
            pass
        try:
            vol_fail = vol_tab[vol_tab['volume_state'].astype(str).str.contains('실패|위험', regex=True, na=False)]
            if not vol_fail.empty and float(vol_fail.iloc[0].get('5일평균', 0)) < overall.get('5일평균', 0):
                lines.append('- 거래량실패 분류는 전체 대비 약해 위험 분류 유지가 타당합니다.')
        except Exception:
            pass
        if len(lines) > 0 and lines[-1] == '[핵심 해석]':
            lines.append('- 최소 2~3주 누적 후 같은 문제가 반복될 때만 튜닝하는 것이 안전합니다.')
        return '\n'.join(lines).strip()
    except Exception as e:
        return f'🧪 [V1080 주간 성과검증]\n- 리포트 생성 실패: {e}'


def v1080_run_weekly_backtest(signal_path: str = '', output_dir: str = '') -> tuple:
    """외부에서 직접 호출 가능한 V1080 주간 성과검증 엔진."""
    hold_days = _v1080_env_int('V1080_BACKTEST_HOLD_DAYS', 5)
    stop_pct = _v1080_env_float('V1080_BACKTEST_STOP_PCT', -5.0)
    weeks = _v1080_env_int('V1080_BACKTEST_WEEKS', 8)
    raw = _v1080_read_signal_file(signal_path)
    if raw.empty:
        report = '🧪 [V1080 주간 성과검증]\n- 신호 CSV가 없거나 비어 있습니다. 먼저 일반 실행으로 TOP15 신호를 누적 저장하세요.'
        return report, pd.DataFrame()
    # 최근 N주만 평가해 속도 부담을 낮춘다.
    raw = _v1080_add_week_columns(raw)
    if weeks and weeks > 0:
        keep = list(raw.sort_values('week_start')['week_label'].drop_duplicates())[-weeks:]
        raw = raw[raw['week_label'].isin(set(keep))].copy()
    eval_df = _v1080_eval_signals(raw, hold_days=hold_days, stop_pct=stop_pct)
    report = _v1080_build_weekly_report(eval_df, weeks=weeks)
    if _v1080_should_save_backtest_file():
        try:
            out_dir = Path(output_dir or os.environ.get('V1080_BACKTEST_OUTPUT_DIR', 'reports'))
            out_dir.mkdir(parents=True, exist_ok=True)
            stamp = datetime.now().strftime('%Y%m%d_%H%M%S')
            eval_path = out_dir / f'v1080_weekly_backtest_eval_{stamp}.csv'
            txt_path = out_dir / f'v1080_weekly_backtest_report_{stamp}.txt'
            if eval_df is not None and not eval_df.empty:
                eval_df.to_csv(eval_path, index=False, encoding='utf-8-sig')
            txt_path.write_text(report, encoding='utf-8')
            try:
                log_info(f'✅ V1080 주간 성과검증 저장 완료 → {txt_path}')
            except Exception:
                pass
        except Exception as _v1080_file_e:
            try:
                log_error(f'⚠️ V1080 주간 성과검증 파일 저장 실패: {_v1080_file_e}')
            except Exception:
                pass
    else:
        try:
            log_info(f'ℹ️ V1080 주간 성과검증 파일 저장 생략: OUTPUT_MODE={_v1080_backtest_output_mode()}')
        except Exception:
            pass
    return report, eval_df



def _v1080_get_backtest_token() -> str:
    """성과검증 전용 텔레그램 BOT 토큰.
    - WEEKLY_BACKTEST 결과 전송은 일반 TELEGRAM_TOKEN이 아니라 TELEGRAM_BACKTEST_TOKEN을 우선 사용한다.
    - 토큰이 없으면 실전방 오발송 방지를 위해 전송을 생략한다.
    """
    try:
        return str(os.environ.get('TELEGRAM_BACKTEST_TOKEN', '') or '').strip()
    except Exception:
        return ''


def _v1080_get_backtest_chat_ids() -> tuple:
    """성과검증 전송 대상 CHAT ID.
    사용자가 요청한 대로 별도 BACKTEST_CHAT_ID를 쓰지 않고 테스트모드 대상과 동일한 순서를 따른다.
    1) TELEGRAM_CHAT_ID_EFFECTIVE 또는 TEST_CHAT_ID_OVERRIDE
    2) TELEGRAM_TEST_CHAT_ID
    실전 TELEGRAM_CHAT_ID는 사용하지 않는다.
    """
    try:
        override_raw = os.environ.get('TELEGRAM_CHAT_ID_EFFECTIVE', '') or os.environ.get('TEST_CHAT_ID_OVERRIDE', '')
        override_ids = _parse_chat_ids(override_raw)
        if override_ids:
            return override_ids, 'test_override'
    except Exception:
        pass
    try:
        test_ids = _parse_chat_ids(os.environ.get('TELEGRAM_TEST_CHAT_ID', ''))
        if test_ids:
            return test_ids, 'test'
    except Exception:
        pass
    return [], 'test_missing'


def _v1080_split_telegram_text(text: str, max_len: int = 3500) -> list:
    try:
        src = str(text or '')
        if not src:
            return []
        max_len = max(500, int(max_len or 3500))
        chunks = []
        buf = ''
        for line in src.splitlines(True):
            if len(line) > max_len:
                if buf:
                    chunks.append(buf.rstrip())
                    buf = ''
                for i in range(0, len(line), max_len):
                    chunks.append(line[i:i+max_len].rstrip())
                continue
            if len(buf) + len(line) > max_len:
                chunks.append(buf.rstrip())
                buf = line
            else:
                buf += line
        if buf.strip():
            chunks.append(buf.rstrip())
        return [c for c in chunks if c.strip()]
    except Exception:
        return [str(text or '')[:max_len]]


def _v1080_send_backtest_telegram(message: str, max_len: int = 3500) -> bool:
    """V1080 성과검증 전용 텔레그램 전송.
    토큰: TELEGRAM_BACKTEST_TOKEN
    CHAT ID: 테스트모드 CHAT ID와 동일한 대상
    """
    token = _v1080_get_backtest_token()
    if not token:
        try:
            log_error('⚠️ TELEGRAM_BACKTEST_TOKEN 없음 — V1080 성과검증 텔레그램 전송 생략')
        except Exception:
            pass
        return False
    chat_ids, mode = _v1080_get_backtest_chat_ids()
    if not chat_ids:
        try:
            log_error('⚠️ V1080 성과검증 전송 대상 없음 — test_chat_id_override 또는 TELEGRAM_TEST_CHAT_ID를 확인하세요')
        except Exception:
            pass
        return False
    try:
        text = str(message or '').strip()
        if not text:
            return False
        if not text.startswith('[TEST]'):
            text = '[TEST]\n' + text
        chunks = _v1080_split_telegram_text(text, max_len=max_len)
        url = f'https://api.telegram.org/bot{token}/sendMessage'
        ok_any = False
        for chat_id in chat_ids:
            for chunk in chunks:
                try:
                    res = requests.post(
                        url,
                        data={'chat_id': chat_id, 'text': chunk[:4000]},
                        timeout=15,
                    )
                    if getattr(res, 'ok', False):
                        ok_any = True
                    else:
                        try:
                            log_error(f'⚠️ V1080 성과검증 텔레그램 전송 실패 chat_id={chat_id} status={getattr(res, "status_code", "?")} body={getattr(res, "text", "")[:200]}')
                        except Exception:
                            pass
                except Exception as send_e:
                    try:
                        log_error(f'⚠️ V1080 성과검증 텔레그램 전송 예외 chat_id={chat_id}: {send_e}')
                    except Exception:
                        pass
        try:
            log_info(f'✅ V1080 성과검증 텔레그램 전송 완료 | token=TELEGRAM_BACKTEST_TOKEN | chat_mode={mode} | 대상방 {len(chat_ids)}개')
        except Exception:
            pass
        return ok_any
    except Exception as e:
        try:
            log_error(f'⚠️ V1080 성과검증 전용 텔레그램 전송 실패: {e}')
        except Exception:
            pass
        return False


