def _v1081_source_mode() -> str:
    try:
        mode = str(os.environ.get('V1081_BACKTEST_SOURCE', 'DIRECT_REPLAY')).strip().upper()
        aliases = {
            'DIRECT': 'DIRECT_REPLAY',
            'REPLAY': 'DIRECT_REPLAY',
            'LIVE_REPLAY': 'DIRECT_REPLAY',
            'CSV': 'CSV_CACHE',
            'FILE': 'CSV_CACHE',
            'CACHE': 'CSV_CACHE',
            'CSV_CACHE': 'CSV_CACHE',
        }
        return aliases.get(mode, mode) if aliases.get(mode, mode) in ('DIRECT_REPLAY', 'CSV_CACHE') else 'DIRECT_REPLAY'
    except Exception:
        return 'DIRECT_REPLAY'


def _v1081_latest_trading_calendar(weeks: int, hold_days: int) -> list:
    """KOSPI 달력 기준으로 평가 완료 가능한 과거 기준일 목록을 만든다.
    WEEK_LAST: 각 완료주차의 마지막 거래일 1개만 선택
    ALL_DAYS : 완료주차의 모든 거래일 선택
    """
    try:
        today = pd.Timestamp(datetime.now().strftime('%Y-%m-%d'))
        extra_days = max(90, int(weeks or 8) * 14 + int(hold_days or 5) * 5 + 30)
        start = (today - pd.Timedelta(days=extra_days)).strftime('%Y-%m-%d')
        end = (today + pd.Timedelta(days=1)).strftime('%Y-%m-%d')
        try:
            idx_df = fdr.DataReader('KS11', start, end)
        except Exception:
            idx_df = fdr.DataReader('KOSPI', start, end)
        if idx_df is None or idx_df.empty:
            return []
        dates = pd.to_datetime(idx_df.index).sort_values().unique()
        dates = [pd.Timestamp(x).normalize() for x in dates if pd.Timestamp(x).normalize() <= today]
        if len(dates) <= max(1, hold_days):
            return []
        # hold_days 이후 성과가 있어야 하므로, 최신 거래일에서 hold_days만큼 뒤로 뺀 날짜까지만 신호일 허용
        max_signal_date = dates[-(int(hold_days) + 1)]
        eligible = [d for d in dates if d <= max_signal_date]
        if not eligible:
            return []
        cal = pd.DataFrame({'date': eligible})
        cal['week_start'] = cal['date'] - pd.to_timedelta(cal['date'].dt.weekday, unit='D')
        cal['week_end'] = cal['week_start'] + pd.Timedelta(days=6)
        week_keys = list(cal.sort_values('week_start')['week_start'].drop_duplicates())
        if weeks and weeks > 0:
            week_keys = week_keys[-int(weeks):]
        mode = str(os.environ.get('V1081_DIRECT_DATE_MODE', 'WEEK_LAST')).strip().upper()
        out = []
        for wk in week_keys:
            w = cal[cal['week_start'] == wk].copy()
            if w.empty:
                continue
            if mode == 'ALL_DAYS':
                out += list(w['date'])
            else:
                out.append(pd.Timestamp(w['date'].max()))
        max_dates = _v1080_env_int('V1081_DIRECT_MAX_DATES', 0) if '_v1080_env_int' in globals() else 0
        if max_dates and max_dates > 0:
            out = out[-max_dates:]
        return sorted(list(dict.fromkeys([pd.Timestamp(x).normalize() for x in out])))
    except Exception as e:
        try:
            log_error(f'⚠️ V1081 기준일 달력 생성 실패: {e}')
        except Exception:
            pass
        return []


def _v1081_load_direct_universe(limit: int = 150) -> pd.DataFrame:
    """직접 재현검증용 universe. 현재 KRX 목록 기준 거래대금 상위 N을 사용한다.
    완전한 과거 생존종목 universe는 아니므로, 튜닝 전 진단용으로 사용한다.
    """
    try:
        limit = max(20, int(limit or 150))
        if 'load_krx_listing_safe' in globals():
            df = load_krx_listing_safe()
        else:
            df = fdr.StockListing('KRX')
        if df is None or df.empty:
            return pd.DataFrame()
        out = df.copy()
        if 'Code' not in out.columns:
            code_col = next((c for c in ['Symbol', 'code', '종목코드'] if c in out.columns), None)
            if code_col:
                out = out.rename(columns={code_col: 'Code'})
        if 'Name' not in out.columns:
            name_col = next((c for c in ['Name', 'name', '종목명'] if c in out.columns), None)
            if name_col:
                out = out.rename(columns={name_col: 'Name'})
        if 'Code' not in out.columns or 'Name' not in out.columns:
            return pd.DataFrame()
        out['Code'] = out['Code'].map(_v1080_norm_code if '_v1080_norm_code' in globals() else lambda x: str(x).zfill(6))
        out['Name'] = out['Name'].astype(str)
        if 'Market' in out.columns:
            out = out[out['Market'].astype(str).isin(['KOSPI', 'KOSDAQ', '코스피', '코스닥', '유가'])].copy()
        out = out[~out['Name'].str.contains('ETF|ETN|스팩|제[0-9]+호|우$|우A|우B|우C', regex=True, na=False)].copy()
        for col in ['Close', 'Price', 'Amount', 'Marcap', 'MarCap']:
            if col in out.columns:
                out[col] = pd.to_numeric(out[col], errors='coerce')
        min_price = float(globals().get('MIN_PRICE', 3000) or 3000)
        if 'Close' in out.columns and out['Close'].notna().any():
            out = out[out['Close'].fillna(0) >= min_price].copy()
        elif 'Price' in out.columns and out['Price'].notna().any():
            out = out[out['Price'].fillna(0) >= min_price].copy()
        min_marcap = float(globals().get('MIN_MARCAP', 0) or 0)
        if min_marcap and 'Marcap' in out.columns and out['Marcap'].notna().any():
            out = out[out['Marcap'].fillna(0) >= min_marcap].copy()
        elif min_marcap and 'MarCap' in out.columns and out['MarCap'].notna().any():
            out = out[out['MarCap'].fillna(0) >= min_marcap].copy()
        if 'Amount' in out.columns:
            out = out.sort_values('Amount', ascending=False, na_position='last')
        elif 'Marcap' in out.columns:
            out = out.sort_values('Marcap', ascending=False, na_position='last')
        elif 'MarCap' in out.columns:
            out = out.sort_values('MarCap', ascending=False, na_position='last')
        return out[['Code', 'Name']].drop_duplicates('Code').head(limit).reset_index(drop=True)
    except Exception as e:
        try:
            log_error(f'⚠️ V1081 직접검증 universe 로드 실패: {e}')
        except Exception:
            pass
        return pd.DataFrame()


try:
    _V1081_BASE_FDR_CACHED = fdr_cached
except Exception:
    _V1081_BASE_FDR_CACHED = None


def _v1081_fdr_cached_asof(ticker, days=900):
    """analyze_final을 과거 기준일로 재사용하기 위한 fdr_cached 임시 대체 함수."""
    code = _v1080_norm_code(ticker) if '_v1080_norm_code' in globals() else str(ticker).zfill(6)
    asof = globals().get('_V1081_CURRENT_ASOF_DATE', None)
    if asof is None:
        if _V1081_BASE_FDR_CACHED:
            return _V1081_BASE_FDR_CACHED(code, days=days)
        return fdr.DataReader(code)
    asof = pd.Timestamp(asof).normalize()
    try:
        if _V1081_BASE_FDR_CACHED:
            df = _V1081_BASE_FDR_CACHED(code, days=max(int(days or 900), 900))
        else:
            start = (asof - pd.Timedelta(days=max(1200, int(days or 900) * 2))).strftime('%Y-%m-%d')
            end = (asof + pd.Timedelta(days=1)).strftime('%Y-%m-%d')
            df = fdr.DataReader(code, start, end)
        if df is None or df.empty:
            return pd.DataFrame()
        out = df.copy()
        out.index = pd.to_datetime(out.index)
        out = out[out.index <= asof].sort_index()
        return out.tail(max(int(days or 900), 900)).copy()
    except Exception:
        return pd.DataFrame()


def _v1081_make_signal_rows_for_asof(asof_date, universe_df: pd.DataFrame, weather_data=None, sector_master_map=None, limit: int = 15) -> list:
    """특정 과거 기준일 기준으로 기존 analyze_final → build_and_sort_candidates를 재사용해 TOP 후보를 만든다."""
    if universe_df is None or universe_df.empty:
        return []
    asof_ts = pd.Timestamp(asof_date).normalize()
    old_today = globals().get('TODAY_STR', '')
    old_asof = globals().get('_V1081_CURRENT_ASOF_DATE', None)
    old_fdr_cached = globals().get('fdr_cached', None)
    rows = []
    try:
        globals()['_V1081_CURRENT_ASOF_DATE'] = asof_ts
        globals()['TODAY_STR'] = asof_ts.strftime('%Y-%m-%d')
        globals()['fdr_cached'] = _v1081_fdr_cached_asof
        target_pairs = list(zip(universe_df['Code'].astype(str), universe_df['Name'].astype(str)))
        all_hits = []
        g_env = {}
        l_env = {}
        s_map = sector_master_map or {}
        hist = weather_data if weather_data is not None else pd.DataFrame()
        total = len(target_pairs)
        for idx, (code, name) in enumerate(target_pairs, start=1):
            try:
                res = analyze_final(code, name, hist, g_env, l_env, s_map)
                if res:
                    all_hits.extend(res)
            except Exception as one_e:
                try:
                    log_debug(f'V1081 직접검증 개별 오류 {asof_ts.date()} {name}: {one_e}')
                except Exception:
                    pass
            if idx % 25 == 0:
                try:
                    log_info(f'🧪 V1081 직접검증 {asof_ts.strftime("%Y-%m-%d")} 진행 {idx}/{total} | 후보 {len(all_hits)}')
                except Exception:
                    pass
        if not all_hits:
            return []
        try:
            sorted_hits = sorted(all_hits, key=lambda x: x.get('N점수', 0), reverse=True)
        except Exception:
            sorted_hits = all_hits
        if 'build_and_sort_candidates' in globals():
            cand_df = build_and_sort_candidates(sorted_hits, top_k=max(50, int(limit or 15) * 4))
        else:
            cand_df = pd.DataFrame(sorted_hits)
        if cand_df is None or cand_df.empty:
            return []
        # 현재 운용 TOP15 정렬 함수가 있으면 재사용
        try:
            if '_v1050_sort_df_for_top15' in globals():
                cand_df = _v1050_sort_df_for_top15(cand_df)
            else:
                sort_cols = [c for c in ['단계랭크', '안전점수', 'N점수'] if c in cand_df.columns]
                if sort_cols:
                    cand_df = cand_df.sort_values(sort_cols, ascending=[False] * len(sort_cols))
        except Exception:
            pass
        cand_df = cand_df.head(max(1, int(limit or 15))).reset_index(drop=True)
        for rank, (_, row) in enumerate(cand_df.iterrows(), start=1):
            r = _v1080_signal_row_from_series(row, rank=rank, source='DIRECT_REPLAY') if '_v1080_signal_row_from_series' in globals() else {}
            if not r:
                continue
            r['signal_date'] = asof_ts.strftime('%Y-%m-%d')
            r['recorded_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            r['source'] = 'DIRECT_REPLAY'
            # 과거 AI Pick은 실제 배치 판단을 재호출하지 않으므로 "없음"으로 오해하지 않게 별도 표기
            r['ai_pick_tier'] = '직접검증(과거 AI 미실행)'
            r['ai_pick_reason'] = '성과검증 속도/비용 보호를 위해 과거 AI 배치판단은 생략'
            # 관점/패턴/수박상태 보강
            try:
                data = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            except Exception:
                data = {}
            if not _v1080_s(r.get('strategy', '')):
                r['strategy'] = _v1080_first(data, ['N조합', '구분', 'N구분', '수박최종상태', '단계태그'], '미분류')
            if not _v1080_s(r.get('pattern', '')):
                r['pattern'] = _v1080_first(data, ['수박최종상태', '수박상태명', '저항구름태그', '흰구름태그', '예비돌반지태그', 'N구분'], '미분류')
            if not _v1080_s(r.get('final_decision', '')):
                r['final_decision'] = _v1080_first(data, ['매매판정', '추천단계', '단계상태', '수박최종상태'], '미분류')
            if not _v1080_s(r.get('phase', '')):
                r['phase'] = _v1080_first(data, ['추천단계', '단계상태', '수박최종상태'], '미분류')
            r['replay_asof_date'] = asof_ts.strftime('%Y-%m-%d')
            rows.append(r)
        return rows
    finally:
        try:
            globals()['TODAY_STR'] = old_today
            globals()['_V1081_CURRENT_ASOF_DATE'] = old_asof
            if old_fdr_cached is not None:
                globals()['fdr_cached'] = old_fdr_cached
        except Exception:
            pass


def _v1081_table_lines(title: str, tab: pd.DataFrame, max_rows: int = 12) -> list:
    try:
        if tab is None or tab.empty:
            return []
        return _v1080_table_lines(title, tab, max_rows=max_rows) if '_v1080_table_lines' in globals() else []
    except Exception:
        return []


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    try:
        base = _v1080_build_weekly_report(eval_df, weeks=weeks) if '_v1080_build_weekly_report' in globals() else ''
        base = str(base or '').replace('🧪 [V1080 주간 성과검증]', '🧪 [V1081 직접 재현 주간 성과검증]', 1)
        header = [
            '🧪 [V1081 직접 재현 주간 성과검증]',
            f'- 방식: CSV 누적 없이 과거 기준일별 후보 직접 생성 → 즉시 성과검증',
            f'- 기준일 수: {len(replay_dates)}개 | 원신호: {raw_count}개 | universe: {universe_count}개',
            f'- 기준일: {", ".join([pd.Timestamp(x).strftime("%Y-%m-%d") for x in replay_dates[:12]])}' + (' ...' if len(replay_dates) > 12 else ''),
            ''
        ]
        # base 첫 줄이 중복이면 제거하고 header를 우선 사용
        body_lines = base.splitlines()
        if body_lines and 'V1081 직접 재현' in body_lines[0]:
            body_lines = body_lines[1:]
        report = '\n'.join(header + body_lines).strip()
        ok = eval_df[eval_df.get('eval_status', '') == 'OK'].copy() if eval_df is not None and not eval_df.empty else pd.DataFrame()
        if not ok.empty:
            add_lines = ['']
            for col, title, n in [
                ('strategy', '관점/전략별', 12),
                ('pattern', '패턴별', 12),
                ('phase', '추천단계별', 10),
            ]:
                try:
                    if col in ok.columns:
                        tmp = ok.copy()
                        tmp[col] = tmp[col].astype(str).replace({'': '미분류', 'nan': '미분류', 'None': '미분류'})
                        tab = _v1080_summary_table(tmp, col)
                        add_lines += _v1081_table_lines(title, tab, max_rows=n)
                except Exception:
                    pass
            add_lines.append('[V1081 해석 포인트]')
            add_lines.append('- 이 결과는 오늘 신호 저장 파일이 아니라, 과거 기준일에 후보를 다시 만든 재현검증입니다.')
            add_lines.append('- AI Pick은 과거 배치판단을 재호출하지 않아 별도 비교 대상에서 제외하고, 관점/패턴/최종판정 중심으로 봅니다.')
            add_lines.append('- 현재 universe 기준 거래대금 상위 N개를 대상으로 하므로, 완전한 과거 생존종목 검증은 아니지만 튜닝 방향성 확인에는 더 적합합니다.')
            report = report.rstrip() + '\n' + '\n'.join(add_lines).strip()
        return report.strip()
    except Exception as e:
        return f'🧪 [V1081 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'


def v1081_run_direct_weekly_backtest(output_dir: str = '') -> tuple:
    """CSV 없이 과거 날짜별 후보를 직접 재현해 주간 성과검증한다."""
    hold_days = _v1080_env_int('V1080_BACKTEST_HOLD_DAYS', 5) if '_v1080_env_int' in globals() else 5
    stop_pct = _v1080_env_float('V1080_BACKTEST_STOP_PCT', -5.0) if '_v1080_env_float' in globals() else -5.0
    weeks = _v1080_env_int('V1080_BACKTEST_WEEKS', 8) if '_v1080_env_int' in globals() else 8
    top_n = _v1080_env_int('V1081_DIRECT_TOP_N', 150) if '_v1080_env_int' in globals() else 150
    per_date = _v1080_env_int('V1081_DIRECT_LIMIT_PER_DATE', 15) if '_v1080_env_int' in globals() else 15
    try:
        replay_dates = _v1081_latest_trading_calendar(weeks=weeks, hold_days=hold_days)
        if not replay_dates:
            report = '🧪 [V1081 직접 재현 주간 성과검증]\n- 평가 완료 기준일을 만들 수 없습니다. KOSPI/FDR 달력 데이터를 확인하세요.'
            return report, pd.DataFrame()
        universe_df = _v1081_load_direct_universe(limit=top_n)
        if universe_df is None or universe_df.empty:
            report = '🧪 [V1081 직접 재현 주간 성과검증]\n- 직접검증 universe를 만들 수 없습니다. KRX/FDR 목록 데이터를 확인하세요.'
            return report, pd.DataFrame()
        try:
            log_info(f'🧪 V1081 직접 재현검증 시작 | 주차 {weeks} | 기준일 {len(replay_dates)}개 | universe {len(universe_df)}개 | 날짜별 TOP{per_date}')
        except Exception:
            pass
        # 과거 기준 검증에서는 시황/섹터 실시간 의존도를 줄이기 위해 최소값 사용
        try:
            weather_data = prepare_historical_weather() if 'prepare_historical_weather' in globals() else pd.DataFrame()
        except Exception:
            weather_data = pd.DataFrame()
        sector_master_map = {}
        try:
            # 현재 listing의 업종 정보만 보조로 사용
            listing = load_krx_listing_safe() if 'load_krx_listing_safe' in globals() else pd.DataFrame()
            if listing is not None and not listing.empty:
                code_col = 'Code' if 'Code' in listing.columns else next((c for c in ['Symbol','종목코드'] if c in listing.columns), None)
                sec_col = next((c for c in ['Sector','Industry','업종'] if c in listing.columns), None)
                if code_col and sec_col:
                    tmp = listing[[code_col, sec_col]].copy()
                    tmp[code_col] = tmp[code_col].map(_v1080_norm_code)
                    sector_master_map = tmp.set_index(code_col)[sec_col].astype(str).to_dict()
        except Exception:
            sector_master_map = {}
        raw_rows = []
        for d in replay_dates:
            try:
                rows = _v1081_make_signal_rows_for_asof(d, universe_df, weather_data=weather_data, sector_master_map=sector_master_map, limit=per_date)
                raw_rows.extend(rows)
                try:
                    log_info(f'✅ V1081 기준일 {pd.Timestamp(d).strftime("%Y-%m-%d")} 후보 {len(rows)}개 생성')
                except Exception:
                    pass
            except Exception as d_e:
                try:
                    log_error(f'⚠️ V1081 기준일 {d} 직접검증 실패: {d_e}')
                except Exception:
                    pass
        if not raw_rows:
            report = '🧪 [V1081 직접 재현 주간 성과검증]\n- 과거 기준일에서 생성된 후보가 없습니다. universe 크기 또는 필터 조건을 확인하세요.'
            return report, pd.DataFrame()
        raw = pd.DataFrame(raw_rows)
        raw['code'] = raw['code'].map(_v1080_norm_code)
        raw['signal_date'] = pd.to_datetime(raw['signal_date'], errors='coerce')
        raw = raw.dropna(subset=['signal_date', 'code']).reset_index(drop=True)
        eval_df = _v1080_eval_signals(raw, hold_days=hold_days, stop_pct=stop_pct) if '_v1080_eval_signals' in globals() else pd.DataFrame()
        report = _v1081_build_direct_report(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=len(raw), universe_count=len(universe_df))
        if _v1080_should_save_backtest_file():
            try:
                out_dir = Path(output_dir or os.environ.get('V1080_BACKTEST_OUTPUT_DIR', 'reports'))
                out_dir.mkdir(parents=True, exist_ok=True)
                stamp = datetime.now().strftime('%Y%m%d_%H%M%S')
                raw_path = out_dir / f'v1081_direct_replay_raw_{stamp}.csv'
                eval_path = out_dir / f'v1081_direct_replay_eval_{stamp}.csv'
                txt_path = out_dir / f'v1081_direct_replay_report_{stamp}.txt'
                raw.to_csv(raw_path, index=False, encoding='utf-8-sig')
                if eval_df is not None and not eval_df.empty:
                    eval_df.to_csv(eval_path, index=False, encoding='utf-8-sig')
                txt_path.write_text(report, encoding='utf-8')
                try:
                    log_info(f'✅ V1081 직접 재현검증 저장 완료 → {txt_path}')
                except Exception:
                    pass
            except Exception as save_e:
                try:
                    log_error(f'⚠️ V1081 직접 재현검증 파일 저장 실패: {save_e}')
                except Exception:
                    pass
        return report, eval_df
    except Exception as e:
        report = f'🧪 [V1081 직접 재현 주간 성과검증]\n- 실행 실패: {e}'
        return report, pd.DataFrame()

