# =============================================================
# ✅ V1082_SIGNAL_STOP_BACKTEST_ACTIVE
# - 성과검증 손절 기준을 고정 -5%뿐 아니라 스캐너 제시 손절가 기준으로 확장
# - FIXED_PCT / SIGNAL_STOP / SIGNAL_STOP_WITH_FALLBACK / BOTH_COMPARE 지원
# - 손절가 거리별 성과 집계 추가
# =============================================================
print("✅ V1082_SIGNAL_STOP_BACKTEST_ACTIVE LOADED")

try:
    os.environ.setdefault('V1082_BACKTEST_STOP_MODE', 'SIGNAL_STOP_WITH_FALLBACK')
except Exception:
    pass


def _v1082_stop_mode() -> str:
    try:
        mode = str(os.environ.get('V1082_BACKTEST_STOP_MODE', 'SIGNAL_STOP_WITH_FALLBACK')).strip().upper()
        aliases = {
            'FIXED': 'FIXED_PCT',
            'FIXED_PERCENT': 'FIXED_PCT',
            'PCT': 'FIXED_PCT',
            'SIGNAL': 'SIGNAL_STOP',
            'SCANNER': 'SIGNAL_STOP',
            'SCANNER_STOP': 'SIGNAL_STOP',
            'SIGNAL_FALLBACK': 'SIGNAL_STOP_WITH_FALLBACK',
            'SCANNER_FALLBACK': 'SIGNAL_STOP_WITH_FALLBACK',
            'FALLBACK': 'SIGNAL_STOP_WITH_FALLBACK',
            'BOTH': 'BOTH_COMPARE',
            'COMPARE': 'BOTH_COMPARE',
        }
        mode = aliases.get(mode, mode)
        if mode in ('FIXED_PCT', 'SIGNAL_STOP', 'SIGNAL_STOP_WITH_FALLBACK', 'BOTH_COMPARE'):
            return mode
    except Exception:
        pass
    return 'SIGNAL_STOP_WITH_FALLBACK'


def _v1082_stop_mode_label() -> str:
    mode = _v1082_stop_mode()
    fixed = _v1080_env_float('V1080_BACKTEST_STOP_PCT', -5.0) if '_v1080_env_float' in globals() else -5.0
    if mode == 'FIXED_PCT':
        return f'고정 손절률 {fixed:g}%'
    if mode == 'SIGNAL_STOP':
        return '스캐너 제시 손절가만 사용(손절가 없으면 평가 제외)'
    if mode == 'SIGNAL_STOP_WITH_FALLBACK':
        return f'스캐너 제시 손절가 우선 / 없으면 고정 {fixed:g}%'
    if mode == 'BOTH_COMPARE':
        return f'기본 집계는 스캐너 손절가 우선 / 고정 {fixed:g}%와 비교 출력'
    return f'스캐너 제시 손절가 우선 / 없으면 고정 {fixed:g}%'


def _v1082_parse_price_text(text, entry: float = 0.0) -> float:
    try:
        s = str(text or '')
        if not s or s.lower() in ('nan', 'none'):
            return 0.0
        # "손절가: 12,300" / "손절 12,300원" / "stop_loss=12300" 형태 보정
        patterns = [
            r'(?:손절가|손절선|손절가격|기준손절가|하단손절가|손절|stop[_ ]?loss|stop[_ ]?price)\s*[:=：]?\s*([0-9]{1,3}(?:,[0-9]{3})+|[0-9]+(?:\.[0-9]+)?)',
            r'([0-9]{1,3}(?:,[0-9]{3})+|[0-9]+(?:\.[0-9]+)?)\s*원?\s*(?:손절|stop)',
        ]
        for pat in patterns:
            m = re.search(pat, s, flags=re.IGNORECASE)
            if m:
                v = _v1080_num(m.group(1), 0.0) if '_v1080_num' in globals() else float(str(m.group(1)).replace(',', ''))
                if v > 0:
                    return float(v)
        # 값 자체가 숫자인 경우
        v = _v1080_num(s, 0.0) if '_v1080_num' in globals() else 0.0
        if v > 0:
            return float(v)
    except Exception:
        pass
    return 0.0


def _v1082_extract_signal_stop_price(row, entry: float = 0.0) -> float:
    keys = [
        '손절가', '손절가격', '손절선', '기준손절가', '하단손절가', 'stop_price', 'stop_loss',
        'stop_loss_price', 'StopLoss', 'StopPrice', 'loss_cut_price', 'cut_loss_price',
        '손절', '스탑', '스탑로스', '리스크기준가'
    ]
    try:
        # 1) 명시 컬럼 우선
        for k in keys:
            try:
                v = row.get(k, '') if hasattr(row, 'get') else row[k]
            except Exception:
                continue
            price = _v1082_parse_price_text(v, entry=entry)
            if price > 0:
                # -3 같은 퍼센트 값이면 가격으로 오해하지 않는다.
                if price <= 0.6 and entry > 0:
                    continue
                if price < 100 and entry > 500:
                    continue
                return float(price)
        # 2) 설명성 컬럼에서 손절가 텍스트 추출
        text_keys = [
            '최종판정', '매매판정', '진입전략', '해석', 'comment', 'reason', '리스크',
            '오늘매매관점', '압축코멘트', 'AI코멘트', '메모'
        ]
        for k in text_keys:
            try:
                v = row.get(k, '') if hasattr(row, 'get') else row[k]
            except Exception:
                continue
            price = _v1082_parse_price_text(v, entry=entry)
            if price > 0:
                if price < 100 and entry > 500:
                    continue
                return float(price)
    except Exception:
        pass
    return 0.0


def _v1082_valid_signal_stop_pct(entry: float, stop_price: float) -> float:
    try:
        entry = float(entry or 0)
        stop_price = float(stop_price or 0)
        if entry <= 0 or stop_price <= 0:
            return float('nan')
        pct = (stop_price / entry - 1.0) * 100.0
        # 손절가는 진입가 아래의 현실적인 범위만 인정한다.
        if pct >= -0.1:
            return float('nan')
        if pct < -30.0:
            return float('nan')
        return float(pct)
    except Exception:
        return float('nan')


def _v1082_stop_bucket(signal_stop_pct) -> str:
    try:
        pct = float(signal_stop_pct)
        if pd.isna(pct):
            return '손절가없음'
        d = abs(pct)
        if d <= 3.0:
            return '-3% 이내'
        if d <= 5.0:
            return '-3~-5%'
        if d <= 8.0:
            return '-5~-8%'
        return '-8% 초과'
    except Exception:
        return '손절가없음'


try:
    _V1082_BASE_SIGNAL_ROW_FROM_SERIES = _v1080_signal_row_from_series
except Exception:
    _V1082_BASE_SIGNAL_ROW_FROM_SERIES = None


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1082 wrapper: 기존 신호행에 스캐너 제시 손절가/손절폭을 추가한다."""
    try:
        base = _V1082_BASE_SIGNAL_ROW_FROM_SERIES(row, rank=rank, source=source) if _V1082_BASE_SIGNAL_ROW_FROM_SERIES else {}
    except Exception:
        base = {}
    try:
        entry = _v1080_num(base.get('entry_price', 0), 0.0) if '_v1080_num' in globals() else 0.0
        if entry <= 0:
            entry = _v1080_num(_v1080_first(row, ['현재가', 'Close', '종가', 'price'], 0), 0.0)
        stop_price = _v1082_extract_signal_stop_price(row, entry=entry)
        stop_pct = _v1082_valid_signal_stop_pct(entry, stop_price)
        base['signal_stop_price'] = round(float(stop_price), 4) if stop_price and stop_price > 0 else 0.0
        base['signal_stop_pct'] = round(float(stop_pct), 4) if not pd.isna(stop_pct) else ''
        base['signal_stop_bucket'] = _v1082_stop_bucket(stop_pct)
    except Exception:
        base.setdefault('signal_stop_price', 0.0)
        base.setdefault('signal_stop_pct', '')
        base.setdefault('signal_stop_bucket', '손절가없음')
    return base


def _v1082_first_event_with_stop(future: pd.DataFrame, entry: float, stop_threshold_pct: float) -> tuple:
    try:
        def ret(v):
            return (float(v) / entry - 1.0) * 100.0 if entry > 0 else 0.0
        for _, r in future.iterrows():
            close_v = r.get('Close', 0) if hasattr(r, 'get') else 0
            low_ret = ret(r.get('Low', close_v)) if hasattr(r, 'get') else 0.0
            high_ret = ret(r.get('High', close_v)) if hasattr(r, 'get') else 0.0
            # 보수 평가: 같은 날 목표와 손절이 모두 터지면 손절 우선
            if low_ret <= stop_threshold_pct:
                return 'stop', 'stop'
            if high_ret >= 5.0:
                return 'plus5', '+5'
            if high_ret >= 3.0:
                return 'plus3', '+3'
            if high_ret >= 2.0:
                return 'plus2', '+2'
        return 'none', ''
    except Exception:
        return 'none', ''


def _v1080_evaluate_one_signal(row, hold_days: int = 5, stop_pct: float = -5.0) -> dict:
    """V1082 override: 손절 기준을 V1082_BACKTEST_STOP_MODE에 따라 결정한다."""
    try:
        code = _v1080_norm_code(row.get('code', ''))
        sig_date = pd.to_datetime(row.get('signal_date'))
        entry = _v1080_num(row.get('entry_price', 0), 0)
        price_df = _v1080_fetch_price_after(code, sig_date, hold_days=hold_days)
        if price_df.empty:
            return {'eval_status': '가격데이터없음'}
        before_or_same = price_df[price_df.index <= sig_date]
        if entry <= 0 and not before_or_same.empty:
            entry = _v1080_num(before_or_same.iloc[-1].get('Close', 0), 0)
        if entry <= 0:
            return {'eval_status': '진입가없음'}
        future = price_df[price_df.index > sig_date].head(max(1, hold_days))
        if future.empty:
            return {'eval_status': '미래데이터부족'}
        closes = future['Close'] if 'Close' in future.columns else future.iloc[:, 0]
        highs = future['High'] if 'High' in future.columns else closes
        lows = future['Low'] if 'Low' in future.columns else closes
        def ret(v):
            return (float(v) / entry - 1.0) * 100.0 if entry > 0 else 0.0
        close1 = ret(closes.iloc[min(0, len(closes)-1)]) if len(closes) >= 1 else np.nan
        close3 = ret(closes.iloc[min(2, len(closes)-1)]) if len(closes) >= 1 else np.nan
        close5 = ret(closes.iloc[min(4, len(closes)-1)]) if len(closes) >= 1 else np.nan
        max_up = ret(highs.max())
        max_down = ret(lows.min())
        plus2_hit = bool(max_up >= 2.0)
        plus3_hit = bool(max_up >= 3.0)
        plus5_hit = bool(max_up >= 5.0)

        fixed_stop_pct = float(stop_pct if stop_pct is not None else -5.0)
        signal_stop_price = _v1080_num(row.get('signal_stop_price', 0), 0.0)
        if signal_stop_price <= 0:
            signal_stop_price = _v1082_extract_signal_stop_price(row, entry=entry)
        signal_stop_pct = _v1082_valid_signal_stop_pct(entry, signal_stop_price)
        signal_available = not pd.isna(signal_stop_pct)
        mode = _v1082_stop_mode()

        if mode == 'FIXED_PCT':
            stop_pct_used = fixed_stop_pct
            stop_basis = 'FIXED_PCT'
        elif mode == 'SIGNAL_STOP':
            if not signal_available:
                return {
                    'eval_status': '손절가없음',
                    'entry_price_eval': round(entry, 4),
                    'signal_stop_price_eval': 0.0,
                    'signal_stop_pct': '',
                    'signal_stop_bucket': '손절가없음',
                    'stop_mode_used': 'SIGNAL_STOP',
                }
            stop_pct_used = float(signal_stop_pct)
            stop_basis = 'SIGNAL_STOP'
        elif mode == 'BOTH_COMPARE':
            stop_pct_used = float(signal_stop_pct) if signal_available else fixed_stop_pct
            stop_basis = 'SIGNAL_STOP' if signal_available else 'FIXED_PCT_FALLBACK'
        else:
            stop_pct_used = float(signal_stop_pct) if signal_available else fixed_stop_pct
            stop_basis = 'SIGNAL_STOP' if signal_available else 'FIXED_PCT_FALLBACK'

        stop_hit = bool(max_down <= stop_pct_used)
        first_event, first_target = _v1082_first_event_with_stop(future, entry, stop_pct_used)
        plus3_first = first_event in ('plus3', 'plus5')
        plus5_first = first_event == 'plus5'
        stop_first = first_event == 'stop'

        fixed_event, fixed_target = _v1082_first_event_with_stop(future, entry, fixed_stop_pct)
        fixed_stop_hit = bool(max_down <= fixed_stop_pct)
        fixed_stop_first = fixed_event == 'stop'
        signal_event, signal_target = ('none', '')
        signal_stop_hit = False
        signal_stop_first = False
        if signal_available:
            signal_event, signal_target = _v1082_first_event_with_stop(future, entry, float(signal_stop_pct))
            signal_stop_hit = bool(max_down <= float(signal_stop_pct))
            signal_stop_first = signal_event == 'stop'

        return {
            'eval_status': 'OK',
            'entry_price_eval': round(entry, 4),
            'next1_close_ret': round(close1, 4),
            'next3_close_ret': round(close3, 4),
            'next5_close_ret': round(close5, 4),
            'max_up_5d': round(max_up, 4),
            'max_down_5d': round(max_down, 4),
            'plus2_hit': plus2_hit,
            'plus3_hit': plus3_hit,
            'plus5_hit': plus5_hit,
            'stop_hit': stop_hit,
            'plus3_first': plus3_first,
            'plus5_first': plus5_first,
            'stop_first': stop_first,
            'first_event': first_event,
            'first_target': first_target,
            'last_eval_date': future.index[-1].strftime('%Y-%m-%d'),
            'stop_mode_used': stop_basis,
            'stop_pct_used': round(float(stop_pct_used), 4),
            'fixed_stop_pct': round(float(fixed_stop_pct), 4),
            'signal_stop_price_eval': round(float(signal_stop_price), 4) if signal_available else 0.0,
            'signal_stop_pct': round(float(signal_stop_pct), 4) if signal_available else '',
            'signal_stop_bucket': _v1082_stop_bucket(signal_stop_pct),
            'signal_stop_available': bool(signal_available),
            'fixed_stop_hit': fixed_stop_hit,
            'fixed_stop_first': fixed_stop_first,
            'fixed_first_event': fixed_event,
            'signal_stop_hit': signal_stop_hit,
            'signal_stop_first': signal_stop_first,
            'signal_first_event': signal_event,
        }
    except Exception as e:
        return {'eval_status': f'평가오류:{e}'}


try:
    _V1082_BASE_BUILD_WEEKLY_REPORT = _v1080_build_weekly_report
except Exception:
    _V1082_BASE_BUILD_WEEKLY_REPORT = None


def _v1082_stop_compare_lines(ok: pd.DataFrame) -> list:
    lines = []
    try:
        if ok is None or ok.empty:
            return lines
        lines.append('[손절 기준]')
        lines.append(f"- 현재 기준: {_v1082_stop_mode_label()}")
        if 'signal_stop_available' in ok.columns:
            avail = pd.Series(ok['signal_stop_available']).astype(bool).mean() * 100.0
            lines.append(f"- 스캐너 손절가 확보율: {avail:.1f}%")
        lines.append('')
        if 'signal_stop_bucket' in ok.columns:
            tmp = ok.copy()
            tmp['signal_stop_bucket'] = tmp['signal_stop_bucket'].astype(str).replace({'': '손절가없음', 'nan': '손절가없음', 'None': '손절가없음'})
            tab = _v1080_summary_table(tmp, 'signal_stop_bucket') if '_v1080_summary_table' in globals() else pd.DataFrame()
            if tab is not None and not tab.empty:
                order = {'-3% 이내': 0, '-3~-5%': 1, '-5~-8%': 2, '-8% 초과': 3, '손절가없음': 4}
                tab['_sort'] = tab['signal_stop_bucket'].map(order).fillna(9)
                tab = tab.sort_values(['_sort', '검증수'], ascending=[True, False]).drop(columns=['_sort'])
                lines += _v1080_table_lines('손절가 거리별', tab, max_rows=10)
        if _v1082_stop_mode() == 'BOTH_COMPARE' and {'fixed_stop_first', 'signal_stop_first'} <= set(ok.columns):
            fixed_rate = _v1080_rate(ok['fixed_stop_first']) if '_v1080_rate' in globals() else 0.0
            sig_avail = ok[ok['signal_stop_available'].astype(bool)] if 'signal_stop_available' in ok.columns else ok
            signal_rate = _v1080_rate(sig_avail['signal_stop_first']) if not sig_avail.empty and '_v1080_rate' in globals() else 0.0
            lines.append('[손절 기준 비교]')
            lines.append(f"- 고정손절 기준 손절먼저: {fixed_rate:.1f}%")
            lines.append(f"- 스캐너 손절가 기준 손절먼저: {signal_rate:.1f}%")
            lines.append('- BOTH_COMPARE에서는 전체 요약은 스캐너 손절가 우선/없으면 고정손절 기준으로 계산합니다.')
            lines.append('')
    except Exception:
        pass
    return lines


def _v1080_build_weekly_report(eval_df: pd.DataFrame, weeks: int = 8) -> str:
    """V1082 wrapper: 기존 주간 리포트에 손절 기준/손절가 거리별 분석을 추가한다."""
    try:
        base = _V1082_BASE_BUILD_WEEKLY_REPORT(eval_df, weeks=weeks) if _V1082_BASE_BUILD_WEEKLY_REPORT else ''
        if eval_df is None or eval_df.empty:
            return base
        ok = eval_df[eval_df.get('eval_status', '') == 'OK'].copy()
        if ok.empty:
            try:
                status_counts = eval_df.get('eval_status', pd.Series(dtype=str)).astype(str).value_counts().to_dict()
                status_line = ' | '.join([f'{k}:{v}개' for k, v in list(status_counts.items())[:6]])
                extra = f"\n- 평가제외 사유: {status_line}" if status_line else ''
            except Exception:
                extra = ''
            return base + f"\n\n[손절 기준]\n- 현재 기준: {_v1082_stop_mode_label()}{extra}"
        add = _v1082_stop_compare_lines(ok)
        if add:
            # 전체 블록 바로 다음에 붙이지 않고 리포트 후반에 추가해 기존 구조를 깨지 않는다.
            base = str(base or '').rstrip() + '\n\n' + '\n'.join(add).strip()
        return base.strip()
    except Exception as e:
        return f'🧪 [V1080 주간 성과검증]\n- 리포트 생성 실패: {e}'


# =============================================================
# ✅ V1083_BACKTEST_QUALITY_FIX_ACTIVE
# - V1081/V1082 직접 재현 성과검증의 신뢰도 보정판
# - 손절가 확보율 0% 문제 보정: 🚨손절가/무효가격/실행기준선 추출 + 가격데이터 기반 구조 손절선 계산
# - DROP/PASS_A를 그대로 튜닝하지 않도록 후보범위(candidate_scope)와 판정품질(final_decision_quality) 추가
# - 평균 왜곡 방지: 중앙값/절사평균/최고·최저 제외평균/상하위 아웃라이어 표시
# - 거래량상태/가짜수박 강도 보강 및 표본 부족 경고 추가
# =============================================================
print("✅ V1083_BACKTEST_QUALITY_FIX_ACTIVE LOADED")

try:
    os.environ.setdefault('V1083_BACKTEST_QUALITY_FIX', '1')
    os.environ.setdefault('V1083_CALC_STRUCTURE_STOP', '1')
    os.environ.setdefault('V1083_MIN_SAMPLE_WARN', '3')
except Exception:
    pass


def _v1083_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return str(default).strip().lower() in ('1', 'true', 'yes', 'y', 'on')


def _v1083_num(v, default: float = 0.0) -> float:
    try:
        return _v1080_num(v, default) if '_v1080_num' in globals() else float(str(v).replace(',', '').replace('%', '').replace('원', '').strip())
    except Exception:
        return default


def _v1083_s(v, default: str = '') -> str:
    try:
        return _v1080_s(v, default) if '_v1080_s' in globals() else str(v or '').strip()
    except Exception:
        return default


def _v1083_price_from_any(v, entry: float = 0.0) -> float:
    try:
        if '_v1082_parse_price_text' in globals():
            p = _v1082_parse_price_text(v, entry=entry)
            if p > 0:
                return float(p)
        p = _v1083_num(v, 0.0)
        return float(p) if p > 0 else 0.0
    except Exception:
        return 0.0


def _v1083_valid_stop(entry: float, stop_price: float, loose: bool = False) -> bool:
    try:
        entry = float(entry or 0)
        stop_price = float(stop_price or 0)
        if entry <= 0 or stop_price <= 0:
            return False
        pct = (stop_price / entry - 1.0) * 100.0
        # 명시 손절은 -30%까지, 계산 구조 손절은 너무 먼 선을 피하기 위해 -18%까지 허용
        min_pct = -30.0 if loose else -18.0
        return (pct < -0.1) and (pct >= min_pct)
    except Exception:
        return False


def _v1083_extract_explicit_stop(row, entry: float = 0.0) -> tuple:
    """명시 손절가 추출. V1082에서 빠졌던 🚨손절가/무효가격 계열을 우선 반영한다."""
    keys = [
        '🚨손절가', '손절가', '손절가격', '손절선', '기준손절가', '하단손절가', '실행손절가',
        '무효가격', '무효가', '무효화가격', '파동무효화', '와이코프무효', 'invalid_price',
        'stop_price', 'stop_loss', 'stop_loss_price', 'StopLoss', 'StopPrice', 'loss_cut_price', 'cut_loss_price',
        '손절', '스탑', '스탑로스', '리스크기준가'
    ]
    try:
        for k in keys:
            try:
                v = row.get(k, '') if hasattr(row, 'get') else row[k]
            except Exception:
                continue
            p = _v1083_price_from_any(v, entry=entry)
            if _v1083_valid_stop(entry, p, loose=True):
                return float(p), f'EXPLICIT:{k}'
        text_keys = [
            '최종판정', '매매판정', '진입전략', '해석', 'comment', 'reason', '리스크', '무효조건',
            '오늘매매관점', '압축코멘트', 'AI코멘트', '메모', 'price_line', '가격', '목표손절'
        ]
        for k in text_keys:
            try:
                v = row.get(k, '') if hasattr(row, 'get') else row[k]
            except Exception:
                continue
            p = _v1083_price_from_any(v, entry=entry)
            if _v1083_valid_stop(entry, p, loose=True):
                return float(p), f'TEXT:{k}'
    except Exception:
        pass
    return 0.0, ''


def _v1083_calc_structure_stop_from_row(row, entry: float = 0.0) -> tuple:
    """후보 행의 구조가격 컬럼에서 계산형 손절선을 만든다. 가장 가까운 유효 하단선을 선택한다."""
    if not _v1083_on('V1083_CALC_STRUCTURE_STOP', '1'):
        return 0.0, ''
    keys = [
        '실행기준선', '파란점선', 'blue_line', 'execution_line', 'entry_line', '기준선',
        '무효가격', '파동무효화', '와이코프무효', '전일저가', '전저점', '최근저점', '박스하단', '눌림하단',
        'MA5', 'MA_5', 'ma5', 'MA10', 'MA_10', 'ma10', 'MA20', 'MA_20', 'ma20',
        'BB20_Lower', 'BB40_Lower', 'bb20_lower', 'bb40_lower', 'lower20', 'lower40', 'Env20_Lower', 'Env40_Lower'
    ]
    cands = []
    try:
        for k in keys:
            try:
                v = row.get(k, '') if hasattr(row, 'get') else row[k]
            except Exception:
                continue
            p = _v1083_price_from_any(v, entry=entry)
            if _v1083_valid_stop(entry, p, loose=False):
                pct = (float(p) / float(entry) - 1.0) * 100.0
                cands.append((float(p), pct, f'ROW:{k}'))
        if cands:
            # 실전 손절은 가장 가까운 하단선이 기본. 너무 먼 구조선은 후순위가 된다.
            cands = sorted(cands, key=lambda x: x[0], reverse=True)
            return cands[0][0], cands[0][2]
    except Exception:
        pass
    return 0.0, ''


def _v1083_calc_structure_stop_from_price_df(price_df: pd.DataFrame, sig_date, entry: float = 0.0) -> tuple:
    """가격 데이터만 있을 때 신호일 이전 데이터로 구조 손절선을 계산한다."""
    if not _v1083_on('V1083_CALC_STRUCTURE_STOP', '1'):
        return 0.0, ''
    try:
        if price_df is None or price_df.empty or entry <= 0:
            return 0.0, ''
        sig_ts = pd.to_datetime(sig_date)
        hist = price_df.copy()
        hist.index = pd.to_datetime(hist.index)
        hist = hist[hist.index <= sig_ts].sort_index().tail(80)
        if hist.empty:
            return 0.0, ''
        close = pd.to_numeric(hist.get('Close', hist.iloc[:, 0]), errors='coerce')
        low = pd.to_numeric(hist.get('Low', close), errors='coerce')
        cands = []
        def add(name, value):
            try:
                p = float(value)
                if _v1083_valid_stop(entry, p, loose=False):
                    cands.append((p, (p / float(entry) - 1.0) * 100.0, name))
            except Exception:
                pass
        # 최근 저점/단기 이평/20일선 기준. 값이 진입가 아래일 때만 사용한다.
        if len(low.dropna()) >= 1:
            add('CALC:전일/신호일저가', low.dropna().iloc[-1])
            add('CALC:최근3일저가', low.dropna().tail(3).min())
            add('CALC:최근5일저가', low.dropna().tail(5).min())
        if len(close.dropna()) >= 5:
            add('CALC:MA5', close.rolling(5).mean().iloc[-1])
        if len(close.dropna()) >= 10:
            add('CALC:MA10', close.rolling(10).mean().iloc[-1])
        if len(close.dropna()) >= 20:
            ma20 = close.rolling(20).mean().iloc[-1]
            std20 = close.rolling(20).std().iloc[-1]
            add('CALC:MA20', ma20)
            if pd.notna(ma20) and pd.notna(std20):
                add('CALC:BB20하단', ma20 - 2 * std20)
        if len(close.dropna()) >= 40:
            ma40 = close.rolling(40).mean().iloc[-1]
            std40 = close.rolling(40).std().iloc[-1]
            if pd.notna(ma40) and pd.notna(std40):
                add('CALC:BB40하단', ma40 - 2 * std40)
        if not cands:
            return 0.0, ''
        # 가장 가까운 유효 하단선 선택. 단, -0.3% 같은 너무 타이트한 값은 valid에서 제외된다.
        cands = sorted(cands, key=lambda x: x[0], reverse=True)
        return float(cands[0][0]), cands[0][2]
    except Exception:
        return 0.0, ''


def _v1083_stop_pct(entry: float, stop_price: float):
    try:
        if '_v1082_valid_signal_stop_pct' in globals():
            return _v1082_valid_signal_stop_pct(entry, stop_price)
        return (float(stop_price) / float(entry) - 1.0) * 100.0
    except Exception:
        return float('nan')


def _v1083_refine_volume_state(row, current: str = '') -> str:
    try:
        raw = ' '.join(_v1083_s(row.get(k, '')) for k in ['거래량상태','거래량판정','거래량응축상태','볼륨상태','거래량분류','N구분','검색패턴','최종판정','매매판정'] if hasattr(row, 'get'))
        if '거래량실패' in raw or '거래량 실패' in raw:
            return '거래량실패(위험)'
        if '거래량부족' in raw or '거래량 부족' in raw:
            return '거래량부족(주의)'
        if '거래량응축' in raw or '거래량 응축' in raw or '응축(양호)' in raw:
            return '거래량응축(양호)'
        vol_ratio = 0.0
        for k in ['거래량배율','거래량비율','VolumeRatio','VolRatio','volume_ratio','매집거래량배율','VRatio']:
            if hasattr(row, 'get') and k in row:
                vol_ratio = _v1083_num(row.get(k), 0.0)
                if vol_ratio > 0:
                    break
        if vol_ratio > 0:
            if vol_ratio >= 2.0:
                return '거래량유입(강)'
            if vol_ratio >= 1.3:
                return '거래량유입(확인)'
            if vol_ratio >= 0.7:
                return '거래량응축(양호)'
            if vol_ratio >= 0.4:
                return '거래량부족(주의)'
            return '거래량실패(위험)'
        return current or '미분류'
    except Exception:
        return current or '미분류'


def _v1083_refine_fake_severity(row, current: str = '') -> str:
    try:
        raw = ' '.join(_v1083_s(row.get(k, '')) for k in ['가짜수박강도','가짜수박','fake_severity','fake_label','수박정제태그','정제','N구분','최종판정','매매판정','검색패턴'] if hasattr(row, 'get'))
        if any(k in raw for k in ['가짜수박 강', '가짜수박강', '강위험', '강(위험)', 'strong']):
            return '가짜수박 강'
        if any(k in raw for k in ['가짜수박 중', '가짜수박중', '중주의', '중(주의)', 'medium']):
            return '가짜수박 중'
        if any(k in raw for k in ['가짜수박 약', '가짜수박약', '약주의', '약(주의)', 'weak']):
            return '가짜수박 약'
        if '가짜수박' in raw:
            return '가짜수박 미세분류'
        return current or '해당없음'
    except Exception:
        return current or '해당없음'


def _v1083_candidate_scope(row) -> str:
    try:
        raw = ' '.join(_v1083_s(row.get(k, '')) for k in ['final_decision','phase','strategy','pattern','decision_mode','최종판정','추천단계','매매판정'] if hasattr(row, 'get'))
        if any(k in raw for k in ['PASS_A', 'S-CORE SAFE', 'SCORE SAFE', '실전후보', '조건부 실행', '분할진입', 'AI Pick']):
            return '실전후보'
        if any(k in raw for k in ['PASS_B', 'PASS_C', '관찰', '회복 확인', '회복확인', '눌림 확인', '눌림대기', 'NEUTRAL']):
            return '관찰후보'
        if any(k in raw for k in ['DROP', '제외', '보류', '신규진입 보류', '추격 금지', 'RISK', '위험']):
            return '필터탈락/보류'
        return '원후보/미판정'
    except Exception:
        return '원후보/미판정'


def _v1083_final_decision_quality(row) -> str:
    try:
        fd = _v1083_s(row.get('final_decision', '') if hasattr(row, 'get') else '')
        src = _v1083_s(row.get('source', '') if hasattr(row, 'get') else '')
        if src == 'DIRECT_REPLAY' and fd.upper() == 'DROP':
            return 'DROP기본값가능성/직접검증주의'
        if not fd or fd in ('미분류', 'nan', 'None'):
            return '최종판정없음'
        return '명시판정'
    except Exception:
        return '판정품질미상'


try:
    _V1083_BASE_SIGNAL_ROW_FROM_SERIES = _v1080_signal_row_from_series
except Exception:
    _V1083_BASE_SIGNAL_ROW_FROM_SERIES = None


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1083 wrapper: 손절가 추출, 후보범위, 거래량/가짜수박 세분류, 판정품질을 보강한다."""
    try:
        base = _V1083_BASE_SIGNAL_ROW_FROM_SERIES(row, rank=rank, source=source) if _V1083_BASE_SIGNAL_ROW_FROM_SERIES else {}
    except Exception:
        base = {}
    try:
        entry = _v1083_num(base.get('entry_price', 0), 0.0)
        if entry <= 0 and hasattr(row, 'get'):
            entry = _v1083_num(row.get('현재가', row.get('Close', row.get('종가', 0))), 0.0)
        explicit_stop, explicit_src = _v1083_extract_explicit_stop(row, entry=entry)
        calc_stop, calc_src = (0.0, '')
        if explicit_stop <= 0:
            calc_stop, calc_src = _v1083_calc_structure_stop_from_row(row, entry=entry)
        stop_price = explicit_stop if explicit_stop > 0 else calc_stop
        stop_src = explicit_src if explicit_stop > 0 else calc_src
        stop_pct = _v1083_stop_pct(entry, stop_price)
        if stop_price > 0 and not pd.isna(stop_pct):
            base['signal_stop_price'] = round(float(stop_price), 4)
            base['signal_stop_pct'] = round(float(stop_pct), 4)
            base['signal_stop_bucket'] = _v1082_stop_bucket(stop_pct) if '_v1082_stop_bucket' in globals() else ''
            base['signal_stop_source'] = stop_src or 'V1083_STOP'
        else:
            base.setdefault('signal_stop_price', 0.0)
            base.setdefault('signal_stop_pct', '')
            base.setdefault('signal_stop_bucket', '손절가없음')
            base.setdefault('signal_stop_source', '손절가없음')
        # row의 원본 분류를 다시 한 번 보강
        if hasattr(row, 'get'):
            base['volume_state'] = _v1083_refine_volume_state(row, base.get('volume_state', '미분류'))
            base['fake_severity'] = _v1083_refine_fake_severity(row, base.get('fake_severity', '해당없음'))
        base['candidate_scope'] = _v1083_candidate_scope(base)
        base['final_decision_quality'] = _v1083_final_decision_quality(base)
        if int(rank or 0) <= int(os.environ.get('V1083_MIN_SAMPLE_WARN', '3') or 3):
            base.setdefault('sample_note', '')
    except Exception:
        base.setdefault('candidate_scope', '원후보/미판정')
        base.setdefault('final_decision_quality', '판정품질미상')
    return base


try:
    _V1083_BASE_EVALUATE_ONE_SIGNAL = _v1080_evaluate_one_signal
except Exception:
    _V1083_BASE_EVALUATE_ONE_SIGNAL = None


def _v1080_evaluate_one_signal(row, hold_days: int = 5, stop_pct: float = -5.0) -> dict:
    """V1083 wrapper: 명시 손절가가 없으면 신호일 이전 가격데이터로 구조 손절선을 계산해 V1082 평가에 넘긴다."""
    try:
        work = dict(row or {})
        code = _v1080_norm_code(work.get('code', '')) if '_v1080_norm_code' in globals() else str(work.get('code', ''))
        sig_date = pd.to_datetime(work.get('signal_date'))
        entry = _v1083_num(work.get('entry_price', 0), 0.0)
        price_df = _v1080_fetch_price_after(code, sig_date, hold_days=hold_days) if '_v1080_fetch_price_after' in globals() else pd.DataFrame()
        if entry <= 0 and price_df is not None and not price_df.empty:
            before = price_df[pd.to_datetime(price_df.index) <= sig_date]
            if not before.empty:
                entry = _v1083_num(before.iloc[-1].get('Close', 0), 0.0)
                work['entry_price'] = entry
        # explicit → row 계산 → 가격데이터 계산 순서
        existing_stop = _v1083_num(work.get('signal_stop_price', 0), 0.0)
        existing_pct = _v1083_stop_pct(entry, existing_stop)
        if not _v1083_valid_stop(entry, existing_stop, loose=True):
            explicit_stop, explicit_src = _v1083_extract_explicit_stop(work, entry=entry)
            row_stop, row_src = (0.0, '')
            calc_stop, calc_src = (0.0, '')
            if explicit_stop <= 0:
                row_stop, row_src = _v1083_calc_structure_stop_from_row(work, entry=entry)
            if explicit_stop <= 0 and row_stop <= 0 and price_df is not None and not price_df.empty:
                calc_stop, calc_src = _v1083_calc_structure_stop_from_price_df(price_df, sig_date, entry=entry)
            stop_price = explicit_stop if explicit_stop > 0 else (row_stop if row_stop > 0 else calc_stop)
            stop_src = explicit_src if explicit_stop > 0 else (row_src if row_stop > 0 else calc_src)
            if _v1083_valid_stop(entry, stop_price, loose=True):
                stop_pct2 = _v1083_stop_pct(entry, stop_price)
                work['signal_stop_price'] = round(float(stop_price), 4)
                work['signal_stop_pct'] = round(float(stop_pct2), 4) if not pd.isna(stop_pct2) else ''
                work['signal_stop_bucket'] = _v1082_stop_bucket(stop_pct2) if '_v1082_stop_bucket' in globals() else ''
                work['signal_stop_source'] = stop_src or 'CALC:STRUCTURE'
        ev = _V1083_BASE_EVALUATE_ONE_SIGNAL(work, hold_days=hold_days, stop_pct=stop_pct) if _V1083_BASE_EVALUATE_ONE_SIGNAL else {}
        if isinstance(ev, dict):
            ev.setdefault('signal_stop_source', work.get('signal_stop_source', '손절가없음'))
            ev.setdefault('candidate_scope', work.get('candidate_scope', '원후보/미판정'))
            ev.setdefault('final_decision_quality', work.get('final_decision_quality', '판정품질미상'))
            if 'signal_stop_source' in work and work.get('signal_stop_source') not in ('', '손절가없음'):
                ev['signal_stop_source'] = work.get('signal_stop_source')
        return ev
    except Exception as e:
        try:
            return _V1083_BASE_EVALUATE_ONE_SIGNAL(row, hold_days=hold_days, stop_pct=stop_pct) if _V1083_BASE_EVALUATE_ONE_SIGNAL else {'eval_status': f'평가오류:{e}'}
        except Exception:
            return {'eval_status': f'평가오류:{e}'}


def _v1083_trimmed_mean(s, pct: float = 0.10):
    try:
        vals = pd.to_numeric(pd.Series(s), errors='coerce').dropna().sort_values().to_list()
        n = len(vals)
        if n == 0:
            return float('nan')
        k = int(n * pct)
        if k > 0 and n > 2 * k:
            vals = vals[k:n-k]
        return float(pd.Series(vals).mean())
    except Exception:
        return float('nan')


def _v1083_excl_extreme_mean(s):
    try:
        vals = pd.to_numeric(pd.Series(s), errors='coerce').dropna().sort_values().to_list()
        if len(vals) <= 2:
            return float(pd.Series(vals).mean()) if vals else float('nan')
        return float(pd.Series(vals[1:-1]).mean())
    except Exception:
        return float('nan')


def _v1083_fmt_pct(v):
    try:
        if pd.isna(v):
            return '-'
        return f'{float(v):+.2f}%'
    except Exception:
        return '-'


def _v1083_quality_lines(eval_df: pd.DataFrame) -> list:
    lines = []
    try:
        if eval_df is None or eval_df.empty:
            return lines
        ok = eval_df[eval_df.get('eval_status', '') == 'OK'].copy()
        if ok.empty:
            return lines
        n = len(ok)
        lines.append('[V1083 성과검증 품질진단]')
        # 손절 확보율/출처
        if 'signal_stop_available' in ok.columns:
            avail = pd.Series(ok['signal_stop_available']).astype(bool).mean() * 100.0
        elif 'signal_stop_price_eval' in ok.columns:
            avail = (pd.to_numeric(ok['signal_stop_price_eval'], errors='coerce').fillna(0) > 0).mean() * 100.0
        else:
            avail = 0.0
        src_counts = {}
        if 'signal_stop_source' in ok.columns:
            src_counts = ok['signal_stop_source'].astype(str).replace({'': '손절가없음'}).value_counts().head(4).to_dict()
        src_txt = ' / '.join([f'{k}:{v}개' for k, v in src_counts.items()]) if src_counts else '출처없음'
        lines.append(f'- 손절가 확보율: {avail:.1f}% | 출처: {src_txt}')
        # DROP 편중 경고
        if 'final_decision' in ok.columns:
            fd = ok['final_decision'].astype(str).fillna('')
            drop_rate = fd.str.upper().eq('DROP').mean() * 100.0
            lines.append(f'- DROP 비중: {drop_rate:.1f}%')
            if drop_rate >= 70.0:
                lines.append('  ↳ DROP이 70% 이상이면 “DROP이 좋다/나쁘다”로 튜닝하지 말고 최종판정 매핑을 먼저 점검하세요.')
        # 후보범위별
        if 'candidate_scope' in ok.columns and '_v1080_summary_table' in globals():
            tab = _v1080_summary_table(ok, 'candidate_scope')
            if tab is not None and not tab.empty:
                lines += _v1080_table_lines('후보범위별', tab, max_rows=8)
        # 판정품질
        if 'final_decision_quality' in ok.columns and '_v1080_summary_table' in globals():
            tab = _v1080_summary_table(ok, 'final_decision_quality')
            if tab is not None and not tab.empty:
                lines += _v1080_table_lines('최종판정 품질별', tab, max_rows=6)
        # 수익률 분포 보정
        ret5 = pd.to_numeric(ok.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').dropna()
        if len(ret5) > 0:
            mean_v = ret5.mean()
            med_v = ret5.median()
            trim_v = _v1083_trimmed_mean(ret5, 0.10)
            ex_v = _v1083_excl_extreme_mean(ret5)
            lines.append('[수익률 분포 보정]')
            lines.append(f'- 5일 평균 {_v1083_fmt_pct(mean_v)} | 중앙값 {_v1083_fmt_pct(med_v)} | 10% 절사평균 {_v1083_fmt_pct(trim_v)} | 최고·최저 제외평균 {_v1083_fmt_pct(ex_v)}')
            try:
                best = ok.loc[pd.to_numeric(ok['next5_close_ret'], errors='coerce').idxmax()]
                worst = ok.loc[pd.to_numeric(ok['next5_close_ret'], errors='coerce').idxmin()]
                bname = f"{best.get('name','-')}({best.get('code','-')})"
                wname = f"{worst.get('name','-')}({worst.get('code','-')})"
                lines.append(f"- 최고수익: {bname} {float(best.get('next5_close_ret',0)):+.2f}% | 최저수익: {wname} {float(worst.get('next5_close_ret',0)):+.2f}%")
            except Exception:
                pass
        # 표본 부족 전략 경고
        min_n = int(float(os.environ.get('V1083_MIN_SAMPLE_WARN', '3') or 3))
        if 'strategy' in ok.columns:
            vc = ok['strategy'].astype(str).replace({'': '미분류'}).value_counts()
            small = vc[(vc > 0) & (vc < min_n)].head(8)
            if not small.empty:
                txt = ', '.join([f'{k}({int(v)}개)' for k, v in small.items()])
                lines.append('[표본 부족 주의]')
                lines.append(f'- {min_n}개 미만 전략은 참고만 보세요: {txt}')
        lines.append('[V1083 해석 원칙]')
        lines.append('- 평균수익률보다 중앙값·손절먼저·표본수·손절가 확보율을 함께 봐야 합니다.')
        lines.append('- 손절가 확보율이 낮으면 SIGNAL_STOP 성과가 아니라 계산/fallback 성과일 수 있습니다.')
        lines.append('- DROP 편중이 크면 전략 성과보다 최종판정 매핑 품질을 먼저 보정해야 합니다.')
        lines.append('')
    except Exception as e:
        try:
            lines.append(f'[V1083 성과검증 품질진단]\n- 생성 실패: {e}')
        except Exception:
            pass
    return lines


try:
    _V1083_BASE_BUILD_WEEKLY_REPORT = _v1080_build_weekly_report
except Exception:
    _V1083_BASE_BUILD_WEEKLY_REPORT = None


def _v1080_build_weekly_report(eval_df: pd.DataFrame, weeks: int = 8) -> str:
    """V1083 wrapper: 기존 리포트에 품질진단/분포보정/후보범위 분석을 추가한다."""
    try:
        base = _V1083_BASE_BUILD_WEEKLY_REPORT(eval_df, weeks=weeks) if _V1083_BASE_BUILD_WEEKLY_REPORT else ''
        if not _v1083_on('V1083_BACKTEST_QUALITY_FIX', '1'):
            return base
        add = _v1083_quality_lines(eval_df)
        if add:
            return str(base or '').rstrip() + '\n\n' + '\n'.join(add).strip()
        return base
    except Exception as e:
        try:
            return _V1083_BASE_BUILD_WEEKLY_REPORT(eval_df, weeks=weeks) if _V1083_BASE_BUILD_WEEKLY_REPORT else f'🧪 [V1083 성과검증]\n- 리포트 생성 실패: {e}'
        except Exception:
            return f'🧪 [V1083 성과검증]\n- 리포트 생성 실패: {e}'

