print("✅ V1084_DIRECT_REPLAY_REPORT_HOOK_FIX_ACTIVE LOADED")

try:
    os.environ.setdefault('V1084_DIRECT_REPORT_HOOK_FIX', '1')
    os.environ.setdefault('V1084_FORCE_QUALITY_BLOCK', '1')
    os.environ.setdefault('V1084_REPORT_TITLE', 'V1084 직접 재현 주간 성과검증')
except Exception:
    pass


def _v1084_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return str(default).strip().lower() in ('1', 'true', 'yes', 'y', 'on')


def _v1084_s(v, default: str = '') -> str:
    try:
        if '_v1083_s' in globals():
            return _v1083_s(v, default)
        if '_v1080_s' in globals():
            return _v1080_s(v, default)
        return str(v if v is not None else default).strip()
    except Exception:
        return default


def _v1084_num(v, default: float = 0.0) -> float:
    try:
        if '_v1083_num' in globals():
            return _v1083_num(v, default)
        if '_v1080_num' in globals():
            return _v1080_num(v, default)
        return float(str(v).replace(',', '').replace('%', '').replace('원', '').strip())
    except Exception:
        return default


def _v1084_recompute_quality_columns(df: pd.DataFrame) -> pd.DataFrame:
    """V1084: 직접 재현검증 결과에 후보범위/판정품질/손절출처 컬럼을 후처리로 확실히 보강한다."""
    try:
        if df is None or df.empty:
            return pd.DataFrame() if df is None else df
        out = df.copy()
        # 후보범위는 V1083 함수가 있으면 재사용하되, DIRECT_REPLAY 후처리 컬럼까지 반영한다.
        def scope(row):
            try:
                raw = ' '.join(_v1084_s(row.get(k, '')) for k in [
                    'candidate_scope','final_decision','phase','strategy','pattern','decision_mode','최종판정','추천단계','매매판정'
                ] if hasattr(row, 'get'))
                if any(k in raw for k in ['실전후보', 'PASS_A', 'S-CORE SAFE', 'SCORE SAFE', '조건부 실행', '분할진입', 'AI Pick']):
                    return '실전후보'
                if any(k in raw for k in ['관찰후보', 'PASS_B', 'PASS_C', '관찰', '회복 확인', '회복확인', '눌림 확인', '눌림대기', 'NEUTRAL']):
                    return '관찰후보'
                if any(k in raw for k in ['필터탈락', 'DROP', '제외', '보류', '신규진입 보류', '추격 금지', 'RISK', '위험']):
                    return '필터탈락/보류'
                return '원후보/미판정'
            except Exception:
                return '원후보/미판정'
        def quality(row):
            try:
                fd = _v1084_s(row.get('final_decision', '') if hasattr(row, 'get') else '')
                src = _v1084_s(row.get('source', '') if hasattr(row, 'get') else '')
                if src == 'DIRECT_REPLAY' and fd.upper() == 'DROP':
                    return 'DROP기본값가능성/직접검증주의'
                if not fd or fd.lower() in ('nan', 'none') or fd == '미분류':
                    return '최종판정없음'
                return '명시판정'
            except Exception:
                return '판정품질미상'
        try:
            out['candidate_scope'] = out.apply(scope, axis=1)
        except Exception:
            if 'candidate_scope' not in out.columns:
                out['candidate_scope'] = '원후보/미판정'
        try:
            out['final_decision_quality'] = out.apply(quality, axis=1)
        except Exception:
            if 'final_decision_quality' not in out.columns:
                out['final_decision_quality'] = '판정품질미상'
        # 손절가 출처/확보율 표시 보정. V1083 계산형 손절이 있는 경우 availability가 빠져도 복원한다.
        try:
            if 'signal_stop_price_eval' in out.columns:
                stop_eval = pd.to_numeric(out['signal_stop_price_eval'], errors='coerce').fillna(0)
            elif 'signal_stop_price' in out.columns:
                stop_eval = pd.to_numeric(out['signal_stop_price'], errors='coerce').fillna(0)
                out['signal_stop_price_eval'] = stop_eval
            else:
                stop_eval = pd.Series([0] * len(out), index=out.index)
                out['signal_stop_price_eval'] = stop_eval
            if 'signal_stop_available' not in out.columns:
                out['signal_stop_available'] = stop_eval > 0
            else:
                out['signal_stop_available'] = pd.Series(out['signal_stop_available']).astype(bool) | (stop_eval > 0)
            if 'signal_stop_source' not in out.columns:
                out['signal_stop_source'] = '손절가없음'
            out.loc[(out['signal_stop_available'].astype(bool)) & (out['signal_stop_source'].astype(str).isin(['', 'nan', 'None', '손절가없음'])), 'signal_stop_source'] = 'V1084:손절가확인'
            if 'signal_stop_bucket' not in out.columns and 'signal_stop_pct' in out.columns:
                try:
                    out['signal_stop_bucket'] = out['signal_stop_pct'].map(lambda x: _v1082_stop_bucket(x) if '_v1082_stop_bucket' in globals() else '손절가확인')
                except Exception:
                    out['signal_stop_bucket'] = '손절가확인'
        except Exception:
            pass
        # 거래량/가짜수박 후처리도 빠져 있으면 보강한다.
        try:
            if '_v1083_refine_volume_state' in globals():
                out['volume_state'] = out.apply(lambda r: _v1083_refine_volume_state(r, _v1084_s(r.get('volume_state','미분류'))), axis=1)
        except Exception:
            pass
        try:
            if '_v1083_refine_fake_severity' in globals():
                out['fake_severity'] = out.apply(lambda r: _v1083_refine_fake_severity(r, _v1084_s(r.get('fake_severity','해당없음'))), axis=1)
        except Exception:
            pass
        return out
    except Exception:
        return df


def _v1084_quality_lines(eval_df: pd.DataFrame) -> list:
    """V1084: 리포트에 반드시 들어갈 품질진단 라인. V1083 라인을 재사용하되, 누락 시 자체 생성한다."""
    lines = []
    try:
        if eval_df is None or eval_df.empty:
            return lines
        work = _v1084_recompute_quality_columns(eval_df)
        ok = work[work.get('eval_status', '') == 'OK'].copy()
        if ok.empty:
            return lines
        lines.append('[V1084 성과검증 품질진단]')
        n = len(ok)
        # 손절가 확보율
        if 'signal_stop_available' in ok.columns:
            avail = pd.Series(ok['signal_stop_available']).astype(bool).mean() * 100.0
        elif 'signal_stop_price_eval' in ok.columns:
            avail = (pd.to_numeric(ok['signal_stop_price_eval'], errors='coerce').fillna(0) > 0).mean() * 100.0
        else:
            avail = 0.0
        src_txt = '출처없음'
        try:
            vc = ok.get('signal_stop_source', pd.Series(['손절가없음'] * len(ok))).astype(str).replace({'': '손절가없음', 'nan': '손절가없음', 'None': '손절가없음'}).value_counts().head(5)
            if not vc.empty:
                src_txt = ' / '.join([f'{k}:{int(v)}개' for k, v in vc.items()])
        except Exception:
            pass
        lines.append(f'- 손절가 확보율: {avail:.1f}% | 출처: {src_txt}')
        if avail <= 0.0:
            lines.append('  ↳ 손절가 확보율 0%면 현재 손절먼저는 사실상 고정손절/fallback 기준입니다. 손절가 컬럼 추출 또는 구조손절 계산을 먼저 점검하세요.')
        # DROP/PASS 편중
        try:
            fd = ok.get('final_decision', pd.Series([''] * len(ok))).astype(str)
            drop_rate = fd.str.upper().eq('DROP').mean() * 100.0
            pass_a_rate = fd.str.upper().eq('PASS_A').mean() * 100.0
            lines.append(f'- DROP 비중: {drop_rate:.1f}% | PASS_A 비중: {pass_a_rate:.1f}%')
            if drop_rate >= 70.0:
                lines.append('  ↳ DROP 편중이 크면 직접검증 원후보가 DROP 기본값으로 들어갔을 가능성이 큽니다. DROP 성과로 튜닝하지 마세요.')
        except Exception:
            pass
        # 후보범위/판정품질 테이블
        try:
            if '_v1080_summary_table' in globals() and '_v1080_table_lines' in globals():
                for col, title, max_rows in [
                    ('candidate_scope', '후보범위별', 8),
                    ('final_decision_quality', '최종판정 품질별', 8),
                ]:
                    if col in ok.columns:
                        tab = _v1080_summary_table(ok, col)
                        if tab is not None and not tab.empty:
                            lines += _v1080_table_lines(title, tab, max_rows=max_rows)
        except Exception:
            pass
        # 수익률 분포 보정
        try:
            ret5 = pd.to_numeric(ok.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').dropna()
            if len(ret5) > 0:
                mean_v = float(ret5.mean())
                med_v = float(ret5.median())
                trim_v = _v1083_trimmed_mean(ret5, 0.10) if '_v1083_trimmed_mean' in globals() else mean_v
                ex_v = _v1083_excl_extreme_mean(ret5) if '_v1083_excl_extreme_mean' in globals() else mean_v
                fmt = _v1083_fmt_pct if '_v1083_fmt_pct' in globals() else (lambda x: f'{float(x):+.2f}%')
                lines.append('[수익률 분포 보정]')
                lines.append(f'- 5일 평균 {fmt(mean_v)} | 중앙값 {fmt(med_v)} | 10% 절사평균 {fmt(trim_v)} | 최고·최저 제외평균 {fmt(ex_v)}')
                try:
                    idx_best = pd.to_numeric(ok['next5_close_ret'], errors='coerce').idxmax()
                    idx_worst = pd.to_numeric(ok['next5_close_ret'], errors='coerce').idxmin()
                    best = ok.loc[idx_best]
                    worst = ok.loc[idx_worst]
                    lines.append(f"- 최고수익: {best.get('name','-')}({best.get('code','-')}) {float(best.get('next5_close_ret',0)):+.2f}% | 최저수익: {worst.get('name','-')}({worst.get('code','-')}) {float(worst.get('next5_close_ret',0)):+.2f}%")
                except Exception:
                    pass
        except Exception:
            pass
        # 표본 부족
        try:
            min_n = int(float(os.environ.get('V1083_MIN_SAMPLE_WARN', '3') or 3))
            if 'strategy' in ok.columns:
                vc = ok['strategy'].astype(str).replace({'': '미분류', 'nan': '미분류', 'None': '미분류'}).value_counts()
                small = vc[(vc > 0) & (vc < min_n)].head(10)
                if not small.empty:
                    txt = ', '.join([f'{k}({int(v)}개)' for k, v in small.items()])
                    lines.append('[표본 부족 주의]')
                    lines.append(f'- {min_n}개 미만 전략은 참고만 보세요: {txt}')
        except Exception:
            pass
        lines.append('[V1084 해석 원칙]')
        lines.append('- 지금 단계에서는 평균수익률보다 손절가 확보율·중앙값·후보범위·DROP 편중을 먼저 확인합니다.')
        lines.append('- V1084 블록이 보이면 직접 재현 리포트 후킹이 정상 적용된 것입니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1084 성과검증 품질진단]', f'- 생성 실패: {e}', '']


try:
    _V1084_BASE_BUILD_DIRECT_REPORT = _v1081_build_direct_report
except Exception:
    _V1084_BASE_BUILD_DIRECT_REPORT = None


def _v1084_inject_quality_block(report: str, quality_lines: list) -> str:
    """V1084: 품질진단 블록을 리포트 앞쪽에 삽입해 텔레그램 첫 청크에서도 보이게 한다."""
    try:
        report = str(report or '').strip()
        if not quality_lines:
            return report
        if '[V1084 성과검증 품질진단]' in report:
            return report
        qtext = '\n'.join(quality_lines).strip()
        # [관점/전략별] 앞에 넣으면 핵심 숫자 직후에 품질진단이 보인다.
        marker_list = ['[관점/전략별]', '[패턴별]', '[추천단계별]', '[V1081 해석 포인트]']
        for marker in marker_list:
            pos = report.find(marker)
            if pos >= 0:
                return (report[:pos].rstrip() + '\n\n' + qtext + '\n\n' + report[pos:].lstrip()).strip()
        return (report.rstrip() + '\n\n' + qtext).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1084 override: DIRECT_REPLAY 리포트에 V1083/V1084 품질진단을 강제 삽입한다."""
    try:
        work = _v1084_recompute_quality_columns(eval_df) if eval_df is not None and not eval_df.empty else eval_df
        if _V1084_BASE_BUILD_DIRECT_REPORT:
            report = _V1084_BASE_BUILD_DIRECT_REPORT(work, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        else:
            report = ''
        report = str(report or '')
        # 제목을 V1084로 명확하게 표시한다.
        report = report.replace('🧪 [V1081 직접 재현 주간 성과검증]', '🧪 [V1084 직접 재현 주간 성과검증]', 1)
        report = report.replace('[V1081 해석 포인트]', '[V1084 해석 포인트]')
        quality = _v1084_quality_lines(work)
        if _v1084_on('V1084_FORCE_QUALITY_BLOCK', '1'):
            report = _v1084_inject_quality_block(report, quality)
        try:
            if 'log_info' in globals():
                log_info('✅ V1084 직접 재현 리포트 품질진단 후킹 완료')
        except Exception:
            pass
        return report.strip()
    except Exception as e:
        try:
            return _V1084_BASE_BUILD_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1084_BASE_BUILD_DIRECT_REPORT else f'🧪 [V1084 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'
        except Exception:
            return f'🧪 [V1084 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

