# - 최종판정별 튜닝용 지표를 final_decision_v1085 / candidate_scope_v1085 기준으로 추가
# =============================================================
print("✅ V1085_FINAL_DECISION_MAPPING_FIX_ACTIVE LOADED")

try:
    os.environ.setdefault('V1085_FINAL_DECISION_MAPPING_FIX', '1')
    os.environ.setdefault('V1085_HIDE_LEGACY_QUALITY_BLOCKS', '1')
    os.environ.setdefault('V1085_DROP_DEFAULT_AS_RAW', '1')
except Exception:
    pass


def _v1085_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() in ('1', 'true', 'yes', 'y', 'on')
    except Exception:
        return str(default).strip().lower() in ('1', 'true', 'yes', 'y', 'on')


def _v1085_s(v, default: str = '') -> str:
    try:
        if '_v1084_s' in globals():
            return _v1084_s(v, default)
        if '_v1083_s' in globals():
            return _v1083_s(v, default)
        return str(v if v is not None else default).strip()
    except Exception:
        return default


def _v1085_row_text(row) -> str:
    keys = [
        # 기존 V1083/V1084가 만든 candidate_scope/final_decision_quality는
        # DROP기본값을 필터탈락처럼 보이게 만들 수 있어 V1085 판정 사유에서는 제외한다.
        'final_decision','phase','strategy','pattern','decision_mode',
        'volume_state','fake_severity','ai_pick_tier','ai_pick_reason','source',
        '최종판정','추천단계','매매판정','단계상태','수박최종상태','N구분','검색패턴','저항구름태그',
        '리스크','무효조건','메모','reason','comment','해석'
    ]
    parts = []
    try:
        for k in keys:
            try:
                if hasattr(row, 'get'):
                    v = row.get(k, '')
                else:
                    v = row[k]
            except Exception:
                continue
            s = _v1085_s(v, '')
            if s:
                parts.append(s)
    except Exception:
        pass
    return ' '.join(parts)


def _v1085_is_direct_replay(row) -> bool:
    try:
        src = _v1085_s(row.get('source', '') if hasattr(row, 'get') else '')
        return src.upper() == 'DIRECT_REPLAY'
    except Exception:
        return False


def _v1085_explicit_drop_reason(row) -> str:
    """DROP이 실제 제외/보류 사유인지, DIRECT_REPLAY 기본값인지 분리하기 위한 사유 추정."""
    try:
        raw = _v1085_row_text(row)
        fd = _v1085_s(row.get('final_decision', '') if hasattr(row, 'get') else '').upper()
        # 직접검증에서 final_decision=DROP만 있는 경우는 기본값 가능성이 크므로, 아래 명시 사유가 있을 때만 실제DROP으로 본다.
        checks = [
            ('가짜수박강', ['가짜수박 강', '가짜수박강', '강(위험)', '강위험']),
            ('거래량실패', ['거래량실패', '거래량 실패', '거래량실패(위험)']),
            ('신규진입보류', ['신규진입 보류', '신규 진입 보류', '신규진입금지', '신규진입 금지']),
            ('추격금지', ['추격 금지', '추격금지', '추격주의']),
            ('상단회복선멀음', ['상단회복선 멀', '회복 확인 후보', '회복확인 후보', '회복 확인']),
            ('위험/RISK', ['S-CORE RISK', 'RISK', '위험', '손익비 나쁨', '손익비부족']),
            ('제외/탈락', ['실전 후보 제외', '후보 제외', '제외', '필터탈락', '탈락']),
            ('보류', ['보류', '관망', '대기']),
        ]
        for label, words in checks:
            if any(w in raw for w in words):
                return label
        # DIRECT_REPLAY가 아닌 저장/실행 후보에서 DROP은 실제 판정일 가능성이 더 크다.
        if fd == 'DROP' and not _v1085_is_direct_replay(row):
            return '명시DROP'
        return ''
    except Exception:
        return ''


def _v1085_map_decision(row) -> dict:
    try:
        fd_raw = _v1085_s(row.get('final_decision', '') if hasattr(row, 'get') else '')
        fd = fd_raw.upper().strip()
        raw = _v1085_row_text(row)
        direct = _v1085_is_direct_replay(row)
        drop_reason = _v1085_explicit_drop_reason(row)
        # 명시 실전 후보
        if fd in ('PASS_A', 'SAFE', 'S-CORE SAFE') or any(k in raw for k in ['PASS_A', 'S-CORE SAFE', 'SCORE SAFE', '실전후보', '조건부 실행', '분할진입 후보']):
            return {
                'final_decision_v1085': 'PASS_A/실전후보',
                'candidate_scope_v1085': '실전후보',
                'final_decision_quality_v1085': '명시판정',
                'drop_reason_v1085': ''
            }
        # 관찰 후보
        if fd in ('PASS_B', 'PASS_C', 'NEUTRAL') or any(k in raw for k in ['PASS_B', 'PASS_C', '관찰', '관찰후보', '눌림 확인', '눌림대기', 'NEUTRAL']):
            return {
                'final_decision_v1085': '관찰후보',
                'candidate_scope_v1085': '관찰후보',
                'final_decision_quality_v1085': '명시판정',
                'drop_reason_v1085': ''
            }
        # 실제 DROP/제외로 추정되는 경우
        if fd == 'DROP' and drop_reason:
            return {
                'final_decision_v1085': f'실제DROP추정({drop_reason})',
                'candidate_scope_v1085': '실제DROP/제외',
                'final_decision_quality_v1085': '명시DROP추정',
                'drop_reason_v1085': drop_reason
            }
        # DIRECT_REPLAY에서 DROP만 있으면 기본값 가능성으로 분리
        if fd == 'DROP' and direct and _v1085_on('V1085_DROP_DEFAULT_AS_RAW', '1'):
            return {
                'final_decision_v1085': '원후보/미판정(DROP기본값)',
                'candidate_scope_v1085': '원후보/미판정(DROP기본값)',
                'final_decision_quality_v1085': 'DROP기본값가능성/직접검증주의',
                'drop_reason_v1085': ''
            }
        if fd == 'DROP':
            return {
                'final_decision_v1085': 'DROP',
                'candidate_scope_v1085': '실제DROP/제외',
                'final_decision_quality_v1085': '명시판정',
                'drop_reason_v1085': drop_reason or 'DROP'
            }
        if not fd_raw or fd_raw in ('미분류', 'nan', 'None'):
            return {
                'final_decision_v1085': '원후보/미판정',
                'candidate_scope_v1085': '원후보/미판정',
                'final_decision_quality_v1085': '최종판정없음',
                'drop_reason_v1085': ''
            }
        return {
            'final_decision_v1085': fd_raw,
            'candidate_scope_v1085': '원후보/미판정',
            'final_decision_quality_v1085': '기타판정',
            'drop_reason_v1085': ''
        }
    except Exception:
        return {
            'final_decision_v1085': '판정매핑오류',
            'candidate_scope_v1085': '원후보/미판정',
            'final_decision_quality_v1085': '판정매핑오류',
            'drop_reason_v1085': ''
        }


def _v1085_recompute_mapping_columns(df: pd.DataFrame) -> pd.DataFrame:
    try:
        if df is None or df.empty:
            return df
        if '_v1084_recompute_quality_columns' in globals():
            out = _v1084_recompute_quality_columns(df).copy()
        elif '_v1083_enrich_eval_df' in globals():
            out = _v1083_enrich_eval_df(df).copy()
        else:
            out = df.copy()
        maps = out.apply(lambda r: _v1085_map_decision(r), axis=1)
        for k in ['final_decision_v1085','candidate_scope_v1085','final_decision_quality_v1085','drop_reason_v1085']:
            out[k] = maps.map(lambda d: d.get(k, '') if isinstance(d, dict) else '')
        return out
    except Exception:
        return df


def _v1085_summary_lines(title: str, ok: pd.DataFrame, col: str, max_rows: int = 10) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        if '_v1080_summary_table' in globals() and '_v1080_table_lines' in globals():
            tmp = ok.copy()
            tmp[col] = tmp[col].astype(str).replace({'': '미분류', 'nan': '미분류', 'None': '미분류'})
            tab = _v1080_summary_table(tmp, col)
            return _v1080_table_lines(title, tab, max_rows=max_rows) if tab is not None and not tab.empty else []
    except Exception:
        pass
    return []


def _v1085_quality_lines(eval_df: pd.DataFrame) -> list:
    lines = []
    try:
        if eval_df is None or eval_df.empty:
            return lines
        work = _v1085_recompute_mapping_columns(eval_df)
        ok = work[work.get('eval_status', '') == 'OK'].copy()
        if ok.empty:
            return lines
        lines.append('[V1085 최종판정 매핑 보정]')
        n = len(ok)
        # 손절가 확보율은 V1084와 동일하게 유지
        try:
            if 'signal_stop_available' in ok.columns:
                avail = pd.Series(ok['signal_stop_available']).astype(bool).mean() * 100.0
            elif 'signal_stop_price_eval' in ok.columns:
                avail = (pd.to_numeric(ok['signal_stop_price_eval'], errors='coerce').fillna(0) > 0).mean() * 100.0
            else:
                avail = 0.0
            src_txt = '출처없음'
            vc = ok.get('signal_stop_source', pd.Series(['손절가없음'] * len(ok))).astype(str).replace({'': '손절가없음', 'nan': '손절가없음', 'None': '손절가없음'}).value_counts().head(5)
            if not vc.empty:
                src_txt = ' / '.join([f'{k}:{int(v)}개' for k, v in vc.items()])
            lines.append(f'- 손절가 확보율: {avail:.1f}% | 출처: {src_txt}')
        except Exception:
            pass
        try:
            old_fd = ok.get('final_decision', pd.Series([''] * n)).astype(str).str.upper()
            old_drop_rate = old_fd.eq('DROP').mean() * 100.0
            mapped = ok.get('final_decision_v1085', pd.Series([''] * n)).astype(str)
            default_drop_n = int(mapped.eq('원후보/미판정(DROP기본값)').sum())
            actual_drop_n = int(ok.get('candidate_scope_v1085', pd.Series([''] * n)).astype(str).eq('실제DROP/제외').sum())
            pass_n = int(ok.get('candidate_scope_v1085', pd.Series([''] * n)).astype(str).eq('실전후보').sum())
            obs_n = int(ok.get('candidate_scope_v1085', pd.Series([''] * n)).astype(str).eq('관찰후보').sum())
            lines.append(f'- 기존 DROP 비중: {old_drop_rate:.1f}% → DROP기본값 분리: {default_drop_n}개 | 실제DROP추정: {actual_drop_n}개')
            lines.append(f'- 보정 후보범위: 실전후보 {pass_n}개 | 관찰후보 {obs_n}개 | 원후보/미판정 {default_drop_n}개')
            if default_drop_n > 0:
                lines.append('  ↳ DIRECT_REPLAY의 DROP기본값은 실전 제외 확정이 아니라 원후보/미판정으로 따로 봅니다.')
        except Exception:
            pass
        lines += _v1085_summary_lines('V1085 후보범위별', ok, 'candidate_scope_v1085', max_rows=8)
        lines += _v1085_summary_lines('V1085 보정판정별', ok, 'final_decision_v1085', max_rows=10)
        lines += _v1085_summary_lines('V1085 판정품질별', ok, 'final_decision_quality_v1085', max_rows=8)
        # 수익률 분포 보정은 유지
        try:
            ret5 = pd.to_numeric(ok.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').dropna()
            if len(ret5) > 0:
                mean_v = float(ret5.mean())
                med_v = float(ret5.median())
                trim_v = _v1083_trimmed_mean(ret5, 0.10) if '_v1083_trimmed_mean' in globals() else mean_v
                ex_v = _v1083_excl_extreme_mean(ret5) if '_v1083_excl_extreme_mean' in globals() else mean_v
                fmt = _v1083_fmt_pct if '_v1083_fmt_pct' in globals() else (lambda x: f'{float(x):+.2f}%')
                lines.append('[수익률 분포 보정]')
                lines.append(f'- 5일 평균 {fmt(mean_v)} | 중앙값 {fmt(med_v)} | 10% 절사평균 {fmt(trim_v)} | 최고·최저 제외평균 {fmt(ex_v)}')
                try:
                    idx_best = pd.to_numeric(ok['next5_close_ret'], errors='coerce').idxmax()
                    idx_worst = pd.to_numeric(ok['next5_close_ret'], errors='coerce').idxmin()
                    best = ok.loc[idx_best]
                    worst = ok.loc[idx_worst]
                    lines.append(f"- 최고수익: {best.get('name','-')}({best.get('code','-')}) {float(best.get('next5_close_ret',0)):+.2f}% | 최저수익: {worst.get('name','-')}({worst.get('code','-')}) {float(worst.get('next5_close_ret',0)):+.2f}%")
                except Exception:
                    pass
        except Exception:
            pass
        # 표본 부족 경고 유지
        try:
            min_n = int(float(os.environ.get('V1083_MIN_SAMPLE_WARN', '3') or 3))
            if 'strategy' in ok.columns:
                vc = ok['strategy'].astype(str).replace({'': '미분류', 'nan': '미분류', 'None': '미분류'}).value_counts()
                small = vc[(vc > 0) & (vc < min_n)].head(10)
                if not small.empty:
                    txt = ', '.join([f'{k}({int(v)}개)' for k, v in small.items()])
                    lines.append('[표본 부족 주의]')
                    lines.append(f'- {min_n}개 미만 전략은 참고만 보세요: {txt}')
        except Exception:
            pass
        lines.append('[V1085 해석 원칙]')
        lines.append('- 기존 DROP 성과는 튜닝에 쓰지 말고, V1085 보정판정별/후보범위별을 우선 봅니다.')
        lines.append('- DROP기본값은 직접검증 원후보로 보고, 실제DROP/제외와 분리해서 해석합니다.')
        lines.append('- 다음 튜닝은 8주 기준에서 V1085 후보범위별 성과가 반복 확인된 뒤 진행합니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1085 최종판정 매핑 보정]', f'- 생성 실패: {e}', '']


try:
    _V1085_BASE_BUILD_DIRECT_REPORT = _v1081_build_direct_report
except Exception:
    _V1085_BASE_BUILD_DIRECT_REPORT = None


def _v1085_strip_legacy_quality_blocks(report: str) -> str:
    """V1083/V1084 품질진단 중복 블록을 제거하고 V1085 블록만 남긴다."""
    try:
        import re as _re
        text = str(report or '')
        if not _v1085_on('V1085_HIDE_LEGACY_QUALITY_BLOCKS', '1'):
            return text
        # V1083 블록: V1084/V1085/관점 전까지 제거
        patterns = [
            r'\n?\[V1083 성과검증 품질진단\][\s\S]*?(?=\n\[V1084 성과검증 품질진단\]|\n\[V1085 최종판정 매핑 보정\]|\n\[관점/전략별\]|\n\[패턴별\]|\Z)',
            r'\n?\[V1084 성과검증 품질진단\][\s\S]*?(?=\n\[V1085 최종판정 매핑 보정\]|\n\[관점/전략별\]|\n\[패턴별\]|\Z)',
        ]
        for pat in patterns:
            text = _re.sub(pat, '\n', text)
        text = _re.sub(r'\n{3,}', '\n\n', text).strip()
        return text
    except Exception:
        return report


def _v1085_inject_mapping_block(report: str, quality_lines: list) -> str:
    try:
        report = str(report or '').strip()
        if not quality_lines:
            return report
        if '[V1085 최종판정 매핑 보정]' in report:
            return report
        qtext = '\n'.join(quality_lines).strip()
        marker_list = ['[관점/전략별]', '[패턴별]', '[추천단계별]', '[V1084 해석 포인트]', '[V1081 해석 포인트]']
        for marker in marker_list:
            pos = report.find(marker)
            if pos >= 0:
                return (report[:pos].rstrip() + '\n\n' + qtext + '\n\n' + report[pos:].lstrip()).strip()
        return (report.rstrip() + '\n\n' + qtext).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1085 override: DIRECT_REPLAY 최종판정 매핑을 보정하고 V1083/V1084 중복 품질진단을 숨긴다."""
    try:
        work = _v1085_recompute_mapping_columns(eval_df) if eval_df is not None and not eval_df.empty else eval_df
        if _V1085_BASE_BUILD_DIRECT_REPORT:
            report = _V1085_BASE_BUILD_DIRECT_REPORT(work, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        else:
            report = ''
        report = str(report or '')
        report = report.replace('🧪 [V1084 직접 재현 주간 성과검증]', '🧪 [V1085 직접 재현 주간 성과검증]', 1)
        report = report.replace('🧪 [V1081 직접 재현 주간 성과검증]', '🧪 [V1085 직접 재현 주간 성과검증]', 1)
        report = report.replace('[V1084 해석 포인트]', '[V1085 해석 포인트]')
        report = report.replace('[V1081 해석 포인트]', '[V1085 해석 포인트]')
        report = _v1085_strip_legacy_quality_blocks(report)
        quality = _v1085_quality_lines(work)
        report = _v1085_inject_mapping_block(report, quality)
        try:
            if 'log_info' in globals():
                log_info('✅ V1085 최종판정 매핑 보정 리포트 후킹 완료')
        except Exception:
            pass
        return report.strip()
    except Exception as e:
        try:
            return _V1085_BASE_BUILD_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1085_BASE_BUILD_DIRECT_REPORT else f'🧪 [V1085 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'
        except Exception:
            return f'🧪 [V1085 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

# =============================================================
# ✅ END V1085_FINAL_DECISION_MAPPING_FIX_ACTIVE
# =============================================================



# ✅ V1086_HOLD10_PATTERN_PERIOD_ACTIVE
# - 성과검증 보유기간을 10거래일까지 확장해 1/3/5/10일 종가·최고수익률을 함께 계산
# - 패턴/전략별로 어느 기간 대응이 유리한지 리포트에 추가
# - V1085 최종판정 매핑 보정은 그대로 유지하고, V1086 블록을 DIRECT_REPLAY 리포트에 주입
print("✅ V1086_HOLD10_PATTERN_PERIOD_ACTIVE LOADED")
try:
    os.environ.setdefault('V1086_HOLD10_PATTERN_PERIOD', '1')
    os.environ.setdefault('V1086_MAX_HOLD_DAYS', '10')
    os.environ.setdefault('V1086_PATTERN_PERIOD_ANALYSIS', '1')
except Exception:
    pass


def _v1086_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return default not in ('0','false','no','off','')


def _v1086_num(v, default: float = 0.0) -> float:
    try:
        if v is None:
            return default
        if isinstance(v, str):
            s = v.replace(',', '').replace('%', '').strip()
            if s == '':
                return default
            return float(s)
        if pd.isna(v):
            return default
        return float(v)
    except Exception:
        return default


def _v1086_s(v, default: str = '') -> str:
    try:
        if v is None or (isinstance(v, float) and pd.isna(v)):
            return default
        s = str(v).strip()
        return s if s else default
    except Exception:
        return default


def _v1086_norm_code(code) -> str:
    try:
        return _v1080_norm_code(code) if '_v1080_norm_code' in globals() else str(code).zfill(6)[-6:]
    except Exception:
        return str(code).zfill(6)[-6:]


try:
    _V1086_BASE_EVALUATE_ONE_SIGNAL = _v1080_evaluate_one_signal
except Exception:
    _V1086_BASE_EVALUATE_ONE_SIGNAL = None


def _v1086_period_ret(entry: float, value: float) -> float:
    try:
        entry = float(entry or 0)
        value = float(value or 0)
        if entry <= 0 or value <= 0:
            return float('nan')
        return (value / entry - 1.0) * 100.0
    except Exception:
        return float('nan')


def _v1086_period_metrics(row, hold_days: int = 10) -> dict:
    """신호 후 1/3/5/10거래일 종가수익률·최고/최저수익률·최고수익 발생일을 계산한다."""
    out = {}
    try:
        max_hold = int(os.environ.get('V1086_MAX_HOLD_DAYS', '10') or 10)
    except Exception:
        max_hold = 10
    try:
        max_hold = max(10, int(max_hold), int(hold_days or 10))
    except Exception:
        max_hold = 10
    periods = [1, 3, 5, 10]
    try:
        code = _v1086_norm_code(row.get('code', ''))
        sig_date = pd.to_datetime(row.get('signal_date'))
        entry = _v1086_num(row.get('entry_price_eval', row.get('entry_price', 0)), 0.0)
        price_df = _v1080_fetch_price_after(code, sig_date, hold_days=max_hold) if '_v1080_fetch_price_after' in globals() else pd.DataFrame()
        if price_df is None or price_df.empty:
            return out
        before_or_same = price_df[price_df.index <= sig_date]
        if entry <= 0 and not before_or_same.empty:
            entry = _v1086_num(before_or_same.iloc[-1].get('Close', 0), 0.0)
        if entry <= 0:
            return out
        future = price_df[price_df.index > sig_date].head(max_hold).copy()
        if future.empty:
            return out
        closes = pd.to_numeric(future['Close'] if 'Close' in future.columns else future.iloc[:, 0], errors='coerce')
        highs = pd.to_numeric(future['High'] if 'High' in future.columns else closes, errors='coerce')
        lows = pd.to_numeric(future['Low'] if 'Low' in future.columns else closes, errors='coerce')
        high_rets = highs.map(lambda x: _v1086_period_ret(entry, x))
        low_rets = lows.map(lambda x: _v1086_period_ret(entry, x))
        close_rets = closes.map(lambda x: _v1086_period_ret(entry, x))
        out['hold_days_eval_actual'] = int(len(future))
        for p in periods:
            if len(future) >= 1:
                idx = min(p, len(future)) - 1
                out[f'next{p}_close_ret'] = round(float(close_rets.iloc[idx]), 4) if not pd.isna(close_rets.iloc[idx]) else float('nan')
                hseg = high_rets.iloc[:min(p, len(future))]
                lseg = low_rets.iloc[:min(p, len(future))]
                out[f'max_up_{p}d'] = round(float(hseg.max()), 4) if len(hseg) else float('nan')
                out[f'max_down_{p}d'] = round(float(lseg.min()), 4) if len(lseg) else float('nan')
                out[f'plus3_hit_{p}d'] = bool(float(hseg.max()) >= 3.0) if len(hseg) else False
                out[f'plus5_hit_{p}d'] = bool(float(hseg.max()) >= 5.0) if len(hseg) else False
        if len(high_rets.dropna()):
            best_pos = int(high_rets.reset_index(drop=True).idxmax())
            out['best_ret_10d'] = round(float(high_rets.iloc[best_pos]), 4)
            out['best_day_10d'] = best_pos + 1
            try:
                out['best_date_10d'] = pd.Timestamp(future.index[best_pos]).strftime('%Y-%m-%d')
            except Exception:
                out['best_date_10d'] = ''
        if len(low_rets.dropna()):
            worst_pos = int(low_rets.reset_index(drop=True).idxmin())
            out['worst_ret_10d'] = round(float(low_rets.iloc[worst_pos]), 4)
            out['worst_day_10d'] = worst_pos + 1
        # 타깃/손절 최초 발생일: 보수적으로 같은 날은 손절 우선
        stop_pct = _v1086_num(row.get('stop_pct_used', row.get('signal_stop_pct', os.environ.get('V1080_BACKTEST_STOP_PCT', -5))), -5.0)
        first_plus3_day = 0
        first_plus5_day = 0
        first_stop_day = 0
        first_event10 = 'none'
        for i in range(len(future)):
            lr = float(low_rets.iloc[i]) if not pd.isna(low_rets.iloc[i]) else 0.0
            hr = float(high_rets.iloc[i]) if not pd.isna(high_rets.iloc[i]) else 0.0
            day = i + 1
            if first_stop_day == 0 and lr <= stop_pct:
                first_stop_day = day
            if first_plus5_day == 0 and hr >= 5.0:
                first_plus5_day = day
            if first_plus3_day == 0 and hr >= 3.0:
                first_plus3_day = day
            if first_event10 == 'none':
                if lr <= stop_pct:
                    first_event10 = 'stop'
                elif hr >= 5.0:
                    first_event10 = 'plus5'
                elif hr >= 3.0:
                    first_event10 = 'plus3'
                elif hr >= 2.0:
                    first_event10 = 'plus2'
        out['first_plus3_day_10d'] = int(first_plus3_day)
        out['first_plus5_day_10d'] = int(first_plus5_day)
        out['first_stop_day_10d'] = int(first_stop_day)
        out['first_event_10d'] = first_event10
        out['plus3_first_10d'] = bool(first_event10 in ('plus3','plus5'))
        out['plus5_first_10d'] = bool(first_event10 == 'plus5')
        out['stop_first_10d'] = bool(first_event10 == 'stop')
    except Exception as e:
        try:
            out['v1086_metric_error'] = str(e)[:120]
        except Exception:
            pass
    return out


def _v1080_evaluate_one_signal(row, hold_days: int = 5, stop_pct: float = -5.0) -> dict:
    """V1086 override: 기존 평가 결과에 10거래일 기간별 대응 지표를 추가한다."""
    try:
        base = _V1086_BASE_EVALUATE_ONE_SIGNAL(row, hold_days=hold_days, stop_pct=stop_pct) if _V1086_BASE_EVALUATE_ONE_SIGNAL else {}
    except Exception as e:
        base = {'eval_status': f'평가오류:{e}'}
    try:
        if not _v1086_on('V1086_HOLD10_PATTERN_PERIOD', '1'):
            return base
        merged_row = dict(row or {})
        merged_row.update(base or {})
        # hold_days가 5로 들어와도 V1086은 10거래일 확장 지표를 별도 계산한다.
        metrics = _v1086_period_metrics(merged_row, hold_days=max(10, int(hold_days or 10)))
        if metrics:
            base.update(metrics)
    except Exception as e:
        try:
            base['v1086_metric_error'] = str(e)[:120]
        except Exception:
            pass
    return base


def _v1086_ok_df(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return pd.DataFrame()
        ok = eval_df[eval_df.get('eval_status', '') == 'OK'].copy()
        return ok
    except Exception:
        return pd.DataFrame()


def _v1086_fmt(v) -> str:
    try:
        if pd.isna(v):
            return 'N/A'
        return f'{float(v):+.2f}%'
    except Exception:
        return 'N/A'


def _v1086_rate(v) -> str:
    try:
        return f'{float(v):.1f}%'
    except Exception:
        return '0.0%'


def _v1086_period_summary_lines(ok: pd.DataFrame) -> list:
    lines = []
    try:
        if ok is None or ok.empty:
            return lines
        lines.append('[V1086 보유기간별 성과]')
        periods = [1, 3, 5, 10]
        parts = []
        for p in periods:
            c = pd.to_numeric(ok.get(f'next{p}_close_ret', pd.Series(dtype=float)), errors='coerce')
            m = pd.to_numeric(ok.get(f'max_up_{p}d', pd.Series(dtype=float)), errors='coerce')
            s = pd.to_numeric(ok.get(f'max_down_{p}d', pd.Series(dtype=float)), errors='coerce')
            if c.notna().sum() == 0 and m.notna().sum() == 0:
                continue
            parts.append(f'{p}일: 종가평균 {_v1086_fmt(c.mean())} | 최고평균 {_v1086_fmt(m.mean())} | 최저평균 {_v1086_fmt(s.mean())}')
        lines += [f'- {x}' for x in parts]
        b = pd.to_numeric(ok.get('best_day_10d', pd.Series(dtype=float)), errors='coerce').dropna()
        br = pd.to_numeric(ok.get('best_ret_10d', pd.Series(dtype=float)), errors='coerce')
        if len(b):
            bucket = pd.cut(b, bins=[0,1,3,5,10,999], labels=['1일','2~3일','4~5일','6~10일','10일초과'], right=True)
            dist = bucket.value_counts().sort_index()
            dist_txt = ' | '.join([f'{k} {int(v)}개' for k, v in dist.items() if int(v) > 0])
            lines.append(f'- 최고수익 발생구간: {dist_txt or "N/A"} | 10일 최고수익 평균 {_v1086_fmt(br.mean())}')
        p3 = ok.get('plus3_first_10d', pd.Series(dtype=bool)).astype(bool).mean() * 100 if 'plus3_first_10d' in ok.columns else 0.0
        p5 = ok.get('plus5_first_10d', pd.Series(dtype=bool)).astype(bool).mean() * 100 if 'plus5_first_10d' in ok.columns else 0.0
        st = ok.get('stop_first_10d', pd.Series(dtype=bool)).astype(bool).mean() * 100 if 'stop_first_10d' in ok.columns else 0.0
        lines.append(f'- 10일 이벤트: +3먼저 {_v1086_rate(p3)} | +5먼저 {_v1086_rate(p5)} | 손절먼저 {_v1086_rate(st)}')
        lines.append('')
    except Exception as e:
        return ['[V1086 보유기간별 성과]', f'- 생성 실패: {e}', '']
    return lines


def _v1086_group_period_table(ok: pd.DataFrame, group_col: str, title: str, max_rows: int = 12) -> list:
    lines = []
    try:
        if ok is None or ok.empty or group_col not in ok.columns:
            return lines
        rows = []
        for key, g in ok.groupby(group_col, dropna=False):
            key = _v1086_s(key, '미분류')
            n = len(g)
            if n <= 0:
                continue
            ret1 = pd.to_numeric(g.get('next1_close_ret'), errors='coerce').mean() if 'next1_close_ret' in g.columns else float('nan')
            ret3 = pd.to_numeric(g.get('next3_close_ret'), errors='coerce').mean() if 'next3_close_ret' in g.columns else float('nan')
            ret5 = pd.to_numeric(g.get('next5_close_ret'), errors='coerce').mean() if 'next5_close_ret' in g.columns else float('nan')
            ret10 = pd.to_numeric(g.get('next10_close_ret'), errors='coerce').mean() if 'next10_close_ret' in g.columns else float('nan')
            max10 = pd.to_numeric(g.get('best_ret_10d', g.get('max_up_10d', pd.Series(dtype=float))), errors='coerce').mean()
            stop10 = g.get('stop_first_10d', pd.Series([False]*n)).astype(bool).mean() * 100 if 'stop_first_10d' in g.columns else 0.0
            p3 = g.get('plus3_first_10d', pd.Series([False]*n)).astype(bool).mean() * 100 if 'plus3_first_10d' in g.columns else 0.0
            # 기간 대응 제안: 종가평균 기준으로 가장 강한 구간 + 손절 위험을 함께 반영
            period_vals = {1: ret1, 3: ret3, 5: ret5, 10: ret10}
            period_vals = {k:v for k,v in period_vals.items() if not pd.isna(v)}
            best_p = max(period_vals, key=lambda k: period_vals[k]) if period_vals else 5
            if stop10 >= 60:
                guide = '초반 손절위험 큼·실전 강등/확인 후 진입'
            elif best_p <= 3:
                guide = '1~3일 단기익절형'
            elif best_p <= 5:
                guide = '3~5일 스윙형'
            else:
                guide = '5~10일 추세보유형'
            rows.append({
                'key': key, 'n': int(n), 'ret1': ret1, 'ret3': ret3, 'ret5': ret5, 'ret10': ret10,
                'max10': max10, 'p3': p3, 'stop10': stop10, 'guide': guide,
                'sort': (0 if n >= 3 else -1, ret10 if not pd.isna(ret10) else ret5 if not pd.isna(ret5) else -999)
            })
        if not rows:
            return lines
        rows = sorted(rows, key=lambda r: r['sort'], reverse=True)[:max_rows]
        lines.append(f'[{title}]')
        for r in rows:
            small = ' ⚠️표본주의' if r['n'] < 3 else ''
            lines.append(
                f"- {r['key']}: {r['n']}개 | 1일 {_v1086_fmt(r['ret1'])} / 3일 {_v1086_fmt(r['ret3'])} / 5일 {_v1086_fmt(r['ret5'])} / 10일 {_v1086_fmt(r['ret10'])} | 10일최고 {_v1086_fmt(r['max10'])} | 손절먼저 {_v1086_rate(r['stop10'])} | 대응: {r['guide']}{small}"
            )
        lines.append('')
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']
    return lines


def _v1086_strategy_tuning_lines(ok: pd.DataFrame) -> list:
    lines = []
    try:
        if ok is None or ok.empty:
            return lines
        lines.append('[V1086 대응 가이드 요약]')
        # 지난 8주 검증의 반복 해석을 자동 가이드로 압축
        def has_strategy(term):
            if 'strategy' not in ok.columns:
                return pd.DataFrame()
            return ok[ok['strategy'].astype(str).str.contains(term, regex=False, na=False)].copy()
        weak_terms = []
        for term in ['BB40재안착눌림목', '수박재폭발', '5-20독사훅']:
            g = has_strategy(term)
            if len(g) >= 3:
                st = g.get('stop_first_10d', g.get('stop_first', pd.Series([False]*len(g)))).astype(bool).mean() * 100
                r10 = pd.to_numeric(g.get('next10_close_ret', g.get('next5_close_ret')), errors='coerce').mean()
                if st >= 50 or r10 < 1.0:
                    weak_terms.append(term)
        if weak_terms:
            lines.append(f'- 강등/확인 필요: {", ".join(weak_terms)}')
        # 패턴 저항돌파/저항전 비교
        if 'pattern' in ok.columns:
            br = ok[ok['pattern'].astype(str).str.contains('저항돌파', na=False)].copy()
            pre = ok[ok['pattern'].astype(str).str.contains('저항전', na=False)].copy()
            if len(br) >= 3 and len(pre) >= 3:
                br10 = pd.to_numeric(br.get('next10_close_ret', br.get('next5_close_ret')), errors='coerce').mean()
                pre10 = pd.to_numeric(pre.get('next10_close_ret', pre.get('next5_close_ret')), errors='coerce').mean()
                if br10 > pre10:
                    lines.append('- 저항돌파가 저항전보다 우위이면, 저항전은 신규진입보다 관찰/돌파확인 대기로 처리합니다.')
        lines.append('- V1086에서는 평균보다 “기간별 최고수익률·최고수익 발생일·손절먼저”를 같이 보고 대응일수를 정합니다.')
        lines.append('')
    except Exception:
        pass
    return lines


def _v1086_lines(eval_df: pd.DataFrame) -> list:
    try:
        ok = _v1086_ok_df(eval_df)
        if ok.empty:
            return ['[V1086 보유 10일·패턴 기간분석]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        lines = ['[V1086 보유 10일·패턴 기간분석]']
        lines.append('- 목적: 1/3/5/10일 종가수익률과 10일 내 최고수익률을 함께 보면서 패턴별 대응 기간을 정합니다.')
        lines.append('')
        lines += _v1086_period_summary_lines(ok)
        lines += _v1086_group_period_table(ok, 'strategy', 'V1086 관점/전략별 기간수익', max_rows=12)
        lines += _v1086_group_period_table(ok, 'pattern', 'V1086 패턴별 기간수익', max_rows=8)
        if 'volume_state' in ok.columns:
            lines += _v1086_group_period_table(ok, 'volume_state', 'V1086 거래량상태별 기간수익', max_rows=8)
        if 'signal_stop_bucket' in ok.columns:
            lines += _v1086_group_period_table(ok, 'signal_stop_bucket', 'V1086 손절거리별 기간수익', max_rows=8)
        lines += _v1086_strategy_tuning_lines(ok)
        return lines
    except Exception as e:
        return ['[V1086 보유 10일·패턴 기간분석]', f'- 생성 실패: {e}', '']


try:
    _V1086_BASE_BUILD_DIRECT_REPORT = _v1081_build_direct_report
except Exception:
    _V1086_BASE_BUILD_DIRECT_REPORT = None


def _v1086_inject_block(report: str, lines: list) -> str:
    try:
        block = '\n'.join(lines).strip() + '\n'
        if '[V1086 보유 10일·패턴 기간분석]' in report:
            return report
        markers = ['\n[관점/전략별]', '\n[패턴별]', '\n[추천단계별]', '\n[V1085 해석 포인트]']
        for m in markers:
            idx = report.find(m)
            if idx >= 0:
                return report[:idx].rstrip() + '\n\n' + block + '\n' + report[idx:].lstrip('\n')
        return report.rstrip() + '\n\n' + block
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1086 override: V1085 리포트에 10일 보유/패턴별 기간수익 분석을 추가한다."""
    try:
        work = eval_df.copy() if eval_df is not None and not eval_df.empty else eval_df
        if _V1086_BASE_BUILD_DIRECT_REPORT:
            report = _V1086_BASE_BUILD_DIRECT_REPORT(work, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        else:
            report = f'🧪 [V1086 직접 재현 주간 성과검증]\n- 리포트 원본 생성기가 없습니다.'
        report = report.replace('🧪 [V1085 직접 재현 주간 성과검증]', '🧪 [V1086 직접 재현 주간 성과검증]', 1)
        report = report.replace('🧪 [V1084 직접 재현 주간 성과검증]', '🧪 [V1086 직접 재현 주간 성과검증]', 1)
        report = report.replace('🧪 [V1081 직접 재현 주간 성과검증]', '🧪 [V1086 직접 재현 주간 성과검증]', 1)
        report = report.replace('[V1085 해석 포인트]', '[V1086 해석 포인트]')
        report = report.replace('[V1084 해석 포인트]', '[V1086 해석 포인트]')
        if _v1086_on('V1086_PATTERN_PERIOD_ANALYSIS', '1'):
            report = _v1086_inject_block(report, _v1086_lines(work))
        return report
    except Exception as e:
        try:
            if _V1086_BASE_BUILD_DIRECT_REPORT:
                return _V1086_BASE_BUILD_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1086 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

# ✅ END V1086_HOLD10_PATTERN_PERIOD_ACTIVE


# =============================================================
# ✅ V1087_LIQUIDITY_COMPRESSION_PRIORITY_ACTIVE
# - 거래대금 상위 universe를 "강한 종목"이 아니라 "매매 가능한 유동성 필터"로 해석
# - 우선순위는 거래량응축/상대거래대금 응축/저항돌파/손절거리/보유기간 성과로 재분류
# - DIRECT_REPLAY 리포트에 응축우선/핵심스윙/공격형/확인필요 집계를 추가
# =============================================================
print("✅ V1087_LIQUIDITY_COMPRESSION_PRIORITY_ACTIVE LOADED")
try:
    os.environ.setdefault('V1087_LIQUIDITY_COMPRESSION_PRIORITY', '1')
    os.environ.setdefault('V1087_VOLUME_COMPRESSION_FIRST', '1')
    os.environ.setdefault('V1087_LIQUIDITY_AS_FILTER_ONLY', '1')
except Exception:
    pass


def _v1087_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return default not in ('0','false','no','off','')


def _v1087_s(v, default: str = '') -> str:
    try:
        if v is None or (isinstance(v, float) and pd.isna(v)):
            return default
        s = str(v).strip()
        return s if s else default
    except Exception:
        return default


def _v1087_num(v, default: float = 0.0) -> float:
    try:
        if v is None:
            return default
        if isinstance(v, str):
            s = v.replace(',', '').replace('%', '').strip()
            if not s:
                return default
            return float(s)
        if pd.isna(v):
            return default
        return float(v)
    except Exception:
        return default


def _v1087_flag_text(row) -> str:
    try:
        parts = []
        for k in ['strategy','pattern','volume_state','signal_stop_bucket','final_decision_v1085','candidate_scope_v1085','phase','final_decision']:
            try:
                parts.append(_v1087_s(row.get(k, '')))
            except Exception:
                pass
        return ' '.join(parts)
    except Exception:
        return ''


def _v1087_classify(row) -> dict:
    """V1087: 거래대금은 유동성 필터, 실제 우선순위는 응축/저항돌파/손절거리/패턴으로 분리한다."""
    try:
        txt = _v1087_flag_text(row)
        vol = _v1087_s(row.get('volume_state', ''))
        strat = _v1087_s(row.get('strategy', ''))
        pat = _v1087_s(row.get('pattern', ''))
        stopb = _v1087_s(row.get('signal_stop_bucket', ''))
        ret10 = _v1087_num(row.get('next10_close_ret', row.get('next5_close_ret', 0)), 0.0)
        stop_first = bool(row.get('stop_first_10d', row.get('stop_first', False)))

        compression = ('거래량응축' in vol) or ('응축' in txt and '거래량' in txt)
        volume_strong = ('거래량유입(강)' in vol) or ('거래량폭발' in strat) or ('거래량폭발' in txt)
        volume_confirm = ('거래량유입(확인)' in vol)
        resistance_break = ('저항돌파' in pat) or ('저항돌파' in txt)
        before_resistance = ('저항전' in pat) or ('저항전' in txt)
        stop_good = ('-3~-5' in stopb) or ('-3%~-5%' in stopb) or ('-3~-5%' in stopb)
        stop_wide = ('-5~-8' in stopb) or ('-8' in stopb) or ('초과' in stopb)
        core_bb40 = ('BB40 2차파동' in strat) or ('BB40 2차' in txt)
        defensive = ('BB하단눌림목' in strat) or ('BB40재안착' in strat and '재안착눌림목' not in strat)
        weak = any(x in strat for x in ['세력눌림목','BB40재안착눌림목','수박재폭발','돌반지단독']) or before_resistance
        snake_only = ('5-20독사훅' in strat) and not (core_bb40 or resistance_break or compression or volume_confirm)

        score = 50
        reasons = []
        if compression:
            score += 25; reasons.append('거래량응축 우선')
        if resistance_break:
            score += 12; reasons.append('저항돌파')
        if stop_good:
            score += 10; reasons.append('손절거리 -3~-5%')
        if core_bb40:
            score += 12; reasons.append('BB40 2차파동')
        if defensive:
            score += 6; reasons.append('방어형 눌림/재안착')
        if volume_confirm:
            score += 4; reasons.append('거래량유입 확인')
        if volume_strong:
            score += 2; reasons.append('거래량강/폭발: 공격형')
        if stop_wide:
            score -= 8; reasons.append('손절거리 넓음')
        if before_resistance:
            score -= 15; reasons.append('저항전')
        if weak:
            score -= 22; reasons.append('확인필요 패턴')
        if snake_only:
            score -= 18; reasons.append('독사훅 단독')
        if stop_first:
            score -= 5
        if ret10 >= 10:
            score += 4
        elif ret10 < 0:
            score -= 6

        if weak or snake_only:
            klass = '🔴 확인필요/강등'
            guide = '선진입 금지, 실행기준선·저항돌파·거래량 재유입 확인 후 대응'
        elif compression:
            klass = '🟢 응축우선'
            guide = '유동성은 통과, 상대거래량 응축 우선. 손절가 지키며 5~10일 추세 보유'
        elif core_bb40 and resistance_break:
            klass = '🟢 핵심스윙'
            guide = 'BB40 2차파동+저항돌파. 3일 이후 반응 확인, 5~10일 보유 가능'
        elif defensive:
            klass = '🟢 방어형스윙'
            guide = '하단/재안착 방어형. 다음날 흔들림보다 3~10일 반등 확인'
        elif volume_strong:
            klass = '🟡 공격형/추격주의'
            guide = '수익폭은 크지만 손절도 큼. 강한 장세·손절거리 -3~-5%일 때만 우선'
        elif before_resistance:
            klass = '🟠 돌파확인대기'
            guide = '저항 전 구간은 신규진입보다 돌파 확인 대기'
        else:
            klass = '🟡 일반관찰'
            guide = '거래대금 상위는 유동성 통과 의미. 응축/저항돌파/손절거리 추가 확인'

        liquidity_role = '유동성필터 통과(거래대금 상위 universe)'
        if compression:
            liquidity_role += ' + 상대거래량 응축'
        elif volume_strong:
            liquidity_role += ' + 당일/최근 거래량 강세(추격주의)'
        elif volume_confirm:
            liquidity_role += ' + 거래량 재유입 확인'
        else:
            liquidity_role += ' + 응축 미확인'

        return {
            'v1087_priority_score': int(max(0, min(100, round(score)))),
            'v1087_priority_class': klass,
            'v1087_liquidity_role': liquidity_role,
            'v1087_action_guide': guide,
            'v1087_reason': ', '.join(reasons[:5]) if reasons else '일반관찰'
        }
    except Exception as e:
        return {
            'v1087_priority_score': 0,
            'v1087_priority_class': '미분류',
            'v1087_liquidity_role': '분류실패',
            'v1087_action_guide': f'분류 실패: {e}',
            'v1087_reason': '분류실패'
        }


def _v1087_enrich(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out = eval_df.copy()
        rows = []
        for _, row in out.iterrows():
            rows.append(_v1087_classify(row))
        add = pd.DataFrame(rows, index=out.index)
        for c in add.columns:
            out[c] = add[c]
        return out
    except Exception:
        return eval_df


def _v1087_fmt(v) -> str:
    try:
        if pd.isna(v):
            return 'N/A'
        return f'{float(v):+.2f}%'
    except Exception:
        return 'N/A'


def _v1087_rate(v) -> str:
    try:
        return f'{float(v):.1f}%'
    except Exception:
        return '0.0%'


def _v1087_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int = 8) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        lines = [f'[{title}]']
        rows = []
        for key, g in ok.groupby(col, dropna=False):
            key = _v1087_s(key, '미분류')
            n = len(g)
            r3 = pd.to_numeric(g.get('next3_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r5 = pd.to_numeric(g.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r10 = pd.to_numeric(g.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            best10 = pd.to_numeric(g.get('best_ret_10d', g.get('max_up_10d', pd.Series(dtype=float))), errors='coerce').mean()
            stop10 = g.get('stop_first_10d', g.get('stop_first', pd.Series([False]*n))).astype(bool).mean() * 100
            p3 = g.get('plus3_first_10d', g.get('plus3_first', pd.Series([False]*n))).astype(bool).mean() * 100
            score = pd.to_numeric(g.get('v1087_priority_score', pd.Series(dtype=float)), errors='coerce').mean()
            rows.append((key, n, r3, r5, r10, best10, p3, stop10, score))
        rows.sort(key=lambda x: ((x[8] if not pd.isna(x[8]) else 0), (x[4] if not pd.isna(x[4]) else -999)), reverse=True)
        for key, n, r3, r5, r10, best10, p3, stop10, score in rows[:max_rows]:
            small = ' ⚠️표본주의' if n < 3 else ''
            lines.append(f'- {key}: {n}개 | 점수 {score:.1f} | 3일 {_v1087_fmt(r3)} / 5일 {_v1087_fmt(r5)} / 10일 {_v1087_fmt(r10)} | 10일최고 {_v1087_fmt(best10)} | +3먼저 {_v1087_rate(p3)} | 손절먼저 {_v1087_rate(stop10)}{small}')
        lines.append('')
        return lines
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1087_top_examples(ok: pd.DataFrame, max_rows: int = 8) -> list:
    try:
        if ok is None or ok.empty:
            return []
        if 'v1087_priority_score' not in ok.columns:
            return []
        tmp = ok.copy()
        tmp['_score'] = pd.to_numeric(tmp['v1087_priority_score'], errors='coerce').fillna(0)
        tmp['_ret10'] = pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp = tmp.sort_values(['_score','_ret10'], ascending=False).head(max_rows)
        lines = ['[V1087 우선관찰 예시 TOP]']
        for _, r in tmp.iterrows():
            name = _v1087_s(r.get('name', r.get('종목명', '')),'')
            code = _v1087_s(r.get('code', r.get('종목코드', '')),'')
            cls = _v1087_s(r.get('v1087_priority_class',''))
            reason = _v1087_s(r.get('v1087_reason',''))
            r10 = _v1087_num(r.get('next10_close_ret', 0), 0.0)
            stopb = _v1087_s(r.get('signal_stop_bucket',''))
            lines.append(f"- {name}({code}) | {cls} | 10일 {r10:+.2f}% | 손절거리 {stopb or 'N/A'} | {reason}")
        lines.append('')
        return lines
    except Exception:
        return []


def _v1087_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1087 거래대금/응축 우선순위 튜닝]', '- 평가 데이터가 없습니다.', '']
        ok = eval_df[eval_df.get('eval_status', '') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok = _v1087_enrich(ok)
        if ok is None or ok.empty:
            return ['[V1087 거래대금/응축 우선순위 튜닝]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        lines = ['[V1087 거래대금/응축 우선순위 튜닝]']
        lines.append('- 원칙: 거래대금 상위는 강한 종목 선별이 아니라 “매매 가능한 유동성 필터”로만 봅니다.')
        lines.append('- 실전 우선순위는 상대 거래량응축, 저항돌파, 손절거리, 3~10일 성과를 함께 봅니다.')
        lines.append('- 핵심: “거래대금은 충분해야 하지만, 지금 막 터진 거래량은 추격주의”입니다.')
        lines.append('')
        lines += _v1087_group_lines(ok, 'v1087_priority_class', 'V1087 우선순위 분류별 성과', max_rows=8)
        lines += _v1087_group_lines(ok, 'v1087_liquidity_role', 'V1087 유동성/응축 역할별 성과', max_rows=8)
        lines += _v1087_group_lines(ok, 'v1087_action_guide', 'V1087 대응 가이드별 성과', max_rows=8)
        lines += _v1087_top_examples(ok, max_rows=8)
        lines.append('[V1087 적용 가이드]')
        lines.append('- 거래량응축(양호): 실전 우선순위 상향, 5~10일 추세보유형으로 관리')
        lines.append('- BB40 2차파동 + 저항돌파: 핵심스윙 유지, 3일 이후 수익 반응 확인')
        lines.append('- 거래량폭발초동돌파/거래량유입(강): 공격형. 약한 장세·손절거리 넓음이면 추격주의')
        lines.append('- 저항전/세력눌림목/BB40재안착눌림목/수박재폭발: 신규진입보다 회복·돌파 확인 후 대응')
        lines.append('- 손절거리 -3~-5%는 우선, -5~-8%는 비중축소/확인 후 진입으로 분리')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1087 거래대금/응축 우선순위 튜닝]', f'- 생성 실패: {e}', '']


try:
    _V1087_BASE_BUILD_DIRECT_REPORT = _v1081_build_direct_report
except Exception:
    _V1087_BASE_BUILD_DIRECT_REPORT = None


def _v1087_inject_block(report: str, lines: list) -> str:
    try:
        if '[V1087 거래대금/응축 우선순위 튜닝]' in report:
            return report
        block = '\n'.join(lines).strip() + '\n'
        markers = ['\n[V1086 보유 10일·패턴 기간분석]', '\n[관점/전략별]', '\n[패턴별]', '\n[V1086 해석 포인트]']
        # V1086 블록 뒤에 붙이면 기간분석→우선순위 해석 순서가 된다.
        if '\n[V1086 보유 10일·패턴 기간분석]' in report:
            # V1086 블록 다음의 [관점/전략별] 앞에 삽입
            for m in ['\n[관점/전략별]', '\n[패턴별]', '\n[추천단계별]']:
                idx = report.find(m)
                if idx >= 0:
                    return report[:idx].rstrip() + '\n\n' + block + '\n' + report[idx:].lstrip('\n')
        for m in markers:
            idx = report.find(m)
            if idx >= 0:
                return report[:idx].rstrip() + '\n\n' + block + '\n' + report[idx:].lstrip('\n')
        return report.rstrip() + '\n\n' + block
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1087 override: 거래대금 상위 universe의 의미를 유동성 필터로 재정의하고 응축 우선순위 튜닝 블록을 추가한다."""
    try:
        work = _v1087_enrich(eval_df.copy()) if eval_df is not None and not eval_df.empty else eval_df
        if _V1087_BASE_BUILD_DIRECT_REPORT:
            report = _V1087_BASE_BUILD_DIRECT_REPORT(work, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        else:
            report = '🧪 [V1087 직접 재현 주간 성과검증]\n- 리포트 원본 생성기가 없습니다.'
        for old in ['🧪 [V1086 직접 재현 주간 성과검증]', '🧪 [V1085 직접 재현 주간 성과검증]', '🧪 [V1084 직접 재현 주간 성과검증]', '🧪 [V1081 직접 재현 주간 성과검증]']:
            report = report.replace(old, '🧪 [V1087 직접 재현 주간 성과검증]', 1)
        report = report.replace('[V1086 해석 포인트]', '[V1087 해석 포인트]')
        report = report.replace('[V1085 해석 포인트]', '[V1087 해석 포인트]')
        if _v1087_on('V1087_LIQUIDITY_COMPRESSION_PRIORITY', '1'):
            report = _v1087_inject_block(report, _v1087_lines(work))
        return report
    except Exception as e:
        try:
            if _V1087_BASE_BUILD_DIRECT_REPORT:
                return _V1087_BASE_BUILD_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1087 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

