def _v1089_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return default not in ('0','false','no','off','')


def _v1089_text(row, keys=None) -> str:
    try:
        if keys is None:
            keys = [
                '최종판정','매매판정','추천단계','단계상태','유형','N조합','검색패턴','전략','태그','근거','이유','대응','전략문구',
                '주의','주의사항','가짜수박강도','가짜수박','수박정제태그','저항구름','저항구름태그','기준/피보','실행기준선상태','상단회복선상태'
            ]
        vals = []
        for k in keys:
            try:
                if hasattr(row, 'get'):
                    v = row.get(k, '')
                else:
                    v = row[k]
            except Exception:
                continue
            sv = _v1088_s(v, '') if '_v1088_s' in globals() else str(v or '')
            if sv:
                vals.append(sv)
        return ' / '.join(vals)
    except Exception:
        return ''


def _v1089_price_state(row) -> dict:
    """현재가와 실행/회복선을 비교해 실행 가능성 정보를 추정."""
    try:
        first = _v1088_first if '_v1088_first' in globals() else None
        num = _v1088_num if '_v1088_num' in globals() else float
        def f(keys, default=''):
            if first:
                return first(row, keys, default)
            for k in keys:
                try:
                    v = row.get(k, '') if hasattr(row,'get') else row[k]
                    if v not in (None, ''):
                        return v
                except Exception:
                    pass
            return default
        cur = num(f(['현재가','Close','종가','price','entry_price'], 0), 0.0)
        exec_line = num(f(['실행기준선','파란점선','기준선','entry_line','blue_line'], 0), 0.0)
        recover_line = num(f(['상단회복선','회복선','upper_recovery_line'], 0), 0.0)
        rsi = num(f(['RSI','rsi','RSI14'], 0), 0.0)
        disp = num(f(['이격','이격도','disparity','Disparity'], 0), 0.0)
        below_exec = bool(cur > 0 and exec_line > 0 and cur < exec_line * 0.995)
        near_exec = bool(cur > 0 and exec_line > 0 and abs(cur / exec_line - 1.0) <= 0.015)
        above_exec = bool(cur > 0 and exec_line > 0 and cur >= exec_line * 0.995)
        needs_recovery = bool(cur > 0 and recover_line > 0 and cur < recover_line * 0.995)
        return {
            'cur': cur, 'exec_line': exec_line, 'recover_line': recover_line,
            'rsi': rsi, 'disp': disp,
            'below_exec': below_exec, 'near_exec': near_exec, 'above_exec': above_exec, 'needs_recovery': needs_recovery,
        }
    except Exception:
        return {'cur':0,'exec_line':0,'recover_line':0,'rsi':0,'disp':0,'below_exec':False,'near_exec':False,'above_exec':False,'needs_recovery':False}


def _v1089_execution_info(row) -> dict:
    """우선순위 라벨보다 먼저 적용할 실행 가능성 게이트."""
    try:
        txt = _v1089_text(row)
        ps = _v1089_price_state(row)
        final = _v1088_first(row, ['최종판정','매매판정','추천단계','단계상태','유형'], '') if '_v1088_first' in globals() else ''
        final_s = _v1088_s(final, '') if '_v1088_s' in globals() else str(final or '')
        reasons = []
        hard = False
        wait = False
        executable = False
        pullback = False
        caution = False

        # 명시 판정 우선
        if any(k in final_s for k in ['신규진입 보류','실전 후보 제외','제외','DROP']):
            hard = True; reasons.append('신규진입 보류')
        if any(k in final_s for k in ['회복선 돌파 확인','회복 확인','회복선 위','회복선 재안착']):
            wait = True; reasons.append('회복확인 필요')
        if any(k in final_s for k in ['눌림 확인','눌림 대기','재지지']):
            pullback = True; reasons.append('눌림/재지지 확인')
        if any(k in final_s for k in ['소액 분할진입 가능','분할진입 가능','지금 1차','1차 분할진입 가능']):
            executable = True; reasons.append('소액 실행 가능')

        # 강한 위험 게이트
        if ('가짜수박주의(강' in txt) or ('가짜수박 강' in txt) or ('가짜수박 강위험' in txt) or ('🚫가짜수박주의' in txt):
            hard = True; reasons.append('가짜수박 강')
        if ps.get('below_exec'):
            hard = True; reasons.append('실행기준선 아래')
        if ('실행기준선 아래' in txt) or ('기준선 아래' in txt):
            hard = True; reasons.append('실행기준선 아래')
        if ('상단회복선' in txt and '회복 필요' in txt) or ps.get('needs_recovery'):
            wait = True; reasons.append('상단회복선 회복 필요')
        if ps.get('rsi', 0) >= 75:
            caution = True; reasons.append(f"RSI{ps.get('rsi',0):.0f} 과열")
        if ps.get('disp', 0) >= 115:
            caution = True; reasons.append(f"이격{ps.get('disp',0):.0f} 부담")
        if ('수급미계산' in txt) and (hard or wait or ps.get('below_exec')):
            caution = True; reasons.append('수급미계산')

        if hard:
            tier = 'EXEC_BLOCK'
            text = '🔴 실행보류'
        elif wait:
            tier = 'RECOVERY_WAIT'
            text = '🟠 회복확인'
        elif pullback:
            tier = 'PULLBACK_WAIT'
            text = '🟡 눌림대기'
        elif executable:
            tier = 'EXECUTABLE'
            text = '🟢 실행가능'
        elif caution:
            tier = 'CAUTION'
            text = '🟡 확인필요'
        else:
            tier = 'OBSERVE'
            text = '🟡 관찰'
        # 중복 사유 제거
        clean = []
        for r in reasons:
            if r and r not in clean:
                clean.append(r)
        return {'tier': tier, 'text': text, 'reasons': clean[:4], **ps}
    except Exception:
        return {'tier': 'OBSERVE', 'text': '🟡 관찰', 'reasons': []}


def _v1089_classify_live(row) -> dict:
    """V1088/V1087 구조분류 + V1089 실행게이트를 합친 실전 출력용 분류."""
    try:
        base = _v1088_classify_live(row) if '_v1088_classify_live' in globals() else {'v1087_priority_class':'🟡 일반관찰','v1087_priority_score':50}
        ex = _v1089_execution_info(row)
        cls0 = _v1088_short_class(base.get('v1087_priority_class','')) if '_v1088_short_class' in globals() else str(base.get('v1087_priority_class',''))
        stopb = base.get('signal_stop_bucket','') or (_v1088_stop_bucket_from_row(row, entry=_v1088_num(_v1088_first(row,['현재가','Close','종가','price'],0),0)) if '_v1088_stop_bucket_from_row' in globals() else '')
        # 실행보류면 구조 라벨을 관찰형으로 바꿔서 "좋은 구조이나 아직 실행금지"를 명확히 표시
        if ex['tier'] == 'EXEC_BLOCK':
            if '응축우선' in cls0:
                cls = '🟢 응축관찰'
            elif '핵심스윙' in cls0:
                cls = '🟢 핵심관찰'
            elif '방어형' in cls0:
                cls = '🟢 방어관찰'
            elif '공격형' in cls0 or '추격주의' in cls0:
                cls = '🔴 공격형보류'
            else:
                cls = '🔴 확인필요'
        else:
            cls = cls0
        out = dict(base)
        out.update({
            'v1089_execution_tier': ex['tier'],
            'v1089_execution_text': ex['text'],
            'v1089_execution_reasons': ', '.join(ex.get('reasons', [])),
            'v1089_priority_class': cls,
            'v1089_stop_bucket': stopb,
        })
        return out
    except Exception as e:
        return {'v1089_execution_tier':'OBSERVE','v1089_execution_text':'🟡 관찰','v1089_priority_class':'🟡 일반관찰','v1089_execution_reasons':str(e)}


def _v1089_label_from_info(info: dict) -> str:
    try:
        cls = _v1088_s(info.get('v1089_priority_class','') or info.get('v1087_priority_class',''), '') if '_v1088_s' in globals() else str(info.get('v1089_priority_class','') or '')
        stopb = _v1088_s(info.get('v1089_stop_bucket','') or info.get('signal_stop_bucket',''), '') if '_v1088_s' in globals() else str(info.get('v1089_stop_bucket','') or '')
        tier = _v1088_s(info.get('v1089_execution_tier',''), '') if '_v1088_s' in globals() else str(info.get('v1089_execution_tier','') or '')
        tails = []
        if tier == 'EXEC_BLOCK':
            tails.append('실행보류')
        elif tier == 'RECOVERY_WAIT':
            tails.append('회복확인')
        elif tier == 'PULLBACK_WAIT':
            tails.append('눌림대기')
        elif tier == 'EXECUTABLE':
            tails.append('소액가능')
        if '-3~-5' in stopb:
            tails.append('손절양호')
        elif '-5~-8' in stopb or '-8' in stopb:
            tails.append('비중축소')
        # 중복 tail 제거
        uniq = []
        for t in tails:
            if t and t not in uniq:
                uniq.append(t)
        return cls + (('·' + '·'.join(uniq)) if uniq else '')
    except Exception:
        return ''


def _v1089_rank_from_info(info: dict) -> int:
    try:
        cls = _v1088_s(info.get('v1089_priority_class',''), '') if '_v1088_s' in globals() else str(info.get('v1089_priority_class','') or '')
        tier = _v1088_s(info.get('v1089_execution_tier',''), '') if '_v1088_s' in globals() else str(info.get('v1089_execution_tier','') or '')
        # 실행 가능성이 우선이다.
        if tier == 'EXECUTABLE' and '응축우선' in cls:
            return 0
        if tier == 'EXECUTABLE' and '핵심스윙' in cls:
            return 1
        if tier == 'EXECUTABLE' and '방어형' in cls:
            return 2
        if tier in ('PULLBACK_WAIT','RECOVERY_WAIT') and ('핵심' in cls or '응축' in cls):
            return 3
        if tier == 'EXECUTABLE' and ('공격형' in cls or '추격주의' in cls):
            return 4
        if tier in ('PULLBACK_WAIT','RECOVERY_WAIT'):
            return 5
        if tier == 'EXEC_BLOCK' and ('응축관찰' in cls or '핵심관찰' in cls or '방어관찰' in cls):
            return 7
        if tier == 'EXEC_BLOCK':
            return 9
        # fallback은 V1088 구조순위 사용
        if '_v1088_class_rank' in globals():
            return 6 + int(_v1088_class_rank(cls))
        return 6
    except Exception:
        return 9


_V1089_LABEL_RE = re.compile(
    r'\s*(?:🟢|🟡|🟠|🔴)\s*(?:응축우선|응축관찰|핵심스윙|핵심관찰|방어형스윙|방어관찰|일반관찰|공격형/추격주의|공격형보류|확인필요|돌파확인대기)'
    r'(?:·(?:손절양호|비중축소|소액가능|실행보류|눌림대기|회복확인|확인대기|관찰))*'
)


def _v1089_strip_priority_labels_from_line(line: str) -> str:
    try:
        s = str(line or '')
        # 종목명(코드) 바로 뒤에 붙은 우선순위 라벨만 제거한다. AI Pick 라벨은 보존.
        m = re.match(r'^(?P<head>.*?\([A-Za-z0-9]{1,8}\))(?P<rest>.*)$', s)
        if not m:
            return s
        rest = m.group('rest') or ''
        # 앞쪽에 반복 삽입된 우선순위 라벨 제거
        prev = None
        while prev != rest:
            prev = rest
            rest = _V1089_LABEL_RE.sub('', rest, count=1).strip()
        if rest and not rest.startswith('|') and not rest.startswith('🤖'):
            rest = ' ' + rest
        elif rest.startswith('|') or rest.startswith('🤖'):
            rest = ' ' + rest
        return m.group('head') + rest.rstrip()
    except Exception:
        return line


def _v1089_build_label_map(df) -> dict:
    mp = {}
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return mp
        for _, row in df.iterrows():
            info = _v1089_classify_live(row)
            label = _v1089_label_from_info(info)
            if not label:
                continue
            code = _v1088_norm_code(info.get('code','') or _v1088_first(row, ['code','Code','종목코드'], '')) if '_v1088_norm_code' in globals() else ''
            name = _v1088_s(info.get('name','') or _v1088_first(row, ['종목명','Name','name'], '')) if '_v1088_s' in globals() else ''
            if code:
                mp[code] = label
            if name:
                mp[name] = label
    except Exception:
        pass
    return mp


def _v1089_enrich_live_df(df) -> pd.DataFrame:
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return df
        out = df.copy()
        infos = []
        for _, row in out.iterrows():
            infos.append(_v1089_classify_live(row))
        add = pd.DataFrame(infos, index=out.index)
        for c in add.columns:
            out[c] = add[c]
        out['v1089_priority_label'] = add.apply(lambda r: _v1089_label_from_info(r.to_dict()), axis=1)
        out['_v1089_rank'] = add.apply(lambda r: _v1089_rank_from_info(r.to_dict()), axis=1).astype(int)
        out['_v1089_score'] = pd.to_numeric(add.get('v1087_priority_score', 0), errors='coerce').fillna(0)
        for c in ['추천정렬점수','TOP15정렬점수','수급정렬점수','안전점수','N점수']:
            if c not in out.columns:
                out[c] = 0
            out[c] = pd.to_numeric(out[c], errors='coerce').fillna(0)
        return out
    except Exception:
        return df


def _v1050_sort_df_for_top15(df):
    """V1089 override: 실행 가능성 게이트를 우선 적용해 TOP15 정렬."""
    try:
        if _V1089_BASE_SORT_TOP15:
            base = _V1089_BASE_SORT_TOP15(df)
        else:
            base = df.copy() if hasattr(df, 'copy') else pd.DataFrame(df or [])
        if base is None or not hasattr(base, 'empty') or base.empty:
            return base
        if not _v1089_on('V1089_SORT_EXECUTABLE_FIRST', '1'):
            return base
        out = _v1089_enrich_live_df(base)
        if out is None or out.empty:
            return base
        out = out.sort_values(
            by=['_v1089_rank','_v1089_score','추천정렬점수','TOP15정렬점수','안전점수','N점수'],
            ascending=[True, False, False, False, False, False],
        ).reset_index(drop=True)
        try:
            globals()['_V1089_LIVE_LABEL_MAP'] = _v1089_build_label_map(out)
            globals()['_V1088_LIVE_LABEL_MAP'] = globals()['_V1089_LIVE_LABEL_MAP']
        except Exception:
            pass
        return out
    except Exception as e:
        try:
            if 'log_error' in globals():
                log_error(f'⚠️ V1089 TOP15 실행게이트 정렬 실패: {e}')
        except Exception:
            pass
        return _V1089_BASE_SORT_TOP15(df) if _V1089_BASE_SORT_TOP15 else df


def _v1089_insert_guide(msg: str) -> str:
    try:
        s = str(msg or '')
        # V1088 안내를 V1089 안내로 교체/보강
        s = s.replace('📌 V1088: 거래대금=유동성 필터 / 실전 우선순위=거래량응축·저항돌파·손절거리',
                      '📌 V1089: 실행가능성 우선 / 응축우선과 응축관찰 분리')
        s = s.replace('📌 우선순위: 🟢 응축우선 → 🟢 핵심스윙 → 🟢 방어형 → 🟡 공격형/추격주의 → 🔴 확인필요',
                      '📌 우선순위: 🟢 실행가능+응축 → 🟢 핵심스윙 → 🟡 눌림/회복확인 → 🟢 응축관찰·🔴 실행보류')
        s = s.replace('V1088: 실전 우선순위 라벨 / 거래대금=유동성 필터 / 응축우선 적용',
                      'V1089: 실행게이트 우선 / 응축우선·응축관찰 분리')
        s = s.replace('V1088: 거래대금은 유동성 통과, 우선순위는 거래량응축·저항돌파·손절거리 기준',
                      'V1089: 거래대금은 유동성 통과, 실행가능성 우선·응축관찰 분리')
        if 'V1089: 실행가능성 우선' in s:
            return s
        guide = '📌 V1089: 실행가능성 우선 / 응축우선과 응축관찰 분리\n📌 우선순위: 🟢 실행가능+응축 → 🟢 핵심스윙 → 🟡 눌림/회복확인 → 🟢 응축관찰·🔴 실행보류'
        if '🎯 [오늘 매매관점 압축]' in s:
            return s.replace('🎯 [오늘 매매관점 압축]', '🎯 [오늘 매매관점 압축]\n' + guide, 1)
        if '📢 [오늘의 실시간 TOP 15]' in s:
            return s.replace('📢 [오늘의 실시간 TOP 15]', '📢 [오늘의 실시간 TOP 15]\n' + guide, 1)
        return s
    except Exception:
        return msg


def _v1089_apply_line_labels(msg: str, label_map: dict = None) -> str:
    try:
        mp = label_map if label_map is not None else (globals().get('_V1089_LIVE_LABEL_MAP', {}) or globals().get('_V1088_LIVE_LABEL_MAP', {}) or {})
        if not mp:
            return msg
        lines = []
        for line in str(msg or '').splitlines():
            new_line = line
            try:
                clean = _v1089_strip_priority_labels_from_line(line) if _v1089_on('V1089_DEDUP_PRIORITY_LABELS','1') else line
                m = re.match(r'^(?P<prefix>\s*\d+\)\s+)(?P<name>[^\(\|\n]+?)\((?P<code>[A-Za-z0-9]{1,8})\)(?P<rest>.*)$', clean)
                if not m:
                    m = re.match(r'^(?P<prefix>\s*[-⭐🎯🟢🟡🔴\*]*\s*)(?P<name>[^\(\|\n]{1,30}?)\((?P<code>\d{6})\)(?P<rest>.*)$', clean)
                if m:
                    code = _v1088_norm_code(m.group('code')) if '_v1088_norm_code' in globals() else m.group('code')
                    name = (_v1088_s(m.group('name')).strip() if '_v1088_s' in globals() else m.group('name').strip())
                    label = mp.get(code) or mp.get(name) or ''
                    if label:
                        rest = m.group('rest') or ''
                        # AI Pick은 rest에 그대로 남는다.
                        new_line = f"{m.group('prefix')}{name}({m.group('code')}) {label}{rest}"
                    else:
                        new_line = clean
                else:
                    new_line = clean
            except Exception:
                pass
            lines.append(new_line)
        return '\n'.join(lines)
    except Exception:
        return msg


def _v1089_postprocess_live_message(msg: str) -> str:
    try:
        s = str(msg or '')
        if not any(k in s for k in ['오늘 매매관점 압축','오늘의 실시간 TOP 15','오늘의 추천주','TOP15','시장 통합 브리핑']):
            return s
        s = _v1089_insert_guide(s)
        s = _v1089_apply_line_labels(s)
        # 신규진입 보류인데 응축우선이라고 남은 예외 텍스트를 완화
        s = s.replace('🟢 응축우선·실행보류', '🟢 응축관찰·실행보류')
        return s
    except Exception:
        return msg


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    """V1089 override: TOP15 compact에 실행게이트 우선 라벨을 직접 표시."""
    try:
        enriched = _v1050_sort_df_for_top15(df) if df is not None and hasattr(df, 'empty') and not df.empty else df
        try:
            globals()['_V1089_LIVE_LABEL_MAP'] = _v1089_build_label_map(enriched)
            globals()['_V1088_LIVE_LABEL_MAP'] = globals()['_V1089_LIVE_LABEL_MAP']
        except Exception:
            pass
        if _V1089_BASE_TOP15_BLOCK:
            msg = _V1089_BASE_TOP15_BLOCK(enriched, limit=limit, title=title)
        elif _V1088_BASE_TOP15_BLOCK:
            msg = _V1088_BASE_TOP15_BLOCK(enriched, limit=limit, title=title)
        else:
            msg = ''
        msg = _v1089_postprocess_live_message(str(msg or ''))
        return msg
    except Exception as e:
        try:
            if 'log_error' in globals():
                log_error(f'⚠️ V1089 TOP15 compact 생성 실패: {e}')
        except Exception:
            pass
        try:
            return _V1089_BASE_TOP15_BLOCK(df, limit=limit, title=title) if _V1089_BASE_TOP15_BLOCK else ''
        except Exception:
            return ''


def _v1089_label_map_from_row_map(row_map: dict) -> dict:
    mp = {}
    try:
        if not row_map:
            return mp
        rows = []
        if isinstance(row_map, dict):
            for _k, v in row_map.items():
                try:
                    if isinstance(v, dict) or hasattr(v, 'get'):
                        rows.append(v)
                except Exception:
                    pass
        if rows:
            df = pd.DataFrame(rows)
            df = _v1089_enrich_live_df(df)
            mp = _v1089_build_label_map(df)
    except Exception:
        pass
    return mp


def _v1073_compact_today_block(base: str, row_map: dict) -> str:
    """V1089 override: 오늘 매매관점 압축에 실행 가능성 우선 라벨을 적용."""
    try:
        msg = _V1089_BASE_TODAY_BLOCK(base, row_map) if _V1089_BASE_TODAY_BLOCK else str(base or '')
    except Exception:
        msg = str(base or '')
    try:
        local_map = _v1089_label_map_from_row_map(row_map) or globals().get('_V1089_LIVE_LABEL_MAP', {}) or globals().get('_V1088_LIVE_LABEL_MAP', {}) or {}
        if local_map:
            globals()['_V1089_LIVE_LABEL_MAP'] = {**(globals().get('_V1089_LIVE_LABEL_MAP', {}) or {}), **local_map}
            globals()['_V1088_LIVE_LABEL_MAP'] = globals()['_V1089_LIVE_LABEL_MAP']
        msg = _v1089_postprocess_live_message(msg)
        msg = _v1089_apply_line_labels(msg, local_map or None)
    except Exception:
        pass
    return msg


def _v1046_send_top15_detail(msg, max_len=3300):
    """V1089 override: 상세 TOP15에도 중복 제거 후 실행게이트 라벨 삽입."""
    try:
        msg2 = _v1089_postprocess_live_message(str(msg or ''))
    except Exception:
        msg2 = msg
    if _V1089_BASE_SEND_TOP15_DETAIL:
        return _V1089_BASE_SEND_TOP15_DETAIL(msg2, max_len=max_len)
    return send_telegram_chunks(msg2, max_len=max_len)


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    """V1089 override: 오늘 매매관점/TOP15 관련 메시지 최종 후처리."""
    try:
        msg2 = _v1089_postprocess_live_message(str(message or ''))
    except Exception:
        msg2 = message
    if _V1089_BASE_SEND_CHUNKS:
        return _V1089_BASE_SEND_CHUNKS(msg2, title=title, max_len=max_len)
    return None

