_V1090_LABEL_RE = re.compile(
    r'\s*(?:🟢|🟡|🟠|🔴)\s*(?:응축우선|응축관찰|핵심스윙|핵심관찰|방어형스윙|방어관찰|방어형관찰|일반관찰|공격형/추격주의|공격형보류|확인필요|돌파확인대기|회복확인)'
    r'(?:·(?:손절양호|비중축소|소액가능|실행보류|눌림대기|회복확인|확인대기|관찰))*'
)


def _v1090_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return default not in ('0','false','no','off','')


def _v1090_extract_existing_label(line: str) -> str:
    try:
        m = _V1090_LABEL_RE.search(str(line or ''))
        return m.group(0).strip() if m else ''
    except Exception:
        return ''


def _v1090_strip_priority_labels_from_line(line: str) -> str:
    try:
        s = str(line or '')
        m = re.match(r'^(?P<head>.*?\([A-Za-z0-9]{1,8}\))(?P<rest>.*)$', s)
        if not m:
            return s
        rest = m.group('rest') or ''
        prev = None
        while prev != rest:
            prev = rest
            rest = _V1090_LABEL_RE.sub('', rest, count=1).strip()
        if rest and not rest.startswith('|') and not rest.startswith('🤖'):
            rest = ' ' + rest
        elif rest.startswith('|') or rest.startswith('🤖'):
            rest = ' ' + rest
        return m.group('head') + rest.rstrip()
    except Exception:
        return line


def _v1090_gate_from_block(block_text: str) -> dict:
    """종목 상세 블록 전체 텍스트에서 실행 가능성 게이트를 재판정한다."""
    try:
        t = str(block_text or '')
        hard = False; wait = False; pullback = False; executable = False
        reasons = []
        if ('최종판정: 🔴 신규진입 보류' in t) or ('최종판정: 신규진입 보류' in t) or ('신규진입 보류' in t and '실전 후보 제외' in t):
            hard = True; reasons.append('신규진입 보류')
        if ('🚫가짜수박주의(강' in t) or ('가짜수박 강위험' in t) or ('가짜수박주의(강' in t):
            hard = True; reasons.append('가짜수박 강')
        if ('실행기준선' in t and '아래' in t) or ('기준선 아래' in t):
            hard = True; reasons.append('실행기준선 아래')
        # "회복선 재안착 전 관찰"은 사실상 실행보류 문구이므로 hard로 본다.
        if ('회복선 재안착 전 관찰' in t) or ('회복선 안착 확인 필요' in t):
            hard = True; reasons.append('회복선 전 관찰')
        # 회복선 돌파 확인 후보는 hard보다 약하지만, hard가 없을 때만 회복확인으로 둔다.
        if ('회복선 돌파 확인 후 진입' in t) or ('회복선 위 종가 안착 확인 후' in t) or ('회복 확인 후보' in t):
            wait = True; reasons.append('회복확인 필요')
        if ('최종판정: 🟡 눌림 확인 후 진입' in t) or ('눌림 확인 후 진입' in t) or ('눌림 재지지' in t) or ('눌림 대기' in t):
            pullback = True; reasons.append('눌림/재지지 확인')
        if ('최종판정: 🟡 소액 분할진입 가능' in t) or ('소액 분할진입 가능' in t) or ('지금 1차 분할진입 가능' in t) or ('1차 분할진입 가능' in t):
            executable = True; reasons.append('소액 실행 가능')
        # 강한 실행보류가 항상 우선
        if hard:
            tier = 'EXEC_BLOCK'
        elif wait:
            tier = 'RECOVERY_WAIT'
        elif pullback:
            tier = 'PULLBACK_WAIT'
        elif executable:
            tier = 'EXECUTABLE'
        else:
            tier = 'OBSERVE'
        clean = []
        for r in reasons:
            if r and r not in clean:
                clean.append(r)
        return {'tier': tier, 'reasons': clean[:4]}
    except Exception:
        return {'tier':'OBSERVE','reasons':[]}


def _v1090_label_from_old_and_gate(old_label: str, gate: dict) -> str:
    try:
        old = str(old_label or '').strip()
        tier = gate.get('tier', 'OBSERVE')
        # 기본 구조 클래스 보존/완화
        if '응축' in old:
            cls_exec = '🟢 응축우선'
            cls_block = '🟢 응축관찰'
        elif '핵심' in old:
            cls_exec = '🟢 핵심스윙'
            cls_block = '🟢 핵심관찰'
        elif '방어' in old:
            cls_exec = '🟡 방어형관찰'  # V1087 결과상 방어형은 실전 우선보다 관찰형으로 완화
            cls_block = '🟡 방어형관찰'
        elif '공격' in old or '추격주의' in old:
            cls_exec = '🟡 공격형/추격주의'
            cls_block = '🔴 공격형보류'
        elif '확인필요' in old:
            cls_exec = '🔴 확인필요'
            cls_block = '🔴 확인필요'
        else:
            cls_exec = '🟡 일반관찰'
            cls_block = '🔴 확인필요'
        tails = []
        if tier == 'EXEC_BLOCK':
            cls = cls_block
            tails.append('실행보류')
        else:
            cls = cls_exec
            if tier == 'RECOVERY_WAIT':
                tails.append('회복확인')
            elif tier == 'PULLBACK_WAIT':
                tails.append('눌림대기')
            elif tier == 'EXECUTABLE':
                tails.append('소액가능')
        # 기존 손절 꼬리표는 유지
        if '손절양호' in old:
            tails.append('손절양호')
        elif '비중축소' in old:
            tails.append('비중축소')
        uniq = []
        for x in tails:
            if x and x not in uniq:
                uniq.append(x)
        return cls + (('·' + '·'.join(uniq)) if uniq else '')
    except Exception:
        return old_label or ''


def _v1090_replace_item_line_label(line: str, block_text: str) -> str:
    try:
        # 종목명(코드)이 없으면 건드리지 않는다.
        m = re.match(r'^(?P<prefix>\s*\d+\)\s+)(?P<name>[^\(\|\n]+?)\((?P<code>[A-Za-z0-9]{1,8})\)(?P<rest>.*)$', str(line or ''))
        if not m:
            return line
        old_label = _v1090_extract_existing_label(line)
        # 기존 라벨이 없고 최종판정도 없으면 예비/별도 섹션으로 보고 패스한다.
        if not old_label and '최종판정:' not in str(block_text or '') and '✅ 대응:' not in str(block_text or ''):
            return line
        gate = _v1090_gate_from_block(block_text)
        if gate.get('tier') == 'OBSERVE' and not old_label:
            return line
        new_label = _v1090_label_from_old_and_gate(old_label, gate)
        clean = _v1090_strip_priority_labels_from_line(line)
        m2 = re.match(r'^(?P<head>\s*\d+\)\s+[^\(\|\n]+?\([A-Za-z0-9]{1,8}\))(?P<rest>.*)$', clean)
        if not m2 or not new_label:
            return clean
        rest = m2.group('rest') or ''
        if rest and not rest.startswith(' ') and not rest.startswith('|') and not rest.startswith('🤖'):
            rest = ' ' + rest
        return f"{m2.group('head')} {new_label}{rest}"
    except Exception:
        return line


def _v1090_apply_block_gate_labels(msg: str) -> str:
    """TOP15/오늘 매매관점의 각 종목 상세 블록을 보고 첫 줄 라벨을 강제 보정한다."""
    try:
        s = str(msg or '')
        if not any(k in s for k in ['오늘의 실시간 TOP 15','오늘 매매관점 압축','최종판정:','신규진입 보류']):
            return s
        lines = s.splitlines()
        out = list(lines)
        item_idxs = []
        for i, line in enumerate(lines):
            if re.match(r'^\s*\d+\)\s+[^\(\n]{1,40}\([A-Za-z0-9]{1,8}\)', line):
                item_idxs.append(i)
        for idx_pos, start in enumerate(item_idxs):
            end = item_idxs[idx_pos + 1] if idx_pos + 1 < len(item_idxs) else len(lines)
            # 너무 긴 다음 섹션까지 먹지 않도록 구분선/섹션 제목에서 자른다.
            for j in range(start + 1, end):
                if re.match(r'^\s*(?:━━━━━━━━|──|\[[^\]]+\]|🧩 \[|🏆 \[|⚠️ \[|🟠 \[|🟢 \[|📢 \[|🎯 \[)', lines[j]):
                    end = j
                    break
            block = '\n'.join(lines[start:end])
            out[start] = _v1090_replace_item_line_label(lines[start], block)
        return '\n'.join(out)
    except Exception:
        return msg


def _v1090_postprocess_live_message(msg: str) -> str:
    try:
        s = str(msg or '')
        if _V1090_BASE_POSTPROCESS:
            try:
                s = _V1090_BASE_POSTPROCESS(s)
            except Exception:
                pass
        s = s.replace('📌 V1089: 실행가능성 우선 / 응축우선과 응축관찰 분리',
                      '📌 V1090: TOP15 블록 기준 실행게이트 보정 / 응축우선·응축관찰 분리')
        s = s.replace('V1089: 실행게이트 우선 / 응축우선·응축관찰 분리',
                      'V1090: TOP15 블록 기준 실행게이트 보정')
        # V1088/1089에서 남은 예외 문구 보정
        s = _v1090_apply_block_gate_labels(s)
        # 첫 줄 텍스트 치환 fallback
        s = s.replace('🟢 응축우선·실행보류', '🟢 응축관찰·실행보류')
        s = s.replace('🟢 방어형스윙·실행보류', '🟡 방어형관찰·실행보류')
        return s
    except Exception:
        return msg


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    try:
        msg = _V1090_BASE_TOP15_BLOCK(df, limit=limit, title=title) if _V1090_BASE_TOP15_BLOCK else ''
        return _v1090_postprocess_live_message(msg)
    except Exception as e:
        try:
            if 'log_error' in globals():
                log_error(f'⚠️ V1090 TOP15 block gate 보정 실패: {e}')
        except Exception:
            pass
        return _V1090_BASE_TOP15_BLOCK(df, limit=limit, title=title) if _V1090_BASE_TOP15_BLOCK else ''


def _v1073_compact_today_block(base: str, row_map: dict) -> str:
    try:
        msg = _V1090_BASE_TODAY_BLOCK(base, row_map) if _V1090_BASE_TODAY_BLOCK else str(base or '')
        return _v1090_postprocess_live_message(msg)
    except Exception:
        return str(base or '')


def _v1046_send_top15_detail(msg, max_len=3300):
    try:
        msg2 = _v1090_postprocess_live_message(str(msg or ''))
    except Exception:
        msg2 = msg
    if _V1090_BASE_SEND_TOP15_DETAIL:
        return _V1090_BASE_SEND_TOP15_DETAIL(msg2, max_len=max_len)
    return send_telegram_chunks(msg2, max_len=max_len)


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    try:
        msg2 = _v1090_postprocess_live_message(str(message or ''))
    except Exception:
        msg2 = message
    if _V1090_BASE_SEND_CHUNKS:
        return _V1090_BASE_SEND_CHUNKS(msg2, title=title, max_len=max_len)
    return None

