_V1092_LABEL_RE = re.compile(
    r'\s*(?:🟢|🟡|🟠|🔴)\s*(?:응축우선|응축관찰|핵심스윙|핵심관찰|방어형스윙|방어형관찰|방어관찰|일반관찰|공격형/추격주의|공격형보류|과열보류|확인필요|돌파확인대기|회복확인)'
    r'(?:·(?:손절양호|비중축소|소액가능|실행보류|눌림대기|회복확인|확인대기|관찰))*'
)


def _v1092_num_after(label: str, text: str, default=None):
    try:
        m = re.search(label + r'\s*([0-9]+(?:\.[0-9]+)?)', str(text or ''))
        return float(m.group(1)) if m else default
    except Exception:
        return default


def _v1092_strip_item_labels(line: str) -> str:
    try:
        s = str(line or '')
        m = re.match(r'^(?P<head>\s*\d+\)\s+[^\(\|\n]+?\([A-Za-z0-9]{1,8}\))(?P<rest>.*)$', s)
        if not m:
            return s
        rest = m.group('rest') or ''
        prev = None
        while prev != rest:
            prev = rest
            rest = _V1092_LABEL_RE.sub('', rest, count=1).strip()
        if rest and not rest.startswith('|') and not rest.startswith('🤖'):
            rest = ' ' + rest
        elif rest.startswith('|') or rest.startswith('🤖'):
            rest = ' ' + rest
        return (m.group('head') + rest).rstrip()
    except Exception:
        return line


def _v1092_old_label(line: str) -> str:
    try:
        m = _V1092_LABEL_RE.search(str(line or ''))
        return m.group(0).strip() if m else ''
    except Exception:
        return ''


def _v1092_gate(block: str) -> dict:
    t = str(block or '')
    rsi = _v1092_num_after('RSI', t, None)
    disp = _v1092_num_after('이격', t, None)
    overheat = False
    hard = False
    recovery = False
    pullback = False
    small = False
    reasons = []
    if rsi is not None and rsi >= 75:
        overheat = True; hard = True; reasons.append(f'RSI{rsi:g}')
    if disp is not None and disp >= 115:
        overheat = True; hard = True; reasons.append(f'이격{disp:g}')
    if '최종판정: 🔴 신규진입 보류' in t or '최종판정: 신규진입 보류' in t or '🧭 🔴 신규진입 보류' in t:
        hard = True; reasons.append('신규진입 보류')
    if '🚫가짜수박주의(강' in t or '가짜수박주의(강' in t or '가짜수박 강위험' in t:
        hard = True; reasons.append('가짜수박 강')
    if re.search(r'실행기준선[^\n]*(아래|미확인)', t) or '기준선 아래' in t:
        hard = True; reasons.append('실행기준선 아래')
    if ('회복선 재안착 전 관찰' in t or '회복선 안착 확인 필요' in t) and ('신규:' in t or '최종판정: 🔴' in t):
        hard = True; reasons.append('회복선 전 관찰')
    if '회복선 돌파 확인 후 진입' in t or '회복선 위 종가 안착 확인 후' in t:
        recovery = True; reasons.append('회복확인')
    if '최종판정: 🟡 눌림 확인 후 진입' in t or '🧭 🟡 눌림 확인 후 진입' in t or '눌림 재지지' in t or '눌림 대기' in t:
        pullback = True; reasons.append('눌림대기')
    if '최종판정: 🟡 소액 분할진입 가능' in t or '🧭 🟡 소액 분할진입 가능' in t or '소액 분할진입 가능' in t or '지금 1차 분할진입 가능' in t or '1차 분할진입 가능' in t:
        small = True; reasons.append('소액가능')
    if overheat:
        tier = 'OVERHEAT'
    elif hard:
        tier = 'BLOCK'
    elif recovery:
        tier = 'RECOVERY'
    elif pullback:
        tier = 'PULLBACK'
    elif small:
        tier = 'SMALL'
    else:
        tier = 'OBSERVE'
    return {'tier': tier, 'reasons': reasons[:5], 'rsi': rsi, 'disp': disp}


def _v1092_structure_class(old_label: str, block: str, blocked: bool=False) -> str:
    src = f"{old_label or ''} {block or ''}"
    if '과열보류' in src:
        return '🔴 과열보류'
    if '응축우선' in src or '응축관찰' in src or 'BB40 수렴' in src or 'BB40 응축' in src or '정제수박' in src:
        return '🟢 응축관찰' if blocked else '🟢 응축우선'
    if '핵심스윙' in src or 'BB40 2차파동' in src:
        return '🟢 핵심관찰' if blocked else '🟢 핵심스윙'
    if 'BB하단눌림목' in src or 'BB40재안착' in src or '방어형' in src:
        return '🟡 방어형관찰'
    if '거래량폭발초동돌파' in src or '공격형' in src or '추격주의' in src:
        return '🔴 공격형보류' if blocked else '🟡 공격형/추격주의'
    if '확인필요' in src or blocked:
        return '🔴 확인필요'
    return '🟡 일반관찰'


def _v1092_new_label(old_label: str, block: str) -> str:
    gate = _v1092_gate(block)
    tier = gate.get('tier')
    old = str(old_label or '')
    if tier == 'OVERHEAT':
        base = '🔴 과열보류'
        tails = ['실행보류']
    elif tier == 'BLOCK':
        base = _v1092_structure_class(old, block, blocked=True)
        tails = ['실행보류']
    else:
        base = _v1092_structure_class(old, block, blocked=False)
        tails = []
        if tier == 'RECOVERY':
            tails.append('회복확인')
        elif tier == 'PULLBACK':
            tails.append('눌림대기')
        elif tier == 'SMALL':
            tails.append('소액가능')
    # 실행보류 종목은 손절양호보다 실행보류가 먼저 보이게 함
    if '손절양호' in old:
        tails.append('손절양호')
    elif '비중축소' in old or '수급 미계산' in str(block or '') or '수급미계산' in str(block or '') or '비중 축소' in str(block or ''):
        tails.append('비중축소')
    uniq = []
    for x in tails:
        if x and x not in uniq:
            uniq.append(x)
    return base + (('·' + '·'.join(uniq)) if uniq else '')


def _v1092_fix_item_line(line: str, block: str) -> str:
    try:
        # 예비 섹션처럼 최종판정이 없는 순위형 리스트는 건드리지 않는다.
        if '최종판정:' not in str(block or '') and '✅ 대응:' not in str(block or '') and '🧭 🟡' not in str(block or '') and '🧭 🔴' not in str(block or ''):
            return line
        m = re.match(r'^(?P<head>\s*\d+\)\s+[^\(\|\n]+?\([A-Za-z0-9]{1,8}\))(?P<rest>.*)$', str(line or ''))
        if not m:
            return line
        old = _v1092_old_label(line)
        label = _v1092_new_label(old, block)
        clean = _v1092_strip_item_labels(line)
        m2 = re.match(r'^(?P<head>\s*\d+\)\s+[^\(\|\n]+?\([A-Za-z0-9]{1,8}\))(?P<rest>.*)$', clean)
        if not m2:
            return clean
        rest = (m2.group('rest') or '').strip()
        rest = (' ' + rest) if rest else ''
        return f"{m2.group('head')} {label}{rest}".rstrip()
    except Exception:
        return line


def _v1092_apply_block_item_labels(msg: str) -> str:
    try:
        s = str(msg or '')
        if not any(k in s for k in ['최종판정:', '오늘의 실시간 TOP 15', '오늘 매매관점 압축']):
            return s
        lines = s.splitlines()
        out = list(lines)
        item_idxs = [i for i, line in enumerate(lines) if re.match(r'^\s*\d+\)\s+[^\(\n]{1,70}\([A-Za-z0-9]{1,8}\)', line)]
        section_re = re.compile(r'^\s*(?:\[TEST\]|━━━━━━━━|──|🧩 \[|🏆 \[|⚠️ \[|🟠 \[|🟢 \[|🟡 \[|📢 \[|🎯 \[|⛔ |기준:|정렬 보정:|진입 공통조건:|AI Pick 기준:)')
        for p, start in enumerate(item_idxs):
            end = item_idxs[p+1] if p + 1 < len(item_idxs) else len(lines)
            for j in range(start + 1, end):
                if section_re.match(lines[j]):
                    end = j
                    break
            block = '\n'.join(lines[start:end])
            out[start] = _v1092_fix_item_line(lines[start], block)
        return '\n'.join(out)
    except Exception:
        return msg


def _v1092_dedup_guides(msg: str) -> str:
    try:
        s = str(msg or '')
        guide1 = '📌 V1092: TOP15 생성단계 하드게이트 / 과열·실행보류 강등'
        guide2 = '📌 우선순위: 🟢 실행가능+응축 → 🟢 핵심스윙 → 🟡 눌림/회복확인 → 🟢 응축관찰·🔴 실행보류 → 🔴 과열보류'
        lines = []
        for line in s.splitlines():
            if line.startswith('📌 V1089:') or line.startswith('📌 V1090:') or line.startswith('📌 V1091:') or line.startswith('📌 V1092:'):
                continue
            if line.startswith('📌 우선순위: 🟢 실행가능+응축'):
                continue
            lines.append(line)
        s2 = '\n'.join(lines)
        for heading in ['🎯 [오늘 매매관점 압축]', '📢 [오늘의 실시간 TOP 15]']:
            if heading in s2 and guide1 not in s2:
                s2 = s2.replace(heading, heading + '\n' + guide1 + '\n' + guide2, 1)
        return s2
    except Exception:
        return msg


def _v1092_cleanup_market_priority_line(msg: str) -> str:
    try:
        s = str(msg or '')
        # 시장 통합 브리핑의 최우선은 라벨 게이트 전 구조 1위일 수 있으므로 표현을 안전하게 바꿈.
        s = re.sub(r'- 최우선: ([^\n]+?) / 1단계 TOP15 정렬 1위: 차트·구조·수급·기준선 우선',
                   r'- 구조상 1차 관찰: \1 / 실행 가능 여부는 TOP15 상세의 최종판정·기준선으로 재확인', s)
        return s
    except Exception:
        return msg


def _v1092_final_cleanup(msg: str) -> str:
    try:
        s = str(msg or '')
        s = _v1092_cleanup_market_priority_line(s)
        s = _v1092_apply_block_item_labels(s)
        s = _v1092_dedup_guides(s)
        # 남은 대표 중복/오류 강제 치환
        s = s.replace('🟢 응축우선·실행보류', '🟢 응축관찰·실행보류')
        s = s.replace('🟢 방어형스윙·비중축소 🟡 방어형관찰', '🟡 방어형관찰')
        s = s.replace('🟢 방어형스윙·실행보류', '🟡 방어형관찰·실행보류')
        # 같은 첫 줄에 라벨 두 개가 남으면 뒤쪽 게이트 라벨을 우선하기 위한 최소 보정
        s = re.sub(r'(\d+\)\s+[^\n]+?\([A-Za-z0-9]{1,8}\))\s+🟢 방어형스윙·비중축소\s+(🟡 방어형관찰[^|\n]*)', r'\1 \2', s)
        return s
    except Exception:
        return msg


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    try:
        msg = _V1092_RAW_TOP15_BLOCK(df, limit=limit, title=title) if _V1092_RAW_TOP15_BLOCK else ''
        return _v1092_final_cleanup(msg)
    except Exception as _v1092_e:
        try: log_error(f'⚠️ V1092 TOP15 생성단계 게이트 보정 실패: {_v1092_e}')
        except Exception: pass
        try:
            return _V1092_RAW_TOP15_BLOCK(df, limit=limit, title=title) if _V1092_RAW_TOP15_BLOCK else ''
        except Exception:
            return ''


def _v1073_compact_today_block(base: str, row_map: dict) -> str:
    try:
        msg = _V1092_RAW_TODAY_BLOCK(base, row_map) if _V1092_RAW_TODAY_BLOCK else str(base or '')
        return _v1092_final_cleanup(msg)
    except Exception:
        return str(base or '')


def _v1046_send_top15_detail(msg, max_len=3300):
    try:
        msg2 = _v1092_final_cleanup(str(msg or ''))
    except Exception:
        msg2 = msg
    if _V1092_RAW_SEND_TOP15_DETAIL:
        return _V1092_RAW_SEND_TOP15_DETAIL(msg2, max_len=max_len)
    if _V1092_RAW_SEND_CHUNKS:
        return _V1092_RAW_SEND_CHUNKS(msg2, max_len=max_len)
    if _V1092_PREV_SEND_TOP15_DETAIL:
        return _V1092_PREV_SEND_TOP15_DETAIL(msg2, max_len=max_len)
    return None


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    try:
        msg2 = _v1092_final_cleanup(str(message or ''))
    except Exception:
        msg2 = message
    if _V1092_RAW_SEND_CHUNKS:
        return _V1092_RAW_SEND_CHUNKS(msg2, title=title, max_len=max_len)
    if _V1092_PREV_SEND_CHUNKS:
        return _V1092_PREV_SEND_CHUNKS(msg2, title=title, max_len=max_len)
    return None

