def _v1093_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1093_s(v, default: str='') -> str:
    try:
        if v is None:
            return default
        if isinstance(v, float) and pd.isna(v):
            return default
        s = str(v).strip()
        return s if s else default
    except Exception:
        return default


def _v1093_num(v, default: float=0.0) -> float:
    try:
        if v is None:
            return default
        if isinstance(v, str):
            v = v.replace(',', '').replace('%','').strip()
        if v == '':
            return default
        return float(v)
    except Exception:
        return default


def _v1093_first(row, keys, default=''):
    try:
        for k in keys:
            try:
                if hasattr(row, 'get'):
                    v = row.get(k, None)
                else:
                    v = row[k] if k in row else None
                s = _v1093_s(v, '')
                if s:
                    return s
            except Exception:
                pass
        return default
    except Exception:
        return default


def _v1093_row_text(row) -> str:
    try:
        parts = []
        keys = [
            '최종판정','매매판정','추천단계','단계상태','유형','decision_mode','final_decision','phase',
            'N조합','검색패턴','수박최종상태','수박상태명','저항구름태그','수박정제태그','N구분','pattern','strategy',
            '근거','이유','대응','전략','주의','fake_severity','volume_state','candidate_scope',
            '실행기준선','상단회복선','기준/피보','RSI','rsi','이격','disparity','Disparity','BB40','bb40',
            'signal_stop_bucket','signal_stop_pct','상단회복선이격','upper_recovery_gap_pct'
        ]
        for k in keys:
            try:
                v = row.get(k, None) if hasattr(row, 'get') else None
                if v is None:
                    continue
                s = _v1093_s(v, '')
                if not s:
                    continue
                # V1092 숫자 파서가 "RSI 87" 형식을 잘 읽도록 key와 value 사이에 공백을 둔다.
                parts.append(f'{k} {s}')
            except Exception:
                pass
        # 원문 컬럼에 숨어 있는 위험 태그도 잡기 위해 짧은 전체 문자열을 보조로 추가
        try:
            if hasattr(row, 'to_dict'):
                raw = ' '.join(_v1093_s(v,'') for v in row.to_dict().values() if _v1093_s(v,''))
                parts.append(raw[:2500])
        except Exception:
            pass
        return ' | '.join(parts)
    except Exception:
        return ''


def _v1093_gate_from_row(row) -> dict:
    """V1093: 행 단위 실행 가능성 게이트. V1092 블록 게이트를 행 텍스트로 재사용하되, 신호행 컬럼도 보강한다."""
    try:
        text = _v1093_row_text(row)
        if '_v1092_gate' in globals():
            gate = _v1092_gate(text)
        else:
            gate = {'tier':'OBSERVE','reasons':[]}
        # 숫자 컬럼 보강
        rsi = _v1093_num(_v1093_first(row, ['RSI','rsi'], gate.get('rsi') or 0), gate.get('rsi') or 0)
        disp = _v1093_num(_v1093_first(row, ['이격','disparity','Disparity'], gate.get('disp') or 0), gate.get('disp') or 0)
        reasons = list(gate.get('reasons') or [])
        tier = str(gate.get('tier') or 'OBSERVE')
        if rsi >= 75 or disp >= 115:
            tier = 'OVERHEAT'
            if rsi >= 75 and not any('RSI' in x for x in reasons): reasons.append(f'RSI{rsi:g}')
            if disp >= 115 and not any('이격' in x for x in reasons): reasons.append(f'이격{disp:g}')
        # 강제 보류 조건
        hard_tokens = ['신규진입 보류','가짜수박주의(강','가짜수박 강위험','기준선 아래','실행기준선 아래','실행기준선 미확인']
        if any(tok in text for tok in hard_tokens) and tier != 'OVERHEAT':
            tier = 'BLOCK'
            if not any('보류' in x for x in reasons): reasons.append('실행보류')
        # 명시 실행 후보는 hard/overheat가 아닐 때 우선
        if tier not in ('OVERHEAT','BLOCK'):
            if any(tok in text for tok in ['소액 분할진입 가능','지금 1차 분할진입 가능','1차 분할진입 가능']):
                tier = 'SMALL'
            elif any(tok in text for tok in ['눌림 확인 후 진입','눌림 재지지','눌림 대기']):
                tier = 'PULLBACK'
            elif any(tok in text for tok in ['회복선 돌파 확인 후 진입','회복선 위 종가 안착 확인 후']):
                tier = 'RECOVERY'
        # direct replay의 DROP 기본값은 과거 미판정일 수 있으므로 단독으로는 BLOCK 처리하지 않음.
        group_map = {
            'SMALL': '🟢 실전후보-소액가능',
            'PULLBACK': '🟢 실전후보-눌림대기',
            'RECOVERY': '🟡 실전후보-회복확인',
            'OBSERVE': '👀 구조관찰',
            'BLOCK': '🔴 실행보류/진입금지',
            'OVERHEAT': '🔴 과열보류',
        }
        rank_map = {'SMALL':0, 'PULLBACK':1, 'RECOVERY':2, 'OBSERVE':6, 'BLOCK':8, 'OVERHEAT':9}
        allowed = tier in ('SMALL','PULLBACK') or (tier == 'RECOVERY' and _v1093_on('V1093_ALLOW_RECOVERY_IN_TOP15','1'))
        if tier == 'OBSERVE' and _v1093_on('V1093_ALLOW_OBSERVE_FILL','0'):
            allowed = True
        return {
            'v1093_gate_tier': tier,
            'v1093_exec_group': group_map.get(tier, '👀 구조관찰'),
            'v1093_gate_rank': rank_map.get(tier, 7),
            'v1093_top15_allowed': bool(allowed),
            'v1093_gate_reason': ', '.join(reasons[:5]) if reasons else tier,
            'v1093_rsi': rsi,
            'v1093_disparity': disp,
        }
    except Exception as e:
        return {
            'v1093_gate_tier': 'OBSERVE',
            'v1093_exec_group': '👀 구조관찰',
            'v1093_gate_rank': 7,
            'v1093_top15_allowed': False,
            'v1093_gate_reason': f'분류실패:{e}',
            'v1093_rsi': 0,
            'v1093_disparity': 0,
        }


def _v1093_enrich_df(df) -> pd.DataFrame:
    try:
        if df is None or not hasattr(df, 'empty') or df.empty:
            return df
        out = df.copy()
        infos = [_v1093_gate_from_row(row) for _, row in out.iterrows()]
        add = pd.DataFrame(infos, index=out.index)
        for c in add.columns:
            out[c] = add[c]
        for c in ['추천정렬점수','TOP15정렬점수','수급정렬점수','안전점수','N점수','v1087_priority_score']:
            if c not in out.columns:
                out[c] = 0
            out[c] = pd.to_numeric(out[c], errors='coerce').fillna(0)
        return out
    except Exception:
        return df


def _v1093_sort_and_filter_df(df, limit: int = None, strict: bool = True) -> pd.DataFrame:
    try:
        base = _V1093_BASE_SORT_TOP15(df) if _V1093_BASE_SORT_TOP15 else (df.copy() if hasattr(df, 'copy') else pd.DataFrame(df or []))
        if base is None or not hasattr(base, 'empty') or base.empty:
            return base
        out = _v1093_enrich_df(base)
        if out is None or out.empty:
            return base
        out = out.sort_values(
            by=['v1093_gate_rank','v1087_priority_score','추천정렬점수','TOP15정렬점수','안전점수','N점수'],
            ascending=[True, False, False, False, False, False],
        ).reset_index(drop=True)
        if strict and _v1093_on('V1093_FILTER_TOP15_CANDIDATES','1'):
            keep = out[out['v1093_top15_allowed'].astype(bool)].copy()
            if keep.empty and int(os.environ.get('V1093_MIN_TOP15_IF_STRICT_EMPTY','0') or 0) > 0:
                # 완전 공백이 부담될 경우에만 관찰 후보를 fallback으로 허용
                keep = out.head(int(os.environ.get('V1093_MIN_TOP15_IF_STRICT_EMPTY','0') or 0)).copy()
            return keep.reset_index(drop=True)
        return out.reset_index(drop=True)
    except Exception as e:
        try: log_error(f'⚠️ V1093 후보 필터 정렬 실패: {e}')
        except Exception: pass
        try:
            return _V1093_BASE_SORT_TOP15(df) if _V1093_BASE_SORT_TOP15 else df
        except Exception:
            return df


def _v1050_sort_df_for_top15(df):
    """V1093 override: TOP15 후보군에서 실행보류/과열보류를 먼저 제외한다."""
    return _v1093_sort_and_filter_df(df, strict=True)


def _v1093_dedup_guides(msg: str) -> str:
    try:
        s = str(msg or '')
        guide1 = '📌 V1093: 실전후보 필터 / 실행보류·과열보류 TOP15 제외'
        guide2 = '📌 우선순위: 🟢 소액가능 → 🟢 눌림대기 → 🟡 회복확인 / 실행보류·과열보류는 관찰·리스크 섹션'
        lines = []
        for line in s.splitlines():
            if line.startswith('📌 V1089:') or line.startswith('📌 V1090:') or line.startswith('📌 V1091:') or line.startswith('📌 V1092:') or line.startswith('📌 V1093:'):
                continue
            if line.startswith('📌 우선순위: 🟢 실행가능+응축') or line.startswith('📌 우선순위: 🟢 소액가능'):
                continue
            lines.append(line)
        s2 = '\n'.join(lines)
        for heading in ['🎯 [오늘 매매관점 압축]', '📢 [오늘의 실시간 TOP 15]']:
            if heading in s2 and guide1 not in s2:
                s2 = s2.replace(heading, heading + '\n' + guide1 + '\n' + guide2, 1)
        return s2
    except Exception:
        return msg


def _v1093_final_cleanup(msg: str) -> str:
    try:
        s = str(msg or '')
        if '_v1092_final_cleanup' in globals():
            s = _v1092_final_cleanup(s)
        s = _v1093_dedup_guides(s)
        s = s.replace('📌 V1092: TOP15 생성단계 하드게이트 / 과열·실행보류 강등\n', '')
        return s
    except Exception:
        return msg


def _v1093_empty_top_block(title='오늘의 실시간 TOP 15') -> str:
    return '\n'.join([
        f'📢 [{title}]',
        '📌 V1093: 실전후보 필터 / 실행보류·과열보류 TOP15 제외',
        '📌 우선순위: 🟢 소액가능 → 🟢 눌림대기 → 🟡 회복확인 / 실행보류·과열보류는 관찰·리스크 섹션',
        '',
        '실전 TOP 후보 없음: 신규진입 보류·과열·기준선 미충족 후보는 TOP15에서 제외했습니다.',
        '대응: 오늘은 예비 삼각수렴/BB응축·저평가 1파 섹션에서 기준선 재지지 후보만 관찰합니다.',
    ]).strip()


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    """V1093 override: TOP15 생성 자체를 실전 후보로 제한한다."""
    try:
        lim = max(1, int(limit or 15))
        filtered = _v1093_sort_and_filter_df(df, limit=lim, strict=True)
        if filtered is None or not hasattr(filtered, 'empty') or filtered.empty:
            return _v1093_empty_top_block(title=title)
        # 실전후보 수가 15개보다 적으면 실제 개수만 출력한다.
        use_lim = min(lim, len(filtered))
        if _V1093_BASE_TOP15_BLOCK:
            msg = _V1093_BASE_TOP15_BLOCK(filtered, limit=use_lim, title=title)
        else:
            msg = ''
        return _v1093_final_cleanup(msg)
    except Exception as e:
        try: log_error(f'⚠️ V1093 TOP15 실전후보 필터 생성 실패: {e}')
        except Exception: pass
        try:
            return _V1093_BASE_TOP15_BLOCK(df, limit=limit, title=title) if _V1093_BASE_TOP15_BLOCK else ''
        except Exception:
            return ''


def _v1073_compact_today_block(base: str, row_map: dict) -> str:
    try:
        msg = _V1093_BASE_TODAY_BLOCK(base, row_map) if _V1093_BASE_TODAY_BLOCK else str(base or '')
        return _v1093_final_cleanup(msg)
    except Exception:
        return str(base or '')


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1093 wrapper: 성과검증 신호행에 실전 필터 그룹을 저장한다."""
    try:
        base = _V1093_BASE_SIGNAL_ROW_FROM_SERIES(row, rank=rank, source=source) if _V1093_BASE_SIGNAL_ROW_FROM_SERIES else {}
    except Exception:
        base = {}
    try:
        info = _v1093_gate_from_row(row)
        base.update({k: v for k, v in info.items() if k.startswith('v1093_')})
    except Exception:
        pass
    return base


def _v1093_fmt(v) -> str:
    try:
        if pd.isna(v): return 'N/A'
        return f'{float(v):+.2f}%'
    except Exception:
        return 'N/A'


def _v1093_rate(v) -> str:
    try:
        return f'{float(v):.1f}%'
    except Exception:
        return '0.0%'


def _v1093_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int=10) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        lines = [f'[{title}]']
        rows = []
        for key, g in ok.groupby(col, dropna=False):
            key = _v1093_s(key, '미분류')
            n = len(g)
            r3 = pd.to_numeric(g.get('next3_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r5 = pd.to_numeric(g.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r10 = pd.to_numeric(g.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            best10 = pd.to_numeric(g.get('best_ret_10d', g.get('max_up_10d', pd.Series(dtype=float))), errors='coerce').mean()
            p3 = g.get('plus3_first_10d', g.get('plus3_first', pd.Series([False]*n))).astype(bool).mean() * 100
            p5 = g.get('plus5_first_10d', g.get('plus5_first', pd.Series([False]*n))).astype(bool).mean() * 100
            stop10 = g.get('stop_first_10d', g.get('stop_first', pd.Series([False]*n))).astype(bool).mean() * 100
            rows.append((key, n, r3, r5, r10, best10, p3, p5, stop10))
        # 실전후보 계열 우선, 그다음 성과순
        order = {'🟢 실전후보-소액가능':0, '🟢 실전후보-눌림대기':1, '🟡 실전후보-회복확인':2, '👀 구조관찰':5, '🔴 실행보류/진입금지':8, '🔴 과열보류':9}
        rows.sort(key=lambda x: (order.get(x[0], 6), -(x[4] if not pd.isna(x[4]) else -999)))
        for key, n, r3, r5, r10, best10, p3, p5, stop10 in rows[:max_rows]:
            small = ' ⚠️표본주의' if n < 3 else ''
            lines.append(f'- {key}: {n}개 | 3일 {_v1093_fmt(r3)} / 5일 {_v1093_fmt(r5)} / 10일 {_v1093_fmt(r10)} | 10일최고 {_v1093_fmt(best10)} | +3먼저 {_v1093_rate(p3)} | +5먼저 {_v1093_rate(p5)} | 손절먼저 {_v1093_rate(stop10)}{small}')
        lines.append('')
        return lines
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1093_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out = eval_df.copy()
        infos = [_v1093_gate_from_row(row) for _, row in out.iterrows()]
        add = pd.DataFrame(infos, index=out.index)
        for c in add.columns:
            out[c] = out[c] if c in out.columns else add[c]
            # 기존 값이 없거나 미분류이면 새 값으로 채움
            try:
                out[c] = out[c].where(out[c].astype(str).str.len() > 0, add[c])
            except Exception:
                out[c] = add[c]
        return out
    except Exception:
        return eval_df


def _v1093_report_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1093 실전후보 필터 백테스트]', '- 평가 데이터가 없습니다.', '']
        ok = eval_df[eval_df.get('eval_status', '') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok = _v1093_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1093 실전후보 필터 백테스트]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        total = len(ok)
        allowed = ok[ok.get('v1093_top15_allowed', pd.Series([False]*total)).astype(bool)].copy() if 'v1093_top15_allowed' in ok.columns else pd.DataFrame()
        blocked = total - len(allowed)
        lines = ['[V1093 실전후보 필터 백테스트]']
        lines.append('- 목적: TOP15에 “구조는 좋지만 실행보류/과열”인 후보가 섞이는 문제를 후보 선별 단계에서 제거합니다.')
        lines.append(f'- 필터 결과: 평가 {total}개 중 실전TOP 허용 {len(allowed)}개 / 제외·관찰 {blocked}개')
        lines.append('- 제외 기준: 신규진입 보류, RSI75↑, 이격115↑, 가짜수박 강, 실행기준선 아래, 기준선 미확인')
        lines.append('')
        lines += _v1093_group_lines(ok, 'v1093_exec_group', 'V1093 실행게이트 그룹별 성과', max_rows=10)
        if not allowed.empty:
            lines += _v1093_group_lines(allowed, 'signal_stop_bucket', 'V1093 실전TOP 손절거리별 성과', max_rows=8)
            lines += _v1093_group_lines(allowed, 'volume_state', 'V1093 실전TOP 거래량상태별 성과', max_rows=8)
            try:
                tmp = allowed.copy()
                tmp['_ret10'] = pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
                tmp = tmp.sort_values('_ret10', ascending=False).head(8)
                lines.append('[V1093 실전TOP 예시]')
                for _, r in tmp.iterrows():
                    name = _v1093_s(r.get('name', r.get('종목명', '')),'')
                    code = _v1093_s(r.get('code', r.get('종목코드', '')),'')
                    grp = _v1093_s(r.get('v1093_exec_group',''))
                    r10 = _v1093_num(r.get('next10_close_ret', 0), 0.0)
                    stopb = _v1093_s(r.get('signal_stop_bucket',''))
                    lines.append(f'- {name}({code}) | {grp} | 10일 {r10:+.2f}% | 손절거리 {stopb or "N/A"}')
                lines.append('')
            except Exception:
                pass
        lines.append('[V1093 적용 가이드]')
        lines.append('- 실전TOP은 소액가능/눌림대기/회복확인 후보만 사용합니다.')
        lines.append('- 실행보류·과열보류는 TOP15 성과와 분리해서 관찰/리스크 섹션으로만 봅니다.')
        lines.append('- 실전TOP 표본이 너무 적으면 검색식이 강한 것이므로, 당일 무리매매보다 관찰 유지가 맞습니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1093 실전후보 필터 백테스트]', f'- 생성 실패: {e}', '']


def _v1093_inject_report(report: str, lines: list) -> str:
    try:
        if '[V1093 실전후보 필터 백테스트]' in str(report or ''):
            return report
        block = '\n'.join(lines).strip() + '\n'
        # V1087 블록 바로 뒤 또는 기존 관점/전략별 앞에 삽입
        for marker in ['\n[관점/전략별]', '\n[패턴별]', '\n[추천단계별]', '\n[V1087 해석 포인트]']:
            idx = str(report).find(marker)
            if idx >= 0:
                return report[:idx].rstrip() + '\n\n' + block + '\n' + report[idx:].lstrip('\n')
        return str(report or '').rstrip() + '\n\n' + block
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1093 override: 실전후보 필터 기준의 백테스트 성과 블록을 추가한다."""
    try:
        work = _v1093_enrich_eval(eval_df.copy()) if eval_df is not None and not eval_df.empty else eval_df
        report = _V1093_BASE_BUILD_DIRECT_REPORT(work, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1093_BASE_BUILD_DIRECT_REPORT else ''
        for old in ['🧪 [V1087 직접 재현 주간 성과검증]', '🧪 [V1086 직접 재현 주간 성과검증]', '🧪 [V1085 직접 재현 주간 성과검증]', '🧪 [V1084 직접 재현 주간 성과검증]', '🧪 [V1081 직접 재현 주간 성과검증]']:
            report = str(report or '').replace(old, '🧪 [V1093 직접 재현 주간 성과검증]', 1)
        if _v1093_on('V1093_BACKTEST_REPORT_BLOCK','1'):
            report = _v1093_inject_report(report, _v1093_report_lines(work))
        return report
    except Exception as e:
        try:
            if _V1093_BASE_BUILD_DIRECT_REPORT:
                return _V1093_BASE_BUILD_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1093 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

