def _v1094_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1094_num_from_text(text: str, key: str) -> float:
    try:
        s = str(text or '')
        # 예: RSI 87 / 이격 127, RSI87↑, 이격127 부담
        pats = [rf'{key}\s*[:=]?\s*([0-9]+(?:\.[0-9]+)?)', rf'{key}([0-9]+(?:\.[0-9]+)?)']
        for pat in pats:
            m = re.search(pat, s, flags=re.I)
            if m:
                return float(m.group(1))
    except Exception:
        pass
    return 0.0


def _v1094_first_line(block: str) -> str:
    try:
        for line in str(block or '').splitlines():
            if re.match(r'^\s*\d+\)\s+', line):
                return line.rstrip()
    except Exception:
        pass
    return ''


def _v1094_stop_tail(block: str) -> str:
    try:
        line = _v1094_first_line(block)
        if '손절양호' in line:
            return '손절양호'
        if '비중축소' in line:
            return '비중축소'
        # 손절참고/손절가와 현재가 거리 계산은 출력문만으로 불안정하므로 기본은 비중축소
        return '비중축소'
    except Exception:
        return '비중축소'


def _v1094_gate_from_block(block: str) -> dict:
    """TOP15 항목 전체 텍스트 기준 최종 실전 허용 여부."""
    s = str(block or '')
    rsi = _v1094_num_from_text(s, 'RSI')
    disp = _v1094_num_from_text(s, '이격')
    final_small = any(tok in s for tok in ['최종판정: 🟡 소액 분할진입 가능','최종판정: 🟢 지금 1차 분할진입 가능','🧭 🟡 소액 분할진입 가능','🧭 🟢 지금 1차 분할진입 가능'])
    final_pull = any(tok in s for tok in ['최종판정: 🟡 눌림 확인 후 진입','🧭 🟡 눌림 확인 후 진입'])
    final_reco = any(tok in s for tok in ['최종판정: 🟠 회복선 돌파 확인 후 진입','🧭 🟠 회복선 돌파 확인 후 진입'])
    final_block = any(tok in s for tok in ['최종판정: 🔴 신규진입 보류','🧭 🔴 신규진입 보류','신규진입 보류'])
    fake_strong = any(tok in s for tok in ['🚫가짜수박주의(강','가짜수박주의(강','가짜수박 강위험','가짜수박 강'])
    base_below = any(tok in s for tok in ['실행기준선 미확인','기준선 미확인','실행기준선 아래','기준선 아래','/아래'])
    overheat = (rsi >= 75) or (disp >= 115)
    reasons = []
    if final_block: reasons.append('신규진입보류')
    if fake_strong: reasons.append('가짜수박강')
    if base_below: reasons.append('기준선아래')
    if rsi >= 75: reasons.append(f'RSI{rsi:g}')
    if disp >= 115: reasons.append(f'이격{disp:g}')
    tier = 'BLOCK'
    allowed = False
    # 과열/명시 보류/강한 가짜수박/기준선 아래는 실전 TOP 제외
    if overheat:
        tier = 'OVERHEAT'
    elif final_block or fake_strong or base_below:
        tier = 'BLOCK'
    elif final_small:
        tier = 'SMALL'; allowed = True
    elif final_pull:
        tier = 'PULLBACK'; allowed = True
    elif final_reco:
        tier = 'RECOVERY'; allowed = _v1094_on('V1094_KEEP_RECOVERY_IN_REAL_TOP','1')
    else:
        # 명시 실행판정이 없으면 TOP 후보로 보지 않는다.
        tier = 'OBSERVE'
        reasons.append('명시실행판정없음')
    label_head = {
        'SMALL': '🟢 응축우선·소액가능',
        'PULLBACK': '🟢 응축우선·눌림대기',
        'RECOVERY': '🟢 핵심스윙·회복확인',
        'OVERHEAT': '🔴 과열보류·실행보류',
        'BLOCK': '🔴 확인필요·실행보류',
        'OBSERVE': '👀 구조관찰',
    }.get(tier, '👀 구조관찰')
    return {
        'tier': tier,
        'allowed': bool(allowed),
        'rsi': rsi,
        'disp': disp,
        'reasons': reasons,
        'label': f"{label_head}·{_v1094_stop_tail(s)}",
    }


_V1094_LABEL_RE = re.compile(
    r'\s*(?:🟢|🟡|🟠|🔴|👀)\s*'
    r'(?:응축우선|응축관찰|핵심스윙|핵심관찰|방어형스윙|방어형관찰|일반관찰|공격형/추격주의|공격형보류|확인필요|돌파확인대기|과열보류|구조관찰)'
    r'(?:·(?:손절양호|비중축소|소액가능|실행보류|눌림대기|회복확인|확인대기|관찰))*'
)


def _v1094_relabel_block(block: str, new_no: int, gate: dict) -> str:
    try:
        lines = str(block or '').splitlines()
        if not lines:
            return block
        # 첫 번호 라인 찾기
        idx = next((i for i,l in enumerate(lines) if re.match(r'^\s*\d+\)\s+', l)), 0)
        line = lines[idx].rstrip()
        line = re.sub(r'^\s*\d+\)\s+', f'{new_no}) ', line, count=1)
        # 종목코드 닫는 괄호 이후 ~ | 현재 사이의 기존 우선순위 라벨만 제거. AI Pick은 보존.
        m = re.search(r'(\([0-9A-Z]{6}\)\s+)(.*?)(\s*\|\s*현재)', line)
        if m:
            prefix, mid, suffix = m.group(1), m.group(2), m.group(3)
            ai = ''
            aim = re.search(r'\s*(🤖\s*[^|]+)$', mid.strip())
            if aim:
                ai = ' ' + aim.group(1).strip()
            clean_mid = _V1094_LABEL_RE.sub('', mid).strip()
            # 라벨 외 잡음은 버리고 AI만 보존
            line = line[:m.start(1)] + prefix + gate.get('label','').strip() + ai + suffix + line[m.end(3):]
        else:
            # fallback: 번호만 바꾸고 라벨을 종목코드 뒤에 삽입
            line = re.sub(r'(\([0-9A-Z]{6}\)\s+)', r'\1' + gate.get('label','').strip() + ' ', line, count=1)
        lines[idx] = line
        return '\n'.join(lines).strip()
    except Exception:
        return block


def _v1094_split_numbered_blocks(msg: str):
    lines = str(msg or '').splitlines()
    starts = [i for i,l in enumerate(lines) if re.match(r'^\s*\d+\)\s+', l)]
    if not starts:
        return lines, [], []
    header = lines[:starts[0]]
    blocks = []
    for pos, st in enumerate(starts):
        en = starts[pos+1] if pos+1 < len(starts) else len(lines)
        blocks.append('\n'.join(lines[st:en]).strip())
    return header, blocks, []


def _v1094_clean_guides_from_header(header_lines):
    guide1 = '📌 V1094: STRICT 실전 TOP / 실행보류·과열보류 NO-BACKFILL'
    guide2 = '📌 원칙: 실전 후보가 적으면 적은 대로 출력 / 진입금지·실행보류는 TOP에서 제외'
    out = []
    inserted = False
    for line in header_lines:
        if line.startswith('📌 V1089:') or line.startswith('📌 V1090:') or line.startswith('📌 V1091:') or line.startswith('📌 V1092:') or line.startswith('📌 V1093:') or line.startswith('📌 V1094:'):
            continue
        if line.startswith('📌 우선순위:') or line.startswith('📌 원칙:'):
            continue
        if _v1094_on('V1094_RENAME_TOP_TITLE','1') and '📢 [오늘의 실시간 TOP 15]' in line:
            line = line.replace('📢 [오늘의 실시간 TOP 15]', '📢 [오늘의 STRICT 실전 TOP]')
        out.append(line)
        if ('📢 [오늘의 STRICT 실전 TOP]' in line or '📢 [오늘의 실시간 TOP 15]' in line) and not inserted:
            out.append(guide1)
            out.append(guide2)
            inserted = True
    if not inserted:
        out = ['📢 [오늘의 STRICT 실전 TOP]', guide1, guide2, ''] + out
    return out


def _v1094_filter_top_message(msg: str, limit: int=15) -> str:
    try:
        s = str(msg or '')
        if '오늘의 실시간 TOP' not in s and '오늘의 STRICT 실전 TOP' not in s:
            return _v1094_cleanup_guides_general(s)
        header, blocks, footer = _v1094_split_numbered_blocks(s)
        if not blocks:
            return _v1094_cleanup_guides_general(s)
        kept = []
        removed = []
        for b in blocks:
            gate = _v1094_gate_from_block(b)
            if gate.get('allowed') and len(kept) < int(limit or 15):
                kept.append((b, gate))
            else:
                removed.append((b, gate))
        new_lines = _v1094_clean_guides_from_header(header)
        # 기존 기준 설명 중 TOP15라는 표현을 실전 TOP으로 완화
        new_head = '\n'.join(new_lines)
        new_head = new_head.replace('TOP15는 1단계 빠른 대응 후보', 'STRICT 실전 TOP은 실행 가능한 후보')
        new_lines = new_head.splitlines()
        if not kept:
            new_lines += ['', '실전 TOP 후보 없음: 오늘은 조건을 만족한 소액가능/눌림대기/회복확인 후보가 없습니다.', '대응: 무리하게 15개를 채우지 않고, 예비/관찰 섹션에서 기준선 재지지 여부만 확인합니다.']
        else:
            new_lines += ['', f'실전 후보 {len(kept)}개만 표시합니다. 실행보류·진입금지 후보는 TOP에서 제외했습니다.', '']
            for i, (b, gate) in enumerate(kept, 1):
                new_lines.append(_v1094_relabel_block(b, i, gate))
                new_lines.append('')
        preview_lim = int(os.environ.get('V1094_OBSERVE_PREVIEW_LIMIT','5') or 0)
        if preview_lim > 0 and removed:
            new_lines += ['👀 [구조관찰/리스크 분리] TOP 제외 후보 일부', '기준: 실행보류·과열·기준선 미충족 후보는 실전 TOP에서 제외하고 관찰만 합니다.']
            for j, (b, gate) in enumerate(removed[:preview_lim], 1):
                fl = _v1094_first_line(b)
                fl = re.sub(r'^\s*\d+\)\s+', f'{j}) ', fl)
                # 너무 긴 첫 줄 정리
                reason = ','.join(gate.get('reasons') or [gate.get('tier','')])
                new_lines.append(f'- {fl} | 제외사유: {reason}')
        return '\n'.join(new_lines).strip()
    except Exception as e:
        try: log_error(f'⚠️ V1094 TOP 메시지 필터 실패: {e}')
        except Exception: pass
        return msg


def _v1094_cleanup_guides_general(msg: str) -> str:
    try:
        s = str(msg or '')
        # 오늘 매매관점 압축의 안내문도 V1094 1회만 남긴다.
        if '🎯 [오늘 매매관점 압축]' in s:
            lines = []
            inserted = False
            for line in s.splitlines():
                if line.startswith('📌 V1089:') or line.startswith('📌 V1090:') or line.startswith('📌 V1091:') or line.startswith('📌 V1092:') or line.startswith('📌 V1093:') or line.startswith('📌 V1094:'):
                    continue
                if line.startswith('📌 우선순위:') or line.startswith('📌 원칙:'):
                    continue
                lines.append(line)
                if '🎯 [오늘 매매관점 압축]' in line and not inserted:
                    lines.append('📌 V1094: STRICT 실전 TOP / 실행보류·과열보류 NO-BACKFILL')
                    lines.append('📌 원칙: 실전 후보가 적으면 적은 대로 출력 / 진입금지·실행보류는 TOP에서 제외')
                    inserted = True
            s = '\n'.join(lines)
        return s
    except Exception:
        return msg


def _v1094_final_cleanup(msg: str, limit: int=15) -> str:
    try:
        s = str(msg or '')
        if '_v1093_final_cleanup' in globals():
            try:
                s = _v1093_final_cleanup(s)
            except Exception:
                pass
        return _v1094_filter_top_message(s, limit=limit)
    except Exception:
        return msg


def _v1050_build_compact_top15_block(df, limit: int = 15, title='오늘의 실시간 TOP 15') -> str:
    """V1094 override: raw TOP 후보를 넓게 생성한 뒤 실전 가능 항목만 남기고 절대 backfill하지 않는다."""
    try:
        lim = max(1, int(limit or 15))
        raw_lim = max(lim, int(os.environ.get('V1094_RAW_SCAN_LIMIT','80') or 80))
        if _V1094_RAW_TOP15_BLOCK:
            msg = _V1094_RAW_TOP15_BLOCK(df, limit=raw_lim, title=title)
        else:
            msg = ''
        return _v1094_final_cleanup(msg, limit=lim)
    except Exception as e:
        try: log_error(f'⚠️ V1094 STRICT 실전 TOP 생성 실패: {e}')
        except Exception: pass
        try:
            return _v1094_final_cleanup(_V1094_RAW_TOP15_BLOCK(df, limit=limit, title=title), limit=limit) if _V1094_RAW_TOP15_BLOCK else ''
        except Exception:
            return ''


def _v1073_compact_today_block(base: str, row_map: dict) -> str:
    try:
        msg = _V1094_BASE_TODAY_BLOCK(base, row_map) if _V1094_BASE_TODAY_BLOCK else str(base or '')
        return _v1094_final_cleanup(msg, limit=15)
    except Exception:
        return str(base or '')


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1094 override: V1093 백테스트 블록을 STRICT NO-BACKFILL 관점으로 명시한다."""
    try:
        report = _V1094_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1094_BASE_DIRECT_REPORT else ''
        s = str(report or '')
        s = s.replace('🧪 [V1093 직접 재현 주간 성과검증]', '🧪 [V1094 직접 재현 주간 성과검증]')
        s = s.replace('[V1093 실전후보 필터 백테스트]', '[V1094 STRICT 실전TOP NO-BACKFILL 백테스트]')
        s = s.replace('TOP15에 “구조는 좋지만 실행보류/과열”인 후보가 섞이는 문제를 후보 선별 단계에서 제거합니다.', '실전 후보가 부족해도 15개를 억지로 채우지 않고, 실행보류/과열 후보를 실전TOP에서 완전히 분리합니다.')
        s = s.replace('실전TOP 허용', 'STRICT 실전TOP 허용')
        s = s.replace('실전TOP은 소액가능/눌림대기/회복확인 후보만 사용합니다.', 'STRICT 실전TOP은 소액가능/눌림대기/회복확인 후보만 사용하고, 표본이 적어도 backfill하지 않습니다.')
        return s
    except Exception as e:
        try:
            if _V1094_BASE_DIRECT_REPORT:
                return _V1094_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1094 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

