# =============================================================
# ✅ V1095_STRICT_BACKTEST_GATE_REPLAY_FIX_ACTIVE
# - V1094 라이브 STRICT TOP은 성공했으나 DIRECT_REPLAY 백테스트에서
#   DROP 기본값/미판정 행이 모두 실전후보-눌림대기로 열리던 문제 수정
# - 백테스트에서는 라벨만 믿지 않고 final_decision/후보범위/RSI/이격/가짜수박/손절거리/V1087 우선순위를 다시 분류
# - DROP 기본값은 실전 제외 확정이 아니라 "미판정/관찰"로 분리하고 STRICT 허용에서 제외
# =============================================================
print("✅ V1095_STRICT_BACKTEST_GATE_REPLAY_FIX_ACTIVE LOADED")
try:
    os.environ.setdefault('V1095_STRICT_BACKTEST_GATE_REPLAY_FIX', '1')
    os.environ.setdefault('V1095_BACKTEST_REPORT_BLOCK', '1')
    os.environ.setdefault('V1095_ALLOW_DROP_DEFAULT', '0')
    os.environ.setdefault('V1095_ALLOW_RECOVERY_IN_STRICT', '1')
    os.environ.setdefault('V1095_ALLOW_PASS_A_AS_PULLBACK', '1')
    os.environ.setdefault('V1095_MIN_STRICT_SCORE', '0')
except Exception:
    pass

try:
    _V1095_BASE_DIRECT_REPORT = globals().get('_v1081_build_direct_report')
except Exception:
    _V1095_BASE_DIRECT_REPORT = None
try:
    _V1095_BASE_SIGNAL_ROW = globals().get('_v1080_signal_row_from_series')
except Exception:
    _V1095_BASE_SIGNAL_ROW = None


def _v1095_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1095_s(v, default: str='') -> str:
    try:
        if v is None:
            return default
        if isinstance(v, float) and pd.isna(v):
            return default
        s = str(v).strip()
        return s if s else default
    except Exception:
        return default


def _v1095_num(v, default: float=0.0) -> float:
    try:
        if v is None:
            return default
        if isinstance(v, str):
            s = v.replace(',', '').replace('%', '').strip()
            if not s:
                return default
            return float(s)
        if pd.isna(v):
            return default
        return float(v)
    except Exception:
        return default


def _v1095_first(row, keys, default=''):
    try:
        for k in keys:
            try:
                if hasattr(row, 'get'):
                    v = row.get(k, None)
                else:
                    v = row[k] if k in row else None
                if v is not None and not (isinstance(v, float) and pd.isna(v)) and str(v).strip() != '':
                    return v
            except Exception:
                pass
    except Exception:
        pass
    return default


def _v1095_text(row) -> str:
    keys = [
        'final_decision','final_decision_v1085','decision_mode','candidate_scope_v1085','judge_quality_v1085',
        'phase','strategy','pattern','volume_state','fake_severity','signal_stop_bucket',
        'v1087_priority_class','v1087_action_guide','v1087_reason','v1093_gate_tier','v1093_exec_group','v1093_gate_reason',
        'v1095_gate_tier','v1095_gate_group'
    ]
    parts = []
    try:
        for k in keys:
            try:
                v = row.get(k, '') if hasattr(row, 'get') else ''
                if _v1095_s(v):
                    parts.append(_v1095_s(v))
            except Exception:
                pass
    except Exception:
        pass
    return ' '.join(parts)


def _v1095_v1087_info(row) -> dict:
    try:
        if 'v1087_priority_class' in row and _v1095_s(row.get('v1087_priority_class','')):
            return {
                'v1087_priority_class': _v1095_s(row.get('v1087_priority_class','')),
                'v1087_priority_score': _v1095_num(row.get('v1087_priority_score',0),0),
                'v1087_reason': _v1095_s(row.get('v1087_reason','')),
                'v1087_action_guide': _v1095_s(row.get('v1087_action_guide','')),
            }
        if '_v1087_classify' in globals():
            return _v1087_classify(row)
    except Exception:
        pass
    return {'v1087_priority_class':'미분류','v1087_priority_score':0,'v1087_reason':'','v1087_action_guide':''}


def _v1095_gate_from_eval_row(row) -> dict:
    """V1095: DIRECT_REPLAY 평가행 기준 STRICT 게이트 재분류.
    핵심 원칙: DROP 기본값/미판정은 실전 허용이 아니라 관찰로 둔다.
    """
    try:
        txt = _v1095_text(row)
        fd = _v1095_s(_v1095_first(row, ['final_decision','final_decision_v1085','추천단계','최종판정'], ''))
        scope = _v1095_s(_v1095_first(row, ['candidate_scope_v1085','candidate_scope','후보범위'], ''))
        quality = _v1095_s(_v1095_first(row, ['judge_quality_v1085','judge_quality','판정품질'], ''))
        phase = _v1095_s(_v1095_first(row, ['phase','추천단계','유형'], ''))
        fake = _v1095_s(_v1095_first(row, ['fake_severity','가짜수박강도','가짜수박'], ''))
        stopb = _v1095_s(_v1095_first(row, ['signal_stop_bucket','손절거리','stop_bucket'], ''))
        vol = _v1095_s(_v1095_first(row, ['volume_state','거래량상태'], ''))
        rsi = _v1095_num(_v1095_first(row, ['rsi','RSI'], 0), 0)
        disp = _v1095_num(_v1095_first(row, ['disparity','이격','Disparity'], 0), 0)
        v1087 = _v1095_v1087_info(row)
        pri = _v1095_s(v1087.get('v1087_priority_class',''))
        pri_score = _v1095_num(v1087.get('v1087_priority_score',0),0)
        alltxt = ' '.join([txt, fd, scope, quality, phase, fake, stopb, vol, pri, _v1095_s(v1087.get('v1087_reason',''))])

        final_drop_default = (fd.upper() == 'DROP') or ('DROP기본값' in alltxt) or ('원후보/미판정' in alltxt) or ('직접검증주의' in alltxt)
        explicit_pass = ('PASS_A' in alltxt) or ('실전후보' in scope) or ('명시판정' in quality)
        explicit_block = any(tok in alltxt for tok in ['신규진입 보류','신규진입보류','진입금지','실행보류','실전 후보 제외','실전제외'])
        fake_strong = any(tok in alltxt for tok in ['가짜수박 강','가짜수박강','강위험','가짜수박주의(강'])
        overheat = (rsi >= 75) or (disp >= 115)
        stop_good = ('-3~-5' in stopb) or ('-3%~-5%' in stopb)
        stop_ok = stop_good or ('-5~-8' in stopb) or ('-5%~-8%' in stopb)
        stop_wide = ('-8' in stopb and not stop_ok) or ('초과' in stopb)
        compression = ('거래량응축' in vol) or ('응축우선' in pri)
        core_swing = ('핵심스윙' in pri)
        high_priority = ('응축우선' in pri) or ('핵심스윙' in pri) or (pri_score >= 65)
        weak_priority = ('확인필요' in pri) or ('강등' in pri)

        small = any(tok in alltxt for tok in ['소액 분할진입 가능','소액가능','1차 분할진입 가능','지금 1차'])
        pull = any(tok in alltxt for tok in ['눌림 확인 후 진입','눌림대기','눌림 재지지','첫눌림'])
        reco = any(tok in alltxt for tok in ['회복선 돌파 확인','회복확인','회복선 위 종가'])

        tier = 'OBSERVE'
        allowed = False
        reasons = []

        if overheat:
            tier = 'OVERHEAT'
            if rsi >= 75: reasons.append(f'RSI{rsi:g}')
            if disp >= 115: reasons.append(f'이격{disp:g}')
        elif explicit_block or fake_strong:
            tier = 'BLOCK'
            if explicit_block: reasons.append('명시보류')
            if fake_strong: reasons.append('가짜수박강')
        elif final_drop_default and not _v1095_on('V1095_ALLOW_DROP_DEFAULT','0'):
            tier = 'UNKNOWN_DROP'
            reasons.append('DROP기본값/미판정')
        elif stop_wide:
            tier = 'OBSERVE'
            reasons.append('손절거리과다')
        else:
            # 명시 실행판정 우선. PASS_A는 과거 직접검증의 제한적 실전후보로 PULLBACK 처리한다.
            if small:
                tier = 'SMALL'; allowed = True; reasons.append('명시소액가능')
            elif pull:
                tier = 'PULLBACK'; allowed = True; reasons.append('명시눌림대기')
            elif reco:
                tier = 'RECOVERY'; allowed = _v1095_on('V1095_ALLOW_RECOVERY_IN_STRICT','1'); reasons.append('명시회복확인')
            elif explicit_pass and _v1095_on('V1095_ALLOW_PASS_A_AS_PULLBACK','1'):
                tier = 'PULLBACK'; allowed = True; reasons.append('PASS_A/명시판정')
            elif high_priority and stop_ok and not weak_priority:
                # DROP 기본값이 아닌 경우에만 구조 우선 후보를 제한 허용한다.
                tier = 'PULLBACK' if compression else 'OBSERVE'
                allowed = (tier == 'PULLBACK')
                reasons.append('우선순위+손절거리')
            else:
                tier = 'OBSERVE'
                reasons.append('실전판정부족')

        # 최종 안전장치: RSI/이격/가짜수박/명시보류는 어떤 경우에도 허용 금지
        if overheat or explicit_block or fake_strong:
            allowed = False
        min_score = _v1095_num(os.environ.get('V1095_MIN_STRICT_SCORE','0'),0)
        if allowed and min_score and pri_score < min_score:
            allowed = False
            reasons.append(f'우선점수미달{pri_score:g}')

        group_map = {
            'SMALL': '🟢 STRICT-소액가능',
            'PULLBACK': '🟢 STRICT-눌림대기',
            'RECOVERY': '🟡 STRICT-회복확인',
            'OBSERVE': '👀 구조관찰',
            'UNKNOWN_DROP': '⚪ 미판정/DROP기본값',
            'BLOCK': '🔴 실행보류/진입금지',
            'OVERHEAT': '🔴 과열보류',
        }
        rank_map = {'SMALL':0,'PULLBACK':1,'RECOVERY':2,'OBSERVE':6,'UNKNOWN_DROP':7,'BLOCK':8,'OVERHEAT':9}
        return {
            'v1095_gate_tier': tier,
            'v1095_gate_group': group_map.get(tier, '👀 구조관찰'),
            'v1095_gate_rank': rank_map.get(tier, 7),
            'v1095_strict_allowed': bool(allowed),
            'v1095_gate_reason': ','.join(reasons[:6]) if reasons else tier,
            'v1095_rsi': rsi,
            'v1095_disparity': disp,
            'v1095_v1087_priority_class': pri,
            'v1095_v1087_priority_score': pri_score,
            'v1095_signal_stop_bucket': stopb,
            'v1095_volume_state': vol,
        }
    except Exception as e:
        return {
            'v1095_gate_tier':'OBSERVE',
            'v1095_gate_group':'👀 구조관찰',
            'v1095_gate_rank':7,
            'v1095_strict_allowed':False,
            'v1095_gate_reason':f'분류실패:{e}',
            'v1095_rsi':0,
            'v1095_disparity':0,
            'v1095_v1087_priority_class':'미분류',
            'v1095_v1087_priority_score':0,
            'v1095_signal_stop_bucket':'',
            'v1095_volume_state':'',
        }


def _v1095_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out = eval_df.copy()
        # V1087 분류 컬럼이 없으면 먼저 보강한다.
        try:
            if '_v1087_enrich' in globals() and 'v1087_priority_class' not in out.columns:
                out = _v1087_enrich(out)
        except Exception:
            pass
        infos = [_v1095_gate_from_eval_row(row) for _, row in out.iterrows()]
        add = pd.DataFrame(infos, index=out.index)
        for c in add.columns:
            out[c] = add[c]
        return out
    except Exception:
        return eval_df


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1095 wrapper: 신호행 생성 시에도 V1095 STRICT 게이트 후보 컬럼을 저장한다."""
    try:
        base = _V1095_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1095_BASE_SIGNAL_ROW else {}
    except Exception:
        base = {}
    try:
        if base is not None:
            tmp = dict(base)
            # 원 row 정보와 base 정보를 함께 보고 게이트 판정
            try:
                raw = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
                tmp.update({k: v for k, v in raw.items() if k not in tmp})
            except Exception:
                pass
            info = _v1095_gate_from_eval_row(tmp)
            base.update(info)
    except Exception:
        pass
    return base


def _v1095_fmt(v) -> str:
    try:
        if pd.isna(v):
            return 'N/A'
        return f'{float(v):+.2f}%'
    except Exception:
        return 'N/A'


def _v1095_rate(v) -> str:
    try:
        return f'{float(v):.1f}%'
    except Exception:
        return '0.0%'


def _v1095_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int=10) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        lines = [f'[{title}]']
        rows = []
        for key, g in ok.groupby(col, dropna=False):
            key = _v1095_s(key, '미분류')
            n = len(g)
            r3 = pd.to_numeric(g.get('next3_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r5 = pd.to_numeric(g.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r10 = pd.to_numeric(g.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            best10 = pd.to_numeric(g.get('best_ret_10d', g.get('max_up_10d', pd.Series(dtype=float))), errors='coerce').mean()
            p3 = g.get('plus3_first_10d', g.get('plus3_first', pd.Series([False]*n))).astype(bool).mean()*100
            p5 = g.get('plus5_first_10d', g.get('plus5_first', pd.Series([False]*n))).astype(bool).mean()*100
            stop10 = g.get('stop_first_10d', g.get('stop_first', pd.Series([False]*n))).astype(bool).mean()*100
            rows.append((key,n,r3,r5,r10,best10,p3,p5,stop10))
        order = {'🟢 STRICT-소액가능':0,'🟢 STRICT-눌림대기':1,'🟡 STRICT-회복확인':2,'👀 구조관찰':6,'⚪ 미판정/DROP기본값':7,'🔴 실행보류/진입금지':8,'🔴 과열보류':9}
        rows.sort(key=lambda x: (order.get(x[0],5), -x[1]))
        for key,n,r3,r5,r10,best10,p3,p5,stop10 in rows[:max_rows]:
            small = ' ⚠️표본주의' if n < 3 else ''
            lines.append(f'- {key}: {n}개 | 3일 {_v1095_fmt(r3)} / 5일 {_v1095_fmt(r5)} / 10일 {_v1095_fmt(r10)} | 10일최고 {_v1095_fmt(best10)} | +3먼저 {_v1095_rate(p3)} | +5먼저 {_v1095_rate(p5)} | 손절먼저 {_v1095_rate(stop10)}{small}')
        lines.append('')
        return lines
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1095_examples(ok: pd.DataFrame, allowed: bool=True, max_rows: int=8) -> list:
    try:
        if ok is None or ok.empty or 'v1095_strict_allowed' not in ok.columns:
            return []
        tmp = ok[ok['v1095_strict_allowed'].astype(bool) == bool(allowed)].copy()
        if tmp.empty:
            return []
        tmp['_r5'] = pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_r10'] = pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_rank'] = pd.to_numeric(tmp.get('v1095_gate_rank', pd.Series(dtype=float)), errors='coerce').fillna(9)
        tmp = tmp.sort_values(['_rank','_r5','_r10'], ascending=[True,False,False]).head(max_rows)
        title = '[V1095 STRICT 실전TOP 예시]' if allowed else '[V1095 제외/관찰 예시]'
        lines = [title]
        for _, r in tmp.iterrows():
            name = _v1095_s(r.get('name', r.get('종목명','')),'')
            code = _v1095_s(r.get('code', r.get('종목코드','')),'')
            group = _v1095_s(r.get('v1095_gate_group',''))
            reason = _v1095_s(r.get('v1095_gate_reason',''))
            r5 = _v1095_num(r.get('next5_close_ret',0),0)
            r10 = _v1095_num(r.get('next10_close_ret',0),0)
            stopb = _v1095_s(r.get('signal_stop_bucket', r.get('v1095_signal_stop_bucket','')),'')
            lines.append(f'- {name}({code}) | {group} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}% | 손절거리 {stopb or "N/A"} | {reason}')
        lines.append('')
        return lines
    except Exception:
        return []


def _v1095_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1095 STRICT 백테스트 게이트 재현 FIX]', '- 평가 데이터가 없습니다.', '']
        ok = eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok = _v1095_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1095 STRICT 백테스트 게이트 재현 FIX]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        total = len(ok)
        allowed = ok[ok['v1095_strict_allowed'].astype(bool)].copy()
        blocked = ok[~ok['v1095_strict_allowed'].astype(bool)].copy()
        lines = ['[V1095 STRICT 백테스트 게이트 재현 FIX]']
        lines.append('- 목적: 라이브 V1094처럼 DIRECT_REPLAY 백테스트에서도 DROP 기본값/미판정 후보를 전부 실전후보로 열지 않고 다시 분리합니다.')
        lines.append(f'- 필터 결과: 평가 {total}개 중 STRICT 허용 {len(allowed)}개 / 제외·관찰·미판정 {len(blocked)}개')
        lines.append('- 핵심 보정: DROP 기본값은 실전 제외 확정이 아니라 미판정/관찰로 분리하며, STRICT 허용에서는 제외합니다.')
        lines.append('- 제외 기준: 신규진입 보류, RSI75↑, 이격115↑, 가짜수박 강, 손절거리 과다, DROP기본값/미판정')
        lines.append('')
        lines += _v1095_group_lines(ok, 'v1095_gate_group', 'V1095 실행게이트 그룹별 성과', max_rows=10)
        if not allowed.empty:
            lines += _v1095_group_lines(allowed, 'signal_stop_bucket', 'V1095 STRICT 손절거리별 성과', max_rows=8)
            lines += _v1095_group_lines(allowed, 'volume_state', 'V1095 STRICT 거래량상태별 성과', max_rows=8)
            lines += _v1095_group_lines(allowed, 'v1087_priority_class', 'V1095 STRICT V1087우선순위별 성과', max_rows=8)
            lines += _v1095_examples(ok, allowed=True, max_rows=8)
        else:
            lines.append('[V1095 STRICT 실전TOP 성과]')
            lines.append('- STRICT 허용 후보가 없습니다. 이 경우 당일/해당 주차는 무리하게 15개를 채우지 않는 것이 원칙입니다.')
            lines.append('')
        lines += _v1095_examples(ok, allowed=False, max_rows=8)
        lines.append('[V1095 적용 가이드]')
        lines.append('- V1094 라이브 출력은 유지하되, 백테스트 해석은 V1095 STRICT 허용/미판정/실행보류 그룹을 우선 봅니다.')
        lines.append('- STRICT 허용 표본이 너무 적으면 검색식이 강해진 것이며, 후보 수보다 손절먼저·5일수익률 개선 여부를 봅니다.')
        lines.append('- DROP 기본값 122개 같은 원후보/미판정 성과는 튜닝 참고용으로만 보고, 실전 후보 성과와 섞지 않습니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1095 STRICT 백테스트 게이트 재현 FIX]', f'- 생성 실패: {e}', '']


def _v1095_remove_old_strict_block(report: str) -> str:
    try:
        s = str(report or '')
        markers = [
            '[V1094 STRICT 실전TOP NO-BACKFILL 백테스트]',
            '[V1093 실전후보 필터 백테스트]',
        ]
        start = -1
        for m in markers:
            i = s.find(m)
            if i >= 0 and (start < 0 or i < start):
                start = i
        if start < 0:
            return s
        # 다음 큰 섹션으로 넘어가기 전까지 제거한다. 관점/전략별부터는 보존.
        next_candidates = []
        for m in ['\n[관점/전략별]', '\n[패턴별]', '\n[추천단계별]']:
            j = s.find(m, start + 1)
            if j >= 0:
                next_candidates.append(j)
        end = min(next_candidates) if next_candidates else len(s)
        prefix = s[:start].rstrip()
        suffix = s[end:].lstrip('\n')
        return (prefix + '\n\n' + suffix).strip()
    except Exception:
        return report


def _v1095_inject_block(report: str, lines: list) -> str:
    try:
        s = _v1095_remove_old_strict_block(str(report or ''))
        block = '\n'.join(lines).strip() + '\n'
        # V1087 적용 가이드 뒤, 관점/전략별 앞에 넣는다.
        markers = ['\n[관점/전략별]', '\n[패턴별]', '\n[추천단계별]']
        positions = [s.find(m) for m in markers if s.find(m) >= 0]
        if positions:
            pos = min(positions)
            return (s[:pos].rstrip() + '\n\n' + block + s[pos:]).strip()
        return (s.rstrip() + '\n\n' + block).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1095 override: V1094의 잘못 열린 STRICT 백테스트 블록을 제거하고, 재분류한 V1095 블록을 삽입한다."""
    try:
        report = _V1095_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1095_BASE_DIRECT_REPORT else ''
        s = str(report or '')
        s = s.replace('🧪 [V1094 직접 재현 주간 성과검증]', '🧪 [V1095 직접 재현 주간 성과검증]')
        s = s.replace('🧪 [V1093 직접 재현 주간 성과검증]', '🧪 [V1095 직접 재현 주간 성과검증]')
        if _v1095_on('V1095_BACKTEST_REPORT_BLOCK','1'):
            s = _v1095_inject_block(s, _v1095_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1095_BASE_DIRECT_REPORT:
                return _V1095_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1095 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

