def _v1096_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1096_s(v, default: str='') -> str:
    try:
        if v is None:
            return default
        if isinstance(v, float) and pd.isna(v):
            return default
        s = str(v).strip()
        return s if s else default
    except Exception:
        return default


def _v1096_num(v, default: float=0.0) -> float:
    try:
        if v is None:
            return default
        if isinstance(v, str):
            s = v.replace(',', '').replace('%', '').strip()
            if not s:
                return default
            return float(s)
        if pd.isna(v):
            return default
        return float(v)
    except Exception:
        return default


def _v1096_join_text(row) -> str:
    keys = [
        'final_decision','final_decision_v1085','candidate_scope_v1085','judge_quality_v1085',
        'phase','strategy','pattern','tags','태그','volume_state','signal_stop_bucket',
        'fake_severity','v1087_priority_class','v1087_reason','v1087_action_guide',
        'v1095_gate_group','v1095_gate_reason','v1095_gate_tier'
    ]
    parts=[]
    try:
        for k in keys:
            try:
                v = row.get(k, '') if hasattr(row, 'get') else ''
                if _v1096_s(v): parts.append(_v1096_s(v))
            except Exception:
                pass
    except Exception:
        pass
    return ' '.join(parts)


def _v1096_recover_info(row) -> dict:
    """V1096: V1095 STRICT 결과 위에 RECOVER 후보를 재분류한다.
    핵심: DROP기본값/미판정이라고 모두 버리지 않고, 손절/거래량/구조 조건이 좋은 후보를 따로 살린다.
    """
    try:
        # V1095 컬럼이 없으면 먼저 보강한다.
        try:
            if 'v1095_gate_group' not in row.index and '_v1095_gate_from_eval_row' in globals():
                base = _v1095_gate_from_eval_row(row)
            else:
                base = {}
        except Exception:
            base = {}
        getv = lambda k, d='': (row.get(k, base.get(k, d)) if hasattr(row, 'get') else base.get(k, d))
        txt = _v1096_join_text(row)
        gate5 = _v1096_s(getv('v1095_gate_group',''))
        tier5 = _v1096_s(getv('v1095_gate_tier',''))
        allowed5 = bool(getv('v1095_strict_allowed', False))
        stopb = _v1096_s(getv('signal_stop_bucket', getv('v1095_signal_stop_bucket','')))
        vol = _v1096_s(getv('volume_state', getv('v1095_volume_state','')))
        pri = _v1096_s(getv('v1087_priority_class', getv('v1095_v1087_priority_class','')))
        pri_score = _v1096_num(getv('v1087_priority_score', getv('v1095_v1087_priority_score',0)),0)
        rsi = _v1096_num(getv('rsi', getv('RSI', getv('v1095_rsi',0))),0)
        disp = _v1096_num(getv('disparity', getv('이격', getv('v1095_disparity',0))),0)
        final = _v1096_s(getv('final_decision', getv('추천단계','')))
        fake = _v1096_s(getv('fake_severity', getv('가짜수박강도','')))
        alltxt = ' '.join([txt, gate5, tier5, stopb, vol, pri, final, fake])

        # 최우선 STRICT 유지
        if allowed5 or gate5.startswith('🟢 STRICT') or gate5.startswith('🟡 STRICT'):
            return {
                'v1096_gate_tier': 'STRICT',
                'v1096_gate_group': gate5 or '🟢 STRICT',
                'v1096_gate_rank': 0,
                'v1096_allowed': True,
                'v1096_recover_score': 999,
                'v1096_gate_reason': _v1096_s(getv('v1095_gate_reason','STRICT')) or 'STRICT',
            }

        explicit_block = any(tok in alltxt for tok in ['신규진입 보류','신규진입보류','진입금지','실행보류','실전 후보 제외','실전제외'])
        fake_strong = any(tok in alltxt for tok in ['가짜수박 강','가짜수박강','강위험','가짜수박주의(강'])
        overheat = (rsi >= 75) or (disp >= 115) or ('과열보류' in gate5)
        stop_good = ('-3~-5' in stopb) or ('-3%~-5%' in stopb)
        stop_mid = ('-5~-8' in stopb) or ('-5%~-8%' in stopb)
        stop_ok = stop_good or stop_mid
        stop_wide = ('초과' in stopb) or ('-8' in stopb and not stop_ok)
        vol_compress = ('거래량응축' in vol) or ('상대거래량 응축' in alltxt)
        vol_strong = ('거래량유입(강)' in vol) or ('거래량유입 강' in vol) or ('거래량폭발' in alltxt)
        vol_confirm = ('거래량유입(확인)' in vol) or ('거래량 재유입' in alltxt)
        pri_core = ('응축우선' in pri) or ('핵심스윙' in pri) or (pri_score >= 64)
        pri_attack = ('공격형' in pri) or ('추격주의' in pri)
        weak_pri = ('확인필요' in pri) or ('강등' in pri)
        resist_break = ('저항돌파' in alltxt)
        bb40_wave = ('BB40 2차파동' in alltxt) or ('BB40저항돌파' in alltxt) or ('BB40재지지' in alltxt)
        good_pattern = any(tok in alltxt for tok in ['5-20독사훅','종베','수급전환','OBV+MFI','BB30시프트','거래량+OBV','삼각발사','진짜매집'])
        unknown_drop = ('미판정' in gate5) or ('DROP기본값' in gate5) or ('UNKNOWN_DROP' in tier5) or ('DROP기본값' in alltxt) or ('원후보/미판정' in alltxt)

        if overheat or explicit_block or fake_strong or stop_wide:
            reasons=[]
            if overheat: reasons.append('과열')
            if explicit_block: reasons.append('명시보류')
            if fake_strong: reasons.append('가짜수박강')
            if stop_wide: reasons.append('손절과다')
            return {
                'v1096_gate_tier':'EXCLUDE',
                'v1096_gate_group':'🔴 EXCLUDE-명시위험',
                'v1096_gate_rank':9,
                'v1096_allowed':False,
                'v1096_recover_score':-99,
                'v1096_gate_reason':','.join(reasons) or '위험제외',
            }

        score = 0
        reasons=[]
        if stop_good:
            score += 3; reasons.append('손절-3~-5')
        elif stop_mid and _v1096_on('V1096_ALLOW_RECOVER_STOP_5_8_WITH_CORE','1'):
            score += 1; reasons.append('손절-5~-8')
        if vol_compress:
            score += 3; reasons.append('거래량응축')
        if vol_strong:
            score += 2; reasons.append('거래량강')
        elif vol_confirm:
            score += 1; reasons.append('거래량확인')
        if pri_core:
            score += 2; reasons.append('V1087우선')
        elif pri_attack:
            score += 1; reasons.append('공격형')
        if resist_break:
            score += 1; reasons.append('저항돌파')
        if bb40_wave:
            score += 1; reasons.append('BB40구조')
        if good_pattern:
            score += 1; reasons.append('패턴양호')
        if weak_pri:
            score -= 2; reasons.append('확인필요감점')
        if not stop_ok:
            score -= 1; reasons.append('손절불명')

        min_score = int(_v1096_num(os.environ.get('V1096_MIN_RECOVER_SCORE','2'),2))
        if score >= min_score:
            if stop_good:
                grp = '🟡 RECOVER-손절짧음'
                rank = 1
            elif vol_compress:
                grp = '🟡 RECOVER-거래량응축'
                rank = 2
            elif vol_strong:
                grp = '🟠 RECOVER-거래량강'
                rank = 3
            elif pri_core or bb40_wave or resist_break:
                grp = '🟡 RECOVER-구조우수'
                rank = 4
            else:
                grp = '🟡 RECOVER-조건부'
                rank = 5
            return {
                'v1096_gate_tier':'RECOVER',
                'v1096_gate_group':grp,
                'v1096_gate_rank':rank,
                'v1096_allowed':True,
                'v1096_recover_score':score,
                'v1096_gate_reason':','.join(reasons[:8]) or 'RECOVER',
            }

        return {
            'v1096_gate_tier':'OBSERVE' if unknown_drop else 'OBSERVE',
            'v1096_gate_group':'⚪ OBSERVE-미판정' if unknown_drop else '👀 OBSERVE-구조관찰',
            'v1096_gate_rank':7,
            'v1096_allowed':False,
            'v1096_recover_score':score,
            'v1096_gate_reason':','.join(reasons[:8]) or '조건부족',
        }
    except Exception as e:
        return {
            'v1096_gate_tier':'OBSERVE',
            'v1096_gate_group':'👀 OBSERVE-분류실패',
            'v1096_gate_rank':7,
            'v1096_allowed':False,
            'v1096_recover_score':0,
            'v1096_gate_reason':f'분류실패:{e}',
        }


def _v1096_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out = eval_df.copy()
        try:
            if '_v1095_enrich_eval' in globals():
                out = _v1095_enrich_eval(out)
        except Exception:
            pass
        infos = [_v1096_recover_info(row) for _, row in out.iterrows()]
        add = pd.DataFrame(infos, index=out.index)
        for c in add.columns:
            out[c] = add[c]
        return out
    except Exception:
        return eval_df


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1096 wrapper: 신호행에도 STRICT+RECOVER 후보 컬럼을 저장한다."""
    try:
        base = _V1096_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1096_BASE_SIGNAL_ROW else {}
    except Exception:
        base = {}
    try:
        if base is not None:
            tmp = dict(base)
            try:
                raw = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
                tmp.update({k: v for k, v in raw.items() if k not in tmp})
            except Exception:
                pass
            info = _v1096_recover_info(tmp)
            base.update(info)
    except Exception:
        pass
    return base


def _v1096_fmt(v) -> str:
    try:
        if pd.isna(v): return 'N/A'
        return f'{float(v):+.2f}%'
    except Exception:
        return 'N/A'


def _v1096_rate(v) -> str:
    try: return f'{float(v):.1f}%'
    except Exception: return '0.0%'


def _v1096_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int=12) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        lines=[f'[{title}]']
        rows=[]
        for key,g in ok.groupby(col, dropna=False):
            key=_v1096_s(key,'미분류')
            n=len(g)
            r3=pd.to_numeric(g.get('next3_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r5=pd.to_numeric(g.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r10=pd.to_numeric(g.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            best10=pd.to_numeric(g.get('best_ret_10d', g.get('max_up_10d', pd.Series(dtype=float))), errors='coerce').mean()
            p3=g.get('plus3_first_10d', g.get('plus3_first', pd.Series([False]*n))).astype(bool).mean()*100
            p5=g.get('plus5_first_10d', g.get('plus5_first', pd.Series([False]*n))).astype(bool).mean()*100
            stop=g.get('stop_first_10d', g.get('stop_first', pd.Series([False]*n))).astype(bool).mean()*100
            avg_score=pd.to_numeric(g.get('v1096_recover_score', pd.Series(dtype=float)), errors='coerce').mean()
            rows.append((key,n,r3,r5,r10,best10,p3,p5,stop,avg_score))
        order={'🟢 STRICT-소액가능':0,'🟢 STRICT-눌림대기':0,'🟡 STRICT-회복확인':0,
               '🟡 RECOVER-손절짧음':1,'🟡 RECOVER-거래량응축':2,'🟠 RECOVER-거래량강':3,'🟡 RECOVER-구조우수':4,'🟡 RECOVER-조건부':5,
               '⚪ OBSERVE-미판정':7,'👀 OBSERVE-구조관찰':7,'🔴 EXCLUDE-명시위험':9}
        rows.sort(key=lambda x:(order.get(x[0],6), -x[1]))
        for key,n,r3,r5,r10,best10,p3,p5,stop,avg_score in rows[:max_rows]:
            small=' ⚠️표본주의' if n < 3 else ''
            score_txt=f' | 회복점수 {avg_score:.1f}' if 'RECOVER' in key else ''
            lines.append(f'- {key}: {n}개 | 3일 {_v1096_fmt(r3)} / 5일 {_v1096_fmt(r5)} / 10일 {_v1096_fmt(r10)} | 10일최고 {_v1096_fmt(best10)} | +3먼저 {_v1096_rate(p3)} | +5먼저 {_v1096_rate(p5)} | 손절먼저 {_v1096_rate(stop)}{score_txt}{small}')
        lines.append('')
        return lines
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1096_examples(ok: pd.DataFrame, tier: str='RECOVER', max_rows: int=8) -> list:
    try:
        if ok is None or ok.empty or 'v1096_gate_tier' not in ok.columns:
            return []
        tmp=ok[ok['v1096_gate_tier'].astype(str).str.contains(tier, na=False)].copy()
        if tmp.empty: return []
        tmp['_r5']=pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_r10']=pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_rank']=pd.to_numeric(tmp.get('v1096_gate_rank', pd.Series(dtype=float)), errors='coerce').fillna(9)
        tmp=tmp.sort_values(['_rank','_r5','_r10'], ascending=[True,False,False]).head(max_rows)
        title_map={'STRICT':'[V1096 STRICT 예시]','RECOVER':'[V1096 RECOVER 예시]','OBSERVE':'[V1096 OBSERVE 예시]','EXCLUDE':'[V1096 EXCLUDE 예시]'}
        lines=[title_map.get(tier, f'[V1096 {tier} 예시]')]
        for _,r in tmp.iterrows():
            name=_v1096_s(r.get('name', r.get('종목명','')),'')
            code=_v1096_s(r.get('code', r.get('종목코드','')),'')
            group=_v1096_s(r.get('v1096_gate_group',''))
            reason=_v1096_s(r.get('v1096_gate_reason',''))
            score=_v1096_num(r.get('v1096_recover_score',0),0)
            r5=_v1096_num(r.get('next5_close_ret',0),0)
            r10=_v1096_num(r.get('next10_close_ret',0),0)
            stopb=_v1096_s(r.get('signal_stop_bucket', r.get('v1095_signal_stop_bucket','')),'')
            lines.append(f'- {name}({code}) | {group} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}% | 손절 {stopb or "N/A"} | 회복점수 {score:g} | {reason}')
        lines.append('')
        return lines
    except Exception:
        return []


def _v1096_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1096 STRICT+RECOVER 백테스트]', '- 평가 데이터가 없습니다.', '']
        ok=eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok=_v1096_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1096 STRICT+RECOVER 백테스트]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        total=len(ok)
        strict=ok[ok['v1096_gate_tier'].astype(str).eq('STRICT')].copy()
        recover=ok[ok['v1096_gate_tier'].astype(str).eq('RECOVER')].copy()
        observe=ok[ok['v1096_gate_tier'].astype(str).eq('OBSERVE')].copy()
        exclude=ok[ok['v1096_gate_tier'].astype(str).eq('EXCLUDE')].copy()
        active=ok[ok['v1096_allowed'].astype(bool)].copy()
        lines=['[V1096 STRICT+RECOVER 백테스트]']
        lines.append('- 목적: V1095의 STRICT 4개는 유지하되, DROP기본값/미판정 중 손절·거래량·구조가 좋은 후보를 RECOVER로 되살립니다.')
        lines.append(f'- 분류 결과: 평가 {total}개 | STRICT {len(strict)}개 / RECOVER {len(recover)}개 / OBSERVE {len(observe)}개 / EXCLUDE {len(exclude)}개')
        lines.append(f'- 실전 후보군: STRICT+RECOVER {len(active)}개 | STRICT 단독보다 후보 수를 늘리되, EXCLUDE/OBSERVE와 성과를 분리합니다.')
        lines.append(f'- RECOVER 기준: 회복점수 ≥ {int(_v1096_num(os.environ.get("V1096_MIN_RECOVER_SCORE","2"),2))} | 손절-3~-5, 거래량응축, 거래량유입강, V1087 우선, 저항돌파/BB40구조 가점')
        lines.append('')
        lines += _v1096_group_lines(ok, 'v1096_gate_group', 'V1096 STRICT/RECOVER/OBSERVE/EXCLUDE 그룹별 성과', max_rows=12)
        if not active.empty:
            lines += _v1096_group_lines(active, 'signal_stop_bucket', 'V1096 실전후보군 손절거리별 성과', max_rows=8)
            lines += _v1096_group_lines(active, 'volume_state', 'V1096 실전후보군 거래량상태별 성과', max_rows=8)
            lines += _v1096_group_lines(active, 'v1087_priority_class', 'V1096 실전후보군 V1087우선순위별 성과', max_rows=8)
        lines += _v1096_examples(ok, 'STRICT', max_rows=5)
        lines += _v1096_examples(ok, 'RECOVER', max_rows=10)
        lines += _v1096_examples(ok, 'OBSERVE', max_rows=8)
        lines.append('[V1096 적용 가이드]')
        lines.append('- 라이브 운용은 V1094 STRICT TOP 구조를 유지합니다.')
        lines.append('- 백테스트 해석은 STRICT만 보지 말고 STRICT+RECOVER 후보군의 5일수익률·손절먼저를 함께 봅니다.')
        lines.append('- RECOVER가 STRICT보다 성과가 낮아도 전체 후보 수와 손절 안정성이 개선되면 실전 후보 보강용으로 사용합니다.')
        lines.append('- OBSERVE/DROP기본값은 대박 종목이 있어도 실시간 실행 기준이 부족한 그룹이므로 단독 매수 후보로 섞지 않습니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1096 STRICT+RECOVER 백테스트]', f'- 생성 실패: {e}', '']


def _v1096_remove_old_block(report: str) -> str:
    try:
        s=str(report or '')
        markers=['[V1096 STRICT+RECOVER 백테스트]']
        start=-1
        for m in markers:
            i=s.find(m)
            if i>=0 and (start<0 or i<start): start=i
        if start<0: return s
        next_candidates=[]
        for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
            j=s.find(m,start+1)
            if j>=0: next_candidates.append(j)
        end=min(next_candidates) if next_candidates else len(s)
        return (s[:start].rstrip()+'\n\n'+s[end:].lstrip('\n')).strip()
    except Exception:
        return report


def _v1096_inject_block(report: str, lines: list) -> str:
    try:
        s=_v1096_remove_old_block(str(report or ''))
        block='\n'.join(lines).strip()+'\n'
        # V1095 블록 바로 뒤에 붙인다. 없으면 관점/전략별 앞에 삽입.
        anchor='[V1095 적용 가이드]'
        ai=s.find(anchor)
        if ai>=0:
            # V1095 적용가이드의 빈 줄 이후를 찾는다.
            next_sec=-1
            for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                j=s.find(m, ai+1)
                if j>=0 and (next_sec<0 or j<next_sec): next_sec=j
            if next_sec>=0:
                return (s[:next_sec].rstrip()+'\n\n'+block+s[next_sec:]).strip()
        positions=[s.find(m) for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]'] if s.find(m)>=0]
        if positions:
            pos=min(positions)
            return (s[:pos].rstrip()+'\n\n'+block+s[pos:]).strip()
        return (s.rstrip()+'\n\n'+block).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1096 override: V1095 리포트 뒤에 STRICT+RECOVER 백테스트 블록을 추가한다."""
    try:
        report = _V1096_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1096_BASE_DIRECT_REPORT else ''
        s=str(report or '')
        s=s.replace('🧪 [V1095 직접 재현 주간 성과검증]', '🧪 [V1096 직접 재현 주간 성과검증]')
        s=s.replace('🧪 [V1094 직접 재현 주간 성과검증]', '🧪 [V1096 직접 재현 주간 성과검증]')
        if _v1096_on('V1096_BACKTEST_REPORT_BLOCK','1'):
            s=_v1096_inject_block(s, _v1096_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1096_BASE_DIRECT_REPORT:
                return _V1096_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1096 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

