def _v1097_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1097_s(v, default: str='') -> str:
    try:
        if v is None:
            return default
        if isinstance(v, float) and pd.isna(v):
            return default
        s = str(v).strip()
        return s if s else default
    except Exception:
        return default


def _v1097_num(v, default: float=0.0) -> float:
    try:
        if v is None:
            return default
        if isinstance(v, str):
            s = v.replace(',', '').replace('%', '').strip()
            if not s:
                return default
            return float(s)
        if pd.isna(v):
            return default
        return float(v)
    except Exception:
        return default


def _v1097_join_text(row) -> str:
    keys = [
        'final_decision','final_decision_v1085','candidate_scope_v1085','judge_quality_v1085',
        'phase','strategy','pattern','tags','태그','volume_state','signal_stop_bucket',
        'fake_severity','v1087_priority_class','v1087_reason','v1087_action_guide',
        'v1095_gate_group','v1095_gate_reason','v1095_gate_tier',
        'v1096_gate_group','v1096_gate_reason','v1096_gate_tier'
    ]
    parts=[]
    try:
        for k in keys:
            try:
                v = row.get(k, '') if hasattr(row, 'get') else ''
                if _v1097_s(v):
                    parts.append(_v1097_s(v))
            except Exception:
                pass
    except Exception:
        pass
    return ' '.join(parts)


def _v1097_diag_flags(row) -> dict:
    """V1097 공통 플래그: 구조우수 중 살릴 조건과 버릴 조건을 분해한다."""
    try:
        txt = _v1097_join_text(row)
        getv = lambda k, d='': row.get(k, d) if hasattr(row, 'get') else d
        stopb = _v1097_s(getv('signal_stop_bucket', getv('v1095_signal_stop_bucket','')))
        vol = _v1097_s(getv('volume_state', getv('v1095_volume_state','')))
        pri = _v1097_s(getv('v1087_priority_class', getv('v1095_v1087_priority_class','')))
        pri_score = _v1097_num(getv('v1087_priority_score', getv('v1095_v1087_priority_score',0)),0)
        rsi = _v1097_num(getv('rsi', getv('RSI', getv('v1095_rsi',0))),0)
        disp = _v1097_num(getv('disparity', getv('이격', getv('v1095_disparity',0))),0)
        bb40w = _v1097_num(getv('bb40_width', getv('BB40폭', getv('v1095_bb40_width',0))),0)
        v1096_group = _v1097_s(getv('v1096_gate_group',''))
        v1096_tier = _v1097_s(getv('v1096_gate_tier',''))
        v1096_score = _v1097_num(getv('v1096_recover_score',0),0)
        alltxt = ' '.join([txt, stopb, vol, pri, v1096_group])
        flags = {}
        flags['stop_good'] = ('-3~-5' in stopb) or ('-3%~-5%' in stopb)
        flags['stop_mid'] = ('-5~-8' in stopb) or ('-5%~-8%' in stopb)
        flags['stop_wide'] = ('초과' in stopb) or ('-8' in stopb and not (flags['stop_good'] or flags['stop_mid']))
        flags['vol_compress'] = ('거래량응축' in vol) or ('상대거래량 응축' in alltxt)
        flags['vol_strong'] = ('거래량유입(강)' in vol) or ('거래량유입 강' in vol) or ('거래량폭발' in alltxt)
        flags['vol_confirm_only'] = (('거래량유입(확인)' in vol) or ('거래량 재유입' in alltxt)) and not flags['vol_compress'] and not flags['vol_strong']
        flags['pri_core'] = ('응축우선' in pri) or ('핵심스윙' in pri) or (pri_score >= 64)
        flags['pri_swing'] = ('핵심스윙' in pri)
        flags['pri_compress'] = ('응축우선' in pri)
        flags['pri_attack'] = ('공격형' in pri) or ('추격주의' in pri)
        flags['weak_pri'] = ('확인필요' in pri) or ('강등' in pri) or ('방어형스윙' in pri)
        flags['general_only'] = ('일반관찰' in pri)
        flags['resist_break'] = ('저항돌파' in alltxt)
        flags['bb40_wave'] = ('BB40 2차파동' in alltxt) or ('BB40저항돌파' in alltxt) or ('BB40재지지' in alltxt)
        flags['good_pattern'] = any(tok in alltxt for tok in ['5-20독사훅','종베','수급전환','OBV+MFI','BB30시프트','거래량+OBV','삼각발사','진짜매집'])
        flags['explicit_block'] = any(tok in alltxt for tok in ['신규진입 보류','신규진입보류','진입금지','실행보류','실전 후보 제외','실전제외'])
        flags['fake_strong'] = any(tok in alltxt for tok in ['가짜수박 강','가짜수박강','강위험','가짜수박주의(강'])
        flags['overheat'] = (rsi >= 75) or (disp >= 115) or ('과열보류' in alltxt)
        flags['bb40_wide'] = bb40w >= 45 if bb40w else False
        flags['structure_only'] = ('RECOVER-구조우수' in v1096_group) or (flags['resist_break'] and not (flags['stop_good'] or flags['vol_compress'] or flags['vol_strong'] or flags['pri_core']))
        flags['v1096_group'] = v1096_group
        flags['v1096_tier'] = v1096_tier
        flags['v1096_score'] = v1096_score
        flags['stopb'] = stopb
        flags['vol'] = vol
        flags['pri'] = pri
        flags['rsi'] = rsi
        flags['disp'] = disp
        flags['bb40w'] = bb40w
        return flags
    except Exception:
        return {}


def _v1097_core_info(row) -> dict:
    """V1097: V1096 RECOVER 중 구조우수 단독을 제거하고 CORE/AGGRESSIVE만 실전 후보로 압축한다."""
    try:
        try:
            if 'v1096_gate_group' not in row.index and '_v1096_recover_info' in globals():
                base = _v1096_recover_info(row)
            else:
                base = {}
        except Exception:
            base = {}
        getv = lambda k, d='': (row.get(k, base.get(k, d)) if hasattr(row, 'get') else base.get(k, d))
        flags = _v1097_diag_flags(row)
        v1096_tier = _v1097_s(getv('v1096_gate_tier', flags.get('v1096_tier','')))
        v1096_group = _v1097_s(getv('v1096_gate_group', flags.get('v1096_group','')))
        score = _v1097_num(getv('v1096_recover_score', flags.get('v1096_score',0)),0)
        reasons=[]

        if v1096_tier == 'STRICT' or v1096_group.startswith('🟢 STRICT') or v1096_group.startswith('🟡 STRICT'):
            return {
                'v1097_gate_tier':'STRICT',
                'v1097_gate_group':v1096_group or '🟢 STRICT',
                'v1097_gate_rank':0,
                'v1097_allowed':True,
                'v1097_core_score':999,
                'v1097_gate_reason':'STRICT 유지',
                'v1097_structure_flag':'STRICT',
            }

        # 명시 위험은 확실히 제외한다.
        hard_risk = flags.get('explicit_block') or flags.get('fake_strong') or flags.get('overheat') or flags.get('stop_wide') or flags.get('weak_pri')
        if hard_risk or v1096_tier == 'EXCLUDE' or 'RECOVER-조건부' in v1096_group:
            if flags.get('explicit_block'): reasons.append('명시보류')
            if flags.get('fake_strong'): reasons.append('가짜수박강')
            if flags.get('overheat'): reasons.append('과열')
            if flags.get('stop_wide'): reasons.append('손절과다')
            if flags.get('weak_pri'): reasons.append('확인필요/강등')
            if 'RECOVER-조건부' in v1096_group: reasons.append('조건부약세')
            return {
                'v1097_gate_tier':'EXCLUDE',
                'v1097_gate_group':'🔴 EXCLUDE-위험/강등',
                'v1097_gate_rank':9,
                'v1097_allowed':False,
                'v1097_core_score':score,
                'v1097_gate_reason':','.join(reasons) or '위험제외',
                'v1097_structure_flag':'위험제외',
            }

        core_min = int(_v1097_num(os.environ.get('V1097_CORE_MIN_SCORE','5'),5))
        agg_min = int(_v1097_num(os.environ.get('V1097_AGGRESSIVE_MIN_SCORE','5'),5))

        # CORE: 손절짧음/응축/핵심스윙/응축우선처럼 손절안정성이 확인된 조건만
        if flags.get('stop_good') and score >= core_min and (flags.get('vol_compress') or flags.get('pri_core') or flags.get('vol_strong') or flags.get('good_pattern')):
            return {
                'v1097_gate_tier':'RECOVER_CORE',
                'v1097_gate_group':'🟢 RECOVER-CORE 손절짧음',
                'v1097_gate_rank':1,
                'v1097_allowed':True,
                'v1097_core_score':score,
                'v1097_gate_reason':'손절짧음+핵심조건',
                'v1097_structure_flag':'구조+손절짧음',
            }
        if flags.get('vol_compress') and score >= core_min and (flags.get('pri_core') or flags.get('resist_break') or flags.get('bb40_wave') or flags.get('good_pattern')):
            return {
                'v1097_gate_tier':'RECOVER_CORE',
                'v1097_gate_group':'🟢 RECOVER-CORE 거래량응축',
                'v1097_gate_rank':2,
                'v1097_allowed':True,
                'v1097_core_score':score,
                'v1097_gate_reason':'거래량응축+구조',
                'v1097_structure_flag':'구조+거래량응축',
            }
        if flags.get('pri_swing') and score >= core_min and (flags.get('resist_break') or flags.get('bb40_wave') or flags.get('vol_compress')):
            return {
                'v1097_gate_tier':'RECOVER_CORE',
                'v1097_gate_group':'🟢 RECOVER-CORE 핵심스윙',
                'v1097_gate_rank':3,
                'v1097_allowed':True,
                'v1097_core_score':score,
                'v1097_gate_reason':'핵심스윙+구조',
                'v1097_structure_flag':'구조+핵심스윙',
            }
        if flags.get('pri_compress') and score >= core_min and (flags.get('resist_break') or flags.get('bb40_wave') or flags.get('vol_compress')):
            return {
                'v1097_gate_tier':'RECOVER_CORE',
                'v1097_gate_group':'🟢 RECOVER-CORE 응축우선',
                'v1097_gate_rank':3,
                'v1097_allowed':True,
                'v1097_core_score':score,
                'v1097_gate_reason':'응축우선+구조',
                'v1097_structure_flag':'구조+응축우선',
            }

        # AGGRESSIVE: 거래량강/공격형은 살리되 따로 분리한다. 손절먼저가 높아 소액형.
        if flags.get('vol_strong') and score >= agg_min and not flags.get('general_only'):
            return {
                'v1097_gate_tier':'RECOVER_AGGRESSIVE',
                'v1097_gate_group':'🟠 RECOVER-AGGRESSIVE 거래량강',
                'v1097_gate_rank':4,
                'v1097_allowed':True,
                'v1097_core_score':score,
                'v1097_gate_reason':'거래량강+공격형',
                'v1097_structure_flag':'구조+거래량강',
            }

        # 구조우수 단독은 대박 가능성이 있어도 실전 TOP 후보가 아니라 관찰로 보낸다.
        if flags.get('structure_only') or 'RECOVER-구조우수' in v1096_group:
            reason=[]
            if flags.get('vol_confirm_only'): reason.append('거래량확인만')
            if flags.get('general_only'): reason.append('일반관찰')
            if flags.get('bb40_wide'): reason.append('BB40폭큼')
            if flags.get('stop_mid'): reason.append('손절-5~-8')
            if not reason: reason.append('구조우수단독')
            return {
                'v1097_gate_tier':'OBSERVE_STRUCTURE',
                'v1097_gate_group':'👀 OBSERVE-구조우수 단독',
                'v1097_gate_rank':6,
                'v1097_allowed':False,
                'v1097_core_score':score,
                'v1097_gate_reason':','.join(reason),
                'v1097_structure_flag':','.join(reason),
            }

        # V1096 RECOVER였지만 CORE 조건을 못 채우면 관찰로 내린다.
        if v1096_tier == 'RECOVER':
            reason=[]
            if flags.get('general_only'): reason.append('일반관찰')
            if flags.get('vol_confirm_only'): reason.append('거래량확인만')
            if not flags.get('stop_good') and not flags.get('vol_compress') and not flags.get('vol_strong') and not flags.get('pri_core'):
                reason.append('핵심조건부족')
            return {
                'v1097_gate_tier':'OBSERVE',
                'v1097_gate_group':'⚪ OBSERVE-RECOVER 미충족',
                'v1097_gate_rank':7,
                'v1097_allowed':False,
                'v1097_core_score':score,
                'v1097_gate_reason':','.join(reason) or 'CORE조건미충족',
                'v1097_structure_flag':','.join(reason) or 'CORE조건미충족',
            }

        return {
            'v1097_gate_tier':'OBSERVE',
            'v1097_gate_group':'⚪ OBSERVE-미판정',
            'v1097_gate_rank':7,
            'v1097_allowed':False,
            'v1097_core_score':score,
            'v1097_gate_reason':'미판정',
            'v1097_structure_flag':'미판정',
        }
    except Exception as e:
        return {
            'v1097_gate_tier':'OBSERVE',
            'v1097_gate_group':'⚪ OBSERVE-분류실패',
            'v1097_gate_rank':7,
            'v1097_allowed':False,
            'v1097_core_score':0,
            'v1097_gate_reason':f'분류실패:{e}',
            'v1097_structure_flag':'분류실패',
        }


def _v1097_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out = eval_df.copy()
        try:
            if '_v1096_enrich_eval' in globals():
                out = _v1096_enrich_eval(out)
        except Exception:
            pass
        infos = [_v1097_core_info(row) for _, row in out.iterrows()]
        add = pd.DataFrame(infos, index=out.index)
        for c in add.columns:
            out[c] = add[c]
        return out
    except Exception:
        return eval_df


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1097 wrapper: 신호행에도 RECOVER CORE 분류를 저장한다."""
    try:
        base = _V1097_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1097_BASE_SIGNAL_ROW else {}
    except Exception:
        base = {}
    try:
        tmp = dict(base or {})
        try:
            raw = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            tmp.update({k: v for k, v in raw.items() if k not in tmp})
        except Exception:
            pass
        info = _v1097_core_info(tmp)
        base.update(info)
    except Exception:
        pass
    return base


def _v1097_fmt(v) -> str:
    try:
        if pd.isna(v): return 'N/A'
        return f'{float(v):+.2f}%'
    except Exception:
        return 'N/A'


def _v1097_rate(v) -> str:
    try: return f'{float(v):.1f}%'
    except Exception: return '0.0%'


def _v1097_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int=12, score_col: str='v1097_core_score') -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        lines=[f'[{title}]']
        rows=[]
        for key,g in ok.groupby(col, dropna=False):
            key=_v1097_s(key,'미분류')
            n=len(g)
            r3=pd.to_numeric(g.get('next3_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r5=pd.to_numeric(g.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r10=pd.to_numeric(g.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            best10=pd.to_numeric(g.get('best_ret_10d', g.get('max_up_10d', pd.Series(dtype=float))), errors='coerce').mean()
            p3=g.get('plus3_first_10d', g.get('plus3_first', pd.Series([False]*n))).astype(bool).mean()*100
            p5=g.get('plus5_first_10d', g.get('plus5_first', pd.Series([False]*n))).astype(bool).mean()*100
            stop=g.get('stop_first_10d', g.get('stop_first', pd.Series([False]*n))).astype(bool).mean()*100
            avg_score=pd.to_numeric(g.get(score_col, pd.Series(dtype=float)), errors='coerce').mean()
            rows.append((key,n,r3,r5,r10,best10,p3,p5,stop,avg_score))
        order={'🟢 STRICT-소액가능':0,'🟢 STRICT-눌림대기':0,'🟡 STRICT-회복확인':0,
               '🟢 RECOVER-CORE 손절짧음':1,'🟢 RECOVER-CORE 거래량응축':2,'🟢 RECOVER-CORE 핵심스윙':3,'🟢 RECOVER-CORE 응축우선':3,
               '🟠 RECOVER-AGGRESSIVE 거래량강':4,
               '👀 OBSERVE-구조우수 단독':6,'⚪ OBSERVE-RECOVER 미충족':7,'⚪ OBSERVE-미판정':7,
               '🔴 EXCLUDE-위험/강등':9}
        rows.sort(key=lambda x:(order.get(x[0],6), -x[1]))
        for key,n,r3,r5,r10,best10,p3,p5,stop,avg_score in rows[:max_rows]:
            small=' ⚠️표본주의' if n < 3 else ''
            score_txt=f' | CORE점수 {avg_score:.1f}' if ('RECOVER' in key or 'OBSERVE' in key) else ''
            lines.append(f'- {key}: {n}개 | 3일 {_v1097_fmt(r3)} / 5일 {_v1097_fmt(r5)} / 10일 {_v1097_fmt(r10)} | 10일최고 {_v1097_fmt(best10)} | +3먼저 {_v1097_rate(p3)} | +5먼저 {_v1097_rate(p5)} | 손절먼저 {_v1097_rate(stop)}{score_txt}{small}')
        lines.append('')
        return lines
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1097_examples(ok: pd.DataFrame, tier: str='RECOVER_CORE', max_rows: int=8) -> list:
    try:
        if ok is None or ok.empty or 'v1097_gate_tier' not in ok.columns:
            return []
        tmp=ok[ok['v1097_gate_tier'].astype(str).str.contains(tier, na=False)].copy()
        if tmp.empty:
            return []
        tmp['_r5']=pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_r10']=pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_rank']=pd.to_numeric(tmp.get('v1097_gate_rank', pd.Series(dtype=float)), errors='coerce').fillna(9)
        tmp=tmp.sort_values(['_rank','_r5','_r10'], ascending=[True,False,False]).head(max_rows)
        title_map={'STRICT':'[V1097 STRICT 예시]','RECOVER_CORE':'[V1097 RECOVER-CORE 예시]','RECOVER_AGGRESSIVE':'[V1097 RECOVER-AGGRESSIVE 예시]','OBSERVE_STRUCTURE':'[V1097 구조우수 관찰 예시]','OBSERVE':'[V1097 OBSERVE 예시]','EXCLUDE':'[V1097 EXCLUDE 예시]'}
        lines=[title_map.get(tier, f'[V1097 {tier} 예시]')]
        for _,r in tmp.iterrows():
            name=_v1097_s(r.get('name', r.get('종목명','')),'')
            code=_v1097_s(r.get('code', r.get('종목코드','')),'')
            group=_v1097_s(r.get('v1097_gate_group',''))
            reason=_v1097_s(r.get('v1097_gate_reason',''))
            score=_v1097_num(r.get('v1097_core_score',0),0)
            r5=_v1097_num(r.get('next5_close_ret',0),0)
            r10=_v1097_num(r.get('next10_close_ret',0),0)
            stopb=_v1097_s(r.get('signal_stop_bucket', r.get('v1095_signal_stop_bucket','')),'')
            lines.append(f'- {name}({code}) | {group} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}% | 손절 {stopb or "N/A"} | CORE점수 {score:g} | {reason}')
        lines.append('')
        return lines
    except Exception:
        return []


def _v1097_structure_diag_lines(ok: pd.DataFrame) -> list:
    try:
        if ok is None or ok.empty:
            return []
        # V1096 구조우수였던 후보를 따로 분해한다.
        if 'v1096_gate_group' not in ok.columns:
            return []
        st = ok[ok['v1096_gate_group'].astype(str).str.contains('RECOVER-구조우수', na=False)].copy()
        if st.empty:
            return []
        lines=['[V1097 구조우수 실패/생존 원인분해]']
        lines.append('- 목적: V1096에서 성과가 약했던 RECOVER-구조우수 후보를 손절·거래량·우선순위·변동성 조건으로 다시 쪼갭니다.')
        lines.append(f'- 구조우수 원표본: {len(st)}개 | 이 중 V1097 실전 유지 {int(st.get("v1097_allowed", pd.Series([False]*len(st))).astype(bool).sum())}개 / 관찰·제외 {len(st)-int(st.get("v1097_allowed", pd.Series([False]*len(st))).astype(bool).sum())}개')
        lines.append('')
        lines += _v1097_group_lines(st, 'signal_stop_bucket', 'V1097 구조우수 손절거리별 성과', max_rows=8)
        lines += _v1097_group_lines(st, 'volume_state', 'V1097 구조우수 거래량상태별 성과', max_rows=8)
        lines += _v1097_group_lines(st, 'v1087_priority_class', 'V1097 구조우수 V1087우선순위별 성과', max_rows=8)
        if 'v1097_structure_flag' in st.columns:
            lines += _v1097_group_lines(st, 'v1097_structure_flag', 'V1097 구조우수 위험/생존 플래그별 성과', max_rows=10)
        return lines
    except Exception as e:
        return ['[V1097 구조우수 실패/생존 원인분해]', f'- 생성 실패: {e}', '']


def _v1097_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1097 RECOVER CORE + 구조진단 백테스트]', '- 평가 데이터가 없습니다.', '']
        ok=eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok=_v1097_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1097 RECOVER CORE + 구조진단 백테스트]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        total=len(ok)
        strict=ok[ok['v1097_gate_tier'].astype(str).eq('STRICT')].copy()
        core=ok[ok['v1097_gate_tier'].astype(str).eq('RECOVER_CORE')].copy()
        aggr=ok[ok['v1097_gate_tier'].astype(str).eq('RECOVER_AGGRESSIVE')].copy()
        obs_struct=ok[ok['v1097_gate_tier'].astype(str).eq('OBSERVE_STRUCTURE')].copy()
        obs=ok[ok['v1097_gate_tier'].astype(str).eq('OBSERVE')].copy()
        excl=ok[ok['v1097_gate_tier'].astype(str).eq('EXCLUDE')].copy()
        active=ok[ok['v1097_allowed'].astype(bool)].copy()
        lines=['[V1097 RECOVER CORE + 구조진단 백테스트]']
        lines.append('- 목적: V1096에서 너무 넓어진 RECOVER 116개를 CORE/AGGRESSIVE/OBSERVE/EXCLUDE로 다시 압축합니다.')
        lines.append('- 원칙: 구조우수 단독은 관찰로 내리고, 구조우수+손절짧음/거래량응축/응축우선/핵심스윙/거래량강만 실전 보강 후보로 유지합니다.')
        lines.append(f'- 분류 결과: 평가 {total}개 | STRICT {len(strict)}개 / CORE {len(core)}개 / AGGRESSIVE {len(aggr)}개 / 구조관찰 {len(obs_struct)}개 / 일반관찰 {len(obs)}개 / EXCLUDE {len(excl)}개')
        lines.append(f'- 실전 후보군: STRICT+CORE+AGGRESSIVE {len(active)}개 | 구조우수 단독은 실전 후보군에서 제외합니다.')
        lines.append('')
        lines += _v1097_group_lines(ok, 'v1097_gate_group', 'V1097 STRICT/CORE/AGGRESSIVE/OBSERVE/EXCLUDE 그룹별 성과', max_rows=14)
        if not active.empty:
            lines += _v1097_group_lines(active, 'signal_stop_bucket', 'V1097 실전후보군 손절거리별 성과', max_rows=8)
            lines += _v1097_group_lines(active, 'volume_state', 'V1097 실전후보군 거래량상태별 성과', max_rows=8)
            lines += _v1097_group_lines(active, 'v1087_priority_class', 'V1097 실전후보군 V1087우선순위별 성과', max_rows=8)
        lines += _v1097_structure_diag_lines(ok)
        lines += _v1097_examples(ok, 'STRICT', max_rows=5)
        lines += _v1097_examples(ok, 'RECOVER_CORE', max_rows=10)
        lines += _v1097_examples(ok, 'RECOVER_AGGRESSIVE', max_rows=8)
        lines += _v1097_examples(ok, 'OBSERVE_STRUCTURE', max_rows=8)
        lines += _v1097_examples(ok, 'EXCLUDE', max_rows=8)
        lines.append('[V1097 적용 가이드]')
        lines.append('- 라이브 운용은 V1094 STRICT TOP 구조를 유지합니다.')
        lines.append('- 백테스트 해석은 STRICT를 1순위, RECOVER-CORE를 2순위, RECOVER-AGGRESSIVE를 소액 공격형으로 봅니다.')
        lines.append('- 구조우수 단독은 대박 예시가 있어도 손절먼저가 높았으므로 실전 TOP에 섞지 않고 관찰 섹션으로 분리합니다.')
        lines.append('- V1097에서 CORE 후보 수가 20~40개 수준이고 손절먼저가 20~30%대로 유지되면 실전 보강 후보군으로 사용할 수 있습니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1097 RECOVER CORE + 구조진단 백테스트]', f'- 생성 실패: {e}', '']


def _v1097_remove_old_block(report: str) -> str:
    try:
        s=str(report or '')
        markers=['[V1097 RECOVER CORE + 구조진단 백테스트]']
        start=-1
        for m in markers:
            i=s.find(m)
            if i>=0 and (start<0 or i<start): start=i
        if start<0:
            return s
        next_candidates=[]
        for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
            j=s.find(m,start+1)
            if j>=0: next_candidates.append(j)
        end=min(next_candidates) if next_candidates else len(s)
        return (s[:start].rstrip()+'\n\n'+s[end:].lstrip('\n')).strip()
    except Exception:
        return report


def _v1097_inject_block(report: str, lines: list) -> str:
    try:
        s=_v1097_remove_old_block(str(report or ''))
        block='\n'.join(lines).strip()+'\n'
        anchor='[V1096 적용 가이드]'
        ai=s.find(anchor)
        if ai>=0:
            next_sec=-1
            for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                j=s.find(m, ai+1)
                if j>=0 and (next_sec<0 or j<next_sec): next_sec=j
            if next_sec>=0:
                return (s[:next_sec].rstrip()+'\n\n'+block+s[next_sec:]).strip()
        positions=[s.find(m) for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]'] if s.find(m)>=0]
        if positions:
            pos=min(positions)
            return (s[:pos].rstrip()+'\n\n'+block+s[pos:]).strip()
        return (s.rstrip()+'\n\n'+block).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1097 override: V1096 리포트 뒤에 RECOVER CORE + 구조진단 블록을 추가한다."""
    try:
        report = _V1097_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1097_BASE_DIRECT_REPORT else ''
        s=str(report or '')
        s=s.replace('🧪 [V1096 직접 재현 주간 성과검증]', '🧪 [V1097 직접 재현 주간 성과검증]')
        s=s.replace('🧪 [V1095 직접 재현 주간 성과검증]', '🧪 [V1097 직접 재현 주간 성과검증]')
        s=s.replace('🧪 [V1094 직접 재현 주간 성과검증]', '🧪 [V1097 직접 재현 주간 성과검증]')
        if _v1097_on('V1097_BACKTEST_REPORT_BLOCK','1'):
            s=_v1097_inject_block(s, _v1097_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1097_BASE_DIRECT_REPORT:
                return _V1097_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1097 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

