def _v1098_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1098_s(v, default: str='') -> str:
    try:
        if v is None:
            return default
        if isinstance(v, float) and pd.isna(v):
            return default
        s=str(v).strip()
        return s if s else default
    except Exception:
        return default


def _v1098_num(v, default: float=0.0) -> float:
    try:
        if v is None:
            return default
        if isinstance(v, str):
            s=v.replace(',','').replace('%','').strip()
            if not s:
                return default
            return float(s)
        if pd.isna(v):
            return default
        return float(v)
    except Exception:
        return default


def _v1098_norm_code(code) -> str:
    try:
        if '_v1080_norm_code' in globals():
            return _v1080_norm_code(code)
    except Exception:
        pass
    try:
        return str(code).strip().split('.')[0].zfill(6)
    except Exception:
        return str(code)


def _v1098_join_text(row) -> str:
    try:
        if '_v1097_join_text' in globals():
            base=_v1097_join_text(row)
        else:
            base=''
        keys=['v1097_gate_group','v1097_gate_reason','v1097_structure_flag','v1096_gate_group','v1087_priority_class','pattern','strategy','tags','volume_state','signal_stop_bucket']
        parts=[base]
        for k in keys:
            try:
                v=row.get(k,'') if hasattr(row,'get') else ''
                if _v1098_s(v): parts.append(_v1098_s(v))
            except Exception:
                pass
        return ' '.join(parts)
    except Exception:
        return ''


def _v1098_fetch_ohlcv_window(code: str, signal_date, lookback_days: int=190, forward_days: int=15) -> pd.DataFrame:
    try:
        code=_v1098_norm_code(code)
        sig=pd.Timestamp(signal_date).normalize()
        start=(sig-pd.Timedelta(days=max(120, int(lookback_days)))).strftime('%Y-%m-%d')
        end=(sig+pd.Timedelta(days=max(5, int(forward_days)))).strftime('%Y-%m-%d')
        key=(code,start,end)
        if key not in _V1098_OHLCV_CACHE:
            _V1098_OHLCV_CACHE[key]=fdr.DataReader(code, start, end)
        df=_V1098_OHLCV_CACHE.get(key)
        if df is None or df.empty:
            return pd.DataFrame()
        out=df.copy()
        out.index=pd.to_datetime(out.index).normalize()
        for c in ['Open','High','Low','Close','Volume']:
            if c not in out.columns:
                return pd.DataFrame()
        return out.sort_index()
    except Exception:
        return pd.DataFrame()


def _v1098_bucket_vol_ratio(vr: float) -> str:
    try:
        vr=float(vr)
        strong=float(os.environ.get('V1098_STRONG_VOL_RATIO','2.5'))
        meaningful=float(os.environ.get('V1098_MIN_MEANINGFUL_VOL_RATIO','1.5'))
        if vr >= strong: return '강한돌파(2.5x+)'
        if vr >= meaningful: return '의미돌파(1.5~2.5x)'
        if vr >= 1.0: return '보통돌파(1.0~1.5x)'
        return '거래량부족(<1x)'
    except Exception:
        return '거래량미확인'


def _v1098_bucket_amount(amount_b: float) -> str:
    try:
        a=float(amount_b)
        if a >= 300: return '300억+'
        if a >= 100: return '100~300억'
        if a >= 30: return '30~100억'
        if a > 0: return '30억미만'
        return '거래대금미확인'
    except Exception:
        return '거래대금미확인'


def _v1098_supply_label(pct: float, kind: str='near') -> str:
    try:
        p=float(pct)
        if kind == 'near':
            if p >= 12: return '두꺼움'
            if p >= 5: return '보통'
            return '얇음'
        if p >= 20: return '두꺼움'
        if p >= 8: return '보통'
        return '얇음'
    except Exception:
        return '미확인'


def _v1098_overhead_supply(df: pd.DataFrame, ref_price: float, sig_ts) -> dict:
    try:
        ref=float(ref_price)
        if ref <= 0 or df is None or df.empty:
            return {'v1098_supply_group':'매물대미확인'}
        lookback=int(_v1098_num(os.environ.get('V1098_BREAKOUT_LOOKBACK_DAYS','120'),120))
        hist=df[df.index < pd.Timestamp(sig_ts).normalize()].tail(max(30, lookback)).copy()
        if hist.empty or 'Volume' not in hist.columns:
            return {'v1098_supply_group':'매물대미확인'}
        tp=(hist['High'].astype(float)+hist['Low'].astype(float)+hist['Close'].astype(float))/3.0
        vol=hist['Volume'].astype(float).fillna(0)
        total=float(vol.sum())
        if total <= 0:
            return {'v1098_supply_group':'매물대미확인'}
        r=(tp/ref-1.0)*100.0
        b03=float(vol[(r>=0)&(r<3)].sum()/total*100.0)
        b37=float(vol[(r>=3)&(r<7)].sum()/total*100.0)
        b712=float(vol[(r>=7)&(r<12)].sum()/total*100.0)
        l03=_v1098_supply_label(b03,'near')
        l37=_v1098_supply_label(b37,'mid')
        l712=_v1098_supply_label(b712,'far')
        if b03 >= 12:
            group='근접매물부담(+0~3%)'
        elif b37 >= 18:
            group='중간매물부담(+3~7%)'
        elif b03 < 5 and b37 < 8:
            group='상단얇음(+7%여백)'
        elif b03 < 8 and b37 < 15:
            group='상단보통'
        else:
            group='상단매물확인'
        return {
            'v1098_supply_group':group,
            'v1098_supply_0_3_pct':round(b03,2),
            'v1098_supply_3_7_pct':round(b37,2),
            'v1098_supply_7_12_pct':round(b712,2),
            'v1098_supply_0_3_label':l03,
            'v1098_supply_3_7_label':l37,
            'v1098_supply_7_12_label':l712,
        }
    except Exception:
        return {'v1098_supply_group':'매물대미확인'}


def _v1098_find_breakout(df: pd.DataFrame, sig_ts, entry_price: float=0.0) -> dict:
    try:
        sig=pd.Timestamp(sig_ts).normalize()
        hist=df[df.index <= sig].copy()
        if hist.empty or len(hist) < 35:
            return {'v1098_breakout_found':False, 'v1098_breakout_state':'데이터부족'}
        sig_pos=len(hist)-1
        search_days=int(_v1098_num(os.environ.get('V1098_BREAKOUT_SEARCH_DAYS','8'),8))
        start_pos=max(25, sig_pos-search_days+1)
        cands=[]
        for pos in range(start_pos, sig_pos+1):
            if pos < 25: continue
            prev=hist.iloc[:pos]
            if prev.empty: continue
            row=hist.iloc[pos]
            prior20=float(prev['High'].tail(20).max())
            prior60=float(prev['High'].tail(60).max()) if len(prev)>=60 else prior20
            resistance=max(prior20, prior60*0.995)
            close=float(row['Close']); high=float(row['High']); low=float(row['Low'])
            vol=float(row.get('Volume',0) or 0)
            v20=float(prev['Volume'].tail(20).mean()) if 'Volume' in prev.columns else 0.0
            vr=vol/v20 if v20>0 else 0.0
            close_break=(close >= resistance*1.002) or (close >= prior20*1.005)
            high_break=(high >= resistance*1.008)
            if close_break or high_break:
                score=((close/resistance-1.0)*100.0 if resistance>0 else 0) + min(vr,5)*0.8 + (1 if close_break else 0)
                cands.append((pos, score, resistance, prior20, prior60, vr))
        if cands:
            # 1차 돌파 후 눌림/재돌파를 보기 위해 가장 이른 의미 돌파를 우선 선택한다.
            pos,score,resistance,prior20,prior60,vr0 = cands[0]
        else:
            pos=sig_pos
            prev=hist.iloc[:pos]
            if prev.empty:
                return {'v1098_breakout_found':False, 'v1098_breakout_state':'데이터부족'}
            prior20=float(prev['High'].tail(20).max())
            prior60=float(prev['High'].tail(60).max()) if len(prev)>=60 else prior20
            resistance=max(prior20, prior60*0.995)
        brow=hist.iloc[pos]
        bdate=hist.index[pos]
        prev=hist.iloc[:pos]
        bopen=float(brow.get('Open',brow.get('Close',0)) or 0)
        bhigh=float(brow.get('High',0) or 0); blow=float(brow.get('Low',0) or 0); bclose=float(brow.get('Close',0) or 0)
        bvol=float(brow.get('Volume',0) or 0)
        v20=float(prev['Volume'].tail(20).mean()) if not prev.empty and 'Volume' in prev.columns else 0.0
        vr=bvol/v20 if v20>0 else 0.0
        amount_b=(bclose*bvol)/100000000.0 if bclose>0 and bvol>0 else 0.0
        rng=max(bhigh-blow, 0.0)
        close_pos=((bclose-blow)/rng*100.0) if rng>0 else 50.0
        upper_wick=((bhigh-bclose)/rng*100.0) if rng>0 else 0.0
        body_pct=(abs(bclose-bopen)/bopen*100.0) if bopen>0 else 0.0
        age=max(0, sig_pos-pos)
        sigrow=hist.iloc[sig_pos]
        sig_close=float(sigrow.get('Close',0) or 0); sig_vol=float(sigrow.get('Volume',0) or 0)
        after=hist.iloc[pos+1:sig_pos+1].copy() if age>0 else pd.DataFrame()
        support_held=False; dry_pullback=False; rebreak=False; pull_vol_ratio=0.0; min_low=0.0
        if age>0 and not after.empty:
            min_low=float(after['Low'].min())
            support_held = min_low >= float(resistance)*0.97
            pull_avg=float(after['Volume'].mean()) if 'Volume' in after.columns else 0.0
            pull_vol_ratio=(pull_avg/bvol) if bvol>0 else 0.0
            dry_pullback = pull_vol_ratio <= 0.75
            prev_after=hist.iloc[pos+1:sig_pos]
            prev_high=float(prev_after['High'].max()) if not prev_after.empty else bhigh
            prev5=hist.iloc[max(0,sig_pos-5):sig_pos]
            prev5_vol=float(prev5['Volume'].mean()) if not prev5.empty and 'Volume' in prev5.columns else 0.0
            vol_rein=(sig_vol/prev5_vol >= 1.15) if prev5_vol>0 else False
            rebreak = (sig_close >= max(float(resistance)*1.002, prev_high*0.998)) and (vol_rein or sig_close >= bhigh*0.995)
        if age == 0:
            pull_state='👀 1차돌파'
        elif support_held and dry_pullback and rebreak:
            pull_state='🟢 눌림후재돌파'
        elif support_held and dry_pullback:
            pull_state='🟡 돌파눌림재지지'
        elif support_held:
            pull_state='🟠 돌파후버팀'
        else:
            pull_state='🔴 돌파실패/깊은눌림'
        supply=_v1098_overhead_supply(df, entry_price if entry_price>0 else sig_close, sig)
        supply_group=supply.get('v1098_supply_group','매물대미확인')
        vol_ok=vr >= float(os.environ.get('V1098_MIN_MEANINGFUL_VOL_RATIO','1.5'))
        close_ok=close_pos >= 70
        wick_ok=upper_wick <= 25
        supply_thin=('상단얇음' in supply_group)
        supply_bad=('부담' in supply_group)
        if '돌파실패' in pull_state:
            quality='🔴 돌파실패/재지지실패'
        elif vol_ok and close_ok and wick_ok and supply_thin:
            quality='🟢 거래량동반+상단얇음'
        elif vol_ok and close_ok and wick_ok:
            quality='🟡 거래량동반+매물확인'
        elif vr >= 1.0 and close_ok:
            quality='🟠 거래량보통/재지지필요'
        else:
            quality='🔴 거래량부족/약한돌파'
        out={
            'v1098_breakout_found': bool(cands),
            'v1098_breakout_day': pd.Timestamp(bdate).strftime('%Y-%m-%d'),
            'v1098_breakout_age_days': int(age),
            'v1098_resistance_price': round(float(resistance),4),
            'v1098_breakout_close': round(float(bclose),4),
            'v1098_breakout_close_gap_pct': round(((bclose/float(resistance)-1.0)*100.0) if resistance>0 else 0.0,2),
            'v1098_breakout_volume_ratio': round(float(vr),2),
            'v1098_breakout_volume_bucket': _v1098_bucket_vol_ratio(vr),
            'v1098_breakout_amount_b': round(float(amount_b),1),
            'v1098_breakout_amount_bucket': _v1098_bucket_amount(amount_b),
            'v1098_breakout_close_pos': round(float(close_pos),1),
            'v1098_breakout_upper_wick_pct': round(float(upper_wick),1),
            'v1098_breakout_body_pct': round(float(body_pct),1),
            'v1098_pullback_volume_ratio': round(float(pull_vol_ratio),2),
            'v1098_pullback_state': pull_state,
            'v1098_breakout_quality_group': quality,
            'v1098_breakout_state': quality,
        }
        out.update(supply)
        return out
    except Exception as e:
        return {'v1098_breakout_found':False, 'v1098_breakout_state':f'진단실패:{e}', 'v1098_breakout_quality_group':'진단실패'}


def _v1098_breakout_info(row) -> dict:
    try:
        code=_v1098_norm_code(row.get('code', row.get('종목코드','')) if hasattr(row,'get') else '')
        sig=row.get('signal_date', row.get('date','')) if hasattr(row,'get') else ''
        entry=_v1098_num(row.get('entry_price', row.get('현재가',0)) if hasattr(row,'get') else 0,0)
        txt=_v1098_join_text(row)
        is_resist=('저항돌파' in txt) or ('구조우수' in txt) or ('RECOVER' in txt) or ('OBSERVE-구조우수' in txt)
        if not code or not sig or not is_resist:
            return {'v1098_breakout_quality_group':'진단대상아님','v1098_pullback_state':'진단대상아님','v1098_supply_group':'진단대상아님'}
        df=_v1098_fetch_ohlcv_window(code, sig, lookback_days=220, forward_days=12)
        if df is None or df.empty:
            return {'v1098_breakout_quality_group':'가격데이터부족','v1098_pullback_state':'가격데이터부족','v1098_supply_group':'가격데이터부족'}
        return _v1098_find_breakout(df, sig, entry_price=entry)
    except Exception as e:
        return {'v1098_breakout_quality_group':f'진단실패:{e}', 'v1098_pullback_state':'진단실패', 'v1098_supply_group':'진단실패'}


def _v1098_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out=eval_df.copy()
        try:
            if '_v1097_enrich_eval' in globals():
                out=_v1097_enrich_eval(out)
        except Exception:
            pass
        infos=[]
        for _, row in out.iterrows():
            infos.append(_v1098_breakout_info(row))
        add=pd.DataFrame(infos, index=out.index)
        for c in add.columns:
            out[c]=add[c]
        return out
    except Exception:
        return eval_df


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1098 wrapper: 필요 시 실시간 신호행에도 저항돌파 품질 진단값을 저장한다."""
    try:
        base = _V1098_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1098_BASE_SIGNAL_ROW else {}
    except Exception:
        base = {}
    try:
        if _v1098_on('V1098_ENRICH_SIGNAL_ROWS','0'):
            tmp=dict(base or {})
            try:
                raw=row.to_dict() if hasattr(row,'to_dict') else dict(row)
                tmp.update({k:v for k,v in raw.items() if k not in tmp})
            except Exception:
                pass
            base.update(_v1098_breakout_info(tmp))
    except Exception:
        pass
    return base


def _v1098_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int=12) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        return _v1097_group_lines(ok, col, title, max_rows=max_rows, score_col='v1097_core_score') if '_v1097_group_lines' in globals() else []
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1098_examples(ok: pd.DataFrame, max_rows: int=10) -> list:
    try:
        if ok is None or ok.empty or 'v1098_breakout_quality_group' not in ok.columns:
            return []
        tmp=ok[~ok['v1098_breakout_quality_group'].astype(str).isin(['진단대상아님','가격데이터부족'])].copy()
        if tmp.empty:
            return []
        tmp['_r5']=pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_r10']=pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_vr']=pd.to_numeric(tmp.get('v1098_breakout_volume_ratio', pd.Series(dtype=float)), errors='coerce').fillna(0)
        tmp=tmp.sort_values(['_r5','_vr','_r10'], ascending=[False,False,False]).head(max_rows)
        lines=['[V1098 저항돌파 품질 예시]']
        for _,r in tmp.iterrows():
            name=_v1098_s(r.get('name', r.get('종목명','')),'')
            code=_v1098_s(r.get('code', r.get('종목코드','')),'')
            q=_v1098_s(r.get('v1098_breakout_quality_group',''))
            day=_v1098_s(r.get('v1098_breakout_day',''))
            vr=_v1098_num(r.get('v1098_breakout_volume_ratio',0),0)
            amt=_v1098_num(r.get('v1098_breakout_amount_b',0),0)
            sup=_v1098_s(r.get('v1098_supply_group',''))
            st=_v1098_s(r.get('v1098_pullback_state',''))
            wick=_v1098_num(r.get('v1098_breakout_upper_wick_pct',0),0)
            pos=_v1098_num(r.get('v1098_breakout_close_pos',0),0)
            r5=_v1098_num(r.get('next5_close_ret',0),0)
            r10=_v1098_num(r.get('next10_close_ret',0),0)
            lines.append(f'- {name}({code}) | {q} / {st} | 돌파일 {day} | V20 {vr:.2f}배 / {amt:.0f}억 / 윗꼬리 {wick:.1f}% / 종가위치 {pos:.1f}% | 매물 {sup} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}%')
        lines.append('')
        return lines
    except Exception:
        return []


def _v1098_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1098 저항돌파 품질 + 매물대 진단 백테스트]', '- 평가 데이터가 없습니다.', '']
        ok=eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok=_v1098_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1098 저항돌파 품질 + 매물대 진단 백테스트]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        total=len(ok)
        diag=ok[~ok.get('v1098_breakout_quality_group', pd.Series(['']*len(ok))).astype(str).isin(['진단대상아님'])].copy()
        structure=ok[ok.get('v1097_gate_tier', pd.Series(['']*len(ok))).astype(str).eq('OBSERVE_STRUCTURE')].copy() if 'v1097_gate_tier' in ok.columns else pd.DataFrame()
        lines=['[V1098 저항돌파 품질 + 매물대 진단 백테스트]']
        lines.append('- 목적: 저항돌파 흔적 후보가 실제로 거래량 동반 돌파였는지, 상단 매물대가 얇았는지, 돌파 후 눌림·재돌파 구조였는지 확인합니다.')
        lines.append('- 원칙: 저항돌파 당일은 관심등록, 눌림 재지지와 거래량 재유입 재돌파가 확인될 때 실전 후보로 봅니다.')
        lines.append(f'- 진단 대상: 평가 {total}개 중 저항돌파/구조 후보 {len(diag)}개 | 구조우수 관찰 {len(structure)}개')
        lines.append('- 돌파품질 기준: V20 대비 1.5배 이상 + 종가 고가권 + 짧은 윗꼬리 + 상단매물 얇음이면 의미 있는 돌파로 봅니다.')
        lines.append('')
        lines += _v1098_group_lines(diag, 'v1098_breakout_quality_group', 'V1098 저항돌파 품질별 성과', max_rows=10)
        lines += _v1098_group_lines(diag, 'v1098_breakout_volume_bucket', 'V1098 돌파 거래량 배수별 성과', max_rows=8)
        lines += _v1098_group_lines(diag, 'v1098_breakout_amount_bucket', 'V1098 돌파 거래대금별 성과', max_rows=8)
        lines += _v1098_group_lines(diag, 'v1098_supply_group', 'V1098 상단 매물대별 성과', max_rows=8)
        lines += _v1098_group_lines(diag, 'v1098_pullback_state', 'V1098 돌파눌림/재돌파 상태별 성과', max_rows=8)
        if structure is not None and not structure.empty:
            lines.append('[V1098 구조우수 저항돌파 품질 재분해]')
            lines.append(f'- 구조우수 관찰 {len(structure)}개를 돌파품질/매물대/눌림상태로 다시 분해합니다.')
            lines.append('')
            lines += _v1098_group_lines(structure, 'v1098_breakout_quality_group', 'V1098 구조우수 돌파품질별 성과', max_rows=8)
            lines += _v1098_group_lines(structure, 'v1098_supply_group', 'V1098 구조우수 상단매물별 성과', max_rows=8)
            lines += _v1098_group_lines(structure, 'v1098_pullback_state', 'V1098 구조우수 눌림재돌파별 성과', max_rows=8)
        lines += _v1098_examples(diag, max_rows=12)
        lines.append('[V1098 적용 가이드]')
        lines.append('- 거래량동반+상단얇음: 실전 후보 상향, 단 1차 돌파 당일 추격보다 눌림 재지지 확인이 우선입니다.')
        lines.append('- 거래량동반+매물확인: 매물대가 남아 있으므로 눌림 후 재돌파 확인형으로 봅니다.')
        lines.append('- 거래량보통/재지지필요: 구조관찰에 두고 재돌파 거래량이 붙을 때만 상향합니다.')
        lines.append('- 거래량부족/약한돌파 또는 돌파실패: 실전 TOP 제외, 다음 돌파 거래량 재확인 전까지 관찰만 합니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1098 저항돌파 품질 + 매물대 진단 백테스트]', f'- 생성 실패: {e}', '']


def _v1098_remove_old_block(report: str) -> str:
    try:
        s=str(report or '')
        markers=['[V1098 저항돌파 품질 + 매물대 진단 백테스트]']
        start=-1
        for m in markers:
            i=s.find(m)
            if i>=0 and (start<0 or i<start): start=i
        if start<0: return s
        next_candidates=[]
        for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
            j=s.find(m,start+1)
            if j>=0: next_candidates.append(j)
        end=min(next_candidates) if next_candidates else len(s)
        return (s[:start].rstrip()+'\n\n'+s[end:].lstrip('\n')).strip()
    except Exception:
        return report


def _v1098_inject_block(report: str, lines: list) -> str:
    try:
        s=_v1098_remove_old_block(str(report or ''))
        block='\n'.join(lines).strip()+'\n'
        anchor='[V1097 적용 가이드]'
        ai=s.find(anchor)
        if ai>=0:
            next_sec=-1
            for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                j=s.find(m, ai+1)
                if j>=0 and (next_sec<0 or j<next_sec): next_sec=j
            if next_sec>=0:
                return (s[:next_sec].rstrip()+'\n\n'+block+s[next_sec:]).strip()
        positions=[s.find(m) for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]'] if s.find(m)>=0]
        if positions:
            pos=min(positions)
            return (s[:pos].rstrip()+'\n\n'+block+s[pos:]).strip()
        return (s.rstrip()+'\n\n'+block).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1098 override: V1097 리포트 뒤에 저항돌파 품질+매물대 진단 블록을 추가한다."""
    try:
        report = _V1098_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1098_BASE_DIRECT_REPORT else ''
        s=str(report or '')
        s=s.replace('🧪 [V1097 직접 재현 주간 성과검증]', '🧪 [V1098 직접 재현 주간 성과검증]')
        s=s.replace('🧪 [V1096 직접 재현 주간 성과검증]', '🧪 [V1098 직접 재현 주간 성과검증]')
        s=s.replace('🧪 [V1095 직접 재현 주간 성과검증]', '🧪 [V1098 직접 재현 주간 성과검증]')
        if _v1098_on('V1098_BACKTEST_REPORT_BLOCK','1'):
            s=_v1098_inject_block(s, _v1098_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1098_BASE_DIRECT_REPORT:
                return _V1098_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1098 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

