def _v1100_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1100_s(v, default: str='') -> str:
    try:
        return _v1099_s(v, default) if '_v1099_s' in globals() else (str(v).strip() if v is not None else default)
    except Exception:
        return default


def _v1100_num(v, default: float=0.0) -> float:
    try:
        return _v1099_num(v, default) if '_v1099_num' in globals() else float(v)
    except Exception:
        return default


def _v1100_clean(txt, limit: int=140) -> str:
    try:
        t=re.sub(r'\s+', ' ', str(txt or '')).strip()
        if len(t) > limit:
            return t[:limit-1].rstrip() + '…'
        return t
    except Exception:
        return ''


def _v1100_row_blob(row) -> str:
    keys=[
        'name','종목명','code','종목코드','섹터','주도섹터','업종','테마','관련테마','뉴스테마','N조합','N구분','태그','tags',
        '검색패턴','대표신호','신호','재료','진입이유','AI재료분류','AI강한근거','AI시황의견','AI시황의견목록',
        'material_comment','theme_reason','market_issue','뉴스','뉴스제목','뉴스키워드','공시'
    ]
    parts=[]
    try:
        for k in keys:
            try:
                v=row.get(k, '') if hasattr(row,'get') else ''
            except Exception:
                v=''
            if _v1100_s(v):
                parts.append(_v1100_s(v))
    except Exception:
        pass
    return ' | '.join(parts)


