def _v1100_detect_row_themes(row) -> list:
    blob=_v1100_row_blob(row).lower()
    found=[]
    for theme, kws in _V1100_THEME_MAP:
        for kw in kws:
            if str(kw).lower() in blob:
                found.append((theme, kw))
                break
    return found


def _v1100_market_context_text() -> str:
    parts=[]
    env_keys=[
        'V1100_MARKET_THEME_TEXT','MARKET_THEME_TEXT','MARKET_BRIEFING_TEXT','NEWS_THEME_TEXT','SECTOR_REPORT_TEXT','US_MAPPING_TEXT',
        'TODAY_MARKET_TEXT','TODAY_THEME_TEXT','STOCKHUNTER_MARKET_CONTEXT'
    ]
    for k in env_keys:
        v=os.environ.get(k, '')
        if _v1100_s(v):
            parts.append(_v1100_s(v))
    # 일부 실행 경로에서는 시황 텍스트가 전역 변수로 남아 있을 수 있으므로 최대한 흡수한다.
    global_names=['briefing','market_briefing','sector_report','oil_briefing','news_theme_text','us_mapping_text','theme_info','sector_text','market_state_text']
    for k in global_names:
        try:
            v=globals().get(k, '')
            if isinstance(v, (str, int, float)) and _v1100_s(v):
                parts.append(_v1100_s(v))
        except Exception:
            pass
    return '\n'.join(parts)


def _v1100_find_market_snippet(text: str, keywords: list, limit: int=130) -> str:
    try:
        t=str(text or '')
        if not t.strip():
            return ''
        lines=[]
        for raw in re.split(r'[\n\r]+', t):
            line=raw.strip(' -\t')
            if line:
                lines.append(line)
        low_lines=[x.lower() for x in lines]
        kws=[str(k).lower() for k in keywords if str(k).strip()]
        for i,ll in enumerate(low_lines):
            if any(k in ll for k in kws):
                return _v1100_clean(lines[i], limit)
        # 라인 매칭이 안 되면 전체 텍스트 주변 스니펫
        low=t.lower()
        for k in kws:
            j=low.find(k)
            if j>=0:
                start=max(0, j-45); end=min(len(t), j+95)
                return _v1100_clean(t[start:end], limit)
    except Exception:
        pass
    return ''


def _v1100_is_attack_watch(row) -> bool:
    try:
        comp=_v1100_s(row.get('v1099_composite_group',''))
        tier=_v1100_s(row.get('v1099_decision_tier',''))
        g97=_v1100_s(row.get('v1097_gate_tier',''))
        p87=_v1100_s(row.get('v1087_priority_group', row.get('V1087우선순위','')))
        blob=' | '.join([comp,tier,g97,p87,_v1100_row_blob(row)])
        attack_terms=['거래량과열+윗꼬리','거래량동반+윗꼬리주의','RECOVER-AGGRESSIVE','AGGRESSIVE','공격형/추격주의','공격관찰']
        return any(x in blob for x in attack_terms)
    except Exception:
        return False


def _v1100_theme_material_comment(row) -> dict:
    """공격관찰 후보에 붙일 시황/테마 재료 코멘트 생성."""
    try:
        row_themes=_v1100_detect_row_themes(row)
        blob=_v1100_row_blob(row)
        market=_v1100_market_context_text()
        name=_v1100_s(row.get('name', row.get('종목명','')))
        code=_v1100_s(row.get('code', row.get('종목코드','')))
        keywords=[]
        if name: keywords.append(name)
        if code: keywords.append(code)
        for theme, kw in row_themes:
            keywords.extend([theme, kw])
        # row 자체에 명시 재료/시황의견이 있으면 우선 표시
        explicit=''
        for k in ['AI시황의견','AI시황의견목록','뉴스테마','관련테마','테마','주도섹터','재료','진입이유','AI재료분류','AI강한근거','material_comment','theme_reason','market_issue']:
            try:
                v=row.get(k,'') if hasattr(row,'get') else ''
            except Exception:
                v=''
            if _v1100_s(v):
                explicit=_v1100_clean(v, 120)
                break
        snippet=_v1100_find_market_snippet(market, keywords, 125) if market and keywords else ''
        theme_name=row_themes[0][0] if row_themes else ''
        matched_kw=row_themes[0][1] if row_themes else ''
        if snippet:
            comment=f"🔥 시황재료 연결: {theme_name or matched_kw or '관련테마'} — {snippet}"
            support='THEME_CONFIRMED'
        elif explicit and row_themes:
            comment=f"🧩 테마단서: {theme_name}({matched_kw}) — {explicit}"
            support='ROW_THEME_ONLY'
        elif explicit:
            comment=f"🧩 재료단서: {explicit}"
            support='ROW_MATERIAL_ONLY'
        elif row_themes:
            comment=f"🧩 테마추정: {theme_name}({matched_kw}) 후보. 시황 본문 연결은 미확인 — 차트 단독 추격 금지"
            support='INFERRED_THEME_ONLY'
        else:
            comment='⚪ 재료 미확인: 시황/테마 연결 없이 차트만 과열된 공격관찰 — 추격 금지'
            support='NO_THEME'
        return {
            'v1100_theme_support': support,
            'v1100_theme_name': theme_name,
            'v1100_theme_keyword': matched_kw,
            'v1100_attack_theme_comment': _v1100_clean(comment, 170),
        }
    except Exception as e:
        return {
            'v1100_theme_support': 'COMMENT_ERROR',
            'v1100_theme_name': '',
            'v1100_theme_keyword': '',
            'v1100_attack_theme_comment': f'코멘트 생성 실패: {str(e)[:80]}',
        }


def _v1100_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out=eval_df.copy()
        try:
            if '_v1099_enrich_eval' in globals():
                out=_v1099_enrich_eval(out)
        except Exception:
            pass
        rows=[]
        for _, row in out.iterrows():
            attack=_v1100_is_attack_watch(row)
            c=_v1100_theme_material_comment(row) if attack else {
                'v1100_theme_support':'NOT_ATTACK', 'v1100_theme_name':'', 'v1100_theme_keyword':'', 'v1100_attack_theme_comment':''
            }
            c['v1100_attack_watch']='🟠 공격관찰' if attack else '기타'
            if attack and c.get('v1100_theme_support') == 'THEME_CONFIRMED':
                c['v1100_attack_operation']='🟠 공격관찰-시황재료확인'
            elif attack and c.get('v1100_theme_support') in ('ROW_THEME_ONLY','ROW_MATERIAL_ONLY','INFERRED_THEME_ONLY'):
                c['v1100_attack_operation']='🟠 공격관찰-테마단서'
            elif attack:
                c['v1100_attack_operation']='⚪ 공격관찰-재료미확인'
            else:
                c['v1100_attack_operation']='기타'
            rows.append(c)
        add=pd.DataFrame(rows, index=out.index)
        for col in add.columns:
            out[col]=add[col]
        return out
    except Exception:
        return eval_df


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1100 wrapper: 실시간 신호행에도 공격관찰 시황재료 코멘트를 저장한다."""
    try:
        base=_V1100_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1100_BASE_SIGNAL_ROW else {}
    except Exception:
        base={}
    try:
        if _v1100_on('V1100_ENRICH_SIGNAL_ROWS','1'):
            tmp=dict(base or {})
            try:
                raw=row.to_dict() if hasattr(row,'to_dict') else dict(row)
                tmp.update({k:v for k,v in raw.items() if k not in tmp})
            except Exception:
                pass
            try:
                if '_v1099_classify_row' in globals() and 'v1099_composite_group' not in tmp:
                    tmp.update(_v1099_classify_row(tmp))
            except Exception:
                pass
            if _v1100_is_attack_watch(tmp):
                c=_v1100_theme_material_comment(tmp)
                base.update(c)
                base['공격관찰코멘트']=c.get('v1100_attack_theme_comment','')
                base['공격관찰시황연결']=c.get('v1100_theme_support','')
    except Exception:
        pass
    return base


def _v1100_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int=8) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        return _v1097_group_lines(ok, col, title, max_rows=max_rows, score_col='v1097_core_score') if '_v1097_group_lines' in globals() else []
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1100_attack_examples(ok: pd.DataFrame, max_rows: int=10) -> list:
    try:
        if ok is None or ok.empty:
            return []
        tmp=ok[ok.get('v1100_attack_watch', pd.Series(['']*len(ok))).astype(str).str.contains('공격관찰', na=False)].copy()
        if tmp.empty:
            return []
        tmp['_r5']=pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_r10']=pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_support_rank']=tmp.get('v1100_theme_support', pd.Series(['']*len(tmp))).astype(str).map({
            'THEME_CONFIRMED':0,'ROW_THEME_ONLY':1,'ROW_MATERIAL_ONLY':2,'INFERRED_THEME_ONLY':3,'NO_THEME':4
        }).fillna(9)
        tmp=tmp.sort_values(['_support_rank','_r5','_r10'], ascending=[True,False,False]).head(max_rows)
        lines=['[V1100 공격관찰 시황재료 예시]']
        for _,r in tmp.iterrows():
            name=_v1100_s(r.get('name', r.get('종목명','')))
            code=_v1100_s(r.get('code', r.get('종목코드','')))
            comp=_v1100_s(r.get('v1099_composite_group',''))
            op=_v1100_s(r.get('v1100_attack_operation',''))
            comment=_v1100_s(r.get('v1100_attack_theme_comment',''))
            r5=_v1100_num(r.get('next5_close_ret',0),0)
            r10=_v1100_num(r.get('next10_close_ret',0),0)
            lines.append(f'- {name}({code}) | {op} | {comp} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}%')
            if comment:
                lines.append(f'  ↳ {comment}')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1100 공격관찰 시황재료 예시]', f'- 생성 실패: {e}', '']


def _v1100_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1100 공격관찰 시황재료 코멘트]', '- 평가 데이터가 없습니다.', '']
        ok=eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok=_v1100_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1100 공격관찰 시황재료 코멘트]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        attack=ok[ok.get('v1100_attack_watch', pd.Series(['']*len(ok))).astype(str).str.contains('공격관찰', na=False)].copy()
        lines=['[V1100 공격관찰 시황재료 코멘트]']
        lines.append('- 목적: 거래량과열+윗꼬리/거래량동반+윗꼬리주의 같은 공격관찰 후보에 시황·테마 재료 코멘트를 붙입니다.')
        lines.append('- 원칙: 시황/뉴스테마/미국연결에서 같은 테마가 확인되면 공격관찰 가치가 있지만, 그래도 추격보다 눌림 재지지 확인이 우선입니다.')
        lines.append(f'- 공격관찰 후보: {len(attack)}개 | 시황재료확인 {int((attack.get("v1100_theme_support", pd.Series(dtype=str)).astype(str)=="THEME_CONFIRMED").sum()) if not attack.empty else 0}개 | 테마단서 {int((attack.get("v1100_theme_support", pd.Series(dtype=str)).astype(str).isin(["ROW_THEME_ONLY","ROW_MATERIAL_ONLY","INFERRED_THEME_ONLY"])).sum()) if not attack.empty else 0}개 | 재료미확인 {int((attack.get("v1100_theme_support", pd.Series(dtype=str)).astype(str)=="NO_THEME").sum()) if not attack.empty else 0}개')
        lines.append('')
        if not attack.empty:
            lines += _v1100_group_lines(attack, 'v1100_attack_operation', 'V1100 공격관찰 재료연결별 성과', max_rows=6)
            lines += _v1100_group_lines(attack, 'v1099_composite_group', 'V1100 공격관찰 유형별 성과', max_rows=6)
            lines += _v1100_group_lines(attack, 'v1100_theme_name', 'V1100 공격관찰 테마별 성과', max_rows=8)
            lines += _v1100_attack_examples(attack, max_rows=10)
        lines.append('[V1100 적용 가이드]')
        lines.append('- 🟠 공격관찰-시황재료확인: 시황 테마와 연결된 단기 탄력 후보. 고점 추격 금지, 눌림 재지지·재돌파 때만 검토')
        lines.append('- 🟠 공격관찰-테마단서: 종목 자체 테마 단서는 있으나 오늘 시황 본문 연결은 약함. 비중 축소 관찰')
        lines.append('- ⚪ 공격관찰-재료미확인: 차트만 과열된 상태. 실전 TOP 제외 또는 재료 확인 전 관망')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1100 공격관찰 시황재료 코멘트]', f'- 생성 실패: {e}', '']


def _v1100_remove_old_block(report: str) -> str:
    try:
        s=str(report or '')
        marker='[V1100 공격관찰 시황재료 코멘트]'
        start=s.find(marker)
        if start<0:
            return s
        next_candidates=[]
        for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
            j=s.find(m,start+1)
            if j>=0: next_candidates.append(j)
        end=min(next_candidates) if next_candidates else len(s)
        return (s[:start].rstrip()+'\n\n'+s[end:].lstrip('\n')).strip()
    except Exception:
        return report


def _v1100_inject_block(report: str, lines: list) -> str:
    try:
        s=_v1100_remove_old_block(str(report or ''))
        block='\n'.join(lines).strip()+'\n'
        anchor='[V1099 적용 가이드]'
        ai=s.find(anchor)
        if ai>=0:
            next_sec=-1
            for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                j=s.find(m, ai+1)
                if j>=0 and (next_sec<0 or j<next_sec):
                    next_sec=j
            if next_sec>=0:
                return (s[:next_sec].rstrip()+'\n\n'+block+s[next_sec:]).strip()
        positions=[s.find(m) for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]'] if s.find(m)>=0]
        if positions:
            pos=min(positions)
            return (s[:pos].rstrip()+'\n\n'+block+s[pos:]).strip()
        return (s.rstrip()+'\n\n'+block).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1100 override: V1099 리포트 뒤에 공격관찰 시황재료 코멘트 블록 추가."""
    try:
        report=_V1100_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1100_BASE_DIRECT_REPORT else ''
        s=str(report or '')
        s=s.replace('🧪 [V1099 직접 재현 주간 성과검증]', '🧪 [V1100 직접 재현 주간 성과검증]')
        s=s.replace('🧪 [V1098 직접 재현 주간 성과검증]', '🧪 [V1100 직접 재현 주간 성과검증]')
        if _v1100_on('V1100_BACKTEST_REPORT_BLOCK','1'):
            s=_v1100_inject_block(s, _v1100_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1100_BASE_DIRECT_REPORT:
                return _V1100_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1100 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

