def _v1101_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1101_s(v, default: str='') -> str:
    try:
        return _v1100_s(v, default) if '_v1100_s' in globals() else (str(v).strip() if v is not None else default)
    except Exception:
        return default


def _v1101_num(v, default: float=0.0) -> float:
    try:
        return _v1100_num(v, default) if '_v1100_num' in globals() else float(v)
    except Exception:
        return default


def _v1101_clean(txt, limit: int=150) -> str:
    try:
        t=re.sub(r'\s+', ' ', str(txt or '')).strip()
        if len(t)>limit:
            return t[:limit-1].rstrip()+'…'
        return t
    except Exception:
        return ''


def _v1101_safe_text(v, limit: int=3500) -> str:
    try:
        if v is None:
            return ''
        if isinstance(v, str):
            t=v
        elif isinstance(v, (list, tuple, set)):
            t='\n'.join([_v1101_safe_text(x, 600) for x in list(v)[:40]])
        elif isinstance(v, dict):
            parts=[]
            for i,(k,val) in enumerate(v.items()):
                if i>=40: break
                parts.append(f'{k}: {_v1101_safe_text(val, 500)}')
            t='\n'.join(parts)
        else:
            t=str(v)
        t=re.sub(r'\s+', ' ', t).strip() if len(t)<500 else str(t).strip()
        return t[:limit]
    except Exception:
        return ''


def _v1101_market_context_parts() -> list:
    """현재 실행에서 생성된 시황/섹터/뉴스/미국연결 텍스트 후보를 source와 함께 수집."""
    parts=[]
    env_keys=[
        'V1101_MARKET_CONTEXT_TEXT','V1101_SECTOR_CONTEXT_TEXT','V1101_NEWS_CONTEXT_TEXT','V1101_US_CONTEXT_TEXT',
        'V1100_MARKET_THEME_TEXT','MARKET_THEME_TEXT','MARKET_BRIEFING_TEXT','NEWS_THEME_TEXT','SECTOR_REPORT_TEXT','US_MAPPING_TEXT',
        'TODAY_MARKET_TEXT','TODAY_THEME_TEXT','STOCKHUNTER_MARKET_CONTEXT'
    ]
    for k in env_keys:
        try:
            v=os.environ.get(k, '')
            if _v1101_s(v):
                parts.append((f'env:{k}', _v1101_s(v)))
        except Exception:
            pass

    # live 본문 변수. DIRECT_REPLAY 백테스트에서는 보통 생성되지 않는다.
    global_names=[
        'sector_report','news_theme_text','us_mapping_text','briefing','oil_briefing',
        'market_briefing','market_news_titles','market_news_map','rule_news_result',
        'us_gpt_result','us_merged_events','us_rule_events','sector_results','directions',
        'issues','global_env','leader_env','extended_macro_pack','macro_status',
        'theme_info','sector_text','market_state_text','STOCKHUNTER_MARKET_CONTEXT_TEXT'
    ]
    for k in global_names:
        try:
            if k in globals():
                t=_v1101_safe_text(globals().get(k), 5000)
                if t:
                    parts.append((f'global:{k}', t))
        except Exception:
            pass

    # 혹시 다른 버전에서 전역 이름을 다르게 썼을 때를 대비한 완만한 자동 수집
    try:
        for k,v in list(globals().items()):
            lk=str(k).lower()
            if any(x in lk for x in ['sector_report','news_theme','us_mapping','market_context']) and k not in dict(parts):
                t=_v1101_safe_text(v, 3000)
                if t:
                    parts.append((f'global:{k}', t))
    except Exception:
        pass

    # 중복 텍스트 제거
    seen=set(); out=[]
    for src,t in parts:
        key=t[:300]
        if key and key not in seen:
            out.append((src,t)); seen.add(key)
    return out


def _v1101_market_context_text() -> str:
    try:
        return '\n'.join([f'[{src}]\n{txt}' for src,txt in _v1101_market_context_parts()])
    except Exception:
        return ''


def _v1101_context_source_summary() -> str:
    try:
        parts=_v1101_market_context_parts()
        if not parts:
            return '본문없음(DIRECT_REPLAY 또는 env 미입력)'
        labels=[src for src,_ in parts[:8]]
        total=sum(len(str(t)) for _,t in parts)
        return f'{len(parts)}개 소스 / {total:,}자 / ' + ', '.join(labels)
    except Exception:
        return '확인실패'


def _v1101_theme_keywords(theme_name: str, theme_kw: str='', row=None) -> list:
    kws=[]
    try:
        if theme_name: kws.append(theme_name)
        if theme_kw: kws.append(theme_kw)
        if row is not None:
            name=_v1101_s(row.get('name', row.get('종목명',''))) if hasattr(row,'get') else ''
            code=_v1101_s(row.get('code', row.get('종목코드',''))) if hasattr(row,'get') else ''
            if name: kws.append(name)
            if code: kws.append(code)
        # V1100 테마맵의 동의어 확장
        for th, words in globals().get('_V1100_THEME_MAP', []):
            if theme_name and th == theme_name:
                kws.extend(words)
        # 수동 확장: 시황문에서는 테마명이 다른 식으로 쓰일 수 있음
        extra={
            'AI전력/전력기기':['전력기기','전력망','전선','변압기','전력설비','AI 전력','전력 인프라','데이터센터 전력'],
            '반도체/HBM':['반도체','HBM','AI반도체','메모리','D램','디램','낸드','소부장'],
            '2차전지/소재':['2차전지','배터리','양극재','음극재','리튬','전구체'],
            '건설/기계/인프라':['건설','인프라','기계','중장비','재건','건설기계'],
            '원전/우라늄':['원전','원자력','SMR','우라늄'],
            '방산/우주항공':['방산','우주항공','항공우주','방위산업','무기'],
            '철강/소재':['철강','소재','비철','구리','알루미늄','니켈'],
            '자동차/부품':['자동차','차부품','전기차','자율주행','모빌리티'],
            '조선/해양플랜트':['조선','해양플랜트','LNG선','선박','수주'],
        }
        if theme_name in extra:
            kws.extend(extra[theme_name])
    except Exception:
        pass
    # 정리
    out=[]; seen=set()
    for k in kws:
        s=_v1101_s(k)
        if len(s)>=2 and s.lower() not in seen:
            out.append(s); seen.add(s.lower())
    return out


def _v1101_find_context_hits(row, max_hits: int=3) -> dict:
    """row의 테마/종목 키워드를 실제 시황본문에서 찾아 source/snippet을 반환."""
    try:
        themes=_v1100_detect_row_themes(row) if '_v1100_detect_row_themes' in globals() else []
        theme_name=themes[0][0] if themes else ''
        theme_kw=themes[0][1] if themes else ''
        kws=_v1101_theme_keywords(theme_name, theme_kw, row)
        parts=_v1101_market_context_parts()
        if not parts:
            return {'context_available':False,'theme_name':theme_name,'theme_keyword':theme_kw,'hits':[],'snippet':'','sources':''}
        hits=[]
        for src,txt in parts:
            try:
                lines=[x.strip(' -\t') for x in re.split(r'[\n\r]+', str(txt or '')) if x.strip()]
                low_lines=[x.lower() for x in lines]
                for kw in kws:
                    lk=kw.lower()
                    if not lk: continue
                    for i,ll in enumerate(low_lines):
                        if lk in ll:
                            hits.append({'source':src,'keyword':kw,'snippet':_v1101_clean(lines[i], 135)})
                            raise StopIteration
            except StopIteration:
                pass
            except Exception:
                # 라인 검색 실패 시 전체 검색
                low=str(txt).lower()
                for kw in kws:
                    j=low.find(str(kw).lower())
                    if j>=0:
                        raw=str(txt)
                        hits.append({'source':src,'keyword':kw,'snippet':_v1101_clean(raw[max(0,j-45):j+110],135)})
                        break
            if len(hits)>=max_hits:
                break
        snippet=' / '.join([f"{h['keyword']}@{h['source']}: {h['snippet']}" for h in hits[:max_hits]])
        sources=', '.join(sorted({h['source'] for h in hits}))
        return {'context_available':True,'theme_name':theme_name,'theme_keyword':theme_kw,'hits':hits,'snippet':snippet,'sources':sources}
    except Exception as e:
        return {'context_available':False,'theme_name':'','theme_keyword':'','hits':[],'snippet':f'본문검색 실패: {str(e)[:80]}','sources':''}


def _v1101_theme_material_comment(row) -> dict:
    """V1101: 공격관찰 후보에 실제 시황본문 직접 연결 여부를 명확히 표시."""
    try:
        # 먼저 V1100의 테마 추정/명시 재료를 재사용한다.
        base=_v1100_theme_material_comment(row) if '_v1100_theme_material_comment' in globals() else {}
        hit=_v1101_find_context_hits(row)
        theme_name=hit.get('theme_name') or base.get('v1100_theme_name','')
        theme_kw=hit.get('theme_keyword') or base.get('v1100_theme_keyword','')
        if hit.get('hits'):
            comment=f"🔥 시황본문 직접연결: {theme_name or theme_kw or '관련테마'} — {hit.get('snippet','')}"
            support='MARKET_CONTEXT_CONFIRMED'
        elif hit.get('context_available') and (theme_name or theme_kw):
            # 본문은 있었지만 해당 테마가 언급되지 않은 경우
            comment=f"🧩 테마단서: {theme_name or theme_kw}({theme_kw}) 후보. 오늘 시황본문 직접 언급은 미확인 — 차트 단독 추격 금지"
            support='THEME_ONLY_CONTEXT_NOT_MATCHED'
        elif not hit.get('context_available') and (theme_name or theme_kw):
            comment=f"🧩 테마단서: {theme_name or theme_kw}({theme_kw}) 후보. DIRECT_REPLAY/환경상 시황본문 없음 — live에서 본문 연결 재확인 필요"
            support='THEME_ONLY_NO_CONTEXT'
        elif base.get('v1100_theme_support') in ('ROW_MATERIAL_ONLY','ROW_THEME_ONLY'):
            comment=f"🧩 재료단서: {base.get('v1100_attack_theme_comment','')}"
            support='ROW_MATERIAL_ONLY'
        else:
            comment='⚪ 재료 미확인: 시황본문/테마 연결 없이 차트만 과열된 공격관찰 — 실전 TOP 제외'
            support='NO_THEME'
        return {
            'v1101_context_support': support,
            'v1101_context_available': 'Y' if hit.get('context_available') else 'N',
            'v1101_context_sources': hit.get('sources',''),
            'v1101_theme_name': theme_name,
            'v1101_theme_keyword': theme_kw,
            'v1101_market_context_snippet': _v1101_clean(hit.get('snippet',''), 210),
            'v1101_attack_theme_comment': _v1101_clean(comment, 240),
            # 호환 컬럼도 같이 업데이트
            'v1100_theme_support': support,
            'v1100_theme_name': theme_name,
            'v1100_theme_keyword': theme_kw,
            'v1100_attack_theme_comment': _v1101_clean(comment, 220),
        }
    except Exception as e:
        return {
            'v1101_context_support':'COMMENT_ERROR','v1101_context_available':'N','v1101_context_sources':'',
            'v1101_theme_name':'','v1101_theme_keyword':'','v1101_market_context_snippet':'',
            'v1101_attack_theme_comment':f'코멘트 생성 실패: {str(e)[:80]}',
            'v1100_theme_support':'COMMENT_ERROR','v1100_theme_name':'','v1100_theme_keyword':'','v1100_attack_theme_comment':f'코멘트 생성 실패: {str(e)[:80]}'
        }


def _v1101_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out=eval_df.copy()
        try:
            if '_v1099_enrich_eval' in globals():
                out=_v1099_enrich_eval(out)
        except Exception:
            pass
        rows=[]
        for _, row in out.iterrows():
            attack=_v1100_is_attack_watch(row) if '_v1100_is_attack_watch' in globals() else False
            c=_v1101_theme_material_comment(row) if attack else {
                'v1101_context_support':'NOT_ATTACK','v1101_context_available':'','v1101_context_sources':'',
                'v1101_theme_name':'','v1101_theme_keyword':'','v1101_market_context_snippet':'','v1101_attack_theme_comment':'',
                'v1100_theme_support':'NOT_ATTACK','v1100_theme_name':'','v1100_theme_keyword':'','v1100_attack_theme_comment':''
            }
            c['v1101_attack_watch']='🟠 공격관찰' if attack else '기타'
            sup=c.get('v1101_context_support','')
            if attack and sup == 'MARKET_CONTEXT_CONFIRMED':
                c['v1101_attack_operation']='🟠 공격관찰-시황본문확인'
            elif attack and sup in ('THEME_ONLY_CONTEXT_NOT_MATCHED','THEME_ONLY_NO_CONTEXT','ROW_MATERIAL_ONLY'):
                c['v1101_attack_operation']='🟠 공격관찰-테마단서'
            elif attack:
                c['v1101_attack_operation']='⚪ 공격관찰-재료미확인'
            else:
                c['v1101_attack_operation']='기타'
            # V1100 호환 컬럼도 맞춘다.
            c['v1100_attack_watch']=c['v1101_attack_watch']
            c['v1100_attack_operation']=c['v1101_attack_operation'].replace('시황본문확인','시황재료확인')
            rows.append(c)
        add=pd.DataFrame(rows, index=out.index)
        for col in add.columns:
            out[col]=add[col]
        return out
    except Exception:
        return eval_df


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1101 wrapper: 실시간 신호행에 시황본문 직접연결 코멘트를 저장."""
    try:
        base=_V1101_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1101_BASE_SIGNAL_ROW else {}
    except Exception:
        base={}
    try:
        if _v1101_on('V1101_ENRICH_SIGNAL_ROWS','1'):
            tmp=dict(base or {})
            try:
                raw=row.to_dict() if hasattr(row,'to_dict') else dict(row)
                tmp.update({k:v for k,v in raw.items() if k not in tmp})
            except Exception:
                pass
            try:
                if '_v1099_classify_row' in globals() and 'v1099_composite_group' not in tmp:
                    tmp.update(_v1099_classify_row(tmp))
            except Exception:
                pass
            if _v1100_is_attack_watch(tmp) if '_v1100_is_attack_watch' in globals() else False:
                c=_v1101_theme_material_comment(tmp)
                base.update(c)
                base['공격관찰코멘트']=c.get('v1101_attack_theme_comment','')
                base['공격관찰시황연결']=c.get('v1101_context_support','')
                base['공격관찰시황스니펫']=c.get('v1101_market_context_snippet','')
    except Exception:
        pass
    return base


def _v1101_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int=8) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        return _v1097_group_lines(ok, col, title, max_rows=max_rows, score_col='v1097_core_score') if '_v1097_group_lines' in globals() else []
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1101_attack_examples(ok: pd.DataFrame, max_rows: int=10) -> list:
    try:
        if ok is None or ok.empty:
            return []
        tmp=ok[ok.get('v1101_attack_watch', pd.Series(['']*len(ok))).astype(str).str.contains('공격관찰', na=False)].copy()
        if tmp.empty:
            return []
        tmp['_r5']=pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_r10']=pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        order={'MARKET_CONTEXT_CONFIRMED':0,'THEME_ONLY_CONTEXT_NOT_MATCHED':1,'THEME_ONLY_NO_CONTEXT':2,'ROW_MATERIAL_ONLY':3,'NO_THEME':4}
        tmp['_support_rank']=tmp.get('v1101_context_support', pd.Series(['']*len(tmp))).astype(str).map(order).fillna(9)
        tmp=tmp.sort_values(['_support_rank','_r5','_r10'], ascending=[True,False,False]).head(max_rows)
        lines=['[V1101 공격관찰 시황본문 연결 예시]']
        for _,r in tmp.iterrows():
            name=_v1101_s(r.get('name', r.get('종목명','')))
            code=_v1101_s(r.get('code', r.get('종목코드','')))
            comp=_v1101_s(r.get('v1099_composite_group',''))
            op=_v1101_s(r.get('v1101_attack_operation',''))
            comment=_v1101_s(r.get('v1101_attack_theme_comment',''))
            r5=_v1101_num(r.get('next5_close_ret',0),0)
            r10=_v1101_num(r.get('next10_close_ret',0),0)
            lines.append(f'- {name}({code}) | {op} | {comp} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}%')
            if comment:
                lines.append(f'  ↳ {comment}')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1101 공격관찰 시황본문 연결 예시]', f'- 생성 실패: {e}', '']


def _v1101_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1101 공격관찰 시황본문 직접 연결]', '- 평가 데이터가 없습니다.', '']
        ok=eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok=_v1101_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1101 공격관찰 시황본문 직접 연결]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        attack=ok[ok.get('v1101_attack_watch', pd.Series(['']*len(ok))).astype(str).str.contains('공격관찰', na=False)].copy()
        sup=attack.get('v1101_context_support', pd.Series(dtype=str)).astype(str) if not attack.empty else pd.Series(dtype=str)
        lines=['[V1101 공격관찰 시황본문 직접 연결]']
        lines.append('- 목적: 공격관찰 후보의 테마가 실제 섹터순환/뉴스테마/미국연결/시황브리핑 본문에 등장했는지 직접 확인합니다.')
        lines.append('- 원칙: 시황본문 직접연결은 공격관찰 상향 조건, 테마단서는 보조 조건, 재료미확인은 실전 TOP 제외입니다.')
        lines.append(f'- 시황본문 소스: {_v1101_context_source_summary()}')
        lines.append(f'- 공격관찰 후보: {len(attack)}개 | 시황본문확인 {int((sup=="MARKET_CONTEXT_CONFIRMED").sum()) if not attack.empty else 0}개 | 테마단서 {int(sup.isin(["THEME_ONLY_CONTEXT_NOT_MATCHED","THEME_ONLY_NO_CONTEXT","ROW_MATERIAL_ONLY"]).sum()) if not attack.empty else 0}개 | 재료미확인 {int((sup=="NO_THEME").sum()) if not attack.empty else 0}개')
        if not _v1101_market_context_parts():
            lines.append('  ↳ 참고: DIRECT_REPLAY 백테스트에서는 과거 시황본문이 없어서 대부분 테마단서까지만 표시됩니다. live 실행 또는 V1101_MARKET_CONTEXT_TEXT env 입력 시 본문확인이 작동합니다.')
        lines.append('')
        if not attack.empty:
            lines += _v1101_group_lines(attack, 'v1101_attack_operation', 'V1101 공격관찰 본문연결별 성과', max_rows=6)
            lines += _v1101_group_lines(attack, 'v1101_context_support', 'V1101 공격관찰 컨텍스트상태별 성과', max_rows=7)
            lines += _v1101_group_lines(attack, 'v1099_composite_group', 'V1101 공격관찰 유형별 성과', max_rows=7)
            lines += _v1101_group_lines(attack, 'v1101_theme_name', 'V1101 공격관찰 테마별 성과', max_rows=10)
            lines += _v1101_attack_examples(attack, max_rows=10)
        lines.append('[V1101 적용 가이드]')
        lines.append('- 🟠 공격관찰-시황본문확인: 실제 시황/뉴스/미국연결 본문에 같은 테마가 등장한 공격관찰. 단, 고점 추격 금지·눌림 재지지 우선')
        lines.append('- 🟠 공격관찰-테마단서: 종목 자체 테마는 있으나 시황본문 직접 연결은 미확인. 소액 관찰 또는 시황 수동 확인')
        lines.append('- ⚪ 공격관찰-재료미확인: 차트 단독 과열. 실전 TOP 제외')
        lines.append('- live에서 본문확인이 0개면 sector_report/news_theme_text/us_mapping_text가 생성되기 전에 후보 리포트가 만들어진 것이므로 V1101_CONTEXT_DEBUG=1로 소스 확인')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1101 공격관찰 시황본문 직접 연결]', f'- 생성 실패: {e}', '']


def _v1101_remove_old_blocks(report: str) -> str:
    try:
        s=str(report or '')
        for marker in ['[V1101 공격관찰 시황본문 직접 연결]','[V1100 공격관찰 시황재료 코멘트]']:
            start=s.find(marker)
            if start>=0:
                next_candidates=[]
                for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                    j=s.find(m,start+1)
                    if j>=0: next_candidates.append(j)
                end=min(next_candidates) if next_candidates else len(s)
                s=(s[:start].rstrip()+'\n\n'+s[end:].lstrip('\n')).strip()
        return s
    except Exception:
        return report


def _v1101_inject_block(report: str, lines: list) -> str:
    try:
        s=_v1101_remove_old_blocks(str(report or ''))
        block='\n'.join(lines).rstrip()+'\n'
        anchor='[V1099 적용 가이드]'
        ai=s.find(anchor)
        if ai>=0:
            next_sec=-1
            for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                j=s.find(m, ai+1)
                if j>=0 and (next_sec<0 or j<next_sec):
                    next_sec=j
            if next_sec>=0:
                return (s[:next_sec].rstrip()+'\n\n'+block+s[next_sec:]).strip()
        positions=[s.find(m) for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]'] if s.find(m)>=0]
        if positions:
            pos=min(positions)
            return (s[:pos].rstrip()+'\n\n'+block+s[pos:]).strip()
        return (s.rstrip()+'\n\n'+block).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1101 override: V1100 블록을 대체해 시황본문 직접 연결 블록을 출력."""
    try:
        report=_V1101_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1101_BASE_DIRECT_REPORT else ''
        s=str(report or '')
        for old in ['🧪 [V1100 직접 재현 주간 성과검증]','🧪 [V1099 직접 재현 주간 성과검증]','🧪 [V1098 직접 재현 주간 성과검증]']:
            s=s.replace(old, '🧪 [V1101 직접 재현 주간 성과검증]')
        if _v1101_on('V1101_BACKTEST_REPORT_BLOCK','1'):
            s=_v1101_inject_block(s, _v1101_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1101_BASE_DIRECT_REPORT:
                return _V1101_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1101 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

