def _v1102_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1102_s(v, default: str='') -> str:
    try:
        return _v1101_s(v, default) if '_v1101_s' in globals() else (str(v).strip() if v is not None else default)
    except Exception:
        return default


def _v1102_num(v, default: float=0.0) -> float:
    try:
        return _v1101_num(v, default) if '_v1101_num' in globals() else float(v)
    except Exception:
        return default


def _v1102_clean(txt, limit: int=170) -> str:
    try:
        t=re.sub(r'\s+', ' ', str(txt or '')).strip()
        if len(t) > limit:
            return t[:limit-1].rstrip() + '…'
        return t
    except Exception:
        return ''


def _v1102_textify(v, limit: int=5000) -> str:
    """실제 시황본문 후보만 문자열화. 함수/모듈/클래스는 제외한다."""
    try:
        if v is None:
            return ''
        if callable(v):
            return ''
        if isinstance(v, str):
            t=v
        elif isinstance(v, (list, tuple, set)):
            parts=[]
            for x in list(v)[:60]:
                tx=_v1102_textify(x, 600)
                if tx:
                    parts.append(tx)
            t='\n'.join(parts)
        elif isinstance(v, dict):
            parts=[]
            for i,(k,val) in enumerate(v.items()):
                if i>=80: break
                tv=_v1102_textify(val, 700)
                if tv:
                    parts.append(f'{k}: {tv}')
            t='\n'.join(parts)
        else:
            # pandas/DataFrame 등은 너무 큰 전체 덤프 방지. 단, 짧은 요약 문자열은 허용.
            cls=v.__class__.__name__.lower()
            if any(x in cls for x in ['dataframe','series','module','function','method','type']):
                return ''
            t=str(v)
        t=str(t or '').strip()
        if not t:
            return ''
        # 함수 repr/기본 객체 repr 필터
        low=t.lower()
        if '<function ' in low or '<module ' in low or '<class ' in low or 'object at 0x' in low:
            return ''
        # 실제 본문 가능성이 낮은 너무 짧은 조각은 제외
        meaningful_marks=['섹터','테마','시장','뉴스','미국','한국','나스닥','코스피','코스닥','반도체','전력','조선','방산','원전','2차전지','브리핑','레이더','mapping','sector','theme','market','news']
        if len(t) < 18 and not any(m.lower() in low for m in meaningful_marks):
            return ''
        return t[:limit]
    except Exception:
        return ''


def _v1102_capture_context(label: str, value, min_len: int=18) -> str:
    """시황/테마/미국연결 함수 출력값을 전역 bucket에 누적한다."""
    try:
        if not _v1102_on('V1102_MARKET_CONTEXT_CAPTURE','1'):
            return ''
        txt=_v1102_textify(value, 7000)
        if not txt or len(txt) < min_len:
            return ''
        # 후보 리포트 전체나 백테스트 전체가 들어오면 자기참조가 되므로 제외
        guard=['[V1101 공격관찰','[V1102 시황본문','[V1099 돌파품질','[V1098 저항돌파','[V1097 RECOVER','🧪 [V110']
        if any(g in txt for g in guard):
            return ''
        key=re.sub(r'\s+', ' ', txt[:400]).strip()
        for _, old in _V1102_CONTEXT_BUCKET:
            if re.sub(r'\s+', ' ', str(old)[:400]).strip() == key:
                return txt
        _V1102_CONTEXT_BUCKET.append((str(label or 'unknown'), txt))
        if len(_V1102_CONTEXT_BUCKET) > 80:
            del _V1102_CONTEXT_BUCKET[:-80]
        if _v1102_on('V1102_CAPTURE_DEBUG','0'):
            try:
                print(f"[V1102_CONTEXT_CAPTURE] {label}: {len(txt)} chars")
            except Exception:
                pass
        return txt
    except Exception:
        return ''


def _v1102_wrap_context_output(func_name: str, label: str=''):
    """이미 정의된 포맷/브리핑 함수의 반환값을 캡처하도록 래핑한다."""
    try:
        if not func_name or func_name in _V1102_CAPTURED_FUNC_NAMES:
            return
        base_func=globals().get(func_name)
        if not callable(base_func):
            return
        _V1102_CAPTURED_FUNC_NAMES.add(func_name)
        def _wrapped(*args, **kwargs):
            res=base_func(*args, **kwargs)
            try:
                _v1102_capture_context(label or func_name, res)
            except Exception:
                pass
            return res
        _wrapped.__name__=getattr(base_func, '__name__', func_name)
        _wrapped.__doc__=getattr(base_func, '__doc__', None)
        globals()[func_name]=_wrapped
    except Exception:
        pass


# live 실행에서 실제 본문이 생성되는 주요 함수들을 후킹한다.
for _nm, _lb in [
    ('format_sector_rotation_report', 'sector_rotation_report'),
    ('get_oil_sector_briefing', 'oil_sector_briefing'),
    ('get_market_briefing', 'market_briefing'),
    ('format_macro_briefing_for_telegram', 'macro_briefing'),
    ('format_news_theme_for_telegram', 'news_theme_report'),
    ('format_us_mapping_for_telegram', 'us_kor_mapping_report'),
    ('_v1025_build_market_leader_analysis_block', 'market_leader_block'),
]:
    _v1102_wrap_context_output(_nm, _lb)


def _v1102_market_context_parts() -> list:
    """V1102 전용: env + live 캡처 bucket + 실제 문자열 전역만 수집."""
    parts=[]
    try:
        # 1) V1102 캡처 bucket 우선
        for src, txt in list(_V1102_CONTEXT_BUCKET):
            t=_v1102_textify(txt, 7000)
            if t:
                parts.append((f'capture:{src}', t))
    except Exception:
        pass
    # 2) 사용자가 env로 직접 넣은 시황 본문
    env_keys=[
        'V1102_MARKET_CONTEXT_TEXT','V1102_SECTOR_CONTEXT_TEXT','V1102_NEWS_CONTEXT_TEXT','V1102_US_CONTEXT_TEXT',
        'V1101_MARKET_CONTEXT_TEXT','V1101_SECTOR_CONTEXT_TEXT','V1101_NEWS_CONTEXT_TEXT','V1101_US_CONTEXT_TEXT',
        'MARKET_THEME_TEXT','MARKET_BRIEFING_TEXT','NEWS_THEME_TEXT','SECTOR_REPORT_TEXT','US_MAPPING_TEXT',
        'TODAY_MARKET_TEXT','TODAY_THEME_TEXT','STOCKHUNTER_MARKET_CONTEXT'
    ]
    for k in env_keys:
        try:
            t=_v1102_textify(os.environ.get(k,''), 7000)
            if t:
                parts.append((f'env:{k}', t))
        except Exception:
            pass
    # 3) live에서 남는 실제 문자열 전역만. callable은 제외.
    global_names=[
        'sector_report','news_theme_text','us_mapping_text','briefing','oil_briefing',
        'market_briefing','market_news_titles','market_news_map','rule_news_result',
        'us_gpt_result','us_merged_events','us_rule_events','sector_results','directions',
        'issues','global_env','leader_env','extended_macro_pack','macro_status',
        'theme_info','sector_text','market_state_text','STOCKHUNTER_MARKET_CONTEXT_TEXT'
    ]
    for k in global_names:
        try:
            if k in globals():
                v=globals().get(k)
                if callable(v):
                    continue
                t=_v1102_textify(v, 5000)
                if t:
                    parts.append((f'global:{k}', t))
        except Exception:
            pass
    # 4) 자동 수집은 더 엄격하게: callables 배제 + 실제 본문 키워드 포함
    try:
        for k,v in list(globals().items()):
            lk=str(k).lower()
            if callable(v):
                continue
            if any(x in lk for x in ['sector_report_text','news_theme_text','us_mapping_text','market_context_text']):
                t=_v1102_textify(v, 4000)
                if t:
                    parts.append((f'global:{k}', t))
    except Exception:
        pass
    # 중복 제거
    seen=set(); out=[]
    for src,t in parts:
        key=re.sub(r'\s+', ' ', str(t)[:350]).strip()
        if key and key not in seen:
            out.append((src,t)); seen.add(key)
    return out


def _v1102_context_source_summary() -> str:
    try:
        parts=_v1102_market_context_parts()
        if not parts:
            return '본문없음(DIRECT_REPLAY 또는 live 본문 생성 전)'
        total=sum(len(str(t)) for _,t in parts)
        labels=[src for src,_ in parts[:10]]
        return f'{len(parts)}개 소스 / {total:,}자 / ' + ', '.join(labels)
    except Exception:
        return '확인실패'


def _v1102_find_context_hits(row, max_hits: int=3) -> dict:
    try:
        themes=_v1100_detect_row_themes(row) if '_v1100_detect_row_themes' in globals() else []
        theme_name=themes[0][0] if themes else ''
        theme_kw=themes[0][1] if themes else ''
        kws=_v1101_theme_keywords(theme_name, theme_kw, row) if '_v1101_theme_keywords' in globals() else []
        parts=_v1102_market_context_parts()
        if not parts:
            return {'context_available':False,'theme_name':theme_name,'theme_keyword':theme_kw,'hits':[],'snippet':'','sources':''}
        hits=[]
        for src,txt in parts:
            txt=str(txt or '')
            lines=[x.strip(' -\t') for x in re.split(r'[\n\r]+', txt) if x.strip()]
            if not lines:
                lines=[txt]
            low_lines=[x.lower() for x in lines]
            matched=False
            for kw in kws:
                lk=str(kw).lower().strip()
                if not lk: continue
                for i,ll in enumerate(low_lines):
                    if lk in ll:
                        hits.append({'source':src,'keyword':kw,'snippet':_v1102_clean(lines[i], 150)})
                        matched=True
                        break
                if matched:
                    break
            if len(hits)>=max_hits:
                break
        snippet=' / '.join([f"{h['keyword']}@{h['source']}: {h['snippet']}" for h in hits[:max_hits]])
        sources=', '.join(sorted({h['source'] for h in hits}))
        return {'context_available':True,'theme_name':theme_name,'theme_keyword':theme_kw,'hits':hits,'snippet':snippet,'sources':sources}
    except Exception as e:
        return {'context_available':False,'theme_name':'','theme_keyword':'','hits':[],'snippet':f'본문검색 실패: {str(e)[:80]}','sources':''}


def _v1102_theme_material_comment(row) -> dict:
    try:
        base=_v1100_theme_material_comment(row) if '_v1100_theme_material_comment' in globals() else {}
        hit=_v1102_find_context_hits(row)
        theme_name=hit.get('theme_name') or base.get('v1100_theme_name','')
        theme_kw=hit.get('theme_keyword') or base.get('v1100_theme_keyword','')
        if hit.get('hits'):
            comment=f"🔥 시황본문 캡처연결: {theme_name or theme_kw or '관련테마'} — {hit.get('snippet','')}"
            support='MARKET_CONTEXT_CAPTURED'
        elif hit.get('context_available') and (theme_name or theme_kw):
            comment=f"🧩 테마단서: {theme_name or theme_kw}({theme_kw}) 후보. 캡처된 시황본문 직접 언급은 미확인 — 차트 단독 추격 금지"
            support='THEME_ONLY_CONTEXT_NOT_MATCHED'
        elif not hit.get('context_available') and (theme_name or theme_kw):
            comment=f"🧩 테마단서: {theme_name or theme_kw}({theme_kw}) 후보. DIRECT_REPLAY/실행순서상 시황본문 캡처 없음 — live에서 재확인"
            support='THEME_ONLY_NO_CONTEXT'
        elif base.get('v1100_theme_support') in ('ROW_MATERIAL_ONLY','ROW_THEME_ONLY'):
            comment=f"🧩 재료단서: {base.get('v1100_attack_theme_comment','')}"
            support='ROW_MATERIAL_ONLY'
        else:
            comment='⚪ 재료 미확인: 시황본문/테마 연결 없이 차트만 과열된 공격관찰 — 실전 TOP 제외'
            support='NO_THEME'
        return {
            'v1102_context_support':support,
            'v1102_context_available':'Y' if hit.get('context_available') else 'N',
            'v1102_context_sources':hit.get('sources',''),
            'v1102_theme_name':theme_name,
            'v1102_theme_keyword':theme_kw,
            'v1102_market_context_snippet':_v1102_clean(hit.get('snippet',''),230),
            'v1102_attack_theme_comment':_v1102_clean(comment,260),
            # V1101/V1100 호환 컬럼
            'v1101_context_support':support,
            'v1101_context_available':'Y' if hit.get('context_available') else 'N',
            'v1101_context_sources':hit.get('sources',''),
            'v1101_theme_name':theme_name,
            'v1101_theme_keyword':theme_kw,
            'v1101_market_context_snippet':_v1102_clean(hit.get('snippet',''),220),
            'v1101_attack_theme_comment':_v1102_clean(comment,250),
            'v1100_theme_support':support,
            'v1100_theme_name':theme_name,
            'v1100_theme_keyword':theme_kw,
            'v1100_attack_theme_comment':_v1102_clean(comment,230),
        }
    except Exception as e:
        return {'v1102_context_support':'COMMENT_ERROR','v1102_context_available':'N','v1102_context_sources':'','v1102_theme_name':'','v1102_theme_keyword':'','v1102_market_context_snippet':'','v1102_attack_theme_comment':f'코멘트 생성 실패: {str(e)[:80]}'}


def _v1102_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out=eval_df.copy()
        try:
            if '_v1099_enrich_eval' in globals():
                out=_v1099_enrich_eval(out)
        except Exception:
            pass
        rows=[]
        for _, row in out.iterrows():
            attack=_v1100_is_attack_watch(row) if '_v1100_is_attack_watch' in globals() else False
            c=_v1102_theme_material_comment(row) if attack else {
                'v1102_context_support':'NOT_ATTACK','v1102_context_available':'','v1102_context_sources':'',
                'v1102_theme_name':'','v1102_theme_keyword':'','v1102_market_context_snippet':'','v1102_attack_theme_comment':'',
                'v1101_context_support':'NOT_ATTACK','v1101_context_available':'','v1101_context_sources':'',
                'v1101_theme_name':'','v1101_theme_keyword':'','v1101_market_context_snippet':'','v1101_attack_theme_comment':'',
                'v1100_theme_support':'NOT_ATTACK','v1100_theme_name':'','v1100_theme_keyword':'','v1100_attack_theme_comment':''
            }
            c['v1102_attack_watch']='🟠 공격관찰' if attack else '기타'
            sup=c.get('v1102_context_support','')
            if attack and sup == 'MARKET_CONTEXT_CAPTURED':
                c['v1102_attack_operation']='🟠 공격관찰-시황본문확인'
            elif attack and sup in ('THEME_ONLY_CONTEXT_NOT_MATCHED','THEME_ONLY_NO_CONTEXT','ROW_MATERIAL_ONLY'):
                c['v1102_attack_operation']='🟠 공격관찰-테마단서'
            elif attack:
                c['v1102_attack_operation']='⚪ 공격관찰-재료미확인'
            else:
                c['v1102_attack_operation']='기타'
            # 하위 버전 호환
            c['v1101_attack_watch']=c['v1102_attack_watch']
            c['v1101_attack_operation']=c['v1102_attack_operation']
            c['v1100_attack_watch']=c['v1102_attack_watch']
            c['v1100_attack_operation']=c['v1102_attack_operation'].replace('시황본문확인','시황재료확인')
            rows.append(c)
        add=pd.DataFrame(rows, index=out.index)
        for col in add.columns:
            out[col]=add[col]
        return out
    except Exception:
        return eval_df


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1102 wrapper: 실시간 신호행에 캡처된 실제 시황본문 연결 코멘트를 저장."""
    try:
        base=_V1102_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1102_BASE_SIGNAL_ROW else {}
    except Exception:
        base={}
    try:
        if _v1102_on('V1102_ENRICH_SIGNAL_ROWS','1'):
            tmp=dict(base or {})
            try:
                raw=row.to_dict() if hasattr(row,'to_dict') else dict(row)
                tmp.update({k:v for k,v in raw.items() if k not in tmp})
            except Exception:
                pass
            try:
                if '_v1099_classify_row' in globals() and 'v1099_composite_group' not in tmp:
                    tmp.update(_v1099_classify_row(tmp))
            except Exception:
                pass
            if _v1100_is_attack_watch(tmp) if '_v1100_is_attack_watch' in globals() else False:
                c=_v1102_theme_material_comment(tmp)
                base.update(c)
                base['공격관찰코멘트']=c.get('v1102_attack_theme_comment','')
                base['공격관찰시황연결']=c.get('v1102_context_support','')
                base['공격관찰시황스니펫']=c.get('v1102_market_context_snippet','')
    except Exception:
        pass
    return base


def _v1102_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int=8) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        return _v1097_group_lines(ok, col, title, max_rows=max_rows, score_col='v1097_core_score') if '_v1097_group_lines' in globals() else []
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1102_attack_examples(ok: pd.DataFrame, max_rows: int=10) -> list:
    try:
        if ok is None or ok.empty:
            return []
        tmp=ok[ok.get('v1102_attack_watch', pd.Series(['']*len(ok))).astype(str).str.contains('공격관찰', na=False)].copy()
        if tmp.empty:
            return []
        tmp['_r5']=pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_r10']=pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        order={'MARKET_CONTEXT_CAPTURED':0,'THEME_ONLY_CONTEXT_NOT_MATCHED':1,'THEME_ONLY_NO_CONTEXT':2,'ROW_MATERIAL_ONLY':3,'NO_THEME':4}
        tmp['_support_rank']=tmp.get('v1102_context_support', pd.Series(['']*len(tmp))).astype(str).map(order).fillna(9)
        tmp=tmp.sort_values(['_support_rank','_r5','_r10'], ascending=[True,False,False]).head(max_rows)
        lines=['[V1102 공격관찰 시황본문 캡처 연결 예시]']
        for _,r in tmp.iterrows():
            name=_v1102_s(r.get('name', r.get('종목명','')))
            code=_v1102_s(r.get('code', r.get('종목코드','')))
            comp=_v1102_s(r.get('v1099_composite_group',''))
            op=_v1102_s(r.get('v1102_attack_operation',''))
            comment=_v1102_s(r.get('v1102_attack_theme_comment',''))
            r5=_v1102_num(r.get('next5_close_ret',0),0)
            r10=_v1102_num(r.get('next10_close_ret',0),0)
            lines.append(f'- {name}({code}) | {op} | {comp} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}%')
            if comment:
                lines.append(f'  ↳ {comment}')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1102 공격관찰 시황본문 캡처 연결 예시]', f'- 생성 실패: {e}', '']


def _v1102_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1102 공격관찰 시황본문 캡처 연결]', '- 평가 데이터가 없습니다.', '']
        ok=eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok=_v1102_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1102 공격관찰 시황본문 캡처 연결]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        attack=ok[ok.get('v1102_attack_watch', pd.Series(['']*len(ok))).astype(str).str.contains('공격관찰', na=False)].copy()
        sup=attack.get('v1102_context_support', pd.Series(dtype=str)).astype(str) if not attack.empty else pd.Series(dtype=str)
        lines=['[V1102 공격관찰 시황본문 캡처 연결]']
        lines.append('- 목적: 섹터/뉴스테마/미국연결/시황브리핑 문자열이 생성되는 순간 캡처해 공격관찰 후보와 직접 연결합니다.')
        lines.append('- 보완점: V1101처럼 포맷 함수명·함수 객체를 시황본문으로 오인하지 않고, 실제 반환 문자열/env/전역 문자열만 사용합니다.')
        lines.append(f'- 시황본문 캡처 소스: {_v1102_context_source_summary()}')
        lines.append(f'- 공격관찰 후보: {len(attack)}개 | 시황본문확인 {int((sup=="MARKET_CONTEXT_CAPTURED").sum()) if not attack.empty else 0}개 | 테마단서 {int(sup.isin(["THEME_ONLY_CONTEXT_NOT_MATCHED","THEME_ONLY_NO_CONTEXT","ROW_MATERIAL_ONLY"]).sum()) if not attack.empty else 0}개 | 재료미확인 {int((sup=="NO_THEME").sum()) if not attack.empty else 0}개')
        if not _v1102_market_context_parts():
            lines.append('  ↳ 참고: DIRECT_REPLAY 백테스트에서는 과거 시황본문을 재생성하지 않으면 캡처본문이 없으므로, 테마단서 중심으로만 해석합니다.')
        lines.append('')
        if not attack.empty:
            lines += _v1102_group_lines(attack, 'v1102_attack_operation', 'V1102 공격관찰 본문연결별 성과', max_rows=6)
            lines += _v1102_group_lines(attack, 'v1102_context_support', 'V1102 공격관찰 컨텍스트상태별 성과', max_rows=7)
            lines += _v1102_group_lines(attack, 'v1099_composite_group', 'V1102 공격관찰 유형별 성과', max_rows=7)
            lines += _v1102_group_lines(attack, 'v1102_theme_name', 'V1102 공격관찰 테마별 성과', max_rows=10)
            lines += _v1102_attack_examples(attack, max_rows=10)
        lines.append('[V1102 적용 가이드]')
        lines.append('- 🟠 공격관찰-시황본문확인: 실제 생성된 시황/섹터/뉴스/미국연결 본문과 매칭된 후보. 추격보다 눌림 재지지·재돌파 확인')
        lines.append('- 🟠 공격관찰-테마단서: 종목 자체 테마는 있으나 캡처본문 직접 연결은 미확인. 소액 관찰 또는 시황 수동 확인')
        lines.append('- ⚪ 공격관찰-재료미확인: 차트 단독 과열. 실전 TOP 제외')
        lines.append('- live에서도 본문확인이 0개면 시황 블록 생성보다 후보 리포트가 먼저 만들어진 순서 문제일 수 있으므로 V1102_CAPTURE_DEBUG=1로 캡처 로그 확인')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1102 공격관찰 시황본문 캡처 연결]', f'- 생성 실패: {e}', '']


def _v1102_remove_old_blocks(report: str) -> str:
    try:
        s=str(report or '')
        markers=['[V1102 공격관찰 시황본문 캡처 연결]','[V1101 공격관찰 시황본문 직접 연결]','[V1100 공격관찰 시황재료 코멘트]']
        for marker in markers:
            start=s.find(marker)
            if start>=0:
                next_candidates=[]
                for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                    j=s.find(m,start+1)
                    if j>=0: next_candidates.append(j)
                end=min(next_candidates) if next_candidates else len(s)
                s=(s[:start].rstrip()+'\n\n'+s[end:].lstrip('\n')).strip()
        return s
    except Exception:
        return report


def _v1102_inject_block(report: str, lines: list) -> str:
    try:
        s=_v1102_remove_old_blocks(str(report or ''))
        block='\n'.join(lines).rstrip()+'\n'
        anchor='[V1099 적용 가이드]'
        ai=s.find(anchor)
        if ai>=0:
            next_sec=-1
            for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                j=s.find(m, ai+1)
                if j>=0 and (next_sec<0 or j<next_sec):
                    next_sec=j
            if next_sec>=0:
                return (s[:next_sec].rstrip()+'\n\n'+block+s[next_sec:]).strip()
        positions=[s.find(m) for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]'] if s.find(m)>=0]
        if positions:
            pos=min(positions)
            return (s[:pos].rstrip()+'\n\n'+block+s[pos:]).strip()
        return (s.rstrip()+'\n\n'+block).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1102 override: V1101 블록을 대체해 실제 시황본문 캡처 연결 블록을 출력."""
    try:
        report=_V1102_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1102_BASE_DIRECT_REPORT else ''
        s=str(report or '')
        for old in ['🧪 [V1101 직접 재현 주간 성과검증]','🧪 [V1100 직접 재현 주간 성과검증]','🧪 [V1099 직접 재현 주간 성과검증]','🧪 [V1098 직접 재현 주간 성과검증]']:
            s=s.replace(old, '🧪 [V1102 직접 재현 주간 성과검증]')
        if _v1102_on('V1102_BACKTEST_REPORT_BLOCK','1'):
            s=_v1102_inject_block(s, _v1102_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1102_BASE_DIRECT_REPORT:
                return _V1102_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1102 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

