def _v1103_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1103_int(name: str, default: int=7) -> int:
    try:
        return int(float(os.environ.get(name, default)))
    except Exception:
        return default


def _v1103_float(name: str, default: float=48.0) -> float:
    try:
        return float(os.environ.get(name, default))
    except Exception:
        return default


def _v1103_s(v, default: str='') -> str:
    try:
        if '_v1102_s' in globals():
            return _v1102_s(v, default)
        return str(v).strip() if v is not None else default
    except Exception:
        return default


def _v1103_num(v, default: float=0.0) -> float:
    try:
        if '_v1102_num' in globals():
            return _v1102_num(v, default)
        return float(str(v).replace(',',''))
    except Exception:
        return default


def _v1103_clean(txt, limit: int=120) -> str:
    try:
        if '_v1102_clean' in globals():
            return _v1102_clean(txt, limit)
        t=re.sub(r'\s+', ' ', str(txt or '')).strip()
        return t[:limit-1].rstrip()+'…' if len(t)>limit else t
    except Exception:
        return ''


def _v1103_rowdict(row) -> dict:
    try:
        if hasattr(row, 'to_dict'):
            return row.to_dict()
        if isinstance(row, dict):
            return dict(row)
        return dict(row)
    except Exception:
        return {}


def _v1103_get(d: dict, *keys, default=''):
    try:
        for k in keys:
            if k in d and d.get(k) is not None and str(d.get(k)).lower() != 'nan':
                return d.get(k)
    except Exception:
        pass
    return default


def _v1103_blob(row) -> str:
    d=_v1103_rowdict(row)
    keys=['name','종목명','code','종목코드','Sector','sector','업종','테마','재료','이슈','검색패턴','N구분','대표신호','신호','구조','해설','AI코멘트','v1102_theme_name','v1101_theme_name','v1100_theme_name','v1099_composite_group','v1097_core_group','최종판정','최종판정(종합)','매매판정','action','대응']
    try:
        return ' '.join(_v1103_s(d.get(k,'')) for k in keys if _v1103_s(d.get(k,'')))
    except Exception:
        return str(d)[:1500]


def _v1103_detect_row_theme(row) -> tuple:
    """후발/저평가 레이더용 테마 분류. V1100 테마 탐지 + V1103 세부 테마맵 보강."""
    try:
        if '_v1100_detect_row_themes' in globals():
            themes=_v1100_detect_row_themes(row)
            if themes:
                th, kw = themes[0][0], themes[0][1]
                # V1100에서 넓게 잡힌 AI전력/반도체 등을 V1103 세부축으로 다시 보정
                blob=_v1103_blob(row).lower()
                for tname, kws in _V1103_THEME_MAP:
                    for k in kws:
                        if str(k).lower() in blob:
                            return tname, k
                return th, kw
    except Exception:
        pass
    blob=_v1103_blob(row).lower()
    for tname, kws in _V1103_THEME_MAP:
        for k in kws:
            try:
                if str(k).lower() in blob:
                    return tname, k
            except Exception:
                continue
    return '미분류', ''


def _v1103_context_text() -> str:
    try:
        parts=[]
        if '_v1102_market_context_parts' in globals():
            for src, txt in _v1102_market_context_parts():
                parts.append(str(txt or ''))
        for k in ['sector_report','news_theme_text','us_mapping_text','briefing','oil_briefing','market_briefing','STOCKHUNTER_MARKET_CONTEXT_TEXT']:
            try:
                if k in globals():
                    v=globals().get(k)
                    if not callable(v):
                        parts.append(str(v or ''))
            except Exception:
                pass
        for k in ['V1103_MARKET_CONTEXT_TEXT','V1102_MARKET_CONTEXT_TEXT','MARKET_THEME_TEXT','MARKET_BRIEFING_TEXT','NEWS_THEME_TEXT','SECTOR_REPORT_TEXT','US_MAPPING_TEXT','STOCKHUNTER_MARKET_CONTEXT']:
            try:
                parts.append(str(os.environ.get(k,'') or ''))
            except Exception:
                pass
        return '\n'.join([p for p in parts if p.strip()])[:30000]
    except Exception:
        return ''


def _v1103_context_line_for_theme(theme: str) -> str:
    try:
        ctx=_v1103_context_text()
        if not ctx:
            return ''
        kws=[]
        for tname, words in _V1103_THEME_MAP:
            if tname == theme:
                kws=words[:]
                break
        kws += [theme.split('/')[0], theme]
        lines=[x.strip(' -\t') for x in re.split(r'[\n\r]+', ctx) if x.strip()]
        for kw in kws:
            lk=str(kw).lower().strip()
            if not lk:
                continue
            for line in lines:
                if lk in line.lower():
                    return _v1103_clean(line, 130)
    except Exception:
        pass
    return ''



def _v1106_1_theme_family(theme: str) -> str:
    t = str(theme or '')
    if any(k in t for k in ['금융','은행','밸류업','보험','증권']):
        return '금융'
    if any(k in t for k in ['AI전력','전력설비','전력망','전선']):
        return 'AI전력'
    if any(k in t for k in ['항공/운송','유가하락','운송','물류','해운']):
        return '운송'
    if any(k in t for k in ['우주항공','스페이스X','방산','위성']):
        return '우주항공'
    if any(k in t for k in ['반도체','HBM']):
        return '반도체'
    return t

def _v1103_active_themes() -> list:
    """live 시황본문 기준으로 오늘 주목 축을 추출. DIRECT_REPLAY에서는 빈 값일 수 있음."""
    try:
        ctx=_v1103_context_text()
        low=ctx.lower()
        found=[]
        def add(theme, grade, reason):
            item={'theme':theme, 'grade':grade, 'reason':_v1103_clean(reason,100)}
            if not any(x['theme']==theme for x in found):
                found.append(item)
        if '반도체' in ctx or 'soxx' in low or 'smh' in low or 'hbm' in low or '마이크론' in ctx or '엔비디아' in ctx:
            add('반도체/HBM/테라팹','🟢주도','반도체 ETF/대표주 또는 HBM·파운드리 맥락')
        if '로봇' in ctx or '자동화' in ctx or 'botz' in low or 'robo' in low:
            add('로봇/자동화','🟡관찰','로봇/자동화 섹터 관찰')
        if '바이오' in ctx or '헬스케어' in ctx or '제약' in ctx:
            add('바이오/헬스케어','🟡초기','바이오 리스크온/초기 순환')
        if 'ai' in low or '데이터센터' in ctx or '광통신' in ctx or '광모듈' in ctx or '광케이블' in ctx:
            add('AI확산/데이터센터/광통신','🟡확산','AI 데이터센터·네트워크 후발 확산')
        if '전선' in ctx or '전력망' in ctx or '전력설비' in ctx or '송배전' in ctx or '변압기' in ctx:
            # 회피가 함께 있어도 완전 제외하지 않고 별도 관찰로 둔다.
            grade='🟡관찰'
            if 'AI전력/전력설비] ⛔회피' in ctx or 'AI전력/전력설비' in ctx and '섹터ETF 약세' in ctx:
                grade='🟠개별확인'
            add('AI전력/전력망/전선',grade,'AI전력/전선은 ETF보다 개별 거래대금·재지지 확인')
        if '2차전지' in ctx or 'ev' in low or '배터리' in ctx or '테슬라' in ctx:
            add('2차전지/EV','👀관찰','2차전지/EV 후발 관찰')
        if ('유가' in ctx and ('하락' in ctx or '유가↓' in ctx or '↓유가' in ctx)) or '비용완화' in ctx:
            add('항공/운송/유가하락수혜','👀역발상','유가하락 비용완화 수혜')
        if '금융' in ctx or '은행' in ctx or '금리' in ctx or '밸류업' in ctx:
            add('금융/밸류업','👀관찰','금리/밸류업/주주환원 맥락')
        return found
    except Exception:
        return []


def _v1103_theme_grade(theme: str) -> tuple:
    try:
        active=_v1103_active_themes()
        for i,item in enumerate(active):
            if item.get('theme') == theme:
                grade=item.get('grade','🟡관찰')
                # 점수 가중치
                if '주도' in grade:
                    return grade, 30, item.get('reason','')
                if '초기' in grade or '확산' in grade:
                    return grade, 24, item.get('reason','')
                if '관찰' in grade:
                    return grade, 20, item.get('reason','')
                if '개별확인' in grade:
                    return grade, 16, item.get('reason','')
        # DIRECT_REPLAY/본문없음에서는 테마 자체만 중립 가점
        if theme != '미분류':
            return '⚪테마단서', 12, '시황본문 없음 또는 직접 매칭 전'
    except Exception:
        pass
    return '⚪미분류', 0, ''


def _v1103_score_row(row) -> dict:
    d=_v1103_rowdict(row)
    theme, theme_kw = _v1103_detect_row_theme(d)
    grade, theme_score, theme_reason = _v1103_theme_grade(theme)
    blob=_v1103_blob(d)
    low=blob.lower()
    rsi=_v1103_num(_v1103_get(d,'RSI','rsi','rsi14','RSI14', default=0), 0)
    disp=_v1103_num(_v1103_get(d,'이격','Disparity','disparity','이격도', default=0), 0)
    bb40=_v1103_num(_v1103_get(d,'BB40','BB40폭','bb40','bb40_width','bb40_pct', default=0), 0)
    score=float(theme_score)
    reasons=[]
    risks=[]

    def add_reason(x):
        if x and x not in reasons:
            reasons.append(x)
    def add_risk(x):
        if x and x not in risks:
            risks.append(x)

    if theme != '미분류':
        add_reason(f'{theme}({grade})')
    if theme_reason:
        add_reason(theme_reason)

    # 저평가/덜 오른 구간: 너무 과열되지 않았고 기준선 근처인 종목 선호
    if rsi:
        if 43 <= rsi <= 62:
            score += 16; add_reason(f'RSI {rsi:.0f} 안정권')
        elif 35 <= rsi < 43:
            score += 10; add_reason(f'RSI {rsi:.0f} 저점권')
        elif 62 < rsi < 70:
            score += 6; add_reason(f'RSI {rsi:.0f} 상승중')
        elif rsi >= 70:
            score -= 18; add_risk(f'RSI {rsi:.0f} 과열')
    else:
        score += 2

    if disp:
        if 96 <= disp <= 108:
            score += 16; add_reason(f'이격 {disp:.0f} 적정')
        elif 90 <= disp < 96:
            score += 10; add_reason(f'이격 {disp:.0f} 저평가권')
        elif 108 < disp <= 112:
            score += 5; add_reason(f'이격 {disp:.0f} 약간부담')
        elif disp >= 115:
            score -= 20; add_risk(f'이격 {disp:.0f} 과열')
    else:
        score += 2

    if bb40:
        if bb40 <= 18:
            score += 12; add_reason(f'BB40 {bb40:.1f} 응축')
        elif bb40 <= 30:
            score += 8; add_reason(f'BB40 {bb40:.1f} 수렴권')
        elif bb40 >= 45:
            score -= 8; add_risk(f'BB40 {bb40:.1f} 과확장')
    if any(x in blob for x in ['삼각수렴','BB응축','응축','이평 수렴','MA수렴','수렴']):
        score += 10; add_reason('수렴/응축')
    if any(x in blob for x in ['거래량응축','응축우선','상대거래량 응축']):
        score += 10; add_reason('거래량응축')
    if any(x in blob for x in ['저평가','소외','바닥','하단권','BB하단','하단눌림']):
        score += 8; add_reason('저평가·소외/하단권')
    if any(x in blob for x in ['외인강','기관강','동반 강매집','외인·기관 동반','외인 중심 강매집','기관 중심 매집','외인우세']):
        score += 10; add_reason('외인/기관 수급')
    if any(x in blob for x in ['재지지','재안착','기준선 위','위안착','파란점선 위','5일선 위']):
        score += 7; add_reason('기준선 재지지/안착')
    if any(x in blob for x in ['후발','순환매','초기','꿈틀']):
        score += 6; add_reason('후발/초기순환')

    # 위험 감점. 순환매 레이더는 실행보류도 볼 수 있지만, 과열/강한 위험은 하단으로 보낸다.
    if any(x in blob for x in ['가짜수박강','가짜수박주의(강','RSI75','이격115','과열보류','진입금지']):
        score -= 18; add_risk('과열/가짜수박 강')
    if any(x in blob for x in ['돌파실패','재지지실패','기준선아래','신규진입보류']):
        score -= 8; add_risk('확인 전/기준선 미충족')
    if any(x in blob for x in ['수급미계산','미계산']):
        score -= 3; add_risk('수급미계산')
    if any(x in blob for x in ['윗꼬리과다','윗꼬리 부담','윗꼬리부담']):
        score -= 6; add_risk('윗꼬리 부담')

    if score >= 74 and len(risks) <= 1:
        bucket='🟢 주도섹터 후발/저평가'
        action='기준선 위 재지지와 거래량 재유입 시 관심 상향'
    elif score >= 60:
        bucket='🟡 순환매 관찰'
        action='대장주 추격보다 눌림·재안착 확인'
    elif score >= 48:
        bucket='⚪ 대기/확인'
        action='테마는 보되 기준선/수급 확인 전 신규 보류'
    else:
        bucket='🔴 과열/제외'
        action='실전 TOP 제외, 다음 재지지 전까지 관찰만'

    ctx_line=_v1103_context_line_for_theme(theme)
    return {
        'v1103_rotation_theme': theme,
        'v1103_rotation_theme_kw': theme_kw,
        'v1103_market_theme_grade': grade,
        'v1103_rotation_score': round(float(score), 1),
        'v1103_rotation_bucket': bucket,
        'v1103_rotation_action': action,
        'v1103_rotation_reasons': ', '.join(reasons[:5]),
        'v1103_rotation_risks': ', '.join(risks[:4]),
        'v1103_context_line': ctx_line,
        'v1103_is_rotation_candidate': 'Y' if bucket != '🔴 과열/제외' and theme != '미분류' else 'N',
    }


def _v1103_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out=eval_df.copy()
        try:
            if '_v1102_enrich_eval' in globals():
                out=_v1102_enrich_eval(out)
        except Exception:
            pass
        rows=[]
        for _, row in out.iterrows():
            rows.append(_v1103_score_row(row))
        add=pd.DataFrame(rows, index=out.index)
        for col in add.columns:
            out[col]=add[col]
        return out
    except Exception:
        return eval_df


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1103 wrapper: 실시간 신호행에도 후발/저평가 순환매 레이더 점수를 저장."""
    try:
        base=_V1103_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1103_BASE_SIGNAL_ROW else {}
    except Exception:
        base={}
    try:
        tmp=dict(base or {})
        try:
            raw=row.to_dict() if hasattr(row,'to_dict') else dict(row)
            tmp.update({k:v for k,v in raw.items() if k not in tmp})
        except Exception:
            pass
        c=_v1103_score_row(tmp)
        base.update(c)
        base['순환매테마']=c.get('v1103_rotation_theme','')
        base['순환매점수']=c.get('v1103_rotation_score',0)
        base['순환매판정']=c.get('v1103_rotation_bucket','')
        base['순환매코멘트']=_v1103_clean((c.get('v1103_rotation_reasons','')+' / '+c.get('v1103_rotation_risks','')).strip(' /'), 180)
    except Exception:
        pass
    return base


def _v1103_collect_live_rows(args, kwargs) -> list:
    try:
        row_map={}
        if '_v1070_collect_rows_from_args_kwargs' in globals():
            row_map=_v1070_collect_rows_from_args_kwargs(args, kwargs)
        if isinstance(row_map, dict) and row_map:
            return list(row_map.values())
    except Exception:
        pass
    rows=[]
    try:
        values=list(args)+list((kwargs or {}).values())
        for v in values:
            if v is None:
                continue
            if hasattr(v, 'iterrows'):
                for _, r in v.iterrows():
                    rows.append(r.to_dict())
            elif isinstance(v, dict):
                # dict of rows or a single row
                if any(isinstance(x, (dict,)) or hasattr(x,'to_dict') for x in v.values()):
                    for x in v.values():
                        if hasattr(x,'to_dict'):
                            rows.append(x.to_dict())
                        elif isinstance(x, dict):
                            rows.append(x)
                else:
                    rows.append(v)
            elif isinstance(v, (list, tuple)):
                for x in v:
                    if hasattr(x,'to_dict'):
                        rows.append(x.to_dict())
                    elif isinstance(x, dict):
                        rows.append(x)
    except Exception:
        pass
    return rows


def _v1103_live_radar_lines(rows: list, max_rows: int=None) -> list:
    try:
        if not _v1103_on('V1103_LIVE_RADAR_BLOCK','1'):
            return []
        if max_rows is None:
            max_rows=_v1103_int('V1103_ROTATION_LIMIT', 7)
        min_score=_v1103_float('V1103_MIN_ROTATION_SCORE', 48.0)
        enriched=[]
        seen=set()
        for r in rows or []:
            d=_v1103_rowdict(r)
            code=_v1103_s(_v1103_get(d,'code','종목코드','Code','ticker', default=''))
            name=_v1103_s(_v1103_get(d,'name','종목명','Name', default=''))
            if not name and not code:
                continue
            key=code or name
            if key in seen:
                continue
            seen.add(key)
            c=_v1103_score_row(d)
            sc=_v1103_num(c.get('v1103_rotation_score',0),0)
            if sc < min_score or c.get('v1103_rotation_theme') == '미분류':
                continue
            d.update(c)
            enriched.append(d)
        if not enriched:
            return []
        enriched=sorted(enriched, key=lambda x: _v1103_num(x.get('v1103_rotation_score',0),0), reverse=True)[:max_rows]
        active=_v1103_active_themes()
        active_txt=', '.join([f"{x.get('grade','')}{x.get('theme','')}" for x in active[:6]]) if active else '시황본문 없음/테마단서 기준'
        lines=['', '🧭 [주도섹터 후발/저평가 순환매 레이더]', '기준: 오늘 주목 섹터 안에서 아직 덜 오른 후발·소외·응축 후보만 따로 봅니다.', f'오늘 주목축: {active_txt}', '']
        for i,d in enumerate(enriched,1):
            name=_v1103_s(_v1103_get(d,'name','종목명','Name', default=''))
            code=_v1103_s(_v1103_get(d,'code','종목코드','Code', default=''))
            price=_v1103_s(_v1103_get(d,'현재가','current_price','price','Close','종가', default=''))
            theme=_v1103_s(d.get('v1103_rotation_theme',''))
            score=_v1103_num(d.get('v1103_rotation_score',0),0)
            bucket=_v1103_s(d.get('v1103_rotation_bucket',''))
            reasons=_v1103_s(d.get('v1103_rotation_reasons',''))
            risks=_v1103_s(d.get('v1103_rotation_risks',''))
            action=_v1103_s(d.get('v1103_rotation_action',''))
            ctx=_v1103_s(d.get('v1103_context_line',''))
            line=f'{i}) {name}({code}) {bucket} | {theme} | 점수 {score:.1f}'
            if price:
                line += f' | 현재 {price}'
            lines.append(line)
            if reasons:
                lines.append(f'   🧩 {_v1103_clean(reasons, 110)}')
            if ctx:
                lines.append(f'   🔗 시황연결: {_v1103_clean(ctx, 110)}')
            if risks:
                lines.append(f'   ⚠️ {_v1103_clean(risks, 95)}')
            lines.append(f'   ✅ {_v1103_clean(action, 100)}')
        lines.append('')
        lines.append('📌 운용: 이 블록은 즉시매수 TOP이 아니라 다음 순환매 감시 목록입니다. 기준선 재지지·거래량 재유입 전 추격 금지.')
        return lines
    except Exception as e:
        return ['', '🧭 [주도섹터 후발/저평가 순환매 레이더]', f'- 생성 실패: {e}', '']


def _v1103_remove_live_block(text: str) -> str:
    try:
        s=str(text or '')
        marker='🧭 [주도섹터 후발/저평가 순환매 레이더]'
        p=s.find(marker)
        if p<0:
            return s
        start=s.rfind('\n',0,p)
        if start<0: start=p
        nexts=[]
        for m in ['\n⚠️ [리스크 참고','\n⛔ 제외/리스크','\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━']:
            j=s.find(m,p+1)
            if j>=0:
                nexts.append(j)
        end=min(nexts) if nexts else len(s)
        return (s[:start].rstrip()+'\n'+s[end:].lstrip('\n')).strip()
    except Exception:
        return text


def _v1103_inject_live_radar(base: str, rows: list) -> str:
    try:
        s=_v1103_remove_live_block(str(base or ''))
        lines=_v1103_live_radar_lines(rows)
        if not lines:
            return s
        block='\n'.join(lines).rstrip()
        # 리스크 참고/제외 블록 앞에 넣으면 실행 후보와 관찰 후보 사이에서 읽기 쉽다.
        anchors=['\n⚠️ [리스크 참고','\n⛔ 제외/리스크 참고']
        for a in anchors:
            pos=s.find(a)
            if pos>=0:
                return (s[:pos].rstrip()+'\n'+block+'\n'+s[pos:].lstrip('\n')).strip()
        # 마지막 구분선 앞 삽입
        sep='\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
        pos=s.rfind(sep)
        if pos>=0:
            return (s[:pos].rstrip()+'\n'+block+s[pos:]).strip()
        return (s.rstrip()+'\n'+block).strip()
    except Exception:
        return base


def build_trade_action_summary_block_from_frames(*args, **kwargs):
    """V1103 live wrapper: 오늘 매매관점 압축에 후발/저평가 순환매 레이더를 추가."""
    try:
        base=_V1103_BASE_TODAY_ACTION_BLOCK(*args, **kwargs) if _V1103_BASE_TODAY_ACTION_BLOCK else ''
    except Exception as e:
        try:
            log_error(f'⚠️ V1103 오늘 매매관점 압축 base 생성 실패: {e}')
        except Exception:
            pass
        base=''
    try:
        rows=_v1103_collect_live_rows(args, kwargs)
        return _v1103_inject_live_radar(str(base or ''), rows)
    except Exception:
        return str(base or '')


def _v1103_group_lines(ok: pd.DataFrame, col: str, title: str, max_rows: int=8) -> list:
    try:
        if ok is None or ok.empty or col not in ok.columns:
            return []
        if '_v1097_group_lines' in globals():
            return _v1097_group_lines(ok, col, title, max_rows=max_rows, score_col='v1103_rotation_score')
        return []
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1103_examples(ok: pd.DataFrame, max_rows: int=10) -> list:
    try:
        if ok is None or ok.empty:
            return []
        tmp=ok[ok.get('v1103_is_rotation_candidate', pd.Series(['']*len(ok))).astype(str).eq('Y')].copy()
        if tmp.empty:
            return []
        tmp['_sc']=pd.to_numeric(tmp.get('v1103_rotation_score', pd.Series(dtype=float)), errors='coerce').fillna(0)
        tmp['_r5']=pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp=tmp.sort_values(['_sc','_r5'], ascending=[False,False]).head(max_rows)
        lines=['[V1103 순환매 후보 예시]']
        for _,r in tmp.iterrows():
            name=_v1103_s(r.get('name', r.get('종목명','')))
            code=_v1103_s(r.get('code', r.get('종목코드','')))
            theme=_v1103_s(r.get('v1103_rotation_theme',''))
            bucket=_v1103_s(r.get('v1103_rotation_bucket',''))
            sc=_v1103_num(r.get('v1103_rotation_score',0),0)
            r5=_v1103_num(r.get('next5_close_ret',0),0)
            r10=_v1103_num(r.get('next10_close_ret',0),0)
            reason=_v1103_s(r.get('v1103_rotation_reasons',''))
            risk=_v1103_s(r.get('v1103_rotation_risks',''))
            lines.append(f'- {name}({code}) | {bucket} | {theme} | 점수 {sc:.1f} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}%')
            if reason:
                lines.append(f'  ↳ 근거: {_v1103_clean(reason, 140)}')
            if risk:
                lines.append(f'  ↳ 주의: {_v1103_clean(risk, 110)}')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1103 순환매 후보 예시]', f'- 생성 실패: {e}', '']


def _v1103_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1103 주도섹터 후발/저평가 순환매 레이더]', '- 평가 데이터가 없습니다.', '']
        ok=eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok=_v1103_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1103 주도섹터 후발/저평가 순환매 레이더]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        cand=ok[ok.get('v1103_is_rotation_candidate', pd.Series(['']*len(ok))).astype(str).eq('Y')].copy()
        active=_v1103_active_themes()
        active_txt=', '.join([f"{x.get('grade','')}{x.get('theme','')}" for x in active[:6]]) if active else '본문없음(DIRECT_REPLAY은 테마단서 기준)'
        lines=['[V1103 주도섹터 후발/저평가 순환매 레이더]']
        lines.append('- 목적: 오늘 바로 실행 가능한 STRICT TOP과 별도로, 주도섹터 안의 후발·저평가·응축 순환매 후보를 추적합니다.')
        lines.append('- 원칙: 대장주 추격보다 덜 오른 종목의 기준선 재지지, 거래량 재유입, 수급 유지를 확인합니다.')
        lines.append(f'- 오늘 주목축: {active_txt}')
        lines.append(f'- 순환매 후보: {len(cand)}개 / 전체 OK {len(ok)}개')
        if not _v1103_context_text():
            lines.append('  ↳ 참고: DIRECT_REPLAY에서는 과거 시황본문이 없으므로, 섹터 점수는 종목 테마단서 중심으로 계산됩니다.')
        lines.append('')
        if not cand.empty:
            lines += _v1103_group_lines(cand, 'v1103_rotation_bucket', 'V1103 순환매 판정별 성과', max_rows=6)
            lines += _v1103_group_lines(cand, 'v1103_rotation_theme', 'V1103 순환매 테마별 성과', max_rows=10)
            lines += _v1103_group_lines(cand, 'v1103_market_theme_grade', 'V1103 시황테마 등급별 성과', max_rows=8)
            lines += _v1103_examples(cand, max_rows=10)
        lines.append('[V1103 적용 가이드]')
        lines.append('- 🟢 주도섹터 후발/저평가: 시황축+저평가/응축+기준선이 맞는 후보. 단, 즉시매수보다 재지지 확인')
        lines.append('- 🟡 순환매 관찰: 테마는 맞지만 수급/기준선/과열 중 일부 확인 필요')
        lines.append('- ⚪ 대기/확인: 관심 테마이나 아직 차트 실행조건 부족')
        lines.append('- 🔴 과열/제외: 이미 과열·윗꼬리·기준선 이탈이면 다음 눌림 전까지 제외')
        lines.append('- 광통신은 AI확산/데이터센터, 전선은 AI전력/전력망, 테라팹은 반도체/HBM/파운드리 안의 세부 재료로 분류합니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1103 주도섹터 후발/저평가 순환매 레이더]', f'- 생성 실패: {e}', '']


def _v1103_remove_old_blocks(report: str) -> str:
    try:
        s=str(report or '')
        markers=['[V1103 주도섹터 후발/저평가 순환매 레이더]']
        for marker in markers:
            start=s.find(marker)
            if start>=0:
                next_candidates=[]
                for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                    j=s.find(m,start+1)
                    if j>=0:
                        next_candidates.append(j)
                end=min(next_candidates) if next_candidates else len(s)
                s=(s[:start].rstrip()+'\n\n'+s[end:].lstrip('\n')).strip()
        return s
    except Exception:
        return report


def _v1103_inject_block(report: str, lines: list) -> str:
    try:
        s=_v1103_remove_old_blocks(str(report or ''))
        block='\n'.join(lines).rstrip()+'\n'
        # V1102 블록 뒤에 붙여서 공격관찰 다음에 순환매 레이더가 오도록 한다.
        anchor='[V1102 적용 가이드]'
        ai=s.find(anchor)
        if ai>=0:
            next_sec=-1
            for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                j=s.find(m, ai+1)
                if j>=0 and (next_sec<0 or j<next_sec):
                    next_sec=j
            if next_sec>=0:
                return (s[:next_sec].rstrip()+'\n\n'+block+s[next_sec:]).strip()
        positions=[s.find(m) for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]'] if s.find(m)>=0]
        if positions:
            pos=min(positions)
            return (s[:pos].rstrip()+'\n\n'+block+s[pos:]).strip()
        return (s.rstrip()+'\n\n'+block).strip()
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1103 override: V1102 리포트 뒤에 주도섹터 후발/저평가 순환매 레이더 추가."""
    try:
        report=_V1103_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1103_BASE_DIRECT_REPORT else ''
        s=str(report or '')
        for old in ['🧪 [V1102 직접 재현 주간 성과검증]','🧪 [V1101 직접 재현 주간 성과검증]','🧪 [V1100 직접 재현 주간 성과검증]','🧪 [V1099 직접 재현 주간 성과검증]']:
            s=s.replace(old, '🧪 [V1103 직접 재현 주간 성과검증]')
        if _v1103_on('V1103_BACKTEST_REPORT_BLOCK','1'):
            s=_v1103_inject_block(s, _v1103_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1103_BASE_DIRECT_REPORT:
                return _V1103_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1103 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

