def _v1104_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1104_context_status(theme: str, ctx_line: str='') -> str:
    try:
        ctx = _v1103_context_text() if '_v1103_context_text' in globals() else ''
        if not str(ctx or '').strip():
            return 'NO_CONTEXT_DIRECT_REPLAY'
        if str(ctx_line or '').strip():
            return 'CONTEXT_MATCHED'
        return 'THEME_ONLY_CONTEXT_NOT_MATCHED'
    except Exception:
        return 'NO_CONTEXT_DIRECT_REPLAY'


def _v1104_oil_down_context() -> bool:
    try:
        ctx = _v1103_context_text() if '_v1103_context_text' in globals() else ''
        low = str(ctx or '').lower()
        return ('유가' in ctx and ('하락' in ctx or '유가↓' in ctx or '↓유가' in ctx or '비용완화' in ctx)) or 'oil down' in low
    except Exception:
        return False


def _v1104_is_avoid_theme(theme: str) -> bool:
    """섹터 레이더/시황본문에서 ⛔회피로 찍힌 축은 순환매 후보에서 자동 강등한다."""
    try:
        if not _v1104_on('V1104_AVOID_SECTOR_DOWNGRADE','1'):
            return False
        ctx = _v1103_context_text() if '_v1103_context_text' in globals() else ''
        if not str(ctx or '').strip():
            return False
        # 유가하락 수혜는 조선/해운 회피와 분리한다. 유가↓/비용완화가 있으면 운송 비용완화 테마로 예외 허용.
        if theme == '항공/운송/유가하락수혜' and _v1104_oil_down_context():
            return False
        alias_map = {
            '반도체/HBM/테라팹': ['반도체'],
            'AI확산/데이터센터/광통신': ['AI확산','데이터센터','광통신','통신장비','소프트웨어/클라우드'],
            'AI전력/전력망/전선': ['AI전력/전력설비','AI전력','전력설비','전력망'],
            '로봇/자동화': ['로봇/자동화','로봇'],
            '바이오/헬스케어': ['바이오','헬스케어'],
            '2차전지/EV': ['2차전지/EV','2차전지','전기차'],
            '조선/해양플랜트': ['조선/해운','조선','해운'],
            '원전/우라늄': ['원전','우라늄'],
            '금융/밸류업': ['금융/은행','금융','은행'],
            '자동차/부품': ['자동차','자동차/부품'],
        }
        aliases = alias_map.get(theme, [theme])
        lines = [x.strip() for x in re.split(r'[\n\r]+', str(ctx)) if x.strip()]
        for line in lines:
            if '⛔' not in line and '회피' not in line:
                continue
            for a in aliases:
                if not a:
                    continue
                if (f'[{a}]' in line) or (a in line and ('⛔' in line or '회피' in line)):
                    return True
        return False
    except Exception:
        return False


def _v1104_force_bucket(res: dict, row=None) -> dict:
    try:
        out = dict(res or {})
        theme = _v1103_s(out.get('v1103_rotation_theme','미분류')) if '_v1103_s' in globals() else str(out.get('v1103_rotation_theme','미분류'))
        ctx_line = _v1103_s(out.get('v1103_context_line','')) if '_v1103_s' in globals() else str(out.get('v1103_context_line',''))
        status = _v1104_context_status(theme, ctx_line)
        avoid = _v1104_is_avoid_theme(theme)
        score = _v1103_num(out.get('v1103_rotation_score',0),0) if '_v1103_num' in globals() else float(out.get('v1103_rotation_score',0) or 0)
        risks = _v1103_s(out.get('v1103_rotation_risks','')) if '_v1103_s' in globals() else str(out.get('v1103_rotation_risks','') or '')
        reasons = _v1103_s(out.get('v1103_rotation_reasons','')) if '_v1103_s' in globals() else str(out.get('v1103_rotation_reasons','') or '')
        risk_count = 0 if not risks else len([x for x in risks.split(',') if x.strip()])

        def add_reason(txt):
            nonlocal reasons
            if txt and txt not in reasons:
                reasons = (reasons + ', ' + txt).strip(', ')
        def add_risk(txt):
            nonlocal risks
            if txt and txt not in risks:
                risks = (risks + ', ' + txt).strip(', ')

        if status == 'CONTEXT_MATCHED':
            add_reason('시황본문 직접연결')
        elif status == 'THEME_ONLY_CONTEXT_NOT_MATCHED':
            add_risk('시황본문 직접연결 없음')
        elif status == 'NO_CONTEXT_DIRECT_REPLAY':
            add_risk('본문없음/DIRECT_REPLAY')

        if avoid:
            score -= 25
            add_risk('회피섹터 자동강등')

        macro_benefit = (theme == '항공/운송/유가하락수혜' and _v1104_oil_down_context())
        if macro_benefit:
            score += 8
            add_reason('유가하락 비용완화 직접수혜')
            if status != 'CONTEXT_MATCHED':
                status = 'CONTEXT_MATCHED'

        # 핵심 게이트: 시황본문 직접연결이 없으면 🟢/🟡 승격 금지.
        if theme == '미분류':
            bucket = '🔴 과열/제외'
            action = '테마 분류 불명확. 실전 TOP 제외'
            is_cand = 'N'
        elif avoid:
            bucket = '🔴 회피섹터/강등'
            action = '섹터 레이더 회피 축입니다. 개별 재료와 기준선 재지지 전까지 제외'
            is_cand = 'N'
        elif _v1104_on('V1104_CONTEXT_REQUIRED_FOR_PROMOTION','1') and status != 'CONTEXT_MATCHED':
            if score >= 48:
                bucket = '⚪ 대기/확인'
                action = '테마단서만 확인. live 시황본문 직접연결·기준선 재지지 전까지 매수 금지'
                is_cand = 'Y'
            else:
                bucket = '🔴 과열/제외'
                action = '시황본문 직접연결도 없고 점수도 부족합니다. 관찰 제외'
                is_cand = 'N'
        else:
            if score >= 78 and risk_count <= 1:
                bucket = '🟢 시황연결 후발/저평가'
                action = '시황축+응축/저평가가 맞습니다. 그래도 기준선 재지지와 거래량 재유입 확인 후 소액'
                is_cand = 'Y'
            elif score >= 62:
                bucket = '🟡 시황연결 순환매 관찰'
                action = '시황축은 맞지만 일부 확인 필요. 눌림·재안착 확인 후 관심 상향'
                is_cand = 'Y'
            elif score >= 48:
                bucket = '⚪ 대기/확인'
                action = '시황 연결은 있으나 차트/수급 조건 부족. 기준선 확인 전 신규 보류'
                is_cand = 'Y'
            else:
                bucket = '🔴 과열/제외'
                action = '실전 TOP 제외, 다음 재지지 전까지 관찰만'
                is_cand = 'N'

        out['v1103_rotation_score'] = round(float(score), 1)
        out['v1103_rotation_bucket'] = bucket
        out['v1103_rotation_action'] = action
        out['v1103_rotation_reasons'] = reasons
        out['v1103_rotation_risks'] = risks
        out['v1103_is_rotation_candidate'] = is_cand
        out['v1104_context_status'] = status
        out['v1104_avoid_sector'] = 'Y' if avoid else 'N'
        out['v1104_context_matched'] = 'Y' if status == 'CONTEXT_MATCHED' else 'N'
        out['v1104_rotation_bucket'] = bucket
        out['v1104_rotation_score'] = round(float(score), 1)
        return out
    except Exception:
        return res


def _v1103_score_row(row) -> dict:
    """V1104 override: V1103 점수 산식 위에 시황본문/회피섹터 게이트를 적용."""
    try:
        base = _V1104_BASE_SCORE_ROW(row) if _V1104_BASE_SCORE_ROW else {}
    except Exception:
        base = {}
    return _v1104_force_bucket(base, row=row)


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1104 wrapper: 실시간 신호행에도 V1104 순환매 게이트 결과를 저장."""
    try:
        base = _V1104_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1104_BASE_SIGNAL_ROW else {}
    except Exception:
        base = {}
    try:
        tmp = dict(base or {})
        try:
            raw = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            tmp.update({k:v for k,v in raw.items() if k not in tmp})
        except Exception:
            pass
        c = _v1103_score_row(tmp)
        base.update(c)
        base['순환매테마'] = c.get('v1103_rotation_theme','')
        base['순환매점수'] = c.get('v1103_rotation_score',0)
        base['순환매판정'] = c.get('v1103_rotation_bucket','')
        base['순환매코멘트'] = _v1103_clean((c.get('v1103_rotation_reasons','')+' / '+c.get('v1103_rotation_risks','')).strip(' /'), 180)
        base['V1104컨텍스트상태'] = c.get('v1104_context_status','')
    except Exception:
        pass
    return base


def _v1103_remove_live_block(text: str) -> str:
    try:
        s = str(text or '')
        markers = ['🧭 [V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]', '🧭 [주도섹터 후발/저평가 순환매 레이더]']
        for marker in markers:
            p = s.find(marker)
            if p < 0:
                continue
            start = s.rfind('\n', 0, p)
            if start < 0:
                start = p
            nexts = []
            for m in ['\n⚠️ [리스크 참고', '\n⛔ 제외/리스크', '\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━']:
                j = s.find(m, p+1)
                if j >= 0:
                    nexts.append(j)
            end = min(nexts) if nexts else len(s)
            s = (s[:start].rstrip()+'\n'+s[end:].lstrip('\n')).strip()
        return s
    except Exception:
        return text


def _v1103_live_radar_lines(rows: list, max_rows: int=None) -> list:
    try:
        if not _v1104_on('V1104_LIVE_RADAR_BLOCK','1'):
            return []
        if max_rows is None:
            max_rows = _v1103_int('V1104_ROTATION_LIMIT', 7)
        min_score = _v1103_float('V1104_MIN_ROTATION_SCORE', 48.0)
        enriched = []
        seen = set()
        for r in rows or []:
            d = _v1103_rowdict(r)
            code = _v1103_s(_v1103_get(d,'code','종목코드','Code','ticker', default=''))
            name = _v1103_s(_v1103_get(d,'name','종목명','Name', default=''))
            if not name and not code:
                continue
            key = code or name
            if key in seen:
                continue
            seen.add(key)
            c = _v1103_score_row(d)
            sc = _v1103_num(c.get('v1103_rotation_score',0),0)
            if sc < min_score or c.get('v1103_rotation_theme') == '미분류':
                continue
            d.update(c)
            # 회피섹터/제외도 디버그 목적이 아니면 live 레이더에서 숨긴다.
            if c.get('v1103_rotation_bucket') == '🔴 회피섹터/강등' and not _v1104_on('V1104_SHOW_AVOID_IN_LIVE','0'):
                continue
            enriched.append(d)
        if not enriched:
            return []
        enriched = sorted(enriched, key=lambda x: _v1103_num(x.get('v1103_rotation_score',0),0), reverse=True)[:max_rows]
        active = _v1103_active_themes()
        active_txt = ', '.join([f"{x.get('grade','')}{x.get('theme','')}" for x in active[:6]]) if active else '시황본문 없음/테마단서 기준'
        lines = ['', '🧭 [V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]', '기준: 회피 섹터는 자동 강등하고, 시황본문 직접연결 후보만 🟢/🟡로 상향합니다.', f'오늘 주목축: {active_txt}', '']
        for i,d in enumerate(enriched, 1):
            name = _v1103_s(_v1103_get(d,'name','종목명','Name', default=''))
            code = _v1103_s(_v1103_get(d,'code','종목코드','Code', default=''))
            price = _v1103_s(_v1103_get(d,'현재가','current_price','price','Close','종가', default=''))
            theme = _v1103_s(d.get('v1103_rotation_theme',''))
            score = _v1103_num(d.get('v1103_rotation_score',0),0)
            bucket = _v1103_s(d.get('v1103_rotation_bucket',''))
            status = _v1103_s(d.get('v1104_context_status',''))
            reasons = _v1103_s(d.get('v1103_rotation_reasons',''))
            risks = _v1103_s(d.get('v1103_rotation_risks',''))
            action = _v1103_s(d.get('v1103_rotation_action',''))
            ctx = _v1103_s(d.get('v1103_context_line',''))
            line = f'{i}) {name}({code}) {bucket} | {theme} | 점수 {score:.1f} | {status}'
            if price:
                line += f' | 현재 {price}'
            lines.append(line)
            if reasons:
                lines.append(f'   🧩 {_v1103_clean(reasons, 110)}')
            if ctx:
                lines.append(f'   🔗 시황연결: {_v1103_clean(ctx, 110)}')
            if risks:
                lines.append(f'   ⚠️ {_v1103_clean(risks, 95)}')
            lines.append(f'   ✅ {_v1103_clean(action, 100)}')
        lines.append('')
        lines.append('📌 운용: 이 블록은 즉시매수 TOP이 아닙니다. 🟢/🟡도 기준선 재지지·거래량 재유입 전 추격 금지입니다.')
        return lines
    except Exception as e:
        return ['', '🧭 [V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]', f'- 생성 실패: {e}', '']


def build_trade_action_summary_block_from_frames(*args, **kwargs):
    """V1104 live wrapper: 오늘 매매관점 압축에 보수화된 순환매 레이더를 추가."""
    try:
        base = _V1104_BASE_TODAY_ACTION_BLOCK(*args, **kwargs) if _V1104_BASE_TODAY_ACTION_BLOCK else ''
    except Exception as e:
        try:
            log_error(f'⚠️ V1104 오늘 매매관점 압축 base 생성 실패: {e}')
        except Exception:
            pass
        base = ''
    try:
        rows = _v1103_collect_live_rows(args, kwargs)
        return _v1103_inject_live_radar(str(base or ''), rows)
    except Exception:
        return str(base or '')


def _v1103_examples(ok: pd.DataFrame, max_rows: int=10) -> list:
    try:
        if ok is None or ok.empty:
            return []
        tmp = ok[ok.get('v1103_is_rotation_candidate', pd.Series(['']*len(ok))).astype(str).eq('Y')].copy()
        if tmp.empty:
            return []
        tmp['_sc'] = pd.to_numeric(tmp.get('v1103_rotation_score', pd.Series(dtype=float)), errors='coerce').fillna(0)
        tmp['_r5'] = pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp = tmp.sort_values(['_sc','_r5'], ascending=[False,False]).head(max_rows)
        lines = ['[V1104 순환매 후보 예시]']
        for _,r in tmp.iterrows():
            name = _v1103_s(r.get('name', r.get('종목명','')))
            code = _v1103_s(r.get('code', r.get('종목코드','')))
            theme = _v1103_s(r.get('v1103_rotation_theme',''))
            bucket = _v1103_s(r.get('v1103_rotation_bucket',''))
            status = _v1103_s(r.get('v1104_context_status',''))
            sc = _v1103_num(r.get('v1103_rotation_score',0),0)
            r5 = _v1103_num(r.get('next5_close_ret',0),0)
            r10 = _v1103_num(r.get('next10_close_ret',0),0)
            reason = _v1103_s(r.get('v1103_rotation_reasons',''))
            risk = _v1103_s(r.get('v1103_rotation_risks',''))
            lines.append(f'- {name}({code}) | {bucket} | {theme} | {status} | 점수 {sc:.1f} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}%')
            if reason:
                lines.append(f'  ↳ 근거: {_v1103_clean(reason, 140)}')
            if risk:
                lines.append(f'  ↳ 주의: {_v1103_clean(risk, 120)}')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1104 순환매 후보 예시]', f'- 생성 실패: {e}', '']


def _v1103_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]', '- 평가 데이터가 없습니다.', '']
        ok = eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok = _v1103_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        cand = ok[ok.get('v1103_is_rotation_candidate', pd.Series(['']*len(ok))).astype(str).eq('Y')].copy()
        avoid = ok[ok.get('v1104_avoid_sector', pd.Series(['']*len(ok))).astype(str).eq('Y')].copy()
        active = _v1103_active_themes()
        active_txt = ', '.join([f"{x.get('grade','')}{x.get('theme','')}" for x in active[:6]]) if active else '본문없음(DIRECT_REPLAY은 테마단서 기준)'
        lines = ['[V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]']
        lines.append('- 목적: V1103 순환매 레이더를 실전용으로 보수화합니다.')
        lines.append('- 원칙: 회피 섹터는 자동 강등하고, 시황본문 직접연결 후보만 🟢/🟡로 상향합니다.')
        lines.append('- 테마단서만 있는 후보는 무조건 ⚪ 대기/확인으로 제한합니다.')
        lines.append(f'- 오늘 주목축: {active_txt}')
        lines.append(f'- 순환매 후보: {len(cand)}개 / 회피섹터 강등 {len(avoid)}개 / 전체 OK {len(ok)}개')
        if not _v1103_context_text():
            lines.append('  ↳ 참고: DIRECT_REPLAY에서는 과거 시황본문이 없으므로, 🟢/🟡 승격은 제한되고 ⚪ 대기/확인 중심으로만 해석합니다.')
        lines.append('')
        if not cand.empty:
            lines += _v1103_group_lines(cand, 'v1103_rotation_bucket', 'V1104 순환매 판정별 성과', max_rows=8)
            lines += _v1103_group_lines(cand, 'v1103_rotation_theme', 'V1104 순환매 테마별 성과', max_rows=10)
            lines += _v1103_group_lines(cand, 'v1104_context_status', 'V1104 컨텍스트상태별 성과', max_rows=8)
            lines += _v1103_examples(cand, max_rows=10)
        if not avoid.empty:
            lines += _v1103_group_lines(avoid, 'v1103_rotation_theme', 'V1104 회피섹터 강등 테마별 성과', max_rows=8)
        lines.append('[V1104 적용 가이드]')
        lines.append('- 🟢 시황연결 후발/저평가: 시황본문 직접연결+저평가/응축+기준선이 맞는 후보. 그래도 재지지 확인 후 소액')
        lines.append('- 🟡 시황연결 순환매 관찰: 시황축은 맞지만 차트/수급 일부 확인 필요')
        lines.append('- ⚪ 대기/확인: 테마단서만 있거나 기준선/수급 부족. 실전 매수 금지')
        lines.append('- 🔴 회피섹터/강등: 섹터 레이더 회피 축. 개별 재료와 재지지 확인 전까지 제외')
        lines.append('- 항공/운송은 유가하락·비용완화가 본문에 있을 때만 우대합니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]', f'- 생성 실패: {e}', '']


def _v1103_remove_old_blocks(report: str) -> str:
    try:
        s = str(report or '')
        markers = ['[V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]', '[V1103 주도섹터 후발/저평가 순환매 레이더]']
        for marker in markers:
            start = s.find(marker)
            if start >= 0:
                next_candidates = []
                for m in ['\n[관점/전략별]', '\n[패턴별]', '\n[추천단계별]']:
                    j = s.find(m, start+1)
                    if j >= 0:
                        next_candidates.append(j)
                end = min(next_candidates) if next_candidates else len(s)
                s = (s[:start].rstrip()+'\n\n'+s[end:].lstrip('\n')).strip()
        return s
    except Exception:
        return report


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1104 override: V1102/기존 리포트 뒤에 보수화된 순환매 레이더를 추가."""
    try:
        report = _V1104_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1104_BASE_DIRECT_REPORT else ''
        s = str(report or '')
        for old in ['🧪 [V1103 직접 재현 주간 성과검증]','🧪 [V1102 직접 재현 주간 성과검증]','🧪 [V1101 직접 재현 주간 성과검증]','🧪 [V1100 직접 재현 주간 성과검증]','🧪 [V1099 직접 재현 주간 성과검증]']:
            s = s.replace(old, '🧪 [V1104 직접 재현 주간 성과검증]')
        if _v1104_on('V1104_BACKTEST_REPORT_BLOCK','1'):
            s = _v1103_inject_block(s, _v1103_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1104_BASE_DIRECT_REPORT:
                return _V1104_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1104 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

