def _v1105_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1105_float(name: str, default: float=0.0) -> float:
    try:
        return float(os.environ.get(name, default))
    except Exception:
        return default


def _v1105_full_context() -> str:
    try:
        if '_v1103_context_text' in globals():
            return str(_v1103_context_text() or '')
    except Exception:
        pass
    return ''


def _v1105_theme_aliases(theme: str) -> list:
    amap = {
        '반도체/HBM/테라팹': ['반도체','HBM','테라팹','테라펩','파운드리','AI칩','SOXX','SMH','마이크론','엔비디아'],
        'AI확산/데이터센터/광통신': ['AI확산','데이터센터','광통신','광모듈','광케이블','CPO','실리콘포토닉스','통신장비'],
        'AI전력/전력망/전선': ['AI전력','AI전력/전력설비','전력설비','전력망','전선','변압기','전력기기'],
        '로봇/자동화': ['로봇/자동화','로봇','자동화','휴머노이드','BOTZ','ROBO'],
        '바이오/헬스케어': ['바이오','헬스케어','제약','신약','CDMO','셀트리온','삼성바이오'],
        '2차전지/EV': ['2차전지/EV','2차전지','전기차','EV','배터리','리튬','테슬라'],
        '2차전지/소재': ['2차전지','소재','양극재','음극재','전해액','포스코퓨처엠','에코프로'],
        '항공/운송/유가하락수혜': ['항공','운송','물류','항공/운송','유가하락','비용완화','대한항공','현대글로비스'],
        '금융/밸류업': ['금융/밸류업','금융','은행','증권','보험','밸류업','주주환원'],
        '금융/지주': ['금융','지주','보험','증권','은행'],
        '조선/해양플랜트': ['조선/해운','조선','해운','해양플랜트','LNG선'],
        '원전/우라늄': ['원전','우라늄','원자력'],
        '자동차/부품': ['자동차/부품','자동차','전장','부품'],
        '철강/소재': ['철강','소재','포스코'],
    }
    return amap.get(theme, [theme, str(theme).split('/')[0]])


def _v1105_context_lines_for_theme(theme: str) -> list:
    try:
        ctx = _v1105_full_context()
        if not ctx.strip():
            return []
        aliases = [a for a in _v1105_theme_aliases(theme) if a]
        lines = [x.strip(' -\t') for x in re.split(r'[\n\r]+', ctx) if str(x).strip()]
        matched = []
        for line in lines:
            low = line.lower()
            for a in aliases:
                if str(a).lower() in low:
                    matched.append(line)
                    break
        return matched[:8]
    except Exception:
        return []


def _v1105_has_full_context_conflict(theme: str) -> bool:
    """불리섹터/피할섹터/회피 문맥과 테마가 충돌하는지 확인."""
    try:
        ctx = _v1105_full_context()
        if not ctx.strip():
            return False
        aliases = _v1105_theme_aliases(theme)
        negative_headers = ['불리섹터', '피할 섹터', '피할섹터', '회피섹터', '회피 섹터', '⛔회피', '강등']
        for line in [x.strip() for x in re.split(r'[\n\r]+', ctx) if x.strip()]:
            if not any(h in line for h in negative_headers):
                continue
            for a in aliases:
                if a and a in line:
                    return True
        return False
    except Exception:
        return False


def _v1105_context_polarity(theme: str, ctx_line: str='') -> tuple:
    """시황본문 매칭이 긍정인지 부정인지 구분한다."""
    try:
        ctx = _v1105_full_context()
        if not str(ctx or '').strip():
            return 'NO_CONTEXT', '본문없음/DIRECT_REPLAY'
        lines = []
        if str(ctx_line or '').strip():
            lines.append(str(ctx_line))
        lines += _v1105_context_lines_for_theme(theme)
        text = ' / '.join(dict.fromkeys([x for x in lines if x]))[:3000]
        low = text.lower()
        full_conflict = _v1105_has_full_context_conflict(theme)

        # 테마별 강제 규칙
        if theme == '항공/운송/유가하락수혜':
            if any(x in text for x in ['유가↑','유가 상승','유가가 상승','고유가','비용 부담','비용부담']) or ('wti' in low and '+' in text):
                return 'NEGATIVE_CONTEXT', '유가상승/비용부담 문맥'
            if any(x in text for x in ['유가↓','유가 하락','유가하락','비용완화','비용 완화']):
                return 'POSITIVE_CONTEXT', '유가하락 비용완화 문맥'
        if theme in ('금융/밸류업','금융/지주'):
            if '금리 인상 우려' in text or '금리인상 우려' in text:
                return 'NEGATIVE_CONTEXT', '금리인상 우려 문맥'
        if full_conflict:
            return 'CONFLICT_CONTEXT', '불리/회피 섹터 문맥 충돌'

        pos_words = ['✅추천','추천','긍정','수혜','강세','상승','리스크온','관심','주도','모멘텀','기대','회복','확산','우대','순환매','재개발','정책 기대감','ETF +','대표주']
        neg_words = ['⛔','회피','불리','피할','주의','리스크','부담','비용 부담','비용부담','약세','하락','둔화','인상 우려','우려','불확실','추격 금지','관찰만']
        pos = sum(1 for w in pos_words if w in text)
        neg = sum(1 for w in neg_words if w in text)
        # "관찰"은 단독으로는 긍정이 아니라 중립으로 둔다.
        if neg > 0 and neg >= pos:
            return 'NEGATIVE_CONTEXT', '부정/주의 문맥 우세'
        if pos > 0 and neg == 0:
            return 'POSITIVE_CONTEXT', '긍정 문맥'
        if pos > neg:
            return 'MIXED_POSITIVE_CONTEXT', '긍정 우세 혼합 문맥'
        if text.strip():
            return 'NEUTRAL_CONTEXT', '중립/관찰 문맥'
        return 'THEME_ONLY_CONTEXT_NOT_MATCHED', '테마단서만 확인'
    except Exception as e:
        return 'UNKNOWN_CONTEXT', f'문맥판별 실패:{e}'


def _v1105_absorb_flags(row_or_dict) -> tuple:
    """V1098/V1099 매물흡수·상단매물확인·손절짧음 조건을 찾아 실전 상향 근거로 사용."""
    try:
        d = _v1103_rowdict(row_or_dict) if '_v1103_rowdict' in globals() else (dict(row_or_dict) if isinstance(row_or_dict, dict) else {})
        blob = _v1103_blob(d) if '_v1103_blob' in globals() else ' '.join(map(str, d.values()))
        flags = []
        risks = []
        if any(x in blob for x in ['매물흡수형 돌파','상단매물확인/흡수대상','상단매물확인','흡수대상']):
            flags.append('매물흡수/상단매물확인')
        if any(x in blob for x in ['손절-3~-5','손절거리 -3~-5','손절짧음','손절양호']):
            flags.append('손절짧음')
        if any(x in blob for x in ['종가강함/윗꼬리짧음','종가양호','윗꼬리짧음']):
            flags.append('캔들양호')
        if any(x in blob for x in ['거래량동반+종가강함','거래량동반(1.5~2.5x)']):
            flags.append('거래량동반')
        if any(x in blob for x in ['근접매물부담','중간매물부담','매물부담형','상단여백+손절넓음']):
            risks.append('매물부담/손절넓음')
        if any(x in blob for x in ['거래량과열+윗꼬리','윗꼬리과다','윗꼬리부담','가짜수박주의(강','가짜수박강']):
            risks.append('윗꼬리/가짜수박 부담')
        return flags, risks
    except Exception:
        return [], []


def _v1105_is_positive_context(pol: str) -> bool:
    return pol in ('POSITIVE_CONTEXT','MIXED_POSITIVE_CONTEXT')


def _v1105_force_bucket(res: dict, row=None) -> dict:
    try:
        out = dict(res or {})
        theme = _v1103_s(out.get('v1103_rotation_theme','미분류')) if '_v1103_s' in globals() else str(out.get('v1103_rotation_theme','미분류'))
        ctx_line = _v1103_s(out.get('v1103_context_line','')) if '_v1103_s' in globals() else str(out.get('v1103_context_line',''))
        pol, pol_reason = _v1105_context_polarity(theme, ctx_line)
        flags, absorb_risks = _v1105_absorb_flags(row or out)
        score = _v1103_num(out.get('v1103_rotation_score',0),0) if '_v1103_num' in globals() else float(out.get('v1103_rotation_score',0) or 0)
        reasons = _v1103_s(out.get('v1103_rotation_reasons','')) if '_v1103_s' in globals() else str(out.get('v1103_rotation_reasons','') or '')
        risks = _v1103_s(out.get('v1103_rotation_risks','')) if '_v1103_s' in globals() else str(out.get('v1103_rotation_risks','') or '')

        def add_reason(txt):
            nonlocal reasons
            if txt and txt not in reasons:
                reasons = (reasons + ', ' + txt).strip(', ')
        def add_risk(txt):
            nonlocal risks
            if txt and txt not in risks:
                risks = (risks + ', ' + txt).strip(', ')

        add_reason(pol_reason if _v1105_is_positive_context(pol) else '')
        if pol in ('NEGATIVE_CONTEXT','CONFLICT_CONTEXT'):
            add_risk(pol_reason)
        elif pol in ('NEUTRAL_CONTEXT','THEME_ONLY_CONTEXT_NOT_MATCHED','NO_CONTEXT','UNKNOWN_CONTEXT'):
            add_risk(pol_reason)

        for f in flags:
            add_reason(f)
        for r in absorb_risks:
            add_risk(r)

        if flags:
            score += _v1105_float('V1105_ABSORB_PRIORITY_BONUS', 10.0)
        if absorb_risks:
            score -= 8
        if pol in ('NEGATIVE_CONTEXT','CONFLICT_CONTEXT') and _v1105_on('V1105_NEGATIVE_CONTEXT_DOWNGRADE','1'):
            score -= 30
        elif pol in ('NEUTRAL_CONTEXT','THEME_ONLY_CONTEXT_NOT_MATCHED','NO_CONTEXT'):
            score -= 8

        has_absorb = any(f in flags for f in ['매물흡수/상단매물확인','손절짧음','캔들양호'])
        positive = _v1105_is_positive_context(pol)
        risk_count = 0 if not risks else len([x for x in str(risks).split(',') if x.strip()])

        if theme == '미분류':
            bucket = '🔴 과열/제외'
            action = '테마 분류 불명확. 실전 TOP 제외'
            is_cand = 'N'
        elif pol in ('NEGATIVE_CONTEXT','CONFLICT_CONTEXT') and _v1105_on('V1105_NEGATIVE_CONTEXT_DOWNGRADE','1'):
            bucket = '🔴 부정문맥/강등'
            action = '시황본문에 등장했지만 부정·충돌 문맥입니다. 우대하지 말고 관찰/제외합니다.'
            is_cand = 'N'
        elif _v1105_on('V1105_CONTEXT_REQUIRED_FOR_PROMOTION','1') and not positive:
            bucket = '⚪ 대기/확인'
            action = '긍정 시황문맥이 아니므로 매수 금지. 기준선 재지지와 실제 수급 확인 전까지 관찰만 합니다.'
            is_cand = 'Y' if score >= 40 else 'N'
        else:
            green_ok = (score >= 82 and risk_count <= 2 and (has_absorb or not _v1105_on('V1105_REQUIRE_ABSORB_FOR_GREEN','1')))
            if green_ok:
                bucket = '🟢 시황긍정+매물흡수 후발'
                action = '긍정 시황문맥과 매물흡수/손절 근거가 같이 있습니다. 그래도 기준선 재지지 후 소액만 접근합니다.'
                is_cand = 'Y'
            elif score >= 64:
                bucket = '🟡 시황긍정 순환매 관찰'
                action = '시황축은 긍정이지만 매물흡수·수급·기준선 추가 확인이 필요합니다.'
                is_cand = 'Y'
            elif score >= 48:
                bucket = '⚪ 대기/확인'
                action = '시황은 맞지만 차트 품질 또는 기준선 조건이 부족합니다. 신규 매수 금지.'
                is_cand = 'Y'
            else:
                bucket = '🔴 과열/제외'
                action = '점수와 품질이 부족합니다. 실전 TOP 제외.'
                is_cand = 'N'

        out['v1103_rotation_score'] = round(float(score), 1)
        out['v1103_rotation_bucket'] = bucket
        out['v1103_rotation_action'] = action
        out['v1103_rotation_reasons'] = reasons
        out['v1103_rotation_risks'] = risks
        out['v1103_is_rotation_candidate'] = is_cand
        out['v1105_context_polarity'] = pol
        out['v1105_context_reason'] = pol_reason
        out['v1105_absorb_flags'] = ', '.join(flags)
        out['v1105_absorb_risks'] = ', '.join(absorb_risks)
        out['v1105_rotation_bucket'] = bucket
        out['v1105_rotation_score'] = round(float(score), 1)
        # 호환 컬럼
        out['v1104_context_status'] = pol
        out['v1104_context_matched'] = 'Y' if positive else 'N'
        return out
    except Exception:
        return res


def _v1103_score_row(row) -> dict:
    """V1105 override: V1104 점수 위에 긍/부정 문맥 + 매물흡수 우선 게이트 적용."""
    try:
        base = _V1105_BASE_SCORE_ROW(row) if _V1105_BASE_SCORE_ROW else {}
    except Exception:
        base = {}
    return _v1105_force_bucket(base, row=row)


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1105 wrapper: 실시간 신호행에도 V1105 문맥/매물흡수 결과 저장."""
    try:
        base = _V1105_BASE_SIGNAL_ROW(row, rank=rank, source=source) if _V1105_BASE_SIGNAL_ROW else {}
    except Exception:
        base = {}
    try:
        tmp = dict(base or {})
        try:
            raw = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            tmp.update({k:v for k,v in raw.items() if k not in tmp})
        except Exception:
            pass
        c = _v1103_score_row(tmp)
        base.update(c)
        base['순환매테마'] = c.get('v1103_rotation_theme','')
        base['순환매점수'] = c.get('v1103_rotation_score',0)
        base['순환매판정'] = c.get('v1103_rotation_bucket','')
        base['순환매코멘트'] = _v1103_clean((c.get('v1103_rotation_reasons','')+' / '+c.get('v1103_rotation_risks','')).strip(' /'), 180)
        base['V1105문맥'] = c.get('v1105_context_polarity','')
        base['V1105매물흡수'] = c.get('v1105_absorb_flags','')
    except Exception:
        pass
    return base


def _v1105_remove_live_blocks(text: str) -> str:
    try:
        s=str(text or '')
        markers=['🧭 [V1105 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', '🧭 [V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]', '🧭 [주도섹터 후발/저평가 순환매 레이더]']
        for marker in markers:
            p=s.find(marker)
            if p<0:
                continue
            start=s.rfind('\n',0,p)
            if start<0:
                start=p
            nexts=[]
            for m in ['\n⚠️ [리스크 참고','\n⛔ 제외/리스크','\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━']:
                j=s.find(m,p+1)
                if j>=0:
                    nexts.append(j)
            end=min(nexts) if nexts else len(s)
            s=(s[:start].rstrip()+'\n'+s[end:].lstrip('\n')).strip()
        return s
    except Exception:
        return text


def _v1105_live_radar_lines(rows: list, max_rows: int=None) -> list:
    try:
        if not _v1105_on('V1105_LIVE_RADAR_BLOCK','1'):
            return []
        if max_rows is None:
            max_rows = _v1103_int('V1105_ROTATION_LIMIT', 7) if '_v1103_int' in globals() else 7
        min_score = _v1103_float('V1105_MIN_ROTATION_SCORE', 48.0) if '_v1103_float' in globals() else 48.0
        enriched=[]; seen=set(); downgraded=[]
        for r in rows or []:
            d=_v1103_rowdict(r) if '_v1103_rowdict' in globals() else (dict(r) if isinstance(r,dict) else {})
            code=_v1103_s(_v1103_get(d,'code','종목코드','Code','ticker', default='')) if '_v1103_get' in globals() else str(d.get('code',''))
            name=_v1103_s(_v1103_get(d,'name','종목명','Name', default='')) if '_v1103_get' in globals() else str(d.get('name',''))
            if not name and not code:
                continue
            key=code or name
            if key in seen:
                continue
            seen.add(key)
            c=_v1103_score_row(d)
            sc=_v1103_num(c.get('v1103_rotation_score',0),0) if '_v1103_num' in globals() else 0
            if c.get('v1103_rotation_theme') == '미분류':
                continue
            d.update(c)
            if c.get('v1103_rotation_bucket') in ('🔴 부정문맥/강등','🔴 과열/제외','🔴 회피섹터/강등'):
                downgraded.append(d)
                if not _v1105_on('V1105_SHOW_DOWNGRADE_IN_LIVE','0'):
                    continue
            if sc < min_score:
                continue
            enriched.append(d)
        if not enriched and not downgraded:
            return []
        enriched=sorted(enriched, key=lambda x: _v1103_num(x.get('v1103_rotation_score',0),0), reverse=True)[:max_rows]
        active=_v1103_active_themes() if '_v1103_active_themes' in globals() else []
        active_txt=', '.join([f"{x.get('grade','')}{x.get('theme','')}" for x in active[:6]]) if active else '시황본문 없음/테마단서 기준'
        lines=['', '🧭 [V1105 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', '기준: 시황본문에 등장해도 긍정 문맥만 상향합니다. 부정/비용부담/불리섹터 충돌은 자동 강등합니다.', f'오늘 주목축: {active_txt}', '']
        for i,d in enumerate(enriched,1):
            name=_v1103_s(_v1103_get(d,'name','종목명','Name', default=''))
            code=_v1103_s(_v1103_get(d,'code','종목코드','Code', default=''))
            price=_v1103_s(_v1103_get(d,'현재가','current_price','price','Close','종가', default=''))
            theme=_v1103_s(d.get('v1103_rotation_theme',''))
            score=_v1103_num(d.get('v1103_rotation_score',0),0)
            bucket=_v1103_s(d.get('v1103_rotation_bucket',''))
            pol=_v1103_s(d.get('v1105_context_polarity',''))
            flags=_v1103_s(d.get('v1105_absorb_flags',''))
            reasons=_v1103_s(d.get('v1103_rotation_reasons',''))
            risks=_v1103_s(d.get('v1103_rotation_risks',''))
            action=_v1103_s(d.get('v1103_rotation_action',''))
            ctx=_v1103_s(d.get('v1103_context_line',''))
            line=f'{i}) {name}({code}) {bucket} | {theme} | 점수 {score:.1f} | {pol}'
            if flags:
                line += f' | 흡수:{flags}'
            if price:
                line += f' | 현재 {price}'
            lines.append(line)
            if reasons:
                lines.append(f'   🧩 {_v1103_clean(reasons, 110)}')
            if ctx:
                lines.append(f'   🔗 시황연결: {_v1103_clean(ctx, 110)}')
            if risks:
                lines.append(f'   ⚠️ {_v1103_clean(risks, 100)}')
            lines.append(f'   ✅ {_v1103_clean(action, 105)}')
        if downgraded:
            # 부정문맥 후보는 과도한 추격을 막기 위해 개수만 알려준다.
            sample=[]
            for d in sorted(downgraded, key=lambda x: _v1103_num(x.get('v1103_rotation_score',0),0), reverse=True)[:3]:
                nm=_v1103_s(_v1103_get(d,'name','종목명','Name', default=''))
                th=_v1103_s(d.get('v1103_rotation_theme',''))
                pr=_v1103_s(d.get('v1105_context_reason',''))
                if nm:
                    sample.append(f'{nm}/{th}/{pr}')
            if sample:
                lines.append(f'   🔻 부정문맥·충돌 강등 {len(downgraded)}개: '+ ' | '.join(sample))
        lines.append('')
        lines.append('📌 운용: 🟢도 즉시매수 신호가 아닙니다. 긍정문맥 + 매물흡수 + 기준선 재지지 + 거래량 재유입이 함께 확인될 때만 소액 대응합니다.')
        return lines
    except Exception as e:
        return ['', '🧭 [V1105 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', f'- 생성 실패: {e}', '']


def _v1105_inject_live_radar(base: str, rows: list) -> str:
    try:
        s=_v1105_remove_live_blocks(str(base or ''))
        lines=_v1105_live_radar_lines(rows)
        if not lines:
            return s
        block='\n'.join(lines).rstrip()+'\n'
        anchors=['\n⚠️ [리스크 참고','\n⛔ 제외/리스크','\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━']
        poss=[s.find(a) for a in anchors if s.find(a)>=0]
        if poss:
            p=min(poss)
            return (s[:p].rstrip()+'\n'+block+s[p:]).strip()
        return (s.rstrip()+'\n'+block).strip()
    except Exception:
        return base


def build_trade_action_summary_block_from_frames(*args, **kwargs):
    """V1105 live wrapper: 오늘 매매관점 압축에 긍/부정 문맥 + 매물흡수 우선 레이더 추가."""
    try:
        base=_V1105_BASE_TODAY_ACTION_BLOCK(*args, **kwargs) if _V1105_BASE_TODAY_ACTION_BLOCK else ''
    except Exception as e:
        try: log_error(f'⚠️ V1105 오늘 매매관점 압축 base 생성 실패: {e}')
        except Exception: pass
        base=''
    try:
        rows=_v1103_collect_live_rows(args, kwargs) if '_v1103_collect_live_rows' in globals() else []
        return _v1105_inject_live_radar(str(base or ''), rows)
    except Exception:
        return str(base or '')


def _v1105_remove_old_blocks(report: str) -> str:
    try:
        s=str(report or '')
        markers=['[V1105 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', '[V1104 회피섹터 자동강등 + 시황연결 순환매 레이더]', '[V1103 주도섹터 후발/저평가 순환매 레이더]']
        for marker in markers:
            start=s.find(marker)
            if start>=0:
                next_candidates=[]
                for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]']:
                    j=s.find(m,start+1)
                    if j>=0:
                        next_candidates.append(j)
                end=min(next_candidates) if next_candidates else len(s)
                s=(s[:start].rstrip()+'\n\n'+s[end:].lstrip('\n')).strip()
        return s
    except Exception:
        return report


def _v1105_inject_block(report: str, lines: list) -> str:
    try:
        s=_v1105_remove_old_blocks(str(report or ''))
        block='\n'.join(lines).rstrip()+'\n'
        positions=[s.find(m) for m in ['\n[관점/전략별]','\n[패턴별]','\n[추천단계별]'] if s.find(m)>=0]
        if positions:
            pos=min(positions)
            return (s[:pos].rstrip()+'\n\n'+block+s[pos:]).strip()
        return (s.rstrip()+'\n\n'+block).strip()
    except Exception:
        return report


def _v1105_examples(ok: pd.DataFrame, max_rows: int=10) -> list:
    try:
        if ok is None or ok.empty:
            return []
        tmp=ok[ok.get('v1103_is_rotation_candidate', pd.Series(['']*len(ok))).astype(str).eq('Y')].copy()
        if tmp.empty:
            return []
        tmp['_sc']=pd.to_numeric(tmp.get('v1103_rotation_score', pd.Series(dtype=float)), errors='coerce').fillna(0)
        tmp['_r5']=pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp=tmp.sort_values(['_sc','_r5'], ascending=[False,False]).head(max_rows)
        lines=['[V1105 순환매 후보 예시]']
        for _,r in tmp.iterrows():
            name=_v1103_s(r.get('name', r.get('종목명','')))
            code=_v1103_s(r.get('code', r.get('종목코드','')))
            theme=_v1103_s(r.get('v1103_rotation_theme',''))
            bucket=_v1103_s(r.get('v1103_rotation_bucket',''))
            pol=_v1103_s(r.get('v1105_context_polarity',''))
            flags=_v1103_s(r.get('v1105_absorb_flags',''))
            sc=_v1103_num(r.get('v1103_rotation_score',0),0)
            r5=_v1103_num(r.get('next5_close_ret',0),0)
            r10=_v1103_num(r.get('next10_close_ret',0),0)
            reason=_v1103_s(r.get('v1103_rotation_reasons',''))
            risk=_v1103_s(r.get('v1103_rotation_risks',''))
            lines.append(f'- {name}({code}) | {bucket} | {theme} | {pol} | 흡수:{flags or "-"} | 점수 {sc:.1f} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}%')
            if reason:
                lines.append(f'  ↳ 근거: {_v1103_clean(reason, 140)}')
            if risk:
                lines.append(f'  ↳ 주의: {_v1103_clean(risk, 120)}')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1105 순환매 후보 예시]', f'- 생성 실패: {e}', '']


def _v1103_lines(eval_df: pd.DataFrame) -> list:
    try:
        if eval_df is None or eval_df.empty:
            return ['[V1105 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', '- 평가 데이터가 없습니다.', '']
        ok=eval_df[eval_df.get('eval_status','') == 'OK'].copy() if 'eval_status' in eval_df.columns else eval_df.copy()
        ok=_v1103_enrich_eval(ok)
        if ok is None or ok.empty:
            return ['[V1105 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', '- 평가 가능한 OK 데이터가 없습니다.', '']
        cand=ok[ok.get('v1103_is_rotation_candidate', pd.Series(['']*len(ok))).astype(str).eq('Y')].copy()
        down=ok[ok.get('v1103_rotation_bucket', pd.Series(['']*len(ok))).astype(str).isin(['🔴 부정문맥/강등','🔴 회피섹터/강등'])].copy()
        active=_v1103_active_themes() if '_v1103_active_themes' in globals() else []
        active_txt=', '.join([f"{x.get('grade','')}{x.get('theme','')}" for x in active[:6]]) if active else '본문없음(DIRECT_REPLAY은 테마단서 기준)'
        lines=['[V1105 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]']
        lines.append('- 목적: V1104의 시황본문 직접연결을 긍정/부정/충돌 문맥으로 분리합니다.')
        lines.append('- 원칙: 긍정 문맥 + 매물흡수/상단매물확인/손절짧음이 붙을 때만 실전 상향합니다.')
        lines.append('- 부정 문맥, 불리섹터 충돌, 항공의 유가상승 비용부담 문맥은 자동 강등합니다.')
        lines.append(f'- 오늘 주목축: {active_txt}')
        lines.append(f'- 순환매 후보: {len(cand)}개 / 부정문맥·충돌 강등 {len(down)}개 / 전체 OK {len(ok)}개')
        if not _v1103_context_text():
            lines.append('  ↳ 참고: DIRECT_REPLAY에서는 과거 시황본문이 없어 긍정/부정 문맥 검증이 제한됩니다. live CONTEXT_MATCHED 결과를 우선 봅니다.')
        lines.append('')
        if not cand.empty:
            lines += _v1103_group_lines(cand, 'v1103_rotation_bucket', 'V1105 순환매 판정별 성과', max_rows=8)
            lines += _v1103_group_lines(cand, 'v1105_context_polarity', 'V1105 문맥판정별 성과', max_rows=8)
            lines += _v1103_group_lines(cand, 'v1103_rotation_theme', 'V1105 순환매 테마별 성과', max_rows=10)
            lines += _v1105_examples(cand, max_rows=10)
        if not down.empty:
            lines += _v1103_group_lines(down, 'v1103_rotation_theme', 'V1105 부정문맥 강등 테마별 성과', max_rows=8)
        lines.append('[V1105 적용 가이드]')
        lines.append('- 🟢 시황긍정+매물흡수 후발: 긍정 문맥과 매물흡수/상단매물확인/손절짧음이 함께 있는 후보. 그래도 기준선 재지지 후 소액')
        lines.append('- 🟡 시황긍정 순환매 관찰: 시황은 긍정이나 차트 품질·수급·기준선 확인이 더 필요')
        lines.append('- ⚪ 대기/확인: 긍정 문맥이 없거나 테마단서만 있음. 실전 매수 금지')
        lines.append('- 🔴 부정문맥/강등: 시황본문에 나오더라도 비용부담·불리섹터·금리우려 등 부정 문맥이면 우대 금지')
        lines.append('- 실제 매수 우선순위는 시황보다 매물흡수형 돌파, 상단매물확인, 손절 -3~-5%, 기준선 재지지입니다.')
        lines.append('')
        return lines
    except Exception as e:
        return ['[V1105 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', f'- 생성 실패: {e}', '']


def _v1081_build_direct_report(eval_df: pd.DataFrame, weeks: int, replay_dates: list, raw_count: int, universe_count: int) -> str:
    """V1105 override: V1104 리포트 뒤의 레이더를 V1105 문맥/매물흡수 레이더로 교체."""
    try:
        report=_V1105_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count) if _V1105_BASE_DIRECT_REPORT else ''
        s=str(report or '')
        for old in ['🧪 [V1104 직접 재현 주간 성과검증]','🧪 [V1103 직접 재현 주간 성과검증]','🧪 [V1102 직접 재현 주간 성과검증]','🧪 [V1101 직접 재현 주간 성과검증]','🧪 [V1100 직접 재현 주간 성과검증]']:
            s=s.replace(old, '🧪 [V1105 직접 재현 주간 성과검증]')
        if _v1105_on('V1105_BACKTEST_REPORT_BLOCK','1'):
            s=_v1105_inject_block(s, _v1103_lines(eval_df))
        return s
    except Exception as e:
        try:
            if _V1105_BASE_DIRECT_REPORT:
                return _V1105_BASE_DIRECT_REPORT(eval_df, weeks=weeks, replay_dates=replay_dates, raw_count=raw_count, universe_count=universe_count)
        except Exception:
            pass
        return f'🧪 [V1105 직접 재현 주간 성과검증]\n- 리포트 생성 실패: {e}'

