def _v1103_detect_row_theme(row) -> tuple:
    try:
        d = _v1103_rowdict(row) if '_v1103_rowdict' in globals() else (dict(row) if isinstance(row, dict) else {})
        blob = _v1103_blob(d) if '_v1103_blob' in globals() else ' '.join(str(v) for v in d.values())
        low = str(blob or '').lower()
        # 항공사/물류와 우주항공은 완전히 다른 운용축이다.
        if any(k in blob for k in ['한국항공우주','AP위성','쎄트렉아이','인텔리안테크','한화에어로','LIG넥스원','스페이스X','우주항공','발사체','위성']):
            return '우주항공/방산', '우주항공'
        if any(k in blob for k in ['대한항공','진에어','제주항공','아시아나','현대글로비스','CJ대한통운','팬오션','HMM']) and not any(k in blob for k in ['우주항공','위성','발사체','방산']):
            return '항공/운송/유가하락수혜', '항공/운송'
        if _V1106_1_BASE_DETECT_ROW_THEME:
            return _V1106_1_BASE_DETECT_ROW_THEME(row)
    except Exception:
        pass
    return ('미분류','')


def _v1103_context_line_for_theme(theme: str) -> str:
    try:
        ctx = _v1106_1_context_text()
        if not ctx:
            return ''
        lines = [x.strip(' -\t') for x in re.split(r'[\n\r]+', ctx) if x.strip()]
        th = str(theme or '')
        # 레이더 순위 라인이 있으면 해당 섹터명 우선 매칭
        aliases = [th, th.split('/')[0]]
        if th == '금융/밸류업':
            aliases += ['금융/은행','은행','밸류업','주주환원']
        elif th == 'AI전력/전력망/전선':
            aliases += ['AI전력/전력설비','전력설비','전력망','전선']
        elif th == '반도체/HBM/테라팹':
            aliases += ['반도체','HBM']
        elif th == '항공/운송/유가하락수혜':
            # 우주항공 문맥은 제외하고 유가/운송 문맥만 연결
            aliases = ['유가하락','비용완화','운송','물류','해운']
        elif th == '우주항공/방산':
            aliases = ['우주항공','스페이스X','위성','발사체','방산']
        for line in lines:
            if th == '항공/운송/유가하락수혜' and any(x in line for x in ['우주항공','스페이스X','위성','발사체']):
                continue
            if any(str(a).lower() in line.lower() for a in aliases if str(a).strip()):
                return _v1106_1_clean(line, 130)
        if _V1106_1_BASE_CONTEXT_LINE_FOR_THEME:
            return _V1106_1_BASE_CONTEXT_LINE_FOR_THEME(theme)
    except Exception:
        pass
    return ''


def _v1106_1_active_axis_text(limit: int=6) -> str:
    try:
        active = _v1103_active_themes() if '_v1103_active_themes' in globals() else []
        if not active:
            return '시황 레이더 미확인/테마단서 기준'
        return ', '.join([f"{x.get('grade','')}{x.get('theme','')}" for x in active[:limit]])
    except Exception:
        return '시황 레이더 미확인/테마단서 기준'


def _v1106_1_split_context_rows(rows: list) -> tuple:
    neg, mixed, pos = [], [], []
    try:
        for d in rows or []:
            pol = str(d.get('v1105_context_polarity','') or '')
            bucket = str(d.get('v1103_rotation_bucket','') or d.get('v1105_rotation_bucket','') or '')
            if pol in ('NEGATIVE_CONTEXT','CONFLICT_CONTEXT') or '부정문맥' in bucket or '회피섹터' in bucket:
                neg.append(d)
            elif pol in ('MIXED_POSITIVE_CONTEXT','NEUTRAL_CONTEXT','THEME_ONLY_CONTEXT_NOT_MATCHED','NO_CONTEXT','UNKNOWN_CONTEXT'):
                mixed.append(d)
            elif pol == 'POSITIVE_CONTEXT':
                pos.append(d)
    except Exception:
        pass
    return neg, mixed, pos


def _v1106_1_context_sample(items: list, n: int=5) -> str:
    out = []
    try:
        def score(x):
            try: return float(str(x.get('v1103_rotation_score',0)).replace(',',''))
            except Exception: return 0.0
        for d in sorted(items or [], key=score, reverse=True)[:n]:
            nm = _v1103_s(_v1103_get(d,'name','종목명','Name', default='')) if '_v1103_get' in globals() else str(d.get('name') or d.get('종목명') or '')
            th = str(d.get('v1103_rotation_theme','') or '')
            pr = str(d.get('v1105_context_reason','') or d.get('v1105_context_polarity','') or '')
            if nm:
                out.append(f'{nm}/{th}/{pr}')
    except Exception:
        pass
    return ' | '.join(out)


def _v1105_live_radar_lines(rows: list, max_rows: int=None) -> list:
    """V1106.1 override: V1105 레이더 출력 문구를 실제 운용 기준으로 정리."""
    try:
        if not _v1105_on('V1105_LIVE_RADAR_BLOCK','1'):
            return []
        if max_rows is None:
            max_rows = _v1103_int('V1105_ROTATION_LIMIT', 7) if '_v1103_int' in globals() else 7
        min_score = _v1103_float('V1105_MIN_ROTATION_SCORE', 48.0) if '_v1103_float' in globals() else 48.0
        enriched=[]; seen=set(); all_scored=[]
        for r in rows or []:
            d = _v1103_rowdict(r) if '_v1103_rowdict' in globals() else (dict(r) if isinstance(r,dict) else {})
            code = _v1103_s(_v1103_get(d,'code','종목코드','Code','ticker', default='')) if '_v1103_get' in globals() else str(d.get('code',''))
            name = _v1103_s(_v1103_get(d,'name','종목명','Name', default='')) if '_v1103_get' in globals() else str(d.get('name',''))
            if not name and not code:
                continue
            key = code or name
            if key in seen:
                continue
            seen.add(key)
            c = _v1103_score_row(d)
            sc = _v1103_num(c.get('v1103_rotation_score',0),0) if '_v1103_num' in globals() else 0
            if c.get('v1103_rotation_theme') == '미분류':
                continue
            d.update(c)
            all_scored.append(d)
            if c.get('v1103_rotation_bucket') in ('🔴 부정문맥/강등','🔴 과열/제외','🔴 회피섹터/강등'):
                continue
            if sc < min_score:
                continue
            enriched.append(d)
        if not enriched and not all_scored:
            return []
        enriched = sorted(enriched, key=lambda x: _v1103_num(x.get('v1103_rotation_score',0),0), reverse=True)[:max_rows]
        neg, mixed, pos = _v1106_1_split_context_rows(all_scored)
        lines = ['', '🧭 [V1106.1 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', '기준: 실제 섹터 레이더 순위와 긍정 문맥이 맞는 후보만 상향합니다. 부정/혼합/긍정 문맥은 분리 표시합니다.', f'오늘 주목축: {_v1106_1_active_axis_text()}', '']
        for i,d in enumerate(enriched,1):
            name = _v1103_s(_v1103_get(d,'name','종목명','Name', default=''))
            code = _v1103_s(_v1103_get(d,'code','종목코드','Code', default=''))
            price = _v1103_s(_v1103_get(d,'현재가','current_price','price','Close','종가', default=''))
            theme = _v1103_s(d.get('v1103_rotation_theme',''))
            score = _v1103_num(d.get('v1103_rotation_score',0),0)
            bucket = _v1103_s(d.get('v1103_rotation_bucket',''))
            pol = _v1103_s(d.get('v1105_context_polarity',''))
            flags = _v1103_s(d.get('v1105_absorb_flags',''))
            reasons = _v1103_s(d.get('v1103_rotation_reasons',''))
            risks = _v1103_s(d.get('v1103_rotation_risks',''))
            action = _v1103_s(d.get('v1103_rotation_action',''))
            ctx = _v1103_s(d.get('v1103_context_line',''))
            line = f'{i}) {name}({code}) {bucket} | {theme} | 점수 {score:.1f} | {pol}'
            if flags:
                line += f' | 흡수:{flags}'
            if price:
                line += f' | 현재 {price}'
            lines.append(line)
            if reasons:
                lines.append(f'   🧩 {_v1106_1_clean(reasons, 110)}')
            if ctx:
                lines.append(f'   🔗 시황연결: {_v1106_1_clean(ctx, 110)}')
            if risks:
                lines.append(f'   ⚠️ {_v1106_1_clean(risks, 100)}')
            lines.append(f'   ✅ {_v1106_1_clean(action, 105)}')
        if neg or mixed or pos:
            lines.append('')
            lines.append('🧭 [시황 문맥 필터 결과 — V1106.1 분리]')
            if neg:
                lines.append(f'🔻 부정문맥 강등 {len(neg)}개: {_v1106_1_context_sample(neg, 4)}')
            if mixed:
                lines.append(f'⚪ 혼합문맥 보류 {len(mixed)}개: {_v1106_1_context_sample(mixed, 4)}')
            if pos:
                lines.append(f'🟡 긍정문맥 관찰 {len(pos)}개: {_v1106_1_context_sample(pos, 4)}')
        lines.append('')
        lines.append('📌 운용: 🟢도 즉시매수 신호가 아닙니다. 긍정문맥 + 매물흡수 + 기준선 재지지 + 거래량 재유입이 함께 확인될 때만 소액 대응합니다.')
        return lines
    except Exception as e:
        return ['', '🧭 [V1106.1 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', f'- 생성 실패: {e}', '']


def _v1106_1_cleanup_output_text(message: str) -> str:
    """최종 텔레그램 문구 안전망. 계산값은 바꾸지 않고 혼동 라벨만 정리한다."""
    try:
        s = str(message or '')
        if not s:
            return s
        # 버전 표기 보강
        s = s.replace('📌 V1092: TOP15 생성단계 하드게이트 / 과열·실행보류 강등', '📌 V1106.1: 실제 섹터 주목축 자동생성 / 문맥 분리 / 실행보류 라벨 정리')
        s = s.replace('📌 우선순위: 🟢 실행가능+응축 → 🟢 핵심스윙 → 🟡 눌림/회복확인 → 🟢 응축관찰·🔴 실행보류 → 🔴 과열보류', '📌 우선순위: 🟢 실행가능+응축 → 🟢 핵심스윙 → 🟡 눌림/회복확인 → ⚪ 구조관찰/실행제외 → 🔴 과열보류')
        s = s.replace('📌 V1094: STRICT 실전 TOP / 실행보류·과열보류 NO-BACKFILL', '📌 V1106.1: STRICT 실전 TOP / 실행제외·과열보류 NO-BACKFILL')
        s = s.replace('진입금지·실행보류는 TOP에서 제외', '진입금지·실행제외는 TOP에서 제외')
        s = s.replace('실행보류·진입금지 후보는 TOP에서 제외', '실행제외·진입금지 후보는 TOP에서 제외')
        # 레이더 제목이 아직 V1105로 남으면 V1106.1로 보정
        s = s.replace('🧭 [V1105 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]', '🧭 [V1106.1 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]')
        # 고정 주목축 안전 교체: 실제 순위 파싱이 가능한 경우만 교체
        axis = _v1106_1_active_axis_text()
        if axis and '시황 레이더 미확인' not in axis:
            s = re.sub(r'오늘 주목축:\s*[^\n]+', '오늘 주목축: ' + axis, s, count=1)
            s = re.sub(r'- 오늘 주목축:\s*[^\n]+', '- 오늘 주목축: ' + axis, s)
        # 한 줄로 뭉친 부정문맥 리스트는 최소한 분리표 제목으로 바꿔 혼동을 줄인다.
        s = re.sub(r'\n\s*🔻 부정문맥·충돌 강등 ([0-9]+)개:', r'\n🧭 [시황 문맥 필터 결과 — V1106.1 분리]\n🔻 부정문맥 강등 \1개:', s)
        s = s.replace('부정문맥·충돌 강등', '부정문맥 강등')
        # STRICT/관찰 라벨 정리
        s = s.replace('응축관찰·실행보류·비중축소', '응축관찰·실행제외·비중축소')
        s = s.replace('확인필요·실행보류·비중축소', '확인필요·실행제외·비중축소')
        s = s.replace('실행보류·비중축소', '실행제외·비중축소')
        s = s.replace('실행보류·손절양호', '눌림확인·손절양호')
        s = s.replace('실행보류', '실행제외')
        # 분할진입 후보의 빨간 라벨 모순 보정
        s = re.sub(r'(\d+\)\s+[^\n]+?)\s+🔴\s+확인필요·소액가능·손절양호', r'\1 🟢 소액분할·기준선확인·손절양호', s)
        return s
    except Exception:
        return message


