        s = re.sub(r'(현대글로비스\([^\n]+?\|\s*항공/운송/유가하락수혜[\s\S]*?\n\s*🔗 시황연결:)\s*5위 \[조선/해운\] ⛔회피 \| 점수 -?\d+(?:\.\d+)?', r'\1 유가↓ 비용완화 수혜: 항공/운송은 조선/해운 회피와 분리해 기준선 재지지만 관찰', s, count=1)
