def _v1106_3_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1106_3_clean_list(items, limit=8):
    out=[]
    for x in items or []:
        x=str(x or '').strip()
        if x and x not in out:
            out.append(x)
    return out[:limit]


def _v1106_3_parse_radar_status(s: str) -> dict:
    """현재 텔레그램 본문에서 섹터 순환 레이더의 추천/관찰/회피 상태를 파싱한다."""
    rec=[]; watch=[]; avoid=[]; score={}
    try:
        for line in str(s or '').splitlines():
            m = re.search(r'(\d+)위\s*\[([^\]]+)\]\s*([^|\n]+?)\s*\|\s*점수\s*(-?\d+(?:\.\d+)?)', line)
            if not m:
                continue
            theme = re.sub(r'\s+', ' ', m.group(2)).strip()
            badge = m.group(3).strip()
            val = float(m.group(4))
            score[theme]=val
            if ('⛔' in badge) or ('회피' in badge) or val < 0:
                avoid.append(theme)
            elif ('✅' in badge) or ('추천' in badge):
                rec.append(theme)
            elif ('👀' in badge) or ('관찰' in badge):
                watch.append(theme)
            elif val > 0:
                watch.append(theme)
    except Exception:
        pass
    return {'recommend': _v1106_3_clean_list(rec), 'watch': _v1106_3_clean_list(watch), 'avoid': _v1106_3_clean_list(avoid), 'score': score}


def _v1106_3_join(items, empty='해당 없음'):
    arr=_v1106_3_clean_list(items)
    return ', '.join(arr) if arr else empty


def _v1106_3_oil_down_text(s: str) -> bool:
    try:
        t=str(s or '')
        return ('유가↓' in t) or ('↓유가' in t) or bool(re.search(r'WTI유가:\s*[^\n]*\(-', t)) or ('유가 하락' in t) or ('유가가 하락' in t)
    except Exception:
        return False


def _v1106_3_rewrite_sector_strategy_blocks(s: str) -> str:
    try:
        st = _v1106_3_parse_radar_status(s)
        rec, watch, avoid = st['recommend'], st['watch'], st['avoid']
        # 시장 통합 브리핑의 유리/관찰/불리 섹터를 레이더 기준으로 재정렬
        if rec or watch or avoid:
            s = re.sub(r'- 유리섹터:\s*[^\n]*', '- 유리섹터: ' + _v1106_3_join(rec), s)
            s = re.sub(r'- 관찰섹터:\s*[^\n]*', '- 관찰섹터: ' + _v1106_3_join(watch), s)
            s = re.sub(r'- 불리섹터:\s*[^\n]*', '- 불리섹터: ' + _v1106_3_join(avoid), s)
        # 오늘 주도 섹터: 추천이 없으면 주도 없음, 관찰만 표시
        if '🏆 [오늘 주도 섹터]' in s:
            if rec:
                repl = '🏆 [오늘 주도 섹터]\n- 주도 섹터: ' + _v1106_3_join(rec) + '\n- 관찰 섹터: ' + _v1106_3_join(watch)
            else:
                repl = '🏆 [오늘 주도 섹터]\n- 주도 섹터: 없음\n- 관찰 1순위: ' + _v1106_3_join(watch) + '\n- 회피 확인: ' + _v1106_3_join(avoid)
            s = re.sub(r'🏆 \[오늘 주도 섹터\][\s\S]*?(?=\n📋 \[섹터별 전략\])', repl, s)
        # 섹터별 전략: 회피 섹터가 공략 섹터로 나오지 않도록 정리
        if '📋 [섹터별 전략]' in s:
            if rec:
                attack = _v1106_3_join(rec)
                observe = _v1106_3_join(watch)
            else:
                attack = '없음 — 레이더상 ✅추천 섹터가 없어 관망 우선'
                observe = _v1106_3_join(watch)
            repl = '📋 [섹터별 전략]\n- 공략 섹터: ' + attack + '\n- 관찰 섹터: ' + observe + '\n- 피할 섹터: ' + _v1106_3_join(avoid)
            s = re.sub(r'📋 \[섹터별 전략\][\s\S]*?(?=\n⚡ \[실전 체크포인트\])', repl, s)
        return s
    except Exception:
        return s


def _v1106_3_fix_theme_conflict_text(s: str) -> str:
    try:
        st = _v1106_3_parse_radar_status(s)
        avoid = set(st.get('avoid') or [])
        watch = set(st.get('watch') or [])
        # 반도체가 레이더 회피인데 뉴스/AI 매핑에서 긍정으로 재승격되는 문제 방지
        if '반도체' in avoid:
            s = s.replace('[테마] 반도체', '[주의테마] 반도체')
            s = re.sub(r'- 이유: 미국 반도체[^\n]*긍정[^\n]*', '- 이유: 레이더상 반도체가 ⛔회피/대표주 breadth 악화라 오늘 단기 신규 추격은 보수적으로 봅니다.', s)
        # 에너지는 유가하락+레이더 관찰이면 주도가 아니라 혼합 관찰
        if _v1106_3_oil_down_text(s) and ('정유/에너지' in watch or '정유/에너지' in avoid):
            s = s.replace('[테마] 에너지', '[혼합/관찰테마] 에너지')
            s = re.sub(r'- 이유: 미국 에너지[^\n]*긍정[^\n]*', '- 이유: XLE 일부 강세와 WTI 하락이 충돌합니다. 정유·에너지는 추격보다 관찰 우선입니다.', s)
            s = s.replace('🟢주도정유/에너지', '🟡혼합정유/에너지')
            s = s.replace('🟡우선관찰정유/에너지', '🟡혼합관찰정유/에너지')
        return s
    except Exception:
        return s


def _v1106_3_fix_airline_shipping_link(s: str) -> str:
    try:
        # 항공/운송 후보 줄 내부의 시황연결이 조선/해운 회피로 붙으면 강제 교체한다.
        pattern = r'((?:\d+\)\s*)?(?:대한항공|현대글로비스|진에어|제주항공|아시아나|티웨이항공)[^\n]*\|\s*항공/운송/유가하락수혜[\s\S]{0,800}?\n\s*🔗 시황연결:)\s*[^\n]*\[조선/해운\]\s*⛔회피[^\n]*'
        repl = r'\1 유가↓ 비용완화 수혜: 항공/운송은 조선/해운 회피와 분리해 기준선 재지지만 관찰'
        s = re.sub(pattern, repl, s)
        # 남은 간단 케이스
        s = re.sub(r'(🔗 시황연결:)\s*3위 \[조선/해운\] ⛔회피 \| 점수 -?\d+(?:\.\d+)?', r'\1 유가↓ 비용완화 수혜: 항공/운송은 조선/해운 회피와 분리해 기준선 재지지만 관찰', s)
        s = re.sub(r'(🔗 시황연결:)\s*5위 \[조선/해운\] ⛔회피 \| 점수 -?\d+(?:\.\d+)?', r'\1 유가↓ 비용완화 수혜: 항공/운송은 조선/해운 회피와 분리해 기준선 재지지만 관찰', s)
        return s
    except Exception:
        return s


def _v1106_3_extract_action_candidate_names(s: str):
    names=[]
    try:
        m = re.search(r'🟢 \[분할진입 후보\][\s\S]*?(?=\n🟡 \[눌림 확인 후보\]|\n⚠️ \[리스크|\n⛔ 제외|\n━━━━━━━━)', s)
        if m:
            for nm in re.findall(r'\n\s*\d+\)\s*([^\(\n]+)\(', m.group(0)):
                nm=nm.strip()
                if nm and nm not in names:
                    names.append(nm)
    except Exception:
        pass
    return names


def _v1106_3_strict_block_is_observation(block: str) -> bool:
    try:
        b=str(block or '')
        if '🧭 최종판정: 🟢' in b or '지금 1차 분할진입 가능' in b:
            return False
        if '🧭 최종판정: 🟡 눌림 확인 후 진입' in b or '눌림 재지지형' in b or '| 유형 관찰' in b:
            return True
    except Exception:
        pass
    return False


def _v1106_3_fix_strict_top_consistency(s: str) -> str:
    try:
        action_names = _v1106_3_extract_action_candidate_names(s)
        # STRICT 블록만 분리해서 관찰형이면 제목과 설명을 바꾼다.
        m = re.search(r'(📢 \[오늘의 STRICT 실전 TOP\][\s\S]*?)(?=\n👀 \[구조관찰/리스크 분리\]|\n\[TEST\]\n🧩|\n🧩 \[예비|\n🏆 \[삼각|\n\Z)', s)
        if not m:
            return s
        block = m.group(1)
        new_block = block
        if _v1106_3_strict_block_is_observation(block):
            new_block = new_block.replace('📢 [오늘의 STRICT 실전 TOP]', '📢 [오늘의 STRICT 관찰 TOP]')
            new_block = re.sub(r'실전 후보 \d+개만 표시합니다\. 실행제외·진입금지 후보는 TOP에서 제외했습니다\.', '아래 후보는 실전 진입이 아니라 눌림·재지지 확인용 관찰 후보입니다.', new_block)
            new_block = new_block.replace('기준: 차트/구조/수급 우선 1단계 압축판입니다.', '기준: STRICT 계산상 상위지만 최종판정이 눌림확인이면 관찰 TOP으로만 표시합니다.')
            if action_names:
                guide = '실전 우선 확인 후보: ' + ', '.join(action_names[:3]) + ' / STRICT 관찰 후보는 추격 금지\n\n'
                new_block = new_block.replace('AI Pick 기준:', guide + 'AI Pick 기준:', 1)
        if new_block != block:
            s = s[:m.start(1)] + new_block + s[m.end(1):]
        return s
    except Exception:
        return s


