def _v1106_4_fix_entry_labels(s: str) -> str:
    """분할진입/관찰/리스크 라벨의 색상·상태 중복을 최종 정리한다."""
    try:
        # 1) 실행보류 잔여 및 중복 제거: 어느 순서로 들어와도 최종적으로 실행제외 1회만 남긴다.
        patterns = [
            (r'확인필요·실행보류·비중축소\s*·실행제외·비중축소', '확인필요·실행제외·비중축소'),
            (r'응축관찰·실행보류·비중축소\s*·실행제외·비중축소', '응축관찰·실행제외·비중축소'),
            (r'실행보류·비중축소\s*·실행제외·비중축소', '실행제외·비중축소'),
            (r'실행제외·비중축소\s*·실행제외·비중축소', '실행제외·비중축소'),
        ]
        for pat, repl in patterns:
            s = re.sub(pat, repl, s)
        s = s.replace('확인필요·실행보류·비중축소', '확인필요·실행제외·비중축소')
        s = s.replace('응축관찰·실행보류·비중축소', '응축관찰·실행제외·비중축소')
        s = s.replace('실행보류·비중축소', '실행제외·비중축소')
        s = s.replace('응축관찰·실행보류', '응축관찰·실행제외')
        s = s.replace('확인필요·실행보류', '확인필요·실행제외')
        s = s.replace('실행보류', '실행제외')

        # 2) 분할진입 후보인데 라벨이 빨간색으로 남는 모순 보정
        #    섹션 내 첫 줄이든 일반 카드든 '소액가능'이면 초록 확인형으로 통일.
        s = re.sub(r'(\d+\)\s+[^\n]+?)\s+🔴\s+확인필요·소액가능·비중축소', r'\1 🟢 소액분할·기준선확인·비중축소', s)
        s = re.sub(r'(\d+\)\s+[^\n]+?)\s+🔴\s+확인필요·소액가능·손절양호', r'\1 🟢 소액분할·기준선확인·손절양호', s)
        s = s.replace('🔴 확인필요·소액가능·비중축소', '🟢 소액분할·기준선확인·비중축소')
        s = s.replace('🔴 확인필요·소액가능·손절양호', '🟢 소액분할·기준선확인·손절양호')

        # 3) 관찰 TOP 안의 초록+실행제외/비중축소가 매수처럼 보이지 않도록 완화.
        #    관찰 TOP에서는 최종판정이 🟡이면 라벨도 관찰형으로 보이게 한다.
        def _obs_card_repl(m):
            card = m.group(0)
            if '📢 [오늘의 STRICT 관찰 TOP]' in s[max(0, m.start()-1200):m.start()] or '🧭 최종판정: 🟡 눌림 확인 후 진입' in card:
                card = card.replace('🟢 응축관찰·실행제외·비중축소', '⚪ 관찰전용·재지지대기·비중축소')
                card = card.replace('🟢 응축우선·눌림대기·비중축소', '🟡 눌림확인·재지지대기·비중축소')
            return card
        s = re.sub(r'\d+\)\s+[^\n]+\([^\n]+\)[\s\S]{0,1400}?(?=\n\d+\)\s+[^\n]+\(|\n👀 \[구조관찰|\n\[TEST\]|\n🧩 \[예비|\n🏆 \[|\Z)', _obs_card_repl, s)
        return s
    except Exception:
        return s


def _v1106_4_fix_airline_context_lines(s: str) -> str:
    """항공/운송 후보의 🔗 시황연결이 매크로 한 줄 또는 조선/해운으로 붙는 문제를 최종 보정."""
    try:
        airline_names = '대한항공|현대글로비스|진에어|제주항공|티웨이항공|아시아나항공|케이피항공산업'
        good = '유가↓ 비용완화 수혜: 항공/운송은 조선/해운·우주항공과 분리해 기준선 재지지만 관찰'
        # 항공/운송 카드 안에서 시황연결이 매크로 라인/조선/해운/방산으로 잘못 붙은 경우
        pat = rf'((?:\d+\)\s*)?(?:{airline_names})[^\n]*\|\s*항공/운송/유가하락수혜[\s\S]{{0,900}}?\n\s*🔗 시황연결:)\s*(?:매크로:[^\n]*|\d+위 \[조선/해운\] ⛔회피[^\n]*|관찰섹터:\s*방산[^\n]*)'
        s = re.sub(pat, rf'\1 {good}', s)
        # 남은 단순 케이스: 직전 5줄 안에 항공/운송 테마가 있을 때만 매크로 연결을 교체
        lines = s.splitlines()
        out=[]
        recent=''
        for line in lines:
            if any(n in line for n in ['대한항공','현대글로비스','진에어','제주항공','티웨이항공','아시아나항공','케이피항공산업']) and '항공/운송/유가하락수혜' in line:
                recent='airline'
            if recent == 'airline' and line.strip().startswith('🔗 시황연결: 매크로:'):
                line = re.sub(r'🔗 시황연결:.*', '   🔗 시황연결: ' + good, line)
                recent=''
            out.append(line)
            if line.strip().startswith('✅ ') or line.strip().startswith('⚠️ '):
                recent=''
        return '\n'.join(out)
    except Exception:
        return s


def _v1106_4_polish_context_samples(s: str) -> str:
    """분리표 샘플에서 이름-테마 오매칭이 신뢰도를 떨어뜨리는 대표 케이스를 숨김/정정한다."""
    try:
        # 금융/보험주가 정유/에너지 부정 문맥으로 보이는 대표 오표시 제거
        bad_fin_oil = [
            r'\s*\|?\s*한화손해보험/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*DB손해보험/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*메리츠금융지주/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*우리금융지주/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*KB금융/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*신한지주/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
        ]
        for pat in bad_fin_oil:
            s = re.sub(pat, ' ', s)
        # 구분자 정리
        s = re.sub(r':\s*\|\s*', ': ', s)
        s = re.sub(r'\s*\|\s*\|\s*', ' | ', s)
        s = re.sub(r'\s{2,}', ' ', s)
        s = s.replace('\n ', '\n')
        return s
    except Exception:
        return s


def _v1106_4_cleanup_output_text(message: str) -> str:
    try:
        s = str(message or '')
        if not s:
            return s
        # 버전 표기 통일
        s = s.replace('V1106.3 긍/부정 문맥 + 매물흡수 우선 순환매 레이더', 'V1106.4 긍/부정 문맥 + 매물흡수 우선 순환매 레이더')
        s = s.replace('시황 문맥 필터 결과 — V1106.3 분리', '시황 문맥 필터 결과 — V1106.4 분리')
        s = s.replace('📌 V1106.3: STRICT 실전/관찰 분리 / 실행제외·과열보류 NO-BACKFILL', '📌 V1106.4: 라벨/시황연결 최종정리 / 실행제외·과열보류 NO-BACKFILL')
        s = s.replace('📌 V1106.3: 레이더 정합성 / STRICT 관찰전환 / 섹터충돌 보정', '📌 V1106.4: 레이더 정합성 / 라벨 중복 제거 / 항공 시황연결 보정')
        s = _v1106_4_fix_entry_labels(s)
        s = _v1106_4_fix_airline_context_lines(s)
        s = _v1106_4_polish_context_samples(s)
        return s
    except Exception:
        return message


