# V1106.4의 같은 이름 함수를 안전 버전으로 덮어쓴다.
# 핵심: re.sub(r'\s{2,}', ' ', s)는 \n\n까지 지워버리므로 절대 사용하지 않는다.
def _v1106_4_polish_context_samples(s: str) -> str:  # noqa: F811
    """V1106.5 safe override: 문맥 샘플을 정리하되 줄바꿈은 보존한다."""
    try:
        bad_fin_oil = [
            r'\s*\|?\s*한화손해보험/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*DB손해보험/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*메리츠금융지주/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*우리금융지주/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*KB금융/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
            r'\s*\|?\s*신한지주/정유/에너지/불리/회피 섹터 문맥 충돌\s*\|?',
        ]
        for pat in bad_fin_oil:
            s = re.sub(pat, ' ', s)
        # 한 줄 내부의 과도한 스페이스만 정리하고 줄바꿈은 보존
        lines = []
        for line in str(s).splitlines():
            line = re.sub(r'[ \t]{2,}', ' ', line).strip()
            line = line.replace(': | ', ': ')
            line = line.replace('| |', '|')
            lines.append(line)
        return '\n'.join(lines)
    except Exception:
        return s


def _v1106_5_fix_risk_label_spacing(s: str) -> str:
    """리스크 후보명과 라벨이 붙거나 중복되는 잔여 케이스 정리."""
    try:
        s = re.sub(r'확인필요·실행보류·비중축소\s*·실행제외·비중축소', '확인필요·실행제외·비중축소', s)
        s = re.sub(r'응축관찰·실행보류·비중축소\s*·실행제외·비중축소', '응축관찰·실행제외·비중축소', s)
        s = re.sub(r'실행보류·비중축소\s*·실행제외·비중축소', '실행제외·비중축소', s)
        s = s.replace('확인필요·실행보류·비중축소', '확인필요·실행제외·비중축소')
        s = s.replace('응축관찰·실행보류·비중축소', '응축관찰·실행제외·비중축소')
        s = s.replace('실행보류', '실행제외')
        # 종목명 뒤 라벨 앞 공백이 사라진 케이스: 코스모로보틱스(439960)·실행제외...
        s = re.sub(r'(\([0-9]{6}\))·(실행제외·비중축소)', r'\1 🔴 확인필요·\2', s)
        s = re.sub(r'(\([0-9]{6}\))\s*🔴\s*확인필요·확인필요·', r'\1 🔴 확인필요·', s)
        return s
    except Exception:
        return s


def _v1106_5_pretty_linebreaks(message: str) -> str:
    """텔레그램에서 읽히도록 섹션/종목카드/항목 줄바꿈을 강제 보정한다."""
    try:
        s = str(message or '').replace('\r\n', '\n').replace('\r', '\n')
        if not s:
            return s

        # 버전 표기 통일
        s = s.replace('V1106.4 긍/부정 문맥 + 매물흡수 우선 순환매 레이더', 'V1106.5 긍/부정 문맥 + 매물흡수 우선 순환매 레이더')
        s = s.replace('시황 문맥 필터 결과 — V1106.4 분리', '시황 문맥 필터 결과 — V1106.5 분리')
        s = s.replace('📌 V1106.4: 라벨/시황연결 최종정리 / 실행제외·과열보류 NO-BACKFILL', '📌 V1106.5: 텔레그램 줄바꿈/가독성 보정 / 실행제외·과열보류 NO-BACKFILL')

        # 주요 섹션 앞 줄바꿈. 이미 줄바꿈이 있으면 중복은 마지막에서 정리한다.
        section_markers = [
            '🌇 [시황 브리핑]', '🔄 [섹터 순환 레이더]', '🛢️ [유가 영향 분석]',
            '🏆 [오늘 주도 섹터]', '📋 [섹터별 전략]', '⚡ [실전 체크포인트]',
            '📰 [뉴스-테마 분석]', '🇺🇸➡🇰🇷 [미국시장 → 한국종목 연결]',
            '🌍 [시장 통합 브리핑]', '🎯 [오늘 매매관점 압축]',
            '🧭 [V1106.5 긍/부정 문맥 + 매물흡수 우선 순환매 레이더]',
            '🧭 [시황 문맥 필터 결과 — V1106.5 분리]',
            '🟢 [분할진입 후보]', '🟢/🟡 [실전 진입 가능 후보]', '🟡 [눌림 확인 후보]',
            '⚠️ [리스크 참고/신규진입 보류]', '📢 [오늘의 STRICT 관찰 TOP]',
            '📢 [오늘의 STRICT 실전 TOP]', '👀 [구조관찰/리스크 분리]',
            '🧩 [예비 삼각수렴·BB응축 TOP 3]', '🏆 [삼각수렴→1파→첫눌림 TOP 5]',
            '🏆 [저평가 1파/BB40 회복 TOP 5]'
        ]
        for marker in section_markers:
            s = s.replace(marker, '\n\n' + marker)

        # 붙어버린 소제목 복원
        bracket_heads = ['【시장 온도】', '【한국장 영향】', '【수혜 테마】', '【오늘 전략】']
        for h in bracket_heads:
            s = re.sub(r'(?<!\n)\s*' + re.escape(h), '\n' + h, s)

        # 자주 붙는 bullet/체크 라인 복원. 음수 금액(-100억)은 건드리지 않도록 특정 키만 처리.
        bullet_keys = [
            '미국 시장', 'VIX 기반', '오늘 코스피', '이유:', '오늘 주목할 테마', '개장 초반 전략', '주의사항:',
            '위험도:', '상태:', '한국장:', '태도:', '🛢️ 유가영향:', '유리섹터:', '관찰섹터:', '불리섹터:',
            '구조상 1차 관찰:', '주의종목:', '요약:', '체크:', '주도 섹터:', '공략 섹터:', '피할 섹터:'
        ]
        for key in bullet_keys:
            s = re.sub(r'(?<!\n)\s*-\s*' + re.escape(key), '\n- ' + key, s)

        # 테마/이슈 블록 내부의 붙은 라인 복원
        inline_heads = ['[이슈]', '[오늘 키워드]', '[테마]', '[주의테마]', '대장주:', '후발주:', '연동주:', '체크:', '해석:', '이유:', '대응:']
        for h in inline_heads:
            s = re.sub(r'(?<!\n)\s*' + re.escape(h), '\n' + h, s)

        # 섹터 레이더 순위/종목 카드 번호 앞 줄바꿈
        s = re.sub(r'(?<!\n)\s+(\d+위 \[[^\]]+\])', r'\n\1', s)
        s = re.sub(r'(?<!\n)\s+(\d+\)\s+[^\n]{1,42}\([0-9]{6}\))', r'\n\n\1', s)
        # 이름 없는 TOP 카드도 일부 복원
        s = re.sub(r'(?<!\n)\s+(\d+\)\s+[^\n|]{1,40}\s+\|\s+현재)', r'\n\n\1', s)

        # 종목 카드의 세부 라인 앞 줄바꿈
        card_tokens = ['🧭 ', '🧩 ', '🛠 ', '🎯 ', '🏦 ', '🔵 ', '✅ ', '📊 ', '📌 ', '🌊 ', '〰️/📶 ', '📐 ', '🔋 ', '🧠 ', '🤖 ', '🏷️ ', '⚠️ ', '🔗 ']
        for token in card_tokens:
            s = re.sub(r'(?<!\n)\s+' + re.escape(token), '\n   ' + token, s)

        # 수급 하위 라인
        s = re.sub(r'(?<!\n)\s+(├\s*1일:)', r'\n      \1', s)
        s = re.sub(r'(?<!\n)\s+(└\s*3일:)', r'\n      \1', s)

        # 문맥 분리표는 각 카테고리 앞을 분리
        for token in ['🔻 부정문맥 강등', '⚪ 혼합문맥 보류', '🟡 긍정문맥 관찰', '📌 운용:']:
            s = re.sub(r'(?<!\n)\s*' + re.escape(token), '\n' + token, s)

        # 긴 구분선 앞뒤 정리
        s = re.sub(r'(?<!\n)(━{6,})', r'\n\1', s)
        s = re.sub(r'(━{6,})(?!\n)', r'\1\n', s)
        s = re.sub(r'(?<!\n)(─{6,})', r'\n\1', s)
        s = re.sub(r'(─{6,})(?!\n)', r'\1\n', s)

        # 한 줄 안에 여러 후보가 붙은 리스크 블록 최소 분리
        s = re.sub(r'(상세카드 기준 확인)\s+(\d+\)\s+[^\n]{1,45}\([0-9]{6}\))', r'\1\n\n\2', s)

        s = _v1106_5_fix_risk_label_spacing(s)

        # 줄 단위 공백 정리. 줄바꿈은 보존.
        lines = []
        for line in s.split('\n'):
            line = re.sub(r'[ \t]{2,}', ' ', line).rstrip()
            if line.startswith(' '):
                # 카드 세부라인은 3칸 들여쓰기만 유지
                stripped = line.strip()
                if stripped.startswith(('🧭','🧩','🛠','🎯','🏦','🔵','✅','📊','📌','🌊','〰️/📶','📐','🔋','🧠','🤖','🏷️','⚠️','🔗')):
                    line = '   ' + stripped
                elif stripped.startswith(('├','└')):
                    line = '      ' + stripped
                else:
                    line = stripped
            lines.append(line)
        s = '\n'.join(lines)

        # 빈 줄 과다 제거. 섹션 간 가독성은 최대 2줄 유지.
        s = re.sub(r'\n{4,}', '\n\n\n', s)
        s = re.sub(r'\n[ \t]+\n', '\n\n', s)
        return s.strip()
    except Exception:
        return message


def _v1106_5_cleanup_output_text(message: str) -> str:
    try:
        s = str(message or '')
        s = _v1106_5_pretty_linebreaks(s)
        return s
    except Exception:
        return message


