def _v1106_6_final_spacing(s: str) -> str:
    try:
        lines = []
        for raw in str(s or '').split('\n'):
            line = raw.rstrip()
            # 단독 공백 제거
            if line.strip() == '':
                lines.append('')
                continue
            stripped = line.strip()
            # 카드 세부라인 들여쓰기 통일
            if stripped.startswith(('🧭','🧩','🛠','🎯','🏦','🔵','✅','📊','📌','🌊','〰️/📶','📐','🔋','🧠','🤖','🏷️','⚠️','🔗')):
                line = '   ' + stripped
            elif stripped.startswith(('├','└')):
                line = '      ' + stripped
            elif stripped.startswith('- ') or re.match(r'^- \d+\)', stripped):
                line = stripped
            else:
                line = stripped
            lines.append(line)
        s = '\n'.join(lines)
        # 섹션 앞 최소 한 줄 확보
        sections = ['🎯 [오늘 매매관점 압축]', '🧭 [V1106.6', '🧭 [시황 문맥 필터 결과', '🟢 [분할진입 후보]', '🟡 [눌림 확인 후보]', '⚠️ [리스크 참고/신규진입 보류]', '📢 [오늘의 STRICT 관찰 TOP]', '📢 [오늘의 STRICT 실전 TOP]', '👀 [구조관찰/리스크 분리]', '🧩 [예비 삼각수렴·BB응축 TOP 3]', '🏆 [삼각수렴→1파→첫눌림 TOP 5]', '🏆 [저평가 1파/BB40 회복 TOP 5]']
        for sec in sections:
            s = s.replace(sec, '\n\n' + sec)
        s = re.sub(r'\n{4,}', '\n\n\n', s)
        return s.strip()
    except Exception:
        return s


