def _v1107_4_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0', 'false', 'no', 'off', '')
    except Exception:
        return str(default).strip().lower() not in ('0', 'false', 'no', 'off', '')


def _v1107_4_text(x) -> str:
    try:
        if x is None:
            return ''
        return str(x).replace('\r\n', '\n').replace('\r', '\n')
    except Exception:
        return ''


def _v1107_4_has(text: str, words) -> bool:
    try:
        t = _v1107_4_text(text)
        return any(str(w) in t for w in words)
    except Exception:
        return False


def _v1107_4_sector_from_text(text: str) -> str:
    """출력 문자열만 보고 대표 섹터를 최대한 보수적으로 추정한다."""
    t = _v1107_4_text(text)
    checks = [
        ('반도체', ['반도체', 'HBM', 'DB하이텍', '동진쎄미켐', '코리아써키트', '한미반도체', '삼성전자', 'SK하이닉스', 'SFA반도체', '제주반도체']),
        ('AI전력/전력설비', ['AI전력', '전력설비', '전력기기', 'HD현대일렉트릭', '산일전기', 'LS', '일진전기', '가온전선', '비나텍']),
        ('로봇/자동화', ['로봇', '자동화', '에스피지', '휴림로봇', '두산로보틱스', '라온로보틱스', '레인보우로보틱스']),
        ('원전/우라늄', ['원전', '우라늄', '두산에너빌리티', '한전기술', '우리기술', '비에이치아이']),
        ('바이오/헬스케어', ['바이오', '제약', 'CDMO', '셀트리온', '삼성바이오로직스', '한미약품', '펩트론', '녹십자']),
        ('금융/은행', ['금융', '은행', '밸류업', 'KB금융', '신한지주', '하나금융', '한화생명', 'DB손해보험']),
        ('자동차/부품', ['자동차', '기아', '현대차', 'HL만도', '현대모비스', '현대글로비스']),
        ('항공/운송', ['항공', '운송', '대한항공', '진에어', '현대글로비스']),
        ('정유/에너지', ['정유', '에너지', 'SK이노베이션', 'S-Oil', 'GS']),
        ('조선/해운', ['조선', '해운', 'HD현대중공업', '한화오션', '삼성중공업']),
        ('소프트웨어/클라우드', ['소프트웨어', '클라우드', 'NAVER', '카카오', '크래프톤']),
    ]
    for sec, keys in checks:
        if any(k in t for k in keys):
            return sec
    return '미분류'


def _v1107_4_sector_strength(text: str) -> str:
    t = _v1107_4_text(text)
    if _v1107_4_has(t, ['STRONG_SECTOR', '🟢주도', '주도반도체', '주도로봇', '주도원전', '시황긍정']) or _v1107_4_sector_from_text(t) in {'반도체', 'AI전력/전력설비', '로봇/자동화', '원전/우라늄', '자동차/부품'}:
        return 'STRONG_SECTOR'
    if _v1107_4_has(t, ['부정문맥', '불리섹터', '회피 섹터', '섹터 문맥 충돌']):
        return 'WEAK_SECTOR'
    return 'NEUTRAL_SECTOR'


def _v1107_4_pullback_cause(text: str) -> str:
    t = _v1107_4_text(text)
    if _v1107_4_has(t, ['STOCK_BREAKDOWN', '종목 단독 훼손', '수급부담', '개인수급/외인기관매도', '외인기관매도', '기준선아래', '실행기준선 미확인', '신규진입 보류']):
        return '🔴 STOCK_BREAKDOWN'
    if _v1107_4_has(t, ['SECTOR_PULLBACK', '섹터 동반', '섹터 붕괴', '부정문맥', '섹터 문맥 충돌', '불리/회피 섹터']):
        return '🟠 SECTOR_PULLBACK'
    if _v1107_4_has(t, ['INDEX_PULLBACK', '지수 영향', '지수 눌림']):
        return '🟡 INDEX_PULLBACK'
    if _v1107_4_has(t, ['HEALTHY_PULLBACK', '건강한 눌림', '쌍끌강', '외인강', '기관 중심 강매집', '동반 강매집', '손절 기준이 짧은 자리']):
        return '🟢 HEALTHY_PULLBACK'
    if _v1107_4_has(t, ['눌림 확인', '재지지', '소액 분할', '기준선 위', '종가 안착', '접촉']):
        return '🟡 NORMAL_PULLBACK'
    return '⚪ MIXED_PULLBACK'


def _v1107_4_block_signal_flags(text: str) -> dict:
    t = _v1107_4_text(text)
    risk = _v1107_4_has(t, [
        'TD-RISK', '실행제외', '신규진입 보류', '기준선아래', '실행기준선 미확인',
        '가짜수박주의(강', '가짜수박 강', '과열보류', 'RSI75', '이격115', 'STOCK_BREAKDOWN',
    ])
    recover = _v1107_4_has(t, ['회복선 돌파 확인 후 진입', '회복선 위 종가 안착 확인 후', '회복확인'])
    small = _v1107_4_has(t, ['지금 1차 분할진입 가능', '1차 분할진입 가능', '소액 분할진입 가능'])
    pullback = _v1107_4_has(t, ['눌림 확인 후 진입', '눌림 재지지', '눌림대기', '재지지 + 양봉 마감'])
    # 60분봉은 라이브에서 직접 계산하지 못할 수 있어, 거래량/재안착/수급 프록시로 보수 추정한다.
    proxy = _v1107_4_has(t, [
        '60분프록시:YES', '전일고점 돌파', '거래량 재유입', '거래량 전일比', '5일평균比',
        '돌파/재안착', '5일재안착', '5일재안착예비', '쌍끌강', '쌍끌', '외인강', '기관 중심 강매집',
    ])
    daily_ready = small or pullback or recover or _v1107_4_has(t, ['실행기준선', '피보38.2', '종가 안착', '위안착', '접촉'])
    strong_sector = _v1107_4_sector_strength(t) == 'STRONG_SECTOR'
    pullback_cause = _v1107_4_pullback_cause(t)
    return {
        'risk': risk,
        'recover': recover,
        'small': small,
        'pullback': pullback,
        'proxy': proxy,
        'daily_ready': daily_ready,
        'strong_sector': strong_sector,
        'pullback_cause': pullback_cause,
    }


def _v1107_4_classify_block(text: str) -> dict:
    """V1107.3 결과를 라이브 텍스트 블록에 적용한 운용 라벨."""
    try:
        t = _v1107_4_text(text)
        f = _v1107_4_block_signal_flags(t)
        sector = _v1107_4_sector_from_text(t)
        strength = _v1107_4_sector_strength(t)
        cause = f['pullback_cause']

        if f['risk'] or cause.startswith('🔴 STOCK_BREAKDOWN'):
            return {
                'label': '🔴 TD-RISK',
                'entry': '실전 제외 / 회복선·기준선 재확인 전 관찰',
                'reason': f'{cause} · 구조/수급 훼손 가능성',
                'sector': sector,
                'strength': strength,
            }
        if cause.startswith('🟠 SECTOR_PULLBACK'):
            return {
                'label': '🟡 TD-WATCH',
                'entry': '섹터 재상승 확인 전 관찰 / 전일고점 돌파 전 추격 금지',
                'reason': f'{cause} · 섹터 동반 조정 가능성',
                'sector': sector,
                'strength': strength,
            }
        if f['small'] and f['daily_ready'] and f['proxy'] and not f['recover']:
            return {
                'label': '🟢 TD-CORE',
                'entry': '기준일 종가·다음날 시가 소액 가능 / 추가는 전일고점 재돌파',
                'reason': f'일봉 READY + 60분프록시 추정 + {cause}',
                'sector': sector,
                'strength': strength,
            }
        if f['proxy'] and (f['strong_sector'] or cause.startswith(('🟢', '🟡'))) and not f['recover']:
            return {
                'label': '🔥 TD-PRIME',
                'entry': '다음날 전일고점 돌파확인 진입 우선',
                'reason': f'주도/정상 눌림 + 60분프록시 추정 + {cause}',
                'sector': sector,
                'strength': strength,
            }
        if f['recover'] or (f['daily_ready'] and cause.startswith(('🟢', '🟡', '⚪'))):
            return {
                'label': '🟠 TD-RECOVER',
                'entry': '소액/확인형 · 회복선 또는 전일고점 돌파 후 추가',
                'reason': f'회복 후보 · {cause}',
                'sector': sector,
                'strength': strength,
            }
        return {
            'label': '🟡 TD-WATCH',
            'entry': '거래량 재돌파 전 관찰',
            'reason': f'주봉/섹터 또는 눌림은 관찰 가능 · {cause}',
            'sector': sector,
            'strength': strength,
        }
    except Exception as e:
        return {'label': '🟡 TD-WATCH', 'entry': '거래량 재돌파 전 관찰', 'reason': f'분류실패:{e}', 'sector': '미분류', 'strength': 'NEUTRAL_SECTOR'}


def _v1107_4_td_line_for_block(block: str) -> str:
    info = _v1107_4_classify_block(block)
    label = info.get('label', '🟡 TD-WATCH')
    entry = info.get('entry', '거래량 재돌파 전 관찰')
    reason = info.get('reason', '')
    sector = info.get('sector', '미분류')
    strength = info.get('strength', 'NEUTRAL_SECTOR')
    return f"   🧭 TD운용: {label} | {sector}·{strength} | {entry}\n   🔎 TD근거: {reason}"


def _v1107_4_insert_td_lines(message: str) -> str:
    """후보 카드마다 TD운용 라인을 삽입한다. 이미 삽입되어 있으면 중복하지 않는다."""
    try:
        if not _v1107_4_on('V1107_4_INSERT_TD_LINES', '1'):
            return message
        s = _v1107_4_text(message)
        if 'TD운용:' in s:
            return s
        if not any(k in s for k in ['📢 [오늘의 STRICT', '🟢 [분할진입 후보]', '🟡 [눌림 확인 후보]', '⚠️ [리스크 참고/신규진입 보류]']):
            return s
        lines = s.split('\n')
        item_idxs = []
        item_re = re.compile(r'^\s*(\d+)\)\s+[^\n]{1,80}\([0-9A-Za-z]{4,8}\)')
        stop_re = re.compile(r'^\s*(?:━━━━━━━━|\[TEST\]|\([0-9]+/[0-9]+\)|🎯 \[|🧭 \[|🟢/🟡 \[|🟢 \[|🟡 \[|⚠️ \[|📢 \[|👀 \[|🧩 \[|🏆 \[|⛔ )')
        for i, line in enumerate(lines):
            if item_re.match(line):
                item_idxs.append(i)
        if not item_idxs:
            return s
        out = list(lines)
        inserts = []
        for p, start in enumerate(item_idxs):
            end = item_idxs[p + 1] if p + 1 < len(item_idxs) else len(lines)
            for j in range(start + 1, end):
                if stop_re.match(lines[j]) and j != start + 1:
                    end = j
                    break
            block = '\n'.join(lines[start:end])
            # 예비 삼각수렴/저평가 섹션은 최종판정 카드가 아니면 과도한 삽입을 피한다.
            if not any(k in block for k in ['최종판정', '신규진입 보류', '소액 분할진입', '눌림 확인', '회복선 돌파', '실행제외']):
                continue
            # 헤더 바로 다음에 삽입. 단, 다음 줄이 AI pick이면 그 다음에 넣어도 읽기 좋다.
            pos = start + 1
            if pos < len(lines) and '🤖 AI' in lines[pos]:
                pos = start + 2
            inserts.append((pos, _v1107_4_td_line_for_block(block)))
        for pos, ins in reversed(inserts):
            out[pos:pos] = str(ins).split('\n')
        return '\n'.join(out)
    except Exception:
        return message


def _v1107_4_insert_guide(message: str) -> str:
    try:
        if not _v1107_4_on('V1107_4_INSERT_TD_GUIDE', '1'):
            return message
        s = _v1107_4_text(message)
        if 'V1107.4: Top-Down 운용라벨 통합' in s:
            return s
        guide = '\n'.join([
            '📌 V1107.4: Top-Down 운용라벨 통합 / TD-PRIME 전일고점 돌파확인 / TD-RISK 분리',
            '📌 TD 우선순위: 🔥 TD-PRIME > 🟢 TD-CORE > 🟠 TD-RECOVER > 🟡 TD-WATCH > 🔴 TD-RISK',
        ])
        # 오늘 매매관점 압축과 STRICT TOP 둘 중 먼저 나오는 곳에 삽입한다.
        for marker in ['🎯 [오늘 매매관점 압축]', '📢 [오늘의 STRICT 실전 TOP]', '📢 [오늘의 STRICT 관찰 TOP]']:
            if marker in s:
                s = s.replace(marker, marker + '\n' + guide, 1)
                break
        return s
    except Exception:
        return message


def _v1107_4_cleanup_output_text(message: str) -> str:
    try:
        s = _v1107_4_text(message)
        s = _v1107_4_insert_guide(s)
        s = _v1107_4_insert_td_lines(s)
        # 버전 라인 갱신. 기존 V1106.7 가독성 보정은 유지하되 현재 운용버전이 보이게 한다.
        s = s.replace('V1106.7: 텔레그램 압축문장 복원 / 실행제외·과열보류 NO-BACKFILL',
                      'V1107.4: Top-Down 운용라벨 통합 / 실행제외·과열보류 NO-BACKFILL')
        # 너무 붙는 경우를 마지막으로 정리
        s = re.sub(r'\n{4,}', '\n\n\n', s)
        return s.strip()
    except Exception:
        return message


