def _v1046_send_top15_detail(msg, max_len=3300):
    try:
        msg2 = _v1107_4_cleanup_output_text(str(msg or ''))
    except Exception:
        msg2 = msg
    if _V1107_4_BASE_SEND_TOP15_DETAIL:
        return _V1107_4_BASE_SEND_TOP15_DETAIL(msg2, max_len=max_len)
    if _V1107_4_BASE_SEND_CHUNKS:
        return _V1107_4_BASE_SEND_CHUNKS(msg2, max_len=max_len)
    return None


