def _v1107_4_1_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0', 'false', 'no', 'off', '')
    except Exception:
        return str(default).strip().lower() not in ('0', 'false', 'no', 'off', '')


def _v1107_4_1_text(x) -> str:
    try:
        return str(x or '').replace('\r\n', '\n').replace('\r', '\n')
    except Exception:
        return ''


def _v1107_4_1_code_from_block(block: str) -> str:
    try:
        b = _v1107_4_1_text(block)
        # 1) 종목명(000000) 형태 우선
        m = re.search(r'\(([0-9]{6})\)', b)
        if m:
            return m.group(1)
        # 2) 코드: 000000 / code 000000 fallback
        m = re.search(r'(?:코드|code|종목코드)\D{0,8}([0-9]{6})', b, flags=re.I)
        if m:
            return m.group(1)
    except Exception:
        pass
    return ''


def _v1107_4_1_td_label_from_block(block: str) -> str:
    try:
        b = _v1107_4_1_text(block)
        m = re.search(r'TD운용:\s*([^|\n]+)', b)
        if m:
            return m.group(1).strip()
        fn = globals().get('_v1107_4_classify_block')
        if callable(fn):
            info = fn(b)
            return str(info.get('label', '') or '').strip()
    except Exception:
        pass
    return ''


def _v1107_4_1_is_risk_label(label: str) -> bool:
    return 'TD-RISK' in str(label or '') or '🔴' in str(label or '') and 'RISK' in str(label or '')


def _v1107_4_1_section_kind(lines, start_idx: int) -> str:
    """현재 카드가 어떤 큰 섹션에 속하는지 역방향 탐색."""
    try:
        for j in range(start_idx, max(-1, start_idx - 120), -1):
            t = str(lines[j] or '').strip()
            if not t:
                continue
            if '⚠️ [리스크 참고/신규진입 보류]' in t:
                return 'risk'
            if '📢 [오늘의 STRICT' in t:
                return 'strict'
            if '🟢 [분할진입 후보]' in t or '🟢/🟡 [실전 진입 가능 후보]' in t:
                return 'entry'
            if '🟡 [눌림 확인 후보]' in t:
                return 'pullback'
            if '🟠 [회복 확인 후보]' in t:
                return 'recover'
            if '👀 [구조관찰/리스크 분리]' in t:
                return 'observe'
            if '🧩 [예비' in t or '🏆 [삼각' in t or '🏆 [저평가' in t:
                return 'study'
            if '🎯 [오늘 매매관점 압축]' in t:
                return 'today'
    except Exception:
        pass
    return 'unknown'


def _v1107_4_1_item_spans(lines):
    """번호형 후보 카드의 line span 목록 반환."""
    item_re = re.compile(r'^\s*(?:-\s*)?\d+\)\s+[^\n]{1,90}\([0-9A-Za-z]{4,8}\)')
    section_re = re.compile(r'^\s*(?:━━━━━━━━|\[TEST\]|\([0-9]+/[0-9]+\)|🎯 \[|🧭 \[|🟢/🟡 \[|🟢 \[|🟡 \[|🟠 \[|⚠️ \[|📢 \[|👀 \[|🧩 \[|🏆 \[|⛔ )')
    starts = [i for i, line in enumerate(lines) if item_re.match(str(line or ''))]
    spans = []
    for p, st in enumerate(starts):
        en = starts[p + 1] if p + 1 < len(starts) else len(lines)
        for j in range(st + 1, en):
            if section_re.match(str(lines[j] or '')) and j != st + 1:
                en = j
                break
        spans.append((st, en))
    return spans


def _v1107_4_1_sanitize_td_conflicts(message: str) -> str:
    """TD-RISK/실전 TOP 중복 충돌을 제거한다. risk-wins 방식으로 실전 오해를 차단."""
    try:
        if not _v1107_4_1_on('V1107_4_1_TD_CONSISTENCY_FIX', '1'):
            return message
        s = _v1107_4_1_text(message)
        if 'TD운용:' not in s and 'TD-RISK' not in s and 'TD-PRIME' not in s and 'TD-CORE' not in s:
            return s

        lines = s.split('\n')
        spans = _v1107_4_1_item_spans(lines)
        if not spans:
            return s

        # 1차: 현재 메시지 내부와 이전 메시지에서 TD-RISK 코드 수집
        risk_codes = set()
        for code, rec in list(_V1107_4_1_TD_REGISTRY.items()):
            try:
                if str(rec.get('label', '')).find('TD-RISK') >= 0:
                    risk_codes.add(code)
            except Exception:
                pass

        for st, en in spans:
            block = '\n'.join(lines[st:en])
            code = _v1107_4_1_code_from_block(block)
            if not code:
                continue
            label = _v1107_4_1_td_label_from_block(block)
            kind = _v1107_4_1_section_kind(lines, st)
            if _v1107_4_1_is_risk_label(label) or kind == 'risk' and ('TD-RISK' in block or 'STOCK_BREAKDOWN' in block):
                risk_codes.add(code)
                _V1107_4_1_TD_REGISTRY[code] = {'label': '🔴 TD-RISK', 'section': kind}
            elif code not in _V1107_4_1_TD_REGISTRY:
                _V1107_4_1_TD_REGISTRY[code] = {'label': label, 'section': kind}

        if not risk_codes:
            return s

        # 2차: risk 코드가 실전/STRICT/분할/눌림/회복 섹션에 다시 등장하면 카드 제거
        remove = set()
        removed_codes = []
        actionable_kinds = {'strict', 'entry', 'pullback', 'recover'}
        for st, en in spans:
            block = '\n'.join(lines[st:en])
            code = _v1107_4_1_code_from_block(block)
            if not code or code not in risk_codes:
                continue
            kind = _v1107_4_1_section_kind(lines, st)
            label = _v1107_4_1_td_label_from_block(block)
            # 리스크 섹션 자체는 유지한다. 실전 후보 쪽 중복만 제거.
            if kind in actionable_kinds and not _v1107_4_1_is_risk_label(label):
                for k in range(st, en):
                    remove.add(k)
                removed_codes.append(code)

        if not remove:
            return s

        out = [line for i, line in enumerate(lines) if i not in remove]
        result = '\n'.join(out)
        try:
            uniq = []
            for c in removed_codes:
                if c not in uniq:
                    uniq.append(c)
            note = f"\n⛔ TD 충돌 제거: TD-RISK 선분류 {len(uniq)}개는 실전 TOP에서 제외했습니다. ({', '.join(uniq[:8])})\n"
            # STRICT TOP 바로 아래에 안내를 붙인다. 없으면 문장 끝에 붙인다.
            if '📢 [오늘의 STRICT 실전 TOP]' in result:
                result = result.replace('📢 [오늘의 STRICT 실전 TOP]', '📢 [오늘의 STRICT 실전 TOP]' + note, 1)
            elif '🟢 [분할진입 후보]' in result:
                result = result.replace('🟢 [분할진입 후보]', '🟢 [분할진입 후보]' + note, 1)
            else:
                result = result.rstrip() + note
        except Exception:
            pass
        return result
    except Exception:
        return message


def _v1107_4_1_polish_numbering(message: str) -> str:
    """청크 번호가 후보 번호 중간에 붙는 현상과 1(4/4)0) 형태를 사전 보정."""
    try:
        s = _v1107_4_1_text(message)
        # 혹시 이전 splitter가 만든 깨진 번호 흔적이 남아 있으면 복원
        s = re.sub(r'(\d)\(([0-9]+)/([0-9]+)\)\s*(\d\))', r'\n(\2/\3)\n\1\4', s)
        s = re.sub(r'(손절\s*[0-9,]+)(?=\d+\)\s)', r'\1\n\n', s)
        s = re.sub(r'(?<!\n)(\d+\)\s*[A-Za-z가-힣0-9&.·\- ]{1,40}\([0-9]{6}\))', r'\n\n\1', s)
        s = re.sub(r'\n{4,}', '\n\n\n', s)
        return s.strip()
    except Exception:
        return message




def _v1107_4_1_renumber_candidate_sections(message: str) -> str:
    """카드 제거 뒤 1) 2) 번호가 건너뛰지 않도록 섹션별로 재번호 부여."""
    try:
        lines = _v1107_4_1_text(message).split('\n')
        out = []
        n = 0
        in_candidate_section = False
        section_markers = (
            '🟢 [분할진입 후보]', '🟢/🟡 [실전 진입 가능 후보]', '🟡 [눌림 확인 후보]',
            '🟠 [회복 확인 후보]', '⚠️ [리스크 참고/신규진입 보류]',
            '📢 [오늘의 STRICT 실전 TOP]', '📢 [오늘의 STRICT 관찰 TOP]',
            '👀 [구조관찰/리스크 분리]', '🧩 [예비 삼각수렴·BB응축 TOP 3]',
            '🏆 [삼각수렴→1파→첫눌림 TOP 5]', '🏆 [저평가 1파/BB40 회복 TOP 5]'
        )
        hard_stop_markers = ('🎯 [오늘 매매관점 압축]', '🧭 [', '🌍 [', '📰 [', '🇺🇸➡🇰🇷', '🔄 [')
        item_re = re.compile(r'^(\s*)(?:-\s*)?\d+\)\s+')
        for line in lines:
            stripped = str(line or '').strip()
            if any(m in stripped for m in section_markers):
                in_candidate_section = True
                n = 0
                out.append(line)
                continue
            if any(stripped.startswith(m) for m in hard_stop_markers) and not any(m in stripped for m in section_markers):
                in_candidate_section = False
                n = 0
                out.append(line)
                continue
            if in_candidate_section and item_re.match(str(line or '')):
                n += 1
                line = item_re.sub(lambda m: f"{m.group(1)}{n}) ", str(line), count=1)
            out.append(line)
        return '\n'.join(out)
    except Exception:
        return message

def _v1107_4_1_cleanup_output_text(message: str) -> str:
    try:
        s = _v1107_4_1_text(message)
        # 이전 가독성 복원 → V1107.4 TD 삽입 → V1107.4.1 충돌 제거 순서
        fn = globals().get('_v1106_7_cleanup_output_text')
        if callable(fn):
            try:
                s = fn(s)
            except Exception:
                pass
        fn = globals().get('_v1107_4_cleanup_output_text')
        if callable(fn):
            try:
                s = fn(s)
            except Exception:
                pass
        s = _v1107_4_1_sanitize_td_conflicts(s)
        s = _v1107_4_1_polish_numbering(s)
        s = _v1107_4_1_renumber_candidate_sections(s)
        # 버전 표시 갱신
        s = s.replace('V1107.4: Top-Down 운용라벨 통합 / TD-PRIME 전일고점 돌파확인 / TD-RISK 분리',
                      'V1107.4.1: TD라벨 충돌제거 / 카드단위 분할 / TD-RISK 중복차단')
        s = s.replace('V1107.4: Top-Down 운용라벨 통합 / 실행제외·과열보류 NO-BACKFILL',
                      'V1107.4.1: TD라벨 충돌제거 / 카드단위 분할 / 실행제외·과열보류 NO-BACKFILL')
        s = re.sub(r'\n{4,}', '\n\n\n', s)
        return s.strip()
    except Exception:
        return message


def _v1107_4_1_safe_int(x, default=3400):
    try:
        v = int(str(x).strip())
        return max(1000, min(v, 3900))
    except Exception:
        return default


def _v1107_4_1_unit_start(line: str) -> bool:
    try:
        t = str(line or '').strip()
        if not t:
            return False
        if re.match(r'^(?:-\s*)?\d+\)\s+.+\([0-9]{6}\)', t):
            return True
        if re.match(r'^\([0-9]+/[0-9]+\)$', t):
            return True
        if t.startswith(('━━━━━━━━', '────────────────')):
            return True
        if re.match(r'^[🎯🟢🟡🟠⚠️📢👀🧩🏆🔄🌍📰🇺🇸🤖]', t) and '[' in t and ']' in t:
            return True
        if t.startswith(('[TEST]', '📌 V1107', '📌 TD 우선순위')):
            return True
    except Exception:
        pass
    return False


def _v1107_4_1_group_units(text: str):
    lines = _v1107_4_1_text(text).splitlines()
    units, cur = [], []
    for line in lines:
        if cur and _v1107_4_1_unit_start(line):
            units.append('\n'.join(cur).rstrip())
            cur = [line]
        else:
            cur.append(line)
    if cur:
        units.append('\n'.join(cur).rstrip())
    return [u for u in units if str(u or '').strip()]


def _v1107_4_1_split_long_unit(unit: str, max_len: int):
    s = str(unit or '').strip()
    if len(s) <= max_len:
        return [s]
    out, cur = [], ''
    for line in s.splitlines():
        line = str(line or '')
        cand = (cur + '\n' + line).strip() if cur else line
        if len(cand) > max_len and cur.strip():
            out.append(cur.strip())
            cur = line
        else:
            cur = cand
        while len(cur) > max_len:
            out.append(cur[:max_len].rstrip())
            cur = cur[max_len:].lstrip()
    if cur.strip():
        out.append(cur.strip())
    return out


def _v1107_4_1_safe_split_message(message: str, max_len: int = None):
    safe_len = _v1107_4_1_safe_int(max_len or _V1107_4_1_SAFE_MAX, _V1107_4_1_SAFE_MAX)
    s = _v1107_4_1_text(message).strip()
    if not s:
        return []
    if len(s) <= safe_len:
        return [s]
    units = []
    for u in _v1107_4_1_group_units(s):
        units.extend(_v1107_4_1_split_long_unit(u, safe_len))
    chunks, cur = [], ''
    for unit in units:
        unit = str(unit or '').strip()
        if not unit:
            continue
        cand = (cur + '\n\n' + unit).strip() if cur else unit
        if len(cand) > safe_len and cur.strip():
            chunks.append(cur.strip())
            cur = unit
        else:
            cur = cand
    if cur.strip():
        chunks.append(cur.strip())
    final = []
    for c in chunks:
        if len(c) <= safe_len:
            final.append(c)
        else:
            final.extend(_v1107_4_1_split_long_unit(c, safe_len))
    return [c for c in final if str(c or '').strip()]


def _v1107_4_1_raw_send_text(text: str):
    try:
        raw = globals().get('_v1048_raw_send_text_to_telegram')
        if callable(raw):
            return raw(text)
    except Exception:
        pass
    # fallback: 기존 전송기에 짧은 청크만 넘긴다.
    try:
        if _V1107_4_1_BASE_SEND_CHUNKS:
            return _V1107_4_1_BASE_SEND_CHUNKS(str(text or ''), max_len=3900)
    except Exception:
        return None
    return None


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    try:
        msg = _v1107_4_1_cleanup_output_text(str(message or ''))
    except Exception:
        msg = str(message or '')
    try:
        if not msg.strip():
            return None
        if title:
            msg = (str(title).strip() + '\n\n' + msg).strip()
        safe_len = min(_v1107_4_1_safe_int(max_len, _V1107_4_1_SAFE_MAX), _V1107_4_1_SAFE_MAX)
        chunks = _v1107_4_1_safe_split_message(msg, safe_len)
        total = len(chunks)
        for idx, chunk in enumerate(chunks, 1):
            out = chunk
            if total > 1:
                out = f"({idx}/{total})\n" + out
            _v1107_4_1_raw_send_text(out)
        return None
    except Exception:
        if _V1107_4_1_BASE_SEND_CHUNKS:
            return _V1107_4_1_BASE_SEND_CHUNKS(message, title=title, max_len=max_len)
    return None


def send_telegram_photo(message, image_paths=[]):
    try:
        msg = _v1107_4_1_cleanup_output_text(str(message or ''))
    except Exception:
        msg = str(message or '')
    try:
        if len(msg) > 1000 or not image_paths:
            chunks = _v1107_4_1_safe_split_message(msg, _V1107_4_1_SAFE_MAX)
            total = len(chunks)
            for idx, chunk in enumerate(chunks, 1):
                out = f"({idx}/{total})\n{chunk}" if total > 1 else chunk
                _v1107_4_1_raw_send_text(out)
            if image_paths and _V1107_4_1_BASE_SEND_PHOTO:
                try:
                    return _V1107_4_1_BASE_SEND_PHOTO('📎 첨부 이미지', image_paths)
                except Exception:
                    return None
            return None
        if _V1107_4_1_BASE_SEND_PHOTO:
            return _V1107_4_1_BASE_SEND_PHOTO(msg, image_paths)
    except Exception:
        if _V1107_4_1_BASE_SEND_PHOTO:
            return _V1107_4_1_BASE_SEND_PHOTO(message, image_paths)
    return None

