def _v1107_4_2_text(x) -> str:
    try:
        return str(x or '').replace('\r\n', '\n').replace('\r', '\n')
    except Exception:
        return ''


def _v1107_4_2_has_actionable_count(s: str) -> bool:
    """오늘 매매관점 압축 내부에 실제 후보 섹션 숫자가 있는지 확인."""
    try:
        t = _v1107_4_2_text(s)
        pats = [
            r'🟢\s*\[분할진입 후보\][^\n]*?(?:검토|가능)\s*([1-9][0-9]*)개',
            r'🟢/🟡\s*\[실전 진입 가능 후보\]\s*([1-9][0-9]*)개',
            r'🟡\s*\[눌림 확인 후보\][^\n]*?\s([1-9][0-9]*)개',
            r'🟠\s*\[회복 확인 후보\][^\n]*?\s([1-9][0-9]*)개',
        ]
        return any(re.search(p, t) for p in pats)
    except Exception:
        return False


def _v1107_4_2_has_zero_actionable(s: str) -> bool:
    try:
        t = _v1107_4_2_text(s)
        return (
            '🟢/🟡 [실전 진입 가능 후보] 0개' in t
            or '오늘은 조건을 만족한 실전 진입 후보가 없습니다' in t
            or re.search(r'\[실전 진입 가능 후보\]\s*0개', t) is not None
        )
    except Exception:
        return False


def _v1107_4_2_record_today_state(s: str):
    """메시지 전송 순서가 분리되어도 오늘 압축 0개 상태를 후속 STRICT 출력에서 기억한다."""
    try:
        t = _v1107_4_2_text(s)
        if '🎯 [오늘 매매관점 압축]' not in t and '🟢/🟡 [실전 진입 가능 후보]' not in t:
            return
        actionable = _v1107_4_2_has_actionable_count(t)
        zero = _v1107_4_2_has_zero_actionable(t)
        _V1107_4_2_STATE['last_today_message_had_actionable'] = bool(actionable)
        if zero and not actionable:
            _V1107_4_2_STATE['today_action_zero'] = True
        elif actionable:
            _V1107_4_2_STATE['today_action_zero'] = False
    except Exception:
        pass


def _v1107_4_2_rewrite_today_zero(s: str) -> str:
    try:
        if not _v1107_4_2_on('V1107_4_2_OUTPUT_CONSISTENCY_FIX', '1'):
            return s
        t = _v1107_4_2_text(s)
        if not _v1107_4_2_has_zero_actionable(t) or _v1107_4_2_has_actionable_count(t):
            return t
        t = t.replace(
            '- 오늘은 조건을 만족한 실전 진입 후보가 없습니다.\n- 무리한 매수보다 TOP15/리스크 참고에서 회복 조건만 확인합니다.',
            '- 오늘 매매관점 압축 기준 즉시 진입 후보는 0개입니다.\n- 후속 STRICT TOP이 나오더라도 오늘은 관찰/눌림·회복 확인 후보로만 봅니다.\n- 무리한 매수보다 기준선 재지지·거래량 재유입·전일고점 돌파 확인만 체크합니다.'
        )
        t = t.replace(
            '- 오늘은 조건을 만족한 실전 진입 후보가 없습니다.',
            '- 오늘 매매관점 압축 기준 즉시 진입 후보는 0개입니다.\n- 후속 STRICT TOP이 나오더라도 오늘은 관찰/눌림·회복 확인 후보로만 봅니다.'
        )
        return t
    except Exception:
        return s


def _v1107_4_2_rewrite_strict_title(s: str) -> str:
    """오늘 압축 0개가 선행되면 후속 STRICT 실전 TOP을 관찰 TOP으로 바꿔 모순을 제거."""
    try:
        if not _v1107_4_2_on('V1107_4_2_TODAY_ZERO_RENAMES_STRICT', '1'):
            return s
        t = _v1107_4_2_text(s)
        today_zero = bool(_V1107_4_2_STATE.get('today_action_zero'))
        if not today_zero:
            return t
        if '📢 [오늘의 STRICT 실전 TOP]' not in t:
            return t
        t = t.replace('📢 [오늘의 STRICT 실전 TOP]', '📢 [오늘의 STRICT 관찰 TOP]')
        t = re.sub(r'실전 후보\s*([0-9]+)개만 표시합니다\.', r'관찰 후보 \1개만 표시합니다. 오늘 압축 기준 즉시진입 0개라 실전 TOP이 아니라 관찰 TOP으로 표시합니다.', t)
        t = t.replace('실전 후보가 적으면 적은 대로 출력 / 진입금지·실행보류는 TOP에서 제외',
                      '실전 후보가 적으면 적은 대로 출력 / 오늘 즉시진입 0개면 후속 TOP은 관찰 TOP으로 표시')
        t = t.replace('기준: 차트/구조/수급 우선 1단계 압축판입니다.',
                      '기준: 차트/구조/수급 우선 1단계 관찰 압축판입니다.')
        if '📌 오늘 압축 기준 즉시진입 0개' not in t:
            t = t.replace('아래 후보는 실전 진입이 아니라 눌림·재지지 확인용 관찰 후보입니다.',
                          '📌 오늘 압축 기준 즉시진입 0개: 아래 후보는 실전 진입이 아니라 눌림·재지지 확인용 관찰 후보입니다.')
            if '아래 후보는 실전 진입이 아니라' not in t:
                t = t.replace('기준: 차트/구조/수급 우선 1단계 관찰 압축판입니다.',
                              '기준: 차트/구조/수급 우선 1단계 관찰 압축판입니다.\n📌 오늘 압축 기준 즉시진입 0개: 아래 후보는 관찰/확인 후보입니다.', 1)
        return t
    except Exception:
        return s


def _v1107_4_2_hard_readability_breaks(s: str) -> str:
    """텔레그램/모바일 복사 시 붙는 문장을 강제 분리한다."""
    try:
        if not _v1107_4_2_on('V1107_4_2_HARD_READABILITY_BREAKS', '1'):
            return s
        t = _v1107_4_2_text(s)

        # TEST 태그와 청크 번호가 본문에 붙는 현상 방지
        t = re.sub(r'(?<!\n)(\[TEST\])', r'\n\1', t)
        t = re.sub(r'(?<!\n)(\([0-9]+/[0-9]+\))', r'\n\1', t)

        # 섹션 헤더 앞 줄바꿈
        t = re.sub(r'(?<!\n)(🎯 \[오늘 매매관점 압축\])', r'\n\1', t)
        t = re.sub(r'(?<!\n)(📢 \[오늘의 STRICT [^\]]+\])', r'\n\1', t)
        t = re.sub(r'(?<!\n)(🟢/🟡 \[실전 진입 가능 후보\])', r'\n\1', t)
        t = re.sub(r'(?<!\n)(🟢 \[분할진입 후보\])', r'\n\1', t)
        t = re.sub(r'(?<!\n)(🟡 \[눌림 확인 후보\])', r'\n\1', t)
        t = re.sub(r'(?<!\n)(🟠 \[회복 확인 후보\])', r'\n\1', t)
        t = re.sub(r'(?<!\n)(⚠️ \[리스크 참고/신규진입 보류\])', r'\n\1', t)
        t = re.sub(r'(?<!\n)(👀 \[구조관찰/리스크 분리\])', r'\n\1', t)
        t = re.sub(r'(?<!\n)(🧩 \[예비)', r'\n\1', t)
        t = re.sub(r'(?<!\n)(🏆 \[삼각)', r'\n\1', t)
        t = re.sub(r'(?<!\n)(🏆 \[저평가)', r'\n\1', t)

        # 섹터 레이더에서 1위/2위/매크로/ETF상세 등이 한 줄에 붙는 것 보정
        t = re.sub(r'([^\n])([1-9][0-9]?위 \[[^\]]+\])', r'\1\n\n\2', t)
        t = re.sub(r'(점수\s*[0-9.]+)(매크로\s*[0-9]/[0-9])', r'\1\n\2', t)
        t = re.sub(r'([^\n])(ETF상세:)', r'\1\n\2', t)
        t = re.sub(r'([^\n])(대표상세:)', r'\1\n\2', t)
        t = re.sub(r'([^\n])(관련주:)', r'\1\n\2', t)
        t = re.sub(r'([^\n])(→\s)', r'\1\n\2', t)

        # 후보 카드 내부 핵심 라벨 앞 줄바꿈. 이미 줄 첫머리면 건드리지 않는다.
        markers = ['🧭 TD운용:', '🔎 TD근거:', '🧭 ', '🧩 ', '🛠 ', '🎯 ', '🏦 ', '🔵 ', '✅ ', '📌 이유:', '📊 ', '🤖 AI']
        for mk in markers:
            esc = re.escape(mk)
            t = re.sub(r'([^\n])(' + esc + r')', r'\1\n   \2', t)

        # 후보 번호 앞 줄바꿈: 10) 같은 번호도 안전하게 처리
        t = re.sub(r'([^\n])((?:-\s*)?[0-9]{1,2}\)\s+[A-Za-z가-힣0-9&.·\- ]{1,50}\([0-9]{6}\))', r'\1\n\n\2', t)

        # 제목/설명 뒤 바로 후보가 붙을 때 분리
        t = re.sub(r'(표시합니다\.)([0-9]{1,2}\)\s+)', r'\1\n\n\2', t)
        t = re.sub(r'(확인합니다\.)([0-9]{1,2}\)\s+)', r'\1\n\n\2', t)

        # 버전 표시 갱신
        t = t.replace('V1107.4.1: TD라벨 충돌제거 / 카드단위 분할 / TD-RISK 중복차단',
                      'V1107.4.2: 출력 일관성 FIX / 즉시진입 0개↔관찰TOP 동기화 / 줄바꿈 최종보정')
        t = t.replace('V1107.4.1: TD라벨 충돌제거 / 카드단위 분할 / 실행제외·과열보류 NO-BACKFILL',
                      'V1107.4.2: 출력 일관성 FIX / 관찰TOP 동기화 / 실행제외·과열보류 NO-BACKFILL')
        t = t.replace('V1107.4.1', 'V1107.4.2')

        # 과한 빈 줄 정리
        t = re.sub(r'[ \t]+\n', '\n', t)
        t = re.sub(r'\n{4,}', '\n\n\n', t)
        return t.strip()
    except Exception:
        return s


def _v1107_4_2_cleanup_output_text(message: str) -> str:
    try:
        s = _v1107_4_2_text(message)
        # 기존 4.1 전체 정리 먼저 적용
        fn = globals().get('_v1107_4_1_cleanup_output_text')
        if callable(fn):
            try:
                s = fn(s)
            except Exception:
                pass
        _v1107_4_2_record_today_state(s)
        s = _v1107_4_2_rewrite_today_zero(s)
        s = _v1107_4_2_rewrite_strict_title(s)
        s = _v1107_4_2_hard_readability_breaks(s)
        _v1107_4_2_record_today_state(s)
        return s.strip()
    except Exception:
        return message


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    try:
        msg = _v1107_4_2_cleanup_output_text(str(message or ''))
    except Exception:
        msg = str(message or '')
    try:
        if not msg.strip():
            return None
        if title:
            msg = (str(title).strip() + '\n\n' + msg).strip()
        safe_fn = globals().get('_v1107_4_1_safe_int')
        split_fn = globals().get('_v1107_4_1_safe_split_message')
        raw_fn = globals().get('_v1107_4_1_raw_send_text')
        safe_len = 3400
        if callable(safe_fn):
            safe_len = min(safe_fn(max_len, 3400), 3400)
        if callable(split_fn) and callable(raw_fn):
            chunks = split_fn(msg, safe_len)
            total = len(chunks)
            for idx, chunk in enumerate(chunks, 1):
                out = f"({idx}/{total})\n{chunk}" if total > 1 else chunk
                raw_fn(out)
            return None
    except Exception:
        pass
    if _V1107_4_2_BASE_SEND_CHUNKS:
        return _V1107_4_2_BASE_SEND_CHUNKS(msg, title=title, max_len=max_len)
    return None


def send_telegram_photo(message, image_paths=[]):
    try:
        msg = _v1107_4_2_cleanup_output_text(str(message or ''))
    except Exception:
        msg = str(message or '')
    try:
        if len(msg) > 1000 or not image_paths:
            split_fn = globals().get('_v1107_4_1_safe_split_message')
            raw_fn = globals().get('_v1107_4_1_raw_send_text')
            if callable(split_fn) and callable(raw_fn):
                chunks = split_fn(msg, 3400)
                total = len(chunks)
                for idx, chunk in enumerate(chunks, 1):
                    out = f"({idx}/{total})\n{chunk}" if total > 1 else chunk
                    raw_fn(out)
                if image_paths and _V1107_4_2_BASE_SEND_PHOTO:
                    try:
                        return _V1107_4_2_BASE_SEND_PHOTO('📎 첨부 이미지', image_paths)
                    except Exception:
                        return None
                return None
        if _V1107_4_2_BASE_SEND_PHOTO:
            return _V1107_4_2_BASE_SEND_PHOTO(msg, image_paths)
    except Exception:
        if _V1107_4_2_BASE_SEND_PHOTO:
            return _V1107_4_2_BASE_SEND_PHOTO(message, image_paths)
    return None

