def _v1107_4_4_on(name: str, default: str = '1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0', 'false', 'no', 'off', '')
    except Exception:
        return str(default).strip().lower() not in ('0', 'false', 'no', 'off', '')


def _v1107_4_4_text(x) -> str:
    try:
        return str(x or '').replace('\r\n', '\n').replace('\r', '\n')
    except Exception:
        return ''


def _v1107_4_4_candidate_spans(text: str):
    """후보 카드 시작/끝 위치를 잡는다. 텔레그램 청크 내부에서만 동작하도록 보수적으로 설계."""
    try:
        s = _v1107_4_4_text(text)
        item_re = re.compile(r'(?m)^\s*(?:-\s*)?(\d{1,2})\)\s+([^\n(]{1,80}?)\(([0-9]{6})\)')
        hard_stop_re = re.compile(r'(?m)^\s*(?:\[TEST\]|\([0-9]+/[0-9]+\)|━━━━━━━━|🔄 \[|🌍 \[|📰 \[|🇺🇸|🎯 \[|🧭 \[|🟢/🟡 \[|🟢 \[|🟡 \[|🟠 \[|⚠️ \[|📢 \[|👀 \[|🧩 \[|🏆 \[|⛔ |📁 |$)')
        matches = list(item_re.finditer(s))
        spans = []
        for i, m in enumerate(matches):
            start = m.start()
            end = matches[i + 1].start() if i + 1 < len(matches) else len(s)
            # 다음 후보보다 앞에 주요 섹션 헤더가 있으면 거기까지만 카드로 본다.
            rest = s[m.end():end]
            hm = hard_stop_re.search(rest)
            if hm and hm.start() > 0:
                end = m.end() + hm.start()
            spans.append({'start': start, 'end': end, 'num': m.group(1), 'name': m.group(2).strip(), 'code': m.group(3), 'head': m.group(0), 'block': s[start:end]})
        return spans
    except Exception:
        return []


def _v1107_4_4_section_ranges(s: str, title_pattern: str):
    """특정 섹션 제목부터 다음 대형 섹션 전까지의 범위 리스트."""
    try:
        t = _v1107_4_4_text(s)
        starts = [m.start() for m in re.finditer(title_pattern, t)]
        if not starts:
            return []
        stop_re = re.compile(r'(?m)^\s*(?:\[TEST\]|\([0-9]+/[0-9]+\)|🎯 \[|🧭 \[|🟢/🟡 \[|🟢 \[|🟡 \[|🟠 \[|⚠️ \[|📢 \[|👀 \[|🧩 \[|🏆 \[|🌍 \[|📰 \[|🇺🇸|📁 )')
        ranges = []
        for st in starts:
            m0 = re.search(title_pattern, t[st:])
            scan_from = st + (m0.end() if m0 else 1)
            end = len(t)
            for m in stop_re.finditer(t, scan_from):
                if m.start() > st:
                    # 같은 STRICT 제목은 시작점이므로 제외하고 다음 섹션만 잡는다.
                    if m.start() == st:
                        continue
                    end = m.start()
                    break
            ranges.append((st, end))
        return ranges
    except Exception:
        return []


def _v1107_4_4_fix_sector_radar_breaks(s: str) -> str:
    try:
        if not _v1107_4_4_on('V1107_4_4_SECTOR_RADAR_BREAK_FIX', '1'):
            return s
        t = _v1107_4_4_text(s)
        # 섹터 레이더 시작부와 순위 라인 결합 방지
        t = re.sub(r'(🔄 \[섹터 순환 레이더\])\s*(매크로:)', r'\1\n\n\2', t)
        t = re.sub(r'(매크로:[^\n]*?)(━━━━━━━━)', r'\1\n\2', t)
        t = re.sub(r'(매크로:[^\n]*?)([1-9][0-9]?위 \[)', r'\1\n\n\2', t)
        t = re.sub(r'(━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━)([1-9][0-9]?위 \[)', r'\1\n\2', t)

        # 관련주 뒤에 다음 섹터 순위가 붙는 문제: 관련주: 000000, 111111, 2222222위 → 줄바꿈
        t = re.sub(r'(관련주:\s*(?:[0-9]{6}\s*,\s*)*[0-9]{6})(?=\s*[1-9][0-9]?위\s*\[)', r'\1\n\n', t)
        t = re.sub(r'(관련주:\s*(?:[0-9]{6}\s*,\s*)*[0-9]{6})\s*([1-9][0-9]?위\s*\[)', r'\1\n\n\2', t)

        # 섹터 카드 내부 핵심 라벨 분리
        t = re.sub(r'(점수\s*-?[0-9]+(?:\.[0-9]+)?)(매크로\s*[0-9]/[0-9])', r'\1\n\2', t)
        t = re.sub(r'(\(유효\s*[0-9]+,\s*실패\s*[0-9]+\))(?=ETF상세:)', r'\1\n', t)
        t = re.sub(r'(ETF상세:[^\n]*?)(?=대표상세:)', r'\1\n', t)
        t = re.sub(r'(대표상세:[^\n]*?)(?=→)', r'\1\n', t)
        t = re.sub(r'(→[^\n]*?)(?=관련주:)', r'\1\n', t)
        t = re.sub(r'(?<!\n)(ETF상세:)', r'\n\1', t)
        t = re.sub(r'(?<!\n)(대표상세:)', r'\n\1', t)
        t = re.sub(r'(?<!\n)(관련주:)', r'\n\1', t)

        # 후보문장 내부에서 "테마),2위"처럼 붙는 경우는 쉼표 뒤 공백만 추가하고 줄바꿈은 만들지 않는다.
        t = re.sub(r',(\s*)([1-9][0-9]?위\s*\[[^\]]+\]\s*(?:✅추천|👀관찰|⛔회피))', r', \2', t)
        return t
    except Exception:
        return s


def _v1107_4_4_fix_market_link_spacing(s: str) -> str:
    try:
        if not _v1107_4_4_on('V1107_4_4_MARKET_LINK_SPACING_FIX', '1'):
            return s
        t = _v1107_4_4_text(s)
        # 시황연결:2위 / 시황연결:\n2위 모두 한 줄 띄어쓰기 형태로 통일
        t = re.sub(r'(🔗\s*시황연결:)\s*\n\s*([1-9][0-9]?위\s*\[)', r'\1 \2', t)
        t = re.sub(r'(🔗\s*시황연결:)\s*([1-9][0-9]?위\s*\[)', r'\1 \2', t)
        t = re.sub(r'(시황연결:)\s*\n\s*([1-9][0-9]?위\s*\[)', r'\1 \2', t)
        t = re.sub(r'(시황연결:)\s*([1-9][0-9]?위\s*\[)', r'\1 \2', t)
        # 후보 요약 줄의 섹터 설명과 순위가 붙는 문제
        t = re.sub(r'(\([🟢🟡👀⚪🔴][^\)]*\)),\s*([1-9][0-9]?위\s*\[)', r'\1, \2', t)
        t = re.sub(r'(\|\s*점수\s*-?[0-9]+(?:\.[0-9]+)?),\s*(RSI\s*[0-9])', r'\1, \2', t)
        # "시황본문 직접연결,긍정" 같은 잔여 공백
        t = re.sub(r',(?=(?:긍정|부정|중립|RSI|이격|BB40|수렴|시황본문|유가하락))', ', ', t)
        return t
    except Exception:
        return s


def _v1107_4_4_filter_strict_td_risk_cards(s: str) -> str:
    """STRICT 실전/관찰 TOP 안에 TD-RISK 카드가 남아 있으면 카드 단위로 제거."""
    try:
        t = _v1107_4_4_text(s)
        if '📢 [오늘의 STRICT' not in t or 'TD-RISK' not in t:
            return t
        ranges = _v1107_4_4_section_ranges(t, r'📢 \[오늘의 STRICT [^\]]+\]')
        if not ranges:
            return t
        pieces = []
        last = 0
        for st, end in ranges:
            pieces.append(t[last:st])
            block = t[st:end]
            spans = _v1107_4_4_candidate_spans(block)
            if not spans:
                pieces.append(block)
                last = end
                continue
            keep, removed = [], []
            cursor = 0
            for sp in spans:
                keep.append(block[cursor:sp['start']])
                card = sp['block']
                if 'TD-RISK' in card or '🔴 TD-RISK' in card:
                    removed.append(sp.get('code') or '')
                    # 카드 전체 제거
                else:
                    keep.append(card)
                cursor = sp['end']
            keep.append(block[cursor:])
            new_block = ''.join(keep)
            if removed and '⛔ TD 충돌 제거:' not in new_block:
                note = f"⛔ TD 충돌 제거: TD-RISK 선분류 {len([x for x in removed if x])}개는 실전/관찰 TOP에서 제외했습니다. ({', '.join([x for x in removed if x][:8])})\n"
                new_block = re.sub(r'(📢 \[오늘의 STRICT [^\]]+\]\n)', r'\1' + note, new_block, count=1)
            pieces.append(new_block)
            last = end
        pieces.append(t[last:])
        return ''.join(pieces)
    except Exception:
        return s


def _v1107_4_4_count_strict_cards(block: str) -> int:
    try:
        spans = _v1107_4_4_candidate_spans(block)
        # STRICT 블록 안에서는 실제 종목 카드만 카운트한다.
        return sum(1 for sp in spans if '(' + str(sp.get('code', '')) + ')' in sp.get('head', ''))
    except Exception:
        return 0




def _v1107_4_4_renumber_strict_cards(s: str) -> str:
    """STRICT TOP 내부 카드 번호를 실제 남은 카드 기준으로 1부터 재정렬."""
    try:
        t = _v1107_4_4_text(s)
        if '📢 [오늘의 STRICT' not in t:
            return t
        ranges = _v1107_4_4_section_ranges(t, r'📢 \[오늘의 STRICT [^\]]+\]')
        if not ranges:
            return t
        out = []
        last = 0
        item_re = re.compile(r'^(\s*)(?:-\s*)?\d{1,2}\)\s+', re.M)
        for st, end in ranges:
            out.append(t[last:st])
            block = t[st:end]
            n = 0
            lines = []
            for line in block.splitlines():
                if item_re.match(line):
                    n += 1
                    line = item_re.sub(lambda m: f"{m.group(1)}{n}) ", line, count=1)
                lines.append(line)
            out.append('\n'.join(lines))
            last = end
        out.append(t[last:])
        return ''.join(out)
    except Exception:
        return s

def _v1107_4_4_sync_observe_count(s: str) -> str:
    try:
        if not _v1107_4_4_on('V1107_4_4_OBSERVE_COUNT_SYNC', '1'):
            return s
        t = _v1107_4_4_text(s)
        if '📢 [오늘의 STRICT 관찰 TOP]' not in t:
            return t
        ranges = _v1107_4_4_section_ranges(t, r'📢 \[오늘의 STRICT 관찰 TOP\]')
        if not ranges:
            return t
        out = []
        last = 0
        for st, end in ranges:
            out.append(t[last:st])
            block = t[st:end]
            cnt = _v1107_4_4_count_strict_cards(block)
            if cnt > 0:
                block = re.sub(r'관찰 후보\s*[0-9]+개만 표시합니다\.', f'관찰 후보 {cnt}개만 표시합니다.', block)
                block = re.sub(r'실전 후보\s*[0-9]+개만 표시합니다\.', f'관찰 후보 {cnt}개만 표시합니다.', block)
                # 문구가 없으면 AI 기준 다음에 짧게 추가
                if '관찰 후보 ' not in block and '후보입니다.' in block:
                    block = block.replace('후보입니다.', f'후보입니다.\n관찰 후보 {cnt}개만 표시합니다.', 1)
            else:
                block = re.sub(r'관찰 후보\s*[0-9]+개만 표시합니다\.[^\n]*', '관찰 후보 0개입니다. 조건을 만족한 관찰 카드가 없습니다.', block)
            out.append(block)
            last = end
        out.append(t[last:])
        return ''.join(out)
    except Exception:
        return s


def _v1107_4_4_extract_risk_names(s: str):
    try:
        t = _v1107_4_4_text(s)
        risk = []
        for sp in _v1107_4_4_candidate_spans(t):
            card = sp.get('block', '')
            if 'TD-RISK' in card or '🔴 TD-RISK' in card:
                name = str(sp.get('name', '')).strip()
                code = str(sp.get('code', '')).strip()
                if name or code:
                    risk.append((name, code))
        # registry에 코드만 있을 수 있으므로 코드도 보조 저장
        try:
            reg = globals().get('_V1107_4_1_TD_REGISTRY', {}) or {}
            for code, rec in reg.items():
                if 'TD-RISK' in str((rec or {}).get('label', '')):
                    c = str(code or '').strip()
                    if c and all(c != x[1] for x in risk):
                        risk.append(('', c))
        except Exception:
            pass
        return risk
    except Exception:
        return []


def _v1107_4_4_clean_ai_pick_line(line: str, risk_names) -> str:
    try:
        s = str(line or '')
        names = [n for n, c in risk_names if n]
        if not names:
            return s
        for name in names:
            # 쉼표/슬래시 리스트에서 종목명 제거
            s = re.sub(r'(?:(?<=Pick\s)|(?<=,\s)|(?<=/\s)|(?<=\s))' + re.escape(name) + r'\s*(?:,\s*)?', '', s)
            s = s.replace(', ,', ',').replace('/ ,', '/').replace(', /', '/')
        s = re.sub(r'AI 관찰 Pick\s*(?:/|$)', 'AI 관찰 Pick 없음 /', s)
        s = re.sub(r'AI 관찰 Pick\s*,', 'AI 관찰 Pick ', s)
        s = re.sub(r'AI 관찰 Pick\s*$', 'AI 관찰 Pick 없음', s)
        s = re.sub(r'Pick\s*/', 'Pick 없음 /', s)
        s = re.sub(r'\s{2,}', ' ', s).strip()
        return s
    except Exception:
        return line


def _v1107_4_4_exclude_td_risk_from_ai(s: str) -> str:
    try:
        if not _v1107_4_4_on('V1107_4_4_AI_EXCLUDE_TD_RISK', '1'):
            return s
        t = _v1107_4_4_text(s)
        risk_names = _v1107_4_4_extract_risk_names(t)
        if not risk_names:
            return t
        # AI Pick 기준 줄에서 TD-RISK 종목명 제거
        lines = []
        for line in t.splitlines():
            if 'AI Pick 기준:' in line or 'AI 관찰 Pick' in line or '강한 확신 Pick' in line:
                lines.append(_v1107_4_4_clean_ai_pick_line(line, risk_names))
            else:
                lines.append(line)
        t = '\n'.join(lines)
        # TD-RISK 카드 안에 남아 있는 AI 라벨 한 줄 제거
        for name, code in risk_names:
            if code:
                t = re.sub(r'(?m)^\s*🤖\s*AI[^\n]*\n(?=\s*🧭\s*TD운용:\s*🔴\s*TD-RISK)', '', t)
                if name:
                    t = re.sub(r'(?ms)(^\s*\d+\)\s*' + re.escape(name) + r'\(' + re.escape(code) + r'\)[^\n]*\n)\s*🤖\s*AI[^\n]*\n', r'\1', t)
        return t
    except Exception:
        return s


def _v1107_4_4_observe_tone_fix(s: str) -> str:
    try:
        if not _v1107_4_4_on('V1107_4_4_OBSERVE_TONE_FIX', '1'):
            return s
        t = _v1107_4_4_text(s)
        if '📢 [오늘의 STRICT 관찰 TOP]' not in t:
            return t
        ranges = _v1107_4_4_section_ranges(t, r'📢 \[오늘의 STRICT 관찰 TOP\]')
        if not ranges:
            return t
        out = []
        last = 0
        for st, end in ranges:
            out.append(t[last:st])
            block = t[st:end]
            # 헤더/공통 설명 톤
            block = block.replace('기준: 차트/구조/수급 우선 1단계 압축판입니다.', '기준: 차트/구조/수급 우선 1단계 조건부 관찰 압축판입니다.')
            block = block.replace('기준: 차트/구조/수급 우선 1단계 관찰 압축판입니다.', '기준: 차트/구조/수급 우선 1단계 조건부 관찰 압축판입니다.')
            block = block.replace('진입 공통조건:', '조건부 관찰 공통조건:')
            block = block.replace('아래 후보는 실전 진입이 아니라 눌림·재지지 확인용 관찰 후보입니다.', '아래 후보는 즉시 매수 대상이 아니라 조건부 관찰 후보입니다.')
            block = block.replace('아래 후보는 관찰/확인 후보입니다.', '아래 후보는 조건부 관찰/확인 후보입니다.')
            # TD/최종판정/전략/대응 톤
            block = block.replace('기준일 종가·다음날 시가 소액 가능', '기준일 종가·다음날 시가 조건부 관찰')
            block = block.replace('소액 가능 / 추가는 전일고점 재돌파', '조건부 관찰 / 추가 확인은 전일고점 재돌파')
            block = block.replace('🧭 최종판정: 🟢 지금 1차 분할진입 가능', '🧭 최종판정: 🟡 조건부 관찰')
            block = block.replace('🧭 최종판정: 🟡 소액 분할진입 가능', '🧭 최종판정: 🟡 조건부 관찰')
            block = block.replace('1차 분할진입 가능', '조건부 관찰')
            block = block.replace('소액 분할진입 가능', '조건부 관찰')
            block = block.replace('현재가 추격보다 소액 10~20% 확인 진입', '즉시 매수 금지, 기준선 재지지 확인')
            block = block.replace('소액 10~20% 확인 진입만 가능, 추가매수는 기준선 재안착 후', '조건 충족 전 신규 진입 금지, 추가 확인은 기준선 재안착 후')
            block = block.replace('1차: 현재가~', '조건부 관찰: 현재가~')
            block = block.replace('1차: 지금 추격보다 눌림 대기 / 진입:', '조건부 관찰: 지금 추격 금지 / 확인:')
            block = block.replace('1차: 현재가 추격보다', '조건부 관찰: 현재가 추격보다')
            # 카드 중간에 남는 즉시매수 뉘앙스 제거
            block = block.replace('지금 1차', '조건 충족 후 1차')
            block = block.replace('즉시진입', '즉시 진입')
            out.append(block)
            last = end
        out.append(t[last:])
        return ''.join(out)
    except Exception:
        return s


def _v1107_4_4_final_version_text(s: str) -> str:
    try:
        t = _v1107_4_4_text(s)
        t = t.replace('V1107.4.2: 출력 일관성 FIX / 즉시진입 0개↔관찰TOP 동기화 / 줄바꿈 최종보정',
                      'V1107.4.4: 출력 하드닝 FINAL / TD-RISK AI제외 / 관찰개수·줄바꿈 보정')
        t = t.replace('V1107.4.2: 출력 일관성 FIX / 관찰TOP 동기화 / 실행제외·과열보류 NO-BACKFILL',
                      'V1107.4.4: 출력 하드닝 FINAL / 관찰TOP 동기화 / 실행제외·과열보류 NO-BACKFILL')
        t = t.replace('V1107.4.2', 'V1107.4.4')
        # 과한 공백 정리
        t = re.sub(r'[ \t]+\n', '\n', t)
        t = re.sub(r'\n{4,}', '\n\n\n', t)
        return t.strip()
    except Exception:
        return s


def _v1107_4_4_cleanup_output_text(message: str) -> str:
    try:
        s = _v1107_4_4_text(message)
        # 기존 V1107.4.2 정리 먼저 적용
        fn = globals().get('_v1107_4_2_cleanup_output_text')
        if callable(fn):
            try:
                s = fn(s)
            except Exception:
                pass
        # 4.4 최종 하드닝 순서: 줄바꿈 → 링크간격 → STRICT 위험카드 제거 → AI 제외 → 관찰톤 → 개수동기화 → 버전표기
        s = _v1107_4_4_fix_sector_radar_breaks(s)
        s = _v1107_4_4_fix_market_link_spacing(s)
        # AI Pick 라인은 TD-RISK 카드를 제거하기 전에 먼저 정리해야 종목명을 안정적으로 제거할 수 있다.
        s = _v1107_4_4_exclude_td_risk_from_ai(s)
        s = _v1107_4_4_filter_strict_td_risk_cards(s)
        s = _v1107_4_4_renumber_strict_cards(s)
        s = _v1107_4_4_observe_tone_fix(s)
        s = _v1107_4_4_sync_observe_count(s)
        s = _v1107_4_4_final_version_text(s)
        return s.strip()
    except Exception:
        return message


def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    try:
        msg = _v1107_4_4_cleanup_output_text(str(message or ''))
    except Exception:
        msg = str(message or '')
    try:
        if not msg.strip():
            return None
        if title:
            msg = (str(title).strip() + '\n\n' + msg).strip()
        safe_fn = globals().get('_v1107_4_1_safe_int')
        split_fn = globals().get('_v1107_4_1_safe_split_message')
        raw_fn = globals().get('_v1107_4_1_raw_send_text')
        safe_len = 3400
        if callable(safe_fn):
            safe_len = min(safe_fn(max_len, 3400), 3400)
        if callable(split_fn) and callable(raw_fn):
            chunks = split_fn(msg, safe_len)
            total = len(chunks)
            for idx, chunk in enumerate(chunks, 1):
                out = f"({idx}/{total})\n{chunk}" if total > 1 else chunk
                raw_fn(out)
            return None
    except Exception:
        pass
    if _V1107_4_4_BASE_SEND_CHUNKS:
        return _V1107_4_4_BASE_SEND_CHUNKS(msg, title=title, max_len=max_len)
    return None


def send_telegram_photo(message, image_paths=[]):
    try:
        msg = _v1107_4_4_cleanup_output_text(str(message or ''))
    except Exception:
        msg = str(message or '')
    try:
        if len(msg) > 1000 or not image_paths:
            split_fn = globals().get('_v1107_4_1_safe_split_message')
            raw_fn = globals().get('_v1107_4_1_raw_send_text')
            if callable(split_fn) and callable(raw_fn):
                chunks = split_fn(msg, 3400)
                total = len(chunks)
                for idx, chunk in enumerate(chunks, 1):
                    out = f"({idx}/{total})\n{chunk}" if total > 1 else chunk
                    raw_fn(out)
                if image_paths and _V1107_4_4_BASE_SEND_PHOTO:
                    try:
                        return _V1107_4_4_BASE_SEND_PHOTO('📎 첨부 이미지', image_paths)
                    except Exception:
                        return None
                return None
        if _V1107_4_4_BASE_SEND_PHOTO:
            return _V1107_4_4_BASE_SEND_PHOTO(msg, image_paths)
    except Exception:
        if _V1107_4_4_BASE_SEND_PHOTO:
            return _V1107_4_4_BASE_SEND_PHOTO(message, image_paths)
    return None

