def _v1107_4_5_9_is_missing_supply(txt: str) -> bool:
    try:
        s = str(txt or '').strip()
        if not s:
            return True
        if re.search(r'(외인|기관|개인)\s*[+\-]?[0-9,.]+\s*억', s):
            return False
        bads = ['미계산', '미확인', '데이터 지연', '데이터 확인 필요', '수급 확인 필요', '수급 데이터 확인 필요']
        return any(b in s for b in bads)
    except Exception:
        return True


def _v1107_4_5_9_clean_supply_text(txt: str) -> str:
    try:
        s = str(txt or '').strip()
        s = re.sub(r'^🏦\s*수급\s*:\s*', '', s).strip()
        s = re.sub(r'\s+', ' ', s).strip(' |')
        if len(s) > 190:
            s = s[:187].rstrip(' |,·/') + '…'
        return s
    except Exception:
        return ''


def _v1107_4_5_9_code_from_header(line: str) -> str:
    try:
        m = re.search(r'^\s*\d{1,2}\)\s+[^\n()]{1,90}\(([0-9]{6})\)', str(line or ''))
        return m.group(1) if m else ''
    except Exception:
        return ''


def _v1107_4_5_9_price_from_header(line: str) -> float:
    try:
        m = re.search(r'현재\s*([0-9,]+)', str(line or ''))
        if m:
            return float(m.group(1).replace(',', ''))
    except Exception:
        pass
    return 0.0


def _v1107_4_5_9_fetch_supply_text(code: str, price: float = 0.0) -> str:
    try:
        if not _v1107_4_5_9_on('V1107_4_5_9_SUPPLY_FALLBACK', '1'):
            return ''
        c = str(code or '').strip().zfill(6)
        if not re.fullmatch(r'[0-9]{6}', c):
            return ''
        cache = globals().setdefault('_V1107_4_5_8_SUPPLY_CACHE', {})
        cached = cache.get(c, '')
        if cached and not _v1107_4_5_9_is_missing_supply(cached):
            return cached
        fetched = globals().setdefault('_V1107_4_5_9_SUPPLY_FETCHED', set())
        if c in fetched:
            return ''
        if len(fetched) >= max(0, _v1107_4_5_9_int('V1107_4_5_9_SUPPLY_FETCH_LIMIT', 25)):
            return ''
        fetched.add(c)
        prof_fn = globals().get('get_supply_profile')
        if not callable(prof_fn):
            return ''
        prof = prof_fn(c, price or 0.0)
        txt = ''
        for conv in [globals().get('_v1055_supply_profile_to_text'), globals().get('_v1059_supply_text_from_profile')]:
            if callable(conv):
                try:
                    txt = conv(prof)
                except Exception:
                    txt = ''
                if txt:
                    break
        if not txt and isinstance(prof, dict):
            tag = str(prof.get('tag', '') or prof.get('summary', '') or '').strip()
            today = str(prof.get('today_text', '') or '').strip()
            d3 = str(prof.get('cum3_text', '') or '').strip()
            parts = []
            if tag:
                parts.append(tag)
            if today:
                parts.append('1일 ' + today)
            if d3:
                parts.append('3일 ' + d3)
            txt = ' | '.join(parts)
        txt = _v1107_4_5_9_clean_supply_text(txt)
        if txt and not _v1107_4_5_9_is_missing_supply(txt):
            cache[c] = txt
            return txt
    except Exception:
        pass
    return ''


