def _v1107_4_5_9_balanced_spacing(message: str) -> str:
    try:
        if not _v1107_4_5_9_on('V1107_4_5_9_BALANCED_SPACING', '1'):
            return message
        s = _v1107_4_5_9_text(message)
        s = re.sub(r'[ \t]+\n', '\n', s)
        s = re.sub(r'(점수\s*-?\d+(?:\.\d+)?)\s*(매크로\s*\d/\d)', r'\1\n\2', s)
        s = re.sub(r'(관련주:\s*[0-9,\s]+)(?=\d위\s*\[)', r'\1\n', s)
        s = re.sub(r'(?<!\n)([2-9]위\s*\[[^\n]+\])', r'\n\1', s)
        s = re.sub(r'(?<!\n)(\d{1,2}\)\s+[^\n()]{1,70}\([0-9]{6}\))', r'\n\1', s)
        s = re.sub(r'📌\s*압축 기준:\s*분할진입 후보\s*\n?→\s*눌림 확인 후보\s*\n?→\s*회복 확인 후보\s*\n?→\s*리스크 참고', '📌 압축 기준: 분할진입 후보 → 눌림 확인 후보 → 회복 확인 후보 → 리스크 참고', s)
        major_pat = r'(?:🔄 \[섹터 순환 레이더\]|📰 \[뉴스-테마 분석\]|🇺🇸➡🇰🇷 \[미국시장|🌍 \[시장 통합 브리핑\]|🎯 \[오늘 매매관점 압축\]|📢 \[오늘의 STRICT|🟢 \[|🟡 \[|🟠 \[|⚠️ \[|👀 \[구조관찰|🧩 \[예비|🏆 \[)'
        s = re.sub(r'\n{0,2}(?=' + major_pat + r')', '\n\n', s)
        s = re.sub(r'\n{0,2}(?=[2-9]위\s*\[)', '\n\n', s)
        s = re.sub(r'\n{0,2}(?=\d{1,2}\)\s+[^\n()]{1,70}\([0-9]{6}\))', '\n\n', s)
        detail_prefix = r'(?:📌|🧭|🧩|🔗|✅|📊|🎯|🏦|🔵|🤖|🛠|📍|🌊|〰️|📐|🏷️|🔋|🧠|💰|📦|💵|🧲|⚠️|📏|📰|📖|🪄|🔁|☁|🧪)'
        s = re.sub(r'\n{2,}(?=\s*' + detail_prefix + r')', '\n', s)
        s = re.sub(r'\n{2,}(━━━━━━━━)', '\n\1', s)
        s = re.sub(r'(━━━━━━━━[^\n]*\n)\n{2,}', r'\1', s)
        s = re.sub(r'(\[TEST\]\n)\n+', r'\1', s)
        s = re.sub(r'(\(\d+/\d+\)\n)\n+', r'\1', s)
        s = re.sub(r'\n{3,}', '\n\n', s).strip()
        return s
    except Exception:
        return message


