        lines = s.split('\n')
        out = []
        i = 0
        while i < len(lines):
            line = lines[i]
            if out and _v1107_4_5_13_line_has_compact_supply(out[-1]) and _v1107_4_5_13_supply_label_only(line):
                j = i + 1
                removed_child = 0
