def _v1107_4_5_13_safe_split_message(text: str, max_len: int = 3400):
    try:
        split_fn = globals().get('_v1107_4_1_safe_split_message')
        if callable(split_fn):
            return split_fn(text, max_len)
    except Exception:
        pass
    s = str(text or '')
    if len(s) <= max_len:
        return [s]
    chunks = []
    while len(s) > max_len:
        cut = s.rfind('\n', 0, max_len)
        if cut < max_len // 2:
            cut = max_len
        chunks.append(s[:cut].strip())
        s = s[cut:].strip()
    if s:
        chunks.append(s)
    return chunks

