def _v1107_4_5_14_supply_child(line: str) -> bool:
    try:
        return bool(re.search(r'^\s*[├└]\s*[135]일:\s*개인\s*[+\-]?[0-9,.]+억\s*\|\s*외인\s*[+\-]?[0-9,.]+억\s*\|\s*기관\s*[+\-]?[0-9,.]+억', str(line or '')))
    except Exception:
        return False


def _v1107_4_5_14_has_real_supply(line: str) -> bool:
    try:
        s = str(line or '')
        if not re.search(r'1일\s*개인\s*[+\-]?[0-9,.]+억', s) or not re.search(r'3일\s*개인\s*[+\-]?[0-9,.]+억', s):
            return False
        # 0.0 placeholder only is not real supply
        nums = re.findall(r'(?:개인|외인|기관)\s*([+\-]?[0-9,.]+)억', s)
        if not nums:
            return False
        vals = []
        for n in nums:
            try: vals.append(float(n.replace(',','')))
            except Exception: vals.append(0.0)
        return any(abs(v) > 0.0001 for v in vals)
    except Exception:
        return False


def _v1107_4_5_14_join_market_context(s: str) -> str:
    try:
        s = re.sub(r'(🔗\s*시황연결:\s*)(?:title|desc)\s*:\s*', r'\1', s)
        s = re.sub(r'(🔗\s*시황연결:\s*)\n+\s*', r'\1', s)
        s = re.sub(r'(\d+위\s*\[[^\]\n]+\])\s*\n\s*(✅추천\s*\|\s*점수\s*-?[0-9.]+)', r'\1 · \2', s)
        s = re.sub(r'(\[TEST\]\n)\n+', r'\1', s)
        s = re.sub(r'(\(\d+/\d+\)\n)\n+', r'\1', s)
        return s
    except Exception:
        return s


def _v1107_4_5_14_wide_header_force(s: str) -> str:
    try:
        # 기존 V1107.4 구형/중간 헤더 전체를 5.14로 강제. V1107.4.5.*뿐 아니라 V1107.4:도 포함.
        s = re.sub(r'(?m)^\s*📌\s*V1107\.4(?:\.5(?:\.\d+)?)?\s*:[^\n]*$', _V1107_4_5_14_VERSION_LINE, s)
        s = re.sub(r'(?m)^\s*📌\s*TD\s*우선순위\s*:\s*.*$', _V1107_4_5_14_PRIORITY_LINE, s)
        # 너무 오래된 레이더 타이틀/필터 타이틀을 현재 운용 문구로 동기화
        s = re.sub(r'V1106\.\d+\s*긍/부정 문맥 \+ 매물흡수 우선 순환매 레이더', 'V1106.7 긍/부정 문맥 + 매물흡수 우선 순환매 레이더', s)
        s = re.sub(r'시황 문맥 필터 결과 — V1106\.\d+\s*분리', '시황 문맥 필터 결과 — V1106.7 분리', s)
        # V1094 원칙 라인은 유지하되 중복 버전 라인이 연속될 경우 1개만 남김
        out = []
        seen_v = False
        seen_p = False
        for line in s.split('\n'):
            st = line.strip()
            if st == _V1107_4_5_14_VERSION_LINE:
                if seen_v:
                    continue
                seen_v = True
                out.append(_V1107_4_5_14_VERSION_LINE)
                continue
            if st == _V1107_4_5_14_PRIORITY_LINE:
                if seen_p:
                    continue
                seen_p = True
                out.append(_V1107_4_5_14_PRIORITY_LINE)
                continue
            out.append(line)
        return '\n'.join(out)
    except Exception:
        return s


