def send_telegram_chunks(message: str, title: str = '', max_len: int = 3800):
    try:
        msg = _v1107_4_5_14_cleanup_output_text(str(message or ''))
        if title:
            msg = (str(title).strip() + '\n\n' + msg).strip()
        try:
            safe_len = min(int(max_len or 3400), 3400)
        except Exception:
            safe_len = 3400
        chunks = _v1107_4_5_14_safe_split_message(msg, safe_len)
        total = len(chunks)
        for idx, chunk in enumerate(chunks, 1):
            out = f"({idx}/{total})\n{chunk}" if total > 1 else chunk
            _v1107_4_5_14_raw_send_text(out)
        return None
    except Exception:
        return _v1107_4_5_14_raw_send_text(str(message or ''))

