def _v1107_4_5_15_on(name: str, default: str='1') -> bool:
    try:
        return str(os.environ.get(name, default)).strip().lower() not in ('0','false','no','off','')
    except Exception:
        return str(default).strip().lower() not in ('0','false','no','off','')


def _v1107_4_5_15_num(v, default: float=0.0) -> float:
    try:
        if '_v1080_num' in globals():
            return float(_v1080_num(v, default))
        if v is None:
            return default
        if isinstance(v, str):
            v = v.replace(',', '').replace('%', '').replace('원', '').replace('억', '').strip()
            if not v or v.lower() in ('nan','none','nat'):
                return default
        out = float(v)
        try:
            if pd.isna(out):
                return default
        except Exception:
            pass
        return out
    except Exception:
        return default


def _v1107_4_5_15_s(v, default: str='') -> str:
    try:
        if '_v1080_s' in globals():
            return _v1080_s(v, default)
        if v is None:
            return default
        try:
            if pd.isna(v):
                return default
        except Exception:
            pass
        s = str(v).strip()
        if s.lower() in ('nan','none','nat'):
            return default
        return s
    except Exception:
        return default


