def _v1107_4_5_15_clean_label(label: str) -> str:
    try:
        t = re.sub(r'\s+', ' ', str(label or '')).strip()
        if 'TD-PRIME' in t:
            return '🔥 TD-PRIME'
        if 'TD-CORE' in t:
            return '🟢 TD-CORE'
        if 'TD-RECOVER' in t:
            return '🟠 TD-RECOVER'
        if 'TD-WATCH' in t:
            return '🟡 TD-WATCH'
        if 'TD-RISK' in t:
            return '🔴 TD-RISK'
        return t or '미분류'
    except Exception:
        return '미분류'


def _v1107_4_5_15_row_text(row) -> str:
    """TD 분류용으로 행의 핵심 문자열/수치 필드를 합쳐 텍스트 블록을 만든다."""
    try:
        parts=[]
        keys = [
            'td_label','td_reason','td_entry','td_sector','td_strength','td_cause',
            'final_decision','decision_mode','phase','strategy','pattern','volume_state','fake_severity',
            'v1087_priority_class','v1097_gate_group','v1099_composite_group','v1105_context_bucket',
            '순환매판정','순환매코멘트','N구분','검색패턴','저항구름태그','수박정제태그','최종판정','매매판정',
            '진입전략','해석','comment','reason','리스크','AI코멘트','오늘매매관점'
        ]
        for k in keys:
            try:
                v = row.get(k, '') if hasattr(row, 'get') else row[k]
            except Exception:
                continue
            sv = _v1107_4_5_15_s(v, '')
            if sv:
                parts.append(f'{k}:{sv}')
        # 수치 힌트도 문장으로 추가한다.
        rsi = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['rsi','RSI'], 0), 0)
        disp = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['disparity','이격','Disparity'], 0), 0)
        bb40 = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['bb40','BB40'], 0), 0)
        upper_gap = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['upper_recovery_gap_pct','상단회복선이격','상단회복선거리'], 0), 0)
        if rsi >= 75:
            parts.append('RSI75')
        elif rsi >= 70:
            parts.append('RSI70')
        if disp >= 115:
            parts.append('이격115')
        elif disp >= 111:
            parts.append('이격111')
        if bb40 and bb40 <= 25:
            parts.append('BB40 수렴')
        if upper_gap and upper_gap > 7:
            parts.append('상단회복선 회복 필요')
        return ' | '.join(parts)
    except Exception:
        return ''


def _v1107_4_5_15_classify_row(row) -> dict:
    """행 단위 TD 라벨/근거를 계산한다. 기존 V1107.4 텍스트 분류기가 있으면 재사용."""
    try:
        existing = _v1107_4_5_15_clean_label(_v1107_4_5_15_first(row, ['td_label','TD라벨','TD운용'], ''))
        txt = _v1107_4_5_15_row_text(row)
        info = {}
        if existing != '미분류':
            info = {'label': existing, 'entry': _v1107_4_5_15_first(row, ['td_entry','TD진입'], ''), 'reason': _v1107_4_5_15_first(row, ['td_reason','TD근거'], ''), 'sector': _v1107_4_5_15_first(row, ['td_sector','섹터'], '미분류'), 'strength': _v1107_4_5_15_first(row, ['td_strength'], 'NEUTRAL_SECTOR')}
        elif '_v1107_4_classify_block' in globals():
            info = _v1107_4_classify_block(txt)
        else:
            # 최소 fallback
            low = txt
            if any(x in low for x in ['TD-RISK','신규진입 보류','실행보류','기준선아래','STOCK_BREAKDOWN','가짜수박 강']):
                info = {'label':'🔴 TD-RISK','entry':'실전 제외 / 재확인 전 관찰','reason':'위험/실행보류 문맥','sector':'미분류','strength':'NEUTRAL_SECTOR'}
            elif any(x in low for x in ['눌림 확인','눌림대기','재지지']):
                info = {'label':'🔥 TD-PRIME','entry':'눌림 재지지 확인','reason':'눌림/재지지 문맥','sector':'미분류','strength':'NEUTRAL_SECTOR'}
            elif any(x in low for x in ['소액 분할','소액가능','위안착']):
                info = {'label':'🟢 TD-CORE','entry':'소액 확인형','reason':'소액/기준선 문맥','sector':'미분류','strength':'NEUTRAL_SECTOR'}
            elif any(x in low for x in ['회복확인','회복선']):
                info = {'label':'🟠 TD-RECOVER','entry':'회복선 확인형','reason':'회복선 문맥','sector':'미분류','strength':'NEUTRAL_SECTOR'}
            else:
                info = {'label':'🟡 TD-WATCH','entry':'관찰','reason':'분류 불명확','sector':'미분류','strength':'NEUTRAL_SECTOR'}
        info['label'] = _v1107_4_5_15_clean_label(info.get('label',''))
        return info
    except Exception as e:
        return {'label':'🟡 TD-WATCH','entry':'관찰','reason':f'분류실패:{e}','sector':'미분류','strength':'NEUTRAL_SECTOR'}


def _v1107_4_5_15_structure_score(row) -> float:
    """서로 다른 버전의 구조점수를 0~100 근사로 압축한다. 확정 매수점수가 아니라 충돌 진단용."""
    try:
        explicit = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['structure_score','구조점수','점수','score'], 0), 0)
        if 0 < explicit <= 120:
            return min(100.0, explicit)
        safe = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['safe_score','안전점수'], 0), 0)
        nscore = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['n_score','N점수'], 0), 0)
        rsi = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['rsi','RSI'], 0), 0)
        disp = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['disparity','이격'], 0), 0)
        bb40 = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['bb40','BB40'], 0), 0)
        vol = _v1107_4_5_15_s(_v1107_4_5_15_first(row, ['volume_state','거래량상태'], ''), '')
        pri = _v1107_4_5_15_s(_v1107_4_5_15_first(row, ['v1087_priority_class','V1087우선순위'], ''), '')
        score = 40.0
        if safe >= _v1107_4_5_15_num(os.environ.get('V1107_4_5_15_STRUCTURE_SAFE_SCORE','250'),250):
            score += 18
        elif safe >= 150:
            score += 10
        if nscore >= _v1107_4_5_15_num(os.environ.get('V1107_4_5_15_STRUCTURE_N_SCORE','170'),170):
            score += 15
        elif nscore >= 120:
            score += 8
        if 35 <= rsi <= 68:
            score += 8
        elif rsi >= 75:
            score -= 12
        if 96 <= disp <= 111:
            score += 8
        elif disp >= 115:
            score -= 12
        if 0 < bb40 <= 25:
            score += 8
        elif 25 < bb40 <= 40:
            score += 4
        if '응축' in vol:
            score += 8
        elif '강' in vol:
            score += 3
        if any(x in pri for x in ['응축우선','일반관찰','공격형/추격주의']):
            score += 8
        if any(x in pri for x in ['확인필요','강등']):
            score -= 12
        return max(0.0, min(100.0, score))
    except Exception:
        return 0.0


def _v1107_4_5_15_prelim_td_score(row, td_label: str, struct_score: float) -> float:
    """확정 공식이 아닌 백테스트 진단용 임시 TD 점수."""
    try:
        lab = _v1107_4_5_15_clean_label(td_label)
        base = {
            '🔥 TD-PRIME': 80,
            '🟢 TD-CORE': 70,
            '🟠 TD-RECOVER': 58,
            '🟡 TD-WATCH': 45,
            '🔴 TD-RISK': 25,
        }.get(lab, 40)
        fake = _v1107_4_5_15_s(_v1107_4_5_15_first(row, ['fake_severity','가짜수박강도'], ''), '')
        vol = _v1107_4_5_15_s(_v1107_4_5_15_first(row, ['volume_state','거래량상태'], ''), '')
        stop_bucket = _v1107_4_5_15_s(_v1107_4_5_15_first(row, ['signal_stop_bucket','v1095_signal_stop_bucket','손절거리'], ''), '')
        rsi = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['rsi','RSI'], 0), 0)
        disp = _v1107_4_5_15_num(_v1107_4_5_15_first(row, ['disparity','이격'], 0), 0)
        score = float(base)
        if struct_score >= 85:
            score += 5
        if '응축' in vol:
            score += 5
        if '-3~-5' in stop_bucket:
            score += 4
        if '가짜수박 강' in fake:
            score -= 12
        elif '가짜수박 중' in fake or '미세' in fake:
            score -= 5
        if rsi >= 75:
            score -= 10
        elif rsi >= 70:
            score -= 4
        if disp >= 115:
            score -= 10
        elif disp >= 111:
            score -= 4
        return max(0.0, min(100.0, score))
    except Exception:
        return 0.0


def _v1107_4_5_15_conflict_group(row) -> str:
    try:
        lab = _v1107_4_5_15_clean_label(row.get('td_label','') if hasattr(row,'get') else '')
        struct = _v1107_4_5_15_num(row.get('td_structure_score',0) if hasattr(row,'get') else 0, 0)
        fake = _v1107_4_5_15_s(row.get('fake_severity','') if hasattr(row,'get') else '', '')
        stop_bucket = _v1107_4_5_15_s(row.get('signal_stop_bucket', row.get('v1095_signal_stop_bucket','')) if hasattr(row,'get') else '', '')
        upper_gap = _v1107_4_5_15_num(row.get('upper_recovery_gap_pct',0) if hasattr(row,'get') else 0, 0)
        rsi = _v1107_4_5_15_num(row.get('rsi',0) if hasattr(row,'get') else 0, 0)
        disp = _v1107_4_5_15_num(row.get('disparity',0) if hasattr(row,'get') else 0, 0)
        high_cut = _v1107_4_5_15_num(os.environ.get('V1107_4_5_15_STRUCTURE_HIGH_SCORE','90'),90)
        if struct >= high_cut and lab == '🔴 TD-RISK':
            return '⚠️ 구조상위×TD-RISK 충돌'
        if struct >= high_cut and lab == '🟡 TD-WATCH':
            return '👀 구조상위×TD-WATCH 관찰충돌'
        if lab in ('🔥 TD-PRIME','🟢 TD-CORE') and ('가짜수박 강' in fake or rsi >= 75 or disp >= 115):
            return '🚨 TD상위×과열/가짜수박 충돌'
        if lab == '🟠 TD-RECOVER' and upper_gap >= 7:
            return '🟠 RECOVER지만 회복선 멀음'
        if lab in ('🔥 TD-PRIME','🟢 TD-CORE') and struct >= 75 and ('-3~-5' in stop_bucket or '응축' in _v1107_4_5_15_s(row.get('volume_state',''),'')):
            return '✅ TD상위×구조양호 정렬'
        if lab == '🔴 TD-RISK':
            return '🔴 TD-RISK 일반'
        return '일반/충돌없음'
    except Exception:
        return '일반/충돌없음'


def _v1107_4_5_15_enrich_eval(eval_df: pd.DataFrame) -> pd.DataFrame:
    try:
        if eval_df is None or eval_df.empty:
            return eval_df
        out = eval_df.copy()
        # 기존 enrich 함수들이 만든 분류를 보존/보강한다.
        for fn_name in ['_v1097_enrich_eval','_v1096_enrich_eval','_v1095_enrich_eval']:
            try:
                fn = globals().get(fn_name)
                if callable(fn):
                    out = fn(out)
            except Exception:
                pass
        infos=[]
        for _, row in out.iterrows():
            td = _v1107_4_5_15_classify_row(row)
            struct = _v1107_4_5_15_structure_score(row)
            pre = _v1107_4_5_15_prelim_td_score(row, td.get('label',''), struct)
            infos.append({
                'td_label': _v1107_4_5_15_clean_label(td.get('label','')),
                'td_entry': td.get('entry',''),
                'td_reason': td.get('reason',''),
                'td_sector': td.get('sector','미분류'),
                'td_strength': td.get('strength','NEUTRAL_SECTOR'),
                'td_structure_score': round(struct, 1),
                'td_prelim_score': round(pre, 1),
            })
        add = pd.DataFrame(infos, index=out.index)
        for c in add.columns:
            out[c] = add[c]
        out['td_conflict_group'] = out.apply(_v1107_4_5_15_conflict_group, axis=1)
        out['td_exec_bucket'] = out['td_label'].map({
            '🔥 TD-PRIME':'실전상위(PRIME/CORE)',
            '🟢 TD-CORE':'실전상위(PRIME/CORE)',
            '🟠 TD-RECOVER':'회복확인(RECOVER)',
            '🟡 TD-WATCH':'관찰(WATCH)',
            '🔴 TD-RISK':'제외/RISK',
        }).fillna('미분류')
        return out
    except Exception:
        return eval_df


def _v1080_signal_row_from_series(row, rank: int = 0, source: str = 'TOP15') -> dict:
    """V1107.4.5.15 wrapper: DIRECT_REPLAY raw/eval에 TD 라벨·구조점수·충돌그룹 컬럼을 저장."""
    try:
        base = _V1107_4_5_15_BASE_SIGNAL_ROW(row, rank=rank, source=source) if callable(_V1107_4_5_15_BASE_SIGNAL_ROW) else {}
    except Exception:
        base = {}
    try:
        if base is None:
            base = {}
        if not _v1107_4_5_15_on('V1107_4_5_15_ENRICH_SIGNAL_ROWS','1'):
            return base
        tmp = dict(base)
        try:
            raw = row.to_dict() if hasattr(row, 'to_dict') else dict(row)
            tmp.update({k:v for k,v in raw.items() if k not in tmp})
        except Exception:
            pass
        td = _v1107_4_5_15_classify_row(tmp)
        struct = _v1107_4_5_15_structure_score(tmp)
        pre = _v1107_4_5_15_prelim_td_score(tmp, td.get('label',''), struct)
        base['td_label'] = _v1107_4_5_15_clean_label(td.get('label',''))
        base['td_entry'] = td.get('entry','')
        base['td_reason'] = td.get('reason','')
        base['td_sector'] = td.get('sector','미분류')
        base['td_strength'] = td.get('strength','NEUTRAL_SECTOR')
        base['td_structure_score'] = round(struct, 1)
        base['td_prelim_score'] = round(pre, 1)
        base['td_conflict_group'] = _v1107_4_5_15_conflict_group(base)
    except Exception:
        pass
    return base


def _v1107_4_5_15_group_lines(df: pd.DataFrame, col: str, title: str, max_rows: int=12, score_col: str='td_prelim_score') -> list:
    try:
        if df is None or df.empty or col not in df.columns:
            return []
        lines=[f'[{title}]']
        rows=[]
        for key,g in df.groupby(col, dropna=False):
            key=_v1107_4_5_15_s(key,'미분류')
            n=len(g)
            r1=pd.to_numeric(g.get('next1_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r3=pd.to_numeric(g.get('next3_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r5=pd.to_numeric(g.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            r10=pd.to_numeric(g.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').mean()
            best10=pd.to_numeric(g.get('best_ret_10d', g.get('max_up_10d', pd.Series(dtype=float))), errors='coerce').mean()
            p3=g.get('plus3_first_10d', g.get('plus3_first', pd.Series([False]*n))).astype(bool).mean()*100
            p5=g.get('plus5_first_10d', g.get('plus5_first', pd.Series([False]*n))).astype(bool).mean()*100
            stop=g.get('stop_first_10d', g.get('stop_first', pd.Series([False]*n))).astype(bool).mean()*100
            avg_score=pd.to_numeric(g.get(score_col, pd.Series(dtype=float)), errors='coerce').mean() if score_col in g.columns else 0
            rows.append((key,n,r1,r3,r5,r10,best10,p3,p5,stop,avg_score))
        order={
            '🔥 TD-PRIME':0,'🟢 TD-CORE':1,'🟠 TD-RECOVER':2,'🟡 TD-WATCH':3,'🔴 TD-RISK':4,
            '실전상위(PRIME/CORE)':0,'회복확인(RECOVER)':1,'관찰(WATCH)':2,'제외/RISK':3,
            '✅ TD상위×구조양호 정렬':0,'⚠️ 구조상위×TD-RISK 충돌':1,'👀 구조상위×TD-WATCH 관찰충돌':2,'🚨 TD상위×과열/가짜수박 충돌':3,'🟠 RECOVER지만 회복선 멀음':4,'🔴 TD-RISK 일반':5,'일반/충돌없음':6,
        }
        rows.sort(key=lambda x:(order.get(x[0],9), -x[1]))
        min_warn = int(_v1107_4_5_15_num(os.environ.get('V1107_4_5_15_MIN_SAMPLE_WARN','5'),5))
        for key,n,r1,r3,r5,r10,best10,p3,p5,stop,avg_score in rows[:max_rows]:
            small=f' ⚠️표본<{min_warn}' if n < min_warn else ''
            score_txt=f' | TD진단점수 {avg_score:.1f}' if score_col and avg_score == avg_score and avg_score > 0 else ''
            lines.append(f'- {key}: {n}개 | 1일 {_v1107_4_5_15_fmt(r1)} / 3일 {_v1107_4_5_15_fmt(r3)} / 5일 {_v1107_4_5_15_fmt(r5)} / 10일 {_v1107_4_5_15_fmt(r10)} | 10일최고 {_v1107_4_5_15_fmt(best10)} | +3먼저 {_v1107_4_5_15_rate(p3)} | +5먼저 {_v1107_4_5_15_rate(p5)} | 손절먼저 {_v1107_4_5_15_rate(stop)}{score_txt}{small}')
        lines.append('')
        return lines
    except Exception as e:
        return [f'[{title}]', f'- 생성 실패: {e}', '']


def _v1107_4_5_15_examples(df: pd.DataFrame, group_contains: str='', title: str='[V1107.4.5.15 TD 충돌 예시]', max_rows: int=10) -> list:
    try:
        if df is None or df.empty:
            return []
        tmp=df.copy()
        if group_contains and 'td_conflict_group' in tmp.columns:
            tmp=tmp[tmp['td_conflict_group'].astype(str).str.contains(group_contains, na=False)].copy()
        if tmp.empty:
            return []
        tmp['_r5']=pd.to_numeric(tmp.get('next5_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_r10']=pd.to_numeric(tmp.get('next10_close_ret', pd.Series(dtype=float)), errors='coerce').fillna(-999)
        tmp['_tds']=pd.to_numeric(tmp.get('td_prelim_score', pd.Series(dtype=float)), errors='coerce').fillna(0)
        tmp=tmp.sort_values(['td_conflict_group','_r5','_r10'], ascending=[True,False,False]).head(max_rows)
        lines=[title]
        for _,r in tmp.iterrows():
            name=_v1107_4_5_15_s(r.get('name', r.get('종목명','')),'')
            code=_v1107_4_5_15_s(r.get('code', r.get('종목코드','')),'')
            lab=_v1107_4_5_15_s(r.get('td_label',''),'미분류')
            cg=_v1107_4_5_15_s(r.get('td_conflict_group',''),'')
            struct=_v1107_4_5_15_num(r.get('td_structure_score',0),0)
            tds=_v1107_4_5_15_num(r.get('td_prelim_score',0),0)
            r5=_v1107_4_5_15_num(r.get('next5_close_ret',0),0)
            r10=_v1107_4_5_15_num(r.get('next10_close_ret',0),0)
            stopb=_v1107_4_5_15_s(r.get('signal_stop_bucket', r.get('v1095_signal_stop_bucket','')),'')
            reason=_v1107_4_5_15_s(r.get('td_reason',''),'')
            if len(reason) > 42:
                reason = reason[:41] + '…'
            lines.append(f'- {name}({code}) | {lab} / 구조 {struct:.1f} / TD진단 {tds:.1f} | {cg} | 5일 {r5:+.2f}% / 10일 {r10:+.2f}% | 손절 {stopb or "N/A"} | {reason}')
        lines.append('')
        return lines
    except Exception:
        return []


