        lines.append('')
        lines += _v1107_4_5_15_group_lines(ok, 'td_label', 'V1107.4.5.15 TD 라벨별 성과', max_rows=8)
        lines += _v1107_4_5_15_group_lines(ok, 'td_exec_bucket', 'V1107.4.5.15 TD 실행버킷별 성과', max_rows=8)
        lines += _v1107_4_5_15_group_lines(ok, 'td_conflict_group', 'V1107.4.5.15 구조점수×TD충돌 성과', max_rows=10)
        if 'td_label' in ok.columns and 'volume_state' in ok.columns:
            top = ok[ok['td_label'].astype(str).isin(['🔥 TD-PRIME','🟢 TD-CORE','🟠 TD-RECOVER'])].copy()
            if not top.empty:
                lines += _v1107_4_5_15_group_lines(top, 'volume_state', 'V1107.4.5.15 TD상위/회복 후보 거래량상태별 성과', max_rows=8)
        if 'td_label' in ok.columns and 'signal_stop_bucket' in ok.columns:
            top = ok[ok['td_label'].astype(str).isin(['🔥 TD-PRIME','🟢 TD-CORE','🟠 TD-RECOVER'])].copy()
            if not top.empty:
                lines += _v1107_4_5_15_group_lines(top, 'signal_stop_bucket', 'V1107.4.5.15 TD상위/회복 후보 손절거리별 성과', max_rows=8)
        lines += _v1107_4_5_15_examples(ok, '구조상위×TD-RISK', '[V1107.4.5.15 구조상위×TD-RISK 충돌 예시]', max_rows=8)
        lines += _v1107_4_5_15_examples(ok, 'TD상위×과열|RECOVER지만|TD상위×구조양호', '[V1107.4.5.15 TD 상위/주의/정렬 예시]', max_rows=10)
        lines.append('[V1107.4.5.15 적용 가이드]')
        lines.append('- TD점수는 아직 확정하지 않습니다. 최소 8~12주, 라벨별 20~30개 이상 누적 후 공식화합니다.')
        lines.append('- 구조상위×TD-RISK가 반복적으로 수익이 좋으면 “관찰 후 승격” 조건을 만들고, 손절먼저가 높으면 현재처럼 실전 제외를 유지합니다.')
        lines.append('- TD-PRIME/CORE라도 가짜수박 강·RSI75↑·이격115↑가 붙으면 점수보다 실행보류가 우선입니다.')
        lines.append('- 기아처럼 구조 섹션 점수가 높고 오늘 매매관점에서 TD-RISK가 뜨는 경우는 오류 확정이 아니라 “구조점수와 실행게이트 충돌”로 별도 검증합니다.')
        lines.append('')
