    # ✅ V1050: 오늘 매매관점 압축 직후 TOP15 compact 분석을 먼저 강제 전송
    core_top15_sent_first = False
    try:
        core_top15_sent_first = _v1050_send_forced_top15(
            telegram_targets,
            fallback_frames=[
                all_hits_df_for_pre,
                wm_intro_top5,
                wm_pullback_top5,
                breakout_watch_df,
                breakout_pick_df,
                dante_watch_df,
                dante_pick_df,
                wm_red_top5,
                wm_blue_top5,
                wm_late_top5,
            ],
            limit=_v1050_env_int('TOP15_COMPACT_LIMIT', 15),
        )
    except Exception as _v1050_send_e:
        core_top15_sent_first = False
        try: log_error(f'⚠️ V1050 TOP15 compact 선전송 실패: {_v1050_send_e}')
        except Exception: pass

    # ✅ V1047: 속도 우선 모드는 유지하되, 오늘 매매관점에서 바로 종료하지 않는다.
    # - 기존 문제: STOCKHUNTER_FAST_REPORT=1 기본값 때문에 오늘 매매관점 압축만 보내고
    #   📢 오늘의 실시간 TOP 15 / 🏆 역매공파·BB40 TOP5 / 상세카드가 전송되기 전에 종료됨.
    # - 새 기준: 빠른 모드에서도 핵심 매매 리포트(오늘 매매관점 + TOP15 상세 + 역매공파 TOP5)는 보낸 뒤
    #   HTML 리포트/구글시트 같은 무거운 후처리만 생략한다.
    _v1047_fast_core_only = _v1036_env_on('STOCKHUNTER_FAST_REPORT', '1')
    if _v1047_fast_core_only:
        try:
            log_info('⚡ V1047 FAST_REPORT: 오늘 매매관점 + TOP15 상세 + 역매공파/BB40 TOP5까지 전송 후 HTML/시트 후처리만 생략합니다.')
        except Exception:
            pass

    # ✅ V1043: TOP15 원본 DF가 비면 오늘 매매관점 압축 후보 순서로 상세카드 후보를 복구
    try:
        telegram_targets = _v1043_build_top15_fallback_targets(
            telegram_targets,
            source_frames=[
                all_hits_df_for_pre,
                wm_intro_top5,
                wm_pullback_top5,
                breakout_watch_df,
                breakout_pick_df,
                dante_watch_df,
                dante_pick_df,
                wm_red_top5,
                wm_blue_top5,
                wm_late_top5,
            ],
            limit=_v1046_env_int('TOP15_DETAIL_LIMIT', 15),
        )
    except Exception as _v1043_fb_e:
        try:
            log_info(f"⚠️ V1043 TOP15 fallback 예외: {_v1043_fb_e}")
        except Exception:
            pass

    current_msg = f"📢 [오늘의 실시간 TOP 15]\n\n"
    
    stage_block = ""
    pre_block = build_pre_dolbanji_block("예비돌반지 TOP 5", pre_top5, exact_mode=False)
    exact_block = build_pre_dolbanji_block("HTS 정확복제형 예비돌반지 TOP 5", exact_top5, exact_mode=True)
    lite_block = build_pre_dolbanji_block("신규예비돌반지 Lite TOP 5", lite_top5, exact_mode=False)

    if len(pre_top5) == 0:
        pre_block = ""
    if len(exact_top5) == 0:
        exact_block = ""
    if len(lite_top5) == 0:
        lite_block = ""
    show_pre_dolbanji = bool(len(pre_top5) > 0 or len(exact_top5) > 0 or len(lite_top5) > 0)
    if not show_pre_dolbanji:
        pre_block = ""
        exact_block = ""
        lite_block = ""

    wm_guide_block = build_watermelon_guide_block()
    wm_green_block = build_watermelon_summary_block(all_hits_df_for_pre)
    wm_red_block = build_watermelon_state_block("수박상태 빨강 TOP 5", wm_red_top5)
    wm_blue_block = build_watermelon_state_block("파란점선 타점 TOP 5", wm_blue_top5)

    wm_debug_block_raw = build_watermelon_debug_block("수박/파란점 디버그 TOP 5", wm_debug_top5)
    wm_debug_block = ""

    show_debug_now = False
    if SHOW_WM_DEBUG:
        show_debug_now = True
    elif SHOW_WM_DEBUG_ON_ALERT and should_show_wm_debug_alert(
        wm_intro_top5=wm_intro_top5,
        wm_pullback_top5=wm_pullback_top5,
        wm_blue1_top5=wm_blue1_top5,
        wm_blue2_top5=wm_blue2_top5,
        wm_late_top5=wm_late_top5,
    ):
        show_debug_now = True

    if show_debug_now and wm_debug_block_raw:
        wm_debug_block = wm_debug_block_raw
    elif not TEST_MODE:
        wm_alert = build_wm_alert_summary(
            wm_intro_top5=wm_intro_top5,
            wm_pullback_top5=wm_pullback_top5,
            wm_blue1_top5=wm_blue1_top5,
            wm_blue2_top5=wm_blue2_top5,
            wm_late_top5=wm_late_top5,
        )
        if wm_alert:
            wm_debug_block = wm_alert

    wm_intro_block = build_watermelon_state_block("초입수박 TOP 5", wm_intro_top5)
    wm_pullback_block = build_watermelon_state_block("눌림수박 TOP 5", wm_pullback_top5)
    wm_late_block = build_watermelon_state_block("후행수박 TOP 5", wm_late_top5)
    dante_pick_block = build_dante_state_block("선취 후보 TOP 5", dante_pick_df)
    dante_watch_block = build_dante_state_block("선취 관찰 후보 TOP 5", dante_watch_df)
    dante_ex_block = build_dante_state_block("선취 제외 후보 TOP 5", dante_ex_df)
    breakout_pick_block = build_breakout_state_block("흰구름 돌파 후보 TOP 5", breakout_pick_df)
    breakout_watch_block = build_breakout_state_block("흰구름 돌파 관찰 TOP 5", breakout_watch_df)

    wm_blue1_block = build_watermelon_state_block("Blue-1 단기 TOP 5", wm_blue1_top5)
    wm_blue2_preview_top5 = pd.DataFrame()
    if all_hits_df_for_pre is not None and (not all_hits_df_for_pre.empty) and "수박최종상태" in all_hits_df_for_pre.columns:
        wm_blue2_preview_top5 = all_hits_df_for_pre[all_hits_df_for_pre["수박최종상태"] == "Blue-2예비"].copy()
        if not wm_blue2_preview_top5.empty:
            _sort_cols = [c for c in ["파란점선2스윙점수", "수박포켓점수", "안전점수", "N점수"] if c in wm_blue2_preview_top5.columns]
            if _sort_cols:
                wm_blue2_preview_top5 = wm_blue2_preview_top5.sort_values(by=_sort_cols, ascending=[False]*len(_sort_cols)).head(5).reset_index(drop=True)
            else:
                wm_blue2_preview_top5 = wm_blue2_preview_top5.head(5).reset_index(drop=True)
    wm_blue2_preview_block = build_watermelon_state_block("Blue-2 예비 TOP 5", wm_blue2_preview_top5)
    wm_blue2_block = build_watermelon_state_block("Blue-2 스윙 TOP 5", wm_blue2_top5)

    stage_block = ""
    stage_block += build_stage_track_block("단계 기반 선취형 TOP 5", stage_preempt_top5)
    stage_block += build_stage_track_block("단계 기반 돌파직전형 TOP 5", stage_ready_top5)
    stage_block += build_stage_track_block("단계 기반 초동발생형 TOP 5", stage_burst_top5)
    log_debug(f"🚀 stage_block 길이: {len(stage_block)}")
 
    _last_rec_section = None
    # ✅ V1050: compact TOP15를 이미 보냈으면 긴 verbose TOP15는 기본 생략하여 중복/누락/지연을 방지
    try:
        _v1050_skip_legacy_top15 = bool(locals().get('core_top15_sent_first', False)) and _v1050_env_on('SKIP_LEGACY_TOP15_DETAIL_IN_CORE_FIRST', '1')
    except Exception:
        _v1050_skip_legacy_top15 = False
    _v1050_legacy_top15_targets = telegram_targets.iloc[0:0] if _v1050_skip_legacy_top15 and hasattr(telegram_targets, 'iloc') else telegram_targets
    if _v1050_skip_legacy_top15:
        try: log_info('⚡ V1050: 긴 TOP15 상세카드는 compact TOP15로 대체하여 생략')
        except Exception: pass
    for _, item in _v1050_legacy_top15_targets.iterrows():
        # ─── 헬퍼
        def _si(v, d=0):
            try: return int(float(v))
            except: return d
        def _sf(v, d=0.0):
            try: return float(v)
            except: return d

        # ─── 핵심 값 추출
        name_str    = item['종목명']
        code_str    = item.get('code', '')
        price       = _si(item.get('현재가', 0))
        n_grade_raw = item.get('N등급', '')
        n_grade     = _cap_grade_label(n_grade_raw, _recommendation_max_grade(item))
        n_combo     = item.get('N조합', '')
        safe_score  = max(0, min(999, _si(item.get('안전점수', 0))))
        n_score     = max(0, min(999, _si(item.get('N점수', 0))))
        rsi         = _si(item.get('RSI', 0))
        disparity   = _si(item.get('이격', 0))
        ma_conv     = _sf(item.get('MA수렴', 0))
        ma_ultra    = _sf(item.get('초단기MA수렴도', 0))
        ma_short    = _sf(item.get('단기MA수렴도', 0))
        ma_struct   = _sf(item.get('구조MA수렴도', 0))
        ma_comment  = str(item.get('MA수렴코멘트', ''))
        obv_slope   = _si(item.get('OBV기울기', 0))
        bb40        = _sf(item.get('BB40', 0))
        stage       = item.get('단계상태', 'DROP')
        supply      = item.get('수급', '-')
        finance     = item.get('재무', '-')
        narrative   = item.get('📜서사히스토리', '')
        ai_tip      = item.get('ai_tip', '')
        energy      = item.get('에너지', '')
        weather     = item.get('기상', '')

        # ─── 핵심 태그만 추출 (중복/노이즈 제거)
        # N구분에서 의미있는 태그만 골라냄 (5개 이하)
        n_tags_raw  = str(item.get('N구분', '')).split()
        # 우선순위: 수박>돌반지>독사>골파기>종베>BB30 순
        priority_kw = ['🍉', '💍', '🐍', '🕳️', '💛', '🎯', '💎', '🟣', '📊OBV']
        n_tags_top  = []
        for kw in priority_kw:
            for tag in n_tags_raw:
                if kw in tag and tag not in n_tags_top:
                    n_tags_top.append(tag)
                    break
        # 부족하면 앞에서 채움
        for tag in n_tags_raw:
            if tag not in n_tags_top and len(n_tags_top) < 4:
                n_tags_top.append(tag)
        key_tags = ' '.join(n_tags_top[:4])

        # ─── 매집 정보
        maejip_grade  = item.get('매집강도등급', 'D(매집없음)')
        maejip_days   = _si(item.get('매집일수_10일', 0))
        vol_ratio     = _sf(item.get('매집거래량배율', 0))
        sv60          = _si(item.get('세력평단_60일', 0))
        gap_pct       = _sf(item.get('평단이격', 0))
        pre_maejip    = _si(item.get('발사직전매집', 0))

        # ─── 공시
        disc_tag      = item.get('공시태그', '없음')
        disc_nm       = item.get('공시내용', '')[:15] if item.get('공시내용') else ''
        has_bad_disc  = bool(item.get('악재공시', False))

        # ─── 타점 정보
        target_p = _si(item.get('🎯목표타점', 0))
        stop_p   = _si(item.get('🚨손절가', 0))
        bb30_gc  = bool(item.get('BB30시프트GC', False))
        bb30_val = _si(item.get('BB30시프트선', 0))

        # ─── 단계 표시 (PASS_A/B를 사람이 읽기 쉽게)
        stage_str = ''
        if stage == 'PASS_A':
            s_from = _short_stage_date(item.get('S1날짜', ''))
            s_to = _short_stage_date(item.get('S3날짜', ''))
            stage_str = describe_stage_status(stage)
            if s_from and s_to:
                stage_str += f" ({s_from}→{s_to})"
        elif stage == 'PASS_B':
            s_from = _short_stage_date(item.get('S2날짜', ''))
            s_to = _short_stage_date(item.get('S3날짜', ''))
            stage_str = describe_stage_status(stage)
            if s_from and s_to:
                stage_str += f" ({s_from}→{s_to})"

        # ─── 이격도 경고
        disp_warn = ''
        if disparity >= 120: disp_warn = ' ⚠️과열'
        elif disparity <= 95: disp_warn = ' 📍눌림'

        # ─── BB30 시프트선 표시
        bb30_str = f"🎯시프트:{bb30_val:,}원" if bb30_gc and bb30_val > 0 else ''

        # ─── 악재 공시 경고 줄
        disc_str = ''
        if disc_tag not in ('없음', '공시없음'):  # 미조회/오류도 표시
            _disc_icon = '🚨' if has_bad_disc else '📋'
            _disc_detail = f" ({disc_nm})" if disc_nm else ''
            disc_str = f"{_disc_icon} 공시: {disc_tag}{_disc_detail}" 

        # ─── AI 코멘트 핵심만 (첫 줄만)
        rec_phase = str(item.get('추천단계','') or '').strip()
        ai_short = f"💡 한 줄 결론: {_recommendation_summary_line(item)}"

        # ════════════════════════════════════
        # 최종 메시지 포맷 (간결 + 구조적)
        # ════════════════════════════════════
        entry = ""
        _section_title = _recommendation_section_title(rec_phase)
        if _section_title != _last_rec_section:
            entry += f"\n{_section_title}\n\n"
            _last_rec_section = _section_title

        entry += (
            f"{'─'*28}\n"
            f"⭐ {n_grade}  [{name_str}]  {price:,}원\n"
            f"🎯 {n_combo}\n"
            f"🏷️ {key_tags}\n"
            f"🪜 유형:{rec_phase}\n"
        )

        # 단계 (PASS만)
        if stage_str:
            entry += f"📶 {stage_str}\n"

        # BB30 시프트 타점
        if bb30_str:
            entry += f"🎯 {bb30_str}\n"

        supply_summary = str(item.get('수급요약', '') or '').strip()
        supply_today = str(item.get('수급당일', '') or '').strip()
        supply_3d = str(item.get('수급3일누적', '') or '').strip()
        supply_5d = str(item.get('수급5일누적', '') or '').strip()
        supply_flow = str(item.get('수급판정', '') or '').strip()
        supply_warn = str(item.get('수급경고', '') or '').strip()
        supply_gross1 = str(item.get('수급매수매도1일', '') or '').strip()
        supply_gross5 = str(item.get('수급매수매도5일', '') or '').strip()
        supply_streak = str(item.get('수급연속', '') or '').strip()
        supply_conf = str(item.get('수급신뢰도', '') or '').strip()
        supply_date = str(item.get('수급기준일', '') or '').strip()
        foreign_hold = str(item.get('외인보유요약', '') or '').strip()

        entry += (
            f"\n"
            f"💰 현재가:{price:,} | 이격:{disparity}{disp_warn} | RSI:{rsi}\n"
            f"📊 초:{ma_ultra:.1f} | 단:{ma_short:.1f} | 구:{ma_struct:.1f} | BB40:{bb40:.1f} | OBV:{obv_slope:+}\n"
            f"🧭 {ma_comment[:42]}\n"
            f"🏦 수급:{supply} | 재무:{finance} | {energy}\n"
        )
        if supply_summary:
            entry += f"📌 수급요약:{supply_summary}\n"
        if supply_today:
            entry += f"💵 최근1일:{supply_today}\n"
        if supply_3d:
            entry += f"📦 최근3일:{supply_3d}\n"
        if supply_5d:
            entry += f"🧲 최근5일:{supply_5d}\n"
        if supply_flow:
            entry += f"📍 수급판정:{supply_flow}\n"
        if supply_streak:
            entry += f"🔁 연속:{supply_streak}\n"
        if foreign_hold and foreign_hold != '미확인':
            entry += f"🌍 외인보유:{foreign_hold}\n"

        # 세력 평단 (0이 아닐 때만)

        if sv60 > 0:
            entry += f"💎 평단:{sv60:,}원 | 이격:{gap_pct:+.1f}% | 매집:{maejip_days}일({vol_ratio:.1f}배)\n"

        # 서사 (있을 때만, 30자 제한)
        if narrative:
            entry += f"📖 {narrative[:40]}\n"

        # 공시 (악재만 표시)
        if disc_str:
            entry += f"{disc_str}\n"

        # 종목 뉴스 감성 (있을 때만)
        _news_sent = str(item.get('news_sentiment', '')).strip()
        if _news_sent:
            entry += f"📰 {_news_sent[:60]}\n"

        # AI 심판 / AI 코멘트
        ai_verdict = str(item.get('AI최종판정', '') or '').strip()
        ai_conf    = safe_int(item.get('AI확신도', 0))
        ai_judge   = str(item.get('AI심판요약', '') or '').strip()
        ai_reason  = str(item.get('AI강한근거', '') or '').strip()

        if ai_verdict:
            entry += f"🧠 심판:{ai_verdict}"
            if ai_conf > 0:
                entry += f" {ai_conf}점"
            if ai_judge:
                entry += f" | {ai_judge[:42]}"
            entry += "\n"
        if ai_reason:
            entry += f"🪄 근거: {ai_reason[:52]}\n"
        if ai_short:
            entry += f"{ai_short}\n"

        item2 = enrich_row_with_human_commentary(item)
        _interp = str(item2.get('interpretation_block', '') or '').strip()
        if _interp:
            entry += f"{_interp}\n"

        _time_tag = str(item.get('time_sym_tag', '')).strip()
        _time_comment = str(item.get('time_sym_comment', '')).strip()
        if _time_tag:
            entry += f"⏱ 시간창:{_time_tag}"
            if _time_comment:
                entry += f" | {_time_comment[:28]}"
            entry += "\n"

        _ma5_tag = str(item.get('5일재안착태그', '')).strip()
        _ma5_comment = str(item.get('5일재안착코멘트', '')).strip()
        if _ma5_tag:
            entry += f"🔁 재안착:{_ma5_tag}"
            if _ma5_comment:
                entry += f" | {_ma5_comment[:30]}"
            entry += "\n"

        _rn_tag = str(item.get('라운드넘버태그', '')).strip()
        _rn_comment = str(item.get('라운드넘버코멘트', '')).strip()
        if _rn_tag:
            entry += f"🚉 라운드:{_rn_tag}"
            if _rn_comment:
                entry += f" | {_rn_comment[:28]}"
            entry += "\n"

        _wc_tag = str(item.get('저항구름태그', '')).strip()
        _wc_comment = str(item.get('저항구름코멘트', '')).strip()
        if _wc_tag:
            entry += f"☁ 저항구름:{_wc_tag}"
            if _wc_comment:
                entry += f" | {_wc_comment[:24]}"
            entry += "\n"

        _refine_tag = str(item.get('수박정제태그', '')).strip()
        _refine_comment = str(item.get('수박정제코멘트', '')).strip()
        if _refine_tag:
            entry += f"🧪 정제:{_refine_tag}"
            if _refine_comment:
                entry += f" | {_refine_comment[:24]}"
            entry += "\n"

        # 타점 (2단계 목표 + 지지저항)
        target2_p = _si(item.get('🎯목표2차', 0))
        if target_p > 0 and target2_p > 0 and target2_p < target_p:
            target_p, target2_p = target2_p, target_p
        rr_ratio  = float(item.get('RR비율', 0))
        nearest_r = item.get('근접저항', '')
        nearest_s = item.get('근접지지', '')
        pp_val    = _si(item.get('PP', 0))
        r1_val    = _si(item.get('R1', 0))
        s1_val    = _si(item.get('S1', 0))
        fib382    = _si(item.get('Fib382', 0))
        fib618    = _si(item.get('Fib618', 0))
        atr_val   = _si(item.get('ATR값', 0))

        if target_p > 0 and stop_p > 0:
            entry += f"📌 목표1:{target_p:,} → 목표2:{target2_p:,} | 손절:{stop_p:,}"
            if rr_ratio > 0:
                entry += f" (RR {rr_ratio:.1f})"
            entry += "\n"

        # 피봇/피보나치 지지저항
        if pp_val > 0:
            entry += f"📐 PP:{pp_val:,} | R1:{r1_val:,} | S1:{s1_val:,}\n"
        if fib382 > 0:
            entry += f"🔢 Fib38.2%:{fib382:,} | Fib61.8%:{fib618:,}\n"
        if atr_val > 0:
            entry += f"📏 ATR:{atr_val:,}원\n"

        entry += f"점수: 안전{safe_score} / N{n_score}\n"


        if len(current_msg) + len(entry) > MAX_CHAR:
            _v1046_send_top15_detail(current_msg, max_len=3300)
            imgs = []
            entry_body = entry.lstrip('\n')
            split_header = _section_title if _section_title else '📢 [오늘의 추천주 - 이어서]'
            if split_header and not entry_body.startswith(split_header):
                current_msg = f"{split_header}\n\n" + entry_body
            else:
                current_msg = entry_body
            log_debug(f"[메시지 분할] {len(current_msg)}자")
        else:
            current_msg += entry

    # ✅ V7: 마지막 블록 첫머리에 매매관점 압축을 직접 삽입
    try:
        trade_action_summary_block = build_trade_action_summary_block_from_frames(
            telegram_targets=telegram_targets,
            wm_red_top5=wm_red_top5,
            wm_blue_top5=wm_blue_top5,
            dante_pick_df=dante_pick_df,
            dante_watch_df=dante_watch_df,
            breakout_pick_df=breakout_pick_df,
            breakout_watch_df=breakout_watch_df,
            wm_pullback_top5=wm_pullback_top5,
            wm_late_top5=wm_late_top5,
            dante_ex_df=dante_ex_df,
            ai_candidates=ai_candidates,
            all_hits_df=all_hits_df_for_pre,
            wm_intro_top5=wm_intro_top5,
            amount_top60_df=amount_top60_df,
        )
    except Exception as _v7_sum_e:
        trade_action_summary_block = f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎯 [오늘의 매매관점 압축]\n- 생성 실패: {_v7_sum_e}\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

    # ✅ V8.1: 이미 TOP15 전에 보냈으면 final_block에서는 중복 제거
    if locals().get('trade_action_summary_sent_first', False):
        trade_action_summary_block = ""

    # 마지막 블록은 급등후보 + 예비돌반지 별도 TOP5
    final_block = trade_action_summary_block + "\n" + (triangle_pre_squeeze_block or "") + "\n" + (triangle_squeeze_block or "") + "\n" + (ymgp_bb40_block or "") + "\n" + (stage_block or "") + "\n" + pre_block + "\n" + exact_block + "\n" + lite_block + "\n" + wm_guide_block + "\n" + wm_green_block + "\n" + wm_red_block + "\n" + wm_blue_block + "\n" + wm_debug_block + "\n" + dante_pick_block + "\n" + dante_watch_block + "\n" + breakout_pick_block + "\n" + breakout_watch_block + "\n" + dante_ex_block + "\n" + wm_intro_block + "\n" + wm_pullback_block + "\n" + wm_late_block + "\n" + wm_blue1_block + "\n" + wm_blue2_preview_block + "\n" + wm_blue2_block

    # ✅ TOP15는 이미지 포함 메시지로 먼저 전송하되, 빈 헤더만 있으면 전송하지 않음
    if _v1043_has_real_top15_body(current_msg):
        _v1046_send_top15_detail(current_msg, max_len=3300)
    else:
        try:
            log_info('🛡️ V1043: TOP15 상세 본문이 없어 빈 헤더 전송을 생략합니다.')
        except Exception:
            pass
    imgs = []

    # ✅ final_block은 절대 한 번에 보내지 않고 청크 분할 전송
    if final_block.strip():
        send_telegram_chunks(final_block, max_len=3500)

    # ✅ V1047: 빠른 모드 종료 지점을 여기로 이동
    # 오늘 매매관점 압축, TOP15 상세카드, 역매공파/BB40 TOP5와 주요 참고 블록까지 보낸 뒤
    # 시간이 오래 걸리는 HTML 생성/첨부, 공개 링크, AI 토너먼트 재전송, 구글시트 업데이트만 생략한다.
    if locals().get('_v1047_fast_core_only', False):
        try:
            log_info('✅ V1047 FAST_REPORT 완료: 핵심 텔레그램 리포트 전송 완료. HTML/시트 후처리는 생략합니다.')
        except Exception:
            pass
        graceful_shutdown(exit_code=0)

    try:
        html_report_path = build_mobile_html_report(
            report_date=TODAY_STR,
            telegram_targets=telegram_targets,
            immediate_entry_df=immediate_entry_top5,
            immediate_watch_df=immediate_watch_top5,
            stage_preempt_df=stage_preempt_top5,
            stage_ready_df=stage_ready_top5,
            breakout_pick_df=breakout_pick_df,
            breakout_watch_df=breakout_watch_df,
            wm_intro_df=wm_intro_top5,
            wm_pullback_df=wm_pullback_top5,
            wm_blue1_df=wm_blue1_top5,
            wm_blue2_df=wm_blue2_top5,
            extra_panels=[
                {'title': '예비 삼각수렴·BB응축', 'body': triangle_pre_squeeze_block, 'open': True},
                {'title': '삼각수렴→1파→첫눌림', 'body': triangle_squeeze_block, 'open': True},
                {'title': '저평가 1파/BB40 회복', 'body': ymgp_bb40_block, 'open': True},
                {'title': '단계형 요약', 'body': stage_block, 'open': True},
                {'title': '예비돌반지', 'body': pre_block},
                {'title': 'HTS 정확복제형 예비돌반지', 'body': exact_block},
                {'title': '신규예비돌반지 Lite', 'body': lite_block},
                {'title': '수박 가이드', 'body': wm_guide_block},
                {'title': '수박 상태 요약', 'body': wm_green_block},
                {'title': '수박 빨강', 'body': wm_red_block},
                {'title': '파란점선 타점', 'body': wm_blue_block},
                {'title': '수박 디버그/알림', 'body': wm_debug_block},
                {'title': '선취 후보', 'body': dante_pick_block},
                {'title': '선취 관찰', 'body': dante_watch_block},
                {'title': '돌파 후보', 'body': breakout_pick_block},
                {'title': '돌파 관찰', 'body': breakout_watch_block},
                {'title': '선취 제외/보류', 'body': dante_ex_block},
                {'title': '초입수박', 'body': wm_intro_block},
                {'title': '눌림수박', 'body': wm_pullback_block},
                {'title': '후행수박', 'body': wm_late_block},
                {'title': 'Blue-1 단기', 'body': wm_blue1_block},
                {'title': 'Blue-2 예비', 'body': wm_blue2_preview_block},
                {'title': 'Blue-2 스윙', 'body': wm_blue2_block},
                {'title': 'AI 토너먼트', 'body': tournament_report},
            ],
        )
        log_info(f"📱 모바일 HTML 리포트 생성 완료: {html_report_path}")
        send_telegram_document(html_report_path, caption=f"📱 모바일 HTML 리포트 | {TODAY_STR}")

        public_url = get_mobile_report_public_url('main7_mobile_latest.html')
        if public_url:
            log_info(f"🔗 모바일 HTML 공개 링크: {public_url}")
            send_mobile_report_link(public_url, report_date=TODAY_STR)
        else:
            log_info('ℹ️ REPORT_BASE_URL / GITHUB_PAGES_URL 미설정: HTML 파일 첨부만 전송합니다.')
    except Exception as e:
        log_error(f"⚠️ 모바일 HTML 리포트 생성 실패: {e}")

    imgs = []
    # AI 토너먼트는 맨 마지막
    if tournament_report and len(tournament_report) > 10:
        log_info(f"📨 토너먼트 결과 전송 중 ({len(tournament_report)}자)...")
        send_tournament_results(tournament_report)
        log_info("✅ 토너먼트 전송 완료")
    else:
        log_error("⚠️ 토너먼트 결과 없어서 전송 생략")

    if should_skip_google_update():
        log_info("🧪 [TEST MODE] Google 시트 업데이트 생략")
    else:
        try:
            update_google_sheet(all_hits_sorted, TODAY_STR, tournament_report + "\n\n" + (ai_debate_text or "") + "\n" + triangle_pre_squeeze_block + "\n" + triangle_squeeze_block + "\n" + stage_block + "\n" + pre_block + "\n" + exact_block + "\n" + lite_block + "\n" + wm_green_block + "\n" + wm_red_block + "\n" + wm_blue_block + "\n" + wm_intro_block + "\n" + wm_pullback_block + "\n" + wm_late_block + "\n" + wm_blue1_block + "\n" + wm_blue2_block)
            log_info(f"💾 총 {len(all_hits_sorted)}개 종목 전수 기록 완료!")
        except Exception as e:
            log_error(f"🚨 시트 업데이트 실패: {e}")

    log_info("✅ 작전 종료: 전수 기록 완료 및 정예 15건 보고 완료!")
    graceful_shutdown(exit_code=0)

